insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA SAGRARIO'and edp.apellido1='GARCIA'and apellido2='PECES'),'2020-03-11','TERESA: FUTUEX DESDE PROINES INFORMA QEU LA SITUACION ECONOMICA HA VARIADO DESDE QEU FALLECIO LA MADRE, HA PASADO A COBRAR EL DOBLE DE PENSION Y POR ELLO LO HAN NOTIFICADO A LA CTAEX EL 8 DE ENERO PERO NO HAN OBTERNIDO RESPUESTA. SE HAN PLANTEADO DERIVAR A CRR YA QEU MARGARITA PRESENTA MAYOR DETERIORO Y NO CUMPLE LOS OBJETIVOS DEL PISO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2020-03-11','TERESA: FUTUEX EL EXPEDIENTE DE DEPENDENICA ESTA INACTIVO A PESAR DE TENER UN GRDO DOS POR NO ACEPTACION PIA. NO SE OPONEN A RECIBIR SAD PERO SOLO EN LAS ZONAS COMUNES. EN LA VISITAN COMENTA QUE HACE TIEMPO COMPRARON UN ROBOT DE COCINA QEU NO ESTAN PAGANDO, LE ESTAN MANDANDO NOTIFICACIONES DE LA DEUDA PERO NO NOS LA PUEDEN DAR PORQEU LAS ROMPEN. EL CONTRATO ESTA FIRMADO A NOMGRE DE JUANI Y Mª FE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2020-03-11','TERESA: FUTUEX COMUNIA LA FINALIZACION DE LAS OBRAS EN LA PLANTA BAJA Y DEXPONE QUE HAN ENVIADO LA FACTURA DEL TOTAL PARA QUE SEA ABONADA AL ALBAÑIL. SE MUESTRA TRANQUILO Y CONTENTO CON PODER UTILIZAR LA PLANTA BAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-03-11','Con motivo del procedimiento DPA 645/2019, se la ha citado en el Juzgado de Primera Instancia e Instrucción nº 2, de Zafra, para comparecencia el día 16/4/2020, a las 12:45 horas, a fin de prestar declaración en calidad de investigada, sobre lesiones ocurridas el 30 de noviembre de 2019 en Fuente de Cantos. Debido a que en este procedimiento debe comparecer asistida de abogado, solicitamos en su nombre se le designe abogado del turno de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2020-03-11','TERESA: FUTUEX DESDE QUE SE REALIZO EL CAMBIO DE LA PENSION A LA CUENTA DE IBERCAJA SE RECIBE DIARIAMENTE LLAMADAS TELEFONICAS DE TRINIDAD PREOCUPADA POR LAS DOMICILIACIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-03-11','TERESA: FUTUEX SIGUE SIN TOMAR LA MEDICACION PORQUE ALEGA QUE NO ESTA ENFERMO QEU DIOS LE HA CURADO. NO SE ASEA TIENE BARBA Y PELO LARGO NO TIENE RUTINAS DE SUEÑO NI DE COMIDA SOLAMENTE SE LAVA LA CARA Y SE PEINA CUANDE SE LE VISITA. TIENE CITA EN SALUD MENTAL EL 19 DE MARZO EN ALMENDRALEJO CON LO CUAL DUDAMOS QUE QUIERA IR YA QUE NO QUIERE NI IR A LAS DE SU PUEBLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-03-11','TERESA: FUTUEX HA ESTANDO INGRESADA EN UHB DESDE EL 13 DE ENERO HATA EL 6 DE FEBRERO, INGRESO MUY ALTERADA Y CON IDEAS DELIRANTES SOBRE SU MADRE. SIGUE ALGO SUBIDA Y HA TENIDO VARIAS DISCUSIONES CON SU PADRE Y SU PAREJA QUE HAN DIFICULTADO SU ESTABILIDAD EMOCIONAL EMPEZO A RECIBIR UNA AXULIAR DE AYUDA A DOMICILIO POR DEPENDENCIA, ELLA ESTA CONTENTA CON EL SERVICIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2020-03-11','TERESA: FUTUEX VIVE EN LA RM JUAN CARLOS IBARRA DE VILLAFRANCA, Y ESTA MUY INTEGRADO DEMANDA IR AL PUEBLO LA DIRECTORA IBA A MADAR UN EMAIL A LA COMISION PARA COMENTAR ESTA DEMANDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-03-11','TERESA: FUTUEX TIENE ALQUILA UN PISO EN LA CALLE LOPEZ DE AYALA MUY CERCA DE LA RESIDEENCIA DONDE COME Y DE LA CASA DE SUS PADRES.SIGUE LLENDO A CASA DE SUS PADRES A ECHARLE DE COMER A LOS PAJAROS QUE TIENE EN UN CUARTO DE LA TERRAZA. SE CREE QUE PASA ALLI MAS TIEMPO DEL QUE DICE E INCLUSO DUERME ALGUNAS NOCHES, LOS CAMBIOS DE CANDIDO SON MUY DIFICILES LE CUESTA ASIMILAR Y TARDA TIEMPO EN HACERLO MARIA JOSE DEL SSB TAMBIEN ESTA HANBLANDO CON EL SOBRE EL TEMA DEL PISO SE ESTA PENDIENTE DE CAMBIAR EL TELEFONO FIJO CON LA ANTENA DEL CANAL SUR AL PISO DE ALQUILER, PERO CANDIDO HA HABLADO DE ESTE TEMA CON LA CTEX PDIIENDO ALGO MAS DE TIEMPO PARA ADAPTARSE AL CAMBIO HACE UN PAR DE SEMANA SE ESTA OBSERVANDO MAS MOVIMIENTO EN EL PISO POR PARTE DE LA LIMPIADORA, EL DORMITORIO SE NOTA MAS USADO Y BAÑO TAMBIEN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-03-12','Ana: Llamo a Chelo (Consuelo Lavado), Jefa de los SSAB de Zafra (924554501, ext. 5): Le explico la situación de Pilar. Acordamos solicitaré por escrito y registro (Tal y como requieren en el SSAB conforme a lo dispuesto en la Ley de Procedimiento) los informes necesarios para las solicitudes pendientes (Dependencia, Revisión CADEX y plaza por Decreto). Una vez registrado, le adelantaré copia a través del correo electrónico: ssbz@zafra.es // mcarmen.pons@zafra.es ///////////////////////////////// Registro de salida el escrito y se lo envío escaneado a ambas direccione de mail. /////////////// Entrego a Julio, CTAEX, el original para que lo remita por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-03-12','TERESA: EMAIL TONI PSICOLOGA MADEX Valorada la documentación aportada por email en relación a la usuaria del servicio de RAL, NATALIA MEJÍAS MILLón, se OBSERVA: • El registro de incidencia lo realiza Miguel Cordón aunque no haya estado presente en la misma. El registro de incidencias debe realizarlo el personal presente en la incidencia. Además de recogerla con todo detalle se deben recoger las medidas adoptadas al respecto. Las medias adoptadas ante la incidencia deben ser las establecidas en las reuniones de coordinación técnicas. Los cuidadores deben tener claro cómo actuar ante las conductas desafiantes de Natalia. • Se deben respetar las pautas de intervención establecidas (dos latas a la semana y tras manifestar conductas desafiantes, la cuidadora pierde autoridad y traslada el hecho a Miguel Cordón y accede a dar la lata de refresco). Se refuerza la conducta desafiante. • En el caso de ser imposible o no recomendable seguir la pauta de intervención establecidas en las reuniones de coordinación técnica se dará traslado nuevamente al equipo para replantear la intervención con los nuevos datos. • Se deben determinar, implementar medidas proactivas. Tan sólo se informa en la documentación aportada de medias reactivas. Las medias proactivas y la participación de las personas reducen la emisión de conductas desafiantes (Apoyo Activo). • Se da reincidencia en las incidencias (ej. retira del WC a una usuaria del CD para sentarse ella). No se recogen intervenciones para aplicar la/os cuidadoras ante la repetición de la repetición de la misma conducta desafiante. • El ir a su casa los fines de semana con su familia, entiendo que es un derecho de Natalina y no es negociable, a priori. No se debe restringir. Se podrán programar intervención con otros objetivos a conseguir que por ejemplo conlleve una gratificación o parte de la paga semanal, manteniendo siempre un mínimo de dinero de bolsillo semanal para sus gastos, etc) y esto le permitirá comprar ticket de autobús o la familia determinar que no la recogen por no cumplir objetivo, etc.). Pero no castigar con las visitas a su domicilio familiar. • Recomendable que Natalia tenga un profesional de referencia a quien dirigir sus demandas, peticiones, y demás. • Se ha de garantizar la participación de Natalia en el diseño de la intervención (programación centrada en la persona). Tener en cuenta sus fortalezas y sus debilidades al diseñarlo. Espero que estas recomendaciones sean tenidas en cuenta para abordar (disminuir o eliminar) las conductas desafiantes de Natalia. Si os parece prudente un plazo de 3 semanas para elaborar o incorporar en su PAI y hacérnoslo llegar por este medio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2020-03-12','TERESA: FUTUEX RESIDE EN CALERA DE LEON EN UNA CASA DE ALQUILER Y SIEMPRE ESTA DEMANDADNDO CAMBIARSE DE DOMICILIO Y DE LOCALIDAD, DICE ESTAR CANSADO DE ESE PUEBLO Y DE LA POCA GENTE QUE VIVE ALLI PERO CUANDO SE HABLA DEL CAMBIO SOLAMENTE SERIA DE LOCALICAZACION PORQEU QUIERE LAS MISMAS CONDICIONES QUE HAORA VIVIR SOLO, QUE LE LLEVEN LA COMIDA, Y QUE LE LIMPIEN LA CASA TRES DIAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-03-12','En relación con la solicitud de aclaración del cargo aceptado enviada al Juzgado de Primera instancia e Instrucción nº 2, de Mérida, nos indican desde el Juzgado (Bernardo 924380613), que nos envían la Resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2020-03-12','TERESA: FUTUEX RESIDE EN CASA PARTICULAR EN LA FUENTE DEL MAESTRE YA QUE SU HERMANO LLEVA EN LA RESIDENCIA DE LOS SANTOS DESDE SEPTBRE DE 2019 TIENE A PILAR DE AUXILIAR DE DOMICILIO DESDE HACE AÑOS PER LA RELACION ESTA MUY DETERIORADA. PILAR MANDO UN MENSAJE PARA DEMANDAR QEU LLAMARA FUTUEX AL CENTRO DE SALUD Y SOLICITE CITA EN SALUD MENTAL YA QUE SEGUN ELLA DIEGO ESTASB MAL. SE LE CONSTETO QUE SI ELLA QUE PASABA MAS TIENPO CON EL LO CONSIDERABA ASI QUE PIDIERA ELLA MISMA LA CITA Y LE ACOMPAÑARA. PORQUE FUTUEX NO HA OBSERVADO NINGUA CONDUCTA DESAJUSTADA NI NADA FUERA DE LO HABITUAL, DIJO QUE LO HARIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-03-12','TERESA: FUTUEX SE ENCUENTRA EN EL CENTRO FRANCISCO ASUAR DESDE HACE UN PAR DE MESES, INGRESO DE MANERA VOLUNTARIA Y DESDE ENTONCES DEMANDA ASISISTIR AL MEDICO DE CABACERA PRA QUE LE PONGAN UN TRATAMIENTO PARA DEJAR DE FUMAR. EL MEDICO LE HA COMENTADO QUE JOSE FLORENCIO TIEN MUCHA MEDICACION Y HABRA QUE REDUCIR PRIMERO SU TRATAMIENTO ANTES DE INTRODUCIRLE MAS. JOSE FLORENCIO ES UAN PERSONA COMPLEJA QUE NO LLEVA BIEN LAS NORMAS Y QEU TIENE LA CABEA EN UN MONTON DE PROYECTOS AL MISMO TIEMPO, AHORA ESTA CONLA IDEA DE VENDER SU MOTO A UNO DE SUS SOBRINOS YA QEU SON LO QUE LA ESTAN USANDO TIEN UNA PROBLEMATICA CON EL TEMA DEL DINERO PORQUE NO SABE ADMINISTRARLO Y DESDE EL CENTRO VAN A INTENTAR TRABJAR ESE TEMA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2020-03-12','En relación con la autorización judicial para vender las fincas heredadas de su tío, hemos solicitado al centro Aprosuba 7, de Mérida (Bibi, TS, 924312056)certificación de residencia, para aportarlo al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2020-03-12','TERESA: FUTUEX JUAN ANTONIO ESTA EN LA RESIENCIA DE LOS SANTOS DESDE EL 11 DE SEPTIEMBRE DEL 2019. TUVO UNA CRISIS EN DICIEMBRE Y ESTUVO VARIAS SEMANAS ALTERADO Y CON DELIRIOS. FUE EN VARIAS OCASIONES A HOSPITAL DE LLERENA DOND ELE CAMBIARON LA MEDIACION PERO DECIDIERON NO INGRESARLE, AL CABO DE UNAS SEMANAS Y ALGUNOS CAMBIOS DE MEDICACION ESTA ESTABLE. SE LE HA ACOMPAÑADO A SALUD MENTAL EL 14 DE FEBRERO Y NO HA HABIDO CAMBIOS EN LA MEDICACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-03-12','TERESA: FUTUEX M ANTONIA RESIDE EN LA CASA DE SU TIA EN ZAFRA MIENTRAS AYUDA EN SUS CUIDADOS Y EN ATENDER LA CASA, ASISTE AL CENTRO OCUPACIONAL DE PLENA INCLUSION ZAFRA COMO PINCHE DE COCINA Y COMER ALLI TIENE BASTATE PROBLEMATICA PARA CONTROLAR SUS NIVELES DE AZUCAR Y CREE QUE SABE ADMNISTRARSE LA MEDICACION CORRECTAMENTE. HA ASISITIDO A CITA CON EL FORENSE EN EL JUZGADO DE ZAFRA YA QUE SE HA INICIADO LOS TRAMITES PARA UN INGRESO INVOLUNTARIO YA QUE ELLA SE NIEGA A IRSE A UN CENTRO MIENTRAS SU TIA SIGA VIVA PORQUE QUIERE CUIDARLA HASTA EL FINAL SIN SER CONSCIENTE DE ELLA TAMBIEN NECESITA AYUDA LA CUAL NO LE PRESTAN EN ESE DOMICILIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2020-03-12','TERESA: FUTUEX SE ENCUENTRA EN EL PISO SUPERVISADO DE FEAFES ZAFRA DEZDE HACE MAS DE DOS AÑOS, SE HA MUDADO DE LOCALIZACION EN ENERO Y PARA ELLA HA SIDO UN CAMBIO MUY GRANDE, SE HA DESAJUSTADO UN POCO Y HA NECESITADO TIEMPO PARA LA ADAPTACION , LAS ULTIMAS VISITAS HAN SIDO DIFIVILES CON ELLA PORQUE NO HA QUERIDO PASEARO O CHARLAR CON NOSOTROS. DECIA QUE ELLA ES UNA PERSONA DESCONFIADA Y CON IDEAS DELIRANTES Y NO CREE QUE VENGAN DE LA COMISION TUTELAR. NO SE LE FORZO A NADA SOLAMENTE SE LE QUEDO CLARO QEU SEGUIRIAMOS VISITANDOLA Y EU ESTRIAMOS AHI PARA CUANDO QUISIERA CONVERSAR EL AL ULTIMA VISITA A MEDIADO DE FEBRERO HA CONSENTIDO DAR UN PASEO TODAVIA ALGO REACIA Y PREGUNTANDO QUE TENIA QUE DECIR EXACTAMENTE. HA COMENTADO QUE QUIERE CONSEGUIR EL ALTA EN EL PISO Y QUE ECAH MUCHO DE MENOS A SU PADRE Y SUS HERMANAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2020-03-12','Puerto Ramos, TS del Ayuntamiento de Plasenca (600449238), llama a la CTAEX para comunicarnos que ha fallecido el padre de José Antonio, el 13/2/2020. Tiene documentación (DNI, C. Defunción, ÚLtimas Voluntades va a pedirlo). Los hermanos están valorando recunciar a la herencia por existir deudas. Va a hablar con el abogado del seguro de decesos. Propiedades no tienen porque vivían en una vivienda social. Hay una cuenta, no saben el saldo. Cree que hay deudas con la Seguridad Social. Nos mantiene informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2020-03-12','TERESA: FUTUEX ROSARIO RESIDE EN EL DOMCILIO FAMILIAR CON SU MADRE LUISA, UNA MADRE SOBREPROTECTORA QUE NO DEJA QEU SU HIJA AVANCE O SALFA DE CASA Y SE RELACIONE CON GENTE DE SU EDAD, TIENE NOVIO ANTONIO DE MONESTERIO QEU LA LLAMA A DIARIO Y LA VISITA UNA VEZ AL MES. SE ROMPIO EL HOMBRO EL PASADO MES DE MAYO Y ESTUVO CON EL BRAZO VENDADO DURANTE SEMANAS, Y LUEGO RECIBIO SESIONES DE REHABILITACION, PERO EN LAS ULITMAS VISITAS AL MEDICO REHABILITADOR LE DIJERON QUE EL HOMBRO NO SE HABIA COLOCADO BIEN Y NO HABIA OPERACION POSIBLE. ESTAN PENDIENTE DE UNA VISITA AL TRAUMATOLOGO PARA QUE ESTE LES DIGA EL SIGUIENTE PASO. ROSARIO ES UNA PERSONA MUY DESCONFIADA QEU NO QUIERE PARTICITPAR EN ACTIVIDADES EN SU COMUNIDAD COMO NO SEA CON SU MADRE. SE LE HA PROPUESTO EN MULTITUD DE OCASIONES SALIR A DAR PASEOS O VISITAR LA UNIVERSIDAD POPULAR DE SU PUEBLO Y AUNQUE NO HA SIDO UN NO ROTUNDO, A LA HORA DE HACER LAS VISITAS SIEMPRE ESTABA ENFERMA Y NO PODIA SALIR DE CASA, SOLAMENTE HEMOS SALIDO A DAR ALGUN PASEO EN CUATRO OCASIONES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-03-12','TERESA: FUTUEX VIVE EN LA CASA FAMILIAR JUNTO A SU HIJO SU PADRE Y SU HERMANO EN FUENTE DE CANTOS. LA RELACION CON SU PADRE ES MUY TENSA Y HA PROVOCADO ENFRENTAMIENTO FISICO ENTRE LOS DOS. VA DOS VECES A LA SEMANA A LOS TALLERES DEL CRPS Y DESDE ALLI LA AYUDA A LA ADMINISTRACION DEL DINERO Y LE ASESORAN PSICOLOGICAMENTE CON AL PROBLEMATICAS FAMILIARES ES UNA PERSONA CON IDEAS MUY CAMBIANTES QUE TAN PROTNO SE QUIERE IR A UNA RESIDENCIA COMO DICE QUE SE QUIERE QUEDAR EN CASA HA ESTADO EN EL HOSPITAL DE LLERENA EN LAS ULTIMAS SEMANAS UN PAR DE VECES PARA QEU LE CAMBIEN EL TRATAMIENTO PORQUE TENIA MUCHA ANSIEDAD POR COMER.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2020-03-12','TERESA: FUTUEX RESIDE EN EL CENTRO FRANCISCO ASUAR DESE EL PASADO NOVIEMBRE. HA NECESITADO VARRAS SEMANA PARA ADAPTARSE A LA RUTINA DEL CENTRO Y HA DEMANDADO MUCHO IRSE A SU CASA A PASAR UNOS DIAS, ESTA EN EL TALLER DE LAVANDERIA Y SE ENCUENTRA MUY CONTENTA EN EL MISMO. TIENE UNA RELACION DE DEPENDENCIA Y BASTANTE TOXICA CON ANTONIO, UN HOMBRE DEL CASAR DE CACERES QUE LE EXIGE QUE VAYA A VERLE A CADA POCO TIEMPO, PERO EL NO ACUDE A VISITARLA PORQQEU SEGUN ELLA NO PUEDE ESTAS NAVIDADES HA ESTADO EN CASA DE SU HERMANA Y HA PASADO TIEMPO CON SU HIJA MAYUR AUNQUE PARTE DE LOS DIAS E INCLUSO ALGUNA LA HA PASADO EN CASA DE ANTONIO DESDE HACE UNAS SEMANAS ESTA MUY PESADA PIDIENDO IRESE A CASA EN LOS CARNAVALES Y CUANDO S ELE PREGUNTA POR QUE NO SABA DAR UNA RESPUESTA CLARA. SE CREE JUNTO CON EL PERSONAL DEL CENTRO QUE M EUGENIA ESTA RECIBIENDO PENSIONES POR PARTE DE ANTONIO PARA QUE VAYA A VERLE O LA DEJA Y ELLA QUIER IR A CUMPLIR SUS DESESOS LA MEJOR OPCION ES M EUGENIA PERMANEZCA EN EL CENTRO Y LA RECLACION CON ANTONIO SE EXTINGA. PARA QEU ELLA PUEDA ADAPTASE POR COMPLETO Y NO TENGA ESA OBSESION POR IRSE A CACERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-03-12','TERESA: FUTUEX RESIDE EN UN PISO DE ALQUILER EN MONESTERIO CON SU PERRO NERON, SU PERRO ES SU VIDA Y SE OCUPA ANTES DE EL QUE DE SI MISMA. EL DIA 24 DE ENERO ESTUVO EN EL HOSPITAL DE LLERNA PORQUE HABIA INGERIDO GRANDES CANTIDADES DE ALCOHOL Y PASTILLAS SE LE PORPUDO INGRESO EN LA UHB AL QUE ACCEDEIO DE BUEN GRADO PERO AL CABO DE UN PAR DE HORAS PIDIO EL ALTA Y SE LE CONCEDIO AL FINAL DE LA MAÑANA ESTA PENDIENTE DE CITA DE MEDICINA INTERNA UA QUE LLEVA MAL CON EL ESTOMAGO DESDE HACE UNOS MESES COMNENTA QUE TIENE VOMITOS POR LAS NOCHES Y NO PUEDE TOMAR ALCHOHO PORQQUE LE SIENTA FATAL, TENIA CITA EL 19 DE FEBRERO PERO LA HAN CANCELADO DESDE EL HOSPITAL Y VOLVERAN A LLAMARLA PARA NUEVA CITA EN LA ACTUALIDAD MARIA COMENTA QUE NO ESTA CONSUMIENDO ALCHOL NI PORROS PORQUE YA NO LE HACEN NADA Y PREFIERE LIMPIARSE DURANTE UN TIEMPO ANTES DE VOLVER A CONSUMIR TIENE CITA EN SALUD MENTAL EN LLERENA EL PROXIMO 7 DE ABRIL A LAS 12:10 CON EL DOCTRO IDILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2020-03-12','Buenas tardes a ambas; os traslado que hace ya más un año de la derivación de Mercedes P. P. a nuestro centro, durante este año han sido numerosos los intentos de iniciar proceso, no siendo esto aceptado por Mercedes e incluso las ultimas ocasiones se ha mostrado suspicaz, valorando por nuestra parte que no es terapéutico seguir insistiendo. Ante esto y viendo en diferentes entrevistas con ella, que su valoración acerca de los cambios en su vida es positiva, así como considera suficientes los apoyos que se le están facilitando pare ello, voy a proceder a sacarla de la lista de espera. No obstante Mar si en un futuro todo esto cambia, podéis de nuevo proceder a una nueva derivación, entiendo que el que tenga vinculación con el esm es crucial, dado la conciencia relativa de problema que tiene. En los últimos contactos mantenidos con Mercedes me refería que el seguimiento lo esta llevando a cabo en una clínica privada, le insistí en que acudiera a las citas con Fernando. ANA DELFA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-03-12','-Amalia : llama Eva , TS de P.I.Montijo , se acuerda que va a buscar una pensión donde poder ir para cumplir la orden de alejamiento del padre. Al parecer hay otra denuncia por parte de la madre por malos tratos. Tiene en cuenta 800€ y se le dan 70€ a la semana .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-03-12','(Pedro) Asisto a la Subcomisión de casos convocada para tratar la situación de D. Juan Ángel. +++CONCLUSIONES: +++++Se considera que NO debería estar incapacitado. +++++Se trata de un inadaotado social que simplemente se aprovecha del sistema todo lo que puede. +++++En estos momentos se plantea el Alta en el momento que se vuelva a escapar, ya que si bien su comportamiento en el Centro no pasa de insultos y malas palabras también es cierto que no tiene intención de aceptar ayuda alguna y solo pretende que se cumplan sus exigencias. +++++Se entiende que en estos momentos y dada la sentencia de incapacitación no se puede dejar en la calle a esta persona. +++PROPUESTA desde la Comisión: redactar un Informe en el que se recojan todas estas opiniones de los presentes, de manera explícita (tanto como lo han sido en el reunión) y se envíe al Juzgado. +++++En cualquier caso, se recogeran en el Acta de la misma todas estas conclusiones y propuestas, para ser remitidas al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2020-03-12','-Buenos días, nos dirigimos a ustedes para informarles de la situación tan alarmante (ya comunicada en reiteradas ocasiones) que estamos viviendo con la tutelada Minerva Martín Blanco. Informar que la Entidad se está planteando seriamente suspender de manera temporal la asistencia de la usuaria al centro, debido a la grave falta de higiene y pediculosis. Hemos tratado por todos los medios trabajar con el objetivo de facilitar hábitos de higiene y responsabilidad, ante la imposibilidad y la gravedad del asunto ante el contagio de sus compañeros y monitores continuamente ( se ha comprobado que el foco se encuentra en ella, se le realiza tratamiento desde clínica “Picapicapum” que utiliza tecnología profesional y garantiza un tratamiento efectivo de forma personalizada, y nos informa que si el foco reside en el domicilio y en el entorno no sirve de nada ), nos vemos opción alguna. Y para que conste donde sea oportuno, a la espera de su parecer, P.I. MERIDA','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2020-03-12','-Buenos días, nos dirigimos a ustedes para informarles de la situación tan alarmante (ya comunicada en reiteradas ocasiones) que estamos viviendo con la tutelada Minerva Martín Blanco. Informar que la Entidad se está planteando seriamente suspender de manera temporal la asistencia de la usuaria al centro, debido a la grave falta de higiene y pediculosis. Hemos tratado por todos los medios trabajar con el objetivo de facilitar hábitos de higiene y responsabilidad, ante la imposibilidad y la gravedad del asunto ante el contagio de sus compañeros y monitores continuamente ( se ha comprobado que el foco se encuentra en ella, se le realiza tratamiento desde clínica “Picapicapum” que utiliza tecnología profesional y garantiza un tratamiento efectivo de forma personalizada, y nos informa que si el foco reside en el domicilio y en el entorno no sirve de nada ), nos vemos opción alguna. Y para que conste donde sea oportuno, a la espera de su parecer, P.I. MERIDA','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2020-03-12','-Buenos días, nos dirigimos a ustedes para informarles de la situación tan alarmante (ya comunicada en reiteradas ocasiones) que estamos viviendo con la tutelada Minerva Martín Blanco. Informar que la Entidad se está planteando seriamente suspender de manera temporal la asistencia de la usuaria al centro, debido a la grave falta de higiene y pediculosis. Hemos tratado por todos los medios trabajar con el objetivo de facilitar hábitos de higiene y responsabilidad, ante la imposibilidad y la gravedad del asunto ante el contagio de sus compañeros y monitores continuamente ( se ha comprobado que el foco se encuentra en ella, se le realiza tratamiento desde clínica “Picapicapum” que utiliza tecnología profesional y garantiza un tratamiento efectivo de forma personalizada, y nos informa que si el foco reside en el domicilio y en el entorno no sirve de nada ), nos vemos opción alguna. Y para que conste donde sea oportuno, a la espera de su parecer, P.I. MERIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-03-12','miguel, hablo con Mila de la Notaria de Carlos Rebosa (Zafra), me comenta que la escritura de herencia la tiene paralizada porque falta mucha documentación. En la oficina tenemos algún original como la escritura de donación de la casa a favor de la curatelada, sin embargo Mila también tiene algún original pero no sabe cuáles. ********************************* Mirará despacio el expediente y me enviará un email explicativo para que a su vez se lo remita, a través de Teresa Ts, al Centro para que la Curatelada entregue la documentación, que me pida en ese email Mila, a alguien de confianza como Futuex, y éstos me entreguen dichos originales para a su vez yo hacerselos llegar a la notaria de zafra (Mila). ************************************* Me comenta que a parte de la casa mencionada que ya es de la curatelada (por donación), hay dos rústicas en hoyos (Feria, Badajoz) de la cual ella tenía legado (por testamento de la madre) y 1/3 parte por testamento del padre, que también había al menos una cuenta en antigua Caja Badajoz (hoy Ibercaja)cuyo certificado de saldo habría que actualizar. ************************************************** Me comenta que la curatelada también la tenía que haber indicado direcciones y teléfonos de los hermanos y no lo ha hecho. Y por otra parte, la ha confirmado la curatelada que sus hermanos (hermano y hermana) no se hablan con ella ni tienen intención de firmar nada en la notaria. Yo le explico a Mila que nosotros intentemos preparar y firmar dicha herencia y si los hermanos no lo firman podremos levantar un acta de constancia (de que hemos intentado firmar la herencia, y con ello podríamos reclamar su firma en un juzgado a su hermano y hermana) ******************************************* Quedamos por tanto, que me remitirá email con lo que necesite y yo se lo solicitaré al Centro(a través de Teresa Ts) para que nos lo remitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-03-12','(Pedro)Conversación con MªÁngeles (P.I. Llerena): +++Beatriz está muy bien adaptada al Centro y al trabajo en C.O. +++Las visitas a su hija son muy positivas para ella aunque requiere apoyo de tercera persona. +++La abuela paterna se muestra muy recepctiva a facilitar dichas visitas, en las cuales NO ESTÄ PRESENTE ANTONIO (padre de la niña). +++Han ido a visitar a Beatriz sus padres (padre y madre). +++Beatriz está saliendo con un chico en estos momentos. Sigue mostrando bastante resistencia a la administración del inyectable, el cual es imprescindicble más si cabe ahora que tiene una relación de pareja. No obstante, desde el Centro está muy pendientes de las citas de Planificación Familia y de la relación que mantiene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2020-03-10','(Pedro). Amalia me netrega Acta provisiónal de la Subcomisión realizada el pasado 06 de marzo. El punto más "conflictivo" es el que hace referencia a que los especialistas proponen informar a los padre "...de cuestiuones exclusivamente médico/clínicas dada la insitencia de estos..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2020-03-11','(Pedro) +++Consulto con Miguel y Ángel al respecto de la demanda de los Psiquiatras, porque considero que siendo precisamente el aspecto médico/clínico el que ha dado lugar a que haya sido la CTAEx la encargada de asumir la tutela (dada la rotunda oposición de los padre y hermano de todo aquello que provenga de la medicina convencional) no creo que se deba mantener informados a los padres de todo ello de manera pormenorizada, desconfianso además de los motivos que ellos tienen para que así sea. +++Planteo esta opinión a Soraya, pero considera que los médicos manifiestan que el no tenerlos informados de ello les está generando una ansiedad que terminan transmitiendo a Rubén. Sigo manteniendo mi ponión al respecto, epro en cualquier caso reflejarán esta situación en el Acta definitiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-03-12','TERESA: FUTUEX PILAR HA DIDO TRASLADADA AL HOSPITAL SANTIAGO DE ZAFRA DESDE CACERES A PRIMEROS DE FEBRERO DESDE QUE HA LLEGADO AL CENTRO SE HA ADAPTADO MUY BIEN SE HA VISITA UNA VEZ Y ESTABA MUY CONTENTA ESE DIA PORQUE IBA A SALIR PARA HACERSE FOTOS DE CARNE Y ASI RENOVARLO SUSANA LA TRABAJADORA SOCIAL HABIA PEDIDO QUE LA COMISION DE UN EXTRA PRA PODER SALIR CON ELLA A COMPRARSE ROPA Y ZAPATOS PUES LLEVABA ROPA DONADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-03-11','miguel, llega el expte físico desde abogacía general de la Junta, en relación al procedimieno de revisión de incapacitación de curatela a tutela (que quedó desistido por la parte actora Ministerio Fiscal, y a la cual no se opuso la parte demandada (abogacía en representación del curatelada)) ****************************************** Visto con Ana Ts, donde aporta 3 documentos ( informe del psiquiatra Juan José Molina Castillo de fecha 13-2-2020; informe social de Futuex de 6-2-2020; e informe de derivación de la UME DE 26-2-2020) a efectos de ver con Pedro Js (para me diga si merece comenzar de nuevo un procedimiento de revisión de incapacitación o bien hablar él directamente con Carmen Barquilla MF, a los efectos de ver qué hacemos con este curatelado que debería estar internado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-12','Ana: Tras valorarlo con Pedro, jefe secc. CTAEX, y ver los ahorros de Margarita, llamo a Pilar Sánchez, Hogar San Vicente de Paúl (671 016 615), hemos acordado que nos remitan presupuesto de Atención Psicológica al ctutelar@ para que comience a asistir a terapia. Por otra parte, le facilito el nº teléfono de la Federación Plena Inclusión, he hablado con Almudena Medina, Técnica de la Federación y Sexóloga, pueden atenderla aunque no asista a ninguna entidad federada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-03-12','TERESA: FUTUEX RESIDE EN UN PISO DE ALQUILER CON SU PADRE, PACO EN JEREZ DE LOS CABALLEROS, ES UNA CHICA JOVEN QUE TIENE SOBREPESO Y QUE SE CUIDA POCO. COME COMPULSIVAMENTE TODO TIPO DE BOLLERIA INDUSTRIAL U NO HACE NADA DE EJERCICIO TIENE MALA HIGIENE PEROSNAL PORQUE HUELE MAL A MENUDO Y AUNQUE SE LE INSISTE EN LA IMPORTANCIA DEL AUTOCUIDADO ELA ASEGURA DUCHARSE A DIARIO Y CAMBIARSE DE ROPA NO TIENE NINGUN CONTROL SOBR SUS CITAS MEDICAS QUE QUE CUANDO LE TOCA INYECTABLE NUNCA LLEGA A LA HORA O VA EL DIA SIGUIENTE. EN ESTA ULTIMA OCASION DIRECTAMENTE NO HA IDO AUQNEU SE LE HA AVISADO PREVIAMENTE. Y CUANDO SE LE HA CONFRONTADO EL TEMA HA MENTIDO FRIAMENTE TIENIA UNA CITA PARA UNA RADIOGRAFIA DE LA RODILLA Y LA PERDIO PORQUE NO SE ACORDO O NO LE APETECIA IR ASI ES QUE TIENE UNA CITA CON SU MEDICO EL 17 DE FEBRERO PARA QUE LA VUELVA A PEDIR NO COLABORA EN NINGUN ASPECTO DE LIMPIEZA DE LA CASA, AUNQUE DICE QUE A VECES FRIEGA LA LOZA Y HACE LA CAMA, TIENE UNA AYUDA A DOMICILIO Y A PARTE SU PADRE TIENE LEY DE DEPENDENCIA POR LO QEU ELLA NO SE PREOCUPA POR EL ESTADO DE LA CASA DEMANDA UN EXTRA PARA COMPRARSE ROPA INTERIOR Y ZAPATOS, EL UNO DE MARZO ES SU CUMPLEAÑOS PERO NO TIENE NINGUN TIPO DE CONTROL SOBRE EL DINERO QUIERE CAMBIARSE A OTRO PISO DE ALQUILER POR LA ZONA DEL POMAR, E INCLUSO HA IDO A UNA AGENCIA INMOBILIARAIA A PREGUTAR. POR AHORA NO HA ENCONTRADO NADA POR 250 EUROS AL MES PROXIMA CITA INYECTALBE 28 FEBRERO 12:30 NO TIENE CITA PARA SALUD MENTAL PORQUE AHORA NO HAY SERVICIO EN JEREZ Y TIENE QUE REEXPLAZAR A LA PSIQUIATRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-03-12','-Amalia : me informa Carmen Ferrer que por el tema del coronavirus no se procederá a realizar traslados de momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-13','Ana: Recibo llamada de Damián (622 834 876), dice que le han llamado del banco, que le han dicho que no han conseguido ponerse en contacto con la CTAEX. Le digo que las compañeras han intentado ponerse en contacto con la oficina de Málaga y que no han conseguido hablar con nadie. Volverán a intentarlo. En cuanto al cambio de entidad bancaria, dice que él prefiere que no sea así, pues tiene prestamos varios de los que debido al bloqueo de cuentas ya debe varios recibos: Cetelén, Cofidís y otro préstamo del propio Banco Popular. Ya le he explicado que estamos pendiente de que nos envíen del Jdo. la Firmeza de la Aceptación del Cargo, sin la que en el banco no añaden al Tutor como titular en la cuenta para poder operar desde la CTAEX. //////////////////////////////////////////// Tras valorarlo con la secc. ecca., finalmente se le cambiará la pensión de entidad bancaria y se realizará una trasnferencia periódica mensual a la cuenta del Popular para pagar los distintos préstamos. ////////////////////////////////////////////////////// Cumplimento la COMUNICACIÓN DE VARIACIONES al INSS, para cambio de nº de cuenta. Subo a por la firma y lo pongo para REGISTRO DE ENTRADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2020-03-12','Ana: Recibo llamada de Sonia Bernabé - Asindi: Por prevención ante la expansión del COVID-19, los hermanos no se irán a casa el fin de semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2020-03-12','Ana: Recibo llamada de Sonia Bernabé - Asindi: Por prevención ante la expansión del COVID-19, los hermanos no se irán a casa el fin de semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-03-13','Ana: Hablo con Mai - Jefa de secc. mayores, mirará la situación de la solicitud de cambio de centro por PIA de María Isabel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-03-12','(Pedro) Llamada de Eduardo, Psicólogo de P.I. Zafra. +++Ante las recoemndaciones propuestas desde el Equipo de Inspección, plantea la duda sobre qué hacer este fin de semana en relación a la salida de fin de semana de Natalia si, como se propone en dichas recomendaciones, no se puede privar del derecho de visita (a priori) Cuestionado sobre su comportamiento, este no ha sido bueno durante la semana, pero insistiendo en aspectos positivos refiere que también ha habido algunos, pero no de tanta relevancia como los negativos.Al respecto se plantea lo siguiente, tratando de combinar en la medida de lo posible lo concluido en las reuniones con las recomendación de Inspección: +++Las salidas están sujetas al acompañamiento, ida y vuelta, de Natalia por parte de los abuelos paternos. +++Si bien su comportamiento ha dejado basatante que desear, hacerle ver que la salida de est fin de semana se permite por aquellas "pequeñas cosa" que ha hecho bien. +++Dada la "mochila vital" que acompaña a Natalia, se insiste en que cualquier pequeño avance en su comportamiento se ha de reforzar como si dicho avance fuese mucho mayor, debiendo temer toda la paciencia necesaria para ir progresando adecuadamente en ello. Esto no quita para que, en caso de riesgo para ella o para terceros, se tomaran las medidas oprtunas ya mencionadas en las reuniones, incluida en su caso potenciales dencuncias. +++En caso de que las salidas no deban ser autorizadas a juicio del Centro, se ha de hacer ver que no es el centro el que provoca la decisión, sino la propia Natalia con su comportamineto (o sus abuelos en caso de que no puedan o no quieran seguir yendo a por ella como se quedó con ellos). Y para no restringir el derecho de visita, en este caso se pueda plantear a los abuelos que la visiten en el Centro y que pasen el día con ella. +++SI los motivos para impedir las visitas tuvieran la consideración necesaria para restringir este derecho, se tomaría dicha decisicón como última opción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-03-03','Ana: Recibo llamada de Felisi y Jesús, pareja de Felisi (722 494 033). Jesús cuenta le que le ha despedido por un problema con un compañero. El día 6 de marzo Felisi tiene cita en Planificación Familiar en Alcántara, para la revisión del DIU. Piden un extra para el cumpleaños de Felisi, que será el próximo día 19. *Se lo paso a Alberto, jefe de la sección económica. Se le autorizarán 50 € la semana del cumpleaños. ///////////////// *En cuanto al Seguro de Hogar, hay un error en la documentación del Seguro, no tiene póliza de hogar, sólo de deceso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2020-03-13','(Pedro)Nuevo intento de comunicar con Reyes Picazo (616-974816) en relación al tema del juicio en curso. +++No coge el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-03-13','Ana: Recibo llamada de Felisi y Jesús (722 494 033), preguntan por la herencia. Su hermana no deja de agobiarla con el tema y el sobrino quiere que vaya a firmar ella a notaría. Le explico que eso no puede ser y que esté tranquila que mientras desde aquí no se firme nada su hermana no puede hacer nada. Quieren hablar con el Asesor Jurídico para que les informe bien. **Paso nota a Ángel-CTAEX, para que le llame cuando pueda. **En cuanto a los arreglos de la vivienda, enviarán presupuestos cuando puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2020-02-20','Ana: Reunión con Paula, Javier y Blanca - CRR. Mª Ángeles presenta mucha vulnerabilidad social. *En el informe de salud mental no constaba la Discapacidad Intelectual. *En el Dictamen del CADEX sí aparece. *Presente incontinencia urinaria y fecal ocasional. Se está adaptando bien, está contenta en la residencia. Participa en las actividades. Ha mejorado en comunciación, expresividad y relación con los demás. **Valorarán el paso a recursos residencial de Discapacidad. Por otra parte, ya ha comenzado el Tto. Dental por el PADDI (Programa de Asistencia Dental a la población con Discapacidad Intelectual).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-02-20','Ana: Reunión con Paula, Javier y Blanca - CRR. A Toñi le están reduciendo la medicación en Salud Mental. Participa en actividades del centro. Ya es capaz de pedir ayuda a los profesionales. Comienza a plantearse/aceptar la idea de pasar a piso como paso previo a vivir de forma independiente. La familia también refiere un cambio positivo. **Aunque NO termina de aceptar su diagnóstico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-03-10','Ana: Pregunto a Clara, Jefa de Secc. de Calidad de Sist. de Dependencia, por el expte. de Pedro Román, a finales de noviembre el Técnico envió el PIA aceptado y firmado y aún no está cobrando la prestación vinculada. /////////////// Me pide que haga, registre y le lleve Informe Social, conforme al modelo establecido por la priorización que hizo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2019-05-21','miguel, llega email de la hermana de Jose A. Barros Cordero (Tutelado)indicandonos que falleció su padre José Barro Barrena, y al hacerle la declaración de renta dl 208, le han salido a devolver 1522,14€.Para poder cobrar ese dinero hay que presentar el modelo H-100 (devolución a los herederos). Junto a esa solicitud hay que presentar una serie de documentos, entre ellos se pide una autorización escrita y firmada por todos los herederos, junto con el dni de todos ellos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2019-05-23','miguel, no contesta su hermana Carmen Barro Cordero (karmelabarro@hotmail.com), nos contesta vía email, que todavía no han hecho la escritura de adjudicación de herencia (que lo único que han hecho ha sido pagar el impuesto de sucesiones y donaciones). De los documentos solicitados en mi email de ayer dice le falta alguno y que en cuanto lo tenga nos lo envía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2019-05-22','miguel, la llamo pero no logro localizarla (móvil 679708252) y la mando un email donde la comento " que al tratarse de una persona tutelada, es necesario que cualquier actuación que hagan relacionada con el tutelado debe ser previamente atorizada), y es por ello por el que le solicito la siguiente documentación: indiquenos si ya está o no hecha la adjudicación de herencia del fallecido padre Don Jose A. Barros Cordero y si han procedido ya a la liquidación del impuesto de sucesiones y donaciones. En cualquier caso necesitamos, certificado de defunción, certificado de últimas voluntades, testamento (si lo hubiera), escritura notarial de adjudicación (si la hubiera), caso contario necesitamos notas simples y cetificados catastrales de todos los bienes muebles del fallecido, del mismo modo que tendrán que aportamos certificados bancarios de todas las cuentas ( corrientes, cuentas de valores, fondos de inversiones...) Necesitamos también el documento de IRPF que indica el importe de esa devolución. Y que nos indique si hay algún profesional tramitando esa herencia ( abogado/gestoría)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-03-13','-Tras la orden de alejamiento del padre , desde ayer se queda a dormir en una habitacion en el hostal " La isla " de Montijo. TF 924455557. Email : info@hostallaisla.es Les he llamado , para decirles que FCO. PINILLA BAENA estará ahí durante días .Se lo abonaremos semanalmente. El psiquiatra, Dtor Pino , ha solicitado CRR por emergencia . Para pisos y UHDAC no ha dado pérfil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2019-06-21','miguel, recibimos email de la hermana del tutelado Carmen Barro Cordero (karmelabarro@hotmail.com)indicando que el procedimiento lo lleva el abogado Emilio Gomez Canseco (tlf 924800360, móvil 679412235','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2019-08-23','miguel,remito al abogado Emilio Gomez Canseco a su email 10622@icaba.com: "Buenos días, en relación a los emails intercambiados por su representada Doña Carmen Barro Cordero, que es hermana del tutelado por esta Comisión Tutelar de Adultos de la Junta de Extremadura. Nos ponemos en contacto con usted ya que uno de los herederos de la herencia arriba indicada, nos informe del estado en que se encuentra y nos remita la documentación que obre en su poder a efectos de su estudio y si fuese preciso solicitud de autorización judicial para la aceptación de dicha herencia. Como le indico es necesario que para cualquier actuación que hagan relacionada con dicha herencia y que pueda afectar a nuestro tutelado habrá de ser previamente autorizada. Es por ello q necesitamos nos aclare algunos datos y nos aporte una serie de documentación: Indiquenos si ya han hecho la escritura de Adjudicación de Herencia del fallecido padre de Jose A. Barros Cordero o si han procedido ya a la liquidación del impuesto de sucesiones y donaciones, en definitiva que nos indique en qué estado de tramitación se encuentra dicha herencia. Asi mismo necesitamos nos aporten, certificado de defunción, certificado de últimas voluntades, testamento (si lo hubiera), escritura notarial de Adjudicación de herencia (si la hubiera), caso contrario necesitamos notas simples y certificados catastrales de todos los bienes inmuebles del fallecido, del mismo modo que tendrán que aportarnos certificados bancarios de todas las cuentas (corrientes, cuentas de valores, fondos de inversiones...). Necesitamos también el documento de IRPF que indica el importe de esa devolución de la renta del año 2018 de IRPF del fallecido padre José Barros Barrena, por importe de 1.522,14€".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-03-13','miguel, hablo con el Jzdo nº4 de Plasencia y me confirma que se aplaza por el coronavirus la citación del 16-3-2020(por videoconferencia ante los jzdos de Mérida) se aplaza al 27-4-2020 +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ABOGADA: Mª Estela Barbero (Col. 1301)','2');
