insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2020-03-13','TERESA:: paso a Julio para que envíe a MUFACE, por correo certificado, la Declaración de persistencia de requisitos para la percepción de la PFHC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2020-03-13','(Teresa/Pedro)Llamada/conversación con Mª Carmen, T. soc. de la Residencia J.C.Rodríguez Ibarra (20259). +++Blas se ha escapado del centro esta mañana porque no aceptaba la prohibición por seguridad sanitaria. +++Se le indica que si vuelve a ocurrir que traten el tema como si de una fuga se tratase. En cualquier caso, se ruega que traten de impedir que se vuelva a ir, como de hecho ha amanazado para esta tarde, tratando de retenerlo a la vez que se avisa a al Policía. En caso de que no lleguen a tiempo no excponerse innecesariamente a una potencial agresión y denunciar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-03-16','TERESA:Te escribo para informarte de que finalmente Natalia se ha ido a casa con sus abuelos a Badajoz. Tras una llamada, a petición de Natalia, a su abuela para pedirle que se la llevara, la abuela ha accedido y han venido a recogerla. Le hemos entregado la medicación, la cartilla sanitaria y 50€ a su abuela para que administre el dinero para comparas necesarias en estos días. Además, de un montón de recomendaciones para que, esperemos, vaya todo bien. Confiamos que así sea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2020-03-13','Ana: Correo de Obdulia, TS HSPA (927 25 63 48): se informa que a criterio facultativo la paciente presenta cuidados continuos e intensos asistenciales por lo que no puede regresar a domicilio .(Como así se le ha comunicado a la Educadora Social de FUTUEX Gloria).Por tanto se solicita que contacten a la mayor brevedad posible con esta UTS del HSPA 927256348 y/o 616941742 por estar programada su alta hospitalaria el lunes 16 marzo 2020. /////////////////////////////// Pedo, jefe secc. CTAEX, habló con Obdulia. Se le solicitará plaza sociosanitaria. Nos enviará la solicitud de plaza para la firma del D.Gerente. En cuanto a la documentación pertienente Juli, CTAEX, solicitó Certificado de Convivencia a Torreorgaz. Se le remitirá también fotocipia del DNI (en expte.) y fotocopia del Certificado de Pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-03-16','TERESA: ENVIO CEDULA DE CITACION PAR EL 16/04/2020 A FUTUEX PARA QUE LA ACOMPAÑEN','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-03-13','Ana: Recibimos RESOLUCIÓN del INSS, han resuelto aprobar con fecha del 05/03/2020 la prestación de Orfandad: 208,90 € x 14. Primer periodo de pago: 01/11/2019 - 31/03/2020. Importe Líquido del primer periodo: 1075,20 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-03-16','(Pedro) Llamada de Teresa (618-819511), Hermana de José Mª. +++"Ha acudido esta mañana el técnico de Caser y ha dicho que él entiende de caldseras, no de calentadores...Ha cortado el agua..." +++Llamo a D.Pedro Herrera. Llamará de nuevo a la compañía para que envíen a alguine que pueda reparar la avería.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-03-16','TERESA: FUTUEX RESIDE CON SU HERMANO MAYOR Y SU MADRE EN LA CASA FAMILIAR EN JEREZ DE LOS CABALLEROS, SU MADRE SE IBA TODOS LOS DIAS A DESAYUNAR COMER Y CENAR A UNA RESIDENCIA CERCANA PERO HACE UNAS SEMANAS NO QUIERE IR Y RAMON REPARTE SU COMIDA CON ELLA SE MANTIEN MUY OCUPADO EN UN CAMPO QUE TIENE CUIDADNDO DE SUS ANIMALES Y DEL HUERTO AUQEN UQ A VECES GASTA MUCHO DINERO EN EL PIENSO YA QEUT TIENE MAS ANIMALES DE LOS QUE PUEDE MANTENER Y AUNQUE SE HA HABLADO DE ESTE TEMA EN VARIAS OCASIONES CON EL NO QUIERE HACER NADA AL RESPECTO SE HA PUESTO INYECTABLE EL 13 DE FEBRERO Y LA HA HECHO SIN PONER NINGUNA OBJECION AUNQUE NO LO HA PAGADO EN LA FARMACIA ALEGANGO QUE YA NO LE QUEDABA DINERO TIENE ESTROPEADA LA LAVADORA DE UN PAR DE SEMANAS Y NO PUEDE LAVAR LA ROPA. SE LE HA PREGUNTADO SI HA IDO A LA TIENDE DE ELECTRODOMESTICOS O HA HECHO ALGO SOBRE ESE TEMA Y HA DCHO QUE NO. SE LLAMO A LA TIENDA DE AGAPITO PARA COMENTAR LA PROBLEMATICA DE LA LAVADORA Y COMENTARON QUE NO HAY TECNICOS QUE LA ARREGLEN Y QEU PROBLAMENTE SE LE HABIA IDO LA PLACA ELECTRONICA, POR LO QEU SERIA MAS BARATO COMPAR QUE ARREGLAR UNA PROXIMA CITA INYECTABLE 23/04/2020 10:30 HORAS NO TIENE CITA PARA SALUD MENTAL PORQUE AHORA EN JEREZ NO HAY SERVICIO TIENEN QUE REEMPLAZAR AL PSIQUIATRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-03-16','Ana: Recibo llamada de Mai, Jefa de Secc. de Acceso a Rec. Mayores (68496). Me comunica que Isabel no tiene pedido el cambio de centro a la Res. S Fco. de Plasencia. Al principio no cumplía criterio por edad (era muy joven), a día de hoy ocupa plaza pública en Jaraicejo. *Habrá que inciar el procedimiento de solicitud de centro por cambio de PIA. ///////////////////////////////////////////////////////////// Reviso el expte. papel: encuentro una fotocopia de "Solicitud de Revisión y/o cambio de circunstancias" solicitando Rvisión PIA: traslado a la residencia de mayores San Fco. de Plasencia por acercamiento familiar, firmado por Mª Consolación Serrano a fecha de 20 de abril. Pero no hay copia de oficio registrado. /////////////////////////////////////////// Llamo a Carmen García, TS Técnico PIA del EVD Plas: Mirará en el expte. de Isabel, pues de memoria no me sabe decir. Me enviará un mail cuando averigüe algo. /////////////////////////////// Hablo con Gema, Registro SEPAD, encuentra y me saca en papel la copia del oficio que se registró a fecha de 25/04/16. Encuentra y me entraga otra copia de otro oficio adjuntado solicitud de Cambio de Centro Residencial registrado por la T.S. del SSB Mª Jesús Gómez a fecha de 18/01/16. ////////////////////////////////////////////// Vuelvo a hablar con Mai, tras volver a revisar ella, se da cuenta de que sí que está, se encuentra la primera en lista de espera para Traslado.','2');
