insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2020-03-16','Ana y Pedro: Llamada a Obdulia, TS del HSPA (927 25 63 48), de momento como desde el SEPAD está todo paralizado y no se va a realizar ningún tipo de ingreso en C.Residenciales, de momento María tiene que seguir allí en el Hptal. Se le informa que ya se han solicitado los cdos. de Convivencia y de Pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN LUIS'and edp.apellido1='ANTONIO'and apellido2='REMEDIOS'),'2020-03-16','TRASLADO El 16/03/2020. "Se comunica a esa Comisión Tutelar de Adultos que el interno Juan Luis..., ingresado en este Centro y tutelado por esa Comisión, será trasladado al Hospital de Mérida, en fecha 16/03/2020."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2020-03-17','(Pedro). +++Intento comunicar con la T. Soc. de Torreorgaz, Alicia, para tratar de tramitar lo antes posible el certificado de convivencia. No me coge el teléfono (927-205001).No se encuentra en Torreorgaz sino en la Mancomunidad (927-389030). Me toman nota y me llamará Alicia. +++Intento contactar con Pensiones de la Seguridad Social para agilizar el certificado de pensiones pero tampoco cogen el teléfono (927-214884).Finalmente contacto con Seguridad Social: no se puede agilizar, van tramitando a medida que entra el correo. Quedo en llamar el Jueves de nuevo. +++Conversación con Alicia, T. Soc. de Torreorgaz (927-215588///tsocial3@mancomunidadsierrademontanchez). +++Ya se han remitido todos los docuemntos para la solcitud de T-2 a Obdulia (obdulia.romero@salud-juntaex.es) ///////////////////////////////////////// Ana: Converación con Luli (Obdulia), TS del HSPA: hoy mismo trasladarán a María a la Res. Virgen de la Montaña del Casar de Cáceres. En esta residencia estará de forma temporal, pues la plaza se la han asignado en al Res. San Jorge, de CC (perteneciente al mismo grupo de residencias: Ciudad Jardín) pero ésta se encuentra en obras en estos momentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-17','(Pedro) Llamada de Beatriz Espinosa, del Banco de Santander.Derivo a Iciar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-03-17','(Pedro)Conversación con Juan Carlos, a petición de Manoli, T. Soc. del Psiquiátrico Penitenciario de Sevilla (954-856048). +++"Cuando se pone nervioso y pide hablar con su tutor es lo único que le tranquiliza..." +++Hablamos de fútbol (es culé), le han comprado una equipación de portero del Barcelona. También del huerto en el que trabaja y de la foto que no nos ha enviado con la euipación puesta..."...Te quiero mucho...Pedro...." +++Pregunto a Manoli sobre el momento en que se cumple la pena, ya que tenemos registrado que es el 2020. No me sabe decir en estos momentos la fecha, pero normalmente lo comunican con un año de antelación, por lo que si no nos ha llegado ninguna comunicación al respecto quizá sea porque tiene alguna pena añadida. +++LE PIDO QUE LO COMPRUEBE Y NOS AVISE PARA TENER EL RECURSO CON ANTELACIÓN. +++Respecto a la Intervención, NO LA HAN REALIZADO TODAVÍA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-03-17','(Pedro)LLamada de Ildefonso (665-940924) +++CUMPLIMIENTO DE LOS TRABAJOS EN BENEFICIO DE LA COMUNIDAD: al parecer le ha dicho que se suspenden y que a partir del 31 de marzo le dirán algo al respecto. +++OBJETIVO DE SU LLAMADA: DINERO. +++++"...LOS ALQUILERES SON MUY ALTOS AQUÍ (se encuentran en Blanes): 500-600 euros/mes, 1 mes de fianza , más 1 mes de adelanto, más la comisión de la inmobiliaria...Necsitamos 2000 euros para ir tirando. De momento nos quedamos esta noche en un Hostal..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-17','miguel, comenta Ana Ts en una de las múltiples llamadas que me ha hecho este tutelado esta mañana, me comenta todo esto que no sé si sabéis: • Su inquilino, Antonino Pinto Estrada (Tlf. 693 37 63 63), no le está pagando el alquiler. Del segundo año de contrato sólo le ha pagado 4 recibos. • La persona de Vivienda del Ayto. de Málaga que lleva la gestión de estos contratos es Antonio López (Tlf. 951 92 60 10). Pide que le llamemos, pues desde el Ayto. tenían que haberle ingresado 1600 € (supongo que por el tipo de convenio o ayuda a la que esté acogido) y no lo han hecho aún. No sé qué plazos hay. • Su contrato de alquiler vence el 31 de julio de 2021 y no lo quiere renovar. Lo formalizó el 1 de agosto de 2018. No sé si tenéis algo iniciado al respecto. Por otra parte, me comunica que el próximo 14 de abril a las 10:30 tiene un juicio en el Jdo. d elo Penal nº 1 de Cáceres, por videoconferencia desde Plasencia. Procedimiento 000005/20, contra Bautista Cordero Jareños y Mª Inmaculada Fuertes Moreno. Al parecer le robaron 5000 €. No sé si queréis informaros o si tenéis que hacer algo al respecto *************************************************** miguel, comento a Ana Ts vía email: Buenos días, he intentado contactar con el Ayuntamiento de Málaga y no está Antonio López, ni nadie que pueda atendernos. La curatela es muy reciente ya que la aceptación de cargo fue de 14-1-2020 y el testimonio llegó hace menos de un mes… No logro entender bien qué quiere el Curatelado , necesitamos más datos y documentación ya que en el expediente no hay nada (contrato de alquiler para ver qué firmó, y qué pinta aquí el ayuntamiento de Málaga, porque si se trata de viviendas sociales no se pueden subarrendar, está prohibido… Cuando pasen estos días de estado de alarma intentaré de nuevo hablar con Antonio López del Ayto de Málaga (Tlf. 951 92 60 10). Por otra parte y en relación al procedimiento judicial que mencionas, necesitamos que se acostumbre a enviarte aunque sea por email todo lo que le llegue de juzgados…En este caso me comenta el Jzdo nº1 de lo Penal de Cáceres que el procedimiento no es 5/20 sino 55/20 y en el cual el Curatelado no es parte interesada ya que lo han citado como testigo, y por lo que veo te ha comentado a ti acudirá por videoconferencia, por lo que nosotros no intervenimos. Por tanto y teniendo en cuenta que en su día le ofrecieron personarse como parte interesada (cuando el procedimiento se instruyó en su día en el Jzdo nº2 de Cáceres, y él no lo hizo…aunque fuera a través nuestra..no sé cuándo se instruyó). Por lo que habrá que esperar a la sentencia que haga el Jzdo nº1 de lo Penal de Cáceres y donde me comentan de allí que si estiman que es parte perjudicada podrían abonarle algo… Ya digo el expediente está recién iniciado por lo que toda la documentación en todos los sentidos que te pueda ir enviando vendrían bien (contrato de alquiler, justificantes de pago, etc) o bien dale nuestros teléfonos y que nos llame','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-03-18','(Pedro)Conversación con José Manuel Escalona (924-003931). +++En estos moemntos el que peor se encuentra es D. Guillermo: "de la vez en la que lo vi durante el procedimiento al momento en que lo vi durante el recurso de apelación su empeoramiento era enorme, por lo que desistí del recurso ya inicialmente pedí una curatela y le habían dado la tutela.Es el que más requeríría un recurso residencial. Pablo quizá podría mantenerse en domicilio con los apoyos de los SSB con el SAD. +++Planteo la imposibilidad de que en estas condiciones sean aceptados en recurso alguno, dado que no cumplen con los criterios de acceso: consumo de sustancias (alcohol, al menos) y alteraciones de conducta (violencia). +++Hablar con los SSB para ver qué alternativas planetan ellos y que emitan un nuevo informe valorando las alternativas y declarando la sistuación de emergencia social.','2');
