insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA SAGRARIO'and edp.apellido1='GARCIA'and apellido2='PECES'),'2020-03-18','TERESA: LLAMO A PROINES PARA COMENTARLE QUE PIDA CITA A SALUD MENTAL PARA POSIBLE DERIVACION A CRR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-03-18','(Pedro)Conversación con Pilar (ESM de Cáceres, 54612) +++El hijo de D. José Manuel está acudiendo a casa (Calle Ecuador nº36, 4º derecha) de éste acompañado de unos amigos.Teme que pueda contagiarse o ser un foco de contagio. Ya Ana le ha insistido en que no abra la puerta y que llame a la Policía cuando aparezca. +++Ha acudido al médico por una diarrea : le mandaron a casa con suero, ayuno de nueve horas y dieta blanda (según ha informado Futuex a Ana). ++++++++++++++++++++++++++++++++ (Pedro)Llamo a José Manuel. +++Ha llamado a su hijo para decirle que no vaya más a su casa porque no le va a abrir. Parece tenerlo "claro". +++Insisto en la recomendación de Ana: no abrir y, si es necesario, llamar a la Policía o al 112: "...sí, ya lo sé. Lo he hecho otras veces..." +++Ha bajado a comprar algo para comer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-03-18','El Juzgado nº 1, de Castuera está en Guardia a partir de la próxima semana (23/3).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-03-18','Hablamos con el Juzgado 2, de Castuera, preguntando por la firmeza de la sentencia de incapacitación. Nos indican que el procedimiento está en la Audiencia Provincial. Llamamos a ésta, pero nos dicen que ya lo han enviado al Juzgado 2, aunque éste no ha recibido aún la documentación. En los próximos días resolverán y nos enviarán la firmeza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2020-03-18','TERESA: ENVIO A MUFACE COMPROBACION ANUAL DE LA PESISTENCIA DE REQUISITO PARA LA PF','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2020-03-18','TERESA: ENVIO A P I, AZUAGA AUTORIZACION MEDICACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-03-18','(Pedro) Conversación con Rosa, Directora de centro para dicapacidad Francisco de Asuar en Fuente de Cantos (667-693216). +++José Florencio se ha marchado voluntariamiente a casa de su madre, con el permiso de esta. +++La directora le ha advertido que si se iba no podía volver hasta que pasara el estado de alarma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2020-03-18','(Pedro)Llamada de Victoria, T. Soc. H. Don benito-Villanueva(86643 y 924-386812). +++Comunica necesidad de intervención (gastroscopia) urgente para esta misma tarde y que comporta altísimo riesgo quirúrgico.Envía consentimineto inofrmado para su firma. +++Le indico que me ponga en contacto con la anestesista para hablar con ella, ya que no podemos tomar una decisión si saber la opinión de los especilaistas.Me da el busca de la Dra. Maribel Orozco (anestesista, 36233). +++CONVERSACIÓN con la Dra. OROZCO. La operación no tiene por qué ser esta tarde, puede ser mañana. El Médico Internista dice que no puede seguir alimentándola con la sonda nasogástrica porque puede axfisiarse debido a las aspiraciones que tiene. Sí o sí la tiene que alimentar vía intragástrica, para lo cual se requiere la gastrostomía. +++SOLICITO INFORMES CLÍNICOS en los que se haga constar los beneficios e inconvenientes de la intervención o no intervención, as í como la calidad de vida y el pronóstico esperado en una u otra situación y la recomendación médica de intervenir o no. Enviará los informes a traves de Victoria, la T. Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2020-03-19','(Pedro)Conversación telefónica con Victoria. +++Pido que me pase con el Médico Internista que sigue el caso de Soledad. Es la Dra. Ana Megías (86835//86834). En estos momentos está en sesión clínica (llamaré apartir de las 09:30h.SOLCITAR INFORME MÉDICO ACTUALIZADO en el que se haga constar: 1.URGENCIA de la intervención//2.PRONÓSTICO de la intervención//3.PRONÓSTICO de la NO intervención// Calidad de vida en ambos supuestos//4. ¿NECESIDAD de REPETIR la intervención en un futuro? ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Clemen, Directora del CAMP (20101). +++Jesús, el Médico del CAMP, está al tanto de los intentos de respolver el problema de Soledad. Al parecer ha sufrido una obstrucción en la sonda intragástrica que requiere intervención quirúrgica. +++Volveré a llamar a Clemen una vez haya contactado con la Médico Internista. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Conversación con la Dra. Ana Mª Mejías, Médico Internista del Hospital Don Benito-Villnueva (86836). +++Soledad está recibiendo alimentación vía parenteral desde el pasado fin de semana. Se han intentado otras alternativas de nutrición pero no han sido viables (por endoscopia, etc.). +++En estos momentos es probable que NO SE PUEDA intervenir, porque Soledad tiene 39º DE FIEBRE, Y HAY QUE DECARTAR EL ORIGEN DE LA MISMA. +++La única alternativa viable es la GASTROSTOMÍA para poder alimentar a Soledad. +++SOLICITO la Dra. INFORME CLÍNICO en el que se haga constar las actauaciones realizadas hasta este momento, así como la INDICACIÓN de la cirugía como única alternativa válida a pesar del alto riesgo quirúrgico existente. Lo enviará hoy o mañana.SE le indicca que seguiremos sus indicaciones y de acuerdo con ellas se autorizará la intervención, remitiendo el Consentimiento Informado de Anestesia debidamente firmado una vez recibido su Informe. DE todo lo cual tenemos que informar a Fiscalía. Está de acuerdo con todo ello. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Llamada de Victoria, T. Social del Hospital. Le inoformo de la conversación mantenida con la Dra. y de los pasaos a dar de acuerdo con ella. Remitirá el Informe Clínico a través de la Trabajadora Social. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Llamo a Clemen para informarle de las conversaciones con la Dra. Mejías. +++Llamará a la familia para informar de la situación y del riego de la intervención, dejando claro, si fuese necesario, que la decisión última es de la Comisión, con quine se pueden poner en contacto si lo desea. +++ACOMPAÑAMIENTO HOSPITALARIO: La empresa que lo realizaba ha dejado de hacerlo.Ha contactado con otras pero no ha conseguido que ninguna realice el servicio. Le pido que NOS ENVÍE UN CORREO-E EXPLICANDO LA SITUACIÓN Y LAS ALTERNATIVAS. tIENE A UNA SEÑOARA QUE ESTARÍA DISPUSTA A HACERLO. pROBLE: LA FACTURACIÓN SI SE TRATA DE UNA CIERTA CANTIDAD DE DINERO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2020-03-18','Ana: Recibo llamada de Pilar Cerrillo, TS de la Res. Virgen de la Montaña (Casar de CC). Ayer ingresó María, pero desde el hospital no le han remitido nada de documentación. *Como por correo también lo ha solicitado Sonia Leo, Directora de la Residencia Virgen de la Montaña, se le remite a ambas por mail: DNI, Tarjeta Sanitaria, Autorización para aplicación de Sujeción Mecánica, Nº Póliza seguro Decesos: 1001112, Código IBAN. ////////////////////////////////////////////////////// *Pilar Cerrillo me remitirá por mail el Certificado de Ingreso en Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2020-03-19','Ana: Entrego a Miguel, Asesor Jurídico CTAEX, copi del Cdo. de Ingreso en Centro que me ha remitido Pilar Cerrillo, TS Grupo Ciudad Jardín, para que comunique el ingreso al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2020-03-19','miguel, envio comunicación al juzgado nº3 de Cáceres el traslado de la tutelada a la Residencia Geriátrica Virgen de la Montaña de forma temporal ya que se le ha asignado Residencia en Ciudad Jardín (Cáceres) que se encuentra en obras. Comentado con la parte económica que tiene un bien (para comprueben si se producen cargos correctos o no en su cuenta de impuestos)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2020-03-19','Ana: Dado el error anterior en el nº de cuenta bancaria, pongo para REGISTRO DE ENTRADA, nueva Comunicación de Variaciones de la PFHC, que cumplimentó y puso para la firma Tere, TS CTAEX. ////////////////// REGISTTADO DE ENTRADA el mismo día 19/03/20','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-17','Ana: Devuelven de Registro la copia registrada de la Comunicación de variaciones al INSS (cambio de nº de cuenta bancaria), REGISTRO DE ENTRADA a fecha de 17/03/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-03-16','Ana: Recibimos RESOLUCIÓN APROBATORIA DE LA PRESTACIÓN FAMILIAR POR HIJO A CARGO. Fecha de efectos: 01/01/2020. Importe Mensual: 395,60 € x 12.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-18','Ana: Llamada de Damián (622 834 876)- Quiere saber cómo va lo suyo. Explico que la compañera contactó ayer con el banco. Le ha vuelto a enviar, por mail esta vez, toda la docuemtación. Espera poder solucionarlo lo antes posible. *Le indico también que Miguel, Asesor Jurídico CTAEX, llamó ayer a Antonio López - Ayto. de Málaga, pero le dijeron que no estaba. Se pondrá en contacto con él pasado el Eº de Alarma. **Pero Damián dice que hoy sí está Antonio, que ha hablado con él y le han dado mi número, me llamará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-19','Ana: Nueva llamada de Damián (622 834 876). Aprovecho para informarle de que la cuenta bancaria está desbloqueada. Hoy harán una autorización para que pueda retirar efectivo en la sucursal de Plasencia. // En cuanto al piso pregunta si hemos hablado con Antonio, le digo que a mí no me llamó. Miguel, Asesor Jurídico, me dijo que volverá a intentarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-03-19','Ana: Recibo llamada de Consultas externas del Hptal. de Mérida (82400). La consulta médica de Medicina Interna que tenía programada para el día 26 de Marzo y la prueba "Fibroscan" se anulan. //// *Se lo comunico a María Barrasa, TS CSS-Mérida (24005). Me pide que lo cumunique al Serv. de Admisión del CSS (Fax: 924 58 80 83). *Redacto el fax y lo envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2020-03-19','(Pedro)Correo-e de Futuex, anunciando de la imposibilidad de comunicar con Carmen. Buenos días y mucho ánimo a todos! Desde el lunes estamos intentando localizar a Mª CARMEN RUIZ LARENA a de numerosas llamadas a su teléfono móvil. Siempre da llamada pero no nos atiende. Al no localizarla, nos ponemos en contacto con el comedor social Beato Padre Cristóbal Sta.Catalina. Nos informan que el comedor permanece cerrado desde el lunes hasta nueva orden debido a las circunstancias actuales de Estado de Alarma. Desde el comedor están intentado localizar a las personas mas vulnerables y expresan que tampoco han sido capaces de localizar a MCarmen. También nos hemos puesto en contacto con el Centro de Acogida Padre Cristobal, nos informan que desde que está el comedor social cerrado algunas personas han pasado por allí pero tampoco tienen constancia de MCarmen Ruiz. Dadas las circunstancias y necesidades de M Carmen, necsitariamos localizarla ya que es una persona que acudía con regularidad al comedor social debido a su déficit para cocinar y realizar correctamente la compra. Ya que si se lo podria gestionar un catering o cualquier otro recurso,nos ponemos en contacto porque sabemos que acostumbra a acudir fisicamente a la comisión o para saber si habeis sabido de ella, si no tendremos que planificar un seguimiento de cara a los proximos dias. A continuación, facilito el número de teléfono del Comedor social Beato Padre Cristóbal Sta.Catalina: 609 503 534 [1]. Nos atendió una Religiosa encargada del comedor. Gracias, y cuidaos mucho! ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Tras sucesivas llamadas al teléfono no lo cogen. Iciar se pone en contacto con Vodafon para restablecer la línea, pero hay que apagar el móvil y encenderlo para que la línea empiece a funcionar. +++Llamamos también al Comedor Social "Beato Padre Cristóbal Sta.Catalina" (609 503 534) y hablamos con la hermana Magdalena. +++LLamamos al 112: enviarán una patrulla al domicilio pero tenemos que ir uno de nosotros. Me reuno con la Policía Nacional a la entrada del bloque de Carmen (6 agentes): le pido por el telefonillo que baje y lleve el móvil (dice que no funciona porque no tiene linea al deber una factura). Una vez abajo, informo a Carmen de que la línea ya está reestablecida y la deuda abonada (compruebo el funcionamineto del teléfono). Le pregunto por la comida: "Tengo mucha comida, la he compardo en una cooperativa que hay aquí cerca...Sube y lo compruebas tú mismo..." Insiste en que suba pero dadas las circunstancias no lo veo necesario ni prudente. +++LLamo a la Hermana magdalena para que se quede tranquila en cuanto al estado de Carmen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-03-19','Ana: Llamo a Felisi (722 494 033) y Jesús, su pareaja. En relación a la petición que le hacen a la Delegada de Futuex de retirar el dinero en la oficina del Casar de CC (de nuevo la misma petición de otras muchas veces) argumentando en esta ocasión que debido al Eº de Alarma no pueden desplazarse a La Nava del Madroño, le digo que no es posible. **De forma excepcional se le hará una tranferencia a la cuenta del hermano de Jesús, Manuel, con la cuantía correspondiente a las autorizaciones de 2 semanas. Se le insiste en que deben administrarlo bien porque no se le autorizará para sacar más en lo que queda de mes. **Paso a Juana - CTAEX, el número de cuenta que me facilitan de Manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-03-19','miguel, recibo del colegio de abogados de Cáceres denegación de abogado de oficio para el procedimiento 498/2019 por delito de incendios con peligro para la vida del jzdo nº4 de Plasencia, porque consideran como beneficiario del servicio a la Comisión Tutelar de Adultos y no al tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-03-20','(Pedro)Conversación con Manoli, T. Soc. del C. Psiquiátrico Penitenciario de Sevilla. +++EXCARCELACIÓN DE Juan Carlos: DICIEMBRE DE 2020. A la condena que termina en juni se le han sumado 6 meses más por agresión. +++Convocarán la reunión para tratar el tema y enviarnos a nosotros ya al SEPAD los informes para ello. +++Pido que en dichos informes propongan el recurso que consideran más apropiado para Juan Carlos, incluyendo las observaciones que por teléfono hemos comentado: es muy deportista (buen portero de fútbol), le gustan las actividades al aire libre. Incluso le propongo que en el Informe el entrenador que tiene (voluntario) pueda incluir sus impresiones sobre él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2020-03-20','(Pedro)Llamada de Victoria (T.Soc. HDBV). +++Ayer se aisló por precaución a Soledad al aparecer la fiebre y se tuvo que retirar la vía parenteral (central) de nutrición, recurriendo a una vía alternativa. Esta segunda vía no está dando resultado y nos van a enviar el Consentimiento Informado para restaurar la vía central. +++Hoy se encuentra algo mejor, incluso dicen que ha hablado un poco. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Nueva llamada de Inma (Atención al Paciente). +++El anestesista ha decidido instaurar una "vía media" (en yugular) para nutrir a Soledad que no requiere consentimiento informado. +++INFORMO A CLEMEN DE TODO ELLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-03-20','Buenos días Amalia, te escribo la situación referente a Mª Rosario Moreno Hermosa (residente en Guadiana). Durante esta semana hemos estado en contacto con Miriam su cuidadora, nos comenta que Rosario continúa enferma con gastroenteritis sin conseguir mantener nada de lo que come, lleva aproximadamente dos semanas que se encuentra muy débil, ha tenido fiebre y las diarreas son continuas. Ayer fue la ultima vez que estuvo en contacto telefónico con el médico, le indicó que continuara con el tratamiento para la diarrea y la alimentara con suero. Con 94 años y dos semanas así, su estado es bastante delicado. A todo ello, Miriam nos comenta que en caso de ingreso de Rosario ella no quiere realizar el acompañamiento, debido a las circunstancias sanitarias actuales, tiene miedo a estar tiempo en el hospital por lo que se negaría a ello.Le hemos indicado que ella es su cuidadora habitual y no puede negarse a ello. Miriam pregunta qué hace si empeora ya que es una persona tutelada por la Junta, se le indica que estamos hablando de la salud de una persona, tutelada o no, lo primero que debe hacer es llamar a emergencias, además Rosario tiene el collar de teleasistencia de Cruz Roja. De todo, debe informar a la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-03-20','Buenos días Amalia, te escribo la situación referente a Mª Rosario Moreno Hermosa (residente en Guadiana). Durante esta semana hemos estado en contacto con Miriam su cuidadora, nos comenta que Rosario continúa enferma con gastroenteritis sin conseguir mantener nada de lo que come, lleva aproximadamente dos semanas que se encuentra muy débil, ha tenido fiebre y las diarreas son continuas. Ayer fue la ultima vez que estuvo en contacto telefónico con el médico, le indicó que continuara con el tratamiento para la diarrea y la alimentara con suero. Con 94 años y dos semanas así, su estado es bastante delicado. A todo ello, Miriam nos comenta que en caso de ingreso de Rosario ella no quiere realizar el acompañamiento, debido a las circunstancias sanitarias actuales, tiene miedo a estar tiempo en el hospital por lo que se negaría a ello.Le hemos indicado que ella es su cuidadora habitual y no puede negarse a ello. Miriam pregunta qué hace si empeora ya que es una persona tutelada por la Junta, se le indica que estamos hablando de la salud de una persona, tutelada o no, lo primero que debe hacer es llamar a emergencias, además Rosario tiene el collar de teleasistencia de Cruz Roja. De todo, debe informar a la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-03-20','-cuadro fin de semana con las auxiliares , está muy delicada de salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2020-03-23','(Pedro)Nos comuniCan el fallecimiento de Dª María. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CORREO DE FUTUEX:Hola Pedro buenas tardes, he estado en contacto con Ana y con Amalia, pero contigo no habia contacto aun en concreto te hago llegar el email que solicitaste de Alicia la ts de Torreorgaz, está informada por la compañera, a través del email, tsocial3@mancomunidadsierrademontanchez.es en esta nota adjunta, se especifican los telefonos de contacto del sobrino que reside en Mallorca, por si teneis que contactar en algun momento con el, ya que al parecer la casa donde residia la tutelada es de él, como indique en un correo anterior nosotros trataremos en cuanto podamos ir al pueblo contactar con la teleasistencia para que recojan lso dispositivos y las auxiliares habian cerrado suministros y todo y van a dejar la llave en el ayuntamiento. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ ARCHIVO ADJUNTO:20/03/2020 Fallecimiento: A primera hora de la mañana se pone en contacto la auxiliar de Dependencia de María, Vale comenta que le han llamado del ayuntamiento para comunicar que María ha fallecido. Se contacta con la residencia Virgen de la Montaña de Casar de Cáceres, donde estaba María desde el día 18 por la tarde-noche, la directora, Sonia, comenta que ocurrió esta mañana, hacía un par de horas, pero que se estaban poniendo en contacto con la CTAEX directamente para agilizar los trámites, se le dice que perfecto. Se contacta, vía telefónica, con su sobrino Poli, el cual ha seguido de cerca todo el ingreso de María, es quien ha estado siempre pendiente de la tutelada; se le comunica la noticia, ya se lo había dicho también la auxiliar. Poli consulta sobre el entierro y demás, se le dice que primero él no puede desplazarse, además de ser persona vulnerable por lo que dice, segundo, no se pueden realizar entierros ni velatorios en la situación que estamos, por seguridad, por lo que no merece la pena que se venga… una vez que pase todo esto ya se verá lo que se realiza. Poli consulta por la casa y demás, según establece es suya, se le dice que así lo comunicó la trabajadora social en la primera visita, Alicia indicó que la casa la pagó su sobrino Poli para que María no se quedase en la calle y acordó que ella viviría ahí el tiempo que durase, luego ya se haría cargo él; se le dice que, en principio, las llaves van a quedar custodiadas en el ayuntamiento y la CTAEX gestionará todo lo que sea oportuno acorde a María, pues sobre sus vienes y pertenencias la potestad de decisión la tiene el juez; Poli acepta, establece que ya contactaremos cuando pase todo esto. Los contactos de Poli son: • Móvil Poli: 654 13 20 71 • Móvil Toñi (mujer): 663 77 42 97 • Teléfono fijo:971 44 06 39 El servicio de teleasistencia ya se ha anulado, comentan que ahora no pasarán a recoger el equipo, pues tienen otras cuestiones más importantes que cubrir, establecen que si tuviesen que ir a la localidad por alguna cuestión, se pondrían en contacto con la auxiliar para recogerlo, por lo que será la única persona que tenga una llave del domicilio de María, ha sido quien siempre ha gestionado todo lo de la tutelada y de forma muy correcta y justificada, en cuanto al área económica. Por otra parte, la auxiliar, Vale, establece que ya comunicó el fallecimiento de María a la empresa de Dependencia, por lo que no se vuelve a llamar al responsable para no repetir información. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ALICIA, T. Soc. de Torreorgaz (927-215588). Pendiente del coste de los servicios adiconales no contemplados en la póliza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-03-23','(Teresa/Pedro) Conversación con Luisa Calderón, T. Soc. de Zalamea de la Serena. +++La situación sigue siendo la misma. Explicamos las dificultade sdel caso para establecer el recurso adecuado dado los criterios de exclusión. +++Solicitamos remita Informe Social en el que se determine la situación de EMERGENCIA SOCIAL, TANTO PARA SOLICITAR CENTRO COMO PARA SOLICITAR LA CORRESPONDIENTE AUTORIZACIÓN JUDICIAL DE INGRESO INVOLUNTARIO. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Teresa/Pedro)Conversación con JOsé, Agente de la Policía Local de Zalamea. +++En estos momentos, dada el Estado de Alarma, es la Policía Local la que se está encargando de llevarles la comida y controlar que no salgan de casa (como ha sucedido esta misma mañana con Guillermo). +++Nos dicen que sí existen denuncias contra ellos y registro de las incidencias ocurridas con y sin denuncia. +++Solcitamos nos envíen por correo electrónico todas las dencuncias, registro de incidencias e informe de la Policía Local en el que se haga mención de las intervenciones mantenidas con ellos en el día a día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-03-23','Teresa/Pedro) Conversación con Luisa Calderón, T. Soc. de Zalamea de la Serena. +++La situación sigue siendo la misma. Explicamos las dificultade sdel caso para establecer el recurso adecuado dado los criterios de exclusión. +++Solicitamos remita Informe Social en el que se determine la situación de EMERGENCIA SOCIAL, TANTO PARA SOLICITAR CENTRO COMO PARA SOLICITAR LA CORRESPONDIENTE AUTORIZACIÓN JUDICIAL DE INGRESO INVOLUNTARIO. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Teresa/Pedro)Conversación con JOsé, Agente de la POLICÍA LOCAL de Zalamea. +++En estos momentos, dada el Estado de Alarma, es la Policía Local la que se está encargando de llevarles la comida y controlar que no salgan de casa (como ha sucedido esta misma mañana con Guillermo). +++Nos dicen que sí existen denuncias contra ellos y registro de las incidencias ocurridas con y sin denuncia. +++Solcitamos nos envíen por correo electrónico todas las dencuncias, registro de incidencias e informe de la Policía Local en el que se haga mención de las intervenciones mantenidas con ellos en el día a día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='VAZQUEZ'and apellido2='GUERRERO'),'2020-03-23','TERESA: ARCHIVO RESOLUCON PLAZA RAL Y CO EN EL CENTRO FRANCISCO ASUAR DE FUENTE DE CANTOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='NOGALES'and apellido2='MATADOR'),'2020-03-23','TERESA: CONVERSSACION CON LA TS M ANGELES SSB DE TORREMEJIAS (619140115/924340001) MANUEL TUVO EN TIEMPO UNA PAREJA DE NACIONALIAD RUMANA, AHORA MISMO NO HAY RELACION ALGUNA. MANUEL NO TIENE DEUDAS ADMINISTRA BIEN SU DINERO LA VIVIENDA ESTA SUCIA Y NO TIENE LUZ LA HERMAN ANTERIORMENTE ERA SU TUTORA, VIVIA EN ARROYO PERO A FECHA DE HOY NO MANTINE RELACION NINGUNA LA CASA ES PROPIEDAD DE SUS PADRES LA VISITA QUE REALIZO LA TS FUE BIEN, PERO POSTERIORMENTE SE ALTERO Y QUEMO UNA PUERTA EN EL PATIO TIENE TRATAMIENTO DE SALUD MENTAL PUESTO POR SU MEDICO DE CABECERA AL CUAL ACUDE DE FORMA ASIDUA SE HA CONTACTADO CON AL ENTIDAD BANCARIA PARA QUE NO LE BLQUEEN LAS CUENTAS Y PUEDA SEGUIR DIPONIENDO DEL DINERO EN PRINCIPIO NO LE VAMOS A PONER RESTRICCIONES, QUEDAMOS PENDITE VISITA PARA EXPLICARLE NUESTRAS FUCIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-03-23','TERESA: LLAMO A LOREZO Y ME COMENTA QUE EL JUZGADO ESTA CERRADO QUE TODO ESTA SUSPENDIDO QUEDAMOS A LA ESPERA DE NUEVA CITACION PARA EL FORENSE DE SALUD MENTAL LE LLAMARAON PAR ANULAR LA CITA LE DARAN NUEVA CITA CUANDO ESTO VUELVA A LA NORMALIDAD LORENZO DE MOMENTO SE QUEDA EN VILLFRANCA A LA ESPERA DE INSTRUCCIONES DE LA EMPRESA CON LA CUAL TRABAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-03-19','TERESA: EMAIL DEL CENTRO Ayer teniamos cita con salud mental en Don Benito, y la cita ha sido telefónica con la psicóloga y que mantiene medicación Cuando volvamos a la normalidad y tengamos informes os los enviamos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2020-03-20','TERESA: EMAIL DEL CENTRO Me pongo en contacto para informar de que los tutelados David Vita Gil se encuentran en sus domicilios familiares. Libertad se fue el jueves Mantenemos el contacto telefónico con la familias y de momento todo esta en orden y se encuentran bien de salud. El resto de tutelados se encuentran en la residencia y la vivienda tutelada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-03-20','TERESA: EMAIL DEL CENTRO Me pongo en contacto para informar de que los tutelados Libertad García Marquez se encuentran en sus domicilios familiares. David el viernes. Mantenemos el contacto telefónico con la familias y de momento todo esta en orden y se encuentran bien de salud. El resto de tutelados se encuentran en la residencia y la vivienda tutelada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-03-23','TERESA: LLAMADA TELEFONICA CON TONI TS DEL CENTRO DE SALUD, ME ENVIA INFORMES MEDICOS , LO ARCHIVO EN SU EXPEDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2020-03-23','(Miguel/Pedro). Conversación con Ana Megías, Médico internista del HDBV (busca 36213). +++Soledad sigue en aislamiento, a pesar de que ha permanecido afebril desde el pasado viernes, por precaución y hasta que reciba los resultados de las pruebas realizadas. +++Existe una clara discrepancia entre la viabilidad o no de la gastrostomía entre el servicio de Medicina Interna y Cirugía y el SAervicio de Anestesiología (ver informes del 13 y 20 de marzo de 2020). Anestesiología considera que "...no es conveniente realizar procedimientos en esta paciente que no mejorarán su estado actual, debido a su diagnóstico y su pronóstico.Esta paciente es NO APTA ASA 4/5." (ASA: SOCIEDAD aMERICANA DE ANESTESIOLOGÍA: clase IV y clase V).Ante esta falta de acuerdo entre los distintos facultativos, se explica que la Comisión debe informar al Juzgado, si se continua con ello, sobre la NO autorización de la intervención. +++FINALMENTE ha sido posible la instauración de una SONDA NASOGÁSTRICA que permite la nutrición y administración medicamentosa de Soledad, por lo que de momento se aplaza cualquier otra intervención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-03-23','TERESA: LLAMADA TELEFONICA CON TONI TS DEL CENTRO DE SALUD, ME ENVIA INFORMES MEDICOS , LO ARCHIVO EN SU EXPEDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-23','miguel, llamo sin éxito al Ayto de Málaga para intentar hablar con Antonio López sin éxito. Compruebo que en catastro no aparece en CCAA Extremadura ningún bien propiedad de él, por lo que solicito (previo comentado con la parte económica)nota simple de posibles bienes que tenga en Andalucía. Seguimos pendiente que desde el CRR nos remitan documentación en relación a este supuesto impago de alquiler que comenta el curatelado.////////////////////////////////////////////////////////////////////////////////////////// Ana: nueva llamada de Damian en relación a la autorización de retirada de efectivo. Le explico que las compañeras del área económica han realizado la autorización con el listado de las personas que nos han indicado desde el CRR que deben aparecer en la misma para que acudan a realizar la retirada de efectivo al banco mientras dure el estado de alarma. Insiste en que se debe poner a Félix, Adtvo., le repito que se ha puesto a quienen nos han dicho desde el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-03-23','miguel, a petición de Pedro Js y Teresa, llamo sin éxito al Jzdo nº1 de Villanueva en relación al procedimiento de internamiento (ITR Internamiento 227/2019), para preguntar si asistió o no la tutelada a la citación que tenía el 17-3-2020 con el forense (si bien es cierto que según el estado de alarma está todo paralizado y así lo confirman desde juzgados, comprobamos que el Ministro de Justicia dijo en comparecencia el viernes 20-3-2020 que se mantendrán estos días los servicios esenciales entre los cuales se encuentran los correspondientes a internamientos involuntarios de art 763 LEC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-03-23','miguel, a petición de Pedro Js y Teresa, llamo al Jzdo nº1 de Villafranca de los Barros (tlfno 924-524013) donde se está conociendo el procedimiento de internamiento involuntario (ITR Internamiento 4/20)con la finalidad de saber si el tutelado se presentó o no el día 17/3/2020 a la citación con el médico forense,y caso contrario saber si lo van o no a citar y cuándo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-03-24','(Pedro)Llamada de José Vicente (924-201117). +++Dice haber recibido su padre una factura de 200 euros de móvil. Padre: D. José Viente Murillo (618-867743). +++Su padre comenta que es una factura de alrededor de 280 euros. No tiene medio de hacerla llegar a la Comisión por fax o correo-e. +++Lo paso a Alberto para que se pongan en contacto con Yoigo y reclamen y la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-24','Llamamos al Ayuntamiento de Málaga para interesarnos por los impagos del alquiler, en el porcentaje que le corresponde al Ayuntamiento. Nos atiende una persona, es su primer día, dice, pero que los pagos están al corriente, intenta pasarnos con alguien responsable de los pagos pero no lo consigue. Propone que llamemos en otro momento, porque ahora solo están atendiendo llamadas de emergencia. ////////////////////////////////////////////////////////////// Ana: Nueva llamada de Damián (622 834 876), con sus recurrentes cuestiones. Se le escucha y explica como van las cosas y que debe tener paciencia. Desde la CTAEX se están realizando las correspondientes gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-03-24','Ana: Redacto y firmo el Informe Social (Modelo oficial - Procedimiento de solicidud de valoración de Dependencia), solicitado por Clara Isabel Gómez Nestares, Jefa de secc. para la priorización del expte. de Pedro Román. *Lo pongo para REGISTRO DE ENTRADA junto con el modelo oficial de "Solicitud o comunicación de cambio de datos del expte. de dependencia" debidamente firmado y sellado por el D.Gerente. Pido que lo entreguen a Clara y me devuelvan copia registrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-03-24','(Pedro) +++Llega a la Comisión Tutelar documentación relativa a la propuesta efectuada por el Equipo Multidisciplinar del Hospital Psiquiátrico Penitenciario de Sevilla en relación a D. José Mª:una propuesta de recomendación de CUMPLIMIENTO de la medida de seguridad impuesta en la Ejec. 643/18 del J.P. de Plasencia EN UN CENTRO DE CARÁCTER NO PENITENCIARIO por entender que pudiera ser más beneficioso dadas las características del paciente. +++Pendiente de pasar a la Uniad de PP. AA. una vez tengamos la resolución judicial sobre mantenimiento o modificación de medida de internamiento involuntario, para lo cual el jzdo escuchará al tutelado (consultado con Miguel la situación de la Ejecutoria 643/2018 todavía pendiente.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-03-24','Correo electrónico de Estrella Duraán. +++De: ESTRELLA DURAN CARRETERO Enviado el: martes, 24 de marzo de 2020 11:07 Para: ANA MATAMOROS GOMEZ >ana.matamorosg@salud-juntaex.es> Asunto: Traslado pacientes UDAC Buenos días, Ana. Te comunico que debido a la emergencia sanitaria se ha trasladado a los pacientes de la unidad de agudos del Hospital Virgen del Puerto de Plasencia a la UDAC de este centro socio-sanitario, con lo cual los pacientes de UDAC han sido trasladados a UDIG estando situada esta unidad en otro pabellón de este centro. Lo trasaldo ya que varios de vuestros tutelados son pacientes de UDAC, en concreto: Felisa Bruno Saavedra. Josefa Domínguez Blanco Yolanda Caldera Martín Carlos Alberto Vicente Calderero Remedios Chaves Masero. Todos se encuentran bien.','2');
