insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-25','(Pedro) Llamadfa de Dª Alicia Cortés (675-517918). +++Se trata de una antigua COMPAÑERA DE TRABAJO, según refiere, a la que Damián le ha pedido que llame a la Comisión porque -le dice- no tiene dinero y para preguntar por el piso que tiene alquilado. +++Se le indica que la Comisión está gestionando estas situaciones. /////////////////////////////////////////////////////////////////////////// Ana: Nueva llamada de Damián (622 834 876), dice que desde el CRR aún no han ido a retirar el efectivo del banco. // Consulto con Íciar, CTAEX, de nuevo ha habido algún problema con el banco, esta vez con la oficina de Plasencia. Ella ha enviado hoy nuevos correos a Málaga y a Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2020-03-25','-Amalia : contacta conmigo la Policia Local de Badajoz , han tenido un altercado con Antonia . Al parecer han salido de casa Antonia , su hno Pedro y la madre para ir al banco a retirar las pensiones. La policia los ha parado y Antonia se ha avalanzado sobre uno de ellos , hay lesiones pero el policía no va a ir ni al hospital. Nos van a enviar el parte de incidencias por email. Hablo con su hno , que me cuenta lo ocurrido . Quieren más dinero , voy a solicitar que le hagan una trasferencia los meses que el centro( C.O. Aprosuba 3) esté cerrado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2020-03-25','-Amalia : Alonso ha tenido una caida la madrugada del viernes , las hnas . avisaron a la Aux. SAD que activó el 112. Está ingresado en el H. Perpetuo Socorro de Badajoz desde entonces . Gestiono con FUTUEX , SSASB , El Angel , un protocolo de actuación. Con las hnas se queda la auxiliar que tienen en casa . En el hospital , y tras comprobar con la sección económica que tiene bastante dinero se contrata acompañamiento hospitalario. Sigue ingresado a día de hoy . A las hnas. se les está avisando por tf. de la situación , así como a la TS del SSASB .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-03-25','miguel, pendiente de firma del gerente la solicitud a abogacía para inicie el procedimiento de revisión de incapacidad a tutela. No solicitaré el internamiento involuntario ya que desde hace un mes reside en la residencia de mayores "Nuestra Señora del Buensuceso" de Castuera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-03-25','-Amalia: lleva dos semanas muy delicada de salud , con diarreas y vómitos que no cesan . El médico de AP la está observando pero no ha considerado oportuno ingreso hospitalario. Myriam está haciendo el servicio , interna , se le amplían las horas . Se establece protocolo de actuación , coordino con TS del SSASB , Futuex , Mryam y ASINDE . Solicito a la empresa un fin de semana más para que Miryam libre , está agotada pq lleva muhas noches sin dormir. Si se precisara ingreso hospitalario , desde la empresa enviarían personal al hospial , Miryam tiene miedo y no quiere hacerlo. Si falleciera , se les ha enviado copia del seguro de decesos a todos , con tf. incluidos para que avisaran si se diera el caso . Así como a todas las personas que tendrían que avisar , incluida a mí. Futuex está haciendo contacto tf casi diario y yo también para ir siguiendo la evolución de su estado y para tranquilizar a la auxiliar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2020-03-25','-Amalia : hablé con la TS del pueblo la semana pasada para cuadrar protocolo a seguir. DEsde el Ayto. se le envia a casa comida de catering gratuito. Se suspende el SAD , él se niega , sólo van a ir un día para asearlo. Me llama la TS , con Bartó en su casa , además de Alonso se queda muchos días una " amiga" con discapacidad. El padre de la chica , que son de Montijo , la lleva y la trae . Hoy cuando las auxiliares han ido a la casa se han encontrado a la chica con fiebre. Se han ido y han avisado a la TS . Ya ha comunicado la situación al Centro de saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2020-03-25','-Amalia : hablé con la TS del pueblo la semana pasada para cuadrar protocolo a seguir. DEsde el Ayto. se le envia a casa comida de catering gratuito. Se suspende el SAD , él se niega , sólo van a ir un día para asearlo. Me llama la TS , con Bartó en su casa , además de Alonso se queda muchos días una " amiga" con discapacidad. El padre de la chica , que son de Montijo , la lleva y la trae . Hoy cuando las auxiliares han ido a la casa se han encontrado a la chica con fiebre. Se han ido y han avisado a la TS . Ya ha comunicado la situación al Centro de salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2020-03-25','-Amalia : hablé con la TS del pueblo la semana pasada para cuadrar protocolo a seguir. DEsde el Ayto. se le envia a casa comida de catering gratuito. Se suspende el SAD , él se niega , sólo van a ir un día para asearlo. Me llama la TS , con Bartó en su casa , además de Alonso se queda muchos días una " amiga" con discapacidad. El padre de la chica , que son de Montijo , la lleva y la trae . Hoy cuando las auxiliares han ido a la casa se han encontrado a la chica con fiebre. Se han ido y han avisado a la TS . Ya ha comunicado la situación al Centro de salud(924457636 TS Carmen ).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-25','Ana: Correo de Pilar, Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "Buenos días, deseamos que todos sigan bien. No nos hemos puesto en contacto antes con ustedes porque, hasta hoy, no hemos recibido noticias de los médicos de Margarita. Nos han dicho que está estable y que le hicieron la prueba del covid 19 ayer, con lo que hay que esperar unos días para conocer el resultado. Nos han dicho que no podemos hablar con ella, ni siquiera por teléfono, que serán ellos quienes nos irán informando. Cuando sepamos algo más les iremos contando. Un saludo Pilar Sánchez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-20','Ana: Correo de Pilar, Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): Buenos días, les informamos que Margarita se encuentra aún en la Unidad de Psiquiatría y, actualmente, en aislamiento, ya que empezó con tos y fiebre. Nos han comunicado que no se le han practicado las pruebas del Covid 19, pero se está actuando con ella como si lo padeciese (aislamiento y utilización de medidas de protección cuando se entra en su habitación) La Doctora Lorenzo nos ha comunicado que no ha vuelto a tener fiebre y que, si seguía así y, según su criterio médico, hubiera que darle el alta tendríamos que tenerla nosotras en aislamiento, a lo que se le ha respondido que nuestro Centro no dispone de una habitación que reúna condiciones para tal situación, ya que nuestras residentes duermen en habitaciones con dos camas, sin posibilidad de sacar una y meterla en otra por las dimensiones de las mismas. Sólo contamos con una habitación con cuarto de baño incorporado y está siendo utilizada por personas muy dependientes a las que no podemos ubicar en otro sitio. El lunes volveremos a ponernos en contacto con la Doctora Lorenzo y seguiremos informándoles. Un saludo y deseamos que todos se encuentren bien Pilar Sánchez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-03-24','Ana: correo de Toni-Futuex, tras haber hablado ella directamente con Alberto (Se valoró hace varios días contratar catering mientas dure el estado de alarma, para que no tenga que salir a por comida y aseguremos su adecuada alimentación): "Se adjuntan presupuestos solicitados a dos empresas que prestan servicios de comida a domicilio, se adjuntan dichos presupuestos a esta nota. Ambas empresas son: Sol Catering: precio menú semanal 39.30 € Qué Bueno Catering: precio menú semanal 38.05€ Con la que decidais gestionamos, para un mes, los recibos a su nombre y que os lo pasen a final de mes, con la comida cubierta y retirada de 100 euros,estara todo super cubierto asique genial!! mcuhas gracias y a cuidarse!" ///////////////////////////////////////////////// Respuesta: "Toni, acabo de verlo con Alberto. Se aprueba el de Sol Catering, parece más sencillo que el otro y entiendo que será de lunes-domingo. Para que empiecen a darle el servicio lo antes posible. Gracias de nuevo. Seguimos en contacto. Cuídate."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='GALINDO'and apellido2='CALLE'),'2020-03-25','(Pedro)Llamada de Maríví (CSS de Plasencia). +++Nos informa del FALLECIMIENTO de Dª Mª Jesús esta pasada noche (covid-19), en el Hospital Viregen del puerto. +++Han intentado avisar a la familia sin conseguirlo (comenta que llevaba más de un año sin recibir visitas). +++Ya se han puesto en contacto con Caser. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++FAMILIARES: D. Blas (hermano, Madrid), 607-673387), D. Miguel (hermano, 615-056992), Dª Consuelo (sobrina, 657-014089), D. Blas (sobrino, hijo de D. Blas, 91-6660575).ç +++Intento ponerme en contacto con D. Blas (hijo) sin conseguirlo. Mariví me comenta que los hermanos son muy mayores y es mejor hablar con este sobrino, que es quien ha estado en contacto con el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2017-05-18','Llama la hija, Puerto T/C 661.27.32.04, indicando que su abuela ha fallecido hace dos meses, y necesita el DNI de su madre para la declaración de herederos.En la residencia no se lo facilitan. Nos informa de la notaría de Plasencia donde se van a realizar los trámites para que nosotros nos pongamos en contacto: Notaría Francisco de Asís Jiménez Velasco T/C 927.41.14.47. Dice haber llamado ya informar del fallecimiento de su abuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-03-25','Ana: Correo de Toni-Futuex: "Hola! a continuacion adjunto actualizaciones de JOse Manuel Romero Mediavilla, hoy empieza el catering, y está de acuerdo con la retirada de dinero pautada, a final de mes nos enviaran la factura del catering sol para que os la pasemos para abono, hoy ha ido al medico pq tenia tos... pero le han dicho que es del tabaco no se preocupe..asique bien.. Estamos en contacto!! cuidate!" Guardo nota en extpe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-26','Ana: llamada de Damián (622 834 876), expresa que no cree que vaya hoy ningún profesional del centro a retirar su dinero. No le han dicho nada ni él lo ha preguntado. Le recuerdo que hoy es temprano, que debe tener paciencia. Ya fue alguien pero hubo dificultades en la oficina de Plasencia, las compañeras del área económico ayer hicieron gestiones para intentar solucionarlo y desde el CRR volverán a acudir al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-03-26','(Pedro)Conversación con Raquel, DEl Hogar de Nazaret. +++José Pedro se encuentra perfectamente. Hace poco recibió la visita de la delegada Tutelar y se quedó asombrada de lo bien que lo había encontrado. +++En el centro No ha habido ningún caso de covid-19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2020-03-26','(Pedro)Se recibe en la Comisión en el día de hoy Solicitud de traslado interautonómico de expediente de reconocimiento de la situación de dependencia de la D.G. deAtención al Mayor y a la Dependencia, de la Consejería de Políticas Sociales, familia, Igualdad y Natalidad de la Comunidad de Madrid. +++La Comisión Tutelar no ha solicitado traslado alguno de expediente ni se lo ha planteado en ningún momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2020-03-26','TERESA: ENVIO DOCUMENTACION SOLICITADA POR JULIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-03-26','Ana: Conversación telefónica con Estrella, TS del CSS-Plas.: Comento sobre la evolución de Juan en los últimos meses y el motivo de llegar a ingresar en UHB y a posteriori en UME. Le informo así mismo sobre la conversación mantenida con Raquel, TS del SSB de Guadalupe. A ella le extraña pues ya no se deriva a nadie a ULE. Le explico las características de Juan, las condiciones de su vivienda, que en nuestro criterio no se encuentra en condiciones para poder vivir solo, las limitaciones de la CTAEX para el seguimiento así como desde Salud Mental para su seguimiento ambulatorio. Por otra parte, le recuerdo las características de los CRR y pisos supervisados y el requisito de la voluntariedad de las personas para acceder y permanecer en los mismos. *Hablará con el equipo al respecto. ////////////////////////////// Por otra parte acordamos que mañana llamaré a Juan para hablar con él, pues lo está demandando de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2020-03-20','EXITUS. Nos comunican desde el centro su fallecimiento el 20/03/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-27','Ana: recibo llamada de Damián (622 834 876): dice que ayer por fin ya cobró, fueron del centro a retirar el dinero y no hubo ningún problema. Pregunta por el resto de cuestiones: cuentas bancarias, contratos de alquiler, créditos... le recuerdo que los compañeros de las correspondientes áreas ya están realizando las gestiones oportunas y se encargan, para eso tiene una curatela económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2020-03-27','- Amalia : Desde el martes reciben la comida a domicilio tanto para Antonio como para Manolo. Asegurándonos así que toman una alimentación equilibrada y cubriendo un déficit importante sobretodo referente a Antonio. Tanto Nuria TS de los SSBB como desde el equipo de apoyo social comunitario, estamos en contacto telefónico con ambos hermanos para persuadir su insistencia a pasear y salir a la calle. Saben que como continúen sin cumplir con ello, la policía tomará las medidas oportunas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2020-03-27','-Amalia : se comunica desde el Ctro penitenciario que ha vuelto a ingresar . Solicito a la seccion eco q paralicen el pago a la tia y abran cuenta peculio enviando toda la pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-27','Ana: Realizo llamada al busca de Psiquiatría del HVP de Plasencia (32987): hablo con el Psiquiatra que está de guardia. Dice que a Margarita le dieron el alta ayer, la han dejado hasta hoy de forma excepcional. Ya han hablado con Pilar, del Hogar San Vicente de Paúl, irán a buscarla a las 12 h. Al pedirle que nos envíen el informe, dice que como se lo darán en mano a ella que no envíen copia desde el centro si no les importa. *En cuanto a Marga, expresa que se encuentra bien, conforme con la decisión, ya tiene ganas de volver al centro. ////////////// Se lo comunico a Pilar por mail, para que cuando puedan nos envíen el informe. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)(Pedro) Se recibe respuesta de salud Pública a través de la Gerencia del Sepad (Manuel CID) mediante el siguinete correo-e: Buenas tardes (por ayer). En base a los protocolos que establece el Ministerio de Sanidad y el Servicio Extremeño de Salud, si una persona tiene el test de coronavirus negativo a todos los efectos se considera como caso descartado. Un saludo. Dirección General de Salud Pública Avda. de las Américas, nº 2 06800 Mérida Teléfono: 924 382507 ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Esta mañana nos ponemos en contacto con el Hogar "San Vivente de Paul" por teléfono para hablar sobre esta situación. Nuestros interlocutores son Pilar Sánchez (T. Soc.) y Sor Marifé. +++Explicamos la respuesta dada desde Salud Mental y les enviamos posteriormente el correo en el que figura la misma. +++Muestran alguna reticencia, pero finalmente aceptan la respuesta de Salud Pública. +++Pilar comenta que esta mañana irá a recoger a Margarita y quedamos en solciatr el informe de Alta al Hospital. ++++++++++++++++++++++++++++++++++++++++++++++++++++ Ana llama al Hospital para solcitar el Informe de Alta pero le dicen que se lo entregará en mano a Pilar cuando vayan a recoger a Margarita, de alta desde ayer a la espera de lo que se resolviera desde la Dirección-Gerencia. +++Ya habíamos quedado con Pilar en que el primero que tuviese el informe la remitiría al otro. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se recibe en la Comisión Informe de ALTA remitido por Pilar por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-03-27','Ana: me devuelven copia registrada de la "solicitud de cambio de datos" con el que adjunté el informe soc. socilitado por Clara, Jefa Secc. Calidad... Dependencia, con REGISTRO DE ENTRADA a fecha de 26/03/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-26','Correo-e recibido en el día de ayer del Hogar San Vicente de Paul: +++Buenos días, Pedro, nos han llamado del Hospital Virgen del Puerto para informarnos que Margarita ha dado negativo en la prueba del Covid 19 y que, psiquiátricamente, puede salir de alta hoy. Ante esta situación, nosotras les hemos pedido un informe donde nos indiquen que no ha posibilidad de contagio si duerme en la habitación con otra de nuestras residentes, ya que nuestro Centro carece de medios para mantenerla aislada en una habitación. Desde Psiquiatría nos dícen que no pueden hacernos dicho informe, solamente informar de que la prueba ha dado negativo y que, psiquiátricamente, se encuentra estable y bien. Nosotras debemos cuidar también de las residentes que se encuentran aquí e informar a las familias del éstas. Ante estos hechos, nuestra pregunta es ¿cómo debemos actuar? Esperamos tu respuesta Un saludo Pilar Sánchez ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Esta situación se pone en conocimiento de la Dirección-Gerencia del SEPAD para que se valoren las alternativas que se consideren viables. +++Gerencia hace la consulta a Salud Pública. --','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-27','(Pedro) Se recibe respuesta de salud Pública a través de la Greencia del Sepad (Manuel CID) mediante el siguinete correo-e: Buenas tardes (por ayer). En base a los protocolos que establece el Ministerio de Sanidad y el Servicio Extremeño de Salud, si una persona tiene el test de coronavirus negativo a todos los efectos se considera como caso descartado. Un saludo. Dirección General de Salud Pública Avda. de las Américas, nº 2 06800 Mérida Teléfono: 924 382507 ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Esta mañana nos ponemos en contacto con el Hogar "San Vivente de Paul" por teléfono para hablar sobre esta situación. Nuestros interlocutores son Pilar Sánchez (T. Soc.) y Sor Marifé. +++Explicamos la respuesta dada desde Salud Mental y les enviamos posteriormente el correo en el que figura la misma. +++Muestran alguna reticencia, pero finalmente aceptan la respuesta de Salud Pública. +++Pilar comenta que esta mañana irá a recoger a Margarita y quedamos en solciatr el informe de Alta al Hospital. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Ana llama al Hospital para solcitar el Informe de Alta pero le dicen que se lo entregará en mano a Pilar cuando vayan a recoger a Margarita, de alta desde ayer a la espera de lo que se resolviera desde la Dirección-Gerencia. +++Ya habíamos quedado con Pilar en que el primero que tuviese el informe la remitiría al otro.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-03-27','Ana: Llamo a la UME del CSS-Plas. (24176) para hablar con Juan: se alegra de que le llame, dice que le tienen en cuarentena, le digo que como estamos toda la población actualemte. Según expresa su médico de referencia le entiende perfectamente y está deseando darle el alta, lo único que dado el estado de alarma no pueden dársela ahora. Y que cuando se la den *al único recurso que quiere ir es a su casa. Por otra parte mantiene activo su delirio del robo del premio, dice que los jurídicos y la Jueza de Instrucción de Logrosán lo saben todo, que hay personas de la junta también implicadas. *Pide que le llame de vez en cuando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-27','miguel,Me llama Antonio López del Ayto de Málaga (tfno fijo 952-408193 y móvil 646-074626) Me indica que está de teletrabajo. Me dice que este tipo de viviendas forman parte de una bolsa donde el Ayto hace de intermediario para familia en situación de crisis donde el ayto abona una ayuda al alquiler consistente en contratos de 3 años con ayudas por % que varían a la baja cada 6 meses (así los primeros 6 meses la ayuda es del 100%, el segundo 6 meses del 90%, etc). Dice que no suele tener error este tipo de contratos ya que se emite un informe cada 6 meses donde un inspector visita al inquilino y se asegura que vive allí y paga la diferencia que le corresponda por alquiler, caso contrario no se le da la ayuda. Me indica Antonio López que le envíe un email (alvargas@malaga.eu) para cualquier información que necesiten de nosotros y para que él me remita cuando se lo den de los departamentos correspondientes del Ayto (copia del contrato de alquiler + dichos informes justificativos de los abonos). Le envío email y quedo a la espera me remita esos dos documentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2020-03-26','Teléfono de Dª FERNANDA PÉREZ (madre de Antonia): 645-170424','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-12-16','Ana: Coordinación con Paula-CRR Plas: Mª Ángeles se irá a pasar Nochebuena y Navidad (del 23-26) con su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2019-12-16','Ana: Paula CRR-Plas. comunica que se irá a pasar unos días en navidad con sus sobrinos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-12-16','Ana: Coordinación telefónica con Paual, CRR-Plas: Conchi tiene hoy cita en Salud Mental. Estas fechas son especialmente difíciles para ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-03-27','miguel, Remito vía email a abogacía solicitud de intervención para pasar de curatela a tutela','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-03-27','Ana: Pongo para la firma del D.Gerente, la Solicitud de elección de centro de Att. a pers. con discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-03-25','(Pedro)Converscaión con mª Ángeles (CAdex). +++Nos envía el Certificado de Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-03-27','(Pedro) Amalia envía el certificado del CAdex a la Seg. Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2020-03-30','(Pedro)Correo de Futuex. +++27/03/2020 Seguimiento Rosa Gomez Nevado: Tras ver noticias de que en Valencia de Alcántara había aumentado el número de positivos y se encontraban, algunos casos, en las residencias de ancianos, se contacta con la San Antonio, donde se encuentra Rosa Gómez. La enfermera establece que desde ayer tienen a Rosa en aislamiento, su compañera de habitación la llevaron a Cáceres, según comenta, por otros motivos y, al hacerle la prueba, dio positivo, por lo que han habilitado una zona de aislamiento para todas las personas que tuvieron contacto con esta señora. Comenta que las enfermeras pasan a hacer control, tomar temperatura… dos veces al día y luego también acude el médico de cabecera que se les ha asignado para la residencia, una vez al día. Por el momento, Rosa se encuentra estable y asintomática, si hay algún cambio, se pondrán en contacto, de todos modos se le dice que se seguirá llamando, como se ha ido haciendo hasta ahora, ya que el miércoles a última hora de la mañana comentaron que todo estaba bien y ahora nos hemos encontrado con esto, preferimos ir conociendo la evolución. Cuidaos mucho, buen finde dentro de lo que se pueda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-08-13','(Pedro)Conversación con Pilar, T. Soc. Hogar San Vicente de Paul. +++Margarita ha sido trasladada a la UME de Plasencia porque no había sitio en la UHB. +++Ingresó como una "forma de castigo" autoimpuesto por su comportamiento más que porque se encontrse mal, ante el intento de fuga de hace unos días. +++Se pondrán encontacto desde la UME con la Comisión porque no cree que tarden en darle el alta (Emilia, T. Soc.). +++Tanto Pilar como yo consideramos que el Hogar San Vicente de Paul es el mejor recurso en el que puede estar, pero Pilar opina que si no combia su actitud quizá tendrá que marcharse a otro, aunque solamente fuera para comparar y tratar de fortalecer el apego al Hogar. +++Pido a PIlar que cuando regrese al Hogar me avise para intentar hablar con ella de esta situación. Así lo hará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-26','Correo-e recibido en el día de ayer del Hogar San Vicente de Paul: +++Buenos días, Pedro, nos han llamado del Hospital Virgen del Puerto para informarnos que Margarita ha dado negativo en la prueba del Covid 19 y que, psiquiátricamente, puede salir de alta hoy. Ante esta situación, nosotras les hemos pedido un informe donde nos indiquen que no ha posibilidad de contagio si duerme en la habitación con otra de nuestras residentes, ya que nuestro Centro carece de medios para mantenerla aislada en una habitación. Desde Psiquiatría nos dícen que no pueden hacernos dicho informe, solamente informar de que la prueba ha dado negativo y que, psiquiátricamente, se encuentra estable y bien. Nosotras debemos cuidar también de las residentes que se encuentran aquí e informar a las familias del éstas. Ante estos hechos, nuestra pregunta es ¿cómo debemos actuar? Esperamos tu respuesta Un saludo Pilar Sánchez ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Esta situación se pone en conocimiento de la Dirección-Gerencia del SEPAD para que se valoren las alternativas que se consideren viables. +++Gerencia hace la consulta a Salud Pública. --','2');
