insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-30','(Pedro)Conversación con Pilar (Hogar Sna Vicente de Paul) +++Margarita ha pasado bien el fin de semana. Ha vuelto tranquila del hospital y en el Hogar han "reorganizado" la casa para que pueda permanecer en aislamiento, si bien tiene contacto con el resto de compañeras a través de la ventana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-03-30','TERESA: RECIBO LLAMADA DE LOLA TS, ME COMENTA QUE LAS LLAMADAS TELFONICAS DE ADRES (PAULA) CON SU MADRE NO SON NADA BENEFICIOSAS. DE LO DIEZ MINUTOS QUE HABLA CON ELLA UNO ES COORDIAL Y EL RESTO ES DE ISULTOS MUTUOS, ADEMAS TIENE AUIDOS DE WASUP CON ESTOS INSULTOS LOS CUALES LE MUESTRA A SUS COPAÑEROS. ESTAS LLAMADAS PRODUCEN UNA ALTERACION EN ADRES (PAULA) EL CUAL LUEGO INFLUYE EN SU COMPORTAMIENTO EN EL CENTRO. NOS PIDEN DESDE EL CENTRO COMO ACTUAR CON RESPECTO A ESAS LLAMADAS YA QUE ELLOS NO PUEDEN CONTROLAR EL QUE NO LLAME A SU MADRE. ME LO MANDARA POR EMAIL PARA QUE LE DEMOS RESPUESTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2020-03-30','TERESA: ENVIO ESCRITO SOLICITANDO INFORME SOCIAL PARA ADJUNTAR A LA SOLICITUD DE DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-30','Ana: llamada de Damián (622 834 876): Me facilita el nº de Mª Ángeles, técnica del Ayto. de Málaga con la que firmó el contrato de alquiler de su piso (951 92 96 46). Le explico que mi compañero Miguel, Asesor Jurídico, habló el viernes con Antonio López, éste va a consultar los pagos y a facilitar información y documentación a Miguel. *Recuerda que el segundo plazo que debería haberle ingresado el Ayto. era de 1600€ en febrero. // Por otra parte pregunta si me ha llamado Pilar de CETELEM, ante mi negativa me da también su número: 931 00 12 00, según afirma de este crédito le quedan pocos recibos para saldar la deuda. El último será el des mes de junio de 165,25€ (debería finalizarlo en mayo, pero dado que al haber tenido la cuetna bloqueada no se le ha pasado un recibo, le amplian un mes más).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-03-30','TERESA: HABLO CON TERESA DE LA RESIDENCIA, ME COMENTA QUE EL TEMA DE LA DOCUMENTACION DE LA PLZA AHORA ESTA PARADADO POR LA SITUCION, HAN HABLADO CON EL SEPAD. JOSEFA SE VA RECUPERANDO POCO A POCO, SE ENCUENTRA BIEN Y ESTA ADAPTADA AL CENTRO. VAN A VALORAR EL BAJAR LA TARIFA UNA VEZ TENGA UN POCO MAS DE AUTONMOMIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-03-30','-Amalia: guardo una copia del resguardo de la pagina de la Seguridad social donde se indica que la solicitud se ha generado correctamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2012-04-19','Vista domiciliaria. Se mantiene entrevista tanto con Sara como con su hermana Esther, conla quien convivie la tuteleda. Esther manifiesta su deseo de la institucionlización de su hermana. Refiiere ser madre de dos hijos, uno de ellos con discapacidad (posiblemente enfermedad mental), estr separada y no poder hacerse cargo de prestar los cuidados que su hermana necesita. Se le plantea a Sara la posibilidad de ingreso en Centro, aceptando en principio el acceso al recurso residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2012-04-27','Solicitado DNI al SSB de jerez de los Caballeros. Igualmente se solicita informe médico a través de la T. Social del Centro de salud. Documentos necesarios para tramitación de recurso residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2013-03-11','Visitamos el CSS de Mérida para tratar el caso de Iganacio Frutos Dorado, lleva algún tiempo en el centro y la psiquiatra considera que se encuenta estabilizado, sin problemas de conducta y aceptando todas las normas, participando en la terapias... por lo que, debe dar el alta al paciente que no puede vovlver a casa por las ínfimas condiciones en las que se encuentra y se le solicita un ingreso en residencia de mayores (Felipe Trigo) que al estar en su localidad y tratarse de un centro abierto, puede ir a su casa siempre que lo desee. Aunque su deseo es volver a su casa, acepta la opción como algo temporal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-03-30','(Pedro)Acude Soraya al dspacho para informar de que Dª Antonia ha sido ingresada en el Hospital aquejada de neumonía, requiriendo respiración asistida. +++Prevé que vaya a estar cierto tiempo ingresada hasata que se descarte con seguridad si se trata de covid-19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='VAZQUEZ'and apellido2='GILEZ'),'2020-03-30','TERESA: RECIBO DOCUMENTACION DEL SOCIOSANITARIO, MANUEL TIENE UN MONTON DE MULTAS Y DEBE RECIBO DE RODAJE. APORTAN UN LISTADO DE COCHES QUE ESTAN A SU NOMBRE Y GENERAN MULTAS Y RODAJE. TIENE UN EMBARGO POR ESTE MOTIVO LE PASO LA DOCUMENTACION A ALBERTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-30','(Pedro)Llamada de Damián (622-834876). +++"La que sabe lo que el inquilino me tiene que pagar el 4º semestre (135 euros) es Rosa, del servicio de inofrmación del Ayto. de Málaga (951-926010).Anonio López sabe lo que le corresponde al Ayto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-03-30','Ana: Recibo llamada de José Manuel (667 384 817), pregunta por el dinero para comprar el bonobús, le digo que ahora no lo necesita, pues en Estado de Alarma no debe salir de casa. Dice que sí, para ir a ver a su hermano. Le vuelvo a explicar, e insisto, que no debe salir de casa, nada más que para cuestiones imprescindibles, farmacia y médico, y a los recursos más cercanos a su casa. Que además no están permitidos los encuentros y reuniones ni en la calle ni en casa de nadie. // En cuanto a su hijo dice que anoche volvieron a discutir y que finalmente le dio 50€ para una "minicadena". *Le recuerdo que ese no es un gasto necesario y que supone la mitad del efectivo autorizado hasta el 11 de abril, por tanto no podrá pedir más dinero hasta esa fecha y tendrán que organizarse con lo que le quede. *En relación a ésto dice que la oficina bancaria le han dicho que habrá que hacerle una tarjeta monedero con la cantidad autorizada para que pueda retirarlo del cajero. *Se lo comunicaré los compañeros del área económica. // Pregunta tamibén por el acceso a centro. Le indico que estas gestiones en estos momentos están paradas. // En relación al catering que se le ha gestionado se muestra muy contento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2020-03-31','(Pedro). Correo-e de Asoc. "Vera": +++Adjunto Autorización para realización de tatuaje de su tutelada Dña. María del Carmen Mellado Guardabrazos, si se autorizase. Nosotras desde el centro le hemos explicado las consecuencias y lo que puede acarrear hacerse un tatuaje pero insiste mucho, lo dejamos a criterio de la Comisión Tutelar de Adultos. +++SE responde por teléfono (Edi, psicóloga) y por correo-e en sentido negativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-03-31','Ana: Recibo llamada de Felisi (722 494 033) y Jesús, preguntan por la próxima asignación, como se le hizo trasnferencia para 2 semanas, ya les correponde volver a sacar efectivo este jueves día 2. *Lo comunico a la secc. ecca. por mail. /// *Las compañeras me confirman que ayer hicieron la tranferencia para otras 2 semanas. Llamo a Felisi y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2020-03-31','(Pedro)Se realiza videollamada desde Novaforma, en la que participan Juan Manuel otros comapañeros y Teresa. +++Nº de videollamada: 633-325790 (el sábado es el cumpleaños de Juan Manuel y le han regalado una Tablet cedida por el banco ¿?).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-03-31','TELÉFONO 635336539','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-03-31','Ana: Correo de Miguel Ángel Ramirez Félix, Director del CRR-CC (residenciadir@feafescaceres.com): "Buenos días, os informo que ayer recibimos llamada telefónica desde el Hospital San Pedro de Alcántara para derivarnos el estado de Salud de Antonia Canelada del Rio durante los días que lleva ingresada en el mismo, nos comentan que la tienen con oxigeno pero que por sus circunstancias la han tenido que poner sujeción mecánica en los miembros superiores ya que se tiraba de la misma y no estaba haciendo el efecto que debiese. Hoy probaran con una mascarilla ya que la que tenía puesta ayer le estaba produciendo sobre- oxigenación. Nos comentan que le realizaron la prueba de la COVID-19 y que el resultado fue negativo, se la volverán a repetir en 48 horas. Nos mantendrán informados durante todos los días que esté ingresada. Un cordial saludo." ////////////////////////////// Nuevo correo de Miguel Ángel, Director CRR-CC: "Buenas tardes, hemos recibido información sobre Antonia Canelada del Rio desde el HSPA, comunicándonos el cambio de regulador de oxigeno por lo comentado anteriormente (sobre- oxigenación) y parece que el resultado esta siendo más eficaz, ya que nos dicen que habían planteado pasarla a la UVI pero al final han decidido dejarla en planta, la tienen con sujeción mecánica en miembros superiores por el tema de la retirada de la mascarilla por la misma no es porque presente ningún síntoma de su psicopatología ni alguna alteración conductual. Mañana le repetirán las pruebas de COVID-19. Os mantendremos informados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MONTAÑA'and apellido2='SANTOS'),'2020-03-31','Ana: Correo de Rosa Bravo, Admvo. CSS Plas . (rosamaria.bravop@salud-juntaex.es): Envía C.I. para realizar BIOPSIA SELECTIVA DE GANGLIO CENTINELA EN EL CÁNCER DE MAMA, para CIRUGÍA MASTECTOMÍA SUBCUTANEA y para LINFADENECTOMÍA AXILAR. *Pedro recaba la firma y lo devuelve debidamente firmado y sellado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-03-31','miguel, tras mi primera conversación telefónica con el tutelado de cerca de 1h, estas son las conclusiones: Sus datos dni nº 53692319S, Y TLFNO 622-834876 Me comenta que tiene una cuenta en Popular (actual SCH de Torremolinos en Pza de Andalucía, DATOS DE CONTACTO EMAIL: 00750214@bancopopular.es y tlfno 952-384844) nº c/c ES 09-0075-0214-61-0602014154. Dice que todos los gastos que indico son cargados en su cuenta: Actualmente a parte de los 80€/mes de la cdad de propietarios, y el IBI, tiene ptmo personal con Cetelem (contacto Pilar 931001200) que termina de pagar en Junio Ptmo con Cofidis con nº de contrato 29907000068399(contacto Tlfno 900848012 y 682860531) de 538€ por el cual paga 35€ y le quedan 20 cuotas. Y por último un ptmo en banco Popular de 4071€ de pago por el que viene pagando al mes 161€. En cuanto al piso que tiene alquilado en c/ DAN 4º A 1, en camino de San Rafael (Málaga)y ref. catastral 9931101UF669350157YI,indica: nº de contrato PAA2388, inquilinos matrimonio Antonio Pinto Estrada (contacto nº 693376363) y Mª Victoria Sánchez Navarro. Fecha de inicio 1/8/2018 y duración de 3 años. Se abona por semestres donde la ayuda o subvención, en %,va disminuyendo desde el 100%, y donde actualmente está en el 4ª semestre. El Ayto le abonó en 2018 5.880€; en 2019 (1º semestre: 2160€); 2º semestre (pte de que le abonen ahora) 1.600€ En 2020 no le han abonado nada En cuanto al inquilino: no sabe cuánto le debe ni desde cuándo, pero lo que es seguro es que tanto lo del ayto como lo del inquilino se lo cargan en la cuenta del popular mencionada. Por tanto tanto los cargos como los abonos de este curatelado podemos verlos en los movimientos de su cuenta en el Popular. Me menciona como contactos del Ayto además de Antonio López, a Rosa: de quién dice que lo sabe todo en torno a lo que le deben y a lo que le han ingresado. La llamo varias veces pero comunica...Me da otro contacto en el Ayto, Mª Angeles (tlfno 951-929646) quién dice llevaba tema de contratos de alquiler. Por tanto, seguiremos a la espera de que Antonio López del Ayto nos envíe contrato de alquiler y pagos realizados hasta ahora. No creo que recibamos del CRR de Plasencia documentación alguna ya que dice el curatelado que está roto el escaner. A él le encargo dos cosas: 1) Cuando termine el estado de alarma pida cita para la declaración de la renta de IRPF, ya que dice ganar 1475€/mes y al haber recibido ayudas de alquiler del Ayuntamiento entiendo que pueda estar superando el mínimo obligatorio de los 22.000€ fijados por hacienda para obligar a declarar. 2)En cuanto termine el estado de alarma, si yo no me hago con la documentación a través de Antonio Lopez o Rosa (tlfno 951926010), él tendría que fotocopiarla (todo lo que tenga de contratos, ptmos, etc) y enviarnosla por correo certificado a la CTAEX. Ya le aviso que ya le llamaremos si necesitamos algo pero que en principio hasta dentro al menos un mes que pase el estado de alarma no le llamaremos. Llama de nuevo para decirle a Pedro que el 14 de abril tenía un juicio de un dinero que le quitaron en Cáritas de Málaga, ya le explica Pedro que los plazos de todo están interrumpidos por el estado de alarma y que ya le volveran a llamar desde el juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GALAN'and apellido2='MERINO'),'2020-03-31','miguel, Amalia llama porque esta mujer tiene el Covid 19, no está en principio grave, pero el problema es que vemos que en el expediente no hay inventario hecho ya que todavía no vemos que haya llegado sentencia firme de nombramiento y aceptación como tutores. Mando email a Julio y Juan Pedro para cercionarme','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2020-03-31','Ana: Correo de Toni-Futuex: "Buenas tardes, la situación de la residencia de Valencia de Alcántara, donde reside Rosa Gómez, es más complicada de lo que indicó ayer la directora, al parecer , en el comunicado diario que saca el alcalde de la localidad, comunicó que hay 21 profesionales de baja de la residencia San Antonio, puestos que están cubiertos (supongo que algunos por voluntarios) y 22 usuarios aislados, entre ellos Rosa Gómez, por el positivo de su compañera de habitación, por ahora lo que sabemos es que se encuentra bien, aunque aislada, no conseguimos tener mucha mas información, por parte de la residencia. Estamos en contacto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2020-03-31','(coral). Maribel del css de Mérida, nos hace saber que Juan Bautista, ha ingresado en el Hospital de Mérida con fecha 30 de marzo de 2020 y que le han hecho la prueba del COVID19 y ha dado NEGATIVO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-04-01','Ana: Correo de Pilar, Hogar San Vicenet de Paúl (direccion.hgsvplasencia@gmail.com): "Buenos días, les informo de que Margarita sigue bien, y está llevando, hasta hoy, esta situación con mucho ánimo y buen talante. Si hubiera cualquier cambio les informaríamos. Deseamos que sigan bien. Un saludo Pilar Sánchez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-01','Ana: Recibo llamada de José Luis, hermano de José Manuel (687 581 061), le ha avisado su hermano, la policía le ha multado, iba en autobús urbano sin causa justificada, al parecer ya es la segunda vez que le paran piden los datos. *Ya le habíamos advertido varias veces sobre el hecho de que no debe salir de casa y menos sin causa justificada. *Por otra parte le ha dicho a su hermano que ya se ha gastado los 100€ que se le dio. Me pide que le llame. ///////////////////////////////////////////////////////////////// Llamo a José Manuel(667 384 817), dice que unos policías le han multuado cuando iba en el bús, pero que no es justo porque no han multado a más personas que iban también en el autobús. Le recuerdo que ya es la 2ª vez que le paran. Le han advertido que a la próxima irá a calabozo. *Le reitero que no debe salir, expresa que iba a ver a su hermano, para pedirle dinero para tabaco, pues ya se ha gastado toda la asiganación. Insisto en que ya se lo expliqué, que tampoco debe ir a ver a su hermano y que también se le dijo que debía administrar bien el dinero que se le daba, no se le va a autorizar más hasta la fecha acordada, además dadas las circustancias las gestiones en los bancos son complicadas, por eso se le dio el dinero de varias semanas y que lo sabe bien, pues se le explicó. Dice que está cansado de estar encerrado en casa, que él sólo sale por las mañanas. Insisto una y otra vez en que no debe salir todos los días y menos aún sin causa justificada, pero me temo que no atenderá a razones. *Cuando reciba la multa nos lo comunicará, no sabe de qué cuantía será.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-04-01','Ana: Recibo llamada de Conchi (677 407 893), quiere conocer el estado de su deuda. Le explico que no es buen momento para estas gestiones dado el estado de alarma por la crisis sanitaria. Responde que entonces "cuando se pueda". Al intersarme por cómo se encuentra, dice que regular, pues ya hace 3 años que perdió a su hijo y 2 a su madre. Pero que tiene que ponerse bien por su hija de 7 años. Trato de reforzarle este aspecto e infundirle ánimos. Se muestra agradecida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-04-01','Ana: Correo del día 30/03 de Cristina, Ed. Asoc. Vera: "Buenos días, Adjunto envío consentimiento para remitir firmado de su tutelado D. Adrián Ortigosa Ortín para extracción de pieza dental." Pedro, Jefe secc. CTAEX, lo puso para la firma del D.Gerente. ////////////////////////// *Icíar remite, a día de hoy, el C.I. del Programa PADDI debidamente firmado y sellado por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-04-02','Ana: Correo de ayer por la tarde (ssb32mancomunidadcomarcatrujillo@hotmail.com): "Buenas tardes Ana: Adjunto remito informe social solicitado de Isabel Muñoz Melchor. Perdona por el retraso pero estamos muy liados Espero te encuentres bien Un abrazo y cuídate Mª Jesús Gómez Lozano Trabajadora Social SSASB Mancomunidad Comarca Trujillo" // Lo reenvío a Icíar y Coral, CTAEX, y lo guardo en el expte. PC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-04-02','Ana: Correo de Miguel Ángel, Director del CRR-CC (residenciadir@feafescaceres.com) "Buenos días acabamos de recibir llamada telefónica del HSPA para informarnos sobre el estado de Salud de Antonia Canelada del Rio, los resultados obtenidos en la segunda prueba de la COVID-19 han sido negativos y hasta el momento se encuentra estable, abordable y comunicativa, continua con el oxígeno puesto y con medicación tanto de salud mental como para los síntomas que está presentando allí. Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-04-02','TERESA: RECIBO LLAMADA DE JOSE VICENTE DESDE CENTRO PENITENCIARIO.NECESITA DINERO PARA COMPRAR ROPA, SE LO PASO A GESTION ECO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-04-02','SE AUTORIZAN 20 EUROS PARA CELEBRAR SU CUMPLEAÑOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-04-01','TERESA: Ante la situación vivida del lunes con Paula, lo han puesto las psicólogas en conocimiento del psiquiatra de salud mental de don benito Y cambia medicación Xeplion (como estaba pautado) Escitalopram 10, 1/2 por la mañana durante una semana. Después de la semana 1 entera Topamax (como estaba pautado) Risperdal 3ml-3ml-3ml Alprazolam 1/2-1/2-1 (como se pautó el 27/03/20)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-04-02','TERESA: EMAIL DE TONI GALAN PSICOLOGA INSPECCION MADEX Buenos días. Acabo de hablar con Silvia, gerente de Plena Inclusión Cabeza del Buey sobre Paula (Andrés Silva Bonifacio) y me dice que los intentos de agresión al personal y ocnducta de autolisis de Paula van en aumento. Están ahora intentando darle la medicaicónderescate...pero les dice Alberto GAlelgo, psiquiatra y su médico que de servir así deben activar el protocolo 112. Hemos hablado de algunas opciones qu pueden hacer ahora de control de estímulos para reducir los intentos de agresión epro quizás no sean posibles llevarlo a cbo. Lo va a hablar ocn el Equipo. La preocupación que Plantea Silvia es que al activar el 112 lo ingresarán en la UHB y después cuando lo estabilicen volverá al centro y necesitará 15 días de aislamiento, lo cual en el caso de Paula es muy difícil por no decir imposible, esta medida preventiva. La entidad plantea que se pueda quedar en el sociosanitario. Le doy traslado a Soraya y me comunica que "si tiene que ingresar en la UHB que lo hagan y luego vemos como se continúa. Que la UHB se trasladará al sociosanitario..." .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-04-01','TERESA: EMAIL LOLA TS PI CABEZA Esta mañana la cuidadora de Residencia nos ha comentado que ayer por la noche Andrés intentó tirarse por el balcón. Nos dice la cuidadora que tuvo que sujetarlo porque tenía, incluso, una pierna por encima de la barandilla del balcón. Estaba hablando con su madre del tema de la tutela; la madre solicitó hablar con alguna cuidadora y dijo que su hijo estaba hablando de suicidarse porque no aguantaba más. La cuidadora le preguntó a Andrés y éste le dijo que era verdad, salió corriendo para el balcón y fué entonces cuando tuvieron que sujetarlo. Nos comenta la cuidadora que la noche la ha pasado tranquilo, pero que esta mañana ha estado llorando y dice que su madre le ha bloqueado el teléfono. No sabemos si fué una llamada de atención o un intento real de suicidio. Tenéis vosotros conocimiento de que haya sucedido algo parecido anteriormente?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELINA'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2020-04-02','Ana: Tras haberlo intentado en varias ociasiones, hoy sí consigo contactar con la Res. Real de Navalmoral (927 87 99 44). Hablo con Beatriz, direcotora, me facilita su correo electrónico: direccion@residenciareal.com. Le enviaré mi teléfono directo así como otros contactos de la CTAEX. *Marcelina continúa bien adaptada al centro y a la dinámica del mismo y de salud se encuentra bien. Ante cualquier cuestión seguiremos en contacto. ////////////// Le envío por mail los contactos de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-04-03','Ana: Pongo para registro de entrada la solicitud de elección de centro de Att. a pers. con discapacidad. // Dan registro de entrada el mismo día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2020-04-03','Ana: Llamo a la Residencia S.Pedro de Alcántara (927580624), me dicen que Ivonne, Directora, no se encuentra en estos momentos. Toma nota, le dirá que me llame cuando llegue. //// A media mañana recibo llamada de Ivonne (690 962 955), expresa que en estos momentos tienen la situación muy controlada y se están guiando por criterios médicos. Ya llevan varios fallecimientos en los centros que gestiona, en todos los casos se tratan de personas de más de 90 años con patologías previas. *Rosa sigue en aislamiento, pues su compañera de habitación y mesa en el comedor dio positivo en el hospital. Como en las residencias no están pasando los test no saben si tiene el virus. De momento continúa estable. Tienen 2 zonas diferenciadas de aislamiento, una para pacientes críticos y otra más intermedia, que es en la que se encuentra Rosa. Estará allí hasta completar los 21 días como les han pedido y de ahí, en función de su evolución, puede que pase a otro confinamiento sola de otros 14 días, si continuara asintomática tras este otro periodo acabaría por pasar al "Albergue", que es a donde han trasladado a los residentes que en principio están bien y no han tenido contacto directo, que sepan, con nadie infectado. *En cuanto a la cadera, evoluciona bien. Llamaron del hptal. para comunicar que se aplazaba su cita de seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-02','Ana: Recibo llamada de Pilar Martín, TS del ESM-CC (54612): Le ha llamado José Manuel, le ha contado lo de las denuncias y multa por saltarse el confinamiento. Propone que lo comuniquemos al Jdo., sobre todo el riesgo que supone para la Salud Pública no sólo el que él no cumpla la cuarentena, sino que su hijo, mudado recientemente a vivir con él, lleva a amigos a casa por las noches, estando prohibido en el estado de alarma. Se lo ha reconocido a ella y a Begoña (686 24 81 40), persona que atiende en la Plataforma Telefónica de CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-03','Ana: Hablo con Miguel, Asesor jurídico, acordamos que llamará a la Policía para solicitar las denuncias que han puesto a José Manuel por saltarse el confinamiento. Hará un escrito para comunicarlo a fiscalía. *Yo llamaré a Begoña y a Pilar Martín, a quién le solicitaré informes. ///////////////////////////////////////// Llamo a Begoña (686 24 81 40), Proyecto "En casa pero no solos" (Red de voluntariado de acompañamiento telefónico), el caso se lo derivó Pilar Martín, para que le llamen a diario. Me cuenta lo que le cuenta José Manuel a diario y su preocupación con el riesgo al que se expone y al que expone al resto de la población saltándose el confinamiento y dejando entrar en casa todas las noches al hijo con sus amigos, según le ha dicho ya no vivie allí el hijo porque volvieron a discutir y se volvió a casa de la abuela, pero va todas las noches con gente. Además éste lleva encima el certificado de discapacidad de José Manuel por si le para la policía justificar que va a atender a su padre. No nos va a poner nada por escrito, pues no sabe la fiabilidad que tiene lo que él le cuenta y ella es voluntaria. //////////////////////////////////////////////// Llamo a Pilar Martín, ESM-CC (54612), no responde.*Envío correo solicitando informes (social y médico) del ESM e informando de las otras gestiones desde la CTAEX. //////////////////////////////////////////////////////////////////// Correo que envía Miguel, Asesor Jurídico CTAEX, a la dirección que le han facilitado la policía municipal de Cáceres: "Buenos días, conforme hemos hablado por vía telefónica, desde la Comisión Tutelar de Adultos somos tutores y curadores por cargos de resoluciones firmes judiciales de más de 700 personas. Desde los Servicios Sociales de Cáceres nos informan problemas con uno de nuestros tutelados. En concreto necesitamos nos remitan cualquier tipo de incidentes (atestados, denuncias, multas etc) en relación con el tutelado por esta Comisión Tutelar de Adultos, Don José Manuel Romero Mediavilla, para podamos comunicarlo a la fiscalía territorial de los Juzgados de Cáceres, a efectos de que si lo estiman oportuno se adopten las medidas oportunas de carácter preventivo ante el incumplimiento de confinamiento que en estos días de estado de alarma viene realizando dicho tutelado. Tal como le he comentado, desde la Junta de Extremadura lo más que podemos hacer en estos momentos es una tutela administrativa, es decir que no podemos impedirle salir de su casa, ni tampoco podemos internarle en un centro porque para ello tendríamos que iniciar judicialmente un procedimiento de internamiento involuntario que puede llevar meses, por lo que les pedimos que si se produce algún tipo de alteración de conducta que requiera intervención de los centros sanitarios rogamos avisen al 112 y que nos lo comuniquen a este email corporativo: ctutelar@salud-juntaex.es a efectos de que a su vez lo podamos comunicar a la fiscalía de los juzgados territoriales de Cáceres. El problema ante el que nos encontramos no es únicamente el incumplimiento de salidas sin autorización de la vivienda del tutelado, sino además que en su vivienda entran y salen continuamente personas que acompañan por la noche a su hijo. No consta que éste va con el documento de incapacidad de su padre a efectos de justificar sus idas y venidas a casa de su padre. Dicho hijo no debería estar viviendo allí, y supone un riesgo por cuanto él y los amigos que lo acompañan incumplen el confinamiento del estado de alarma y supone una desestabilización para nuestro tutelado. Todos estos hechos nos comentan desde Servicios Sociales de Cáceres pueden comprobarlo por las noches. Desde esta Comisión quedamos a su disposición para cualquier aclaración. Asimismo les comentamos que procederemos a actuar de la misma forma con cualquier otro tutelado por esta Comisión Tutelar de Adultos de la Junta de Extremadura, en el sentido de comunicárselo a ustedes a efectos de que nos remitan cualquier incidencia que se pueda producir, y de esta forma podamos a su vez dar traslado a la fiscalía de Cáceres. Agradeciéndoles de antemano su colaboración les saludo atentamente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-03','Ana: Hablo con Miguel, Asesor Jurídico, dice que ha recibido correo de Antonio López - Ayto. de Málaga, y éste le facilita el nº directo de su compañera Loreto (626 96 73 21) para que hablemos con ella. ///////////////////////////////////////////////////////// **Icíar me comunica que le ha llamado Damián y éste le ha dicho que el Ayto. de Málaga le ha hecho el ingreso pendiente del alquiler: 1800 €. **Al parecer Damián tiene acceso para ver los movimientos bancarios online. /////////////// Llamo a Loreto, Ayto. de Málaga (626 96 73 21), pero salta el buzón de voz. Le dejo un mensaje pidiendo que cuando pueda se ponga en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-02','Ana: Recibo llamada de Damián (622 834 876), dice que ha llamado al Ayto. de Málaga y ha hablado con Loreto. Ésta le ha dicho que tendremos que enviarle la Incapacitación Judicial y otros documentos que justifiquen la situación para que pueda remitirnos el contrato de alquiler. Acordamos que como ya es muy tarde llamaré mañana. ///// *Independientemente de esto, Damián aprovecha la ocasión para expresar que es gay, que tuvo pareja con la que no le fue bien y a raíz de ello entró en depresión. Dice que le "trataba como un crío y no como un hombre".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-04-03','Ana: Correo de Miguel Ángel Ramirez, Director del CRR-CC (residenciadir@feafescaceres.com): "Buenas tardes, os informo, se han puesto en contacto con nosotros desde el Hospital para darnos la información sobre Antonia Canelada del Rio, ya no lleva oxigeno puesto porque el nivel de saturación ya se ha disminuido mucho, que no le van a repetir más pruebas de COVID-19 puesto que ha dado negativo en las dos pruebas que le han realizado y los síntomas que presenta no están relacionadas con el VIRUS. Me ha comentado que ya no le van a realizar más pruebas por lo comentado anteriormente y que probablemente le den de alta el lunes, me vuelven a llamar para reafirmar que le van a dar de alta el lunes… Me informa esta última que nos llamará otra tercera persona para informarnos definitivamente de lo que nos han comentado las dos anteriores. Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-06','Ana: Recibo llamada de José Luis, hermano de José Manuel (687 581 061), me pide que llame a su hermano. //// Llamo a José Manuel (667 384 817): pide que le busquemos un centro. Una vez más vuelvo a explicarle el procedimiento y cómo está la situación. Me cuenta también que anoche volvió a tener problemas con su hijo, que lo tuvo que echar de su casa y que éste incluso quiso pegarle. **Vuelvo a insistir que es él quién le está permitiendo entrar en casa, a él y a sus amigos, y que ante estas situaciones lo que debe hacer es llamar a la policía. *Jura que su hijo no volverá a entrar más en su casa. //////////////////////////*Miguel, Asesor Jurídico CTAEX, recibe por mail el Acta de la Denuncia que pusieron a José Manuel por saltarse las condiciones del Eº de Alarma. Lo guardo en el expte. PC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2020-04-06','TERESA: ANASTASIO RESIDE EN LA R.M. DE BARCARROTA. ACTUALMENTE NO TIEN DNI POR ELLO NO PUEDE SACAR DINERO. ESTA JUANA MEDOIANDO CON LA RESIDENCIA PARA QUE SE LO HAGA COBRA UN INC PERMANENTE 913.79 EUROS, PAGA 800 DE RESIDENCIA LE COMENTO A CORAL QUE TIENE SEGURO DE DECESO PERO EL ULTIMO RECIBO HA SIDO DEVUELTO PORQUE NO HABIA SALDO EN LA CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-03-31','-Amalia: Su madre, Rosa Galan Merino ( en defensa judicial a la espera de tener sentencia firme) está aislada en la RM Rosalba por covid19. Hablo con el medicio y me comenta que está estable. Hablo con la DTRA. ( BEA) , para comentarle la situacion juridica de esta Sra. Confirmamos que no tiene S. Decesos ni dinero . Sus herederos serían J. Carlos ( sin dinero en cuenta ) y su hno que reside en Barcelona. Si falleciera tendrían que ponerse en contacto con él o hacerlo por beneficencia con el Ayto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-04-01','-Amalia : Me llama la TS del pueblo , la auxiliar SAD que tiene asignada está con tos. Se activa protocolo covid y aislan a la chica hasta conocer resultados . Al quearse sin auxiliar y aunque tenemos asegurados comida y medicacion que se le envia desde el C.Dia, se solicita SAD privado. Contacto con ASINDE para poner a alguien un par de horas , para supervisar higiene personal y tirar la basura ...Al rato me avisan que la chica ha dado negativo y regresa al trabajo , anulo el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-04-02','-Amalia. Sigue bien , con auxiliar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2020-03-31','-Amalia : ha sido dado de alta y gestiono traslado al domicilio. Siguen las dos auxiliares que tenemos de la Asociacion Oncologica por prestacion vinculada. Me comenta la TS del pueblo a través de Futuex que necesita acompañamiento por la tarde pq necesita máquina de oxigeno. Tras reticencias de las auxiliares, temen a pesar de que la prueba que se le practicó en el hospital que dio negativo a covid19 , que pueda estar contagiado. Van a estar unas horas más y se amplia el servicio con la empresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2020-04-03','-No acaba de remontar , han llamado al C. Salud y activan protocolo . No van a verlo a domicilio pero envian una ambulancia q lo traslada a Badajoz.Con la coordinación de Futuex , ponemos nuevamente acompañamiento hospitalario con la empresa el Angel. Son las 14.30 del viernes , contacto con Coral ( CTAEX ) necesito saber si tiene S. Decesos y con qué compañía por si tuviese que avisar . Consigue averiugar que es de Maphre. La auxiliar contratada va al hospital , pero sobre las 15.00 h. nos avisan que por protocolo , va a aislamiento hasta ver nuevas pruebas. Se anula servicio . El viernes por la tarde , a las horas, nos avisan que ha dado negativo en covid a pesar de su insuf. respiratoria y renal. Se vuelve a activar el acompañameinto hospitalario, 8h. al dia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-03-31','-Rorio ha mejorado un poco , sigue en domicilio atendida por Miryam.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-04-06','-Amalia: Recibo email de Miryam , la interna , está con sintomas de tos y se activa protocolo covid19. EStá aislada y en sustitucion de ella está con Rosario su sobrina. Parece que Rosario tiene tos y se supone que le harán las pruebas a todas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-04-06','-Tras contactar con Inma , la TS , se acuerda esto: Hola Amalia, yo sí conozco la situación porque hablé con Miriam el sábado. La sobrina es de confianza, ya ha cuidado algunas veces a Rosario y es competente y Rosario la acepta bien. Con respecto a las compras, simplemente es que Rosario no puede quedarse sola y entonces necesitaría apoyo para las compras, pero nos ocuparemos desde la Ayuda a Domicilio municipal, no te preocupes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2020-04-06','Amalia : resumen de la semana pasada y estado actual . Alonso Ortiz Germán con D.N.I nº 76248290C, ingresado con fecha 03 de abril 2020 en el hospital universitario de Badajoz por recaída en su infección renal, dando como resultado parámetros muy alterados en las analíticas y con necesidad de oxígeno. Por protocolo establecido, se le tuvo que repetir prueba de covid19 y ser aislado en zona del hospital para ello. Los resultados han dado de nuevo, por segunda vez, negativo. Se decide por tanto su traslado inmediato al hospital perpetuo socorro el viernes noche, quedando ingresado en planta 2ª habitación 204. En el fin de semana, según la información de sus cuidadoras, en los horarios ya establecidos (cuatro horas mañana y cuatro horas tarde) se encuentra tranquilo, con buen apetito. Con sonda y gotero, además del oxígeno. Contactos de cuidadoras: -Horario Mañana -Horario tarde: Montse Villalobos (638720505)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2020-04-06','-Amalia : Me confirma Cori que no tiene seguro de decesos , tiene dinero para cubrir gastos llegado el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-04-06','Ana: Recibo llamada de Mariví Clemente, TS CSS-Plas (927 428 800), el viernes pasado (día 3/04) ingresaron a Desideria y Ángel en el CSS, por descompensación (con su delirio compartido) pero los llevaron con lo puesto. Necesitarían que les llevaran ropa y dinero. Proponen que acudan las compañeras de Futuex. //// Llamo a Toni (600 56 42 15), y expongo lo ocurrido y la propuesta de Mariví. Dice que esta opción no es viable, desde que Desideria y su marido se trasladaron a la nueva casa que comprá Ángel, éstos no han consentido que acudan por allí, ni siquiera saben dónde está ubicada la casa. Tampoco conoce las condiciones de la misma ni si el matrimonio ha estado expuesto al COVID-19, por lo que no va a exponer a las delegadas a una situación de posible riesgo. Por otra parte se sorprende del ingreso del matrimonio, pues la semanas pasada cuando hablaron con ellos no notaron nada raro. /////// Tras hablar también con Pedro, Jefe secc. CTAEX, intento contactar numerosas veces con el CSS sin éxito. *Finalmente envío un correo a Mariví Clemente pidiendo que se ponga en contacton conmigo de nuevo. /////////////// Más tarde Toni-Futuex reconoce que estaba confundida, aún no se habían mudado a la nueva casa, continuaban en la de alquiler a fecha del ingreso en CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-04-06','Ana: Correo de Toni-Futuex recibido por la tarde: "Desde que se declara el estado de alarma en nuestro país debido a la situación de emergencia sanitaria por COVID19, se realiza seguimiento telefónico continuado para estar al tanto de la situación de la tutelada. Desideria vive con su marido Ángel. El seguimiento telefónicos se realiza tanto al teléfono de Desideria como al de Ángel, incluso en ocasiones se comunican vía WhatsApp. Durante el seguimiento en estas semanas no hemos percibido ninguna incidencia, pudiéndose mantener buena conversación con ambos y transmitiendo que la situación era estable. La última conversación fue del jueves 02 de abril por la tarde, en la que expresan estar bien y preguntan por la gestión de retirada de dinero en efectivo. Hoy, lunes 6 de abril a primera hora se intenta contactar con ellos a través de los dos números de teléfono siendo imposible por estar apagados. Seguidamente nos informan de la situación referente a sus ingresos en el CSS de Plasencia. Sorprendiéndonos de dicha situación pues en ningún momento hemos percibido ningún indicativo de ello. Se resalta que a principio del pasado mes de marzo cuando proceden a la compra del piso, nos ponemos en contacto con la pareja para preguntar qué tienen pensado hacer con el contrato de alquiler que tienen actualmente referente al piso en el que residen. Ángel expresa que ha hablado con el casero (propietario del inmueble) para avisar que dejarían el piso el mes siguiente, es decir, Abril; y habían llegado al acuerdo de dejar el dinero de la fianza por la cuantía correspondiente al mes de marzo. Al decretarse después el estado de alarma, no sabemos si esa situación ha cambiado, si han decidido gestionarlo de otra manera y no nos han informado o si por el contrario se mantiene y por ello han decidido ingresarse en el CSS. Lo cual sería extraño ya que aún mantienen todas sus pertenencias en el piso de alquiler por no poder realizar la mudanza al coincidir con el estado de alarma. Con ellos es impredecible, pues gestionan sin informar bajo la responsabilidad de Ángel sin tener en cuenta la situación de incapacitación judicial correspondiente a Desideria. No tenemos el contacto del casero, cuando Angel procedió al alquiler con la persona que contactamos fue con la profesional de la inmobiliaria Estucasa (660196943). En la factura se refleja los datos de contacto de la inmobiliaria. Tal en una situación excepcional como puede ser esta se puede contactar con ellos que tendran contacto con propietarios... como comentamso antes los chanchullos de angel o acuerdos que haya hecho con ellos para pago de este mes o no pago, los desconocemos Mañana seguimos! buena tarde y cuidaos mucho"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-04-06','Ana: Correo de Pedro González Peña, T.O. del CRR-CC (residenciadir@feafescaceres.com): "Acaban de confirmarnos que le dan el alta hospitalaria a A.C.D.R. Se ha intentado que esperaran a mañana para dar tiempo a preparar la habitación, pero la médico ya había solicitado la ambulancia. Se ha hablado con los monitores para que se ubique a A.C.D.R en la habitación que está libre en la actualidad en el CRR y se proceda a informarle que deberá estar con mascarilla en todo momento y extremar las medidas de limpieza. En el informe que nos traen viene con negativo en COVID-19. Por lo que estas medidas se toman en base a nuestra seguridad y la del resto de personas usuarias. Un cordial saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-04-01','Se envía a Asociación Vera por correo electrónico consentimiento informado para tratamiento odontológico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-04-07','Ana: Correo de Miguel Ángel Ramirez, Director del CRR-CC (residenciadir@feafescaceres.com): "Buenos días Ana, te remito el informe de Ingreso y alta hospitalaria de Antonia Canelada del Rio, con todas las pruebas realizadas y los resultados obtenidos en las pruebas y el tratamiento que debe mantener. Un cordial saludo" // *Guardo en expte. PC (Carpeta COVID-19) el Informe de Alta Hospitalaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-06','Ana: Llamo a Loreto, Ayto. de Málaga (626 96 73 21)sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-07','Ana: Llamo a Loreto, Ayto. de Málaga (626 96 73 21): no obtengo respuesta, pero dejo un mensaje en el buzón de voz piendiendo que cuando sea posible se ponga en contacto conmigo, indico nº tlf.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-04-07','Ana: Llamo al CSS (927 42 88 00), Mariví no está, se turnan para trabajar, no realizan teletrabajo. Me pasan con Estrella Durán, TS: Le comento el motivo de la llamada de ayer de Mariví. Averiguará el motivo del ingreso del matrimonio , la unidad en la que están ingresados y si necesita dinero. En cuanto al tabaco, aún a los pacientes de UHB, en el CSS se les está permitiendo fumar. *Explico que desde Futuex no van a acudir a Plasencia y que *desde la CTAEX, sólo se llevarán a cabo gestiones que atañan a Desideria. Me devolverá la llamada. //////////////////// Llamada de Estrella Durán: Me informa que el lunes 30 ya habló Ángel con la Psicóloga y estaban mal, decían que no dormían tenían activo el delirio, decía que había un hombre viviendo entre cartones que les quería robar. Cuando otro día dijo que él iba a rociar al hombre en cuestión es cuando activó al 112. *Tanto Desideria como su marido están ingresados en UME, puesto que no están estables permanecerán ahí. *En cuanto al COVID-19, a día de hoy no presentan síntomas. **En el caso de que valoren que Desideria necesita dinero para gastos de bolsillo, enviarán un correo al ctutelar@. ///////////////////////////////////////////////////////////////////// Correo que envío a Estrella con copia a Mariví y Pedro, Jefe secc CTAEX: "Buenas tardes de nuevo Estrella, Pongo en copia a Mariví, dado que hoy no está, para que esté al corriente. Tras haberlo hablado y valorado con Pedro, Jefe de Secc. CTAEX, nos planteamos que sería bueno hablar con Ángel, marido de Desideria Barbero Bueno, en relación al estado de la vivienda, es decir, si tiene él las llaves y si recuerda haber cerrado bien la casa y preguntarle además si tienen gas, y en este caso, si lo dejaron cerrado. Las compañeras de Futuex creen recordar que en la casa de alquiler no tenían gas, pero no pueden asegurarlo al 100%. Agradecemos la gestión. Ya nos dices cuando puedas. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-07','Ana: Recibo llamada de Pila Martín, TS ESM: Ayer comunicó a la Policía Nacional, las incidencias de José Manuel con su hijo, quién acude a la vivienda por las noches acompañado de otros amigos saltándose las medidas del Eº de Alarma. // En cuanto a los informes solicitados para adjuntar a la posible comunicación al Jdo. dice que no lo tiene claro, "podría complicarnos más la vida" expresa. Hablará hoy con José Manuel y con el Psiquiatra y me volverá a llamar más tardes. ///////// Nueva llamada de Pilar: plantea la posibilidad de reducir las salidas de José Manuel contactando con voluntarios que le lleven a casa el pan y la leche que no le suministra el catering. Le digo que si José Manuel está de acuerdo, sería ya para a partir del día 11 de abril y que deberían de enviar presupuesto del establecimiento al ctutelar@ y desde el mimso a final de mes factura con número de cuenta para que le realicen transferencia. // En cuanto al informe, no nos va a enviar ninguno, plantea que hagamos un escrito nosotros en que se anoten lo que nos ha transmitido ella y el propio José Manuel y el consiguiente riesgo para la salud pública. // Por último dice que José Manuel le ha comentado que ayer, entre las 18:30-19 h. volvión su hijo con un amigo, pero que no le abrió la puerta. ////////////////// Nueva llamada de Pilar Martín: Ha llamado a RedCor, plataforma civil de voluntariado de la ciudad de CC, realizan compras y la lleva a domilicio a quien las necesita durante el confinamiento. Ha hablado con Juan, Presidente (670 877 278), podrían llevarle la leche y el pan un día a la semana (el pan tendría que congelarlo). Le planteo a Pilar que a José Manuel ya se le ha indicado en múltimples ocasiones que haga compra sólo un día a la semana y que congele el pan, pero no lo hace, es más, siempre tiene alguna excusa para salir de casa, sale a diario. Insiste en que cuantas menos justificación tenga él para salir mejor. Al menos que no sea porque desde los recursos le hemos facilitado las cosas. *Lo consultaré con la secc. ecca. antes de confirmar nada a RedCor. **También añade que José Manuel ya debe 6€ de pan en un establecimiento del barrio. //////////////////// Nueva llamada de Pilar Martín: Dice que justo cuando estaba hablando con él le ha vuelvo a parar la policía. Al parecer tenía que ir a la farmacia a por un inhalador que le han recetado desde el 112 (él mismo había llamado) y a la panadería. Pero a Pilar le han dicho que se recorre la ciudad de punta a punta. Ella ha intentado justificar su salida de hoy y les ha explicado que además es un paciente de salud mental con dificultades para el control de impulsos. Les ha dicho que está tutelado por la CTAEX y les ha facilitado el número de Pedro, Jefe Secc., y el mío. ++++++++++++++++++++++++++++(Pedro)Llamo a la Policía Nacional de Cáceres (927-626510). Me confirman que en esta mañana no ha habido registro alguno de intervención con José Manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2020-04-07','Ana: Correo de la residencia femar (residenciafemar2019@gmail.com // 927 36 04 30): "Buenos días, el departamento de enfermería de nuestra residencia nos informa de que el estado de salud de Valentina Fernández Trejo es bueno, no tiene síntomas de la COVID-19, y se encuentra como todos nuestros residentes manteniendo todas las medidas de seguridad recomendadas por las autoridades sanitarias. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-04-07','Correo CRR Mérida: +++...En este sentido, Ángel Pinilla fue dado de alta y se encuentra en el CRR. Hasta ahora, parece que se encuentra mucho más estable con el ajuste farmacológico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-04-07','Correo CRR Mérida. +++María Dolores Fernández está llevando la situación bastante bien, comprendiendo que no es el momento de acudir a los servicios médicos salvo que sea imprescindible. Mantiene contacto telefónico con su familia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-04-07','orreo CRR Mérida. +++José María Guillén se muestra algo irascible y de mal humor, entendemos que motivado por no poder salir a la calle ya que él acostumbraba a pasar la mayor parte del día fuera del recurso. Se le están generando espacios de desahogo frecuentemente para abordar esta cuestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-04-07','Correo CRR Mérida. +++Luisa Rodríguez en general bien, aunque sigue en su línea habitual de no hacer mucho caso a nuestras recomendaciones...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-04-07','Correo CRR Mérida. +++Antonio Merchán bien, siguiendo su rutina. Casi siempre aprovecha para estar al aire libre en los bancos de la entrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2020-04-07','Correo de APNABA. +++Buenos días, gracias por la información. En la actualidad nuestras usuarias Carmen y Sandra Castaño Cárdenas se encuentran en perfecto estado de salud, si bien cabe destacar que tenemos a dos usuarios de nuestra residencia en aislamiento pendiente del resultado de las pruebas que les hicieron ayer. El aislamiento responde a las medidas preventivas y de protección aconsejadas por las autoridades sanitarias tal y como os hicimos llegar con el envío de nuestro protocolo de actuación. Estoy a vuestra entera disposición para cualquier duda o información que necesitéis al respecto. Un cordial saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2020-04-07','Correo de APNABA. +++Buenos días, gracias por la información. En la actualidad nuestras usuarias Carmen y Sandra Castaño Cárdenas se encuentran en perfecto estado de salud, si bien cabe destacar que tenemos a dos usuarios de nuestra residencia en aislamiento pendiente del resultado de las pruebas que les hicieron ayer. El aislamiento responde a las medidas preventivas y de protección aconsejadas por las autoridades sanitarias tal y como os hicimos llegar con el envío de nuestro protocolo de actuación. Estoy a vuestra entera disposición para cualquier duda o información que necesitéis al respecto. Un cordial saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-04-07','Ana: Convesación con Estrella Durán, TS CSS-Plas: Juan no presenta síntomas de Covid-19. De momento continúa en UME, su delirio continúa activo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-04-07','Ana: Correo de Toni-Futuex (areasocial3@futuex.es): "Seguimiento Nemesia Paniagua: Se contacta con los PPTT de Guijo para consultar cómo sigue la situación, responde Blanca, responsable de los pisos; comenta que la situación es complicada, ya sólo quedan cinco residentes en los mismos, el resto están ingresados en el Hospital Virgen del Puerto de Plasencia. Blanca establece que Nemesia se encuentra bien, hasta el momento está bien de salud, tanto física, como psíquica, pues está mucho más tranquila; parece ser que ha asumido la situación en la que estamos inmersos y se ha relajado, de hecho, tal ha sido el cambio que no precisan darle las gotas que le recetó el médico para mantenerla tranquila. Neme está aislada en una habitación individual, todos los residentes están igual, confinados en sus habitaciones, se les lleva la comida y todo a las mismas. Si no se ha entendido mal a Blanca, los tres trabajadores de los pisos permanecen confinados con los residentes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2020-04-07','Ana: Correo de Toni-Futuex (areasocial3@futuex.es): "Seguimiento Rosa Gómez: Se contacta con la residencia San Antonio, tras haber llamado, por su parte, a la oficina de FUTUEX, no se entiende porqué lo han hecho, ni de dónde sacaron el contacto… Se habla con la enfermera comenta que acaba de pasar la revisión diaria la doctora, la de la primera de la mañana, establece que Rosa sigue igual que ayer por la tarde, como comunicó, está asintomática y estable; el único inconveniente es su alteración debido a que no quiere estar encerrada, como era de esperar, indica que intentan que esté lo más tranquila posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-04-08','Ana: recibo llamada de Mariví Clemente, TS CSS-Plas. (927 428 800), en relación a la solicitud de dinero que hace Desi, al parecer es para proveer de tabaco a Ángel, pues ella no fuma. No obstante, pregunta cómo se va a hacer y explico que ayer Estrella, su compañera TS, se coordinó con Icíar, secc. ecca. CTAEX, y acordaron que se autorizará a Soraya Cobos, Directora del CSS, para retirar la asignación mensual de Desi. // Por otra parte, expresa que entiende que de Futuex no vaya a acudir nadie el domicilio. ////////////// En cuanto al estado de Desi y Ángel, dice que ambos están productivos y activos. Ángel en plena crisis no es funcional, por lo que no sería buena idea que él acudierea al domicilio. *Confía en que los que fueron del 112 a buscarlos al domicilio comprobaran que todo estuviera bien antes de marcharse. Ingresaron los 2 descompensados, de forma involuntaria, derivdos del HVP. Ángel está en URA y Desi en UME. Permanecerán ingresados al menos de 14-21 días por protocolo Covid-19. *Al decretarse el Eº de Alarma, al igual que a todos los pacientes en media estancia se les ofreció ingresar voluntariamente en el CSS, hasta que todo pase, pero declinaron el ofrecimiento. Se ha mantenido seguimiento telefónico hasta que fue necesario activar el 112. Segçun informe presentabana alucinaciones auditivas y olfativas. Ángel llegó a decir que tenía atrapado al ladrón, que lo tenía encerrado en una habitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2020-04-08','(Pedro) +++Se remite por correo electrónico autorización para realización de sesiones telemáticas para continuar con el Servicio de Habilitación Funcional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-04-07','(Pedro) +++SE pone en conocimeinto de la Dirección-Gerencia la situación planteada con Dª Rosario para que se prevea la actuación en caso de una posible desatención de la misma debido a un posible caso de covid-19 de Miriam(su Cuidadora). +++A última hora de la mañana se comunica a Amalia el resultado del test: NEGATIVO. +++Sustituirá a Miriam su sobrina Ana. +++Amalia ha contactado también con la empresa de servicios ASINDE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-04-08','(Pedro)Llamada de Dª Belén Bono Contreras, madre de Alejandro. +++Pregunta por la cuenta de bancaria de su hijo, en la que dice figurar con él pero de la que ya nos hemos hecho cargo en la Comisión (CURATELA PATRIMONIAL Y SANITARIA). +++Segun el Informe Social de lam Sección de Apoyo y Recursos a la Infancia y la Familia Alejandro ha HEREDADO de su PADRE 150.000 EUROS. +++Dª Belén comenta que de la cuenta de su hijo pagaba los gastos que el estar con ella le suponía y que ahora, HABÍAN PENSADO COMPRAR UN PISO PORQUE LES IBAN A ECHAR DEL QUE TENÍAN EN ALQUILER (450 euros aprox. que pagan los oabuelos maternos de Alejandro (según I. Social mencionado). +++Paso a Alberto consulta de gestión económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-04-08','Ana: Envío a Remedios, TS Infancia y Familia, por mail (remedios.venegas@salud-juntaex.es) copia registrada de la Solicitud de elección de centro. A posteriori, tras conversación con Maribel, Secc. Acceso a Recursos Discap., respondo a un nuevo correo de Reme Venegas: ..."Me anoto el contacto de Juan Pedro. Decirte que justo iba a escribirte para comunicarte que he hablado con Maribel, me dice que Aitor ya está en lista de espera para acceso a plaza de RAL (Residencia de Apoyo Limitado), en dos de los centros está el 2º y en otro el 3º. No obstante como sabéis en estos momentos, dado el Estado de Alarma, los ingresos en centros se han paralizado, pero en cambio, como me confirma Maribel, la lista de espera se sigue gestionando, por lo que no sabe si habrá variación en las próximas semanas. Cuando pase todo esto no creo que tarden mucho tiempo en llamarle de la lista, pero no podemos saber cuánto será exactamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-08','Ana: Llamo a Belén, secc. ecca. CTAEX, me informa que finalmente para las 2 próximas semanas de confinamiento se realizarán las autorizaciones bancarias para retirar el efectivo de la sucursal correspondietne como la última vez, pues dada la falta de respuesta del banco, la gestión de las tarjetas no ha podido realizarse. ///////////////////////////////////// Llamo a Pilar Martín (927 21 37 30 // 695 19 45 73), le explico lo del banco y que José Manuel deberá abonar de su próxima asignación el dinero que debe de pan en la multitienda, así como lo próximo que quiera comprar de pan y leche. **Por otra parte comunio que ayer, Pedro, Jefe de secc. CTAEX, llamó a la policía nacional y le dijeron que no constaban partes de denuncia de ayer. *Suponemos se debe a la mediación que realizó ayer Pilar. //////////////////////////////////////// Llamo a José Manuel (667 384 817): , le explico que finalmente lo de la tarjeta que le dijeron en el banco no puede ser y que tendrá la nueva autorización para retirar su asignación para otras dos semanas a partir del lunes 13 en la misma sucursal de la última vez. Desde Futuex le gestionarán la cita para que acuda al banco y se la comunicarán. Le he explicado que de esa asignación debe abonar lo que debe en la Multitienda “Deseo”, así como pagar el pan, leche, tabaco y productos de la farmacia que pueda necesitar, expresa que lo sabe. Le he recordado que ahora, dadas las circunstancias se le está dando en cómputo sólo 10€ menos a la semana y aparte se le paga el catering, por lo que tiene dinero más que suficiente. En cuanto al Voluntariado él mismo me ha dicho que no hace falta, que prefiere comprar las cosas él, así que no se le va a gestionar nada al respecto. *Le he pedido e insistido en que el mismo día que acuda al banco a retira el efectivo, a la vuelta pase por los establecimientos usuales de su barrio a pagar lo que debe y a comprar leche, pan, medicamentos y tabaco para toda la semana y que no vuelva a salir más en toda la semana. Dice que así lo hará, pero que él no sale, que hoy sólo ha salido al final de la calle para que su hermano le diera dinero para tabaco….. respondo que dice que no sale pero que está saliendo a diario, sale todos lo días…. “ya ya” contesta. //// Envío e-mail a Pilar Martín para informarle, pongo en copia a Pedro y a Alberto, Jefes CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-04-08','Correo-e de Paula, CRR de Plasencia: +++Una excepción es Emilia Morales Botello quién ingresó anoche, por importantes dificultades para manejar su impulsividad y conductas que la ponían en riesgo tanto a ella como a sus compañeros, rompiendo además tanto el confinamiento como las medidas preventivas de prevención. En este momento se encuentra en el centro socisanitario (se están realizando ingresos de agudos directamente allí).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-04-13','Ana: Envío email a Estrella y Mariví, TS del CSS, para interesarme por la evolución de Emilia. /////////////////////////////////////////////////////// Correo de Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Ingresó el fin de semana, pregunto a su Psiquiatra la Doctora Pérez Puente y afirma que no ha habido ninguna incidencia que destacar. Os mantenemos informados. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='ESCOBAR'and apellido2='MACIAS'),'2020-04-13','EXITUS El centro comunica su fallecimiento acaecido el 08/04/2020. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Acabo de hablar con Paloma, de la Residecnia "El Cuartillo" (690-839922). Trataron de ponerse en contacto con la de D. José Mª: hablaron con una sobrina que los remitió a otro teléfono en el que no localizaron a nadie.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2020-04-08','NOS COMNICAN FALLECIMIENTOS DESDE LA RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2020-04-13','Ana: Correo de Ángela, Directora de PLACEAT (directora@placeat.org): "Buenos días, comunicaros que la Usuaria de RAL Mª Rosa Iglesias Calzas, se encuentra bien de salud, confinada evidentemente en la residencia de Plasencia. Un saludo Angela Bueno"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2020-04-13','EXITUS El centro nos comunica su óbito acecido el 08/04/2020. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Acabo de hablar con Paloma, de la Residencia “El Cuartillo” (690-839922). Ya comunicaron al hijo de Dª Antonia su fallecimiento, enviando a la Guardia Civil para localizarlo y prevenir cualquier posible alteración. No hubo ninguna incidencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2020-04-13','Acabo de hablar con Paloma, de la Residencia “El Cuartillo”. Ya comunicaron al hijo de Dª Antonia su fallecimiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-04-13','TRAS VARIAS CONVERSACIONES TELEFONICAS Y CORREOS ELECTRONICOS SE LE VA A PEDRI CAMBIO DE PERFIL PARA QUE PASE DE RAIL A RAE Y PODER OFRECERLES MAYORES APOYOS. EL USO DEL TELEFONO DEBE SER SUPERVISADO, NOS INFORMA QUE A DEMAS DE HABLAR CON LA MADRES (LA CUAL TIENE ESQUIZOFRENIA) TAMBIEN LO USA PARA HABLAR CON OTRAS PEROSNAS CON LAS CUALES LE PIDEN DINERO O INCLUSO SE OFRECE PARA ENCUENTROS SEXUALES EN LAS REDES SOCIALES QUIERENE MANTENER UNA VIDEO LLAMDADA PARA QUE HABLEMOS CON LA MADRE Y CON EL .... NOS PIDEN INFORMACION SOBRE LOS INTENTOS AUTOLITICOS Y AMENAZAS DE SUCIICIO SE LE REMITE INFORMARCION DE SU PASO POR EL DULCE NOMBRE EN MALAGA. INFORME TECNCIO . DESDE LA COMSION TUTELAR VEMOS QUE NO ES PERFIL DE PLENA INCLUSION QUE QUIZAS DEBERIA VOLVER UN TIEMPO AL SOCIOSANITARIO. QUEDMAMOS PENDIENTE DE HABLAR CON PSIQUITRAS PARA QUE VALOREN EL CAMBIO DE RECURSO YA QUE TRAS MULTIPLES INGRESOS EN UHB POR LLAMDA AL 112 UNA VEZ ESTA ESTABALE VUELVE A SU CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-04-13','(Pedro)llega a la Comisión designación provisional de Letrado Turno de Oficio: D. ANICETO MATAMOROS RAMÍREZ (647-122340 Y correo-e: anicetomr@icaba.com). +++SE lo envío por correo-e a Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2020-04-13','(Pedro)Llamó Aquilino el pasado Jueves Santo. Le devuelvo la llamada: +++Quiere comprarse un traje para ir a una boda en el mes de octubre (parecía que no quisiera que nadie le oyese)...Le digo que llame más adelante, que queda mucho tiempo para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-04-13','Ana: Correo de Pilar, Hogar San Vicenet de Paúl (direccion.hgsvplasencia@gmail.com): "Buenos días, Feliz Pascua de Resurrección. Deseo que estos días hayan servido para renovar fuerzas y seguir trabajando en estos momentos de tanta dificultad. Les informo que Margarita ya ha salido del aislamiento y que se encuentra muy bien. La verdad, es que ha llevado esta situación fenomenal y se ha comportado de una manera increíble. Esperemos que esta situación termine lo antes posible y podamos seguir siendo portadoras de buenas noticias. Un saludo Pilar Sánchez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2020-02-09','SALIDA. EL 09/02/2020 Procesión de las Antorchas, en CACERES','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2020-02-15','SALIDA. El 15/02/2020 Jornada de Convivencia, Comida fuera del centro (Restaurante Altacuesta) de ALCUESCAR','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2020-02-15','SALIDA. El 15/02/2020 Jornada de Convivencia, Comida fuera del centro (Restaurante Altacuesta) de ALCUESCAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2020-02-09','SALIDA. EL 09/02/2020 Procesión de las Antorchas, en CACERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-04-13','Ana: Correo de Toni-Futuex (areasocial3@futuex.es): "Buenas tardes Ana espero que hayas podido pasar unos buenos dias, dentro de lo que se pueda, almenos que hayan servido para desconectar, Te mando nota, de Nemesia Garcia Paniagua de los pisos tutelados de Guijo de Granadilla, segun nos informan se la llevaron el día 9, por la tarde-noche, al hospital Virgen del Puerto de Plasencia porque le subió la fiebre a 38. La dejaron ingresada porque dio positivo en coronavirus y tenía la tensión bastante baja. Ayer le comunicaron a los pisos que Nemesia se encontraba bastante bien, está tranquila y evoluciona bien, la fiebre le ha bajado y tiene bien la saturación, además no presenta problemas en los pulmones, por lo que igual le dan el alta pronto. , desde los pisos, facilita el número del Hospital para que se pueda contactar directamente, 927 45 80 00, se encuentra en la planta 5ª, habitación 517; es la información que solicitan para poner en contacto; a partir de las 13:30 atienden llamadas telefónicas y comunican la situación. Seguimos! buena semana"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CORBACHO'and apellido2='GALINDO'),'2020-04-13','Tras conversación con Amalia, me confirma haber hablado con su exnuera Antonia Silguero (trabaja en la Notaria de Almendral 924-483239), separada actualmente del hijo de nuestros tutelados (tlfno 600-201481). Comenta Antonia la excuñada que hay un préstamo hipotecario de una vivienda en entrin alto donde deberían estar pagando los tres (los padres, el hijo y ella) y hasta la fecha sólo lo paga ella. Tras revisar las carpetas virtuales de ambos veo que son cargos de tutela aceptados de mediados del 2019 con lo cual no tenemos ninguna cuenta anual enviada, por lo que revisando el inventario veo que hay una cuenta en común de nuestros tutelados con algo más de 2.000€. Hasta la fecha la única pensión que había es la de él de 854€ de 14 pagas. Amalia ha solicitado PNC a la madre Isabel, pero hasta la fecha no la han contestado sobre su concesión. Unicamente me aparece un bien en Entrin Alto en Catastro cuya titularidad está al 100% pleno dominio a nombre de nuestro tutelado el padre Manuel Corbacho Galindo. Llamo a la notaria de Almendral y logro hablar con la interesada excuñada Antonia Siguero, quién se encuentra bastante afectada emocionalmente…Me comenta que lleva divorciada de Manuel Hipolito Corbacho Parra desde el año 2014. Me comenta que su exmarido e hijo de nuestros tutelados es ludópata que actualmente vive en un cortijo donde trabaja para otro y duerme allí, en Torre de Miguel Sesmero, que tienen una hija en común y que nunca le ha pasado la pensión correspondiente. Que por convenio cuando se divorciaron en 2014, se acordó que ella se hacía cargo de dos hipotecas que mantiene con él (cuyo origen son los vicios por el juego del hijo de nuestros tutelados). En dicho convenio el se comprometió cuando tuviese trabajo a pasarle la mitad de los gastos y pensión de la hija. Que a fecha actual a ella ya la han embargado la casa, el 16% de la propiedad que tiene por herencia de su padre, y lo último ha sido su nómina. Que este caso lo lleva desde hace algo más de 1 año el abogado Luis Carretero Bernáldez (Tlfno 625-114240), pero no me sabe confirmar qué trámites ha hecho el abogado. Me indica que toda la documentación e información la tiene él y de hecho que en su día se puso en contacto con nosotros para mandarnos toda la documentación (hablaré con los compañeros de Ctaex por si alguien sabe algo). La indico el email de la comisión ctutelar…y mi teléfono para cualquier duda o si quiere enviarnos cualquier documento. En definitiva: ella lo que pide es que se embargue o venda la casa de entrin bajo de nuestros tutelados ya que dice que el ptmo se pidió para unas obras de la casa y que como el hijo no tenía trabajo, tuvieron que entrar los 4 de prestatarios y como la madre no cobra pensión y el padre cobra muy poco pues es a ella a quién se lo reclaman. De todo esto parece que no la han notificado desde el banco sino que directamente se entera cuando la han embargado la casa y ahora la nómina. Cree que la deuda asciende a unos 21.000€ con el banco. No obstante en la hoja de Excell de inventario de nuestros tutelados compruebo que tienen al menos 4 embargos más con AEAT, y en el informe social que nos remiten desde el centro donde residen “La Granadilla de Badajoz” compruebo que hablan de varias deudas por multa con DGT( por un Renault 11, imagino que estará a nombre de alguno de los dos tutelados) tanto a nombre de la excuñada como del hijo. También se menciona en dicho informe deudas con el OAR. Hablaré de todo con la parte económica (Alberto) y la Jurídica (Angel) para saber qué saben y su parecer, antes de hablar con el abogado para pedirle documentación. Una vez lo tengamos todo y antes de tomar una decisión sobre solicitar o no venta de inmueble, (ya que los tutelados por renta son insolventes), deberemos reunirnos las 3 partes de la Ctax (social Amalia y Pedro, Económica Alberto y Jurídica) para tomar una decisión.','1');
