insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MENDO'and apellido2='RODRIGUEZ'),'2020-04-15','(Pedro) Correo-E de Carmen Franco (CSS Mérida): +++Test covid-19: POSITIVO. En aislamiento y en buen estado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-04-15','Ana: Recibo llamada de Cristina, Ed. de Asoc. Vera (617 732 074 = Nº personal, utilizar sólo durante el Eº de Alarma). Me comunica que Adrián ha sustraído 4 móviles, 2 auriculares y 2 relojes entre otras pertenecias de una compañera del centro que te tenían bien guardado en un almacén. No era algo que supiera el resto por lo que ha tendio que rebuscar bien. Con estos artículos ha estado trapicheando con otras/os residentes. Además les amenaza para que no se chiven. Se han dado cuenta que es mentiroso y manipulador. *Estuvieron hablando con él largo y tendido, y durante casi una hora lo negaba todo, hasta que finalmente acabó confesando. Pusieron un candado en el almacén, pero al poco lo rompió y volvió a entrar. Además ha agredido a un compañero. La mayoría de los hecho se han producido durante el estado de alarma, el confinamiento y el hecho de que el equipo trabaje al mínimo en el día a día dificultan la intervención y favirece los comportamientos negativos. Cristina expresa que ya no saben cómo actuar. ***Indico que comuniquen todo por escrito a la Secc. de Discapacidad y que no duden en poner las denuncias correspondientes. Y que intenten mantener el diálogo con Adrián, así como establecer límites claros. Debe aprender que cada un de sus actos tiene consecuencias, tanto positivas como negativas, en función de cómo actúe. //////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////// Correo de Toni-Futuex (areasocial3@futuex.es) al final de la mañana: "Al respecto de Adrián Ortigosa en centro Vera de Jaraiz de la Vera en contacto con profesionales de la Asociación Vera, Manuel (terapeuta) y Marisol (cuidadora), se nos informa en este día de la incidencia registrada con Adrián el domingo 12 de abril. En este tiempo, desde su ingreso el 20 de Enero 2020, su adaptación y evolución está siendo buena, participando activamente en talleres, colaborando en tareas, haciendo amigos, siguiendo las indicaciones de los profesionales, registrando, según nos comenta el terapeuta, unas conductas formidables, aunque en algún momento insista en querer ir a su pueblo, con el hecho de el día que se marchó del centro y lo encontraron en la carretera fuera del pueblo. Pero, el domingo 3 de abril, han observado que en una de las naves-garajes que tiene el centro, dónde una de las usuarias guarda objetos de valor de su propiedad, Adrián ha cogido varios objetos: relojes, móviles y ha estado trapicheando con ellos con otros usuarios de dicho centro, a cambio de otras cosa o dinero. Se ha detectado el hecho rápidamente por parte de los profesionales, con lo que se ha recuperado todos los objetos que había sustraído indebidamente. En el día de ayer, parece que ha intentado acudir de nuevo a la caja, que ya estaba precintada y asegurada con un candado y ha sido reventado. Él, en un principio aseguraba que no había sido esta vez. Pero, al final ha reconocido la verdad, aunque ahora no ha cogido nada. Los profesionales han estado con él, por eso no hemos podido hablar directamente con Adrián, porque estaba en una sesión con ellos, dónde se nos afirma que ha reconocido el hecho y que está muy mal hacerlo, que ha llorado por ello. Como contingencia, no se le permite hablar con su familia, que además le suelen alentar a estar a la defensiva en el centro y con los demás, a que consiga dinero y poder ir a su pueblo. Detectando desde el centro la influencia negativa de su familia, en concreto su padre. Que en general, ellos están contentos con la evolución que estaba llevando hasta ahora en el centro, sumado a los momentos de confinamiento, no siendo fácil para nadie. Y que van a trabajar con él todas estas conductas, una vez que Adrián reconoce y ha pedido disculpas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-04-15','En relación al procedimiento de venta de inmuebles, enviamos documentación al Abogado designado por el turno de oficio, Aniceto Matamoros Ramírez (anicetomr@icaba.com) para que presente EJV de autorización judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2020-04-15','Ana: Correo de la Residencia de Romangordo (ResidenciaRomangordo@live.com): "Buenos días, Ana: Daros las gracias por vuestras palabras y deseos y sobre todo comunicaros que tanto nuestro residente tutelado , Guillermo Muñoz Pallero, como los demás están todos en perfectas condiciones de salud física. Atentamente, Juan Jesús Alonso Ríos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-15','(Pedro) En los tres últimos díasse han estado haciendo las siguientes gestiones en relación con José Manuel: +++ESM de Cáceres, con Pilar (T. Social) y con Juan Pedro Jiménez (Psiquiatra, 54610) +++Policía Local de Cáceres (ver denuncias y correos-e) +++Con la UHB de Cáceres, con Mamen, T. Social (56283///corre-e: maria.alvarezs@salud-juntaex.es) +++Con la Fiscalía de Cáceres. Fiscal Ruth Creuet (619-790504) ++++++++++++++++++++++++++++++ +++UHB (en el día de hoy): Van a hacerle el test para la covid-19. En el caso de que dé negativo, lo mantendrán ingresado durante esta semana y si se mantiene asintomático le darán el alta y lo enviarán a su casa. +++Fiscalía (en el día de hoy): tras plantearle la situación, me indica que solicitemos Internamiento Involuntario al Juzgado de Guardia (Nº 1 de Cáceres, actualmente) indicando cuál es el recurso más adecuado en este momento (le explico que el Psiquiatra del ESM cree que la Unidad de Larga Estancia sería la adecuada-y yo opino lo mismo- de tal forma que viendo su evolución se pueda hacer una derivación a CRR sise considera oportuno. +++++Desde le Juzgado de Guardia se pediría al Forense realizar un reconocimiento. ////////////////////////////// Ana: Correo de Toni - Futuex (areasocial3@futuex.es) al final de la mañana: "...al respecto de Jose Manuel Romero Mediavilla, mañana te envio el informe firmado y sellado, esta mañana henos hablado con el hospital y nos comentan que José Manuel ya quiere irse de allí pero han negociado con el que mínimo estará allí una semana también dependiendo de su comportamiento....el esta estabilizado a nivel psiquiátrico pero entienden la necesidad del ingreso por causas sociales por eso va a intentar retenerlo al máximo Recomienda que llamemos a Jose Manuel más tarde y mantenga el vínculo por si así somos capaces de retenerlo más tiempo en el hospital, ahora en torno al mediodia lo llamaremos. Su médico prevé q va a necesitar contención física...quiere evitarlo pero cree q José Manuel querrá irse por la fuerza como ya ha sucedido otras veces que ha está ingresado según ha contado el medico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-04-15','Ana: Llamo al HVP-Plas. (927 42 83 00), hablo con Miguel Ángel Barrios, Admvo. de Serv. At. Usuario, me comunica que siguen sin T.S., ambos siguen de baja (tanto Ana Marta como Fernando). Pero casualmente están ahora mismo allí reunidos la Responsable del Serv. de Enfermería y el Jefe de Medicina Interna, buscando una solución al caso de algunos pacientes, entre ellos el de Nemesia. Ya han puesto la situación en conocimiento del Gerente de Área del SES. *Nemesia está para darle el alta, aún no se la dan porque no puede volver a los pisos en estos momentos. Él mismo ha hablado con Blanca, Responsable de los Pisos y con el Alcalde del pueblo, pues él es de allí y le han llamado. En el centro hay varios casos positivos en Covid-19, incluídos profesionales, le han dado precisamente hoy los resultados que tenían pendientes. Están confinados en los pisos tanto residentes como profesionales y aún no han ido a desinfectar allí, motivos por los que no creen conveniente que vuelva Nemesia ahora que presenta mejoría. **Acuerda llamarme cuando determinen algo. ///////////////////////////// *Más tarde recibo nueva llamada de Miguel Ángel (927 42 83 02) me dicen que desde el SES, como no existen recursos residenciales ni se han implementado protocolos para estas circunstancias, han determinado derivar los casos al SEPAD, por lo que de momento no se le va a dar el alta, permanecerá ingresada al menos un día o dos más hasta que desde el SEDAD determinen algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-15','miguel, Tras conversación de Pedro con el psiquiatra y el centro donde se encuentra UHB, parece ser que como mucho lo tendrán aproximadamente una semana tras lo cual pretenden darle el alta. Acuerdo con Pedro que hable con Fiscalía de Cáceres y les pregunte como actuar, ya que tenemos una sentencia que autoriza su ingreso en centro adecuado. Me indica Pedro que el psiquiatra pide que sea una Orden no una Autorización. Por ello Fiscalía le comenta a Pedro que no servirá un documento de comunicación sino que tenemos que iniciar un procedimiento de internamiento involuntario en Centro Socio Sanitario de Plasencia en larga estancia. Preparo borrador y lo enviaré a Pedro entre hoy y mañana. Él intentará comunicarle al Centro que intenten mantenerlo allí más tiempo porque vamos a inicial el procedimiento de internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2020-04-15','miguel, Solicito al Oar de Badajoz las deudas de ambos tutelados Isabel Parra y Manuel Corbacho y me remiten las de período voluntario y me dan otro email para las de período ejecutivo, que solicito vía email hoy mismo. Tras conversación con Alberto de la situación, acordamos: 1.-Hablar con la entidad bancaria para que nos informe de todo (para lo cual envío email a Tony la exnuera para que ella o su abogado nos remita esa información y a ser posible escaneadas las escrituras de préstamo hipotecario, recibos y contratos…) 2.- Una vez que tengamos la información de las deudas en total que haya (Oar, préstamo hipotecario, etc…), viendo los inconvenientes que hay para pedir Abogado de Oficio, ya que dada la situación de urgencia y lo que tarda el colegio en asignarlo y si lo hace…Como digo valoraremos si hay dinero suficiente en poner uno de oficio para tramitar la Venta del Inmueble de Entrin Alto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CORBACHO'and apellido2='GALINDO'),'2020-04-15','miguel, Solicito al Oar de Badajoz las deudas de ambos tutelados Isabel Parra y Manuel Corbacho y me remiten las de período voluntario y me dan otro email para las de período ejecutivo, que solicito vía email hoy mismo. Tras conversación con Alberto de la situación, acordamos: 1.-Hablar con la entidad bancaria para que nos informe de todo (para lo cual envío email a Tony la exnuera para que ella o su abogado nos remita esa información y a ser posible escaneadas las escrituras de préstamo hipotecario, recibos y contratos…) 2.- Una vez que tengamos la información de las deudas en total que haya (Oar, préstamo hipotecario, etc…), viendo los inconvenientes que hay para pedir Abogado de Oficio, ya que dada la situación de urgencia y lo que tarda el colegio en asignarlo y si lo hace…Como digo valoraremos si hay dinero suficiente en poner uno de oficio para tramitar la Venta del Inmueble de Entrin Alto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-04-15','Correo de Toni-Futuex (areasocial3@futuex.es): "Al respecto de Isabel Muñoz, pisos tutelado de Jaraicejo.Tras llevar un par de días intentando contactar con la residencia (927 33 62 21) y el teléfono indicado, siempre, aparecia como apagado; se contacta con Jose, gerente de la misma (608 96 27 82) para consultar si hay algún problema con el teléfono. Jose comenta que desconoce si ocurre algo con el teléfono, quizá estén saturados, pues ayer se llevaron a una señora al hospital con síntomas de COVID-19 y dio positivo, por lo que tuvieron que activar el protocolo y aislar a todos los residentes en sus habitaciones. Por el momento es la única residente que ha presentado síntomas, Isabel se encuentra bien, aunque agobiada por la situación. Jose cuenta que ayer habló con ella desde la calle, se asomó a la ventana y la notó bastante triste y apagada… se le dice que es normal, pues si ya estaba pasándolo mal con el confinamiento dentro de la residencia, reducir su movimiento a un cuarto, compartido, donde tiene unos 10 metros para moverse… Jose comenta que el comportamiento de Isabel es bastante bueno y colaborador, pero preocupa su salud psíquica, pues le cuesta afrontar las situaciones y los cambios, especialmente cuando se le priva de libertad. Le hemos preguntado si podemos hablar con ella, y nos indican que no se puede hablar con la tutelada, aunque funcione el teléfono, porque por prevención no lo pasan de unas habitaciones a otras, quizá es una medida demasiado drástica, pues el teléfono se puede desinfectar, pero como está todo muy reciente, puede ser pronto para proponerlo. Ella no tiene móvil personal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-06-16','TERESA HABLO CON MARIBEL DE DISCAPACIDAD Y ME COMENTA QUE NO HA CERRADO AUN EL EXPDIENTE DE CUADO SE PIDIO EL MODULO FAMILIAR YA QUE NO LLEGO A ASISITIR A LA CITA DEL CADEX. HE LLAMADO AL CADEX Y ESTA PENDIETE DE CITA VAMOS A APROVECJAR ESTA CITA PARA QUE LA VALORESN PERO PARA CENTRO RESIDENCIAL PARA ELLA EN VEZ DE MODULO FAMILIA HAY QUE SOLICITAR EL CAMBIO DE PIA PARA SERVICIO DE RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-04-15','Ana: Correo de Estrella, TS - CSS de Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Espero sigas bien. Te escribo porque me plantea la Psiquiatra de Desi que necesita ropa y sujetadores y que vean cómo dejaron la casa, los de Futuex. Los llamé a ellos y me dice Gloria que tiene que comentarlo con su coordinadora porque no van a desplazarse desde Badajoz a Plasencia por el estado de alarma. Les digo que, aquí, consideramos que su trabajo es al igual que el nuestro, asistencial, por lo que deberían asistir a los tutelados. De todos modos ya me dirás. Gracias. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GALLEGO'and apellido2='CALDERON'),'2020-04-16','Recibimos llamada de Davil Candel (650265820), para comunicarnos que nos ha enviado al correo electrónico de CTAEX, las fotos del estado en el que se encuentra la puerta de la vivienda de María. Están guardadas en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-04-16','Ana: Recibo llamada de Chus, Responsable de los PPTT de Miajadas - Empresa Serv. Tierra de Barros (638 499 546). Me informa de que Steve está llevando muy bien la cuarentena. En los pisos realizan muchas actividades y él participa en todo. Con quienes siguen "teniendo problemas es con el C.O., les solicitaron al inicio del Eº de alarma 100 € y le dieron sólo 75, diciendo además que no les darán nada más hasta mayo. No sólo tienen problemas de este tipo con respecto a Steve, sino que también le pasa con el resto de residentes... Como a ella no le cuadra la gestión económica que realizan, y así lo ha manifestado, desde el Ayto. le han dicho que "tenga la boca callada porque desde que han entrado ellos no dejan de tener problemas con el C.O. y que si no es así les van a quitar el programa". // Por otra parte, ayer les visitó la T.S. del Ayto. y se sorprendión de lo bien que estaba Steve y cómo se está comportando dadas las circunstancias de confinamiento. //////////////////////// Consultaré a la secc. ecca. por qué siguen "administrando" el dinero desde el C.O.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-04-16','TERESA:DEBIDO AL ESTADO DE ALAMARMA LA LIMPIADORA NO PUEDE SEGUIR CON LA LIMPIEZA EN LA VIVIDNDA, HE RECIBIDO LLAMADA DE LA PROPIETARIA DEL PISO YA QUE LE ESTAN DANDO QUEJAS DE QUE CANDIDO HUELE MAL Y EL PISO TAMBIEN. NO LE DEJAN QUE USE EL ASCENSOR YA QUE SALE Y ENTRA CONTINUAMENTE DEL PISO Y NO TOMA MEDIDAS DE PREVENCION HABLO CON M JOSE TS SSB DE ALMENDRALEJO PARA QUE VAYA ALGUIEN A LIMPIAR Y A LAVARLE LA ROPA. LE VAN A PONER UNA AXUIIAR DEL SAD MUNICIPAL HASTA QUE PUEDA IR DE NUEVO LA CHICA QUE IBA A LIMPIAR. LE COMUNICO A FUTUEX LA SITUACION PARA QUE LE DE UN TOQUE Y LE INSISTA EN QUE NO PUEDE SALIR DEL DOMICILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-04-16','Recibimo hoy de Abogacía General, el Auto autorizando el ingreso involuntario de María Antonia. No es firme. Al caber recurso de apelación y al estar paralizado los plazos hasta finalizar el estado de alarma (en principio para el día 26 de abril), habremos de esperar para empezar a contar los 20 días hábiles a partir de entonces. Esperaremos a que sea firma, aprovecha si quieres para ir moviendo el centro adecuado de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-16','miguel, remito Solicitud de Internamiento Involuntario en CSS de Plasencia. Pedro lo envia vía fax y más adelante cuando haya registro de salida enviaremos la documentación física al Juzgado de guardia de Cáceres (Jzdo 1º instancia nº1 de Cáceres), conforme a las instrucciones que dió la Fiscal a Pedro ayer. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Remito por fax (927-620182) el documento referido al Juzgado de 1ª Instancia e Instrucción nº 1 de Cáceres (en estos moemnto Juzgado de Guardia. Contacto: Fátima (927-620321). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada del Dr. Enrique Daniel, psiquiatra de la UHB del H. San pedro de Alcántara (56964): +++++El TEST/covid-19 realizado a José Manuel ha sido NEGATIVO. Se encuentra bien y comenta que la UHB no es la Unidad adecuada para mantenerlo. Ha acordado con él que si evoluciona bien le dará el alta el próximo lunes 20. +++++Le comento las gestione realizadas con el Juzgado y la posibilidad de que requieran desde el mismo un reconocimeinto forense de José Manuel. +++++En el informe de Alta, si se llega a producir ésta antes de la respuesta del Juzgado, hará constar el perfil de personalidad que manifiesta José Manuel, entre cuyas caracaterísticas desdtaca su carácter manipulador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-04-16','Ana: comunican nueva dirección de e-mail de Susana Cortés, TS de la Casa Hptal. Santiago de Zafra: hospisantiago.ts@esclavasvirgendolorosa.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-04-16','TERESA: SE RECIBE VIA EMIAL INGRESO INVOLUNTARIO PARA LA TUTELADA AUN NO ES FIRME, VOY A ESPERAR A QUE SE FIRME Y TENER RESOLUCION DE PLAZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2020-04-16','Ana: Recibo llamada de Margarita Montero, TS de la Mancomunidad Sierra de Montánchez (927 221 206 // tsocial4@mancomunidadsierrademontanchez.ef). Desde la Resid. donde reside Isabel, "Balcón de Extremadura" de Montánchez, le han pedido que se ponga en contacto con nosotros en relación al escrito que han recibido solicitando documentación (*para Inventario), ella no ha visto el escrito. Le informo qué documentación suelen pedir los compañeros y para qué es. Ella está teletrabajando, por lo que hay documentos que tiene en papel en el despacho y ahora no puede acceder. El DNI y tarjeta sanitaria la tienen en el centro. Ahora será difícil que nos lo hagan llegar. *Nos remitirá el Informe Social basándose en el que envió en su día a Fiscalía, pues la situación no ha cambiado. ///////////////////////////////// En cuanto a la Residencia, es de titularidad municipal pero de gestión privada, pertenece al Grupo Ciudad Jardin. Los datos de cotactos = 927 380 516 // balconextremadura@grupociudadjardin.com // En la residencia están desbordados en estos momentos, han tenido varios casos positivos en Covid-19 (6 fallecidos y en estos momentos 14 personas contagiadas) *Isabel de momento está bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-16','Ana: Recibo llamada de Damián, pregunta si nos hemos puesto en contacto con Pilar de Cetelem, le comunico que los compañeros están en ello. Pide, una vez más, que se pague y cancele la deuda que le queda con el banco popular para que se le pueda abrir nueva cuenta en Extremadura. Ayer se lo dijo también a Icíar, secc. ecca. *Le digo lo mismo que le dijo ella y que ya le he dicho en varias ocasiones; lo que propone lo tienen que estudira en la secc. ecca. y autorizarlo el jefe de dicha sección. Y en cuanto a la apertura de nueva cuenta, le recuerdo que ya la tiene abierta y se ha solicitado el cambio de la pensión a la misma. // En cuanto a la retirada de la próxima asignación, pide de nuevo que se añada en la autorización a Félix, le digo que la autorización anterior se hizo como pidieron desde el centro y si esto es una demanda del CRR, que lo comunique alguno de los profesionales del mismo. **Me recuerda también lo de ampliar la contratación del Nicho de su madre. /////////////////////////////////////////////////////////// Recibo llamada de Paula, T.O. CRR-Plas. (682 704 401): le informo de las continuas y múltiples llamadas diarias de Damián a los disintos profesionales de la CTAEX, con sus demandas recurrentes. Y su insistencia para que se añada a Félix, admvo. del CRR en la autorización para retirar efectivo del bando. *Enviarán un correo al ctutelar@ si lo ven necesario. Y tratarán de trabajar el control de impulsos de Damián en relación a las llamadas. **Por otra parte, le dio cita a Damián para hoy a las 14:00 para enseñarle a enviar correos electrónicos y adjuntar imágenes y archivos. *En relación a los documentos del alquiler y demás, Paula dice que hicieron fotocopias de todo justo antes de Eº de Alarma y a posteriori no han podido enviarlo. Cuando todo esto pase lo enviarán. ////////////////////////// Damián envía un correo a Miguel, Asesor Jurídico, con imágenes de documentos relativos al alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2020-04-16','Ana: Recibo llamada de Chus, Responsable de los PPTT de Villa del Rey - Empresa Serv. Tierra de Barros (638 499 546). Me comunica que Mª Salvadora está bien, no ha presentado en ningún momento síntomas de Covid-19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-04-16','Ana: Correo de ayer por la tarde de Cristina, Educadora Asoc. Vera (educadorasocial@asociacionvera.com): "Buenos días, Adjunto envío Incidencias del usuario Adrián Ortigosa Ortíz. Después de varias incidencias graves y después de tomar medidas que no han resultado, desde asociación vera nos ponemos en contacto para pediros que nos aconsejen y orienten en las medidas que podemos emplear para que el usuario se adapte y tome conciencia de sus actos. Saludos, Muchas gracias. Cuidaos." ////////////// Mi respuesta: "Buenos días Cristina, Pongo en copia al Jefe de sección de la CTAEX para que pueda leer también las incidencias. Supongo que Toni y/o alguna otra personas de la Unidad de Recursos Asistenciales se pondrá en contacto con vosotras a la mayor brevedad. Desde la CTAEX mantenemos las indicaciones dadas mediante conversación telefónica el pasado miércoles 15. Por cierto el segundo apellido de Adrián es Fuentes. Seguimos en contacto. Ánimo y un saludo." //// Guardo el correo y las incidencias en el expte. PC de Adrián.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-04-17','(Pedro)Llamo al Jzgado de 1ª Instancia e Instrucción Nº2 de Plsencia. Contacto: Juan Carlos (927-405361///927-426377). +++Pregunto por el Exped. de Jurisd. Vol. 706/2019: restitución de la capacidad de María Antonia. +++Pido a Juan carlos que nos envíe por Fax la Resolución., que resuelve lo siguiente: CONCEDER AUTORIZACIÓN a Dª Mª Antonia Bernardo Piris para COMPARECER POR SÍ MISMA en procedimiento de REINTEGRO DE LA CAPACIDAD. +++ Según Juan Carlos, hasta la fecha, quizá debido al estado de alarma, no se ha presentado solicitud alguna para abrir dicho procedimiento. +++Toda la documentación fue remitida a los SS. Jurídicos de la Junta el pasado 30 de enero, recibido el 31 y siendfo efectiva la resolución desde el 03 de feberero. +++Fue Curro quien intervino por parte de los SS. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-04-17','LLAMADA TELEFÓNICA RECIBIDA Se recibe llamada (Julio Glez.) de Dña. CATALINA (n/ tutelada). Según parece ha estado el SSB a por la documentación solicitada para abrir expte. y formación de inventario. Cuenta Catalina que su padre, dice ella que tiene 84 años y se le va la cabeza, se ha negado a entregarla. Habla, sobre todo, de la libreta del banco. Se le informa que de no entregarla será el Jzdo. quien se la requiera. Le guste a él o no. Se informa a Ana y a Icíar por la parte que les toca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2020-04-17','EMAIL TS P.I. ALMEDNDRALEJO Saúl presenta problemas estomacales que están en seguimiento médico por el equipo de servicio de digestivo del hospital de Mérida. su patología cursa por "brotes". Suele presentarlos dos o tres veces al año (aproximadamente). Este brote cursa con vómitos de color posos de café que aún no saben muy bien el motivo de ello ni tan siquiera a qué se debe dicho color. En la madrugada del miércoles (15) hacia el jueves (16) tuvo un episodio de vómitos. En la mañana del jueves 16 me puse en contacto con su médico de familia de referencia, para lo cual nos pautó una serie de medicación y observación 24 horas En la madrugada del jueves (16) al viernes (17) volvió a presentar dichos vómitos, esta vez acompañado de un desvanecimiento de Saúl. Llamamos al 112 y fue trasladado al hospital Tierra de Barros. En la mañana de hoy viernes 17 he contactado con el hospital y me han indicado que Saúl no ha vuelto a vomitar, que se le ha administrado un enema de limpieza, que los valores de potasio en analítica de sangre se encuentran un poco bajos. En la mñana de hoy volverán a repetir analítica, comenzarán a comprobar si va tolerando la ingesta de comida, y si no vomita, regresará a residencia hoy mismo. En esta ocasión, y debido a la situación sanitaria, no nos han permitido que nadie permanezca con Saúl para acompañarle. Su padre ha sido informado de dicha situación por mí misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-17','Ana: Llamada de Damián, dice que sólo quiere disculparse por su insistencia de ayer y por haberme molestado. Envió por la tarde correos con el mismo fin. Le preocupa que deje de ayudarle. *Le explico que yo le seguiré atendiendo igualmente, que no le dije en ningún momento que no fuera a hacerlo, pero que las cuestiones económicas debe plantearlas a la sección correspondiente y las autorizaciones o variaciones en las mismas desde solicitarlas desde el propio centro. // Parece quedarse algo más tranquilo tras mi aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-04-17','TERESA: HABLO CON MAITE DISCAPACIDAD, ACORDAMOS ESPERAR LA RESOLUCION DE LA PLAZA HASTA QUE SE LEVANTE EL ESTADO DE ALARMA PARA PODER HACER EL INGRESO EN LAS MEJORES CONDICIONES, LA SENTENCIA AUN NO ES FIMRE Y A FECHA DE HOY LOS PLZASO ESTAN SUSPENDIDO POR EL ESTADO DE ALARMA. LE INFORMO A FUTUEX DE LA SITUACION Y LE PIDO QUE LE SIGAN CONTROLANDO PARA ASEFURAR QUE SU DIABETES ESTA CONTROLADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIO'and edp.apellido1='GALLEGO'and apellido2='MOLINA'),'2020-04-17','TERESA: INFORME SALIDAS DEL PRIMER TRIMESTRE, SALE POR LAS INSTALACIONES Y HA PLASENCIA AL PADDI','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2020-04-17','TERESA: SALIDA EL 24 DE ENERO A PLASENCIA PARA COSULTA A DIGESTIVO.SUELE PASEAR POR LAS INSTALACIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2020-04-17','TERESA: HACE SALIDAD POR EL PUEBLO CON SUS COMPAÑEROS, EL 5 DE MARZO TUVO CITA EN SALUD MENTAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCOS'and edp.apellido1='GARRIDO'and apellido2='PEREZ'),'2020-04-17','SALIDA. Sale esporádicamente pro el pueblo y a dar algún paseo por los alrededores con los compañeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2020-04-17','(Pedro)Se transcriben los correos electrónicos enviado por Jesús Serrano, Director de la Residencia "El Torno". +++Buenos días Jesús, Pongo en copia a Pedro, Jefe de Sección de la CTAEX, por si él opinase otra cosa, pero yo entiendo que si el propio médico de Att. Primaria de la Seguridad Social considera que lo mejor es que la vean en el hospital, supongo que ha de ser así. Imagino también que están intentando extremar en el mismo las medidas de prevención. No obstante, se me ocurre que quizá se pueda consultar primero en el 112 o llamando al propio hospital. Ya me decís que opináis, porque que yo sepa en estas situaciones tampoco hay establecido otro protocolo de actuación, en cuyo caso además el médico debería haberlo informado. Seguimos en contacto. De: jesus Serrano izquierdo >jesusi6@hotmail.com> Enviado el: viernes, 17 de abril de 2020 12:23 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: MARIA ROMERO buenos dias.llamo desde la residencia de mayores de el torno caceres es referente a MARIA ROMERO QUE ESTA TUTELADAPOE USTEDES UNA PREGUNTA LA MANDAN AL HOSPITAL POR QUE SE HA HECHO DAÑO EN UN CADO Y CREE EL MEDICO QUE MEJOR QUE LA VEAN EN EL HOSPITAL,¿ PODEMOS MANDARLA YA QUE ES UN FOCO DE INFECCION EL HOSPITAL? ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamada de Jesús Romero en los mismos términos de los correos. ++++De cara al retorno de Dª María al centro se plantea su aislamiento. Sobre ello le comento que la necesidad de tomar esas medidas debe consultarlas con su médico de familia o con el hospital, para ver la necesidad o no de las mismas. +++Si el Médico considera necsaria una RX será porque así lo requiere, y en los Hospitales ya se han tomado medidas preventivas para separar y aislar a la personas infectadas. +++En "EL Torno" han realizado el test a todos los residentes y profesionales, dando todos NEGATIVO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2020-04-17','SALIDA. Sale esporádicamente por el pueblo y a dar algún paseo por los alrededores con los compañeros. Acude el 12 de Marzo a Plasencia para realizarse una radiografía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2020-04-17','Ana: Recibo correo de Margarita, TS de la Mancomunidad de Montánchez (tsocial4@mancomunidadsierrademontanchez.es): "Ana, buenso días: soy la Trabajadora Social en Montanchez, tal y como hablamos ayer por teléfono te envio informe social de DÑA. ISABEL PULIDO CARAVACA, saludos" // *Lo guardo en su expte. PC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-04-17','(Pedro)Ante la información que le han dado a Ana (CTAEx) desde el Hospital "Virgen del Puerto" de la inmediata Alta clínica prevista para hoy y su derivación a una Residencia privada (sin comunicación a CTAEx) pongo el caso en conocimiento de Víctor, Jefe de Unidad de Gestión de Control de la Actividad Asistencial (SEPAD)quien me informa de lo siguiente: +++El Gerente del SEPAD se ha Puesto en contacto con la Gerencia del Área de Salud y han llegado a la decisión de NO DAR DE ALTA A NINGUNA DE LAS PERSONAS COVID-19 POSITIVO RESIDENTES en los Pisos Tutelados de Guijo de Granadilla. +++Me pongo en contacto con el Dr. Luis García (645-777295), del Hospital "Virgen del Puerto" y le pongo al tanto de dicha decisión, la cual desconocía, comentando que se va a poner en contacto con su responsable inmediato. +++Al rato me llama Maribel, T. Social del Hospital (78206), a quien pongo al tanto de la última conversación con el Dr. Luis García. +++++Le informo, además, de que sin la autorización de la Comisión no se puede tampoco trasladar a una tutelada a ningún centro. ///////////////////////////////////////////////////////////////////////////////// La TS que había gestionado plaza privada en la Res. Ciudad Jardín de Plasencia, sin haberlo consultado con la CTAEX, es Piedad, de la Mancomunidad de Trasirra (670 29 30 45 // ssbp@trasierratierrasdegranadilla.es). *Manifiesta que ha hecho gestiones para buscar alojamiento para los distintos residenetes ingresados por Covid de los PPTT de Guijo. Le informo de las conversaciones mantenidas desde la CTAEX con el hospital y las úlitmas indicaciones desde el SEPAD. Pide que se lo comunique por mail pues debe enviarlo al Alacalde de Guijo. //////////////// En cuanto a Nemesia, se encuentra bien y asintomática a pesar de ser positivo aún. ///////////////////////////////////////////////////// Maribel, TS que se ha incorporado hoy al HVP-Plas. (927 428 302) me confirma mediante conversación telefónica que EL ALTA SE HA PARALIZADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-04-17','Ana: Respuesta al anterior correo de Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenas tardes Estrella, Perona que no te haya contestado aún, pero la misma mañana que me escribiste tuvimos una mañana complicada. Y ayer y hoy hemos tenido que hacer las consultas oportunas relativas a las funciones especificadas en el convenio que se firmó desde el SEPAD con Futuex y la conveniencia o no de que acudan al domicilio. Está claro que el que acudan sin estar Desideria presente, que es quién está tutelada por la CTAEX, no puede ser. De todas formas, te he llamado antes y me han dicho que comunicaba y justo después en conversación con Toni, Coordinadora de Futuex, me ha dicho que Sonia estaba hablando contigo al respecto, por lo que no he querido marearte más. Ya me han comentado la propuesta de comprarle ropa online, pues como ya hablé yo con ellas, en tienda física a día de hoy no es viable. De todas formas si quieres la semana que viene lo vemos. Buen fin de semana y cuídate."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2020-04-15','Ana: Recibo llamada de Sara, TS de la Res. Baños de Montemayor. Dado que Concepción no tiene Seguro de Deceso, pues las aseguradorsas no se lo hacen por su edad, dice haber enviado con anterioridad un correo a la CTAEX (ctutelar@) proponiendo contratar un paquete en una aseguradora, para estar cubiertos en caso de que fallezca. Envió adjunto un presupuesto, pero le respondieron que no se podía hacer. No entiende el porqué, si a día de hoy la tutelada puede pagarlo y le preocupa que pueda fallecer y que no cuenten con ello. Le explico los motivos por los que imagino que l@s compañeros le han dicho que no (que se quede sin recursos frente a otras situaciones de urgente necesidad que puedan suceder, como por ejemplo necesitar un acompañamiento hospitalario de larga duración, y que además dado el elevado precio de éstos paquetes habría de pedirse una autorización judicial) e indico cómo actuar en el caso de que fallezca en el centro residencial: comunicarlo mediante un correo electrónico a la CTAEX y llamar a la Funeraria directamente si se produce en fin de semana u fuera del horario laboral. Desde la Funeraria o través de ellos deberán remitir también presupuesto y factura del sepelio. **Dado que tiene dinero para el sepelio debe estar tranquila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTEVIRGEN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2020-04-20','EXITUS El centro comunica su fallecimiento el 16/10/2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2020-04-20','TERESA: EMAIL DE JULIA TS PLENA INCLUSION Respecto al tutelado Saúl Rodríguez Ramos, indicarte que finalmente, el viernes 17 de abril, no recibió alta hospitalaria. La doctora que le atendía en el turno de tarde, y con la cual me puse en contacto, me comentaba que habían decidido que Saúl permanecieses ingresado durante el fin de semana. En las heces había restos de hemorragía, los niveles de potasio los seguía presentando bajos, a pesar de estar con gotero. Durante este fin de semana, y para que Saúl estuvieses acompañado, hemos puesto en marcha el servicio de acompañamiento de residentes del cual os informamos. Dicho servicio se está llevando a cabo con personal del centro. Cuando finalice su estancia en el hospital, os haré la hoja de gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-04-20','TERESA_ EMAIL FUTUEX se llama a Cándido y se le pregunta cómo se encuentra, responde que está bien, tranquilo. En esos momentos está en el piso con Montse, la auxiliar que va a limpiar tres veces por semana. Decide pasarle el teléfono a la auxiliar y ésta comenta que ha ido a poner la lavadora y no funciona. Han abierto una llave de paso que había en la terraza y aún así la lavadora no va, por lo que no ha podido lavar la ropa de cama de Cándido. Se le pregunta a la auxiliar si el piso de Cándido estaba sucio o en mal estado para que los vecinos se quejaran de malos olores. Montse responde que se ha encontrado el piso más o menos limpio, en buen estado y oliendo normal, no justificaba para nada las quejas de los vecinos. Se ha procedido a llamar a Moni, la casera del piso, y se le ha comunicado la avería de la lavadora, ella ha comentado que va a llamar a un técnico para que se pase por el piso el próximo lunes día 20 sobre las 12 del mediodía, a la hora que estará la auxiliar para limpiar. Se estará en contacto con ella durante la mañana del lunes para que confirme si el técnico se pasará por el piso de Cándido o debido al estado de alarma, no podrá','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2020-04-20','Ana: Jesús, director de la Res. de El Torno, nos remite por mail (jesusi6@hotmail.com) la Resolución aprobatoria de PNC de María. Se la han remitido a la res. en lugar de a la CTAEX. *Lo comunico a la secc. ecca. y la guardo en el expte. PC. ///////////// Nuevo correo de Jesús, en respuesta al mío intersándome por María: "buenos dias ana. todo bien. bajo al hospital le hicieron radiogracia y la mandaron para arriba con inmobilizacion de brazo nada mas. la tenemos aislada para prevenir, ella esta bien. gracias" /// Vuelvo a responer pregutando si la indicación de aislamiento se la dieron desde el hptal. *Su respuesta: "HOLAA. SEGUN EL PROTOCOLO Y LO QUE NOS DIJO EL DE LA AMBULANCIA 15 DIAS"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-17','(Pedro)Se pone en contacto conmigo Antonio Alonso, Jefe de Los Servicios Contenciosos de la Junta (32301// correo-e: antonio.alonsoc@juntaex.es +++El Juzgado se ha puesto en contacto con la Abogacía a raíz del escrito remitido por fax en el día de ayer.Le tenemos que enviar a Abogacía Resolución de la Presidencia de la Comisión Tutelar resolviendo el internamiento y solicitando de la Abogacía interese la ratificación judicial de la misma. +++Junto con miguel se redacta dicha Resolución y se pone a la firma de José Vicente. Se envía por correo-e a Antonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-04-20','TERESA Me pongo en contacto para solicitar dinero extra para Libertad García Marquez puesto que se encuentra en su casa en Badajoz desde el inicio del estado de alarma y aunque ya le hicisteis un ingreso de 50€ me dice que necesita algo más de dinero para colaborar con los gastos de alimentación en la casa. Mantenemos el contacto casi a diario con ella y dice encontrarse bien. Si fuera posible, al menos 30€ necesita para esta semana Se lo tenéis que ingresar el numero de cuenta que ya os pase a primeros del mes de abril. Y a medidos de mayo ingresarle los 50€ mensuales correspondientes al mes de mayo. Ya me comunicáis si es posible','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-20','(Pedro) +++Envío Auto de internamiento a Mamen, T. Soc. del H. "San Pedro de Alcántara" para que no le den el Alta a José manuel y lo deriven a CSS de Plasencia. Me confirma que sigue ingresado, pero al cabo de un tiempo me llama y me informa de que le han dado el Alta a las 9:00h y que cuando me ha confirmado el ingreso no la habían subido todavía a Jara. +++Tramito ingreso mediante activación del 112 para ingreso en CSS de Plasencia. +++Comunico a Nuria, Secretaria de Dirección del CSS de Plasencia el traslado de José Manuel, una vez que me confirman el mismo desde el 112 (Sonia, coordinadora de Enfermería). +++Llamada de Rosa, de Admisión del CSS de Plasencia: allí no se puede llevar, no hay camas ni ninguna unidad donde se pueda ingresar. Llamo a Sonia para que detenga hasta confirmación de destino el traslado. +++Planteo la situación a Soraya. Está gestionando el Centro sanitario donde realizar el ingreso. Le planteo la posibilidad de volver a la UHB del H. "San Pedro de Alcántara" hasta que se pueda ingresar de manera estable donde se determine. ///////////////////////////////////////////////////////////////////////////////////////////// Llamo a José Manuel (667 384 817): el viernes tiene que acudir al ESM para ponerse el inyectable y el lunes tiene cita con el psiquiatra. Está bien, tranquilo. Dice que él no tenía qu estar en la UHB, pues está bien, no para esar allí. //////////////////////////// Tal y como me transmite Pedro,Jefe secc. CTAEX, comunico a Pilar Martín, TS ESM, que José Manuel será ingresado de nuevo en la UHB del HSPA, en espera de plaza en CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-08','Ana: Llamada de Damián, dice que quiere renovar el nicho de su madre, ENCARNACIÓN HERERDIA POSTIGO, otros 25 años más. Pide que llamemos a PARCEMASA, empresa que gestiona el Cementerio de Málaga, según dice: 952 43 41 00. / Por otra parte insiste en que ahora que tiene ahorrado dinero quiere quitarse el prestamos que tiene en el Banco Popular. Le indico que esto tendrá que estudiarlo y decidirlo el Jefe de la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2020-04-20','Ana: Nota enviada por Toni-Futuex (areasocial3@futuex.es): "20/04/2020 Seguimiento: Se habla con la médico de cabecera de Rosa, hoy no es Belén, pasó una nueva. Comenta que Rosa está mucho mejor, no presenta sintomatología alguna, la presión de oxígeno en sangre es buena, además ya no tiene pitidos en el pecho como la semana pasada; por lo que la evolución es muy positiva. Además, establece que Rosa se encuentra bastante tranquila hoy." **Me sorprende, pues hasta ahora, en ningún momento nos habían comentado que se encontrara mal ni que presentara ningún síntoma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-04-20','Ana: Nota enviada por Toni-Futuex (areasocial3@futuex.es): "20/04/2020 Seguimiento: Se contacta con el Hospital Virgen del Puerto de Plasencia, se habla con el Dr. Vadillo, facultativo que atendió hoy a Nemesia; comenta que la tutelada se encuentra en muy buen estado, no precisa de tratamiento alguno, ni oxígeno. El Dr. comenta que están a la espera de resolución para la derivación a residencia u otro centro adecuado, ya que los resultados proporcionados el día 17 de abril de la PCR son positivos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-21','(Pedro) llamo a Mamen, T. Soc. de la UHB del Hospital "San Pedro de Alcántara". +++Confirma que ayer se realizó el ingreso de José Manuel en la UHB del Hospital. //////////////////// Comunico a Toni-Futuex, mediante mail, que José Manuel ha ingresado de nuevo en la UHB del HSPA-CC, en espera de plaza en CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-04-21','(Pedro) Conversación con Critina, Educ. Social de Asociación Vera. +++Adrián se encuentra más tranquilo. Mañana empieza con tareas en lavandería. +++REfuerzo las medidas propuestas por Ana en su conversación anterior y se valoran algunas otras que ya se habían puesto en marcha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS'and edp.apellido1='PEREZ'and apellido2='GARCIA'),'2020-04-21','SE recibe carat de D. Miguel Pérez García (927-435170) en la que solicita la cartilla de su hermano. +++SE le explica que una vez aprobada la rendición final pra la Comisión la tutela queda extinguida. +++Se queda conforme con la explicación, entendiendo que ya la familia se ha hecho cargo de los bienes de D. Luis.Comenta que se lo dirá a sus hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-04-21','Ana: Pedro, Jefe CTAEX, me comunica que ha hablado con Rosa, TS del Ayto. de Plasencia (600 478 433). Al parecer han recibido el escrito de solicitud de informe social para la rendición anual. Rosa le ha dicho que no conoce a Desideria ni ha intevenido nunca con ella. *Dado que Desideria está ingresada ahora en el CSS y que desde que la CTAEX asumió la tutela, es paciente en régimen de media estancia del mismo, se le solicitará dicho informe al CSS. *No obstante, cuando le den el alta, facilitaré a Rosa, TS, la dirección de Desideria y el marido para que conozcan el caso y puedan intervenir cuando sea necesario. ///// Llamo a Rosa, TS Ayto. (600 478 433) le explico a grosso modo la situación de Desideria y acordamos que volveré a ponerme en contacto con ella una vez le den el alta en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-04-21','TERESA se ha llamado esta mañana a Moni, la casera de Cándido, para confirmar que se iba a pasar un técnico por el piso para revisar la lavadora, ella comenta que así será. Que un técnico de confianza irá al piso entre las 12 y las 13 horas y echará un vistazo a la lavadora. - Se llama a Montse, la auxiliar y se le comenta que entre las 12 y las 13 horas se va a pasar el técnico para revisar la lavadora. - Se habla con Cándido sobre las 12:45h y confirma que ha pasado el técnico por el piso y ha arreglado la problemática que había: la toma de agua de la terraza estaba cerrada y por lo tanto la lavadora no podía coger agua. El técnico la ha abierto y la lavadora ha vuelto a funcionar perfectamente. Cándido ha contado que Montse le ha dicho que le pondrá la lavadora el miércoles porque hoy ya no le iba a dar tiempo a ponerla y tenderla. Asique todo solucionado en ese sentido!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-04-21','TERESA: MANDO COMUNICADO DE PEDRO Y APROVECHO PARA PREGUNTAR POR LA DOCUMNETANCION DE JOSEFA ANOTO RESPUESTA AL EMAIL Gracias por entender al situación vivida en las residencias, es cierto que a veces los teléfonos se encentran colapsados por las llamadas de los familiares. En cuanto a Josefa, se encuentra muy bien, se ha adaptado a la residencia y a los profesionales. Es cierto que, con todo esto, su documentación se quedó parada, ya que estábamos procediendo a gestionarla justo con el inicio del estado de alarma. Como sabéis, ahora se encuentran confinados con l@s trabajador@s, por lo que resulta aún más complejo completar la documentación. Espero poder completarla pronto. En cuanto se la adjunte al trabajador social, os informo, para que los tramites puedan hacerse lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-21','Ana: en respuesta a varios de los correos que ha enviado entre ayer y hoy Damián, le envío este: "Buenos días Damián, Decirte que los y las compañeras ya están haciendo las gestiones correspondientes relativas a bancos, préstamos y demás. En cuanto a lo de Cetelem, concretamente Miguel, Asesor Jurídico, está en contacto con Pilar mediante mail. Ya han intercambiado algunos correos electrónicos y Miguel ha enviado documentación. No te preocupes, están en ello. Por cierto, con que envíes un correo al día con las dudas y cuestiones es suficiente, procura no mandar muchos más porque se colapsa la bandeja de entrada y entonces no podemos atender ni los tuyos ni los de nadie más. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-04-21','Iciar; HAblo con Juzgado nº 2 Montijo(José Luis)me facilita nº de cueta , cantidad y concepto para realziar el pago de la multa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-21','miguel, tras recibir constantes llamadas e emails todos en la Ctaex, envío el siguiente email a Damian: Buenos días Damian, hemos recibido tuyos si no me equivoco alrededor de 355 mensajes. Te escribo para que entiendas que así no se puede trabajar. No podemos darte una dedicación exclusiva a ti ya que tenemos otras 700 personas que necesitan de nuestra ayuda diaria. Es por eso que o bien me envías en un solo email todas los documentos ordenados y en pdf o bien me los tendrás que hacer llegar tras el estado de alarma bien presencialmente o bien en sobre certificado con acuse de recibo. Espero que lo entiendas, ya que llevamos 2 días intentado poner en pie todos estos mensajes y es imposible. Si alguna vez necesitas algo envía uno o dos mensajes no más porque saturas los emails. Gracias, saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-04-21','(Pedro)Correo del CRR de Mérida. +++Ángel Pinilla está bien. Mantiene buena relación con el resto de sus compañeros, pasa tiempo en zonas comunes con ellos y se encuentra mucho más tranquilo que antes de ingresar en el hospital. Algunas veces, cuando ve que tenemos muchas tareas pendientes se ofrece a ayudarnos. Siempre que lo pide, favorecemos el contacto telefónico con su madre','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-04-21','(Pedro) Correo del CRR de Mérida: +++María Dolores Fernández en algunas charlas conjuntas con el resto de residentes, ha afirmado que esta situación está contribuyendo a una mayor cohesión entre los compañeros. También resalta como positivo que su familia se está poniendo en contacto con ella de manera más frecuente. Pasa más tiempo que antes en la habitación, al preguntarle, nos comenta que sigue recomendaciones de su familia de mantener la distancia. Sin embargo, no lo vive como algo negativo, hace hincapié en que ella se encuentra a gusto de esta forma y cose, limpia, abre las ventanas, escribe...En algunas ocasiones ha venido al despacho algo afectada, pero charlando con ella se ha reconducido fácilmente, nada especialmente destacable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-04-21','(Pedro) Correo del CRR de Mérida. +++José María Guillén, en la misma línea que la compañera anterior. Ha pasado una semana muy buena, tranquilo, menos demandante y de mejor humor. Coincide con María Dolores en que pasar más tiempo en la residencia le está ayudando a relacionarse y conocer más a los demás. De la misma forma que con el resto de usuarios, se facilita el contacto telefónico con su familia. Hay tareas simples, como avisar a los compañeros de que vamos a realizar una actividad, que algunas veces se las encomendamos ya que hemos observado que le hace sentir bien, casi siempre está muy dispuesto a colaborar. Tiene intención de hablar con vosotros para solicitar un aumento de su paga mensual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-04-21','(Pedro)Correo del CRR de Mérida. +++Luisa Rodríguez más participativa que semanas atrás, sin embargo algunos días nos cuesta muchísimo que salga de la habitación. En general, bien aunque pasa durmiendo gran parte del día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-04-21','(Pedro) Correo de CRR de Mérida. +++Antonio Merchán tal y como os comentamos sufrió una agresión días atrás por parte de otro usuario de la residencia. Al no prescribir, Dirección acordó con él valorar cuando termine esta situación si quiere interponer la denuncia. Su compañero se disculpó con él por lo ocurrido. Antonio se encuentra más tranquilo y continúa con su rutina habitual en la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GARCIA'and apellido2='GONZALEZ'),'2020-04-22','EXITUS El Jzdo. informa, además de la firmeza de la Sentencia de Icp., el fallecimiento de D. José. Ocurrido el 22/10/2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-04-22','Ana: Correo de la Dirección de la Res. San Jorge-Grupo Ciudad Jardín - CC (recepcionsanjorge@grupociudadjardin.com): "Buenos dias Ana,Queria informarte del estado de salud de nuestra residente Juliana Paula Centeno Rodriguez. (TUTELADA)Esta pasada noche ha tenido fiebre,deposicion diarreica y ha desaturado,con lo cual su estado de salud ha empeorado.Hemos procedido a la prueba del covid,siendo esta positiva.La residente se mantiene en el centro,valorando el equipo médico su traslado al centro hospitalario si asi lo consideran.No dudeis que haremos todo lo que este en nuestras manos para darle la mejor asistencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2020-04-22','DIVISIÓN DE HERENCIA. Correo de Ángel. +++Este tema lo estuve llevando yo, hay un problema entre los hermanos por la herencia de sus padres fallecidos, no se ponen de acuerdo, porque tanto Isabel como Lino (hermanos), quieren hacer un reparto desigual de la herencia, en lugar de hacerla tal y como vienen en los testamentos de sus padres y tanto la notaría de Guadalupe como nosotros queremos que se realice según los testamentos de sus padres, o en su caso, si algún hermano quiere hacer un reparto desigual, que compense al resto. Veo que la parte demandante, su hermana Isabel, interviene con Abogado y Procurador. Por este motivo, vamos a solicitarle abogado de oficio a Tomás, para que le represente en este procedimiento. Voy a redactar un fax para remitirlo al Juzgado. En ese mismo fax, solicitaremos que nuestra comparecencia se realice mediante videoconferencia en los Juzgados de Mérida, si en esa fecha, ya se ha vuelto a la normalidad en cuanto al estado de alarma. En cuanto a las citaciones, creo que se trata de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-04-22','miguel, me pide Curro y le remito el word de solicitud de revisión de capacidad para pasar de curatela a tutela, para prepare la Demanda de revisión de capacidad de curatela a tutela','2');
