insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2020-04-22','TERESA: SALIDA DOMICILIO FAMILIAR DE 31/01/20 AL 3/02/20 ZAFRA. domicilio familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2020-04-22','TERESA: SALIDA DOMICILIO FAMILIAR ZAFRA DEL DEL 21 AL 27 DE FEBRERO. domicilio familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-04-22','TERESA: EMAIL DE LA ENTIDAD Lo menos importante podría ser la falta de rutinas y de horarios que tiene…por ejemplo dormir prácticamente de día y la noche despierta… el episodio más importante y de más gravedad se ha dado a raíz de una discusión con su novio Juan Antonio, quien también está en el domicilio familiar y hacemos seguimiento telemático como usuario de centro ocupacional, y es él mismo el que nos pone en sobre aviso de lo que estaba sucediendo: Natalia había roto con él por teléfono, acusándolo de serle infiel y de tontear con otras chicas. Esto la llevó a amenazarlo con darle una paliza y demás “lindezas” cuando vuelvan a verse. Pero este episodio Juan Antonio lo mantuvo en secreto, hasta que entra en acción la MADRE de Natalia, quien hace pasarse por una chica joven, para demostrarle a su hija que ese chico no era de fiar y ella también lo amenaza. Ante tanta presión, Juan A. se lo cuenta con mucho miedo a su monitora de referencia y bajo la advertencia de que nadie más se puede enterar. Evidentemente con ayuda de los psicólogos, su monitora ha podido intervenir dándole más apoyos a Juan Antonio, al que se le asesoró y se le sugirió, siempre que él estuviera de acuerdo, que la forma más rápida y segura de librarse de esas amenazas sería bloqueándolas en el móvil a ambas. Así lo hizo y parece estar más tranquilo. Por otra parte, quedaba pendiente por tanto, la intervención con Natalia sobre el asunto. Pilar, la abuela, dice que desconocía todo lo ocurrido y Natalia, en un primer momento intenta confundirnos en la manera que había retomado el contacto con su madre, pero finalmente (y resumiendo) reconoce que lo mantiene con frecuencia y que no piensa renunciar a ella. Como ya conocéis, el hecho de que no mantenga contacto con su madre siempre se le ha argumentado..se le ha trabajado… desde la base que no es ni buena referencia, ni recibe los apoyos adecuados…que la incita a actos poco morales e incluso delictivos… y que Natalia puede llegar a entender y a reflexionar con nosotros que así es…peeeeeero que vuelva a aparecer una y otra vez en escena y para nada bueno. Natalia conoce que os íbamos a informar sobre esto, no parece que haya arrepentimiento, más bien se reafirma en lo ocurrido e incluso llega a culpar a su abuela de que nos hayamos enterado de todo esto y de que sea ella la que quiera separarla de su madre. A lo que la abuela también nos ha mostrado su preocupación y su temor por la actitud y conducta de Natalia así como por la madre. Llegados a este punto y tras informaros…no sabemos si desde vuestra posición podríais, deberíais o queréis intervenir…tenéis alguna idea o sugerencia…la situación ahora mismo es la que tenemos……. en la entidad estamos ya valorando y priorizando el orden de admisión, tras el confinamiento, al servicio de residencia…a Natalia la hemos priorizado en segundo lugar pero hasta que nos tengamos respuesta de la Consejería no sabemos cuándo será posible el regreso. La abuela, de momento, no nos ha expresado que quiera llevarla al centro de nuevo, de hecho esta pendiente de que le enviemos más dinero por los gastos, digamos de manutención de Natalia osea que la previsión es de que Natalia pueda finalizar en confinamiento con los abuelos en Badajoz. Sé que puede ser difícil de entender todo esto por escrito…no sé si me he explicado bien o lo suficiente…si te parece oportuno, te pongo mi numero personal, me llamas y lo hablamos. Nº móvil: 659 338 110','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-04-22','(Pedro) Llamada de Ceferino desde el 642-412904. +++PETICIÓN: se quiere ir a vivir con su novia, Ramona Belmonte, a un piso de alquiler: "...ella sabe cocinar y limpiar y yo puedo adquirir otras habilidades como planchar, etc...".Llama en presencia de Ramona, que incluso se pone un momento al teléfono para saludar."...pedro, porque yo no quiero estar toda mi vida de CRR en CRR, yo quiero tener una vida como los demás...". +++Me comenta que su PSICÓLOGA es BLANCA. +++Les digo a ambos que es algo que hay que pensar y que la Comisión hablará con los compañeros del CRR sobre el tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2020-04-22','TERESA: Hola Teresa Saúl recibió alta hospitalaria el lunes 20 de abril por la tarde (te adjunto el informe de alta hospitalaria). El doctor me comunicó el lunes que había dejado de vomitar, que los niveles de potasio están bien y que por tanto procedían a darle el alta hospitalaria. Regresó por la tarde a residencia y hemos activado con él el protocolo de Coronavirus para residentes que salen de hospital. Y este consiste en aislamiento durante 14 días y pendientes de si presenta sintomatología. Tras ese periodo y si no hay sintomatología, finalizará su aislamiento. Respecto al tiempo destinado al acompañamiento de Saúl en hospital te adjunto nuestro protocolo (aunque ya lo envié por correo ordinario) y el documento de justificación de gastos. El pago del mismo hay firmado un documento llamado "gestiones médicas" y lo que hacemos es cargar en la cuenta que nos indicasteis la cantidad. El sábado día 18 se acompañó a Saúl durante dos horas, y en la tarde igual. El domingo se procedió al mismo acompañamiento, dos horas por la mañana y dos horas por la tarde. El lunes no hubo acompañamiento, pues el doctor nos indicó que recibía alta hospitalaria y que el traslado hasta residencia se haría en ambulancia. El documento original os lo enviaré cuando sea posible para que me lo remitan firmado y sellado, aunque te lo adjunto. Para cualquier duda o aclaración, aquí estoy','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-04-22','TERESA: CONFINAMIENTO EN DOMICILIO FARMILIAR, SE PRIORIZ PARA SU VUELTA AL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2020-04-22','TERESA: ROSA ESTA PASANDO EL CONFINAMIENTO EN DOMICILIO FAMILIAR EN VILLFRANCA DE LOS BARROS , SE ENCUETRA BIEN Y ESTABLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2020-04-22','Ana: Recibimos correo del C.R. Cervantes (rm.caceres@salud-juntaex.es): "Adjunto remito informe médico del Centro Residencial Cervantes de Cáceres referente a la residente Dª VICTORIANA HERNANDEZ GARCIA. un saludo LA DIRECCION DEL CENTRO" / *Ha dado positivo en el Test de Covid-19. *Guardo el correo y el informe en el expte. PC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-22','Ana: Correo de Toni-Futuex: "Hola! te cuento un poco, lo que hemos actualizado de el hoy, el catering lo anulamos y el hermano está al tanto de todo, te explico mejor: Esta mañana el a llamado a la compañera e informa que está en la ambulancia de camino a Mérida para su ingreso en cetro sociosanitario (acompañado por el conductor y un celador), durante el tiempo que ha permanecido a la espera en el hospital, el equipo médico le ha explicado que se ha emitido una orden judicial por parte de los juzgados para su ingreso en el centro, por lo que es consciente que no debe oponerse a dicho ingreso, ya que ha sido decisión judicial y de la CTAEX. Por su parte el tutelado se muestra tranquilo, a pesar de que no quería ingresar en este tipo de centros si no en un CRR, debido al carácter abierto del último, asume que debe ser así se le recomienda de paso que cumpla con la normativa y las indicaciones que se le impongan en el centro para evitar posibles problemas o limitaciones que le pudieran surgir por el incumplimiento de la normativa.Él también es consciente que en Cáceres no podía seguir. Se muestra preocupado por cómo podrá acceder a su dinero y cómo se hará la provisión de tabaco una vez esté ingresado, en este caso se le emplaza a los profesionales del centro que le explicarán todos los detalles de la normativa a su llegada. Que este tranquilo. Posteriormente contacta de nuevo con la educadora para interesarse si la Orden de alejamiento hacia Consuelo Nevado está en vigor, porque la policía le dijo que teína dos órdenes de alejamiento, solicita que se contacte con Pilar la TS de salud mental, para que informe de dicha situación, se le transmite que de estar en vigor no debe preocuparse puesto que se traslada a otra ciudad y no podrá incumplirla, hecho que no se había planteado y lo tranquiliza. Comenta también que su hermano ha estado en el hospital a primera hora de la mañana y le ha llevado su ropa y 6 paquetes de tabaco para los primeros días. Él ha estado en contacto con su hermano José Luis estos días y le ha ido informando de la situación. Se contacta posteriormente con Pilar se ESM Cáceres, para confirmar que efectivamente ya se ha producido el traslado, informa que ha solicitado información al ministerio fiscal sobre las órdenes de alejamiento y según este organismo no existe ninguna orden activa puesto que la que tenía hacia Consuelo ya ha prescrito."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-04-23','Ana: Recibo correo de Mariola, Directora Res. San Jorge, Grupo Ciudad Jardín (recepcionsanjorge@grupociudadjardin.com): "Buenos días Ana, no tengo buenas noticias.Juliana Paula continua con mala evolución. Esta noche hemos llamado al 112,ya que seguia saturando mal.Le han puesto medicación y nos han dado pautas a seguir si empeorase.Medidas de confort si fuese necesario. Debido a su empeoramiento,cuando puedas me hagas llegar poliza de decesos,e indicaciones a seguir en caso de fallecimiento. Seguimos en contacto,un abrazo Mariola." ////////////////////////// Envío imagen con el nº de poliza del seguro de deceso y las indicaciones a seguir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2020-04-22','TERESA: EMAIL JULIA TS PI ALMENDRAELJO De nuevo me pongo en contacto contigo para trasladarte una información sanitaria sobre Saúl Rodríguez Ramos. En la madrugada de hoy volvió a vomitar (color poso de café), la barriga muy inflamada y verbalizaba que le dolía el estómago. Procedimos a llamar al 112. Tras ocultación, nos dice que tiene una gran cantidad de gases acumulados y de ahí que probablemente le duela. Cierto es que no vomitó tanto como las anteriores veces, por lo que le inyectan buscapina y priperan. Nos comunican que derivarlo al hospital no serviría de nada en este momento, pues la doctora leyó los informes del último ingreso hospitalario (lunes 20 de abril) y nos comenta que probablemente lo que le suceda a Saúl solo se le diagnostique tras la elaboración de una endosocopia. Debido a la situación sanitaria, dicha prueba solo se está realizando para casos urgentes. Nos pauta vigilancia. El resto de la noche la pasó bien. Te mantengo informada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-04-23','(Pedro)Llamada de Pilar (ESM). +++Plantea que Saturnino vaya al CEDEX. la próxima consulta en el ESM la tiene en julio. +++Le planteo un adelanto de la cita y que en ella se hable con él de su voluntariedda para iniciar tratamiento en CEDEX y, si acepta, derivarlo desde allí. Quizá también habría que ver la disponicbilidad de su hermano para colaborar en ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='HERNANDEZ'and apellido2='MARCOS'),'2020-04-23','TERESA: RECIO EMIAL DEL CENTRO Lamentablemente tengo que escribiros para comunicaros una mala noticia, aunque podría ser peor. El pasado martes, la tutelada FELISA HERNANDEZ MARCOS, sufrió una caída en la que se fracturó el húmero y tuvimos que llevarla al servicio de urgencias del Hospital Virgen del Puerto de Plasencia, allí se hizo un TAC y una radiografía que confirmaron la fractura. Debe volver a revisión en tres semanas. Tenemos protocolarizado que cualquier usuario que recibiera atención en el Hospital debe mantener aislamiento los siguientes 14 días y tratarlo como un posible coronavirus. Puede parecer exagerado desde fuera, pero no hacerlo ha sido el fatal error de algunas residencias y así lo decidimos y pusimos por escrito al iniciarse el Estado de Alarma. Por todo esto, Felisa se encuentra en aislamiento preventivo en una habitación habilitada para ellos, se le atiende con EPI completo y se entra en su habitación lo menos posible. Ella se encuentra bastante triste (y nosotros también), aunque intentamos que haga cosas que le gustan (le gusta hacer punto y también le hemos llevado chocolatinas y una radio). Por todo esto se nos ha ocurrido (y previendo que después de su revisión, tiene que volver al aislamiento), poder comprarle una televisión y un pen drive para poder ponerle películas. Muchos de nuestros usuarios tienen televisión en su habitación, pero en el caso de Felisa no os lo he pedido anteriormente porque solía hacer uso de la televisiones comunitarias (hacemos sesiones de cine habitualmente). Quedo a la espera de vuestra respuesta (yo me encargaría de pedirla y todo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='GALINDO'and apellido2='CALLE'),'2020-04-23','EXITUS Fallecida el 25/03/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-04-23','Ana: correo de Estrella, TS CSS-Plas.(estrella.duranc@salud-juntaex.es): "Buenos días Ana. Demanda Juan que te pongas en contacto con su Psiquiatra Doctor Pizarro. Gracias. Saludos" //////////////////// Mi respuesta: "Buenos días Estrella, ¿la demanda es de Juan o del Psiquiatra? Si es el psiquiatra quien quiere hablar conmigo, si no te importa cuando le veas le dices que puede llamarme al número de la CTAEX cuando quiera sin problema. Si la demanda es de Juan, ¿sabes por qué lo pide? Pues si no es por nada en concreto y necesario, cuanto te lo vuelva a decir le dices que desde la Comisión nos pondremos en contacto con el psiquiatra cuando lo consideremos oportuno o cuando el psiquiatra así lo estime. Desde aquí no vamos a importunarle sin un motivo aparente. Espero que sigas bien. Gracias y un saludo." /////////////////////////////////// Respuesta de Estrella: "La demanda es de Juan, pero no obstante le pregunté a su Psiquiatra, éste me dijo que podías llamarlo cuando quisieras, que cuando pase el confinamiento se le dará el alta. Así que si vuelve Juan a decirme algo, ya le dará tu respuesta. Gracias Ana" ////////////////////////////////////////// Remito a Estrella por mail el registro de la Intranet de la conversación con Juan el día 13. Le digo también que o Pedro, Jefe de secc., o yo llamaremos al Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2020-04-23','(Pedro)LLamada de Dª Concepción, hermana de D. Francisco (924-600468). +++Su hermano quiere cambiar la domiciliación de su pensión del BBVA a Ibercaja para no tener que acudir a Castuera a sacar el dinero. +++Según sentencia, el tiene plena capacidad para gestionar dicho cambio, lo que ya se le exolicado en otra ocsaiones. +++Él, a través del T. Social de la localidad, ya ha remitido escrito a la Seguridad Social, quien le contestó que para hacerlo requería la firma del curador. +++Le pido que, una vez pasado el estado de alarma, vuelva ainsistir con la Seguridad Social y en caso necesario pedirles que se pongan en contacto con la Comisión Tutelar.','1');
