insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2005-04-21','El Auto Declarando el desamparo junto con el expediente nos lo remite Gabinete Jurídico en noviembre de 2004. La sentencia de incapacidad declara la incapacidad parcial por lo que respecta a la esfera personal.... Intervenir el curador en actos de decisión en materia de admón de fármacos y viajes que superen los 50 Km desde la localidad de su residencia. Con plena capacidad para adminstrar sus bienes y para los actos de gobierno de su persona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-04-23','Ana: Correo de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es):Hola de nuevo. El martes tuvimos reunión el equipo terapéutico de UDAC, donde está Josefa y como ya te he comentado anteriormente, nos estamos planteando darle de alta y en vez de ir a su centro de Aprosuba de Zafra, pase a vivir con su hermano Rafa en el domicilio familiar. Queremos saber si necesitáis algún documento, informe etc, para poder llevar a cabo dicha incorporación al domicilio familiar. Gracias Ana. Saludos" //////////////////// Mi respuesta: "Hola de nuevo, Es verdad que dejamos la conversación pendiente unos días antes de decretarse el estado de alarma, que te llamé y estabas ocupada. A ver, a las compañeras y a mí (ellas son las que han llevado anteriormente el caso y lo conocen mejor) no nos parece mal probar la convivencia con su hermano. Lo que nos da miedo es que no funcione y haber pedido la plaza… pues supondría tener que comenzar luego de cero. En uno de los correos anteriores expresabas: “He hablado con su hermano y le parece bien probar a ver qué tal le va y si se descontrolara, según él se descontrola por la convivencia con la gente del pueblo que le dan consejos no siempre buenos, la traería otra vez aquí.” Y yo entiendo que esto no es así, pues no os la puede llevar allí de vuelta sin más… voy a consultar si hubiera alguna opción de que le reservaran la plaza en el centro durante un tiempo. Cuando tenga respuestas volvemos a hablar sobre ello. Un saludo." /////////////// Realizo a Maite Gómez, TS Secc. Discap., la consulta mediante mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-04-24','Ana: Correo de Maite Gómez, TS "¡Buenos días Ana! Puede estar en el domicilio cumpliendo los dias de ausencia permitidos al año. Pero no más. Sinceramente no creo que funcione. Está bien que prueben , pero no habrá una plaza disponible cuando haya problemas, si pierden la plaza de Zafra. Le voy a reeenviar tu correo a Manuela para que te de su opinión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-04-24','Ana: Recibo llamada de Emilia, dice que ya está mejor, le dieron el alta en el CSS y está de vuelta en el CRR. Expresa que cuando les informaron que se decretaba el Confinamiento y que no podrían salir del centro le dió una crisis y rompió la montura de las gafas, pero conserva los cristales. Pregunta si puede comprarse una cuando pase la crisis sanitaria. También dice que necesita ropa, lo habló con Paula. *Le indico que cuando pase esta situación y se pueda ir a las tiendas, que pida presupuestos de ambas cosas y los envíen desde el CRR al correo ctutelar@','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-04-24','TERESA: EMAIL P.I a Libertad García, también mantenemos el contacto telefónico tanto yo como mi compañera psicóloga de Centro Ocupacional así como los monitores de taller para enviar tareas semanales. La situación de Libertad es más complicada dada la situación sociofamiliar y económica. El martes Libertad manifestó el deseo de regresar al Centro, pero hoy dice que se encuentra bien. Lo hemos puesto en conocimiento del SEPAD y si regresa sería cuando le hayan realizado la prueba del COVID y sea negativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2020-04-24','TERESA: EMIAL PI mantiene contacto la delegada de FUTUEX y yo personalmente hablo tanto con el usuario como con su padre y puede mantenerse en casa hasta el fin del estado de alarma','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-23','Ana: Recibimos en el ctutelar@ un correo con la condonación de la deuda de Banco Cetelem.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-24','Ana: Icíar, secc. ecca. CTAEX, me informa que a Damián ya le han ingresado la Pensión en la nueva cuenta de Liberbank.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-04-24','Ana: Recibo llamada del Dr. Daniel Pizarro, Psiquiatra del CSS-Plas. (llaman desde este nº, pero no es el suyo directo 927 42 88 00): Me pregunta desde cuando conozco a Juan, pues su delirio es crónico, él lo conoce desde hace 7 años. Le informo de las conversaciones telefónicas de caracter semanal que he mantenido con Juan desde hace meses (desde verano) y el notorio empeoramiento que vengo notando desde octubre. Y en la última conversación no noté mejoría desde entonces. Daniel expresa que Juan no está dando ningún problema en el CSS, de hecho, dice, "está manteniendo un comportamiento ejemplar, incluso media entre compañeros cuando discuten", que está tranquilo y en relación a mi última conversación con él dice que puede que lo pillara en un día de mayor angustia. En esas fechas el ejército acudió a fumigar y desinfectar el centro y estaban todos, de forma más generalizada, angustiados. Aunque cuando habló con Juan de este tema, verbalizó que sabía perfectamente que los militares habían ido por el virus, que no estaba loco. Desde el equipo de psiquiatría y psicología han intentado hacer una trabajo psicoeducativo con todos los pacientes para abordar la situación de crisis sanitaria por Covid-19. Aunque Juan lleva mal los internamientos le sorprende su actitud, está aguantando con más pacienciencia de lo esperado. *Está haciendo bien el tratamiento, acepta y tolera el nuevo inyectable así como la medicación oral. *Su planteamiento es que si sigue razonablemente bien y comprometido con el tratamiento, cuando pase la crisis sanitaria darle el alta. Es consciente de que es un paciente crónico, que tendrá temporadas intermitentes, que podrá pasar temporadas en casa y otras temporadas tendrá que ingresar de nuevo en el CSS. Pero Juan es bastante autónomo, se maneja bien en las actividades diarias, hay que tener en cuenta sus habilidades y evitar la institucionalización. *Indico que en su pueblo no cuenta con los apoyos necesarios ni suficientes, dice que lo sabe, pero que contactará con el C.Salud para que desde Att. Primaria se le haga mejor seguimiento y se le dé mayor apoyo. Nombra también a Cruz Roja, pero le recuerdo que éste recurso sólo se encarga de proveerle alimentos. Y rechaza el seguimiento de Teresa, Delegada Tutelar, así como el de la Dra. Consolación, Médica de Att. Primaria y al Dr. Miguel Medina, Psiquiatra del ESM al que no quiere ni ver ni que se le nombre. *Manifiesta que sabe que Juan es muy listo, y sabe a quién puede o no contar ciertas cosas, cuestión que corroboro, pero que él también cuenta con otros mecnismos para saber cómo está, por ejemplo la relación que mantiene con otros pacientes y con el personal del centro (le recuerdo que dice que las auxiliares también están en la trama). Con todos en el centro se relaciona bien, se muestra educado y tiene buen manejo del lenguaje. Son habilidades a mantener. "En cuanto a la parte delirante intentamos mantenerla encapsulada, pues sabemos que no va a desaparecer nunca" añade. // En cuanto a mis llamadas, dice que es bueno para Juan contar con alguien de referencia, pero me pide que le llame mejor ya la semana que viene en lugar de hoy (hace 11 días que le llamé).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PECO'and apellido2='CARRANZA'),'2020-04-24','Ana: Recibo llamada de Longina, T.S. de Madrigalejo (659 149 639 = Nº Personal, sólo usar durante el Eº de alarma o en casos excepcionales). En relación al informe que le han solicitado para la rendición anual desde la CTAEX, dice que no sabe si podrá enviarlo durante el confinamiento, pues la mayoría de los días teletrabaja. Le indicio, como en el otro caso del que hablamos, que la compañera que lleva las rendiciones me ha dicho que no pasa nada, que dadas las circunstancias, si ahora no le es posible cuando finalice esta situción de crisis sanitaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2020-04-21','Recibo llamada de Longina, T.S. de Madrigalejo (659 149 639 = Nº Personal, sólo usar durante el Eº de alarma o en casos excepcionales). En relación al informe que le han solicitado para el inventario, dice que no sabe si podrá enviarlo durante el confinamiento, pues la mayoría de los días teletrabaja. Plantea si es urgente o puede esperar a que finalice esta situación. *Lo consultaré con la compañera encargada de las rendiciones y le informaré al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2020-04-23','Ana: Llamo a Longina, le transmito lo que me ha dicho Coral, secc. ecca.: no pasa nada si tarda más en enviar el informe social para la rendición anuarl, dadas las circunstancias, si ahora no le es posible, lo puede enviar cuando finalice esta situción de crisis sanitaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-04-24','BELEN: LLAMA HERMANA DE RAMON (ANGELA 722504512)PARA COMENTARNOS QUE RAMON QUIERE COMPRAR UN CUARTO,DE SEGUNDA MANO, AL PARECER CUANDO LE HICIERON LA LIMPIEZA EN LA VIVIENDA LE TIRARON TODO,Y TIENE EL COLCHON EN EL SUELO. LE INDICO QUE CUANDO SE PUEDA,UNA VEZ PASE EL PERIODO DE CONFINAMIENTO,PIDA PRESUPUESTO Y NOS LO HAGA LLEGAR A TRAVÉS DE LA DELEGADA TUTELAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-03-25','"Buenos días Ana,queria informarte,del fallecimiento de nuestra residente Juliana Paula Centeno Rodriguez,el día 24/04/2020 alas 14:00 hrs. Aunque hemos procedido a la notificación segun me indicastes; queria trasmitirtelo personalmente. Para nosotros ha sido muy dura la pérdida,pero nos queda la satisfacción del buen hacer por parte del equipo,acompañarla y cuidarla hasta el último momento. Gracias por facilitarme todas mis dudas,recibe un abrazo.Mariola -- Saludos, Mariola."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-04-25','Ana: Correo de Mariola, Directora de la Res. San Jorge-Grupo Ciudad Jardín - CC (recepcionsanjorge@grupociudadjardin.com): "Buenos días Ana,queria informarte,del fallecimiento de nuestra residente Juliana Paula Centeno Rodriguez,el día 24/04/2020 alas 14:00 hrs. Aunque hemos procedido a la notificación segun me indicastes; queria trasmitirtelo personalmente. Para nosotros ha sido muy dura la pérdida,pero nos queda la satisfacción del buen hacer por parte del equipo,acompañarla y cuidarla hasta el último momento. Gracias por facilitarme todas mis dudas,recibe un abrazo.Mariola -- Saludos, Mariola."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-04-24','Ana: Correo de la residencia San Jorge al ctutelar por la tarde: "Buenas tardes,adjunto certificado médico de defunción de nuestra residente Juliana Paula Rodriguez Centeno. Tutelada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2020-04-24','(Pedro) Conversación con Jossé Manuel, Subdirector de Régimen en el C.P. de Badajoz ((924-289105). Tras solicitarla, remite correo electrónico el pasado viernes 24 de abril con la siguiente información: +++ Cristofer Rollan Suarez es PRESO PREVENTIVO estando a disposición del Juzgado de 1ª Instancia e Instrucción nº 4 de Mérida en diligencias Previas 217/2019, por lo que NO SE PUEDE PREVER el tiempo que permanecerá ingresado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-04-27','EXITUS El centro informa de su fallecimiento, por COVID-19, el 24/04/2020. /////////////////////////////////////////////////////// Ana: Recibo llamada de Soledad (660 802 605), "hija" de Jualiana Paula, le facilito la información del Jdo. que incapacitó a su "madre" para que pueda ponerse en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-04-24','(Pedro) Se recibe del C. Penitenciario de Badajoz (José Manuel, Subdirector de Régimen) Informe sobre la situación de las condenas pendientes: +++CONDENA ACTUAL (Juzgado Penal Don Benito 299/2019): hasta el 22-agosto-2020. +++CONDENAS PENDIENTES(Juzgado penal Don Benito 374/2019):1 AÑO y 15 MESES. COMIENZO el 23-agosto-2020 HASTA el 25-marzo-2022)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-27','Ana: Recibo llamada de María Barrasa, TS CSS-Mérida (924 388 081), primero para informarse sobre José Manuel, su situación y trayectoria, pues Taciana, Psiquiatra, no encuentra motivos clínicos para mantener el internamiento. No obstante me informa que en el fin de semana que lleva en el centro, demanda irse de alta y al parecer ya ha provocado varias situaciones conflictivas llegando a tener que intervenir el vigilante del seguridad del centro. “Genera mucha agresividad ante cualquier frustración”. Demanda más tabaco del que está permitido fumar en el centro, tienen establecido por norma un máximo de un paquete diario por paciente, pero él demanda más, le han puesto parches de nicotina y se los quita y pone a otros pacientes, dice que eso no lo quiere. Finalmente le han autorizado 2 paquetes al día y le siguen pareciendo poco. ++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con María Barrasa. +++Le pido que me envíe Informe sobre la situación de José Manuel, pero me dice que hable con taciana ¿?. +++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Taciana. +++Considera que los motivos que el Auto de internamiento escrime para llevarlo a cabo ya han cesado, por lo que José Manuel está para darle el alta. +++Le pido que me envíe informe clínico para adjuntar al Juzgado. Lo enviará mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-04-20','(Pedro) Llamada de Dª Cristina (664665395), hermana de José Vicente. +++"MI hermano me está llamando desde prisión diciéndome que le duele mucho la barriga y que no le hacen caso...". La tranquilizo: si fuese algo importante ya nos lo habrían dicho desde el centro. +++Llamo al Centro Penitenciario. Hablo con José Manuel (Subdir. Régimen). Pasará a verlo el médico. +++Llamo a José Vicente. Lo noto como siempre. DEspués de hablar con él llamo a la hermana para comentarle que pasará averlo el médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-04-23','(Pedro)Durante la semana he intentado hablar con el C. penitenciario varias vesces sin conseguirlo. Hoy he hablado con el Subdirector de Régimen. +++Durante el fin de semana pasado y el lunes lo están viendo los médicos, porque tiene un fuerte estreñimiento. Le han recetado un laxante, pero por lo demás se encuentra bien. +++Seguirá en el módulo 3 que es el que se considera mejor para él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2020-04-24','Vuelven a llamar con el mismo tema, a pesar de insitirles en que desde la Comisión Tutelar no podemaos hacer nada al respecto. +++Insistenen que hable con Casimiro, el T. Soccial que les hizo el escrito para la Seguridad Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-04-27','Ana: Recibo llamada de Emilia, plantea que necesita también unas gafas de sol. Como en la llamada anterior, se le indica que cuando pase la situación de confinamiento, remitan desde el CRR presupuestos de un par de ópticas al ctutelar@ a la A/A de la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2020-04-27','Ana: Correo de Toni-Futuex (areasocial3@futuex.es): "Hola Ana, buenos tardes! Te paso pequeña nota de Felipe Rodriguez de Miajadas, ha estado enfermo con una clinica sugestiva de Covid, le hicieron prueba rapida y salió negativo, aun ha si, ha estado una dia en el hospital, poruqe tenia baja saturación de oxigeno, le han hecho algunas pruebas complementearias y paraece aunque se ve un poco mal el informe que esta todo bien, tiene un cuadro de amigdalitis o algo asi. Mña intentaremos hablar con su medico de primaria para que le hagan un seguimiento, pero con el tratamiento que le han puesto se encuentra mejor.. Mñana seguimos!" /// Guardo el correo, nota e informe médico en el expte. PC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2020-04-28','Ana: Juana, secc. ecca. CTAEX, me comunica que a María ya le han ingresado en su cuenta la PNC, ahora mismo tiene 1974,40 euros. // Contacto por mail con Estrella, TS Mancomunidad (ssbestrella@mancomunidadvalledeljerte.es), y Jesús, Director Res. de El Torno (jesusi6@hotmail.com), planteando las cuestiónes que Juana me plantea: - Deuda que tiene contraída con el centro por atrasos - Coste actual de la plaza y saber si lo van a cargar en cuenta o se hace el pago por transferencia. - Gastos personales y forma de pago. *Pregunto también cómo sigue María. /////////////////////// Remito a Juana, secc. ecca. los correos que me envían tanto Jesús como Estrella, especificando la deuda pendiente. **Recuerdo a Juana que María tiene otra cuenta compartida con su marido, Antonio Paredes Hdez, tb tutelado ya por la CTAEX, de la que se planteó hacer una transferencia a la nueva cuenta de María para que pueda costear parte de lo que debe y otras cuestiones pendientes (necesitaba ropa). ///////////////////// Jesús añade en el correo: "En cuanto al estado de salud de Maria Romero, decir que evoluciona satisfactoriamente, no tienen dolores, sigue aislada por precaución hasta el 1 de mayor de 2020 pero por lo demás esta bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-04-28','(Pedro). Conversación de Amalia con Dª Isabel, hermana de D. José Antonio. +++José Antonio se encuentra viviendo con su hermana en la localidad de Daimiel (Ciudad Real) desde hace aproximadamente 4-5 años, donde se encuentra empadronado. +++Dª Isabel tiene la tutela de su hermano Félix. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++INTERVENCIÓN: +++++SOLICITAR INFORME SOCIAL al SSB de Daimiel. T. Social: Ana Beatriz Mejía Sánchez-Hermosilla. Teléfono Ayto: 926-260603. FAX: 926-260650. SE solcita por correo electrónico (Teresa) +++++SOLCITAR CERIFICADO DE EMPADRONAMIENTO COLECTIVO. +++++Solicitar traslado de expedeinte de tutela a la C.A.de Castilla La Mancha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2020-04-28','(Pedro) Se recibe en la Comisión Auto del Juzgado de 1ª Instancia nº4 de Plasencia en realción a la decisión de NO intervenir a D. Pablo. +++El Auto CONFIRMA la decisión adoptada por la CTAEx (ver en expediente virtual/ intervención quirúrgica decisión). +++Intento hablar con el Dr. Urbina pero no se encuentra en el Hospital. +++Hablo con Ana Marta Fernández (78471), T. Social del Hospital: le nevío por correo electrónico (anamarta.fernández@salud-juntaex.es) el Auto. Pongo en copia a Teresa y Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-04-28','TERESA: RECIBO LLAMDA DE ANA PLENA INCLUION PARA COMENTARME LOS ULTIMOS ACONTECIMIENTOS CON RESPECTO A NATALIA. HAN RECIBIO EN LOS TELEFONOS PERSONALES DE MIGUEL Y DE ANA MARUQEZ (MONITORES DE NATALIA) UNA SERIE DE WASUP EN LOS QUE PONEN EN ENVIDECIA QUE NATALIA SIGUE TENIENDO CONTACTO CON SU MADRE A TRAVES DEL TELEFONO DE LA ABUELA, SE RECOGEN AMENZAS DE LA MADRE DE NATALIA HACIA SU ABUELA EN EL SENTIDO DE QUE NO LA CUIDA BIEN Y NO SE HACE RESPONSABLE DE ELLA Y QUE LA VA A DENUNCIAR POR ESTO. ME DICE ANA QUE PILAR QUEIERE HABLAR CON LA COMSION POR ELLO ME PONGO EN CONTACOT CON PILAR LA LLAMO (PILAR 642 53 60 20) Y LE DIGO QUE QUE NECESITA QUE ANA ME HA DIHO QUE QUIRE H ABLAR CON LA COMINION, AL PRINCIPIO ME DICE QEU NO QUIERE NADA QUE SOLO LE EXTRAÑA QUE LA COMISION NO LA LLAME PARA I NTERESARSE POR NATALIA, LE COMENTO QUE EL SEGUMIENTO SE HACE A TRAVES DE LOS CENTROS Y QUE LOS CENTROS NOS INFORMAN A NOSOTROS YA QUE HAY MAS TUTELAS EN LA MISMA SITUACION QUE NATALIA. SEGUIDO ME COMENTA QUE HAN PEDIDO DINERO Y QUE CHARO LE IBA A HACER UNA TRANSFERENCIA LE COMENTO QUE TENGO CONOCIMIENTO DE ELLO Y QUE ESTAN INTENTANDO HACERLE UNA TRANSAFERENCIA. ME COMENTA QUE NATALIA ESTA BIEN QUE ESTA TRANQUILA QUE LLEVA CON ELLOS DESDE EL 13 DE MARZO. QUE LO ESTA LLEVANDO BIEN PERO QUE LA SEMANA PASADO RECIBIO UNA LLAMADA DE SU MADRE EN EL TELEFONO DE SU ABUELA. NATALIA RESPONDIO A LA LLAMADA Y LE DIJO QUE NO PODIA HABLAR CON ELLA Y LA MADRE LE RESPONDE QUE ENTONCES SI NO HABLA CON ELLA QEU NO VA A MOVER NI UN PAPEL PARA QUE SEA ELLA SU TUTORA. A RAIZ DE ESTO EMPIEZA A RECIBIR MENSAJEES DE AMENAZA HACIA PILAR, LE PONE QUE ESTA USANDO A LA NIÑA PARA PEDIR DINERO, QUE NO LA TIENE BIEN ASEADA..... PILAR COMENTA QUE NECESITA UNA MAYOR ATENCION POR PARTES DE EDUARDO YA QUE SOLO LA HA LLAMAMDADO DOS OTRES VECES DESDE QUE ESTA ALLI. PILAR AFIRMA QUE LO QUE QUIERE LA MADRES ES UNA PAGA PARA QUE LE SOLUCIONES SU VEJES Y POR ESO QUIERE SER LA TUTORA DE NATALIA YA QUE EN 23 AÑOS NO SE HA PREOCUPADO POR SU HIJA. PILAR COMENTA ESTAR AGOTADA Y QUE YA NO PUEDE MAS QUE NO TIERNE VIDA.... SE DESPIEDE DANDO LAS GRACIAS POR NUESTRO INTERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-04-28','Ana: Recibo llamada de Felisa (722 494 033), sólo quiere preguntar si esta semana podrá volver a retirar su asignación. Le indico que las compañeras volverán a hacerle la transferencia a la cuenta de su cuñado. Por lo demás, sólo quería charlar un ratito, dice que sigue bien, que espera que esta situación pase pronto, hoy la noto mejor de ánimos. Dice que le gustaría conocerme algún día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-28','Ana: Llamada de Damián (622 834 876), expresa que le ha costado mucho contenerse para no llamar estod días atrás. Le gustaría poder ver los movimientos de sus cuentas, ya no tiene acceso online. Pide que se le atorice. Le explico que no es posible facilitarle las claves. No obstante consultaré con la parte económica si hay alguna otra opción. *Por otra parte, dice que tenía más deudas pendientes que no sabe si están en vigor en: Experian Bureau, DIN-DIN y Wonga. Le gustaría que comprobasen si aún las tiene, cree que alguna de las empresas han desaparecido. Lo consultaré también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-04-28','(Pedro). Llamo a Plena Inclusión de Cabeza del Buey (924-601081). Hablo con Silvia, su Directora. +++Ver último Informe remitido y hablar con Miguel y Ángel sobre viabilidadde restringir uso del teléfono, autorizar el acceso a sus llamadas (mensajes, redes, etc.), autorizar solo llamadas supervisadas o retir el terminal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-04-28','Ana: Recibo llamada del Dr. Daniel Pizarro, me dice que Juan ayer estaba bastante irritable, me pide que me espere un par días más para llamarle. Juan empieza a estar un poco nervioso por el tiempo que lleva ya ingresado. Así y todo mantiene su postura en cuanto al próximo alta de Juan, expresa que éste está muy comprometido con el tratamiento, le ha verbalizado que acudirá rigurosamente a ponerse el inyectabale al C. Salud, mantiene buen trato con la enfermera. Juan le ha solicitado cambiar de Psiquiatra del ESM, él ya ha hablado con el ESM de Cáceres y no hay problema, se encargará de solicitar el cambio de forma telemática desde el CSS. Le incluirán en el Programa de Trastorno Mental Grave y le harán un seguimiento estrecho. Considera que no es bueno para Juan mantnerlo mucho más tiempo allí encerrado. "Está demostrado que la persmanencia en estos centros a largo plazo no funciona, el último ingreso largo de Juan llegó a provocarle ideación autolítica y no quiero volver a llegar a eso". Se plantea el alta en las próximas 2 semanas si el Estado de Alarma lo permite, pero le gustaría asegurar primero que le seguirán llevando alimentos desde Cruz Roja y que preguntemos si hay más médicos de Atención Primaria en Guadalupe y si es posible cambiarle, pues considera que al igual que hacen en el CSS, a veces es bueno cambiar de referentes y a la Dra. Consolación también la ha incluído ya en su delirio. *Expresa que con el paso de los años, es consciente que Juan necesitará ser institucionalizado, pero a día de hoy sigue siendo bastante autónomo y cree que la mejor opción es que vuelva a casa y que se alterne con periosos cortos de ingreso en el CSS cuando sea necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2020-04-28','ASUNTO: Mantenimiento de Servicio de Atención Residencial. Entregan desde la Unidad de Gestión de Progamas Asistenciales Resolución del Director Gerente del SEPAD, de 26 de febrero de 2020, de Programa Indicidual de Atención, consistente en mantenimiento del servicio de atencion residencial en ASPACE CACERES. Archivo la misma en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-04-28','Ana: Llamo al HVP - Plas., Maribel, TS, no está, hablo con Ana Marta, TS, dice que ya están esperando el alta de Nemesia, podrá volver a los PPTT de Guijo de Granadilla, éstos ya reúnen las condiciones para que pueda volver. Me mantendrán informada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-04-28','(Teresa y Pedro) Se intenta comunicar varias vecs con ella pero no coge el teléfono. No es la primera vez que ocurre esto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-04-29','Correo-e de Futuex de ayer, 28 de abril de 2020. En el seguimiento realizado el día 27 de abril, José Manuel establece que quiere solicitar el cambio en el beneficiario de la ayuda de Dependencia de su abuela y vincularla a él como cuidador; en un principio, establece que es porque se ha dado cuenta de que puede hacerlo todo sin apoyo, pues así lleva desde antes de la declaración del estado de alarma, cuando pidió a la auxiliar que sin medios de prevención no acudiese. Según avanza la conversación, acaba admitiendo que se le acaba el subsidio que cobra de desempleo y no tiene opción de solicitar más… Comenta que tiene toda la documentación para solicitar dicho cambio, se la envió Pilar, la trabajadora social y le digo que podía hacerlo. Auqnue se le explica que no puede hacerlo, obvia lo que se le comunica. Se contacta con Pilar, Trabajadora Social, de la localidad para consultar lo comunicado por José Manuel, Pilar establece que le facilitó la documentación para el cambio, pero eso fue a finales de febrero, principios de marzo, no ahora… no entiende por qué no lo ha comunicado hasta ahora. Establece que le dijo que le parecía bien, pero que fuese consciente de que ese tipo de ayuda es diferente a la que tiene, por ser familiar y la cantidad es menor, de unos 100-200€. Se le dice que dicha documentación se le ha dicho que la devuelva a la trabajadora social y la tendrá que enviar a la CTAEX pues son quienes tienen que autorizar para la solicitud de la revisión. Pilar comenta que así lo hará, enviará todo a la CTAEX, pero que ella no se va a enfrentar a José Manuel, porque es una persona muy problemática, prefiere decirle que sí a todo y darle el gusto antes que discutir y enfrentarse con esta persona. Se le dice que eso perjudica la labor, tanto de la educadora de apoyo como de la CTAEX y el enfrentamiento constante; comenta que lo siente y sabe que la educadora de apoyo es quien da la cara y carga, pero ella es la que reside en la localidad y no quiere problemas… ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Respuesta a Ana al respecto. Y en relación a Dª Manuela, sintiendo mucho la situación en la que dice encontrarse D. Manuel no es aceptable la propuesta de cambiar el beneficiario de Dependencia, no solamente porque él no es el tutor de su abuela ni tampoco quien genera el derecho a percibirla, sino porque, además, la presencia de la Auxiliar de Ayuda a Domicilio es una garantía para la Comisión Tutelar de que se le están prestando los apoyos que necesita Dª Manuela y una forma más de supervisar objetivamente el estado en que esta se encuentra. Por lo que dice Toni, entiendo que la Trabajadora Social no va a tramitar esa petición y nos remitirá toda la documentación a la Comisión. Si no fuera así, habría que hablar con Dependencia para que no hicieran el cambio. ////////////////////////////////////////////////////////////////// Ana: Tras revisar los requisitos para percibir la Prestación por Cuidados en el Entorno Familiar, entiendo que este cambio que José Manuel, nieto de Manuela, quiere hacer, no es posible. No obstante, **llamo a Clara Gómez Nestares, Jefa de Secc. Calidad Dependencia (924 00 92 69) me corrobora que no se puede hacer el cambio habiendo tenido previamente la Prestación de Ayuda a Domicilio por la Ley de Dependencia y que además las distintas prestaciones y servicios se ofrecen a criterio técnico, no a petición del familiar. Así mismo, como Manuela está tutelada por la CTAEX, esto no se aceptaría de ninguna de las maneras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2020-04-28','Ana: Correo de Toni-Futuex: "A primera hora se contacta con el centro de salud (927 16 06 63) para solicitar hablar con la doctora de Felipe y consultar la situación del tutelado, tal y como se indica en el informe de urgencias, que se haga seguimiento por médico de cabecera. Recogen los datos y comentan que llamarán. A continuación, se habla con Felipe, comenta que ha pasado mejor noche y se encuentra mucho mejor, está para tomarse la medicación y con el desayuno. Acude al banco a hacer la retirada de la asignación y establece que bien, ha ido sin problema y no se ha cansado mucho, por lo que va mejor. A última hora de la mañana contacta la doctora, revisa el informe durante la conversación e indica que no se le repitió la prueba de COVID-19 en el hospital, pero sí se le hizo una revisión a fondo, además en la radiografía se podía apreciar si había algún problema en los pulmones relacionado con el coronavirus. La Dra. establece que se siga con el tratamiento indicado, se le siga de cerca, comprobando temperatura y la capacidad respiratoria; si hay cambio que se contacte rápido, sino en una semana se vuelve a contactar para ver evolución"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-04-29','TERESA:NUEVO NUMERO 632 03 80 94, RAMON NO SE HA PUESTO EL INYECTABLE, ESTA FUTUEX EN CONTACO CON SUS HERMANO PARA QUE SE LO PONGAN PERO NO LO HAN CONSEGUIDO, VOY A INTENTAR PONERME EN CONTACTO CON EL A VER SI LO CONSIGO QUE VAYA A PONERSELO ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada Ramón: No coge el telefóno. Dejo mensaje para que me llame. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada a Toni, de Futuex. Hablamos de la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-04-29','Ana: Recibo llamada de Damián (622 834 876), expresa que ayer se le olvidó comentarme que necesita ir al dentista, tiene caries y alguna otra afección bucal. *Le indico que envíe por mail al ctutelar@ el presupuesto y en el asunto especifique Área Económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-04-29','TERESA: EMAIL DEL CENTRO Os informamos que Paula está mejor esta semana pero me comentan que está realizando llamadas que pueden causarle problemas. Ayer contactó con un bufete de abogados, no sabemos lo que les preguntó, pero más tarde le enviaron el contacto de un abogado de Castuera para que se pusiese en contacto con él. Por la tarde le llamaron para preguntarle lo que quería y les contestó que ya no les necesitaba. Estamos preocupados por las consecuencias que pueden tener llamadas de este tipo y que pueda contratar algún servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2020-04-28','(Pedro)Llamo a Casimiro, T. Socila del C. Salud de Cabeza del Buey (924-601186). NO se encuentra en el centro. Dejo mensaje a recepciónista (87626).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2020-04-29','(Pedro)Llamo de nuevo a Casimiro, T. Social del C. Salud de Cabeza del Buey (924-601186). Le pasan la llamada pero no contesta. La comapñera me da su extensión(87626). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Recibo llamada de Casimiro. +++Él envió un escrito al CAIS de Navalvillar de Pela el pasado mes de 31 enero/febrero, incluyendo la sentencia de incapacitación, pero le dijeron que allí tenían una advertencia de estar "tutelado" y que sein la firma del "tutor" no podían cambiar la domiciliación de la pensión. +++Le pido que me mande el docuemnto que envió. +++CONTACTO en el CAIS: DIONISIO GARCIA (Director) o Felipe. +++++Teléfono CAIS: 924-860662 +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Veo que la sentencia está incompleta. Antes de llamar al CAIS solicitamos al Juzgado testimonio de la sentencia completa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-04-29','Ana: Recibo llamada de Ana Marta, TS del HVP - Plas. (927 428 302): A pesar de lo comunicaco ayer, hoy me dice que como Nemesia dio positivo en la prueba de Covid-19 la última vez que se la hicieron, no puede volver a los PP.TT. Pero que como está para darle el alta, va a hablar con la Médica del SES que está atendiendo la Res. Privada Ciudada Jardín de Plas. y gestiona los ingresos en la misma y que si dice que sí nos avisará para que se gestione la plaza. **Le digo que esa no es la directriz que se ha marcado desde las Gerencias del SES y SEPAD. Y que desde la CTAEX habría que autorizar ese ingreso. *Llamará de todas formas a Guadalupe y yo hablaré con Pedro, Jefe de Secc. CTAEX. /// Recibo nueva llamada de Ana Marta (927 428 302), ha hablado ya con la Guadalupe, que además está en la Comisión Covid del SES, y han determinado que Nemesia se tiene que quedar en el hptal sí o sí hasta que dé negativo en las pruebas de Covid y pueda regresar a los pisos. El hptal. no está saturado y tiene habitaciones libres, por lo que permanecerá en el mismo mientras se pueda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-04-29','TERESA: HABLO CON ENFERMERA DEL A UHB SOBRE BEATRIZ, ME COMENTA QUE LA LLEVA LA DOCTORA REYES Y QUE ESTA DE SALIENE CON LO CUAL HASTA EL LUNES NO PUEDO HABLAR CON ELLA.+ LE COMENTO EL CASO Y ME DICE QUE ESTA AL TANTO DE LA SITUAICON YA QUE ES UNA PACIENTE CONOCIDA. QUE SE LE HA OFRECICO LA OPICON DE INGRESAR PERO QUE FIANLMENTE NO HA INGRESADO Y QUE AHORA POR LA SITUACION DEL COVID NO ES MUY RECOMENDABLE INGRESAR.SE LO VA A COMENTAR A LA DOCTORA PARA QUE VALORE LA SITUACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-04-29','(Pedro) Tras consulta de Miguel con el Juzgado, remite el siguinete correo-e: +++Hola Pedro, por si ves este email antes de hablar con Abogacía, comentarte que desde el Jzdo nº1 de Castuera me comentan que la abogacía recurrió también la sentencia de Pablo y sobre el 9 o 10 de Marzo desistieron por lo que no hay resolución definitiva (testimonio firme) desde el Juzgado. Intentaran enviarlo seguramente semana próximo o siguiente a través de Lexnet.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-04-29','Ana: Recibo llamada de Emi (633 501 059), en esta ocasión dice que la asignación semanal es escasa, que en el CRR de Cáceres le daban más dinero, que cree que quienes se la bajaron fueron Gisela del CRR de Mérida y Pedro Gracia. Que necesita más al mes, pues fuma y no le sobra casi nada y quiere que le sobre para comprar despues otras cosas, como por ejemplo un bolso. *Le indico que tanto su asignación como el extra anual, lo acordaron en una reunión Paula-CRR y Alberto, Jefe Secc. Ecca. Que si realmente necesita más dinero que lo hable con Paula y si ella lo cree necesario que envío un correo a la Secc. Ecca. comunicándolo para que se pueda valorar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-04-29','(Pedro)Conversación con Betariz (643-600503).Temas tratados. +++ Con el confinamiento se ha entido más deprimida. Le han cambiado el tratamiento y ahora duernme mejor. +++La llaman desde el ESM y desde el C.Salud para ver cómo se encuentra, lo que le tranquiliza mucho. +++Mañana la tiene que llamar la Psiquiatra para ver cómo lleva el tratamiento. +++Quiere CAMBIAR de PISO de ALQUILER, y mudarse al que hay cerca de donde vive ahora. La propietaria, Virginia, dice que vive en Málaga y quiere hacer el contrato por correo-e. +++++Le pregunto por qué quiere cambiarse de alquiler y responde lo siguiente:" Porque no estoy bien en el piso...me da miedo -me da la sensación de que es una excusa- Ahora está viviendo con su novio, Antonio (de unos 40 años). Él tiene otro piso en el mismo bloque. Yo lo que quiero es que si discutimos yo me pueda quedar en mi casa y él se vaya al otro piso, que es lo que hacemos ahora. Yo no quiero depender de nadie para no tener miedo -le recuerdo la experiencia negativa que tuvo con Manuel, su anterior pareja, y lo importante es que ella se preocupe de sí misma y no dependa de los demás-. Me dice que no, que Antonio es muy bueno aunque tiene un carácter fuerte y es un poco "despegao", no es cariñoso. Le regaló una perrita hace un año a la que tiene que llevar al veterinario . Tiene una hija diabética y un hijo quye trabaja en una obra. +++++Respecto del alquiler le comento que en estos moemntos no podemos plantear un cambio de alquiler, que ya hablaremos de ello cuando pase esta crisis. Insiste en hablar con Virginia para que le guarde el piso, a lo que le digo que le comente que de momento no va a poder ser. Y, por supuesto, le INSISTO en que NO FIRME NADA QUE NO HAYA REVISADO LA COMISIÓN TUTELAR. +++QUIERE SER TAROTISTA. Dice que aprendió desde pequeña y que ha colaborado con algunos "gabinetes" de tarot "...pero gratis...". Ya lo veremos cuando todo esto pase.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-04-29','Ana: Llamo al C.Salud de Guadalupe (927 15 43 05), me comunican que Clara, TS, está hoy en el C.S. de Logrosán. Aprovecho para preguntar por le número de Médicos que hay en el CS de Guadalupe, me informan que hay 2 y que para solicitar el cambio hay que hablar con el Dr. Adolfo Cabanillas. ························································································································ Llamo al C.S. de Logrosán (927 36 08 08), Clara, TS, debe estar ocupada. Toman nota de mi teléfono y le dirán que me llame cuando pueda.······· Clara me devuelve la llamada a última hora, se alarma ante la idea de que Juan pueda volver pronto al domicilio. Durante el Eº de Alarma ella acude sólo de forma presencial a Logrosán, al CS de Guadalupe no está yendo. Opina que Juan no cuenta con apoyos en el pueblo y que no es buena idea darle el alta. Desde Cruz Roja sólo le dan alimentos, como a otras personas en situación de necesidad económica. A Raquel, TS del SSB tampoco la puede ni ver. *La posibilidad de cambiarle de médico de atención primaria no la ve viable, dado que Juan siempre ha dicho que el Dr. Adolfo Cabanillas es un "médico nazi", desde hace muchos años lo tiene incluído en su delirio. Considera que sería mejor mantenerle con la Dra. Consolación, está convencida que entre las dos opciones Juan la preferiría a ella. *Clara acepta que el darle el alta o no es una decisión médica y pide que le informemos cuando esto ocurra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-04-30','(Pedro)Carmen Franco me comunica que José Manuel ha dao NEGATIVO en pcr. +++Pasa del pabellón Monesterio, donde permanecía aislado, a la UME. +++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Se envía Fax al Juzgado para mantener ingreso en CSS. ++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Llamada de Taciana. +++Plantea que, una vez el día 9 de mayo termine el confinamiento, dará el alta a José Manuel. +++Le comento que ya he enviado la docuemntación al Juzgado incluyendo su Informe clínico. +++REspecto del alta, tal como le he dicho a Carmen por correo electrónico, es esperable que del juzhado contesten pronto y propongo mantener ingreso hasta entonces.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-04-30','(Pedro) Correo del CRR de Mérida (29-04-2020). +++Ángel Pinilla: Estos últimos días le hemos notado cambios de humor repentinos. Sin embargo, cuando se habla con él y se le expone lo que observamos él lo agradece y se reconduce. Está pasando bastante tiempo en su habitación, acostado. Hemos llegado a ciertos acuerdos con él pero refiere que le cuesta mucho levantarse por dolores de espalda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-04-30','(Pedro) Correo del CRR de Mérida (29-04-2020): +++María Dolores Fernández: Muy bien, empieza a demandar algunas cosas (un móvil mejor con internet, se ha acordado de las sillas que compró antes de la pandemia...) Hemos conseguido que entienda que actualmente están la mayoría de los servicios paralizados y cuando todo se pase nos ponemos en marcha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-04-30','(Pedro) Correo del CRR de Mérida (29-04-2020): +++José María Guillén: Sigue contactando frecuentemente con su familia vía telefónica. Lleva una temporada más accesible, no tan demandante de atención como las primeras semanas del confinamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-04-30','(Pedro) Correo-e del CRR de Mérida (29-04-2020): +++Luisa Rodríguez: En la misma línea que en comunicaciones anteriores, gran parte del día en el habitación pero con buen comportamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-04-30','(Pedro) Correo-e del CRR de Mérida (29-04-2020): +++Antonio Merchán: Muy bien, por espacios comunes con compañeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-04-30','TERESA: HABLO CON LA EDUCADORA LOS SERVICIOS SOCIALES, CONOCE EL CASO PERO NO ME DA MAS INFORION QUE UN TELEFONO PARA QUE HABLE CON SU HERMANA. ME FACILITA EMAIL DE LA TRABAJADORA SOCIAL, ANA, PARA QUE LE SOLICITIE EL INFORME SOCIAL. MANDO EMAIL EXPLIACANDO EL TEMA DEL TRASLADO DEL EXPEDIENTE A LA TS Y ENVIO OFICIO SOLICITANDO EMPADRONAMIENTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-04-30','Ana: Recibo llamada de Clara, TS CS Guadalupe (Despacho Logrosán: 927 360 769), dice que ha hablado tanto con la Dra. Consolación como con el Dr. Adolfo y ninguno de los dos ve posible el cambio de médico, pues Juan tiene fijación con el Dr. Adolfo. *Clara me solicita el tlf. del Dr. Pizarro, pues la Dra. Consolación quiere hablar con él. ···························································· Recibo llamada de Raquel, TS SSB de Guadalupe (605 429 865), preguna por Juan. No entiende que vaya a darle próximamente el alta. Considera que en estas circunstancias de Crisis Sanitaria Juanno va a respetar las medidas que se dicten, ni se va a proteger él ni a los demás. *Antes del ingreso de Juan en el CSS, fueron ella y Teresa de Futuex a visitar la vivienda y no reune condiciones mínimas de higiene y habitabildiad, está en situación de abandono total. Lleva 30 años trabajando con este caso y conoce perfectamente a Juan, lo listo que es y su capacidad para manipular. **Los alimentos de Cruz Roja no siempre los acepta, la última vez los rechazó y fue diciendo por el pueblo que dan comida caducada. *Él no guisa y la cocina esá sucísima... *La posibilidad de otros apoyos, por lo general también los rechaza, pero aunque aceptara SAD, nadie el pueblo quiere entrar en su casa por miedo y no puede obligar a ninguna auxiliar a hacerlo. *Por otra parte presente Ludopatía, se gasta gran parte de las asignación en las máquinas. *A los profesionales les amenza, y sabe cómo hacerlo. **Al Jdo. acude limpio, bien aseado y bien vestido y con muy buen discurso. **EL ÚLTIMO PROCEDIMIENTO JUDICIAL DE MODIFICACIÓN DE SUS CAPACIDAD LEGAL LO INICIÓ ÉL con la ayuda de Raquel, del SSB para cumplimentar el modelo. ··························································· *Llamada a Juan Chamorro, comienza la conversación bastante tranquilo, pero a medida que avanza va elevando el volumen y el tono y mostrando cada vez más enfado. Cuando le pregunto cómo está, de entrada dice que sigue mal, "bajo el techo de la gente que me roba", "ahi en la Junta tienes muchos ladrones, hasta los que están al servicio de la Junta en Guadalupe están metidos en el reparto de los permisos". La mayor parte del timpo no hace falta casi ni asentir para siga su discurso, es casi un monólogo: "Han asesinado a mi tía y a mi madre", "Mi propia familia robándome", "Espero que tú no estés también encubriendo los robos". Al pedirle que no piense eso continúa: "Lo que quiero es mi tutela, no quier depender de vosotros", "El fiscal y la jueza lo saben todo", "lo que tienen que averiguar es lo del dinero", "estoy muy harto de todo esto", "se me utiliza como una cobaya, ¿no ves la televisión todos los días?", "el que está jodidio soy yo, que no tengo intimidad". "Me han quitado un inyectable y me han puesto otro que es un tratamiento experimental para esquizofrénicos y yo no tengo esquizofrenia, a ver quién se ha inventado eso, lo que yo tengo son secuelas de las inyecciones nazis que me pusieron". Al decirle que el Dr. Pizarro me dijo que el nuevo inyectable le estaba yendo bien, dice que eso es sólo porque lleva 2, que cuando lleve 4 ó 5 ya no podrá ni caminar. *Añade que el Dr. Pizarro ya ha pedido el cambio para que le hagan el seguimiento en ESM de Cáceres, porque al Dr. Medida no lo quiere ni ver, "intentó matarme" y relata los efectos secundarios de la inyección que le ponían, diciendo que tanto el Dr. Medina, como el Dr. Adolfo Cabanillas y la Dra. Consolación y la enfermera que había antes en el C.S. de Guadalupe, son todos unos nazis. "Tenéis que hacer algo ya, que vosotros sois quienes tenéis que velar por mis intereses", "te estoy haciendo sabedora y no haces nada, dile a mi tutor que se ponga en contacto contacto conmigo y con el Jdo de Logroán para que me devuelvan mi tutela"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-04-30','TERESA: A FECHA DE HOY RAMOS SIGUE SIN PONERSE EL INYECTABLE, LO LLAMAMOS Y EL TELEFONO ESTA APAGADO....ME QUEDO A LA ESPERA DE QUE NOS INFORME FUTUEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-04-29','TERESA: CORREO DE M CIELO DEL CRPS Esta tarde me ha llamado tres veces ella y una su hermana: quiere comentarte varias cosas: lo del tarot, que quiere cambiarse de piso y que quiere solicitar la reincapacitacion. Yo he intentado retenerla lo maximo posible, pero me resulta complicado. Esta muy verborreica y muy centrada en quien la incapacitacion; ha llamado a la hermana comentando que no deja de llamarla de madrugada y a cualquier hora para pedirle explicaciones sobre por qué la incapacitaron, tiene sospecha de que no se esta tomando bien la medicación. A ver que te cuenta mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-04-29','TERESA: EMAIL TONI FUTUEX se está llamando a Ramón, a su nuevo número que es el 632 03 80 94, durante toda la mañana sin obtener respuesta porque lo tiene apagado. -Se ha llamado a su hermana Amalia, que estuvo en Jerez el día de ayer y habló con Ramón para explicarle la importancia de ponerse el inyectable. Pero él le decía que no se lo quería pone sin darle muchas más explicaciones. - Se ha hablado con Ángela, otra de sus hermanas que además es vecina para preguntarle si había hablado con Ramón. Ella cuenta que estuvo anoche en su casa y le vio algo alterado, Ángela le recordó que tenía que ponerse el inyectable por su bien pero escuchó cómo su madre María apoyaba a su hijo y le decía que no necesitaba la inyección para nada. - Se ha estado llamando a su hermano Luis para que hablara con Ramón ya que se llevan muy bien y podría intentar hacerle cambiar de idea. Pero no ha cogido el teléfono. - Se ha llamado al centro de salud para hablar con Míriam y comentarle que cuándo Ramón fuera a la farmacia, no le iban a dejar recoger el inyectable porque ya no le saldría en la tarjeta sanitaria. Míriam cuenta que va a hablar con uno de los médicos del centro de salud para que le hagan una receta en papel del Trevicta y así cuando vaya Ramón al centro de salud, pueda recoger la receta, vaya a la farmacia, recoja el inyectable, lo paque y se lo ponga. Esta solucionado para que solo tenga que ir a recogerlo y al centro de salud a ponerselo... pero esta "montando el numero" y la verdad no sabemso porque, ya que estaba en una linea muy buena..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2020-04-30','Ana: envío copia de la poliza del seguro de decesos a Jesús, director de la Res. de El Torno (jesusi6@hotmail.com), y Estrella, TS de la Mancomunidad (ssbestrella@mancomunidadvalledeljerte.es). Coral, CTAEX, cree recordar que nos la habían solicitado en su día. En cualquier caso no está demás que la tengan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-04-30','TERESA: EMAI DE TONI FUTUEX Buenas tardes Teresa, PUES JUSTITO AHORA MISMO ME INFOMA LA COMPI, QUE HA IDO AL CENTRO DE SALUD.. Y SE LO HA PUESTO POR FIN! te detallo la secuencia de hoy: - Se ha estado llamando a Ramón durante toda la mañana sin respuesta. - Se ha hablado con su hermana Ángela que ha comentado que su hermano Luis no podía acercarse a la farmacia recoger el inyectable, y ella tampoco porque estaba convaleciente de una operación. Por lo que la opción de que se la pusieran en su casa, se veía muy poco probable -Se ha llamado a Amalia, otra de sus hermanas y ha contado que estuvo hablando con Ramón anoche y le dijo que era bueno para él que se lo pusiera, y él le dijo que hoy se lo iba a poner. -Sobre las 13:00h se ha recibido un mensaje de Míriam, la enfermera de salud mental, diciendo que Ramón había estado en el centro de salud llevando el inyectable para ponérselo. Estaba tranquilo y algo bromista, incluso. Cuando Míriam le ha preguntado que por qué ha tardado tanto en ir, Ramón ha contestado que no sabía en el día que vivía. Por lo que ha procedido a ponérselo sin ningún tipo de problema. El siguiente le tocaría el 9 de Julio a las 10:30h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-06-16','TERESA HALBO CON LA TS DE ZALAMEA (646 49 36 08) ME COMENTA QUE MAÑANA TIENE LA VISITA CON FUTUEX A LOS HERMANOS CON RESPECTO A PABLO COMENTA QUE NO VA PODER ENTRAR EN LA RESIDENCIA DE MAYORES DE LA LOCALIDAD DEBIDO A LOS PROBLEMAS DE CONDUCTA Y DE AGRESIVIDAD QUE PRESENTA, NECEISTA UN RECURSO MAS ESPECIFICO A SU PERFIL PABLO TIENE UN 65% DE DISCACIDAD Y PROBLEMAS DE CONDUCTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2020-04-30','(Pedro)llamada de Julia Mohedano, Geriatra de la Residencia "El Cuartillo" (22165). +++Carmelo ha pasado dos pruebas IGG e IGM, ambas NEGATIVAS para covid-19. +++EStá asintomático.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2020-04-30','(Pedro)llamada de Julia Mohedano, Geriatra de la Residencia "El Cuartillo" (22165). +++María Concepción ha pasado dos pruebas IGG e IGM, ambas POSITIVAS para covid-19. +++Está asintomática y en aislamiento en la propia residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2020-04-30','Ana: Solicito a Domingo, Director del CADEX (927 00 53 09 // cadex.caceres@salud-juntaex.es) cdo. de Discapacidad o escrito en que informe que no ha sido valorada por el CADEX. *NO ha sido valorada. Me envía documento, guardo en su expte. y se lo remito a Ángel, Asesor Jurídico. // Solicito a Clara I. Gómez Nestares por mail (clara.gomez@salud-juntaex.es) Cdo. de Dependencia. **Me lo enviará el lunes firmado electrónicamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2020-05-01','Servicio de Orientación Jurídica del Ilustre Colegio de Abogados de Cáceres (927-620357). +++Expediente: 2020/01321','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2020-05-04','Ana: Llamo a Rosa, Admvo. del CSS-Plas. Le solicito Certificado de Ingreso de Tomás, en el que indiquen además la cuota mensual que abona (75% de su pensión). ·················································· Envío un mail a Mariví Clemente (victoria.clemente@salud-juntaex.es) solicitando Informe Social actualizado que solicita Ángel, Asesor Jurídico - CTAEX, para remitir al Colegio de Abogados (procedimiento de División de Herencia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2020-05-04','(Pedro)Converscaión con Clemen, Directora del CAMP "Nuestra Señora de las Cruces". +++Quieren PEDIR UNA SEGUNDA OPINIÓN para valorar de nuevo la intervención de Soledad. +++En estos momentos, su calidad de vida está permanentemente condicionada por la sonda nasogástrica que tiene y que se trata de quitar constantemente, lo que obliga a mantener sujección mecánica para evitarlo, situación que se considera inasumible desde el punto de la calidad de vida de la persona. +++Se le explica que tendrían que emitir un Informe de la situación desde el CAMP, que unido a la valoración médica permitiera a la Comisión tomar una decisión al respecto (dado el riesgo vital existente en situaciones anteriores) que pondría en conocimiento del Juzgado para ratificación o no de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-05-04','TERESA:recibo diligencia de ordenación del Juzgado de Instrucción nº 2 de los de Castuera, sobre incapacitación de D. Guillermo GALÁN GILGADO. La archivo en su expediente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-05-04','Ana: Recibo llamada de Maica (Mª Carmen), TS de Torrecilla de los Ángeles (652 481 740 = *Nº personal, usar sólo durante confinamiento y situaciones excepcionales): Comunica que está de baja por I.T. (Incapacidad Temporal) por fractura osea. Cree que podrá reincorporarse a su puesto en 1 mes y 1/2 apróx. No le han sustituido. Le han comunicado del Ayto. que se le ha solicitado informe para la rendición anual de Alfonso y propone que esperemos a que ella se incorpore si no es urgente, pues las compañeras de la mancomunidad que asumen sus funciones no conocen el caso. Supongo que no hay problema en esperar (y más dada la situación de crisis sanitaria y confinamiento). Le preguntaré a la compañera y si no le llamo para decir lo contrario es que esperaremos a que ella se incorpore. ·········································· Coral, CTAEX, me cofirma que podemos esperar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-05-04','Ana: Llamo a Mariví, TS de Torrejoncillo (927 30 33 66). Intentará enviarnos a lo largo de esta semana el informe social pendinte para el inventario. Le informo sobre la estructura y funcionamiento de la CTAEX, pues dice que es la primera vez que tiene algún usuario con tutela (curatela en este caso) de adultos. En relación a José Manuel, informa de que no cuenta con apoyos familiares ni de amistades en el pueblo. Su hermana Juliana, anterior curadora, vive en Cataluña y sí que se intersa por él y llama con cierta frecuencia. Aunque tuvieron desavenencia y además ella estuvo enferma de cáncer. Tienen otro hermano con el que ninguno de los dos tienen relación. Hubo conflictos con la herencia. A Mariví le preocupa las compañias con las que a veces se relaciona José Manuel, pues además éste es muy influenciable. José Manuel tiene temporadas con más autonomía que otras. Estuvo trabajando en el Ayto. Tras finalizar a posteriori la prestación por desempleo, ella le tramitó Renta Básica. Hasta que ingresó el año pasado en el CSS-Plas. Tras este ingreso hubo algún error en el SEPE con la última prestación que solicitó y han tenido que reclamar. Ya está solucionado y le han ingresado los atrasos. Actualmente tiene aprobada la prestación para mayores de 50 años = 430 €. Por otra parte está *pendiente de pasar por tribunal médico para la Incapacidad. *Está valorado por la Ley de Dependencia y tiene prestación de SAD 1h/día. La auxiliar se llama Pilar, la contrata una empresa del pueblo, en el que también reside y actualmente es su principal apoyo y fuente de información para la TS. **Él quiere ir a recurso residencial, está en lista de espera para CRR. *Cuando fue a la entrevista para piso supervisado le dijeron que no estaba "apto" para dicho recurso. *Tiene seguimiento por el ESM de Coria. La TS que suele atenderle es Marisa Olivera, aunque ésta pertenece realmente al CEDEX. No recuerda el nombre del Psiquiatra. *La TS del C.Salud de Torrejoncillo, que también suele intervenir, es Guadalupe. *En este caso ha colaborado incluso el cura del pueblo, que se implica bastante en cuestiones sociales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-04','(Pedro) Llamada de Consolación, Médico del C.Salud de de Guadalupe. +++Sobre la situación de D. Juan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-05','Ana: Correo de Estrella, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Como ya sabrás, en el transcurso de esta semana se irá de alta a su domicilio Juan Chamorro, previamente su Psiquiatra lo ha puesto en conocimiento del Equipo de Salud Mental de Cáceres y de su médico de cabecera, con objeto de que su estancia en su domicilio sea duradera. Saludos." ····································· Intento contactar con Estrella para que me confirmen el día del alta, pero no consigo que respondan al teléfono. ························································· Más tarde recibo llamada del Dr. Daniel Pizarro, Psiquiatra del CSS. Informa de que "Juan sigue igual", su idea es darle el alta el viernes, pero si puede lo retrasará hasta el lunes-marte de la semana que viene. El hecho de precipitar el proceso obedece también a una necesidad del centro, pues tienen las unidades llenas y necesitan camas. Ya ha hablado con el ESM-CC, tiene cita programa el día 15 con el Dr. Juan Pedro Jiménez Cano. *"Lo importante es que Juan se ponga el inyectable y no genere problemas en el pueblo". "Ya lleva 3 meses ingresado aquí y no se le puede tener mucho más, está muy cansado", aunque entiende la falta de soporte en el pueblo. Lo ideal sería un Programa de Apoyo Comunitario que en Extremadura no existe. *Es consciente de que tarde o temprano Juan volverá a ingresar en el CSS. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro). Varias conversaciones telefónicas con Ana, Consolación y por último con el Dr. Adolfo Cabanillas, Coordinador del C.Salud de Guadalupe. +++A este último le informo de la previsión de Alta Clínica para D. Juan para finales de esta semana o lunes o martes de la que viene. +++Plantea muchas dudas de que D.Juan respete las medidas de confinamiento actuales y ya han informado al Alcalde de su próxima vuelta al pueblo, teniendo claro que ante cualquier incumplimiento se dará parte a la Guardia Civil. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Llamada del Dr. Daniel Pizarro, Psiquiatra del CSS de Plasencia. +++"Juan no va a mejorar. Su futuro pasa porque con la edad termine requiriendo el ingreso permanente en el CSS o bien, si en algún momento se establecen los mecanismos para poner en funcionamiento un Programa de Apoyo Comunitario, que se pueda mantener en domcilio con dichos apoyos". +++Los tres meses de ingreso que lleva no solo no ha dado problema alguno, sino que incluso a mediado entre algunos compañeros en determinadas circunstancias. +++Le pido a Daniel que, por favor, le hagan tomar consciencia, en la medida de lo psoible, de la situación de confinamiento en la que se va a ver , y en la que no ha estado todavía ya que su ingreso se produjo antes del Estado de Alarma. Que sea consciente de que su quebrantamiento le puede suponer un conflicto con la Guardia Civil, la posibilidad de multa y, según las circusntancias, de medidas más severas. +++++Daniel me comenta que ya han estado trabajando en ello y que D. Juan reconoce y asegura que va a comportarse correctamente, que solamente va a barir la puerta a la Cruz Roja para la recogida de alimentos y que va a ir el día 15 al ESM el próximo día 15 de mayo con el Dr. Juan Pedro Jiménez. +++++Le van a dar guantes y mascarillas para que las utilice une vez esté en el pueblo y le van a explicar cuando y cómo utilizarlas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-05-05','(Pedro)Llamada de Ceferino. +++"Quiero volver al CRR de Badajoz, porque añoro a mis amigos, salir al Corte Inglés, María y...me entienden mejor que Paula. Aquí cada dos por tres está la Policía...Y además mi novia se va a ir al CRR de Badajoz y yo me voy a morir de pena aquí..." ······························································································· Ana: Recibo llamada de Ceferino (642 412 904), dice que ya ha hablado hoy con Pedro - CTAEX, pero que quería hablarlo también conmigo. El contenido de la conversación es el mismo que el anotado por Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-05-05','TERESA:Os informo que esta mañana han llamado del SES a Libertad para hacerle la prueba del COVID-19 para que pueda regresar al Centro lo antes posible. Dada su situación sociofamiliar será la primera usuaria que se encuentra en su domicilio y que va a regresar al centro. seguimos en contacto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-05-05','TERESA: EMAIL CRPS ZAFRA Esta mañana mi compañera ha estado hablando con Beatriz, estaba mal, ha tenido un conflicto con su pareja y estaba muy descontrolada. Pero esta tarde me ha llamado a mi, estaba muy alterada, diciendo que su pareja la maltrata que va a denunciarle que va a llamar a la guardia civil y va a denunciarle a él y a su madre. Yo he intentado calmarla y llegar con ella a algunos acuerdos, como que no va a ir a su casa a molestarlo o no va abrirle la puerta si el va a verla; que haga algo que le guste y le tranquilice y comenta que va a ducharse y a ver la televisión. Mañana por la mañana la llamará la psicóloga e intentaremos contactar con a psiquiatra para que hable con ella, pero ella no quiere ingresar; una parte por las condiciones del ingreso que no pueden salir de las habitaciones, otra parte porque piensa que ingresar es darle la razón a su pareja cuando la llama loca. También he hablado con su hermana, que también esta preocupada, le ha propuesto irse a Calera a casa de su abuela con ella, pero su hermana trabaja todo el día y no quiere estar sola allí. Yo creo que tarde o temprano la va a liar. Nosotros intentamos contener, pero la situación cada vez es peor y su salud también. No sabemos cuanto tiempo vamos a poder contener mas. Pensamos que necesita ingreso, pero ya la ha visto el 112 y no la han ingresado porque ella no quiere. Escribiéndote este email, me ha llamado la hermana y me ha dicho que ha hablado con ella y que quiere irse a Calera de León con ella, pero esta averiguando como hacer el traslado. Nosotros vamos a proponerle a la psiquiatra el ingreso. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2020-05-05','Ana: Correo de Felisa Custodio, TS CAMF-Alcuéscar (trabajador_social_alcuescar@imserso.es): "Estimada Ana, espero que estés bien de salud. Te comento, he hablado con la hermana de la residente Carmen Gómez, que ejercéis la curatela. La residente fue derivada a urgencias desde el CAMF. Me dice la hermana que ha llamado al Hospital Universitario de Cáceres y le han informado que Carmen está en coma inducido, refiere que está a la espera del resultado de Covid pero que su situación le han dicho que es crítica. Te dejo el contacto de la hermana por si te viene bien tenerlo: Rocío Gómez Muñoz: 626 87 72 76. 983 /40 39 16."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-05-06','miguel, aunque estamos pendientes de testimonio de aceptación del cargo, remito a Pedro borrador para su internamiento involuntario, para lo vaya viendo con Soraya e efectos de cuando tengamos la firmeza proceder a solicitar al Jzdo de Castuera su internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-06','teresa:email silvia PI Buenas tardes, he intentado ponerme en contacto está tarde pero no lo he conseguido, nose si disponéis de algún número de guardia o algo similar. Durante el día de hoy Paula se ha fugado del centro en varias ocasiones y hemos tenido que activar el 112. Finalmente se ha realizado traslado involuntario a la UHB. Como sabéis la situación es complicada y ahora sin una prueba PCR no lo podremos mantener en residencia. Estamos viendo cómo aislarla cuando vuelva y es complicado porque sola con una persona no puede estar. Soraya está al corriente de todo porque Silvia la ha llamado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-05-06','TERESA: EMAIL DEL CRPS M CIELO Beatriz se va esta tarde a Calera, con su hermana; ya hemos hablado con la psiquiatra y le ha dado un certificado para poder venir a por ella, además le ha propuesto el ingreso, y aunque ha dicho que no, la psiquiatra le ha dicho que si no mejora en Calera tiene que ingresar aunque no quiera. El lunes no fue a por el dinero al banco, porque tenía, pero ahora se va a Calera sin dinero; su hermana me plantea la posibilidad de ingresarle a ella el dinero en su cuenta para que Beatriz no tenga que ir a Monesterio a sacar dinero. Me ha pedido que te lo solicite. También me han llamado la dueña del piso de Beatriz; el lunes tiene que pasar la revisión la goma del gas, que le va a caducar, pero ella no esta; Beatriz les ha dicho que su pareja (que comenta que ya no lo es, pero que ahora son amigos) le va abrir la puerta para que hagan la revisión, ella esta convencida y le he dicho que haga lo que considere. Bueno esto es todo por ahora. Espero que estemos unos días tranquilos, eso significará que ella esta tranquila. SOLIOCITO A LOS COMPAÑEROS AUTORIZACION PARA SACAR EL DIERO LA HERMANA TRAS CONVERSAION TELEFONICA QUEDAMOS A LA ESPARA A VER COMO SE DESARROLLA EL FIN DE SEMANA, LA PSIQUIATRA VA A ESAR EN CONTACTO CON ELLA EN EL CASO DE QUE SIGA MAL INGRESARA, SE VA A CALERA A PESAR DE QUE LA PSIQUIATRA LE HA INDICADO QUE INGRESE PERO ELLA NO QUIERE Y COMENTA ESTAR MAS TRANQUILA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2020-05-06','Ana: Recibo llamada de Mariví Clemente, TS CSS-Plas., dice que en agosto de 2019 envió un informe social para la rendición anual y que desde entonces no ha variado nada la situación. Pregunta si vale ese, pues sino enviaría el mismo cambiando la fecha a la actual, pues no va a elaborar ninguno nuevo. ······························· Se lo comunico a Ángel, CTAEX, mediante email. *Lo necesitan con la fecha actual. ················ Llamo a Mariví, nos enviará el informe hoy mismo. ··········· Una vez recibido lo guardo en su expte. y se lo digo a Ángel, Asesor Jurídico CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-06','Ana: Correo de Susana Cortés, TS Casa Hptal. Santiago - Zafra (hospisantiago.ts@esclavasvirgendolorosa.es): "Hola Ana! Buenos días, espero que estés bien, parece que poco a poco vamos viendo la luz... aunque de manera lenta y con mucha cautela... Mira te comento, he estado hablando con la médica de Pilar para intentar retomar todos los trámites pero tengo que esperar mínimo una semana porque me comenta que debo de tramitarle la tarjeta sanitaria ya que lo que tiene Pilar es el papel que te dan cuando te asignan médico de manera temporal. Así que he llamado al centro de salud pero la oficina para hacer éste trámite de la tarjeta aún está cerrada al público, creen que para el 11 de mayo irán atendiendo a la gente en horarios muy restringidos. Así que a ver si voy consiguiendo sacar adelante el dichoso informe médico. Por otro lado estamos a punto de presentar ya la subvención para las plazas de Residencia de apoyo extenso (RAE) y aquí es donde tenemos que ver qué plaza ocupa Pilar, si se quedará o no aquí porque el ratio para asignar a profesionales nos varía un poco teniendo en cuenta a Pilar como usuaria habitual del centro, o bien si va a ceder desde el SEPAD y nos la asignan como plaza RAE por situación de emergencia social... no sé, voy a hablar con alguna técnica a ver qué me dice. Si tu por tu parte me puedes echar una mano para ver si Pilar entra con plaza te lo agradezco, sino nos afectaría negativamente porque tenemos que bajar la asignación de ratio de cuidadoras por contabilizar una usuaria más... en fin que debemos de formalizar la situación de Pilar en el centro, con plaza pública o no pero saber hasta qué punto nos afecta a la hora de solicitar la subvención, si sigue en pie lo de la reserva de plaza en el otro centro pues no la contabilizamos entonces como usuaria de este centro, bueno a ver cómo podemos ir gestionando esto... Bueno ya me comentas... sino me llamas si quieres y te lo explico porque es un poco lioso lo del ratio del MADEX. Gracias de nuevo, un saludo" ······························································· Mi respuesta: "Buenos días Susana, En mi opinión, lo ideal sería que Pilar accediera con plaza RAE por situación de emergencia social, pero no sé si es posible, dado que ahora mismo, al estar en vuestro centro, aunque haya sido acogida como favor, no sé si van a valorarla como emergencia social y aparte, supongo que por las situación en la que nos encontramos, no me han enviado aún el informe social que solicité a los SSAB de Zafra… Pongo en copia a Pedro, Jefe de sección CTAEX, para que esté al corriente, y por si él pudiera hablar con alguien de la unidad al respecto. Por cierto, ¿cómo sigue Pilar, tiene más asumida la situación? Espero que estéis bien. Un saludo y cuídate." ····························································· Respuesta de Susana: "Hola de nuevo Ana!! Pues Pilar lo lleva un poco mejor, si es verdad que la pobre tiene muchas ganas de salir a la calle pero no está agobiada ni desanimada, además hace poco le cortaron el pelo y está muy contenta porque se ve muy guapa, también le viene muy bien hablar con Susana, la delegada de apoyo de Futuex, hacemos una videollamada a la semana y la verdad que se alegra mucho. Respecto a lo de la plaza RAE le he mandado un mail a Soraya, la jefa de sección y también a una técnica que gestiona este tema, bueno le he expuesto la situación para que valoren y me digan, a ver si tenemos suerte y la tenemos como plaza de RAE, sino pues ya vemos como la formalizamos aquí o si finalmente va a Plasencia... Muchas gracias por tu apoyo, un abrazo y cuídate!!" ··························································································································· Llamo a Chelo (Consuelo Lavado), Jefa de los SSAB de Zafra (924554501, ext. 5). Cree que unos de los 2 informes que pedimos ya lo hicieron, consultará si se registró y envió ya. Mañana me confirmarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-05-05','(Pedro)Llamada de Mª Dolores. +++Ahora quiere marcharse al CRR de PLASENCIA, porque le hen dicho que "...allí se come mejor..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-06','TERESAE SE ENVIA AL CENTRO P.I. CABEZA DEL BUEY CONSENTIMIENTO INFORMADO PARA SOLICITAR CAMBIO DE PERFIL AL CADEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-06','Ana: Llamo a Clara, TS CS Guadalupe (Despacho Logrosán: 927 360 769): En cuanto al alta de Juan, me indica que según le han dicho los doctores Adolfo y Consolación - C.S. Guadalupe, al volver Juan a su domicilio procedente de otro área de salud, por protocolo deberá estar en aislamiento durante una semana. Si debe ir al médico el día 15, no transcurrirá la misma. Puesto que es una cuestión sanitaria, deberían hablarlo ellos con el CSS. **Pedro, CTAEX, habló justo lo mismo con Clara. **En cuanto a la provisión de alientos de Juan, si debe estar aisalado, se valorará la posibilidad de cáterin. ·································· *Pregunto a los compañeros de la secc. ecca. mediante mail. ··················································· Llamo a Raquel, TS del SSB (605 429 865): le comunico el próximo alta de Juan. *Expresa que "si a Juan le dan es alta médica de un servicio especializado habrá que tratarlo como a cualquier otro usuario, sin ningún trato especial, pues además tienen una curatela, no una tutela". Lwe pregunto por algún caterin en el pueblo o alrededores, pues si tiene que estar aisaldo sería una buena alternativa. Me facilita los siguientes contactos: Caterin Avellaneda - Castañar de Ibor (Carlos: 649 71 28 51 // Pilar: 660 33 11 42). Hablo con Pilar. Sirven la comida envasada al vacío una vez a la semana, en pac aptos para microondas. A Guadalupe sirven los viernes, y esta semana excepcionalmente lo harán el jueves. *Sería un problema si a Juan le dan el alta en la fecha indicada. Pasaría varios días sin este servicio. *Para que nos envíen presupuesto tendría que llamar de nuevo mañana, les he pillado fuera y no pueden anotar ahora. ······································ El centro de día de Guadalupe también tiene servicio de comidas a domicilio. Mª Carmen es la Directora (667 891 640). Llamo, Mª Carmen me dice que tiene que consultarlo, en principio sólo están llevando comidas a sus usuarios del centro de día, pero a han hecho alguna excepción con otro caso. **Eso sí, en ese caso la comida la llevaba Protección Cívil, ellos por protección no hacían el reparto, ya que no han tenido ningún caso en al residencia y quieren seguir así. *Me llamará mañana para confirmar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-05-06','TERESA:Me pongo en contacto para comunicar que ya le han facilitado a Libertad el resultado la prueba del COVID-19 y consideramos necesario el regreso de la usuaria al centro lo antes posible. Según protocolo a pesar de resultado negativo la usuaria tiene que hacer aislamiento durante unos días, de lo cual ya está informada Libertad. No nos parece conveniente que regrese en un medio de transporte público por el riesgo de contagio y su hermano, que en otras ocasiones la ha traído, en estos momentos no dispone de coche. Se ofrece la posibilidad de que se venga desde Badajoz a Llerena mañana con un trabajador de nuestra Entidad que va a hacer una recogida al Banco de Alimentos. En primer lugar os informo para contar con vuestra aprobación con respecto al regreso inmediato de Libertad y para que en caso afirmativo autorizáseis el viaje de la forma expuesta anteriormente. Entiendo que la autorizacion la estoy planteando con muy poco tiempo con lo cual si os parece oportuno sería suficiente contestando a este email. Espero vuestra respuesta lo antes posible para poder continuar con la planificación del regreso AUTORIZO TRASLADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-06','Ana: Llamo a Chelo (Consuelo Lavado), Jefa de los SSAB de Zafra (924554501, ext. 5). Cree que unos de los 2 informes que pedimos ya lo hicieron, consultará si se registró y envió ya. Mañana me confirmarán.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-05-06','Ana: Correo de Toni-Futuex: "Buenas de nuevo!te mando nota redactada de Desideria Bueno Barbero, que han estado las compañeras recopilando información del sociosanitario y a través de Angel, están de alta desde ayer,.. parece que compensados y tranquilos (lo de la urgencia de la ropa para que no fue tal pq solo compraron para Angel, finalmente.. Un.saludo y feliz tarde" En el informe de seguimiento que adjuntan, indican: "Para poder llevarles un control durante todo el tiempo en el que continúe cerrada la unidad de hospitalización parcial de la cual son usuarios, acuerdan con el Equipo de Salud Mental del Centro de Especialidades Luis de Toro de Plasencia llevarles un control semanal a ambos, todos los martes a las 12h. Se les realizará el seguimiento y analíticas para el control de la medicación. En el momento en el que vuelva a haber alguna descompensación importante, se procedería de nuevo al ingreso en el CSS. Rosa Fernández expresa que es Ángel el que sufre peores descompensaciones retroalimentando los delirios de Desideria. Desideria parece descompensada pero al tratarla de forma individual se muestra bastante estable." Han empezado a limpiar (con la chica que les hace la limpieza) la vivienda que han comprado, el viernes harán la mudanza con una furgoneta que han alquilado. Su idea es trasladarse a la misma antes del 11 de mayo, que les vence la mensualidad del alquiler, para no tener que pagar otra. Quieren hacer reformas en el baño, pero debido a las deudas que tienen (no saben en qué empresas) no les conceden créditos. "Principalmente todas sus preocupaciones giran alrededor de la nueva vivienda, de los gastos que supone tenerlo todo disponible".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2020-05-06','Correo de Toni-Futuex: "06/05/2020: Concepción Canelada García: Se recibe llamada de Paloma TS del Centro residencial “El cuartillo "Cáceres informando que Concha ha dado positivo por COVID19 y está en aislamiento. A pesar de haber dado positivo no presenta síntomas, según se comunica desde el centro, la familia de origen de la tutelada también está informada a través de su hijo, que ha mantenido el contacto por videollamada con su madre durante la crisis sanitaria."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-05-06','Correo de Toni-Futuex: 05/05/2020 Situación actualizada Nemesia García Panigua: Se contacta con los PPTT de Guijo para ver cómo ha ido la vuelta de Nemesia a las instalaciones, se habla con Ángel, auxiliar, comenta que Nemesia, finalmente, no le dieron el alta ya que la PCR de finales de mes dio positiva, por lo que tuvieron que mantenerla ingresada. Los médicos le han dicho, hoy, que este jueves, 7 de mayo, le harán una nueva prueba a la espera de que el resultado ya sea negativo y se pueda proceder al alta. También comenta que han recibido una notificación del juzgado donde se indica que se debe presentar una relación de la contabilidad de la tutelada, los gastos que ha tenido durante el año y demás, la enviará, por e-mail, segun dicen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-05-07','Ana: Solicito mediante mail a Mariví y Estrella, TS CSS-Plas., que cuando puedan, una de las dos me remitan el informe de alta de Desi. ········································ Solicito a Toni,Futuex, que cuando puedan me faciliten la dirección de la nueva vivienda de Desideria. ····································· Estrella, TS CSS (estrella.duranc@salud-juntaex.es), me remite Informe de Alta del CSS, en el mismo aparece fecha de alta 07/05/20, pero el alta real se produjo el lunes día 5. Guardo en el expte. ·························································· Correo de Estrella Durán, TS CSS, al final de la mañana: "Ana, al parecer ha llamado Desi agobiada a su Psiquiatra para decirle que no le funciona la lavadora y no tienen calentador, y alguien de la Comisión les ha dicho que necesitan tres presupuestos para comprar la lavadora y ella solo quiere comprarla en Electrocash que está al lado de su casa, tienen servicio técnico por si se les estropea etc. Me puedes decir algo al respecto. Gracias" Mi respuesta: "Hola de nuevo Estrella, No sé con quién habrá hablado de la CTAEX, sí que es cierto que desde el área económica se suelen pedir al menos 2 presupuestos para la adquisición de electrodomésticos y similar, pues deben justificarlo, de todas formas hablo con Futuex para ver si pueden darle apoyo y soporte al respecto. Gracias por avisar. Un saludo." Vuelvo a escribirle: "De todas maneras, estoy pensando el gasto de ambos electrodomésticos deberá ser compartido con el marido, no lo va a pagar sólo ella, cuando además quién se empeñó en comprar la vivienda nueva, y así lo hizo por su cuenta, fue él. Se abordarán todas estas cuestiones con ellos. Voy a llamar a Futuex. Un saludo. ······································································· Llamo a Toni-Futuex (600 56 42 15): Quién ha llamado es Ángel, tanto a Sonia como a Gloria (FUTUEX), no a la CTAEX: lo primero que le han dicho es que quién se empeñó en comprar la vivienda fue él, por tanto que asuma también el gasto de los electrodomésticos que la vivienda no tiene. Y en todo caso, como mucho Desi podría asumir la mitad del gasto, para lo que sería necesario presentarar 2-3 facturas a la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-05-07','TERESA: EMAIL CRPS Trasladado. La dueña del piso de Beatriz me han dicho que no van hacerla revisión de la goma del gas hasta que no acabe el confinamiento. La llamo para comunicárselo esto y lo del dinero y la encuentro muy mal, estaba discutiendo con su hermana porque quiere que vaya a Llerena a que la valore y ella no quiere. Esta con delirios con respecto a su madre, pensando que es la causante de su enfermedad, de su ruptura sentimental, de enfermedades de su padre, y otros familiares, porque esta haciendo brujería. Intento convencerla para ingresar pero no hay manera; me cuelga el telefono. Me llama un rato despues mas tranquila y diciendo que no va a ir a Llerena pero me va hacer caso y va a disfrutar estos días con su hermana (muy inestable, parecía otra persona....) Se lo he comunicado a mis compañeros para que mañana valores junto a la psiquiatra que este de guardia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-05-07','El CRR de Plasencia nos envía minuta de Abogado en procedimiento de rehabilitación de capacidad de María Antonia. Se le envía un correo electrónico con el siguiente contenido: ------------------------------------------------------------ "En relación con esta minuta, hemos hablado con el Abogado, para hacerle ver que esta Comisión tutelar de Adultos de Extremadura no ha tenido conocimiento previo, en relación con la contratación de sus servicios, para representar a María Antonia en este procedimiento, debido a que, de necesitar representación procesal, acudimos, en primer lugar, a la solicitud de asistencia jurídica gratuita, a la que, por otra parte, puede tener acceso María Antonia, por sus recursos económicos y, de lo contario, acudimos a la contratación de asistencia jurídica particular, para lo que se solicitan varios presupuestos. Sin embargo, el Abogado que presenta esta minuta, lo hace, a pesar de ser conocedor de la incapacitación plena de María Antonia, para gobernar su persona y bienes, requiriendo supervisión y control constante por parte de terceros, al ser fácilmente influenciable por terceros para acometer actos o contraer obligaciones en perjuicio de su patrimonio y del ejercicio de la tutela llevada a cabo por esta Comisión Tutelar, pudiendo haberse puesto en contacto con esta Comisión Tutelar, antes de iniciar procedimiento alguno, sin embargo no lo hizo, si lo hace ahora, reclamando el pago de la minuta. De acuerdo con todo lo anterior, se le indica que no podemos autorizar este gasto, puesto que la Comisión Tutelar es la encargada de llevar a cabo estas contrataciones, en nombre de María Antonia, para el caso que lo necesite, en el procedimiento que corresponda. Nos indica que actuó de buena fe, que desistirá de continuar el procedimiento y de reclamar minuta alguna".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-07','Ana: Recibo llamada de Clara, TS CS Guadalupe (Despacho Logrosán: 927 360 769): Ha hablado con Consoli, ésta le confirma que a Juan le darán el alta mañana viernes día 8. El día 15 acudirá a su cita en ESM-CC. *Clara se muestra preocupada por la alimentación, medicación de Juan y posiblemente necesidad de botella de butano en relativo poco tiempo. *Le informo de las gestiones realizadas ayer en relación a la posibiliad de catering. En cuanto me confirmen algo del C. Día se lo comunicaré. Ella volverá a hablar con Raquel, SSB, para ver si pueden organizar con Protección Civil la retirada de medicación y un termómetro, entre otras cuestiones que puedan surgir, para lleváselas a Juan a su domicilio. ······················································· Recibo nueva llamada de Clara, TS C.S., ha hablado con Raquel y ésta plantea que como Juan tiene capacidad legal y además ha recibido el alta de un servicio médico especializado, tiene capacidad para encargarse él mismo de estas cuestiones. Si debe estar en aislamiento, debe ser él quién se encargue de solucionar lo relacionadao con su medicación, alimentación y lo que pueda necesitar. Que llame él a donde tenga que llamar.··························································· Recibo llamada de Mª Carmen, Directora del C.Día (667 891 640). Sí que pueden hacer la excepción. El coste de menú son 7 €/día sólo comidas y 13 €/día comida y cena. Sirven sólo de lunes a viernes. La comida está compuesta de 1er y 2º plato, pan y postre, tienen buenas cantidades. Pero tendremos que hablar con el Ayto. para que le haga el reparto diario Protección Civil. /// *Habría que pedir también que le compraran alimentos para el fin de semana así como la medicación en la farmacia. ············································································· Nueva llamada de Clara, dice que Consoli, Médica de Att. Primaria ha llamado al Alcalde, pero éste se muestra reticente con respecto a que Protección Civil se encargue del reparto de comida y gestiones de Juan, en la misma línea que Raquel. *Informo a Clara de que Pedro, Jefe secc. CTAEX, va a llamar a Raquel, TS SSB y si fuera necesario a posteriori al Alcalde. ·····························································++++++++++++++++++++++++++++ (Pedro) conversación con Raquel, TS del SSB. Finalmente Raquel se va a implicar y realizará las gestiones para que Juan reciba el apoyo de Protección Civil. Necesita saber a qué hora llegará Juan mañana al pueblo. ++++++++++++++++++++++++++++++++++++++++++ Convesación con el Dr. Pizarro-CSS Plas.: Juan tiene ya la medicación activada en la tarjeta sanitaria, para que pueda retirar la medicación de la farmacia. No obstante lleva mediación para el fin de semana. A petición de Pedro, le prepararán comida para el fin de semana para que se la lleve también a casa. *Al ESM Juan se trasladará cada vez que tenga cita en ambulancia. *En cuanto a la hora de llegada a Guadalupe, no la sabe pues dependerá de la ambulancia. Mañana a primera hora lo preguntará y me llamará para que se lo pueda comunicar a Raquel. ······································· Ana: llamada a Mª Carmen, Directora del C.Día (667 891 640): salta el buzón de voz. Tampoco consigo hablar con Clara, C.S. Mañana volveré a llamar a ambas. +++POR SI FUERA NECESARIO: D. Felipe Sánchez Barba, ALCALDE de GUADALUPE (927-367006)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BLAZQUEZ'and apellido2='ACEDO'),'2020-05-07','(Pedro)Llamada de Paqui. +++Tiene presupuesto seguro de decesos de Santa Lucía: algo más de 4000 euros. +++Va a pedir algún presupuesto más y nos los enviará. +++Le comento que en caso de fallecimiento habría deinero para pagarlo, pero si gastamos más de la mitad de sus ahorros en el seguro, y surge cualquier imprevisto (necesidad de un acompañamineto hospitalario, p.e.), podríamos no tener recursos para hacerle frente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2020-05-07','Ana: Recibo llamada de Amor, TS de Aspace. Santi sigue bien, aunque un poco rebelde dada la duración del "encierro". Sólo salen un rato cada día al jardín trasero del centro, lo cual le viene muy bien. Por otra parte, me pide que le confirme la cuantía del ingreso de Santi en este año. Por último, me comunica que desde Aspace van a solicitar la susbención para Progamas de Integración a la Junta de Extremadura. Su propuesta es un **proyecto de ocio en el que les gustaría que Santi participara (realizan salidas para participar en conciertos, teatros y otras actividades). Le digo que desde la CTAEX se apoyará la participación de Santi en dicho proyecto. Llegado el momento nos enviarán la autorización corespondiente. *No cree que suponga ningún gasto adicional y en tal caso será poco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELINA'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2020-05-07','Correo-e de Beatriz, Directora dela Residencia "Real de Navalmoral" (Tlf. 927 533 322).: +++Buenos días, nos ponemos en contacto con ustedes para informar sobre la situación que presenta la tutelada Marcelina Sevillano Sevillano. La señora actualmente se encuentra ingresada en el Hospital Campo Arañuelo tras derivarla los servicios sanitarios en la madrugada del día 7 de mayo. Se encuentra en estado crítico según informan desde el Hospital, se le realizada TEST Covid-19 con resultado POSITIVO, y esto se le añaden las patologías de base que la que señora ya tenía. Nosotros hemos contactado con el Hospital para que nos informen sobre la situación que presenta, como centro donde está institucionalizada. Esto es debido a que la persona que convive con su hermano está intentando recaudar información de Marcelina, la persona se llama Conchi. Además necesitamos saber cómo proceder en el caso de fallecimiento, teniendo en cuenta que la señora tiene un seguro de decesos con Santa Lucia con numero de Póliza 116026561. Rogamos nos informen a la mayor brevedad posible. Gracias, ······································································································ Ana: Mi respuesta: "Buenas tardes Beatriz, Lamentamos mucho la noticia y ojalá la evolución de Dña. Marcelina sea positiva, aunque veo que el pronóstico no es muy halagüeño… Como te comenté por teléfono esta mañana, en el caso de fallecimiento, puedes comunicarlo al hermano sin problema. No obstante, como bien habéis comunicado al hospital, no tienen ni tenéis por qué dar ningún tipo de explicaciones a la persona que mencionas. Si Dña. Marcelina falleciese debéis avisar a la compañía de seguro y comunicarlo mediante correo electrónico a la Comisión Tutelar de Adultos. Si os facilitan el certificado médico de defunción, hacérnoslo llegar también, por favor. Aunque desde la Comisión se solicitará el correspondiente certificado al registro. Podéis usar como planteabas el velatorio del que disponéis hasta que sea trasladada al cementerio. Si el hermano os pide alguna información remitirle al Jdo. que la incapacitó. Ante cualquier otra cuestión, no dudéis en contactar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-07','(Pedro) Conversación con David, Psiquitra de la UHB de Mérida (81621), sobre respuesta del Juzgado a su petición de ingreso involuntario: +++El Informe del Forense NO va a ratificar el internamiento, ya que según su opinión NO existe criterio válido para su autorización. +++Durante el reconocimiento Andrés ha dado una imagen positiva de su estado actual, por lo que el dictamen forense va a ser el referido. Todavía no les ha llegado el Auto del Juzgado en este sentido. +++Se ha realizado un TEST PCR con resultado NEGATIVO, pero habría que repetirlo en 7 días, dado que dicho tiene una BAJA SENSIBILIDAD por el poco tiempo transcurrido entre la fuga y su realización. +++Si finalmente el Auto del Juzgado no ratifica su internamiento, en el centro debería estar EN AISLAMIENTO DURANTE 7 DÍAS y REPETIR EL TEST al cabo de ese tiempo. +++PONGO TODO ELLO EN CONOCIMIENTO DE Soraya.Le planteo la psoibilidad de qu edesde Gerencia se hable con Salud Pública pero me indica que habría que tratar de hablar con el Juez. +++LLAMO AL JUZGADO de 1ª Instancia e Instrucción Nº 5 de Mérida (924-380607). Hablo con José Antonio Pantojo Falero, Letrado del Juzgado. +++++Expongo la situación y pido hablar con el Juez o Jueza. Le va a consultar y finalmente me pide que le remita los Informes de los que le he hablado por Lexnet. Le informo de que no tenemos Lexnet, por lo que me da su correo-e. Es el siguiente: joseantonio.pantojo@justicia.es +++++Le envío los dos últimos Informes de Plena Inclusión de Cabeza del Buey, insistiendo, como durante la conversación, en la gravedad de la situación si Andrés finalmente regresa al Centro (aspecto que también se refleja en el último Informe remitido. +++Antes de terminar la jornada intento ponerme en contacto con David para saber si había recibido alguna comunicación del Juzgado pero finalmente no pude hablar con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-08','Ana: Llamo a Clara, TS CS Guadalupe (Despacho Logrosán: 927 360 769) varias veces, pero no responde. Consigo hablar con ella más tarde, le informo de las últimas conversaciones de Pedro con Raquel y el Dr. Pizarro, se queda mucho más tranquila. Se lo comunicará a la Dra. Consolación. *Por otra parte, insiste mucho en la necesidad de comprar a Juan un termómetro para que se tome la temperatura a diario esta semana. ····················································· Llamo a Mª Carmen, Directora del C.Día (667 891 640): Salta el buzón de voz, dejo un mensaje pidiendo que me devuelva la llamada. *Más tarde si coge la llamada. Confirmamos el servicio de comidas para la semana que viene. Si fuera necesario se podría ampliar una semana más. En principio sólo contratamos la comida, si a Juan le resultase poco podría ampliarse con la cena. ························································ Ana: Recibo llamada de Pedro, ha hablado con el Dr. Pizarro; ha surgido un nuevo problema, la ambulancia no puede llevarle hasta Guadalupe por ser un área de salud diferente. Ambos seguirán intentado subsanarlo con el SES. ························································· Como posible alternativa llamo a Cruz Roja - CC (927 24 78 58). Me dicen que no les compete por zona, que llame a Plasencia. ············································· Llamo a la asamblea de Cruz Roja de Plasencia (927 41 10 10), lo primero que me dicen es que ya no hacen este tipo de servicio, que se encarga Ambulancias Tenorio. Me dicen que llame directametne al 112 o al responsable provincial de ambulancias en Cruz Roja: Rafa (927 24 78 62 / 927 24 78 58 / 661 527 679). Ellos no pueden mover ningún vehículo sin autorización. LLamo a Rafa: me dice que hoy no es posible realizar el traslado. ·············· *Hablo con Pedro, Jefe de Secc., llamará de nuevo al CSS, para que soliciten un taxi de confianza (se ha informado del coste apróx.: entorno a 130€). ················································· Nueva llamada de Pedro-CTAEX, ha vuelto a hablar con el Dr. Pizarro: **Han solucionado el traslado en ambulancia. Y a petición de la Dra. Consolación le darán un termómetro también. Lleva suficiente comida hasta el lunes. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamada de Daniel Pizarro: la ambulancia recogerá a Juan a las 14:30h. +++Llamo a Consolación para decírselo y pido que se lo comente a Clara. +++Nuevo intento de hablar con Raquel, pero no coge el teléfono. ············································ Ana: Llamo a Raquel, TS del SSB (605 429 865): acaba de llegar del ayto. que ha tenido que ir hoy. Dice que tienen solicitados los alimentos de Cruz Roja, pero lo de Protección Civil tenemos que hablarlo directamente nosotros con el Alcalde, ella no lo lleva. (Nº directo del Alacalde, Felipe Sánchez Barba = 609 54 88 02) *Llamo varias veces, pero no obtengo respuesta. *Volveremos a intentarlo el lunes. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Remiten Informe de Alta a petición de la Comisión. SE guarda en expediente virtual y en papel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-05-08','TERESA: email crps Te informo de que esta mañana se ha hablado con la psiquiatra y se le ha informado de la situación y se le ha explicado a la hermana que cuándo Beatriz esté alterada llame al 112, que ya están a corriente para que hagan el ingreso. La hermana comenta que esta mañana ha estado tranquila. Beatriz me ha llamado para pedirme que se le de autorización a su hermana para recoger su dinero de la próxima semana, para sacarlo el lunes, porque piensa quedarse con ella LE COMENTO QUE EN PRINCIPIO NO TIENE QUE HABER PROBLEMAS PARA SACAR EL DINERO ALI EN EL CASO QUE LO HAYA QUE LLAMEN A LA OFICINA DE ZAFRA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-08','(Pedro)Conversación con José Antonio, Letrado del Juzgado nº 5 de Mérida. +++Ayer pasó los Informes al Juez, que mediante Diligencia de Ordenación remitió al Médico-Forense para que informara. Éste, tras realizar el Informe, lo envió en la tarde de ayer a Fiscalía. +++Durante la mañana de hoy, o mañana, se remitirá la decisión tomada tanto a la UHB como a la Comisión Tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-05-08','(Pedro) Correo del CRR de Mérida (08-05-2020). +++Ángel Pinilla: Más tranquilo que la semana pasada, hemos intentado pedir cita con su Fisioterapeuta pero actualmente por la situación no está disponible así que lo intentaremos más adelante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-05-08','(Pedro) Correo del CRR de Mérida (08-05-2020). +++María Dolores Fernández: Se encuentra bien, no sabemos si finalmente querrá salir ya que comentaba días atrás que para 15 minutos "con todo lo que hay que liar" (ducha, cambio de ropa, desinfección, etc) no merece la pena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-05-08','(Pedro) Correo del CRR de Mérida (08-05-2020). +++José María Guillén: Tranquilo y adecuado, con días puntuales en los que está de peor humor pero bien, incluso mejor que cuando pasaba tanto tiempo en la calle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-05-08','(Pedro) Correo del CRR de Mérida (08-05-2020). +++Luisa Rodríguez: Sigue en la habitación gran parte del día, sale un poco más aunque no tanto como nos gustaría, con algunas faltas de respeto que estamos tratando con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-05-08','(Pedro) Correo del CRR de Mérida (08-05-2020). +++Antonio Merchán: Muy bien, como en ocasiones anteriores pasa gran parte del día en zonas comunes con resto de compañeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-08','TERESA: RECIVO EMIAL DE SILVIA P.I Buenas tardes: Nos falta información de dónde estuvo Andrés entre el 13 de julio al 19 de diciembre de 2017, puesto que en el informe del Centro Dulcenombre de María consta que no estuvo en en ese centro durante 6 meses. Puesto que dependía de Menores de la Junta de Extremadura, solicito información a sus tutores del motivo por el cual sale del centro de Málaga y luego regresa, e informe del centro donde haya permanecido durante esos 6 meses, pues nos parece fundamental para intervenir con Andrés conocer su historia. EN ESE PERIODO DE TIEMPO PAULA (ANDRES SIVLA), ESTUVO EN EL CARSI EN CASAR DE CACERES. SE LE DERIVO ALLI PORQUE ERA UN CENTRO ESPECIAL EN EL QUE SE OFRECE UNA INTERVENCIO DIRETA EN PROBLEMAS DE CONDUCTA Y DIO PERFIL PARA INGRESAR EN ESTE CENTRO. EN DICIEMBRE DICHO CENTRO CERRO YA QUE FUNCIONA A CONCURSO PUBLICO Y ES POR ELLO QUE TUVO QUE VOLVER AL DULCE NOMBRE. HE HABLADO CON LA DIRECCION GENERANL DE INFANCIA Y FAMILIA, CON OLGA, QUE ES LA QUE LLEVO SU EXPEDIENTE PARA QUE ME DIERA INFORMACION. ME SOLICITA QUE LO HAGA POR ESCRITO. EN CUANTO TENGA LA INFORMACION OS LA HAGO LLEGAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-08','TERESA ENVIO OFICIO SOLICITANDO INFORME DEL CARSI A LA DIRECCION GENRAL DE INFANCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2020-05-08','Ana: Correo de la Resid. Femar (residenciafemar2019@gmail.com) :"Buenos días, adjunto le remito para su conocimiento, la cita médica de Valentina Fernández Trejo, usuaria de nuestra Residencia de Mayores FEMAR. Un saludo" Guardo la cita en el expte. y les solicito nos envíen informe médico tras la consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-05-08','Ana: Convesación con Toni-Futuex: Acordamos finalmente que el mensaje a Desi y su marido, será que sea Ángel quien compre la lavadora y Desi si quiere que aporte el dinero de la asignación mensual. Como no sé si desde el CSS, se le ha retirado dinero a Desi, ni cuánto, preguntaré a la sección económica por los movimientos bancarios. ··································· *Envío correo al ctutelar@ ················································ Respuesta de Juana, CTAEX: "Buenas Ana, El día 13 de abril fue el último reintegro por importe de 100 euros. Si te parece se le podría autorizar 100 o 150 euros hasta que finalice mayo, indicando que no irá acompañada y luego a patir de junio sacar su asignación mensual normal, que no habría que avisar a Liberbank puesto que sigue activa la orden de reintegro." ·············································· Mi respuesta: "Ok Juana, me parece bien, Darle los 150 €. Habrá que avisarla para decirle cuánto y cuándo podrá retirarlo, si queréis podéis decírselo a Toni-Futuex para que sea la Delegada la que se lo explique. Gracias!! Buen difne!" ··············· Juana me da el OK.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2020-05-08','(Pedro)Llama Marisa, de una Gestoría de Jerez de los Caballeros (697-137567), +++La madre de Remedios quiere, para hacer la declaración de la renta de 2019, saber desde que fecha está tutelada por la Junta. +++Le indico que cualquier información que deseen la han de pedir por escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-05-11','Correo de Toni-Futuex (areasocial3@futuex.es), con incidencia del día 8: 08/05/2020 Incidencia Alfonso Marín de Caceres: Contacta Isabel, madre de Alfonso, muy alterada y nerviosa, comenta que no puede con la situación de Alfonso, especialmente, con la parte económica, pues le está quedando sin ahorros… Cuenta que ayer tuvo que hacer frente a una deuda de su hijo de 400€, uno de los chicos a los que le compra para consumir, acudió al domicilio solicitando que se le pagase, por lo que Alfonso se gastó toda la asignación y luego pidió a Isabel que le diese para ir a comprar… Isabel descarga todo sobre la CTAEX y la educadora de apoyo, estableciendo que no tiene ayuda por parte de nadie y se hace cargo de todo sola, aunque esté tutelado… Se le dice que se entiende su desesperación, pero el hecho de que haga frente a las deudas de Alfonso o le administre más dinero para su consumo es algo que hace de manera voluntaria, por supuesto por miedo, pues Alfonso la amedrenta y la chantajea acusándole de ser la culpable de todo lo que le pasa, pero no es por culpa ni de la CTAEX, ni de la educadora de apoyo… Isabel establece que si no lo hace es peor, pues ayer, Alfonso, estaba, constantemente, acusando de que se le roba, se le quita todo desde pequeño, incluso de que le ha quitado la herencia de su padre; se le dice que una posible solución es que llame al 112 o la policía cuando esté así de alterado, pues supone un peligro y así es la mejor forma de que se lleve a cabo un ingreso.. El problema de Isabel radica en que tiene mucho miedo a Alfonso, llegando a ceder a todo lo que el tutelado le solicita, es más, cuando se habla de ingresarle cambia su forma de hablar, deja de acusar y culpabilizar para pedir, por favor ayuda… Pide ayuda económica para hacer frente a los gastos de manutención que tiene su hijo, se le dice que se desconoce la pensión de Alfonso, pero, posiblemente, no sea alta, por lo que para darle algo de sustento a ella, supondría reducirle la asignación al tutelado, aspecto que lo alteraría más… Finalmente, se le comunica que se transferirá todo a la CTAEX para que lo vea y tome las decisiones que estime oportuno, indicando que se transmitirá, como posible opción, el ingreso involuntario en centro, pues, en estos momentos, parece la alternativa más viable y que más ayudaría tanto a Alfonso como a ella. También, se le insiste en la importancia de pedir ayuda en el momento preciso, pues llamar al 112 cuando Alfonso está alterado no es una traición para su hijo, al revés, es echarle una mano, ya que él no es consciente del problema que tiene y puede causar mucho daño con sus alteraciones o si se produce una crisis." ·························································· No hay informes médicos en el expte. en los últimos años. ····················· Llamo al Consultorio Médico de Torrecilla de los Ángeles (927 18 56 83), Carmen, Médica, está ocupada, le dejarán nota para que me devuelva la llamada más tarde. ················ Recibo llamada de la Dra. Carmen Ballesteros, dice que Alfonso acude regularmente a ponerse el inyectable, mantiene conducta adecuada, la semana pasada fue la última vez que acudió (jueves o viernes) y les sorprendió lo bien que lo vieron, pues otras veces parece más taciturno. Una vez que su madre acudió a hablar con ella, le pidió que su hijo acudiera a la consulta y éste no fue. No ha querido darle cita pues considera que ésto podría provocar el que Alfonso dejara el tratamiento. **A Salud Mental no acude. Según le relató la madre en su día, no lleva un estilo de vida saludable, consume porros, sólo sale de casa para "pillar" cannabis, duerme de día, permanece despierto por la noche, no come lo que la madre prepara, malcome, no hay figura de autoridad en el domicilio, hace lo que quiere, los límites los pone él. "La madre es un elemento patológico para el chico" **Me enviará informe médico. ··························· Recibo correo de Carmen Ballesteros, en el mismo redacta informe de evolución. *Pido que si es posible nos lo envíe escaneado a en PDF con su firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-11','Ana: Llamo a Felipe Sánchez Barba, Alcalde de Guadalupe (609 54 88 02), refiere que éste es su número personal, le pido disculpas y le digo que es el teléfono que me facilitó Raquel, TS del SSB. *En relación a Protección Civil, me dice que son voluntarios y que no sabe si éstos estarán dispuestos a llevarle la comida a Juan, pues conoce bien a su pueblo y pueden decirle que dado que Juan tiene familiares en Guadalupe, que sean ellos quienes acudan. *Tampoco entienden que desde el centro de día no le hagan el reparto, como hacen con otras personas que tampoco son usuarias del C.Día. También dice que es un poco precipitado, de hoy para hoy, explico que le llamé el viernes varias (varias veces) y no obtuve respuesta. *Preguntará a Protección Civil y me llamará. ················································ Recibo llamada de Clara, TS CS (927 360 769), le informo de las últimas gestiones realizadas el viernes y esta mañana. *Estoy a la espera de que el Alcalde me llame para confirmar. Ella por su parte ha intentado hablar con Juan, pero consigue contactar. Le digo que Juan suele tener problemas de cobertura en Guadalupe, pues a mí me pasaba cuando le llamaba. ·············· *Recibo nueva llamada de Clara, ha hablado con Juan y éste se encontraba en la farmacia. Le ha dicho que no podía salir, pero él argumenta que necesitaba comprar la medicación y no le habían llamado de Protección Civil ni nada. ···································· Intento hablar con Juan, salta contínuamente el buzón de voz, la vez que conseguimos contactar se le va la cobertura y a penas podemos intercabiar un par de frases. ··········································· Recibo llamada de Felipe Sánchez, Alcalde (605 853 615*), dice que "con Protección Civil ya está todo arreglado", irán a llevarle la comida. Pero que Juan se ha saltado ya el cofinamiento. Le digo que ya me lo ha comunicado Clara y qué por qué no los comunican a la Guardia Civil y Policía. Expresa que no le hemos enviado ningún documento que lo ponga. Nosotros no tenemos tal documento y eso compete al C. Salud. Dado que ha hablado con la Dra. Consolación, le preguntun que si no se lo ha pedido a ella. Dice que no. Hablaremos cone ella. ···························· Recibo llamada de Mª Carmen, Directora del C.D. Guadalupe (667 891 640), ya han pasado de Protección Civil a recoger la comida de Juan. De todas formas me dice que esta mañana ya han visto a Juan en la calle y que el viernes por la noche también le vió en la calle una trabajadora del centro. *Le indico que en estos casos hay que avisar a la policía y/o a la guardia civil para que actúen. ············································ Conversación con Pedro, Jefe Secc. CTAEX, ha hablado con la Dra. Consolación, va a elaborar el informe de aislamiento de Juan para remitirlo a la Guardia Civil. ······························ Nueva llamada de Juan (625 895 394) comunica que la Guardia Civil ha ido a verle a casa, él le ha dicho que si tienen alguna duca que llamen al Dr. Pizarro de Plasencia. Añade que éste le dijo que tenía que estar 4 días en casa. Le explico que por protocolo, al haber cambiado de ára de salud de plasencia a Guadalupe, debe estar una semana completa en el domicilio. Dice que de acuerdo. Dice que el viernes tiene que ir a ponerse en inyectable al centro de salud y que hasta el día "ventialgo" no tiene que ir a la consulta de ESM-CC. Le indico que a partir del viernes ya podrá hacer "vida normal", respetando las medidas del estado de alarma que ese establecen para toda la ciudadanía, hasta entonces debe estar en casa. Le comunico que de protección civil le llevarán la comida de un momento a otro, pues ya han pasado a recogerla al centro de día. ········································ Nueva llamada de Clara, TS CS, le informo de las últimas gestiones y de cómo está la situación. ······························· Nueva llamada de Juan: se ha comido todo lo que le han llevado y no le ha quedado nada para la cena, tiene buen apetito. ································· Llamo a Mª Carmen, C.D., prepararán también la cena, esta misma tarde podrán pasar, a eso de las 19h, a recoger la cena. A partir de mañana le entragarán comida y cena juntas. ····································· Llamo a Manuel, Protección Civil (685 531 733). Dice que ha hablado él con el Alcalde, estaba reunido y por eso Pedro no consiguió hablar con él cuando éste lo intentó. *No hay ningún problema, llevarán a esta tarde a Juan tanto la cena como la medicación de la farmacia. ··························· Llamo a Juan varias veces (625 895 394) para comunicárselo pero salta el buzón de voz. Finalmente le dejo un mensaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-05-08','TERESA:Buenas tardes Teresa. Me pongo en contacto para informaros de que Libertad ya llegó ayer al Centro y se encuentra bien. Hemos informado a nuestro referente de Salud Publica y nos ha comunicado la necesidad de aislamiento durante una semana. Ella es conforme y tiene garantizadas todas las medidas de comodidad posibles como televisión en la habitación, equipo de música, mesa auxiliar para comer, etc. Se muestra tranquila y colaboradora. Seguimos en contacto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-05-08','Ana: Recibo llamada de Javier, Director del CRR-Plas. (677 407 640), en relación al correo que les ha remitido el compañero jurídico como respueta a la minuta que les envión el abogado con el que habló Antonia y que ellos remitieron por mail al ctutelar@. Tienen dudas sobre qué decirle a Antonia, pues no quieren que la respuesta afecte negativamente a su evolución. *Desde el CRR, consideran que "Antonia tiene capacidad para el gobierno de ciertos aspectos de su persona" y que por ello estaría bien continuar con el proceso de revisión de su capacidad. Por otra parte dicen que no les da ninguna confianza el abogado al que acudió Antonia, pues primero le pidió 1400 €, que le pareceía excesivo, después bajó a 700 € y ahora, a pesar de haber habaldo con la CTAEX, llama a Antonia y le exige que le pague. *Acordamos que leeré los correos mencionados y hablaré con los compañeros correspondientes de la CTAEX y les daré una repuesta. ································· *Tras leer los correos-e y hablar con Pedro, Jefe de secc. CTAEX, devuelvo la llamada a Javier (677 407 640), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELINA'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2020-05-11','Ana: Recibo llamada de Beatriz, Directora de la Res. Real de Navalmora. Comunica que Marcelina HA FALLECIDO. Nos lo comunicará también mediante correo-e al ctutelar@. *Su poliza del seguro de decesos es básica y no cubre nicho. Lo hablará con la funeraria para preguntar en su localidad si tiene alguno en propiedad y si no es así, enviarán presupuesto y a posteriori la correspondiente factura. ································································ Correo de Beatriz, Res. Real de Navalmoral (direccion@residenciareal.com): "Buenos días, les comunicamos según indicaciones de ustedes que la Señora Marcelina Sevillano Sevillano ha fallecido en el Hospital de Navalmoral de la Mata en la fecha 11 de mayo de 2020. Más abajo les enviamos la información que ha emitido la funeraria que se está encargando del servicio fúnebre, para que autoricen el pago del nicho. Saludos" "De: Javier Iñigo Arroyo [mailto:javier.ia@grupoa-alvarez.com] Enviado el: lunes, 11 de mayo de 2020 11:37 Para: direccion@residenciareal.com Asunto: Servicio funerario sra MARCELINA SEVILLANO SEVILLANO AA DIRECTORA RESIDENCIA REAL POR EL SEGURO DE DESCESOS DE LA SRA MARCELINA , SANTA LUCÍA NOS COMUNICA QUE NO LE ENTRA NICHO EN LA PÓLIZA . TRAS HABLAR CON EL AYUNTAMIENTO DE CUACOS DE YUSTE , EL VALOR DEL NICHO PARA PODER INHUMAR A LA SRA MARCELINA SON 600 EUROS , Y SERÁ INHUMADA EN EL NICHO NÚMERO 480. LO DEMÁS LO CUBRE LA PÓLIZA DE SANTA LUCÍA , NÚMERO 116026561."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-11','(Pedro)Se recibe en la Comisión Auto del Juzgado de 1ª Instancia e Instrucción nº 5 de Mérida ratificando el internamiento de D. Andrés en la UHB de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-05-11','Ana: Llamada de Damián (622 834 876): informa que a fecha de hoy le han pasado el recibo de CETELEM y no se lo deberian haber pasado. A parte recuerda que le gustaría poder mirar los movimientos de su nueva cuenta bancaria. ·········· Lo comunico a Icíar mediante correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-05-11','TERESA: RECIBO EMAIL DE ANA EDUCADORA PI El viernes ya no pude llamarte para informarte de que conseguí hablar con Manuela y me explicó el protocolo para el reingreso de los residentes al mencionado servicio. Les harán la PCR en los centros de salud que les corresponda, según dónde estén los domicilios familiares, de eso se encarga Manuela en coordinación con Salud Pública. El viernes priorizamos dos casos RAE pero hoy nos hemos encontrado con un nuevo episodio en el caso Natalia y vamos a proceder a activar el protocolo para su vuelta pero antes queríamos informaros a vosotros, puedo llamarte y te cuento las últimas novedades?? Prefiero contarte a ti primero, que llevas el hilo de todo…y después, quizás si lo ves oportuno pues llamamos a Pedro y se lo contamos también. ME LLAMA POR TELFEFONO Y ME COMENTA QUE LA ABUELA MANDO AUDIO A ANA MARQUEZ DICIENDOLE QUE HA RECIBIDO UN AUDIO CON AMANENAZAS DE MUERTE HACIA ELLA Y HACIA SU HIJO. HAN DENUNCIADO A LA GUARDIA CIVIL, LOS AUIDOS SON DE UN ARGENTINO Y EL NUMERO DE TELEFONO DICE SER DE NUEVA YORK LE COMENTO QUE COMO ESTE ASUNTO NO ATAÑE A NATALIA QUE ARCHVIE LOS AUIDOS POR LO QUE PUEDA PASAR EN UN FUTURO Y DEJEN AHI EL TEMA ESTA SEMANA VAN A PROCEDER A LA VUELTA DE NATALIA, SE ESEPRA QUE ESTE EN EL CENRO A FINAL DE SEMANA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-11','(Pedro)Alta de José Manuel del CSS de Mérida en el día de hoy. +++SE ha marchado a casa en taxi. +++Ya está llamando a Virginia para ver qué pasa con el catering... +++Taciana ha comunicado al Juzgado el Alta clínica y nos enviará copia del Informe. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada a Pilar Martín, del ESM de Cáceres(54612). +++Informar del Alta. +++No tiene cita en estos momentos. Lo citarán lo antes posible y planteo,en la medida de lo posible, un seguimiento en consulta con una mayor frecuencia, al margen del seguimiento de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-11','Ana: Correo de Icíar: "Hola, Me ha llamado Taciana, nos informa que José Manuel Romero Mediavilla ya está de alta. Ha pedido cita para salud mental pero no se la han dado." ·························· Conversación con Pedro, Jefe Secc. CTAEX: ha hablado ya con Soraya al respecto, ésta dice que ambos han hecho ya lo que debían de hacer. Si así y todo la Psiquiatra ha decidido dar el alta, poco más pueden hacer. *Pedro solicitará informe de alta al sociosanitario. ························································ Llamada de Toni-Futuex (600 564 215); Virgina, Educadora, le ha comunicado que José Manuel le ha llamado diciendo que estaba ya en casa, exigiendo poder sacar dinero y preguntando qué pasa con el caterin. *Consultaré las posibilidades económicas con la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-05-12','Ana: Recibo llamada de Carmen Ballesteros, médica del consultorio de Torrecilla de los Ángeles (927 185 683), me informa que la situación en el domicilio de Alfonso, como expresa,"ha dado un giro de 180º", le ha llamado Isabel, madre de Alfonso y le ha contado este pasado fin de semana se han mudado al domicilio 2 hijos procedentes de Madrid, uno con orden de alejamiento de su pareja y el otro porque se quedó en paro y presenta dificultades económicas. *Alfonso ha perdido la tarjeta sanitaria. **Isabel expresa que Gloria (Delegada de Futuex) se va a encargar de que ingresen involuntariamente a su hijo Alfonso, porque está "fatal", ha tendio "delirios", no acude a salud mental ni a nada y esto no puede seguir así... A Carmen no le ha gustado la actitud de Isabel, expresa que la impresión que le ha dado es que se quiere quitar a un hijo de en medio y como Alfonso está tutelado... Por otra parte cree que la situación en casa puede estallar en cualquier momento. *En cuanto a la medicación de Alfonso, al tener que hacer las recetas, se ha dado cuenta de que toma más medicación de lo que pensaba y según Isabel la gestiona él sólo. Lleva mucho tiempo también sin hacerse las correspondientes analiíticas de control. *Por otra parte, en el pueblo es sabido que un tío de Alfonso (hermano de la madre) pasa drogas en Torrecillas, el hombre tuvo un accidente hace años y va en silla de ruedas, pero se maneja bien y trapichea. Es una familia complicada. ····· *Le pido nos envíe informe también de esto, así lo hará. En cuanto al informe de ayer lo remitirá en papel a la Comisión. ······································· Llamo a Ana Benavete, TS-ESM Plas., pero no obetngo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CORBACHO'and apellido2='GALINDO'),'2020-05-12','miguel, la semana pasada Luis Carretero (abogado de la exnuera Tony Silvero de nuestros tutelados) me escribió para nos pongamos en contacto con él a efectos de ver lo de la deuda común de ella con nuestros dos tutelados y su exmarido. ********************************************************* Tras conversación con Juana y Alberto, me remiten contestación de Caja Almendralejo indicando que nuestros tutelados no tienen en dicha entidad cuentas, tarjetas, etc, únicamente tienen el préstamo que con carácter solidario tienen los cuatro, el matrimonio que tenemos tutelados de Don Manuel Corbacho Galindo y Doña Isabel Parra Ochoa, y el hijo Don Manuel Corbacho Parra y Antonia Dominga Silvero Nogales (exnuera). Además me remiten Auto del Juzgado nº1 de Almendralejo donde figura un Procedimiento de Ejecución 109/2018, notificado el 5/9/2018. Esto significa que además de tener embargada la casa de Entrin Bajo cuyo único titular es nuestro tutelado Don Manuel Corbacho Galindo, han embargado la nómina de la exnuera Tony Silvero y de el hijo de nuestros tutelados Don Manuel Hipólito Corbacho Parra(su paro). *********************************************************** Veo con la parte económica posibles opciones de venta o dejar que continúe el procedimiento, así como si hay o no que ceder a petición de devolución de alguna cantidad abonada por la exnuera, quién dice haberse hecho cargo del pago de todo el ptmo hasta la fecha. Parece ser que se deben unos 15.000€ del principal y unos 4.500€ de intereses (según el Auto, siendo 21.000€ el principal inicial). ********************************************************* Intento hablar con el Juzgado nº1 de Almendralejo sin éxito para saber el estado de dicho procedimiento de ejecución y si ya está o no prevista una subasta. Dependiendo de dicha situación cabría intentar iniciar previa tasación Solicitud Judicial de Venta (para lo que necesitaríamos Abogado de Oficio). En mi opinión al ser responsables solidarios del ptmo, no cabría compensación de cantidad alguna a la exnuera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2020-05-12','miguel, la semana pasada Luis Carretero (abogado de la exnuera Tony Silvero de nuestros tutelados) me escribió para nos pongamos en contacto con él a efectos de ver lo de la deuda común de ella con nuestros dos tutelados y su exmarido. ********************************************************* Tras conversación con Juana y Alberto, me remiten contestación de Caja Almendralejo indicando que nuestros tutelados no tienen en dicha entidad cuentas, tarjetas, etc, únicamente tienen el préstamo que con carácter solidario tienen los cuatro, el matrimonio que tenemos tutelados de Don Manuel Corbacho Galindo y Doña Isabel Parra Ochoa, y el hijo Don Manuel Corbacho Parra y Antonia Dominga Silvero Nogales (exnuera). Además me remiten Auto del Juzgado nº1 de Almendralejo donde figura un Procedimiento de Ejecución 109/2018, notificado el 5/9/2018. Esto significa que además de tener embargada la casa de Entrin Bajo cuyo único titular es nuestro tutelado Don Manuel Corbacho Galindo, han embargado la nómina de la exnuera Tony Silvero y de el hijo de nuestros tutelados Don Manuel Hipólito Corbacho Parra(su paro). *********************************************************** Veo con la parte económica posibles opciones de venta o dejar que continúe el procedimiento, así como si hay o no que ceder a petición de devolución de alguna cantidad abonada por la exnuera, quién dice haberse hecho cargo del pago de todo el ptmo hasta la fecha. Parece ser que se deben unos 15.000€ del principal y unos 4.500€ de intereses (según el Auto, siendo 21.000€ el principal inicial). ********************************************************* Intento hablar con el Juzgado nº1 de Almendralejo sin éxito para saber el estado de dicho procedimiento de ejecución y si ya está o no prevista una subasta. Dependiendo de dicha situación cabría intentar iniciar previa tasación Solicitud Judicial de Venta (para lo que necesitaríamos Abogado de Oficio). En mi opinión al ser responsables solidarios del ptmo, no cabría compensación de cantidad alguna a la exnuera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-05-12','miguel, tras email de Amalia la semana pasada y conversación a tres bandas con Pedro y Alberto sobre posibles soluciones a este expte, nos planteamos lo siguiente: Plantear ante el Juzgado con carácter previo al alquiler o la venta de la vivienda, el Procedimiento de modificación de capacidad a tutela. Y paralelamente Solicitud Judicial de Internamiento Involuntario en Centro de Discapacidad. *********************************************************** Amalia que la casa está desde hace meses en alquiler (la opción de venta se está planteando ahora). Hablaré con Pedro y Alberto para que o bien llamen ellos o yo a la interesada en alquilar y proponerle un precio cerrado de venta con algún descuento o de alquiler con opción a compra (con una entrada importante). Caso de dicho alquiler con opción a compra si incumpliera dicho contrato no tendría derecho a indemnización por mejoras ni a la devolución de la entrada que realice. ********************************************************* No necesita autorización de venta, ni para alquiler al ser curatela. Por tanto, a la espera de decisión de la parte económica para comenzar o esperar con trámite de procedimiento modificación de capacidad a tutela e internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-12','(Pedro)Conversación con Pilar, T. Soc. ESM Cáceres. +++Plantea SAD. En estos momentos no se está prestando este servicio desde los ayuntamientos y se podría pèdir por PIA pero se considera más adecuado el PIA ya solcitado de ingreso en CRR. Si este recurso no fuera posible, entonces se valoraría el SAD. +++De nuevo se contratará el catering, una vez la parte económica ajuste el dinero disponible. +++CITA EN ESM: 21 DE MAYO a las 10:50h MEDIANTE LLAMADA TELEFÓNICA con Juan Pedro (Psiquiatra), Ya lo han avisado por teléfono desde el Equipo. ······················································· Ana: Correo de Toni-Futuex (areasocial3@futuex.es ): "12/05/2020 Se recibe llamada del tutelado para informar que está de regreso al su domicilio en cáceres, tras haber estado varias semanas en el centro sociosanitario de Mérida. Explica que le han dado el alta porque ya ha pasado el confinamiento y dice textualmente: "la psiquiatra del sociosanitario me ha dicho que estoy muy bien de la cabeza para estar en casa”. Explica también que estaba planificado previamente el traslado a Plasencia pero el insiste en que a Plasencia no se va porque ya ha estado en el centro sociosanitario de dicha localidad y no quiere volver. Solicita que se reanude el servicio de catering lo antes posible y que también se le autorice para poder retirar dinero en efectivo. Con respecto a este último asunto se aborda en conversación con el usuario la cantidad que considera oportuno, haciéndole entender que si se contratan de nuevo los servicios de catering se debe reducir la asignación semanal con respecto a lo que estaba cobrando antes. En un principio retiraba 60 euros semanales que luego se redujo a 50, en conversación con el tutelado se acuerda la posibilidad de reducir la asignación a 40 €, explica que le costara mucho puesto que es una cantidad muy justa ya que fuma dos paquetes diarios y también debe comprar con ese dinero productos para el desayuno y la cena y productos de higiene y limpieza. Es cierto que es una cantidad bastante ajustada, pero accede al esfuerzo tras hacer cálculos con él y darse cuenta que no le queda mucho más dinero disponible de sus ingresos mensuales. Si aún asi se valora que la cantidad de asignacion es incompatible con el catering por el resto de pagos que tiene, se le trasladará que tendra que organizarse como antes de recibir el catering. Desde salud mental nos comentan que habian puesto en vuestro conocimiento la posibilidad de pedir ayuda a domicilio, supongo que la gestion de los recursos con este hombre es algo que habra que ver muy detalladamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-12','Ana: Llamada de Juan (625 895 394), dice que le han llamado del centro de salud, cree que la Dra. Consolación, pide que llame yo para hablar con ella. Como se le va la cobertura se corta la llamada. Intento llamar de nuevo pero salta el buzón de voz contínuamente. ······································· Conversación con Clara, TS CS Guadalupe (Despacho de Logrosán 927 360 769), Juan mantiene que el viernes 15 no tiene que acudir a CC al ESM, que se pondrá el inyectable en el CS-Guadalupe. Que ha recibido una carta de que su cita se pospone al 21 de mayo. Pero *en el JARA consta la cita del día 15. *Además Juan insiste en que para ir a CC tendrá que ir en ambulancia para él solo, no está dispuesto a compartirla con más gente y hacer ruta por todos los pueblos. Y eso no es posible. **Si no acepta esto tendrá que ir en autobús. ······························· Llamo a Pilar Martín, TS del ESM-CC (695 194 576): comprueba que la cita de Juan es el viernes 15 a las 12:00 h. Pero dice que el Dr. Jiménez Cano no está atendiendo de forma presencial aún, y que es posible que tenga la consulta por teléfono. **Me pide que se lo recurde mañana para que lo confirme con el médico. ···················· Llamo a Clara y le informo. ················································· Llamo a Juan, le comunico lo que me ha dicho Pilar, parece quedarse más tranquilo, no obstante si hubier algún cambio ya le llamaría. *Me lee la carta que le ha llegado, en la que dice que tiene la cita el "jueves 21 a las 10:5... casi a las 11 vamos" *Dice que no me fie de nadie del C.S. que "están todos metidos en Holocausto", que de Clara no se lo esperaba pero también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-12','Ana: Recibo llamada de Carmen Pons García, TS del SSAB de Zafra (924 554 601), va a enviar por registro el informe social solicitado para la revisión del CADEX y para la solicitud de plaza en C.D. *Me lo adelanta por email. Lo guardo en el expte. telemático y se lo remito a Pedro, Jefe Secc. CTAEX, quien acudirá a hablar a la Unidad de Recursos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-05-12','Ana: Llamada de Felisi (722 494 033), le recordó Jesús que llamara para recordar que le toca la asignación, le digo que no se preocupe que las compañeras lo tienen controlado. Aprovecha para charlar un poquito, Jesús ha empezado a trabajar en una empresa del pueblo. Se desahoga pues se ve un poco anguiada con las medidas preventivas frente al COVID, y desde que Jesús está trabajando no se le acerca ni da besos. Se queda más tranquila tras la conversación. Con repecto a su hijo Aitor, dice que hacen videollamadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2020-05-12','Ana: Llamada de Felisa Custodio, CAMF Alcuescar (927 121 951), en respuesta a mi correo: las últimas noticias que tiene de Mª Carme, es que despertó del coma, estaba estable y evolucionando bien, aunque está bastante desorientada. No obstante si averigua algo hoy o mañana me lo comunicará mediante correo-e. ····················································· Correo de Felisa: "Me dice mi Directora que la hermana ha informado al CAMF que Carmen ha dado negativo en la prueba PCR de covid. Continua ingresada, estable, refiere que ha tenido una subida alta de azúcar como posible motivo del ingreso hospitalario. Seguimos en contacto. Saludos." Lo guardo en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2020-05-13','Llamada de Felisa Custodio, CAMF Alcuescar (927 121 951), en respuesta a mi correo: las últimas noticias que tiene de Mª Carme, es que despertó del coma, estaba estable y evolucionando bien, aunque está bastante desorientada. No obstante si averigua algo hoy o mañana me lo comunicará mediante correo-e.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-05-13','SIDEX Tiene dependencia. Consultadas las solicitudes, tampoco arroja dato alguno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2020-05-13','(Pedro)Llamada de D. José Mª Flores, Director de la Residencia "Los Olivos" (924-310755 y 638-961228). +++Solicita información sobre qué hacer en caso de fallecimiento (no hay motivo alguno en estos momentos para pensar que pueda ocurrir acorto plazo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-05-13','TERESA: LAMA RAMON A LA COMISON PORQUE QUIERE HABLAR CONMIGO, NI AYER NI HOY ME COGEL EL TELEFONO, LE LLAMO TANTO AL NUEVO NUMERO QUE ME PROPORCIONO FUTUEX COMO AL QUE HA LLAMADAO A LA COMISION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-13','Ana: Llamo a Pilar Martín, ESM (695 194 573), salta el buzón de voz, le dejo un mensaje para que me devuelva la llamada cuando pueda. Pruebo a llamar a Salud Mental (927 213 730), pero no obtengo respuesta. ············································· Recibo llamada de José Luis, herman de José Manuel (687 581 061), su hermano quiere que le llame en relación a la lavadora y alguna cosa más. A parte aprovecha para decirme que, según le ha contado su hermano Jose Manuel, en el CSS no le han querido lavar nada de la ropa que llevaba, por lo que ha vuelto a casa con la maleta llena de ropa sucia, le digo que me extraña mucho y responde que a él no le extraña, porque también le ha contado que "un vigilante de seguridad le dio una paliza" y que se lo cree. ··················································· Vuelvo a llamar a Pilar Martín, ESM (695 194 573), plantea en modificar el PIA y solicitar SAD, José Manuel le ha dicho que lo acepta. Le recuerdo que la prioridad era CRR, lleva meses pidiéndolo y esperamos que valore cuando tenga lugar la subcomisión pendiente. Además José Manuel no tiene capacidad económica para asumir el copago, si también quiere mantenter el catering y una asignación semanal, pues debe seguir pasando las manuntenciones a su exmujer e hijos mientras un juez no diga lo contrario. Por otra parte, previo a un servicio de SAD, sería necesaria una limpieza en profundidad en su casa, y esto también supone un gasto. Propone que se le pida al ayto. por salubridad. ·················································· Conversación con Pedro, Jefe de secc. CTAEX: Consideramos que la prioridada es el recurso residencial. **Si a José Manuel llegan a concederle plaza en CRR y éste la rechace, haremos un escrito al Jdo. comunicándolo. *En cuanto al SAD, desde el SEPAD debe prevalecer la Promoción de la Autonomía, y José Manuel puede realizar las tareas del hogar, demuestra mucha autonomía para muchas cosas y para las domésticas también la tiene. A parte del copago, que no podría permitirse y del gato de la limpieza necesaria previa, que repercutiría en sus asignaciones periódicas y extras, entendemos que no es apropido destinar recursos públicos al alguien que no los aprovecha ni valora. No obstante, si José Manuel insistiese, se solicitarían un par de presupuestos de limpieza y se le explicaría que habría que reducirle de otros gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2020-05-13','TERESA: LLAMO A MERCEDES TS SOCIAL DE REFERENCIAC924 26 01 75/607 55 74 12) ME COMENTA QUE TOMAS ESTA CANSADO DE VIDA EN EL PISO, ES UN PSIO DE ESTANCIA TEMPORAL Y COMO EL LLEVA YA MUCHO TIEMPO EN EL PUES ESTA CANSADO DE VER SALIR Y ENTRAR A LA GENTE, COMENTA QUE NO ES EL RECURSO IDONEO PARA EL. COMENTA QUE TIENE AMITADES EN BADAJOZ QUE SERIA BUENO BUSCAR UN RECURSO POR LA ZONA, EL LE GUSTARIA PARTICIPAR EN LAS ACTIVIDADES DE EXPAINBA Y VIVIR EN UN PISO TUTELADO. ACTUALMETE SU EXPEDIENTE LO GESTIONA ROSA (637 35 33 64) EMAIL RGARAY.CDMEBA@CARITAS.ES ESCRIBO EMAIL A ROSA PARA COMENTARLE QUE VOY A SOLICIAR RECURSO RESIDENCIAL DE DISCAPACIDAD VIA DECRETO ME QUEDO A LA ESPERA ME ENVIE DNI Y CONFIRME SI TIENE SEGURO DE DECESOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2020-05-13','TERESA: RECIBO CORREO CON DOCUMENTANCIO SOLICITADA AL CAMP PARA TRAMITAR ORFANDAD DE RAUL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-05-13','Ana: llamo a Javier, Director del CRR-Plas. (677 407 640), de acuerdo con la conversación mantenida con Pedro, le explico que para iniciar el procedimiento de recuperación de la capacidad de Mª Atonia, deberían solicitarlo desde el CRR, como guardadores de hecho que son y técnicos que intervienen con ella en el día a día. Pedimos que estén seguros de que la remoción de la tutela no la va a dejar a ella en situación de desprotección, hay que valorarlo mucho y muy bien. Y en tal caso, necesitaríamos que nos enviasen un Informe completo y detallado en el que especifiquen los motivos en los que se basan para plantear la recuperación de su capacidad, total o parcial. **Javier expresa que en área en el quizá la ve más vulnerable es en el de la salud, pues tiene poca conciencia de enfermedad. **Le pido también que cuando acuda a la próxima consulta en Salud Mental, le solicite informe médico al repecto, en el que valore la idoneidad o no de iniciar el procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-05-13','Ana: Llamada de Pilar Cerrillo, TS de la Res. (618 90 85 06), han recibido la resolución de dependencia, le han reconocido Grado II, pero sólo conceden a Pedro 100€/mes como prestación económica vinculada al servicio de residencia, lo cuál nos resulta muy raro pues no es lo que se negoción en el PIA. *Pedro abona 1476,78 €. Me enviará la resolución escaneada por mail. *Quizá tengamos que solicitar una revisión económica. **Lo hablaré con Clara Gómez, jefa de secc. Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-05-13','(Pedro)Conversación con la Policía Local de Zalamea de la Serena (924-780032). +++Baja Feli para decirme que estaban tratando de hablar con la Comisión Tutelar. +++Llamo y hablo con D. Alfonso, Policía Local. Han conocido la sentencia que da la tutela a ambos hermanos (la de D. Pablo todavía no es firme) y quieren saber como nos vamos a encargar de lo que ellos, voluntariamente , se han encargado hasta ahora: llevarles la comida (comida y cena de la Residencia y desayuno por Cruz Roja), baño, limpieza de la casa, etc. +++++Les explico la capacidad de actuación de la Comisión y que estamos preparando el inventario (dos meses) y que la idea es solcitar el internamiento involuntario de ambos hermanos. +++++Seguirán prestando este apoyo mientras tanto. Informan que desde que se inició el confinamineto no consumen alcohol: "Estamos pasando con ellos la desintoxicación..." +++D. Alfonso comenta que D. Guillermo está muy deprimido, que no quiere levantarse de la cama. Tiene que hacerse una analítica este próximo viernes.Pido el nombre de las doctopras que atienden a ambos hermanos: +++++Dra. Leonor, Médica de D. Guillermo(no está trabajando durante la cuarentena por motivos que no vienen al caso). Está atendiendo a sus pacientes la Dra. Baldomera Rojas (83004), Médica de una localidad cercana. Dra. María Arévalo, Médica de D. Pablo (pendiente de firmeza de la Sentencia). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamo al C.Salud de Zalamea. Hablo con la Dra. Rojas: +++Tras explicar someramente el plan de intervención de la Comisión en el caso, le planteo la posibilidad de valorar un ingreso de D. Guillermo en la UHB de Vva.-Don Benito si su estado mental (depresión) así lo justificara, como una medida para atenderlo de manera más rápida que lo que podría ser la vía judiciallo antes posible. Considera que en caso de hacerlo, es posible que en la UHB no consideraran su derivación a CSS y volvería a casa. No obstante, hablará con los compañeros que lo concoecen más y me llamará. Dejo mi teléfono y correo de ctutelar: aviso a Teresa (Comisión) para que esté pendiente del caso (no existe posibilidad dedesvío de llamadas). +++LLAMADA de la Dra. Rojas. Ha hablado con la Dra. Antonia Romero (Coordinadora del C.Salud) y le ha comentado que D. Guillermo está mejor que nunca (en realción a la situación previa al confinamiento). Refiere la atención que se le está prestando desde la Polciía Local, quienes han avisado a D. Pablo de que como no limpie la casa (la Polícía lo ha hecho en otras ocasiones) lo van a llevar detenido. Esto hace que la casa esté muy limpia en relación a momentos anteriores. +++En estos momentos NO están consumiendo alcohol (debido al confinamiento, probablemente). +++Quedo con la Dra. en esperar al resultado de la analítica y seguir con los planes que la Comisión tiene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MONTAÑA'and apellido2='SANTOS'),'2020-05-13','Ana: Recibo llamada de Mariví Clemente, TS del CSS-Plas.: Comunica el el próximo domingo día 17 a las 9:00 h Juan ingresa en el HPVP-Plas. La intervención quirúrgica de cáncer de mama tendrá lugar el martes 19. *Ya han avisado a los familiares, un sobrino y hermano dicen que acudiderán, a pesar de residir en Madrid y existir la situación de crisis sanitaria actual (en Madrid continúan en fase 0). Desde el CSS le han enviado un escrito que esperan le sirva de salvoconducto. Mariví dice no conocer mucho al paciente, pues está en la Ud. de Larga Estancia y ella no ha llevado nunca dicha unidad. Pero cree que, al menos antes de la intervención Juan no necesitaría acompañamiento hospitalario. Qué sí que es un poco "indómito" y más que nada necesitaría que le guiaran un poco (por ejemplo para no salir a fumar...) Si el lunes no hubieran llegado los familiares, no avisarían por su hubiera que contratar algún servicio de acompañamiento hospitalario. ···························· Puesto que la última rendición es de hace más de un año, consulto mediante mail a la secc. ecca. la situación económica de Juan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-05-14','Ana: Llamo al ESM-Plas. (927 458 036 ), me comunican que Ana Benavente, TS, está teletrabajando, no tiene las llamadas desviadas. Le comunicarán que le he llamado para que me devuelva la llamada. ·························· Recibo llamada de Ana Benavente (620 275 323), le informo con respecto a la situación de Alfonso. El informe clínico habrá que solicitarlo por escrito, pero dependiendo del Psiquiatra lo pedirá de una u otra forma. Averiguará a qué médico corresponde y le preguntará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-05-13','Ana: Llamo al ESM-Plas. (927 458 036 ), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-14','Ana: Llamo a José Manuel (667 384 817), le explico que estoy a la espera de una respuesta de la secc. ecca. de la prouesta de para volver a contratar cáterin y reducir la asignación a 40€/semana. En cuanto a la lavadora que necesita, acudirá con Virgina a pedir un par de presupuestos. Y en relación al SAD, dice que no le conviene, que la cocina está muy mal y que no quiere que entre una mujer en su casa. Prefiere ir a CRR, a ser posible al de Mérida o al de CC, pero accede a que lo dejemos abierto, pues así tendrá mas probabilidades. ························································ Llamo a Pilar Martín, ESM (695 194 573): salta el buzón de voz. ·········································· Dr. Juan Pedro Jiménez Cano: dice estar ya "quemado" con este caso, que no entienden por qué le han dado el alta. Y que si no le conceden plaza en CRR, la única opción que queda es la Larga Estancia en el CSS, que no entienden por qué no quieren ingresarle allí. *Entiende que lo de la "voluntariedad" de los recursos de Salud Mental tendrá que cambiar algún día. ++++++++++++++++++++++++++ Carmen Gallego. Buenos días Pedro: espero que tú y los tuyos esteis bien ante la situación que estamos viviendo. Me ha llamado Clara Nestares para pasarme el expdt de José Manuel Romero Mediavilla y negociar una RV PIA como prioritaria por emergencia social; este hombre, según la Trabajadora Social de Salud Mental necesita una Ayuda a Domicilio hasta que pueda entrar en un CRR, que es lo que tiene tb solicitado. Le paso el caso a una Terapeuta del Equipo de Cáceres, Marisa González Sánchez y que contacte contigo telefónicamente, ya que entiendo que la negociación es con vosotros, pero previamente quería anunciártelo. Un saludo. Carmen Gallego Morillo Jefe Sección Dependencia I Gerencia Territorial de Cáceres SEPAD +++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada de MARISA, Técnico Pía (610-333553 es personal, pero ahora lo utiliza para trabajar///correo-e: marialuisa.gonzalezs@salud-juntaex.es). +++Tramitará revisión PIA para CRR y SAD (45h/mes con cláusula suspensiva). +++Manifiesto mis dudas al respecto de la viabilidad del SAD por la actitud de José Manuel a aceptar cualquier tipo de ayuda que le suponga aceptar unas mínimas reglas de comportamiento. ++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Pilar (ESM de Cáceres): +++No se puede creer la conversacaión que José manuel ha tenido con Ana. +++Tras hablar de nuevo con él, me dice que él sí quiere el SAD (¿?) Sin comentarios. +++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamo a José Manuel. +++Niega haber habaldo esta mañana con Ana. +++Le "refresco un poco la memoria": "Ah, sí, que le he dicho que tenía la lavadora estropeada..." Le "refresco un poco más la memoria": "Es verdad, que le he dicho que no quiero que entre en casa ninguna mujer a limpiar...ES que me han dado una pastilla para la esquizofrenia y tengo la cabeza muy revueta..." +++Si no aprovecha esta última oportunidad, le indico que pondremos su situación en manos del Juzgado inidcando que no es posible intervenir con él de ninguna de las maneras dada la actitud que demuestra una y otra vez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-05-14','(Pedro)Convesración con Ana, T. Soc. Hospital "Tierra de Barros" (89325). +++No nos ha llegado el consentimiento informado de Dª Anica como me dijo ayer Juana (Comisión) que nos remitirían. +++No nos lo ha enviado porque el Dr. Vázquez, que es quine la ateiende, va a hacerle una resonancia y según el resultado quizá no haga falta solicitar el consentimiento para otra prueba. +++Seguiremos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-14','(Pedro) Conversación con Silvia (P.I. Cabeza del Buey). +++Han llevado a Andrés al Hospital para hacerse la prueba del PRC. Probablemente mañana tengan los resultados. Nos informará. +++Están muy preocupados por la situación y solcitan se agilice el tra´mite de cambio de perfil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-14','Ana: Llamo a Pilar Martín, ESM (695 194 573), como salta el buzón de voz, llamo al ESM: me dicen que no está. Me pasan con el Dr. Juan Pedro Jiménez Cano: Expresa que no conoce al paciente, pregunta si le han derivado con él para una segunda opinión, le explico que no, que han pedido el cambio permante. Pregunta el motivo y aprovecha para que le cuente un poco sobre la situación. *La cita de Juan está fijada para el día 15, no sabe nada de la carta que dice Juan. Entre hoy y mañana le llamará el médico residente, pues la primera vez lo hacen así. *En cuanto al inyectable le digo que acudirá a ponérselo mañana en el C.S. de Guadalupe. ·························································· Llamo a Juan (625 895 394): le confirmo que no tiene que ir el día 21 a Cáceres, que la cita es mañana, pero no será presencial, entre hoy y mañana le llamarán por teléfono un médico compañero del Dr. Jiménez Cano. *Le indico que mañana cuando acuda a ponerse el inyectable al CS debe llevar puestos los guantes y la mascarilla que los que le proporcionaron en el CSS. ································· Llamada de Clara, TS CS Guadalupe (Despacho de Logrosán 927 360 769), le ha llamado Consoli, me piden que llame a Juan y le explicque que para ponerse el inyectable mañana tiene que acudir a las 13:15 h y cuando necesite ver a Consoli deberá pedir cita previa, pues por protocolo están organizando todo para que los pacientes acudan de uno en uno y así reducir riesgos fretne al Covid. ·························· Llamo de nuevo a Juan varias veces, pero salta el buzón de voz, finálmente le dejo un mensaje explicándoselo. ················· Envío un correo a Toni, para que si Teresa consigue hablar con él hoy se lo explique. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Consigo hablar con D. Juan a última hora. Le indico que mañana tienme que ir a ponerse el inyectable a las 13:15h, con mascarilla y guantes. La convesración se entrecortaba un poco pero me ha dado tiempo a confirmar la recepción del mensaje. +++Está también pendiente de la llamada de su Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-05-14','(Pedro) Correo del CRR de Mérida (14-05-2020) +++Ángel Pinilla: Bien, de buen humor, adecuado, más calmado. Está en lista de espera para fisioterapeuta, le llamarán cuando abran el servicio en Clínica Diana. Salió por primera vez a un bar con tres compañeras más y profesional y lo hizo MUY BIEN. Poco a poco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-05-14','(Pedro) Correo del CRR de Mérida (14-05-2020). +++Antonio Merchán: Muy adecuado también. Ha salido y con él ha sido mucho más costoso que haga caso a indicaciones aunque con mucha insistencia se ha conseguido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-05-14','(Pedro) Correo del CRR de Mérida (14-05-2020). +++Luisa Rodríguez: Mañana tiene cita con traumatología de forma privada. Sigue manifestando querer percibir más dinero. Ha tenido cambio de pauta por su Psiquiatra de referencia. Ella misma reconoce que no hace nada, que pasa mucho tiempo en la habitación. Afirma echar de menos la libertad que tenía de poder salir a la calle a tomar su café, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-05-14','(Pedro) Correo del CRR de Mérida (14-05-2020). +++José María Guillén: Muy adecuado en las salidas, muy buen humor, colaborador. Mucho mejor que antes de la pandemia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-05-14','(Pedro) Correo del CRR de Mérida (14-05-2020). +++María Dolores Fernández: Los primeros días de esta semana han sido regulares, con insultos a profesionales, con el tema recurrente de querer irse a su casa, con llamadas de atención respecto a su salud (decía tener diarrea pero al rato para comprar en el quiosco del CRR no...) Hoy parece que mejor, aunque bastante crítica con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-05-13','(Pedro).Llamada de Mª Dolores para pedirme disculpas por haberme insinuado que si no le dabamos "el alta" se iba a suicidar. +++Tras la conversación con ella el día 12, llame al CRR e informe a Cristina del estado en el que parecía encontrarse Dolores para que estuvieran pendientes de ella. +++"No voy a hacer nada de eso, te lo prometo y me voy a quedar aquí, porque ahora me han puesto en una haboitación sola y estoy muy bien..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2020-05-14','miguel, por indicación de Pedro a preparar la venta del inmueble del tutelado, para lo cual y a efectos de que se pueda iniciar procedimiento judicial al respecto, procedo a preparar la solicitud de abogado de oficio y documentación que la acompaña (pido a Pedro y Alberto informe de servicios sociales, empadronamiento, gastos mensuales, saldo actual...). Así mismo solicitará prueba pericial para valoración del bien a efectos de su futura venta. Una vez que recibamos autorización de venta habrá que ponerlo en una inmobiliaria para su venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-05-13','miguel, hablo con Alberto para pedirle que hable con Sindy(625712629), pareja del que quiere comprar o alquilar la vivienda. Dependiendo de si hay o no acuerdo se procederá a poner la vivienda en venta en una inmobiliaria o se le venderá a los interesados. Alberto me dirá lo que sea para comenzar ya o no con la solicitud de modificación de capacidad (pasar de curatela a tutela y paralelamente solicitud de internamiento involuntario)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2020-06-16','Ana: Una vez cumplimentado la Solicitud de Dependencia, la pongo para la firma del D.Gerente. ···· **Pero el informe médico que nos remitieron en su día (que también se lo dije a Mariví, TS-CSS, mediante conversación telefónica en marzo), no es el del modelo de la valoración de Dependencia. El que nos remitieron no sirve!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CORBACHO'and apellido2='GALINDO'),'2020-05-14','miguel, llamo al juzgado nº1 de Almendralejo y comunico lo siguiente a la parte económica a Alberto: comentarte que he hablado con el Juzgado nº1 de Almendralejo y me comentan que el procedimiento de ejecución que ha solicitado Caja Rural de Almendralejo (Procedimiento de títulos no judiciales 109/2018) que el estado en que se encuentran es que han embargado la nómina del hijo de nuestros tutelados y de la exnuera Tony Silvero. La solución pasa por intentar llegar a un acuerdo con Caja Rural de Almendralejo o no hacer nada porque a nuestros tutelados no les afecta porque son insolventes. En el peor de los casos subastarían la vivienda. Hay que olvidarse de ponerlo en venta ya que tal y como me ha recordado la funcionaria de justicia, al existir un procedimiento de ejecución no se puede vender porque sería un delito de alzamiento de bienes. Pensad entonces que como mucho la opción pasa por llegar a un acuerdo con Caja Rural de Almendralejo (hablando con su procuradora) y ofrecer una dación en pago no es viable porque el valor fiscal (que siempre es inferior al de mercado es de 40.143,08€, y ten en cuenta que las cantidades reclamadas son de 15.990,46€ de principal+4.797€ de intereses de demora, sin perjuicio de las futuras costas procesales (abogado y procurador).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2020-05-14','miguel, llamo al juzgado nº1 de Almendralejo y comunico lo siguiente a la parte económica a Alberto: comentarte que he hablado con el Juzgado nº1 de Almendralejo y me comentan que el procedimiento de ejecución que ha solicitado Caja Rural de Almendralejo (Procedimiento de títulos no judiciales 109/2018) que el estado en que se encuentran es que han embargado la nómina del hijo de nuestros tutelados y de la exnuera Tony Silvero. La solución pasa por intentar llegar a un acuerdo con Caja Rural de Almendralejo o no hacer nada porque a nuestros tutelados no les afecta porque son insolventes. En el peor de los casos subastarían la vivienda. Hay que olvidarse de ponerlo en venta ya que tal y como me ha recordado la funcionaria de justicia, al existir un procedimiento de ejecución no se puede vender porque sería un delito de alzamiento de bienes. Pensad entonces que como mucho la opción pasa por llegar a un acuerdo con Caja Rural de Almendralejo (hablando con su procuradora) y ofrecer una dación en pago no es viable porque el valor fiscal (que siempre es inferior al de mercado es de 40.143,08€, y ten en cuenta que las cantidades reclamadas son de 15.990,46€ de principal+4.797€ de intereses de demora, sin perjuicio de las futuras costas procesales (abogado y procurador).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-05-14','TERESA: EMAIL DEL CRPS Me acaba de confirmar el Gerente del Centro que Beatriz ha sido ingresada en la UHB de LLerena: La ha acompañado esta mañana al hospital y según me comenta despues de la valoración con la psiquiatra se queda ingresada. Esperemos que en esta ocasión el alta se produzca cuando haya una estabilidad real QUEDO PENDITE LA ANULACION DE LAS LINEAS QUE HA CONTRATADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-05-14','Ana: Correo de Icíar, CTAEX: "Mira, hemos comprobado la cuenta de Juan Ángel y en Caixabank le está entrando en abril una pensión de orfandad por 208,90 €, pero la otra, la PF de Hijo a Cargo no le ha entrado, y en Ibercaja que es la cuenta nueva que le abrimos no le está entrando nada como te dije. No sé qué estará pasando." ····························· Llamo al INSS Ba - PFHC (Gloria: 924 21 61 52 / Begoña: 924 21 61 41) vavias veces a cada uno, pero no obtengo respuesta. ···························· En cuanto al a Pensión de Orfandad, tal y como me solicitan desde la secc.ecca. cumplimento el modelo de Comunicación de variación de datos bancarios al INSS y pido a Pedro, Jefe Secc. CTAEX, lo ponga para la firma del D.Gerente. ······································· Pido a Juan Pedro, admvo. CTAEX, que el lunes ponga para registro de entrada la solicitud original y copia (para que nos la devuelvan registrada), junto con la fotocopia del DNI del D.Gerente y la aceptación del cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2020-05-14','(Pedro) Consulta al Juzgado de 1ª Instancia Nº 1 de Logrosán, sobre los dos procedimientos de División de Herencia en trámite: el 19/2020 y el 20/2020. +++Son dos procedimientos distintos, porque uno se refiere al fallecimiento del marido y el otro al de la esposa. No me saben explicar por qué no han abierto un solo procedimiento. +++INFORMACIÓN: han notificado vía Lexnet (no nos ha llegado nada de la Abogacía, aún) la SUSPENSIÓN DE TODOS LOS SEÑALAMIENTOS DE MAYO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-14','TERESA: CORREO SILVIA DIRECCION PI Os informo que hoy dan el alta a Andrés Silva Bonifacio (Paula, como quiere que le llamemos) de la UHB de Mérida. Nos han avisado esta mañana. La situación es la siguiente: desde el lunes nos informa el Centro de Salud que a todos los profesionales que se vayan a incorporar presencialmente (estaban teletrabanjado), es necesario hacer prueba PCR. El procedimiento es que en el CS de Cabeza del Buey se puede hacer en el mismo día de analíticas (lunes, miércoles y viernes). El resultado tarda aproximadamente 1 día. Hay que comunicarles por tanto con antelación la incorporación, para poder solicitar la prueba, hacerla y tener el resultado antes de que se incorporen presencialmente. Andrés (Paula) viene con una PCR de hace una semana y un análisis de anticuerpos de hoy. Aun así, se hace necesario repetir aquí la PCR para evitarle el tiempo de aislamiento. Esto no se lo podemos hacer hasta el viernes. El personal va a ir mañana con carácter extraordinario a mediación de Salud Pública a hacer la prueba al Hospital de Talarrubias para intentar agilizar su incorporación y poder sustituir al personal de residencia. De momento hasta obtener resultados, vamos a proceder a su aislamiento, teniendo a 2 personas por turno con él. Por tanto, urge revisar la ratio y el perfil de Andrés. Necesitamos al día 4 personas que no deben luego volver a entrar en Residencia, es decir, de aquí al viernes que tengamos resultados como poco vamos a sacar a 6 trabajadores de residencia desde hoy al viernes, lo que ahora mismo es un lujo para compatibilizar con descansos. Debemos tener en cuenta el estado de estres al que están sometidos estos trabajadores. Ruego se establezca con carácter de urgencia una Comisión Técnica tal como os pedí la semana pasada (adjunto), por favor, necesitamos coordinar los apoyos con vosotros. Muchas gracias por vuestra disposición, sé que estais trabajando mucho con este tema. Atentamente, Silvia Cortés Rengel','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-05-15','Ana: Recibo llamada de Felisis (722 494 033) un poco enfadada porque dice que fue al banco ayer y esta mañana y aún no le han ingresado el dinero en la cuenta de su cuñado. ················ Pregunto a las compañeras de la secc. ecca. la transferencia la harán el lunes. ···························· Llamo a Felisi y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-05-15','Ana: Llamo al INSS Ba - PFHC (924 21 61 52), me atiende Marisol. Dice que el banco ha devuelto todos los recibos desde enero. No sabe por qué será, en nº de cuenta que le aparece es el de Caixaban (el mismo del inventario). Nos parece muy raro pues la P.Orfandad sí se la continúan ingresando. *Me envía por email, en PDF, el documento de Solicitud de abono de mensualidades impagadas. Me indica que sirve sólo para PFHC. ··························· Se lo envío a Icíar, quién el martes lo pondrá para la firma y a posteriori para Registro de Entrada con copia para que nos devuelvan registrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-05-15','Ana: Recibo llamada de Damián (622 834 876), dice que lleva un par de días "muy malito", que ayer le dió un ataque de ansiedad, le llevaron al médico y le han cambiado la medicación. Por otra parte dice que el lunes envió por correo ordinario una serie de documentos, quiere saber si han llegadeo bien. *Le indico que el lunes se lo confirmaremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-15','Ana: Llamada de Juan (625 895 394), dice que ya se ha puesto el inyectable y que ha hablado con el Psiquiatra, pero que no era el que le dijimor. Le recuerdo que le dije que la primera vez le llamaría un compañero del Dr. Jiménez Cano. Según refiere sólo le ha preguntado cómo está, qué medicación toma y poco más. Le ha dicho que de momento no tiene que acudir a Salud Mental a CC y que ya le volverán a llamar. *En cuanto al Cátering le recuerco que hoy es el último día. Le pregunto que si después de la experiencia le gustaría que contratámesos uno privado y su respuesta es un rotundo NO. Añade "así como lo que ellos quieren y yo prefiero comer lo que yo quiero y me apetece". ············································ Recibo llamada de Clara, TS del C.S., diciendo que Juan se ha presentado en el C.S. diciendo que cómo su teléfono no iba bien, el psiquiatra iba a llamarle al C.S., por lo que han tenido bloqueado el tlf. y eso no puede ser, pues puede surgir alguna urgencia y es el número al que llama la población. Exprea que llama más para deahogarse, que para otra cosa... en cualquier caso le digo que eso lo tiene que resolver desde el C.S. con el E.S.M. ······················· En cuanto al tlf. de Juan, si él quisiera se podría plantear el cambiar de comañía de teléfono (si el problema fuera la cobertura) *su tlf. es de prepago (tarjeta), o cambiar de terminal si éste fuera el problema. *Solicitaré a Toni-Futuex, que lo valore Teresa, Delegada, con Juan cuando acuda a visitarlo a Guadalupe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-15','Teresa: HABLP CON LOLA TS, ME COMENTA QUE ANDRES SE ENCUENTRA BIEN Y TRANQUILO. YA ESTA PARTICIPANDO EN LAS RUTINAS DEL CENTRO PUES HA DADO NEGATIVO EN EL PCR LOLA ME COMENTA QUE HABRA UNA REUNION DE LA COMISION TECNCA EL PROXIMO 28 DE MAYO EN LA CUAL QUIEREN QUE PARTICIPE ALGUIEN DE LA COMISION TUTELAR, ESTMOS A LA ESPERA DE SER CONVOCADOS ARCHIVO LOS INFORMES DEL ALTA DE UHB EN SU EXPEDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-05-15','Ana: Recibo llamada de Ana Benavente (620 275 323): La Psiquiatra que Corresponde a Alfonso es la Dra. Mª Victoria Gómez Tomé, Coordinadora de la Ud. de Psiquiatría. El informe clínico habrá que solicitarlo por fax al nº 927 458 046, deberemos especificar lo que queremos que conste en el mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-18','TERESA:Ayer domingo Paula se encontraba mal, había intentado tirarse por el balcon pero la cuidadora lo agarró, le dieron el rescate y habló con la psicóloga, se quedó tranquila. Habló con ella otra psicóloga para que Begoña le llamará y le diera ánimo. Pero por la tarde llamaron otra vez, ha vuelto a intentarlo y expresa que se encuentra mal. Activan el 112 para que sea el médico quien valore la situación. Finalmente lo derivan a la UHB ++++++++++++++++++++++++++++++++++++++ (Pedro)Conversación con David Jimeno, Psiquiatra de Andrés. +++Tras comentarme sus planes de ingreso unos días y alta si se encuentra bien le planteo la necesidad de que Andrés pase un tiempo en un recurso con capacidad de contención, a lo que inmediatamnete David manifiesta su total acuerdo, planteando la UDHAC como recurso más adecuado. +++Plantea que se convoque una Subcomisión de Casos para tratar el tema, algo que le comento ya está Soraya sobre ello. +++Informo de esta conversación a Soraya, a quien envio los Informes de la estanbcia de Andrés en el CARSI de julio a diciembre de 2017. +++Teresa envía esos Informes también a Plena Inclusión de Cabeza del Buey.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-05-18','(Pedro)Se solicta informe clínico por fax nº927 458 046 en el día de la fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-15','Ana: Conversación con Belen, secc. ecca. CTAEX, me comunica que Pilar tiene un embargo de 20€/mes, aún no saben de qué. *Mientras siga percibiendo la LISMI, pasarán al centro todos los meses 100-110 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-18','(Pedro)Comunican por correo-e el ingreso de Andrés en la UHB de Mérida. Correo-e: +++buenos días Volvemos con Paula Ayer domingo Paula se encontraba mal, había intentado tirarse por el balcon pero la cuidadora lo agarró, le dieron el rescate y habló con la psicóloga, se quedó tranquila. Habló con ella otra psicóloga para que Begoña le llamará y le diera ánimo. Pero por la tarde llamaron otra vez, ha vuelto a intentarlo y expresa que se encuentra mal. Activan el 112 para que sea el médico quien valore la situación. Finalmente lo derivan a la UHB saludos. ++++++++++++++++++++++++++++++++ (Pedro) Intento hablar con David Jimeno, su Psiquiatra, pero se encuentra atendiendo una urgencia. Le dan mi número para que me llame.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-06-15','TERESA ARCHIVO RESOLUCION RECONOCIMIENTO ATP CON EFECTOS ECONOMICOS DESDE EL 1/02/20 593,40 ERUOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-05-18','(Pedro)Llamada de Jorge (Dependencia Mérida). 669312521 (Teletrabajo). +++El contrato de Residencia que tienen es el de 2005. +++SE pone a la firma el documento de solicitud de cambio de datos. Ana solicitará a la Residencia el contrato actualizado para adjuntarlo a la solcicitud de cambio de datos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-05-18','Ana: Llamo a Rosa, TS Ayto. de Plas. (600 478 433), confirmo el nuevo domicilio de Desi: C/Tomás del Barco, nº4, 4ºB. Barrio de San Miguel. Plasencia. Me comunica que esa zona la lleva su compañera Puerto Ramos: 600 449 238. Me indica que de L-X es mejor llamar a última hora de la mañana, pues tienen atención, o llamar J o V. *Llamo a Puerto, le informo sobre la situación del matrimonio y la nueva dirección. Acordamos que le facilitaré su número a Futuex, para que cuando puedan y consideren oportuno se pongan en contacto con ella y por si quisieran hacer alguna visita conjunta de seguimiento más adelante, una vez haya pasado la situación de crisis sanitaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='SANCHEZ'and apellido2='GARCIA'),'2020-05-18','coral.La única hermana que se interesa por ella vive ne Aldea Moret, c/ sena, 22 bloque 8. (676897592 y 669138791)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-18','Ana: Recibo llamada de José Luis (687 581 061), hermano de José Manuel, éste quiere que le llame. Al parecer se queja de la asignación que se ha acordado de 40€ semanales. Le indico que si quiere tener cáterin es la única manera, pues con el resto de gastos que tiene que afrontar no le da para más la pensión. *Le recuerdo que tampoco quiere acudir al Comedor Social, como se le ha ofrecido en otras ocasiones. ················································· Pido a Juan Pedro,admvo. CTAEX, que solicte Cdo. de Convivencia al Ayto. de Cáceres. para la solicitud de Prestación Económica vinculada al SAD. Pedro pondrá a la firma las Aceptaciones PIA y el alta a terceros. ·· Yo contactaré con alguna empresa de SAD acreditada. ·················································· Conversación con Toni-Futuex: José Manuel le ha dicho a Virgnia, Delegada, que *ya no quiere el cáterin, que prefiere tener 60€ como antes y prescindir de sericio de caterin. Pero Virginia también informa de que antes de haber tenido dicho servicio comía fatal. ······································ Llamo a Jose Manuel (667 384 817), dice que está esperando a poder retirar el dinero. Además dice que no quiere el caterin, pues no quiere tener sólo 40 € a la semana. Al preguntarle si comía bien antes de tener el caterin, reconoce que no. Le indico que por su salud es conveniente que coma bien, a lo que responde aue "no le importa su salud". Le replico que en la Comisión, como Tutora, si nos importa, y preferimos invertir más en alimentos saludables que en tabaco. Qué de hecho debería plantearse el reducir su consumo diario de tabaco. "Ya, ya", responde. Tras decir que "está hecho un lío", finalmente pide que se le contrate el catering. ···································· Como no consigo contactar con Pedro, CTAEX, llamo a Toni y le pido que sigan adelante con el cáterin. Como con el último ha habido dificultades cuando se produjo el ingreso de José Manuel en el CSS-Mér., acordamos contratar el Caterin "Qué bueno", un poquito más barato y que ya conocen de otros casos. ························································ En cuanto a empresas de SAD, Toni me envirá un listado con referencias de empresas de CC con las que ya han contactado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-05-18','(Pedro)Vivienda de Hinojal nº 4. Escritura del 04 de junio de 2008. Notario D. Gabriel Arasa Vericat (Notaría de la calle Obispo, Badajoz). PROTOCOLO 1659. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamo a Sindy. No me coge el teléfono. Volveré a intentarlo.eN CASO DE NO CONTESTAR DEJAR MENSAJE EN BUZÓN. +++Comento con Sindy la situación: tenemos que ver la viabilidad del alquiler y/o compra de la vivienda al tratarse de una VPO con una carga por préstamo hipotecario. +++DATOS DEL INTERESADO: D. Pablo Esteban Núñez Olguín. C/. Federico González Moreno, portal 6, 2º F (Montijo) DNI: 80243770-J. Trabaja en Agroconesa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-05-18','(Pedro) Llamada de Ana, Plena Inclusión de Zafra. +++Natalia ha dado problemas este fin de semana y los abuelos han dicho que tiene que volver al centro ¡YA!. +++Tiene que cumplirse el protocolo de retorno: ya lo hablaron con Manuela y Natalia está pendiente la prueba de PCR. Y una vez vuelva al Centro deberá estar en aislameinto una semana. +++Les pido que pongan esto en conocimiento de la Unidad de Programas para que sean conocedores de la situación. +++Pido que nos envéin por correo-e las incidencias de este fin de semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-05-18','(Pedro). Llamo a Miriam al 645-049410. No me coge el teléfono. Volveré a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='REYES'and apellido2='MIEL'),'2020-05-18','(Pedro) Conversación con Maribel, T. Soc. del CSS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2020-05-18','Ana: llamo a Longina, T.S. de Madrigalejo (672 614 686), en relación al Cdo. de PFHC que nos solicitó. Me dicen que hoy está en Campo Lugar. Llamo al Ayto. 927 35 00 02, me comunican que se ha tendio que marchar por ponerse enferma. *Le envío un correo-e (ssbmadrigalejo@hotmail.com), explicándole que no disponemos del Cdo. de PFHC,a pesar de haberlo solicitado antes de decretarse el estado de alarma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-05-18','Recibido EXPEDIENTE de CAM Francisco Pizarro. Lo archivo en carpeta social de su expediente. +++TELÉFONO CAM FRANCISCO PIZARRO.........:927 02 76 00','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-05-18','Ana: Recibo llamada de Damián (622 834 876), le confirmo que en la CTAEX hemos recibido los 2 sobres con documentación que envió. Ya se pondrán en contacto con él los compañeros cuando lo estimen oportuno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-05-18','Ana: Recibo llamada de Javier, Director del CRR (677 407 640); Emi acudió a la óptica el primer lunes que se podía (Fase 1). Mandó a arreeglar las gafas de ver, sin solicitar y remitir como se le dijo presupusto previo. Desde el CRR para asuma las consecuencias han acordado con ella que pagará el arreglo con su asingación. Son 60 €, para lo que le reducen la asignación diaria 2€, en 30 días las habrá pagado. ················· *Pero luego ha encargado a la misma óptica (Opticalia) unas gafas de sol graduadas, sin haber remitido tampoco previamente a la secc. ecca. de la CTAEX los presupuestos correspondientes (como también se le explicó días antes). Las gafas cuestan 229€. Javier enviará un correo al respecto al ctutelar@ ······························································· Finalmente se decide que Emi tiene que pagar las gafas con su próxima asignación mensual, pues las encargó ella sin enviar presupuesto previo y sin autorización, a pesar de habérsele indicado tanto desde la CTAEX como desde el CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-05-18','miguel, tras llamada a 3 bandas con Amalia, Pedro y yo, quedamos en que yo me haré con esos certificados de Precio Máximo Legal y Autorización de Venta de la Consejería de Fomento, para lo cual como dije en el email del viernes necesitamos las escrituras de Compraventa. Dichas escrituras me confirma Amalia que si no es de las que trajo en su día, no las tiene... Por tanto yo intentaré que la notaría me de una copia simple. Llamo sin éxito a la notaria, así que les envío un email para me remitan copia simple. Una vez me llegue pagaré la tasa para pedir los certificados a Fomento y cuando lo haya hecho le digo a Pedro que le avisaré.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-05-15','miguel, tras verificar los emails de Amalia y Alberto, compruebo que al referirse a la vivienda de la c/El Hinojo, dicha vivienda según nota simple tiene muchas limitaciones al tratarse de VPO, y fue adquirida en 2008, por lo que tiene derechos de tanteo y retracto a favor de la Junta de Extremadura. Por tanto, para vender hace falta pedir a Consejería de Fomento Certificado de Precimo Máximo Legal y en caso de que se transmita (alquiler con opción de compra o venta) hay que pedir Autorización de Venta a la Junta. Por otro lado, y tal como les indico por email en Catastro no aparece a nombre de él ni de los padres dicha vivienda. Intentaré hablar con Alberto a ver si en los recibos de IBI aparece la referencia catastral.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-18','Ana: Susana, TS de Casa Hptal. Santiago de Zafra, me remite escaneado por mail Informe de Salud + Índice de Barthel, para la Valoración de Dependencia (Modelo oficial SEPAD). Lo guardo en el expte. PC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-05-18','Ana: Recibo correo de Reme, TS Infancia y Familia, (remedios.venegas@salud-juntaex.es): "Buenos días Ana Me pongo en contacto contigo para informar de la situación de Aitor en el CAM. El jóven está intranquilo por la incertidumbre que tiene acerca de su futuro, de cuando se marcha al recurso del SEPAD, no quiere continuar en el CAM y verbaliza querer marcharse porque es mayor de edad. No sé si habreis contactado con él, creo que sería conveniente, aunque sea de forma telefónica que tengais una conversación con Aitor y le expliqueis su situación jurídica, orienteis y ayudeis a resolver sus dudas. He llamado a Maribel del SEPAD y me dice que no está habiendo ingresos en los Centros por lo que no se prevee que a corto plazo Aitor vaya a salir del CAM. Consideramos que Aitor debe salir ya del Centro de Menores porque no es su sitio y no evoluciona. Un saludo" ··························· Mi respuesta: "Buenas tardes Reme, Entiendo que Aitor quiera salir del CAM a la mayor brevedad, si bien es cierto, como ya sabéis, el acceso a recursos no depende de CTAEX y dadas las circunstancias actuales, como te ha comentado Maribel, el ingreso va a tardar más de lo que nos gustaría. Intentaremos llamarle al centro para al menos hablar con él y explicarle, lo que supongo que ya le habrán explicado, bien las educadoras, bien el director del CAM. No obstante si esto le ayuda a rebajar el nivel de ansiedad/angustia bien está, así lo haremos. Pero me temo que no podremos decirle nada nuevo. Pongo en copia a Pedro, Jefe de sección, para que esté al corriente. Seguimos en contacto. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='REYES'and apellido2='MIEL'),'2020-05-19','EXITUS Amalia informa por correo electrónico: "Buenos días Julio , te confirmo , la señora , Manuela Reyes falleció ... el CSS de Mérida se olvidó de comunicárnoslo. Ha hablado Pedro con Maribel , la TS , para que nos envíe , cdo de defunción o algún escrito en el que se indique lo sucedido, para poder proceder a realizar la declaración anual de cuentas. En cuanto yo lo reciba se lo pasaré a las compañeras . Por favor , copia y pega este comunicado en la intranet de Manuela , sigo sin acceso. Un saludo"** Se procede a dar la baja. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Esta señora falleció el 13 de noviembre de 2019 en el CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-05-19','Ana: Dado que no consigo contactar con Pilar Cerrillo, TS de la Res. del Casar CC (618 90 85 06), le dejo un mensaje en el buzón de voz y le envío un correo electrónico (calidad@grupociudadjardin.com) solicitándole un cotrato actualizado en que conste el precio de las últimas facturas y la fecha desde la que viene abonando dicha cantidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-05-19','(Pedro) Llamada de Luisa, T. Soc. (664-493608).SE incorpora hoy al trabajo presencial. +++Ha recibido la solcitud de informes para inventario de D. Guillermo. No sabe si con la que ya envió (antes de ser tutores) es necesrio. +++Le pido que envíe todo lo que se pide en el escrito y que luego le llegará otra referida a D. Pablo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada de la Baldomera, Dra. del C. Salud (83004). +++ANALÍTICA: PERFECTA. No la enviará por correo-e. +++Refiere que en estos momentos D. Guillermo se muestra muy receptivo y tranquilo, por lo que cree que podría ser un momento adecuado para promover su ingreso voluntario. Le dirijo al ESM de su zona para que si voluntariamente acepta el ingreso en la Unidad de deshabituación alcohólica del CSS de Plasencia pueda ser trasladado allí. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)CEDEX CASTUERA: llamada de Ricardo Bueno, Médico (81837). +++La Dra. Baldomera ha derivado el caso al CEDEX. Para intentar derivación al CSS de Palsencia (Unidad de ddeshabituación alcohólica). +++Ricardo enviar a Baldomera la Hoja de Ingreso en dicha Unidad. +++Le explico los planes de la Comisión: paso del CSS de Plasencia a Centro de Mayores (si la situación clínica lo permite y aconseja). Ricardo insiste en que entre un centro y otro no','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-05-13','Ana: Recibo llamada de José Manuel Correa, nieto de Manuela (927 582 309 / 620 67 33 71), en relación a la obra pendiente en la vivienda. Dice que ya se envió el Informe de Javier, el Perito del Ayto. y que Gloria - Futuex, ha enviado ya 3 veces presupuestos de albañiles. También acudió a hablar con Pilar, TS del Ayto. quien le dijo que el albañil debe estar sujeto a las indicaciones del perito. **Les está entrando agua en casa cuando llueve, urge la reforma.*En cuanto al Covid, dice que cuando vayan a hacer la obra no habrá problemas de contacto, pues la obra es en la entrada y en la habitación que está en la parte delantera de la casa y él ya ha preparado todo para que puedan estar en la otra parte de la casa. Le digo que consultaré el expte. no recuerdo haber visto los presupuestos, preguntaré sino a la secc. ecca. **En cuanto a la solicitud de la subvención, Pilar les facilitó la documentación al respecto. Le indico que ella puede presentar la solicitud, no tendremos inconveniente en recabar la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-05-18','miguel, conforme consulta de Ana de la firmeza de la autorización judicial para el desbloqueo de cuentas de valores, hablo con Juan Pedro para que reclame al juzgado dicha firmeza','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-05-19','miguel, llega la firmeza para el desbloqueo de cuentas y le reenvío dicha resolución al Santander por email','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-05-14','Ana: Nueva llamada de José Manuel Correa, nieto de Manuela (927 582 309 / 620 67 33 71), ha vuelto a consultar con el ayto., el albañil que finalmente se contrate tiene que proceder bajo proyecto de obra del técnico, por tanto los presupuestos anteriores que envió no sirven (era para "un parche"). Solicitarán nuevos presupuestos. Indica que hay otra persona del ayto. con la que también se puede contactar en caso de ser necesario: Merche - Gestión Urbanística. ········ **A parte de esto, quiere poner en nuestro conocimiento, para que no nos pille desprevenidos, que ha informado de absolutamente todo al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-05-19','Ana: Correo de Miguel Ángel, Director CRR-CC (residenciadir@feafescaceres.com): "Buenos días os informamos sobre INGRESO en UNIDAD DE HOSPITALIZACIÓN BREVE del HOSPITAL SAN PEDRO DE ALCÁNTARA de Consuelo Nevado Peinado. “En la tarde de ayer se produce ingreso voluntario de la usuaria C.N.P por aumento de sensaciones generadoras de malestar que alteran la conducta de la persona usuaria y generan gran sufrimiento. En la mañana había sido valorada por su psiquiatra de referencia sin estar presente dichas sensaciones en el momento de la valoración. En la tarde tras alteración de conducta que requiere contención verbal por parte del equipo de rehabilitadores del centro, C.N.P finalmente acepta valoración psiquiátrica y es la misma paciente quien valora y propone se valore la necesidad de un ingreso para disminuir estimulación y la probabilidad de realización de conductas relacionadas con auto o heteroagresividad. Finalmente se produce al ingreso en la UHB de Cáceres”. Un cordial saludo." ··················································· Mi respuesta: "Buenos días Miguel Ángel, Gracias por comunicarlo. Por favor, mantennos informados de su evolución. Aprovecho para recordaros que la compañera de la CTAEX encargada de elaborar y enviar la rendición anual al Juzgado, sigue pendiente del informe necesario para la misma, que se ha solicitado ya al CRR en varias ocasiones. Cuando os sea posible hacédnoslo llegar, por favor. Seguimos en contacto. Un saludo." ·············· *Miguel Ángel responde que la psicóloga está elaborando el informe, en cuanto lo tenga finalizado nos lo remitirán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-19','(Pedro) Se pone a la firma la opción PNC/LISMI optando por la PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-05-19','(Pedro)Llamada de Juan José (667-958878). +++"LLevo mucho tiempo haciendo bien el seguimiento de como utilizo el dinero y los Educadores me dicen que lo estoy haciendo bien...y querría volver a tener la posibilidad manejarme como antes..." +++Le pido que siga así y que lo hablaremos con los compañeros para tomar una decsión al respcto. Acepta de buen grado el continuar con dicho seguimiento un tiempo más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-05-19','TERESA: EMAIL MERCES P.I Buenas tardes. Me pongo en contacto para comunicarles que Beatriz Muñoz se encuentra bastante desanimada por no poder visitar presencialmente a su hija Rocío. Me ha planteado la posibilidad de realizar alguna videollamada al numero de telefono de la abuela paterna para que al menos pueda verla de esa manera. Cuando estudiéis la posibilidad me comunicáis la decisión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2020-05-18','(Pedro) Bartolomé (678-237885) acudió ayer sin cita programada a la Comisión. +++Hable por teléfono con él y entrego fotocopia de la tarjeta de seguro dental. +++Finalmente, de lo que quería hablar era del aumento de su asignación mensual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2020-05-19','(Pedro)Llamada de Bartolomé. +++Sigue insistiendo en el mismo tema del dinero. +++Quiere hablar con Teresa, de Futuex.','2');
