insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-19','Ana: Recibo llamada de Belén, secc. ecca. CTAEX; autorizarán una retirada puntual de 40 € esta semana para José Manuel y a partir de la semana que viene, volverá a retirar de forma quincenal, tal y como se acordó con el banco mientras dure el estado de alarma. Confirmará a Toni-Futuex los días en que podrá acudir. ············································· Llamo varias veces a la empresa de SAD acretitada ADELANTA (633 42 55 39) pero salta el buzón de voz. ································ Llamo a la empresa de SAD acreditada AIMEKOL (927 22 21 43). Ángela me dice que le he pillado conduciendo. Me devolverá la llamada hoy o mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MODESTA'and edp.apellido1='GARCIA'and apellido2='PIÑERO'),'2020-05-19','Ana: Llamada de Mariví Clemente, TS del CSS, envío correo a la secc. ecca. : "Buenos días compañeras/o, Me han llamado del SocioSanitario de Plasencia, en relación a Modesta García Piñero (7/C/15), dicen que no tiene dinero y que como Modesta no tienen cuenta en Liberbank, no pueden retirarle efectivo para gastos de bolsillo. Necesita dinero para pagar el servicio de podología entre otros pequeños gastos. Plantea si sería posible: • bien cambiar de entidad bancaria a Liberbank • bien abrir una cuenta nueva en Liberbank y hacerle una transferencia periódica para sus pequeños gastos Mariví, TS, dice que ya lo planteó una compañera suya hace unos meses, pero no han vuelto a saber nada. No sé con quién habló. Ya me decís cuando podáis. Gracias!!" ······························ Respuesta de Juana: "Buenas Ana, Vamos a abrir cuenta en Liberbank y vamos a traspasar la cantidad que nos diga el sociosanitario para sus gastos personales. Para eso necesitamos que escaneen su DNI en la oficina de Liberbank de Plasencia (aunque se le abrirá la cuenta en Mérida) y estimación anual de sus gastos personales. Estamos en contacto." ············································· **Renvío la respuesta de Juana a Mariví, Estrella y Rosa Bravo del CSS-Plas. Pues no sé exactamente a quién corersponderá hacer estas gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-19','Ana: Llamada de Mª Carmen, Directora de C. Día de Guadalupe (667 891 640), me pide los datos de Juan para la factura del servicio de comida de esta semana. *La enviará al ctutelar@.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-05-19','miguel, recibo email de la parte económica (Iciar), preguntan si hay que abonar o no honrarios de la abogada que representó en varios procedimientos (zafra(abogada adjuntó el 19-12-19 vía email documento donde el Colegio Abogados no concedió el turno de oficio) y Badajoz) a Ildefonso. Yo sólo le he acompañado a el procedimiento que huboe en Badajoz (acusado de 4 delitos y faltas contra su madre y hermano)donde dicha abogada ya estaba designada en el procedimiento con lo que entiendo que sería nombrada por Ildefonso y habría que pagarla. Tras comentarlo con Angel el tampoco tiene constancia de su nombramiento por nosotros...','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-05-19','miguel, recibo email de la parte económica (Iciar), preguntan si hay que abonar o no honrarios de la abogada que representó en varios procedimientos (zafra(abogada adjuntó el 19-12-19 vía email documento donde el Colegio Abogados no concedió el turno de oficio) y Badajoz) a Ildefonso. Yo sólo le he acompañado a el procedimiento que huboe en Badajoz (acusado de 4 delitos y faltas contra su madre y hermano)donde dicha abogada ya estaba designada en el procedimiento con lo que entiendo que sería nombrada por Ildefonso y habría que pagarla. Tras comentarlo con Angel el tampoco tiene constancia de su nombramiento por nosotros...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-05-19','miguel, me remiten desde la notaria la escritura que en su día se firmó de compraventa. Remito por email a Pedro, Alberto y Amalia para tengan constancia de los valores y limitaciones de dicha vivienda en el año 2008. ***************************************************** Mañana presentaré en Consejería de Fomento solicitud de Valor de Precio Máximo legal actual y si es posible Autorización de Venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-05-19','Ana: Llamada de Joaquín, Técnico de la Oficina de Igualdad de la Mancomunidad de Centro - Miajadas. Vanesa Fernández ha acuidido a la oficina a poner una denuncia por Violencia de Género. Pregunta quién debe firmarla. Le explico que en la actualidad Vanesa sólo tienen una Curatela Económica. Ella ha recuperado la capacidad en el resto de esferas personales y por tanto ella debe firmar la denuncia. *En cuanto a la ayuda económica que le van a tramitar, le explico que tampoco hay incinveniente, sólo necesita autorización para gestiones y actos que impliquen un gato superior a 3000 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-05-19','Ana: Llamada de Lidia Cabanillas, TS del C.S. de Valencia de Alcántara (927 580 295); Julián ha acudido hoy a la consulta de su médico de atención primaria, por presentar mareos y desequilibrios al andar. Acusaba también dolor en las cervicales, pero tras el reconocimiento médico parece ser que no es Vértigo. Lo que sí tenía era la tensión arterial elevada. Le ha puesto un tratamiento nuevo. **Ha acudido poco aseado y con la ropa sucia. **Nos enviarán por fax informe al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-05-20','(Pedro)Llamada de DªAinés Murillo Horrillo (659-251339), hermana (pequeña) de D. José Luis. +++Solicita inofrmación sobre el estado de los trámites de la herencia. +++Hara la solicitud por correo electrónico de ctutelar. ******************************************************* miguel, a petición de Pedro llamo a la hermana de José Luis sin éxito, por lo que aviso a Pedro que si llama la informe que la ratificación de la herencia ya se la enviamos a la abogada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-20','Ana: Tras recibir listado de empresas consultadas por Futuex, llamo a Adiper (924 66 75 78 – 645 99 80 48) Marian me confirma que realizan contratos con clausula suspensiva, tienen un modelo de contrato presentado en el SEPAD que es el que utilizan. Cuentan con Auxiliares con experiencia en salud mental, incluye: visita y entrevista de valoración previa al incio del servicio, sustición por enfermedad y vacaciones desde el 1er día, Seguro de Responsabilidad Civil de hasta 400.000 € y plan de alimentación. *Durante el Eº de Alarma no van a comenzar ningún servicio nuevo, aunque están tardando en resolver los PIA y abonar el servicio más de 1 año. *El precio por 45h/mes = 495,98 € (IVA incluído). Para elaborar el contrato hay que enviarle: fotocopia del DNI, nº Seg. Soc. y nº de cuenta bancaria. Y especificar hora aproximada del servicio. Su correo es marian.navia@adiper.es Cuando puedan comenzar a dar el servicio elaborarán un contrato nuevo con la fecha de inicio y horas exactas de atención. ············································· Recibo llamda de AIMEKOL (628 229 575): No tienen experiencia en Salud Mental y aunque dicen que podría buscar alguan auxiliar que la tuviera noto cierta reticencia y pregunta por las patologías explícitas... El precio por 45h/mes sería de 493,30, iva inluido, con cláusula suspensiva y según dice "todo legal". ········································· En vista que no obtengo respuesta otras empresas a las que llamo y que las condiciones y disposición de Adiper parecen adecuadas, le envío el correo a Marian con la documentación que piden. ················· Concversación con Marisa, Técnica de Dependencia: Pide que registremos toda la documentación junta, incluida la Aceptación PIA del CRR. **Me comunica que las compañeras del IMAS de CC, le han dicho que la empresa CONISEL podría ser una buena opción para la limpieza previa de la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='REYES'and apellido2='MIEL'),'2020-05-20','EXITUS El 13/11/2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-05-20','TERESA: Hablo con Magadalena la abuela 694460354 le comento la posibilidad de realizar una videollamada. Le parece buena idea, le pido autorizacion para facilitar el umero al centro. Llamo a Mercedes PI y le comunico que pueden hacer la videollamada cualquier dia por la tarde, les facilitio el telefono de la abuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2020-05-20','TELEFONOS Y DIRECCIONES Teléfono hermana 603674864/661261920','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-05-20','(Pedro)Conversación con Juan Pedro, Director del CAM Francisco Pizarro. +++Sobre la propuesta de mantener una conversación desde la Comisión con Aitor, lo ha hablado con su Educador y tienen dudas sobre la conveniencia o no de dciha conversación. Le comento que, por supuesto, lo que no queremos es interferir en la dinámica que los profesionales del centro estén llevando con él y que dejamos a su criterio la conveniencia o no de mantener dicho contacto y, en su caso, el momento para hacerlo. Pueden llamrnos tanto a Ana como a mí para ello. +++Respecto a Aitor parece ser que se está comportando aceptablemnete bien: le insisto en que le comenten la importancia de no tener alteraciones de conducta dado que son uno de los criterios de no admisión en los Centros. reitero la información que le dió Ana ayer en cuanto al acceso al recurso. +++Le planteo la conveniencia o no de tratar de que el centro esté en la provincia de Cáceres (como la sentencia plantea dentro de las posibilidades para ello) y dice que sí, por la relación afectiva que le une a su madre. El problema parace venir de la relación con la pareja de su madre, D. Jesús: Juan Pedro comenta que parece ser su único interés el dinero que Aitor pueda aportar cuando va a casa. +++Mantiene converscaiónes telefónicas con su madre pero sigue sin salir a su casa. +++Comento a Juan Pedro que probabalemente una de las causas que pueden condicionar una parte del comportamiento de Adrian son las probablemente altas expectativas en relación a su mayoría de edad, que él creería le permitiría organizar su vida como quisiera, prescindir de la tutela y "ser libre". Juan Pedro está de acuerdo en que ello puede ser uno de los factores que inicidan de manera importante en ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-05-20','(Pedro)Llamada de Sila, T.Social del C.Salud de Castuera (81838). +++Llamaba para solcitar información sobre D. Guillermo, ya que ella se ha incorporado hace poco y no lo conoce. Sí ha tratado más a su hermano. +++Le comento que se ponga en contacto con Luisa, la T. Social del SSB a la hora de coordinar la intervención con ella, ya que nosotros estamos todavía en periodo de inventario. +++Le informo sobre la intervención prevista eb este caso: Unidad de Deshabituación Alcohólica (UDH) del CSS de Plasencia y paso a Centro de Mayores cuando esté de alta en ella (pasar directamente de CSS a Centro residencial). +++Comenta que todavía la Unidad está atendiendo casos de Covid-19, y además hay unos cinco casos en espera, por lo que ese ingreso puede tardar algún tiempo. +++Desde el Centro de Salud, en coordinación con CEDEx solicitarán el ingreso en la UDH.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-05-20','(Pedro) Conversación con Toni (MADEX,68421). +++Ha habaldo con José Florencio y ha quedado en que esta tarde, a las 18:00h, cogerá un taxi para volver al Centro. +++Se le ha informado de cómo tiene que ir en el vehículo, con la mascarilla. +++Toni nos avisará para confirmar su reingreso en el Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-05-20','TERESA: ENVIO EMAIL PIEDNIENDO INFORMACION SOBRE COMO VA EL PROCESO DE PLZA DE JOSEFA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-05-20','(Pedro) Llamada de AnaSánchez, T. Soc. H. Tierra de Barros (89325). Ha enviado por fax INFORME de ALTA. +++Lo escaneo a su expediente. Lo han enviado también a COMSER +++Su Médico, el Dr. José María Vázquez Labrador (89273), quiere hablar con la Comisión para saber su opinión sobre la prueba CPRE que podría realzarse a DªAnica. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamo al Dr. Vázquez pero no me coge el teléfono. Volveré a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-05-20','Ana: Correo de Estrella Durán: "Buenos días, Ana. SE persona Jairo en mi despacho demandando hablar con vosotros... Espero tu respuesta Gracias. Saludos" ································ Mi respuesta: "Buenos días Estrella, ¿sabes sobre qué quiere hablar, si es una cuestión en concreto? Dinos si ha manifestado en el Sociosanitario alguan demanda y si sabes si mantienen la misma actitud que la última vez que estuvimos allí hablando con él en persona Pedro y yo. En cualquier caso, decirnos qué día ya qué hora podríamos llamarle en caso de que Pedro crea conveniente el que lo hagamos. Le pongo a él en copia. Gracias y un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-03-13','BELEN, CONTACTAMOS CON EL HOSTAL LA ISLA DE MONTIJO, PARA INDICAR TF CONTACTO Y EMAIL DE CTAEX, PARA ENVÍO FRA. POR GASTOS ALOJAMIENTO.NOS INDICAN QUE ESTÁN REUNIDOS Y NO SABEN AÚN SI CERRARÁN EL HOSTAL POR EL ESTADO DE ALARMA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-04-22','Amalia: Vive en un chalet propiedad familiar del padre y los hermanos de éste, en Montijo. Su madre le lleva la comida. Por el estado de alarma, dudamos si se quedó en el Hostal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-05-20','Ana: a petición de Ángel, Asesor Jurídico CTAEX, solicito a Javier, director del CRR de Plasencia (677 407 640), Certificado de Ingreso en Centro, en qué indique fecha en al que ingresó y motivo del ingreso. Lo necesita para revocar un poder que otorgó Antonia en el Juzgado de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-05-20','miguel, preparo solicitud de certificado de VPO para Fomento de la Junta, y pago modelo 50, y tras acercarme personalmente en Badajoz, compruebo que está cerrado, así que envío email a Pedro, Alberto y Amalia "informaros que las consejerías están todas cerradas al público y por tanto también sus registros. Me he acercado esta mañana a Fomento, tal y como os comenté para hacer la solicitud de Precio Máximo Legal y Autorización de Venta de JUAN CARLOS RUBIO GALÁN, y me ha comentado el guardia jurado que no es seguros que abran la semana próxima. No obstante, si entramos en fase dos me acercaré y lo intentaré de nuevo".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-05-21','(Pedro)Conversación con José Mª Vázquez Labrador, Médico de Medicina Interna del Hospital Tierra de Barros (89273). +++Juicio clínico: +++++TUMORACIÓN en MAMA IZDA: NO TOCARLA. Aunque se hiciese una biopsia no se intervendría terapéuticamente. +++++PIEDRA EN TERCIO DISTAL DE CONDUCTO BILIAR: administrado tratamiento antiinflamatorio y antibiótico. +++++Puede recidivar, la piedra volver a obturar el conducto y provocar una sepsis: en este caso habría que hacer una CPR y extracción en el Hospital Universitario de Badajoz. +++++"Si fuera mi madre, en mejores condicones que Anica, no la intervendría...Salvo que Anica vuelva al hospital con una sepsis que requiera si o sí intervención para salvar su vida." +++Pido que nos envíe Informe con la explicación referida en la conversación telefónica, y junto con la opinión de COMSER tomar una decisión al respecto, que pueda ser comunicada al Juzgado previamente a cualquier intervención.ENVIARÁ DICHO INFORME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-05-20','Ana: Me comunica Paula, TO - CRR Plas. que Damián tiene que hacer declaración de la renta y dadas las circunstancias actuales no podrán acompañarle para hacerla. Preguntan si desde la CTAEX se la pueden hacer. Le digo que hacérsela en la CTAEX NO, pero que consultaría a la secc. ecca. si se puede contratar una Asesoría/Gestoría. ························ Envío correo a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-05-20','Ana: Llamada de Paula, CRR Plas.: Me pide que consulte a la secc. ecca. si pueden comprobar si Conchi realizó o no la retirada del extra anual de 2020, pues con el jaleo de estos últimos meses (Eº de alarma) no lo tienen claro. ··········· Envío un correo a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-05-20','Ana: Llamada de Paula, CRR Plas.: nos comunica, sólo para que estemos al corriente, que van a comprar a Ceferino un móvil nuevo como refuerzo positivo a los pasos que ha dado durante el confinamiento en el centro participando activamente en las actividades. No supone dinero extra. ····················· Me sorprende la actitud positiva que dicen que tiene en el centro, cuando hace unos días pedía irse del mismo. *Con respecto a esto, Paula dice que Cefe, cada vez que hay algo que no le gusta suele reaccionar así, sería un mal día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-05-21','Correo-e de Toni Galán: Me confirman que llegó ayer al servicio residencial por la tarde según se acordó con él. También me ha comentado que ha llegado cargado de maquinaria de bricolaje... A los 7 días le van a hacer test covid en el centro de salud otra vez y si es negativa, no necesitaría los 14 días de aislamiento porque anticipan que va a ser dificil el aislamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-05-21','TERESA: EMAIL DEL TS DE ZAFRA Beatriz Megias de la Morena se encuentra ingresada en Llerena su hermana necesita hablar con vosotros 696 337732 un saludo SE LLAMA A LA HERMANA PARA QUE RETIRE LA ASIGANCION DE ESTA SEMANA Y LA DE LA SEMANA PASADA SE LE HARA UNA TRANSFERENCIA A SU CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-05-21','(Pedro)Conversación con Eva, Sección de Salud Mental de la U. PP. +++Manuel (en lista de espera desde marzo de 2017) se enceuntra el SEGUNDO (24 puntos/Grado I)en el listado general, con una persona delante (40 puntos, Grado II) y con otras dos personas por delante de ellos considerados de emergencia social. +++Pido a EVa que me envíe el motivo por el que no se ha considerado de emerncia social este caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2020-05-21','Teresa REcibo llamda de salund mental para anular la cita que tiene el 26 de mayo.Le llamo para comunicarselo y preguntar como se encuentra','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-05-21','TERESA: EMAIL CRPS ESTADO DE BEA Perdona el retraso, pero he tenido un problema personal y no he podido responder. Beatriz continua en UHB de Llerena, hemos hablado con Constanza y nos ha dicho que esta mejor, ha estado un poco agresiva, pero comenta que ya esta más tranquila, porque han comenzado a darles permiso para salir al patio a fumar. Ha hablado con el juez, ante la posibilidad de que pueda solicita el alta sin estar preparada. Le hemos planteado la posibilidad de que Beatriz pase de nuevo por el circuito asistencial antes de volver a su casa, ya que pensamos que si le dan el alta para volver a su domicilio no va a mejorar, si no que va a seguir empeorando; lleva inestable mas de un año y cada vez el deterioro es mayor. Constanza se muestra de acuerdo en principio de iniciar el procedimiento para que pase por el circuito asistencial: derivar a Unidad de Media Estancia, después a Unidad de Rehabilitación Hospitalaria y/o Piso Supervisado; van a comenzar a trabajar con ella la imposibilidad de momento de volver a su casa. En cuanto a las lineas contratada, las de Calera de León las contrato a nombre de Manuel Domínguez Martín; fue pareja suya y tuvo hace un tiempo un juicio por una denuncia que le puso por trato vejatorio, también esta tutelado. La linea que tiene en su casa no se a nombre de quien estará. En relación a la cuenta bancaria, no se el numero de cuenta, solo se que es en el BBVA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-21','Ana: Conversación con Toni, Futuex. Le comunico que hemos solicitado contrato SAD con cláusula suspensiva y que es necesaría la limpieza previa que habíamos hablado. Recordará a Virgina que solicite un par de presupuestos de limpieza. ········································ *Marian - Adiper, me remite por mail el contrato de SAD. ····················· Renvío el contrato a Ángel y Miguel, Asesores Jurídicos CTAEX para que lo revisen antes de ponerlo a la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2020-05-21','TERESA: ARCHIVO INFORMES DEL REHABILITADOR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-05-21','TERESA: CONVERSACION TELEFONICA CON ANA EDUACARORA PI NATALIA VUELVE HOY AL CENTRO TRAS HABER DADO NEGATIVO EN EL PCR, ANA ME PLANTEA AUTORIZACION PARA PONER UNA CADENA EN SU HABITACION POR SI EN ALGUN MOMENTO HAY QUE DEJARLA SOLA PARA QUE ELLA NO SALGA DE LA HABITACION NI NADIE ENTRE, LE PIDO QUE ME LO PASE POR ESCRITO PARA FIRMARLO COMO MEDIA DE CONTENCION ANTE LA SITUCION DEL COVID NATALIA VUELVE AL CENTRO EN COHCE DE PLENA INCLUSIONM, VA A IR UN COMPAÑERO A POR ELLA SOSPECHAMOS QUE LA ABUELA NO VA A QUERER MAS LLEVARSELA EL FIN DE SEMANA CON LO CUAL VA A DEJAR DE TENER SALIDAS A BADAJOZ LOS FINES DE SEMANA YA QUE TRAS LOS ULTIMOS ACONTECIMIENTOS LOS ABUELOS MUESTRAN NO QUERER SABER MAS DE NTATALIA PORQUE LES OCIASIONA MUCHOS PROBLEMAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-05-21','Ana: Llamo a Emilia, TS del CADEX-CC (927 005 505), pero o está. Llamo a Domingo, Director (927 005 509), comprueba que Mª Antonia sí está valorada de Discapacidad, tiene un certificado provisional hasta marzo de 2021. Acordamos que solicitaré el Certificado y el Dictamen Técnico por mail. ······················ Envío email al CADEX con dicha solicitud (cadex.caceres@salud-juntaex.es) adjuntando los documentos pertinentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-05-20','Ana. Recibimos el informe médico de Att. Primaria por fax. Pedro lo escanea y lo guarda en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-05-22','Enviamos al Letrado de la Administración de Justicia de Plasencia, solicitud para revocar el Poder Apud Acta, tanto general, como especial, que otorgó en su día María Antonia, en su propio nombre, a la Procuradora, poder en el que se basan tanto ella, como el Abogado que está reclamando la minuta, en el procedimiento de recuperación de su capacidad, a pesar de que ya hablamos con el Abogado y le indicamos que no podemos autorizar ningún gasto de este tipo, porque no hemos intervenido previamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-05-21','Ana: Llamo a Toni-Futuex, tras haberlo hablado con Pedro. *Se retomará la intervención planteada de forma previa a decretarse el Eº de Alarma. En cuanto puedan nos enviarán presupuestos de limpieza, especificando si es necesario que Julián salga del domiclio alguna noche (dadas las circustancias esperamos que no sea necesario). Retomarán contacto con la empresa de SAD (volví a pedirle presupesto el 10 de marzo, pero no he obtenido respuesta. Supongo que por las circunstancias). Y Gloria trabajará de nuevo con Ramón, la necesidad del SAD y acceso a C. Día, mientras tanto se mantendrá el cáterin contratado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2020-05-21','(Pedro) Llamada de Mercedes. +++"He perdido el dinero que saqué y tengo que ponerme el inyectable y comer..." +++Dice que lo ha dencunciado pero que no tiene copia de la denuncia porque al final no la puso y que perdió el dinero hace cuatro días pero que lo perdió hace día y medio y que ha contratado un abogado para que lo recupere...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-05-21','Ana: Llamadas de Juan, al décimo intento conseguimos medio esccharnos mutuamente.... es prioritario cambiar el terminal (seún Juan es el problema), envío correo a Toni pidiendo que Teresa le acompañe a la gestión en la próxima visita. Ya lo he hablado con Juan. ·························· Por otra parte Juan pregutna cuándo le darán de alta el enganche de la luz, envío correo a Belén, consultando al repecto y diciéndole que lo hable con los asesores jurídicos. ····················· Por otra parte Juan insiste en que los Asesores Jurídicos tienen que reclarmar lo de sus premios de la lotería...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-05-22','(Pedro) Correo del CRR de Mérida (21-05-2020). +++ Ángel Pinilla: Mañana nos llamará el fisioterapeuta para concretar cita para la semana que viene. Vamos a gestionar también cita con su Psiquiatra privado Dr. De La Rubia. Lleva dos días más agitado y, aunque se reconduce, creemos conveniente dicha cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-05-22','(Pedro) Correo del CRR de Mérida (21-05-2020). +++María Dolores Fernández: En general bien, contenta por la vuelta de su educadora de apoyo, retomando el recetario. De vez en cuando hace alguna queja física que se le olvida pronto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-05-22','(Pedro) Correo del CRR de Mérida (21-05-2020). +++José María Guillén: Bien, en concreto hoy un poco crítico e inflexible con todo lo que le rodea, pero tras hablar con él y cortar un poco su discurso parece que se ha tranquilizado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-05-22','(Pedro) Correo del CRR de Mérida (21-05-2020). +++Luisa Rodríguez: Como os comentó el Director, en una salida al traumatólogo su comportamiento fue bastante disruptivo y desadaptativo, sin atender a indicaciones de la profesional que le acompañaba... Tras valoración psiquiátrica decidieron dejarla INGRESADA. Durante estos días hemos intentado contactar con el facultativo que llevaba su caso pero no ha sido posible. Alguna compañera suya del CRR le ha llamado y Luisa se encuentra bien. Comenta que es PROBABLE QUE LE DEN MAÑANA EL ALTA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-05-22','(Pedro) Correo del CRR de Mérida (21-05-2020). +++Antonio Merchán: En la misma línea que días y semanas atrás, le notamos muy bien. Bastante correcto en las salidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELINA'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2020-05-11','EXITUS Según informa el centro, el óbito tuvo lugar el 11/05/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-05-22','TELÉFONO DE Anaybeth: 633-407539. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Conversaciones telefónicas con Miriam, Anaybeth e Inmaculada (T.Soc.). +++MIRIAM: Dª Rosario se encuentra mejor, ha mejorado en el sueño y en el apetito, pero a veces se muestra nerviosa. En el moemtno de esta llamda la Enfermera estaba en su domicilio para ponerle la inyección. +++En cuanto al pago de la sustitución por parte de su sobrina le corresponde hacerlo a ella, tal como la parte económica quedó en anteriores sustituciones (salvo en caso de vacaciones). +++ANAYBETH: le comento lo mismo que a Miriam y le pido que lo arreglen entre ellas según lo inidcado a Miriam. +++INMACULADA (924-471014, SOLO TELETRABAJO): Informo de las conversaciones con ambas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='MACHIO'),'2020-05-22','Correo-e de Amalia: +++Buenos días , en relación con la Vivienda de Promoción Pública cuyo titular es nuestro tutelado , y tras valorar la situación , no es posible darlo de baja como titular de la misma. Roberto está ingresado desde hace años en la Unidad de Crónicos del CSS de Mérida. No está separado legalmente , y tiene tres hijos, todos con discapacidad intelectual muy grave. Ellos son los que viven en esa vivienda . No podemos darle de baja como titular de la VPP porque es el lugar donde sigue residiendo su familia , que no tienen otro lugar donde vivir . Por todo ello y tras contactar con la Trabajadora Social del CSS de Mérida y el TS de la localidad de Zafra ,para valorar la situación sociofamiliar ; se solicita , se sigan abonando los recibos de alquiler y suministros de la misma .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2020-05-22','TERESA: HABLO CON ANA EDUCARORA PI ME COMENTA QUE ROSA ESTA MUY BIEN EN EL DOMICLIO POR LO TANTO VA A CONTINUAR EN EL UN TIEMPO MAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-05-22','Ana: Llamada y correo de Rosa Bravo, Admvo. del CSS-Plas.: Nos remite Sentencia Ejecutoria por Delito de Lesiones y cédula de citación judicial para que comparezca en el Jdo. el día 9 de julio de 2020. Hay que elegir entre Localización Permanente, Trabajos en Beneficios a la Comunidad o Pagar la Multa (150 €) + la indemnización (150 €) ········································ Recibo llamada de Estrella, CSS - Plas.: pregunta si podemos hablar con Jairo ahora, le digo que sin problema. Pero él le dice a Estrella que sólo quiere hablar con Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-05-22','TERESA: JUANA SE ENCUENTRA PASANDO EL CONFINAMIENTO EN SU DOMICILIO FAMILAR. EN ESTE PERIDO DE TIEMPO HA FALLMECIDO SU MADRE CON LO CUAL AHORA VIVE CON SU HERMANO. JUANA QUIER ESTAR EN EL DOMICILIO CON SU HERMANO HASTA SEPTIEMBRE PERO DESDE EL CENTRO VE QUE ES MUCHO TIEMPO PARA ESAR ALLI SIN UNA SUEPRVISION DIRECTA POR LO TANTO SE VA A PROCEDER A SOLICITAR EL REOTORNO EN EL MES DE JUNIO UNA VEZ SE CELEBRE LA MISA DE SU MADRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2020-05-22','Ana: Recibo llamada de Mª Eugenia (633 578 274), expresa que se siente muy lejos de su famlia. Desde Nochebuena no les ve. Le gustaría poder ir unos días en verano. Y aunque con los profesionales del centro se siente bien y dice haber hecho ya amistades, le gustaría ir a vivir a algún centro que esté más lejos. Le explico que estas cosas debe hablarlas ya con mi compañera Teresa, que lleva la zona, pero como actualmente su teléfono "no funciona", puede llamarme cuando lo necesite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-05-22','(Pedro)Llamada der Jairo (concertada con CSS Plasencia). +++Su única opción es irse a vivir de manera independiente (pero sin dejar de depender del todo de la Junta): piso de alquiler compartido, seguir sus estudios, etc...NO ACCEDE A VALORAR MÍNIMAMENTE LA POSIBILIDAD DE CAMBIO DE CENTRO si su Psiquiatra estuviese de acuerdo en CRR o, en último caso, Piso Tutelado. +++Sigue pensando en un mundo "ideal" en el que cree tener todo el control y para el que se cree perfectamente preparado para afrontar cualquier situación que se le plantee. RECORDAR, en la visita que hicimos Ana y yo hace unos meses, que le dijimos que si se quería matricular en la academia para preparar el acceso a la UNED fuese haciendo los docuemntos para la matrícula: "...Pero eso lo tendréis que hacer vosotros que sois mis tutores...yo no sé..." +++Ha tratado de engañarme diciéndome que había hablado con el Psiquiatra (en ese mismo momento y que le había dicho que estaba de acuerdo en que me fuera a un piso "normalizdao".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELINA'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2020-05-22','(Pedro)Conversación con D. José Mª, Alcalde dec Cuacos de Yuste (927-172058///650-441127). +++Le indico el ERROR que se ha cometido en la notificación de Alcaldía, en la que además de indicarnos la liquidación de la Tasa (600 euros) se da a la Comisión la concesión de los derechos funerarios del nicho 480 del cementerio municipal por un periodo de 75 años improrrogables. +++Hablará con el funcionario que tramitó la notificación para que se ponga en contacto con la Comisión, sin necesidad de tener que proceder a instar el recurso de reposición. +++Pongo a Ángel al tanto de esta conversación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-22','Ana: Hablo con Manuela Glez. Jefa de Secc. Discap.: Hasta donde ella sabe, la Casa hospital Santiago de Zafra no se encuentra aún en la Cartera de Servicios. Ellos van por subvenciones (que en teoría la convocatoria se va a publicar ya mismo) no por conciertos del MADEX. *Las plazas que tienen acreditadas son de RAE y están todas ocupadas. No obstante, Pilar necesitaría una de RAL. *En estos momentos no sería viable darle plaza por Emergencia Social en dicho cento. ··················································· Llamo a los SSAB de Zafra (924 554 601 , ext. 5) para preguntar por el Informe para la Valoración de Dependencia, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2020-05-22','(Pedro) Conversación con Clara. +++Va a cobrar en los 10 primeros días de cada mes y a mes vencido: +++++Atrasos, desde el 13 de julio de 2019 al 14 de mayo de 2020: 1477, 36 euros (a cobrar entre el 1 y el 10 de junio). +++++Mensualidad: 125,80 euros (primeros diez días de cada mes).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-22','Ana: Llamada de Pilar Martín (927 222 417): le informo de que ya se ha pedido contrato de SAD y puesto para la firma del D.Gerente. Sólo falta el Cdo. de Convivencia del Ayto. Acoredamos que si vemos que tarda en llegar se lo diremos a ella, pues tiene algún contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-25','Ana: Recibo llamada de José Manuel (móvil de la novia de su hijo: 655 587 842): Ahora dice que NO quier el catering, que prefiere más dinero a la semana y no tenerlo, que además la comida de la empresa nueva ("Qué bueno") no le gusta, que le han traído muchas verduras y no lleva pan. Que prefiere tener más dinero y acudir al comedor social y tener tarjeta del autobús. Ha retirado esta mañana los 40€ y sólo le quedan 10€ para el resto de la semana. Por otra parte, dice que se le ha estropeado el móvil y necesita uno nuevo. Y que a su exmujer no le llega el dinero de la manuntención, pero que a él si se lo cobran. *Comentaré a los compañeros jurídicos lo de la manutención. En cuanto a las cuestiones que pide le digo que no puede estar camabiando de opinión cada dos por tres. Tendrá que tener paciencia y aguantar con el cáterin hasta que se resuelva lo del SAD. Cuando ya tenga este servicio se podrá dejar el cáterin pues la auxiliar le hará la comida y puede que se pueda volver a aumentar la asignación. En cuanto al móvil, le digo que envíe presupuestos y que en la secc. ecca. tendrán que valorar todo y decidir, pues son muchos gastos los que plantea (lavadora, teléfono, ropa, termo, arreglo del plato de ducha... y además hay que realizar limpieza previa al SAD). Habrá que establecer prioridades. Dice que el plato de ducha lo puede arreglar su hermano. Le contesto que en ese caso el hermano nos lo haga saber. ·································································································································· Correo de Toni-Futuex el viernes 22 por la tarde: "Buenos tardes ya te dejo esto, al respecto de Mediavilla que lo abordamos si te parece la semana que vien, ya que ayer por la tarde volvimos a tener conflictos con José Manuel y su hijo, movilizó al hermano a la compañera educadora ya los servicios de emergencia , amenazaba con una conducta autolitica, aunque finalmente no paso nada, hoy está perfectamente,pero la novedad es la sospecha de que están "trapicheando" el y su hijo con la medicación, no está comprobado pero a la educadora no le extrañaría nada, esta atando cabos y tiene esa sospecha o esa impresión que pudiera no estar haciendole efecto la medicacion porque la venda... de ser cierto seria tremendo, todo es complicadisimo con este hombre..." *Guardo nota en el expte. y se lo renvío a Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-05-25','Ana: Correo de Toni-Futuex del viernes 22 por la tarde con nota de las gestiones realizadas por Gloria los días 21 y 22. Julián Ramón acepta tanto el servicios de SAD como la limpieza previa, pero pide que Goria esté presente cuando acudan por primera vez tanto unos como otra. En cuanto a la limpieza, escribo a Toni recordándole que no se ha hecho visita previa al presupuesto y tal y cómo está la casa no sé si serán suficiente 8 horas. También valorarían si fuera necesaria una empresa específica de desinfección. *Gloria también pedirá cita a la peluquería para que Ramón acuda a cortarse el pelo y la barba. Y ha retomado el contacto con la empresa de SAD, seguramente en la 2ª fase de la desescalada podrían inciar el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-25','(Pedro)Videoconferencia. Subcomisión Regional de Casos. +++Conclusiones: +++++SE mantendrá ingreso en UHB con la idea de traslado hasta la UHDAC tras el alta. SE da un plazo de unos 230 días para ello. +++++ESM de Don benito realizará derivación a UHDAC. +++++En caso de que el alta de la UHB se debiese producir antes de lo esperado y sin plazas en la UHDAC, se volvería a reunir la Subcomisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-25','TERESA: RESUMEN SUBCOMSION DE CASO CELEBRADA HOY POR VIDEOCONFERENCIA CON LOS DIFENTES PROFESIONALES QUE TRABAJAMOS CON ADRES. SE ACUERDA MANTENER EN UHB HASTA QUE HAYA PLZA EN UDAC YA QUE SE CONSIDERA EL RECURSO MAS IDÓNEO EN ESTE MOMENTO DENTRO DE LOS QUE DISPONEMOS. EL INFORME DE DERIVACION LO LLEVARA A CABO EL EQUIOPO DE SALUD MENTAL DE DON BENITO NO SE CONSIDERA QUE HATA CRITERIO CLINICO PARA UME ADEMAS DEL RIESGO QUE ESO SUPONE PARA LOS USUARIOS DE ESTA UNIDAD POR LAS CONDICIONES ACTUALES DEL COVID 19 SE SOLIICTA CAMBIO DE PERFIL A RAE PARA DARLE TODOS LOS APOYOS NECESARIOS EN LA UDAC SE TRABAJARA SUS ALTERACIONES DE CONDUCTA PARA POSTERIORMENTE VOLVER AL CENTRO DE FORMA PROGRESIVA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-05-25','Ana: Llamada de Mariví Clemente, TS del CSS: José Mª ha dado una paliza a otro paciente también tutelado: J. L. Murillo Horrillo, éste está ingresado en el HVP-Plas. con traumatismo orofacial, traumatismo nasal, luxación de varias piezas dentales, graves problemas oculares... Ya se ha informado al Jdo. Rosa. Admvo. nos enviará el Parte de Lesiones. Aún no saben las actuaciones que llevará a cabo el Jdo. ······················································· (Pedro)Correo electrónico de Rosa (CSS PLasencia): +++Buenos días Pedro: Te adjunto Parte de lesiones sufridas por J.L. MURILLO HORRILLO y provocadas por J.M. VICHO ALFONSO, ambos tutelados por la Comisión. Estamos pendientes de decisión judicial con respecto a José Mª; en cuanto a José Luis permanece ingresado en el Hospital. +++Lo reenvío a Miguel, Ángel y Ana. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++NUEVO CORREO-e del CSS: +++Hola Pedro: José Luis sigue en el Hospital. José Mª ha sido trasladado a la Unidad de Media Estancia (cerrada). El Juzgado no se ha pronunciado. Medidas urgentes, al parecer y según información del Juzgado, no se pueden tomar. Un saludo. Si tenemos más información ya os la remitiremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-05-25','Ana: Llamada de Mariví, TS del CSS-Plas.: José Luis está ingresado en el HVP-Plas. con traumatismo orofacial, traumatismo nasal, luxación de varias piezas dentales, graves problemas oculares... a consecuencia de una paliza que le ha dado J.M. Vicho, también tutelado. Ya se ha informado al Jdo. Rosa. Admvo. nos enviará el Parte de Lesiones. Aún no saben las actuaciones que llevará a cabo el Jdo. ····················································· (Pedro)Correo electrónico de Rosa (CSS PLasencia): +++Buenos días Pedro: Te adjunto Parte de lesiones sufridas por J.L. MURILLO HORRILLO y provocadas por J.M. VICHO ALFONSO, ambos tutelados por la Comisión. Estamos pendientes de decisión judicial con respecto a José Mª; en cuanto a José Luis permanece ingresado en el Hospital. +++Lo reenvío a Miguel, Ángel y Ana. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++NUEVO CORREO-e del CSS: +++Hola Pedro: José Luis sigue en el Hospital. José Mª ha sido trasladado a la Unidad de Media Estancia (cerrada). El Juzgado no se ha pronunciado. Medidas urgentes, al parecer y según información del Juzgado, no se pueden tomar. Un saludo. Si tenemos más información ya os la remitiremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-25','Ana: Vuelvo a llamar a los SSAB de Zafra (924 554 601 , ext. 5) varias veces para preguntar por el Informe para la Valoración de Dependencia, pero no obtengo respuesta. ································································ Juan Pedro, admvo. CTAEX, lleva para que den REGISTRO DE ENTRADA las Solicitudes de Revisión del Grado de Discapacidad y de Acceso a Centro de Discapacidad por Decreto. *Ponen también para registro de entrada la elección de PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-05-25','Ana: Llamada de Mariví Clemente, TS del CSS, en relación a la Sentencia, le digo que lo estuve hablando con Pedro, quién también había hablado con los compañeros Asesores Jurídicos. En vista de que los trabajos en beneficios a la comunidad tendría que hacerlos en el CSS, donde, dada su actitud no iba a hacer nada... se decide que abone la multa. Eso sí, se procurará que él lo note en su asignación habitual, para que sienta que hay alguna consecuencia. ··············································· Pedro, Jefe Secc. CTAEX, lo pasará a Alberto, Jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2020-05-25','Ana: Llamada de Mariví Clemente, TS del CSS de Plas.; Antonia necesitan dinero para unas cremas que le receta el médico pero que no entran por la seguridad social. No tiene cuenta en Liberbank pero necesitan retirar efectivo. Pide que por favor le llamen a lo largo de la mañana (Directo hoy: 24146) para ver cómo lo pueden hacer. ······································ lo comunico a la secc. ecca. mediante correo-e y pido que le llamen ellas directamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-05-25','Ana: En relación a la llamada del padre de Consuelo (927 582 223), envío correo a la secc. ecca: "Buenas tardes compis, En relación a Consuelo Nevado Pacheo, he recibido llamada del padre. Dice que de la cuenta que tenía Consuelo se ha retirado el dinero que había, pero no se ha cerrado la cuenta y ahora están pasando comisiones. No sé si podéis cerrarla. Ya me decís. Gracias" ··················································· Respuesta de Juana, secc. ecca. día 26: "Buenos días compañera! Se ha solicitado la baja como titular en la cuenta de Consuelo Nevado. De todas formas, si quiere su familia cancelarla, puede hacerlo, ya que sólo basta la firma de uno de los titulares. Si te vuelve a llamar se lo comentas, seguro que el Banco Santander le hará más caso que a nosotros. Gracias!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-26','Ana: Llamo a Chelo (Consuelo Lavado), Jefa de los SSAB de Zafra (924554501, ext. 5). El informe social que iba a redactar Adela, TS, para la solicitud de valoración por la Ley de Dependencia, no ha salido aún. Hablará con ella. Hoy tiene atención, pero espera que mañana pueda enviarlo. Le pedirá que me lo adelante por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-05-26','(Pedro) Llama la hermana de Jonathan Ramírez, Dª María (641-261121). +++Según comenta, el pasado sábado agredió a su padre clavándole unas tijeras. El padre lo denunció, hubo juicio rápido y tiene una orden de alejamiento, pendiente de señalar Juicio. +++Pido a Dª María que nos envíe la denuncia por correo-e a ctutelar. +++++++++++++++++++++++++++++++++++++++ (Pedro)Llamo al Juzgado de 1ª Instancia nº 2 de Mérida. Hablo con Bernardo. +++No han enviado la aclaración a la sentencia todavía, porque esperaban hacerlo junto con el dictamen forense. pero se decretó el Estado de Alarma y la forense no pudo hacer la visita. +++Hablará de nuevo con la Forense, ya que en estas circunstancias podríamos solicitar medida de seguridad apoyándonos en la "autorización" de ingreso de la sentencia de incapacitación. ++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada de Bernardo (Nº 2 de Mérida): +++SE ha puesto en contacto con la Forense y está a la espera de que le indiquen la fecha para la exploración. +++Comunicará a Comisón la fecha y tratarán de localizar a Jonathan a través de la Policía. +++Al parecer, la jueza no contestó a la aclaración por no haber sido ella la que dictó la sentencia de incapacitación ¿?.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-05-26','(Pedro)Nueva llamada de Ceferino Mariscal. +++Sigue con el mismo tema...de irse de recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-05-26','(Pedro)Correo de Rosa (CSS de Plasencia. +++Buenos días: Acabamos de hablar con la Juez que lleva el caso. Nos dice que van a actuar de oficio. (No será necesario la denuncia). Se procederá a la toma de declaración de testigos por la Policía y reconocimiento por Médico Forense. Intentará agilizar los trámites. Seguiremos informándote de acontecimientos que vayan produciéndose. Buen día. Rosa Bravo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-05-26','(Pedro)Correo de Rosa (CSS de Plasencia. +++Buenos días: Acabamos de hablar con la Juez que lleva el caso. Nos dice que van a actuar de oficio. (No será necesario la denuncia). Se procederá a la toma de declaración de testigos por la Policía y reconocimiento por Médico Forense. Intentará agilizar los trámites. Seguiremos informándote de acontecimientos que vayan produciéndose. Buen día. Rosa Bravo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELINA'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2020-05-26','(Pedro) Llamada de D. Domingo Hernandez,funcionario del Ayto. de Cuacos de Yuste (673-451044), en realción al pago del nicho y la concesión de los derechos funerarios. +++CONCLUSIÓN: otorgarán la concesión del nicho a un hermano de Dª Marcelina y nos remitirán la tasa para el pago del nicho (euros). +++Derivo la llamada a Ángel por si quedase algo pendiente. Remitirán la anulación de la Resoclución de la Alcaldía para el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-05-26','Ana: Llamo varias veces a Clara Gómez, Jefa de secc. Depend. (924 00 92 69), en relación a la solicitud de activación del expte. que se registró hace más de un año, pero no obtengo respuesta ·········································································································· Llamo al C.S. de Valencia de Alcántara (927 580 295) y hablo con Lidia Cabanillas, TS. Le pregunto si sería posible que acudiese, si no ahora más adelante, a hacer visita a Julián Ramón aocompañada de Gloria, Delegada Tutelar. Primero me dice que no le conoce, después que por qué no se lo hemos pedido a Pilar, TS del SSB, pero al explicarle las circunstancias y que llevamos más de un año esperndo informe de Pilar, que lo hemos pedido en múltiples ocaciones diferentes personas de la CTAEX, se queja de que al final de rebote siempre le toca todo a ella. Cada vez que hay un caso difiícil en el pueblo le acaba tocando. **Finalmente accede a acudir al domicilio con Gloria-Futuex cuando haya pasado el Eº de alarma y si le deja pasar elaborá el informe de priorización para Dependencia. ············································································································································· Ana: Llamo a Paco Ortés, Albañil (638712004); dice que en cuanto finalice otra obra que está realizando en otro sitio arreglarán la cubierta del edificio. Ya ha hablado con dos de los dueños (uno de ellos es el arquitecto) y están de acuerdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-05-26','miguel, a petición de Amalia solicito al subdirector del Centro Penitenciario de Badajoz,vía email, acerca de las penas pendientes por cumplir,así como procedimientos y juzgados de origen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-05-25','(Pedro) Se recibe por fax Informe Médico con la opinión facultativa respecto la intervención a realizar en cuanto a las pruebas previstas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-05-26','Ana: Llamo al padre de Consuelo, le comunico lo transmitido por Juana en el correo. ······························································································································· Correo de Miguel Ángel, Director CRR-CC: "Buenas tardes, os informo que a día de hoy ha sido dada de alta en la UHB del Hospital San Pedro de Alcántara Consuelo Nevado Pacheco por mejoría en sus ideas auto y heteroagresivas debido a descompensación psicopatológica. Un cordial saludo. PD: Si necesitáis el informe de Alta os lo puede remitir." ······················································· Mi respuesta: "Buenos días Miguel Ángel, Nos alegramos de que la evolución haya sido positiva y le hayan dado el alta. Gracias por mantenernos informados. Y sí, agradeceríamos que nos remitieras el informe de alta cuando te sea posible. Un saludo y buena tarde." ····························· Más tarde recibimos el Informe de Alta de la UHB. Lo guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-05-26','(Pedro)Me comunica Amalia que Emi ha sacado una cantidad de dinero importante y se ha marchado a Almendralejo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2020-05-26','Ana: Correo de Guadalupe - Pisos Tutelados: "Buenos días. Como responsable del Piso Tutelado donde reside su tutelada, me pongo en contacto con ustedes para tratar un tema que nos traslada el Ats de Ana Priscila. Nos dice que Ana no figura en el programa Jara, se han dado cuenta cuando han tenido que volcar los datos de las pruebas del Coronavuris que han hecho a todos los usuarios del centro. No aparece registrada en este programa y no hay datos de ella. Quedamos a la espera de sus instrucciones por si tuviésemos que hacer algo. Les dejo mi número de teléfono para cualquier consulta, 605918070. Gracias y un saludo. Guadalupe Fuentes Benito, coordinadora del Piso Tutelado de Madrigalejo." ······················································································· Mi resppuesta: "Buenos días Guadalupe, Que cosa más rara… ¿y en el centro de salud no saben qué se debe hacer?? Bueno, mañana intentaré contactar con el SES a ver si alguien me sabe decir cuál es el problema y cómo solucionarlo. Gracias por comunicárnoslo. Esperamos que estéis todos bien. Un saludo y buena tarde. PD: Pongo en copia a Pedro, jefe de secc. para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2020-05-26','miguel, conforme email recibido por Teresa que nos remite de la trabajadora social del Centro Residencial " Nuestra Señora de las Cruces" de Don Benito, le contesto vía email lo siguiente: Buenas tardes, me han remitido mis compañeras documentación de testamentaria de la madre fallecida de nuestro tutelado Raúl. Compruebo que sigue en vida su padre y su hermano, ambos residiendo en un centro. Comentarle que nosotros no tenemos que tramitar esa herencia pues únicamente representamos los intereses de Raúl y desde ese punto de vista desconocemos los bienes de cualquier tercero (es más no podríamos acceder a ellos, ejemplo cuentas, bienes inmuebles, etc, por la ley de protección de datos). Le comento esto para que traslade a quién le haya solicitado nuestra intervención, que únicamente firmaremos el modelo 650 del impuesto de sucesiones cuándo nos remitan la herencia o bien nos indiquen en qué notaria se está tramitando para que nos informen directamente desde allí. Gracias, y disculpe no podamos ayudar en más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-05-26','miguel, a petición de Pedro haré informe para remitir al Juzgado conforme sus siguientes instrucciones:"Buenos días, Miguel. En el expediente virtual de Dª Anica M. (34-T-18) tienes los Informes clínicos de alta y de opinión facultativa, junto con un Informe Social que solicitamos para que valoraran el día a día de Dª Anica en el centro a la hora de decidir si se le hacían las pruebas que se plantean o no. En mi opinión este Informe no aclara gran cosa al respecto. Por favor, haz un documento con la misma finalidad del que hiciste en relación a D. Pablo G. G. (09-T-99) para su intervención para remitirlo al Juzgado solicitando la ratificación de nuestra decisión, la cual va en la misma línea que la expresada por el Dr. Vázquez Labrador en su Informe de opinión facultativa".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-26','Ana: Conversación con Pilar Martín, ESM: Virgina - Futuex, le ha comentado las sospechas de que José Manuel no toma la medicación adecuadamente y trapichea con las pastillas. Pero no tenemos pruebas de nada. *Lo ha hablado con su Psiquiatra, pero éste lo da por imposible, dice que mientras al menos se ponga el inyectable ya es "lo dará por bueno". Plantea la opción de que alguien pueda controlarle y administrarle la medicación. Le digo que estando en su casa eso no es posible. *Por otra parte informo a Pilar de la llamada de ayer de José Manuel en la que decía que no quería el caterin y que le suban la asignación. Por supuesto esto no se va a hacer. ···································································· Correo de Toni-Futuex: "A continuación adjunto varios presupuestos solicitados por Jose Manuel Romero Medivilla y según el nos indica aprobados desde la comisión, como ponemos todas comunicaciones en cuarentana lo trasladamos, se trata de la compra de lavadora que no tiene (aunque habria que considerar si va permanecer mucho tiempo en el domicilio o va valorarse la idea de ingreso en centro) ropa, cuya necesidad si hemos comprobado pues que ha engordado bastante, y el telefono móvil que no segun el indica no funciona. A continuación adjunto presupuesto para ropa de Jose Manuel Romero, dicho presupuesto se solicito antes del estado de alarma y estaba pendiente para su aprobación,pero dados los hecho quedo todo parado, el es consciente que está realizando bastante gasto en el último mes pero apenas tiene ropa y la que tiene le va bastante pequeña puesto que ha engordado bastante y la ropa no le cubre. Por lo que se envía la solicitud junto al presupuesto que realizó que dudo que hayan variado los precios puesto que la mayoría de los productos son prendas básicas que mantienen su precio temporada tras temporada. ... Se aborda el asunto de la avería del teléfono y explica que le han dejado uno pero que el suyo está destrozado porque le ha dado un golpe fuerte, enseña un terminal viejo que es diferente al que utilizaba habitualmente... es importante mencionar que continúan los conflictos constantes con su hijo, hoy explica que la novia de este se está tomando su medicación para la anemia y se ha quedado sin ella, se le recuerda la importancia de hacer un uso correcto de la medicación y la peligrosidad de compartirla..." ··································································· Contesto a Toni con copia a Pedro: "Buenas tardes Toni, Gracias. Haces bien en poner todo lo que os diga en duda, porque yo le dije que hasta que no vieran los presupuestos y tomaran las decisiones en la sección económica no se podía comprar nada. Eso sí, añadí que había que establecer prioridades, que unas cosas podían urgir más que otras, como lavadora y teléfono, pero deben dar el visto bueno desde la sección económica y son muchos gastos los que se plantean en poco tiempo. Aún falta también presupuesto para la limpieza profunda del domicilio con carácter previo al Serv. De Ayuda a Domicilio. La subcomisión para CRR sigue en standby y no creo que lo vayan a conceder fácilmente dado el historial…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-05-26','Ana: Correo de Toni-Futuex: "Te envio hoja con las situaciones acontecidas en torno al tema obra de la casa de Manuela Morato (el nieto ha llamado esta mañana la comparañera)" ································ Guardo nota de incidencias en el expte. digital. *José Manuel no ha dejado entrar a uno de los albañiles en la vivienda para hacer mediciones y poder elaborar informes. El otro parece ser que no vio el informe del aparejador (técnico municipal) que se le remitió por mail. ·························· Escribo a Toni y le pido, ya que Gloria es la que está en contacto con los constructores, hable con el aparejador municipal y pregunte si el proyecto de obras necesario lo pueden elaborar desde el Ayto. o tienen que ser un arquitecto privado. Lo ideal sería lo primero. Y si fuera la segunda opción, que contacte con algún arquitecto que acuda al domicilio y haga el proyecto de obra acorde al informe técnico del ayto para que puedan elaborar presupuesto los albañiles y proceder lo antes posible a las obras necesarias. ···························································································································· Llamada de José Manuel Correa, nieto de Manuela (927 582 309) pregunta si hemos hablado con Javier, el aparejador del ayto. Le digo que precisamente Pedro iba a llamarle, no sé si habrán hablado ya. Me facilita un número de atención mientras dure el teletrabajo: 690 94 18 37. ··············································································· Nuevo correo de Pedro, Jefe Secc. CTAEX: "Hola de nuevo, Ana. Acabo de hablar con el Aparejador del Ayuntamiennto y sí, es necesario un Proyecto Técnico. Lo que no es necesario es que lo realice un arquitecto: puede ser un arquitecto Técnico y me comenta que no cree que el coste pueda superar los 600 euros. He quedado en que me va a enviar los contactos de varios Arquitectos Técnicos de la localidad. Cuando los tenga te los envío, se los pasas a Futuex y que les pidan presupuestos. …Seguimos." ···················································································· Envío por mail a Toni-Futuex los contactos que le facilitan para que Gloria llame y pida presupuestos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-05-27','TERESA: Desde la Junta Directiva, y valorando la situación de Josefa y las mejorías que ha tenido en estos meses, se ha llegado al acuerdo de bajarle de Grado. En este caso, sería bajar del grado II al grado I, bajando así la cuota de 1190 a 969 euros. Para nosotros sería un placer poder seguir cuidando de ella, ya que sentimos que se encuentra muy adaptada, tanto con cuidadores como con los compañeros. Aún así, para tratar mejor el tema, le facilito mi número de teléfono y hablamos más tranquilamente: 617 66 53 97 (Teresa) HABLO CON TERESA Y LE COMENTO QUE ESE PRECIO TAMPOCO LO PODEMOS ASUMIIR YA QUE SUS INGRESOS SON DE 726 EUROS DE LA PENSION DE ORFANAD. VA A TRAMITAR LA DOCUMENTANCION PARA SOLICITAR PLAZA PUBLICA VIA DECRETO, LE ENVIARA LA DOCUEMNTANCION A AGUEDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-05-26','Ana:Llamada de Javier, Director CRR-Plas (677 407 640): llama para comunicar que Emi, ayer por la tarde pidió el alta voluntaria y se marchó del centro. Al parecer se enfadó mucho cuando le comunicaron que las gafas que había encargado sin autorización de la CTAEX iba a tener que pagarlas de su próxima asignación mensual, con lo que se le vería reducida la asignación diaria para gastos de bolsillo. *Intentaron que recapacitara y convencerla para que se quedara, o al menos que pasara allí la noche y se lo pensara mejor, pero no hubo forma. Como es curatela económica se la dieron. **Debió de sacar mucho dinero del banco, no saben exactamente cuánto, pues llegó cargada de cosas que se había comprado (móvil y reloj entre otras), además se fue en taxi a casa del hermano de Mariloli en Almendralejo (190 €). *Javier ya ha hablado con Carmen Ferrer - Secc. Salud Mental. Y aunque Carmen ha propuesto que no le den de baja en el recurso todavía por si Emi cambia de idea, Javier se mantiene en que no van a hacer excepciones pues nunca las han hecho y considera que Mariloli debe aprender de sus actos y vivir las consecuencias de sus decisiones. ·· En cuanto a la factura de las gafas de Opticalia, pregunta qué hacer. Le digo que desde la CTAEX no se autorizó dicho gasto, no obstante hay que consultarlo a la secc. ecca. **Envirá un mail para comunicar por escrito todo lo acurrido y plantera lo de la factura también. ···························· Comunico por mail a la secc. ecca. la retirada de efectivo del banco que ha realizado Emi sin autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-05-22','Ana: Hablo con Manuela Glez. Jefa de Secc. Discap.: Manuela dice que Josefa en estos momentos no puede pasar a centro, supondría aislamiento de 14 días. Y para asegurarse de que el retorno es viable habría que hablarlo con Ana, TS del Plena Inclusión-Zafra. Se podría plantear el que fuera unos días a su casa y después volver a su plaza para que no la pierda, pero de forma programada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-05-27','En relación con la solicitud de asistencia jurídica gratuita, enviamos al abogado designado provisionalmente, correo indicándole que la Comisión De Asistencia jurídica de Badajoz, aún no ha resuelto. Una vez lo hagan, lo comunicarán al solicitante y al abogado designado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-05-27','Ana: Envío correo a Estrella Durán, TS del CSS-Plas.: "Buenos días Estrella, No hemos vuelto a hablar en relación a Josefa Domínguez Blanco. ¿Se mantienen el mismo planteamiento en la UHDAC? A mí aún no me han confirmado cuántos días son los permitido al año para permanecer fuera del recurso residencial de discapacidad sin perder la plaza, haré la consulta de nuevo. No obstante, tanto Pedro Gracia, Jefe de secc. de la CTAEX, como Maite Gómez, Técnica de Discapacidad que conoce el caso, coinciden en que no va a funcionar la convivencia con el hermano. Tal vez una temporada sea positivo para ella, y más aprovechando “las próximas vacaciones de verano”, pero explicándole que puede tomarlo como una prueba y que tras ella debería volver a la residencia, pero que según como funcione todo se podría ir valorando un retorno más definitivo al domicilio a medio-largo plazo (si las pruebas, más largas que las últimas visitas, funcionasen bien). Ya me vais diciendo qué opináis y cómo sigue ella. De momento desde la CTAEX como tutores, no se autoriza el retorno a su casa. Cuando me confirmen los días autorizados te lo comunico. Un saludo. PD: Pongo en copia a Pedro, jefe de sección, para que esté al corriente y por si quisiera hacer alguna aportación." ······································Y vuelvo a preguntar a Maite Gómez, mediante email, los días permitidos de ausencia del recurso. **Los días de ausencia permitidos son 45 al año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-05-27','(Pedro)Llamada de Dª Gema, hermana de Juana (667-095756). +++"Mi hermana NO quiere volver al colegio. Quiere ir por el día pero volver a casa para dormir...Y yo no la voy a obligar..." +++Se le trata de hacer entender que lo mejor para Juana es estar en el Centro y que luego ya se autorizarán las visitas o estancias más prolongadas...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2020-05-26','Correo-e de Alberto: +++Hola a todos. Os hago un breve resumen de la reunión de ayer en el Ayuntamiento de Puebla de la Calzada entre Reme, la Trabajadora Social, su compañero policiá municipal, el tutelado Bartolomé y yo. El objeto principal de la reunión era la modificación del reintegro permanente que se le da al tutelado. Se alcanza un acuerdo con el tutelado, con el ok de la trabajadora social y la perplejidad del policía municipal ante los gastos del tutelado. Principales puntos acordados: • El reintegro permanente, a partir del próximo 01/06/2020, pasa a ser de 108 €/semana (470 €/mes). • Se informa a tutelado que tiene unos gastos totalmente excesivos en cuanto a teléfono (Vodafone) y energía (Endesa) y que, si la suma de estos conceptos y otros (imprevistos que la CTAEX se viera obligada a pagar), superase los 200 €/mes, ese EXCESO por encima de los 200 €, se detraería DIRECTAMENTE del reintegro mensual del mes siguiente. Tutelado ACEPTA. • Se informa REPTIDAMENTE al tutelado, y el mismo ACEPTA, de los pagos que a partir del 01/06/2020 deberá ASUMIR con su reintegro: o Pienso o Taxi o Ropa y calzado o Farmacia o Cualquier reparación o arreglo de la vivienda, cualquier compra de muebles o electrodomésticos, o similares. • Se informa REPETIDAMENTE al tutelada, y el mismo ACEPTA, de que no se aceptará pago alguno que PREVIAMENTE no haya sido autorizado por la CTAEX. Se le informa que estos gastos como norma no se aceptarán ya que serán abonados por el con su asignación. • Se garantiza alimentación mediante acuerdo con 2 supermercados x importe de 325 €/mes (se encarga de este control la trabajadora social del Ayuntamiento (Reme). • Por CTAEX se siguen abonando préstamo hipotecario, cofidis, oar, seguros vigentes a día de la fecha, vodafone, endesa. Se informa a tutelado que CTAEX no autorizará un sólo gasto que no venga incluído en el listado anterior. Tutelado ACEPTA. • Se informa al tutelado de su situación económica anterior al día de hoy y como será a partir del 01/06/2020. Tutelado ACEPTA. • Se acuerda con tutelado REVISAR esta situación en DICIEMBRE de 2020 y NO ANTES.: o se verá la amortización de préstamos y otras deudas. o se planteará la posibilidad de afrontar un gasto dental muy elevado que el pretende afrontar. o se valorará la posibilidad de aumentar el reintegro mensual. Todos conocemos a Bartolomé. Cualquier llamada, duda, petición pasará por la trabajadora social del Ayuntamiento, Reme o por Belén. Cualquier cuestión que nos llegue a los demás, NO LE DEMOS CARRETE, por favor, centralicemosla en BELÉN y luego, si se escapa de la esfera ECO, lo vemos entre todos. Repito. Lo que tenga que ver con Bartolomé, que generalmente se circunscribe a tema económico (lo decore como lo decore), se lo pasamos directamente a Belén y luego, si es necesario, entre todos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-27','Ana: Recibo llamada de José Manuel (de nuevo desde el nº 655 587 842): Pregunta si se sabe algo de los presupuestos. Le digo que están en manos de la parte económica. *Le han llamado del C.Salud para decirle que tiene que hacerse una endoscopia. Le han pedido ya la cita, le llamarán más adelante. **Por otra parte dice que la medicación le tiene decaído y que va a dejar de tomarla. Le recuerdo que no debe dejar medicación así como así, debe hacerlo bajo criterio médico y que debe consultarlo con el Dr. Jiménez Cano por si necesitaran reajustársela. *Pide que se le recargue la tarjeda de autobús. Le digo que ya se le explicó que no puede ser, no tiene dinero para todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-05-27','Ana: Correo de Pedro, Jefe Secc. CTAEX: Ayer hablé con Javier, director del CRR de Plasencia. "Finalmente no van a dar de baja la plaza de Emi, a la espera de que desde el SEPAD les digan el tiempo que la pueden mantener. No creo que Dª Emilia tarde mucho en regresar o en ingresar nuevamente en la UHB si sigue fuera del Centro." ················································································· LLamada de Emi (633 501 059), dice textualmente "me he metido en un lio y necesito que me ayudéis, Pedro es un machista" (refiriéndose a su pareja). NO quiere estar en esa casa. Acepta volver al CRR-Plas. y atenerse a las consecuencias, incluído el abono de las gafas que tiene que pagar. Ya no le queda dinero de los 325 que dice que retiró. No tiene dinero para volver ni en bus. ················································ Lo comunico a Pedro y a la secc. eco. Habrá que autorizarle dinero para su regreso al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-05-27','Ana: Llamo a Clara Gómez, Jefa de secc. Depend. (924 00 92 69), en relación a la solicitud de activación del expte. que se registró hace más de un año. Clara me confirma que el expte. está activado y pendiente de que acudan a valorarlo. Habrían acudido ya si no fuera por el Covid. Será de los próximos que acudan a valoran cuando comiencen a acudir las técnicas a los domicilios de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-05-27','Ana: Llamada de Miguel Ángel, Director del CRR-CC (687 487 908). Juan Mario se cayó ayer, llamaron al médico, pero cuando acudieron a verlo, había cogido unas muletas y se había marchado, por lo que no pudieron reconocerlo. Hoy le han llevado al hptal. Tiene fractura en el tobillo (la tibia y el peroné). Al salir de la consulta ha vuelto a caerse y se ha hecho una brecha en la cabeza. *Tienen que operarle y necesitan Consentimiento Informado pero a ellos no le han dado el documento. Les piden que llame yo al Hptal. Universitario (927 15 31 79), como comunica todo el tiempo pruebo en el 927 25 62 00. Me pasan con la Consulta de Traumatología de Urgencias, lo intento varias veces sin éxito. ···························· Llamo a Miguel Ángel, CRR, facilitará mi número y el fax al monitor que está acompañando de momento a Juan Mario para que lo facilite al especialista en el hptal. En cuanto al acompañamiebnto que necesita Juan Mario, preguntará a la secc. ecca. si es viable contratar a alguien. ··················································· Nueva llamada de Miguel Angel, seguramente operen esta misma tarde a Juan Mario, pero aún no han enviado C.I. (son casi las 15:00 h). Por otra parte, no han encontrado a nadie de confianza que pueda hacer el acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-05-28','Correo-e:PENAS PENDIENTES: +++De: Sub.Regimen_CP_Badajoz >SubRegimen.Badajoz@dgip.mir.es> Enviado el: miércoles, 27 de mayo de 2020 18:06 Para: MIGUEL FERNANDEZ DE LLERA >miguel.fernandezd@salud-juntaex.es> Asunto: RE: CONDENAS PENDIENTE DE ALEJANDRO NUÑEZ BONO Buenas tardes, Alejandro NUÑEZ BONO, DNI nº 80106903L fue puesto en libertad y EXCARCELADO el pasado 11 de DICIEMBRE de 2019. saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-05-28','Ana: Llamo al HUC (927 25 62 00), me pasan con Marisol-TS: Juan Mario no aparece hoy como ingresado. Encuentra informe en Jara, le dieron el alta ayer por la tarde. Pendiente de intervención quirúrgica. *Dice que no puede enviarme el informe sin autorización del médico y como le atendieron urgencias, no sabe dónde localizarlo hoy. ························································································· Recibo correo de Miguel Ángel Ramírez, Director CRR (residenciadir@feafescaceres.com): "Buenos días, os informo que sobre las 16:00 de la tarde del día de ayer al final le dan de alta a Juan Mario San Román Blasco a las 16:21, le informan al monitor que acompañaba al mismo que al no tener especialistas suficientes no se le va a poder operar al final y deciden hacerlo dentro de 15 días aproximadamente. Le hacen todas las pruebas necesarias para la intervención, a excepción de la prueba de la anestesia. Muy importante llevar el electrocardiograma (lo dejamos encima de la mesa de monitores) cuando envíen cita para la prueba de anestesiología que será dentro de 7 días. Tiene cita el próximo miércoles 3/6/2020 en el Hospital Universitario con Traumatología. Al no llegar posiblemente la carta con esta cita, dejamos en su carpeta un papel en el que pone ORDEN CLÍNICA DE CONSULTA, que tendremos que llevar el miércoles, a partir de las 9 de la mañana, para que se le atienda. De medicación le receta CLEXANE cada 24h (comenzará mañana), ENANTYUM 1-1-1, y PARACETAMOL solo si refiere dolor con pauta entre tomas de Enantyum. Os adjunto el informe de alta del Hospital Universitario de Cáceres en el cual viene especificado qué especialista ha sido quien le ha estado tratando durante todo el día de ayer. Un cordial saludo. PD: Siento mucho las molestias del día de ayer." ··································· Llamo a Miguel Ángel (687 487 908) acordamos que cuando sepan la fecha exacta de la I.Q. buscaremos acompañamiento. Me enviará datos de una empresa de att. sociosanitaria de confianza de Fernando, Monitor que acompañó a Juan Mario ayer en el hptal. *Contacto: Empresa RehActiva - Javier Bravo (927 21 17 52 / 665 28 79 06).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-05-28','(Pedro)Llamada de Dª Mª José, prima de Juana (654-742372). +++Mismo tema que ayer. +++Ella si plantea la remoción de la curatela y dice que la van a solicitar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2020-05-27','TERESA: ENVIO SOLICITUD PERFIL CADEX','2');
