insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-05-28','(Pedro)Llamada de Maribel Cortés (pareja de Pedro Tomás). 657-930954. +++Quieren pedir un préstamo para arreglar la casa del pueblo. "La íbamos a vender, pero nos vamos a casar y queremos arreglarla para irnos a vivir allí." +++POngo al tanto a Amalia y Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-05-27','TERESA: HABLO CON TERESA ADMINISTRATIVA DEL CENTRO ME COMENTA QUE A PARTIR DE JUNIO JOSEFA PAGARA 969 ERUOS POR LA PLAZA, AUN ASI NO LLEGAMOS CON LA PENSION QUE COBRA DE ORFANDAS CON CON LO CUAL LE INSISTO EN LA QUE GESTIONE LA PLAZA PUBLICA, CON ESTA NUEVA CUANTIA TENEMOS DIEERO PARA PAGAR HASTA SEPBRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2020-05-27','TERESA: ENVIO SOLICITUD DE DEPENDENCIA SIN INFORME SOCIAL YA QUE NO LO HE RECIBIDO EN ESTO ESTE TIEMPO Y TAMPOCO LO RECIBEN LAS COMPAÑERAS PARA LAS RENDICIONES ANUALES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-05-28','(Pedro)Llamada de la Dra. Ana Mª Megías, H. Don Benito-Vva.(86836 y busca 36213). +++No tiene claro como ahcer la derivación a la Unidad de Alcoholismo.Le explico la situación y que la finalidda era evitar el ingreso involuntario. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamo a Soraya (CSS de Plasencia). No está. +++Hablo con Rosa quien me dice que la Unidad de Alcoholismo ahora mismo está cerrada y que quizá se abra a partir del 8 de junio. +++Ahora no se están realizando ingresos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Llamo a la Dra. Ana Megías. Le informo sobre la situación en Plasencia. +++No tiene motivo clínico para mantener el ingreso y tampoco entiende por qué fue ingresado en el hospital. No lo va a derivar a la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-05-28','Ana: Recibo llamada de José Luis (687 581 061), hermano de José Manuel, éste último pide que le llame. ································· Llamo a José Manuel (667 384 817), quería hablar conmigo porque dice tener una llamada perdida de un nº muy largo y no sabía si le había llamado yo. Aprovecha para preguntarme si han dado ya respuesta a los presupuestos. Aún no sé nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-05-28','miguel, Pedro pasará a la firma y dejará enviado la próxima semana la Comunicación al Juzgado, la decisión de la Ctaex de no operar para su ratificación por dicho Juzgado nº1 de Almendralejo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-05-28','TERESA: HABLO CON LA DR BALDOMERO PARA COMUNICARLE QUE YA ESTA DE ALTA GUILLERMO, LE COMENTO QUE EL CEDEX DEBE TRAMITAR LA DERIVACION Y ME DICE QUE YA ESTA EL CEDEX EN ELLO (81837 CEDEX CASTUERA) TABMIEN LLAMO A LA POLICIA LOCAL PARA PONER EN CONOCIMIOENTO EL ALTA DE GUILLERMO, ME COMENTA QUE ELLOS TIENEN TODA SU DOCUMENTACION PARA QUE LO TENGANMOS EN CUANTA A LA HORA DE SU DERIVACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2020-05-29','TERESA: LLAMO A LA TS DEL HOSPOITAL PARA QUE LO RETIREN DE LA LISTA DE ESPERA QUIRURGICA LES COMUNICO A LA ENFERMERA DE NUÑOMRAOL QUE HEMOS RETIRADO A PABLO DE LA LSITA, LE PREGUNTO POR SU ESTADO DE SALUD Y ME DICE QUE SE ENCUTRA BIEN SIN DOLOR TAN SOLO QUE COGE MUCHAS INFECCIONES DE ORINA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-05-28','Ana: Llamo a Ana Benavente, T.S. del ESM-Plas. (620 275 323): dejo mensaje en el buzón de voz. ··········· Ana: Llamo al ESM-Plas. (927 458 036): como Ana está trabajando, le avisarán para que me llame cuando pueda. ································································ Cuando me devuelve la llamada le explico la situación. Hablará con Carmen Parrado, Psiquiatra, para ponerla en antecedentes, pero debemos enviar el fax solicitando dicho informe. ············································ Redacto e imprimo el fax. Pido a Pedro que lo envíe al: 927 458 046','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2020-05-28','(Pedro) Pongo a la firma la elección de Centro RAL: Zafra y Almebdralejo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-05-28','Ana: Conversación con Felisi (722 494 033), le confirmo que el próximo martes día 2 podrá retirar la asignación para la primera quincena de junio. A parte dice que necesita ropa, haré la consulta para retiradad de extra a la secc. ecca. Por último, un sobrino suyo quiere hablar con alguien de la CTAEX en relación a la herencia de su padre. Le facilito los números de los Asesores Jurídicos. ··························· Envío un mail al ctutelar@ sobre el extra para ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-05-28','Ana: En relación a los correos enviado hoy por Damian, le llamo varias veces (622 834 876), pero no consigo contactar con él, no da llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-05-28','Ana: Llamada de Emi (633 501 059). Emi dice que le falta alguna de las medicaciones que debe tomar. Sólo le queda Transilium para hoy. La Olanzapina no se la echaron cuando se fue del centro. Acudirá hoy a la farmacia a ver qué medicamentos le salen ya en la tarjeta. Con respecto a su regreso al centro aún no le puedo confirmar nada, pues estoy a la espera de que me confirmen a mí. ···································································· Nueva llamada de Emi: dice que Pedro, su pareja, le está amenazando con no darme más comida. Al momento de colgar vuelve a llamar para decir que le ha amenazado con echarle de casa esta misma noche. *De fondo escucho una voz de hombre hostil, pero no entiendo lo que ha dicho. *Le indico a Emi que si fuera necesario llame al 112. ······································································· Conversación con Pedro, Jefe de secc. CTAEX, Emi podrá volver esta misma tarde o mañana al centro. Finalmente se le autorizará costear un taxi ········································· Se lo comunico a Emi. Llamará a un taxista que conoce. ··············································· Nueva llamada de Emi, me pide que llame al taxista, éste quiere que le confirme que va a cobrar. ················································ Llamo a Salvador, taxista (609 11 95 06). Confirmo que se le hará una transferencia bancaria. Facilitará la factura con el nº de cuenta al CRR para que nos la hagan llegar. Es el mismo taxista que le trajo desde Plasencia a Almendralejo. ··········································································· Correo de Pedro, Jefe Secc. CTAEX: "…Sí, ya he hablado con Javier y comentado las estrategias a seguir para “intentar”, por enésima vez, hacerle entender lo inadecuado y peligroso de su actitud y comportamiento. Antes de acceder al CRR deberá hacerse un PCR que ya desde el centro están tramitando para hacérselo mañana mismo. En caso de ser negativo retornaría al Centro donde debería permanecer unos días en aislamiento. Esta noche la pasará en un hostal que también Javier va a gestionar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-05-29','(Pedro) Correo del CRR de Mérida (29-05-2020). +++Ángel Pinilla: Ayer tuvo cita con Psiquiatra privado, le ve mejor y seguimos recomendando tanto él como nosotros que evite malgastar dinero en lotería. Ha mandado litemia que se hará el día 1 de Junio y próxima cita dentro de 6 meses, salvo que sea necesario antes. Esta mañana ha estado en el Fisioterapeuta. Observamos que hay días en los que tiene cambios de humor importantes. Ha mejorado en la rutina del sueño.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-05-29','(Pedro) Correo del CRR de Mérida (29-05-2020). +++Antonio Merchán: Sigue en grupo con apoyo de profesional para las salidas, no lleva del todo bien esta cuestión aunque se le han explicado los motivos en numerosas ocasiones. Intentamos incluirle en salidas "aunque no le corresponda" porque le observamos contestaciones que no son habituales en él. Ha discutido con la que era su pareja (también residente del centro) aunque siguen pasando tiempo por espacios comunes. Estamos pendientes de él, nos encontramos con la situación de que su Psiquiatra de referencia se ha jubilado y estamos a la espera de nueva cita (todavía no sabemos quién será su nuevo Psiquiatra).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-05-29','(Pedro) Correo del CRR de Mérida (29-05-2020). +++Mª Dolores Fernández: Estamos muy pendientes de ella por lo acontecido con Emi. Agradecemos enormemente vuestra llamada. Estamos hablando con ella todos los días. Hasta ahora, ha salido por las mañanas y vuelve muy contenta tras tomarse un café y una tostada. Hoy ha estado tomando algo con otra compañera del recurso. Me ha dicho que quiere irse a casa, como era de esperar, pero parece haber entendido que no es una opción actualmente. Ella misma me ha dicho que se siente muy bien. Ayer y antes de ayer se vistió muy elegante y hasta se maquilló.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-05-29','(Pedro) Correo del CRR de Mérida (29-05-2020). +++José María Guillén: Tal y como os ha comentado mi compañera Alba, está solicitando una cita para pedir un aumento de la cantidad económica que percibe. Parece que el confinamiento le ha ayudado a conocer más a sus compañeros y aunque, a veces se muestra irascible, está de mejor humor que antes del confinamiento. Parece que ha establecido una relación más especial con otra de las usuarias aunque ambos afirman ser amigos. Está pendiente que vuelva al traumatólogo por el tema de la mano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-05-29','(Pedro) Correo del CRR de Mérida (29-05-2020). +++Luisa Rodríguez: Seguimos pendientes y observando su evolución respecto al ajuste farmacológico. Hasta ahora la vemos bien, menos somnolienta y más respetuosa. Precisamente hoy ha sido el primer día que hemos tenido que ir a despertarla porque a las 11 no se había levantado todavía. Ella también sale acompañada de profesional, se ha notado gran avance en este sentido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-05-28','Ana: Llamo a José Manuel, nieto (927 582 309), para comunicar que Pedro, Jefe secc., habló con el aparejador municipal y se van a solicitar presupuestos de proyectos de obra, pero no obtengo respusta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-05-29','Ana: Vuelvo a llamar a José Manuel, nieto (927 582 309); no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2020-05-29','Ana: Llamo a Guadalupe Fuentes Benito, coordinadora del Piso Tutelado de Madrigalejo (605 918 070). Le explico que Anita Priscila no aparece en Jara por estar afiliada a ISFAS (El programa Jara se sustenta en la base de datos de Cívitas y en ésta ya no aparecen las personas afiliadas a seg. privados). Hasta ahora Anita no ha precisado acudir mucho al médico, las pocas consultas a especialistas que ha necesitado ha acudido por lo privado, pero de ahora en adelatne necesitará más atención médica. Dado que en Madrigalejo no cuentan con estos servicios privados, **solicitaré cambio a la Seguridad Social. ····· *Su nº de afiliación a IFAS es: 28-70323179/00 ································································· Según la web de la Seg. Soc. sólo se puede hacer cambio ordinario durante el mes de enero. El resto del año podría hacerse de manera extraordinaria. ·············································· Llamo a IFAS (91 567 77 01), me confirman que si se solicita en el mes de enero el cambio es automático. Si es preciso hacerlo ahora sería por la vía extraordiaria, en la que habría que presentar documentos que aleguen la necesidad del cambio en este momento (ejemplos: Cambio de domicilio que implique cambio de provincia se justifica con cdo. de empadronamiento. O si fuera por necesidad médica Informe Médico que aconseje el cambio. *No disponemos de informe que lo recomiende) De todos modos en estos supuestos deben estudiar el caso y pueden tardar en resolver hasta 6 meses. *La solicitud en enero podría enviarse telemáticamente a la dirección ifascaceres@oc.mde.es, escaneada y adjuntando la documentación que se indica en el formulario. ······················································································ Llamo a Guadalupe - PP.TT.: Acordamos que la semana que viene hablará con la enfermera y médico que tiene asignado (no entiendo cómo, si continúa en IFAS y anteriormente no se le ha hecho el camibo a Seg. Soc.) para valorar si esperamos a enero para solicitar el cambio o si emiten informe que podamos adjuntar ahora y hacerlo por la vía extraordinaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-05-29','(Pedro) Pongo a la firma la elección de Centro RAE: Nuestra Señora de la Luz. Se amplia con APNABA BJOZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-05-29','(Pedro)Comsulta realizada al Srvicio de Traumatología del Hospital Universitario de Cáceres. +++Conversación con María, Traumatóloga de Guardia (31590).PREGUNTA QUE SE LE PLANTEA: "Dado que se le dijo en Traumatología que no se le podría intervenir hasta dentro de aproximadamente 15 días, ¿no es posible que durante ese tiempo se pueda producir una soldadura defectuosa del hueso o un desagarro del tejido circundante que empeore el pronóstico de la recuperación?" +++RESPUESTA: " No, porque al tratarse de una fractura de calcáneo debe pasar al menos una semana para que la piel se recupere. En la consulta que tine prevista se valorará el momento adecuado de la intervención".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-05-29','(Pedro)Remito fax al ESM de Plasencia solicitando Informe Clínico para valoración de apertura de procedeimeinto de reintegro de la capacidad. +++SE obtirne el ok del envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-05-29','(Pedro) Nueva llamada de Dª Maribel Cortés (629561914). +++¿Ya habéis decidido algo? ¿ES que nos tenemos que ir del piso pronto porque lo necesita el dueño?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-05-29','(Pedro)Llamada del Hostal "Real" de Plasencia (927-412900). +++llaman para pedir una dirección de correo-e para enviar la factura. +++Comenta que Emilia se va a quedar allí hasta el lunes. +++Pido que pongan la factura a nombre de ella y que la envíen a ctutelar, indicando en el asunto "Sección Económica. Factura". ······································································································· Ana: Recibo llamada de Emi (633 501 059). Dice que ha pasado bien la noche en el hostal. Permanecerá en el mismo hasta el lunes por la mañana, cuando tendrá cita en la Clínica San Miguel para hacerse la prueba del Covid (PCR). Si resulta negativo podrá volver ese mismo día al centro y estar 7 días en aislamiento en su habitación, lo cual acepta. Expresa que después de la que ha liado y lo mal que lo ha pasado tiene que hacer las cosas bien. Por otra parte dice que apenas tiene dinero y sólo le quedan 4 cigarros, por los que cuando se le acaben dejará de fumar... Por último dice que le han llamado de la clínica dental porque aún no se han pagado los dientes. ············ Lo consultaré a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-05-28','HAY UNA COPIA DE LLAVES DE LA VIVIENDA DE CRISTINA VILLEGAS, EN EL CENTRO HOGAR DE NAZARET DE PLASENCIA, DONDE ESTÁ ACTUALMENTE JOSE PEDRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-05-29','(Pedro)Llamada de PNC (64596). +++Nos van a enviar de nuevo la opción para elegir entre LISMI y PNC porque se han dado cuenta de que los datos personales que nos enviaron son erróneos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2020-05-29','Ana: Correo de Laura Pulido, TS de la Secc. Depend. Plas. (laura.pulido@salud-juntaex.es): "Buenas tardes, Soy Laura (T. S. sección dependencia Plasencia). Tengo la revisión PIA de Guadalupe Barragán García pendiente, en ella solicitáis plaza en residencia de mayores y necesito saber qué localidades pido o ¿solicito en toda extremadura?. No tengo datos familiares, me imagino que no tiene personas de referencia. ¿Puedes decirme algo? Gracias." ·············································· Mi respuesta: "Buenas tardes Laura, Dña. Guadalupe, como ya sabéis, está tutelada por la Comisión Tutelar de Adultos y reside en el CRR de Plasencia. En este centro es donde mejor la conocen. En su día Guadalupe manifestaba querer irse cerca de Jaraíz de la Vera, lugar de residencia de su hija. No obstante hablaré con el centro para ver si pedimos algunas localidades concretas o dejamos abierto a toda Extremadura. Por otra parte, decirte que no hemos recibido en la CTAEX la Resolución del Grado de Dependencia, ¿podríais hacérnosla llegar? Gracias de antemano. Seguimos en contacto. Un saludo." ················································· Envío correo a Javier, Director CRR-Plas. preguntando preferencias o si dejamos abierto a toda Extremadura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-05-29','TERESA: SE LE VA A ENVIAR OBJETOS PERSONALES A ANDRES A LA UHB A TRAVES DE EMPRESA DE MENSAJERIA 23 EUROS. UNA VEZ SE VAYA A LA UHDAC LE LLEVARA EL RESTO ALLI LA DELEGADA TUTELAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-05-29','Correo-e del CRPS de Zafra: +++Esta mañana hemos hablado con Constanza y nos ha comentado que Beatriz ha sido valorada por la UME; pero debido a la evolución que ha tenido durante el ingreso y la gran mejoría que ha experimentado, consideran que no cumple perfil para ingresar (cumple perfil en cuanto a los continuos ingresos en UHB, pero no en relación a presentar inestabilidad emocional). Por este motivo, han decidido darle el alta hoy, con la condición que en cuanto vuelva a presentar algún signo de inestabilidad sintomatológica ingresaría de nuevo en UHB y pasaría automáticamente a UME. Han tomado esta decisión sabiendo que es cuestión de tiempo que vuelva a ingresar; esperemos que con todos estos ingresos no se produzca un deterioro tan grande que influya en su posible futura recuperación. Así que te comunico que Beatriz esta de alta desde esta mañana LE INDICO A FUTUEX QUE REFUERCE LAS VISITAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2020-06-01','Ana: Recibo email de Maribel Álvarez Bejarano, T.S. Residencia Ciudad Jardín Parque del Príncipe (trabajosocial@grupociudadjardin.com // 927 24 34 72): "Buenos días: Os adjunto la resolución de PIA de Jacinta Cabrera Mora para que lo incluyáis en su expediente. Ya se presentaron las facturas y recibos. Saludos" ······················· *Le reconocen Grado III de dependencia y el derecho a percibir la prestación económica vinculada al Servicio Residencial por un importe de 175€/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-05-29','Ana: Conversación telefónica con Damián (622 834 876) ································· En relación a la conversación mantenida envío el siguiente mail a Miguel, Asesor Jurídico - CTAEX: "Buenas tardes compi, Sólo pasarte los datos de contacto que me ha facilitado Damián hoy vía teléfono para que puedas contactar y terminar de aclarar/solucionar sobre la vivienda que tiene alquilada en Málaga: Tlef: 951 926 157 Email: imv.paa@malaga.eu Según ha dicho en numerosas ocasiones, y ha vuelvo a decir hoy, los inquilinos le han pagado muy pocas mensualidades y le deben mucho dinero. También han manifestado querer comprar la vivienda (alquiler con opción a compra), pero él dice que no el interesa venderla, se la dejaron sus padres y no quiere deshacerse de ella. Con quién ha hablado esta vez es con un tal José Luis del Ayto. Un saludo y buen finde!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-06-01','Ana: Envío correo a la secc. ecca.: "Buenos días compañeras/o, En relación a Damián Salvador Granados Heredia, éste plantea el que se le cambie la domiciliación bancaria de la ayuda que cobra por tener alquilada su vivienda a la cuenta nueva de Liberbank que le abristeis. Le he dicho que eso tenéis que valorarlo en la sección económica. Informa de que entre junio y septiembre tiene que cobrar el 5º semestre = 1620 €. La cuantía del siguiente será de 1350 €. Los datos de contacto que facilita para estas posibles gestiones son las del Instituto de la Vivienda de Málaga: imv.paa@malaga.eu // 951 926 157 Ya me vais contando. Buena mañana!!" ······················· Respuesta de Icíar: "Buenos días, Ana Seguimos con tema Damián, De momento yo no quitaría el ingreso de la ayuda del Santander porque todavía tiene dos préstamos que pagar y ya le hemos pasado la pensión a Liberbank, no vaya a ser que se quede a 0 aquella cuenta. Pero lo comentaré con Alberto A ver cómo se da la mañana" ···························································· Nueva llamada de Damián: Dice haber hablado con Miguel, Asesor Jurídico, pero se le ha olvidado decirle lo del nicho de su madre que es muy importante para él. Enviará un recibo de Parcemasa, para la renovación del nicho de su madre para otros 25 años. La dirección de e-mail de Parcemasa es: info@parcemasa.es / y la web: www.parcemasa.es La dirección física: Carretera Colonia Santa Inés - Campanillas, km 5 C.P.: 29590. Tlf: 952 43 41 00. Fax: 952 00 64 67/ 07. *Debe más de 2 años del nicho por importe de 50,53 €. La base imponible para otros 25 años = 780,04 €. -- Total 788,88€. ···························· Se lo comunico a Miguel, Jurídico y a la secc. ecca. mediante e-mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-01','Ana: Llamada de Javier, Director del CRR-Plas. (677 40 76 40): Emi anoche no durmió en el hostal, se fue a casa de no saben quién con Francis, otro usuario del CRR. Esta mañana acudión a hacerse las pruebas del Covid, pero a después ha acudido al CRR sin tener aún los resultados. Le han dicho que sin ellos no podía entrar, se ha enfadado, ha tirado allí su maleta y sus cosas y se ha ido enfadada no saben dónde. Javier ha llamado al centro de salud y hasta mañana no le dan los resultados de la PCR. En cuanto al hostal, ha llamado y todo ha ido bien, el único incidente es que Emi llamó al 112, acudió allí una ambulancia que en el hostal no esperaban y después dijo que era sólo porque tenía la tensión baja. La doctora le echó una buena bronca. ······································································· Llama Emi (633 501 059) bastante enfadada, apenas escucha ni deja hablar, dice que le ha ido al CRR despues de ir a hacerse la prueba y le han echado de allí. Expresa que tanto Carolina como Javier y Paula son muy malas personas. Le han reñido por gastar más dinero en el hostal y le ha sentado mal también, dice que lo paga y punto que para eso tiene su dinero. *No quiere dormir hoy en el hostal, que no se quiere gastar el dinero en eso y prefiere dormir en la calle. Le pregunto dónde ha pasado esta última noche y dice que sola en un banco de la calle, despues reconoce que con Francis, pues está saliendo con él, pero sigue diciendo que en un banco. Despues añade que uiere irse al CRR-CC, le recuerdo que allí no tiene plaza, la plaza la tiene en Plas. que es donde debería volver y más adelante si quiere puede solicitar el cambio de recurso como hizo en Mérida. *Le digo que mañana cuando recoja los resultados de la PCR, si es negativo puede volver al CRR pero que allí tendrán que hacer el aislamiento marcado por el protocolo, lo acepta a regañadientes. ·············································································· Nueva llamada de Javier (677 407 640): han llamado a Emi, ésta no quiere ir al CRR a recoger la medicación que ha dejado allí, dice que no se ha tomado la Olanzapina y está bien sin ella. Tampoco quiere ir a dormir al hostal, no quiere tener que pagarlo ································································ Hablo con Pedro, Jefe Secc.CTAEX; ha hablado con Mariluz, Jefa de Secc. Salud Mental y le ha comunicado la situación. ····· Si Emi vuelve mañana al CRR e incumple el aislamiento, desde el centro tendrán que comunicarlo a la policía. Y si se descompensa por no tomar la medicación tendrá que ingresar en UHB. *Mañana llamará a Javier-CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2020-06-01','(Pedro)Se recibe carta de Dª Mª Rosario Fdez. Cerecinos. +++Teléfonos de contacto: 981-635211//663-034247//682-875497. +++Dirección: C/. Isaac Peral nº 20 (01378) A Coruña.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATIAS'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2020-06-01','(Pedro)Se recibe carta de Dª Mª Rosario Fdez. Cerecinos. +++Teléfonos de contacto: 981-635211//663-034247//682-875497. +++Dirección: C/. Isaac Peral nº 20 (01378) A Coruña.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-06-01','miguel, me indica Angel que la abogada me remitirá email con documentación. Que quiere firmarse en la notaria de Juan Manuel Angel Avila (Angel Casas). Veo en la intranet que habrán de firmar ellos y ratificar nosotros a posteriori...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-01','(Pedro) Información proporcionada por MªLuz (SEcc. Salud Mental). +++El resultado del PCR no se lo dan hasta mañana, por lo que esta noche tendrá que dormir en el hostal. +++Esta noche no ha dormido en él porque se ha ido con otro usuario del CRR y ha pasado la noche con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-06-01','TERESA:Parece ser que no se han cargado como bien dice, por tanto, le digo la deuda total, teniendo en cuenta que, para el mes de mayo, como hablamos, la tarifa será de grado 1, siendo la cuantía desde este mes de 969 euros, para que los tengan en cuenta en los próximos meses. Mes de abril: 1190 euros Mes de mayo: 969 euros Total: 2159 euros. El número de cuenta para el ingreso es: ES49 0078 0009 7040 1002 4646 (BANCA PUEYO) Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-06-01','TERESA: LLAMO A OLGA PARA PREGUNTAR POR JOSE MARAI. ME COMENTA QUE ESTA BIEN Y QUE SIGUE RECIBIENDO EL SAD CON NORMALIDAD. LE COMENTO QUE TIENE CITA EN SALUD MENTAL PROXIMO 8 DE JUNIO PRA QUE ESTE PENDITE PUESTO QUE SUPONEMOS QUE LA HARAN TELEFONICAMENTE. LE DIGO A FUTUEX QUE COMIENCE CON LA VISITAS A JOSE MARIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-01','Ana: Correo de Toni-Futuex: "Buenos dias, se envía adjunto la factura de nuevo terminal móvil para el tutelado Juan Chamorro Holguín, modelo Wiko Y50 , configurado y sin pin de bloqueo para facilitar el uso. Nuevo número asignado 633391891. Con fecha de mañana martes 02 de junio, en visita planificada a Guadalupe, le será entregado. En la factura aparece el numero de cuenta para poceder al pago, Graciias!" ··············································· Pido a Toni que comuniquen el nuevo número a Salud Mental de CC. ··································· Llamo a Clara, TS C.S. (C.S. Logrosán: 927 360 769) Y se lo comunico. ····················· Clara me llama, la administrativa del C.Salud no quiere cambiar el nº, dice que tendrá que ir el propio Juan. ·································· Pido a Toni que Teresa se lo diga mañana e intente acompañarlo para hacer el cambio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-06-01','Ana: Recibo llamada de Maribel Mesa (924 010 142), Discapacidad; ha recibido la solicitud de plaza en C.Discapacidad de Mª Pilar, lo enviará al CADEX y solicitará perfil, pero duda que le vayan a dar plaza, pues entiende que según los informes es más perfil de Salud Mental que de Discapacidad. Índico que en Psiquiatría no opinan lo mismo y le informo sobre la trayectoria, gestiones e intervenciones en los últimos 8 meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-06-01','Ana: Recibo llamada de Ceferino (641 881 543), de nuevo transmite su deseo de cambiar al CRR-Ba, porque está allí su novia principalmente. Pero después dice que preferiría ir a Piso Supervisado, pues no quiere pasar su vida en un CRR y morir en residencia, aspira a algo más pues es muy joven. Pero se queja de que Carolina, Psicóloga del centro le ha hicho que no está para pasar a piso supervisado. Dice que hablará con Ana Benavente, TS del ESM-Plas. Se queja también de la asignación económica, de cómo se la administran en el centro, ahora le dan 1,50 € por la mañana y otro tanto por la tarde. *Abordo la idea de que quizá deba demostrarse así mismo y a los profesionales del centro que puede administrarse mejor y que está preparado pasar a piso. Le pongo varios ejemplos para que lo entienda mejor. Parece comprenderlo y gustarle la idea y dice que va a probar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-06-01','miguel, llega hoy del Jzdo Nº2 de Montijo decreto concediendonos 10 días para contestar a alegaciones a Procedimiento de Excusa de Curatela 78/2020. Visto con Amalia y Pedro. Remitimos a secretaria general solicitud de intervención de la abogacía firmada por el Director Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-06-01','Ana: Correo de Miguel Ángel, Director del CRR (residenciadir@feafescaceres.com): "Buenas tardes, Ana, te reenvío el informe de interconsultas de urgencia en atención primaria relacionado al incidente que presento Félix Figueroa en la noche del sábado. Un cordial saludo." Guardo el informe médico en su expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-06-02','Ana: Juana, secc. ecca, me comunica que hay que cambiar la pensión de Miguel a la nueva cuenta de liberbank. ············································· Cumplimento y pongo par la firma del D.Gerente la Comunicación de variaciones al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-02','Ana: Llamada de Emi (633 501 059); dice que se encuentra muy mal, está muy floja y con hambre, ha pasado la noche en la calle con Franci, han pasado frío. Según dice anoche no le dejaron entrar en el hostal por miedo al contagio. Le recuerdo que ella es la responsable de su situación actual. *Con respecto a los resultados de la PCR, dice que no quieren dar cita para recoger los resultados. *Si da negativo está dispuesta a volver al CRR y cumplir el aislamiento. Le digo bien claro que si lo incumple no tendrá más oportunidades en el centro. ·············································································· Ana: Llamo a Javier, Director del CRR-Plas. (677 40 76 40): ayer fue a recoger la medicación, aunque dijo que no se la iba a tomar toda, la cipresa no se la está tomando añade. Desde el C.S. llamarán tanto a Emi como al CRR para comunicar el resultado de la PCR, esta mañana a primer hora, pero aún no estaban los resultados. Nos lo comunicarán en cuanto lo sepan. ·· Llamarán también a Salud Mental cuando Emi vuelva al centro para que la valoren, por si fuera necesario reajustar la medicación. ······························ Llamo a Emi, le explico que no tienen que darle cita, se lo comunican por teléfono, sólo tiene que espera la llamada. +++++++++++++++++++++++++++++ (Pedro) Conversación con Javier (CRR Plasencia). +++Emi está ya en el CRR, EN AISLAMIENTO. La PCR ha sido NEGATIVA. +++Ha dormido esta noche en la calle con su compañero Francisco porque en el Hostal no la han aceptado porque ya habían desinfectado la habitación (tenía reserva de viernes a domingo). +++Ha regresado "muy bajita" de ánimos y cansada. +++Han llamado al ESM: no le han cambiado la pauta de medicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-06-02','Ana: Llamada de Beatriz, dice que le gustaría retomar la depilación láser facial, aunque la chica de "Silueta" le ha recomendado que los meses de verano (junio-sept) se haga la cera. También necesita dinero para peluquería y comprarse algo de ropa. *Enviará presupuesto a la secc. ecca. al ctutelar@ *Por otra parte, expresa que al CRP sólo acudirá un día a la semana, el que le marquen, para asistir tanto con la psicóloga como con la Trabajadora Social. A orientación laboral no va a acudir, pues en el propio hospital le han dicho que en estos momentos ella no está bien para buscar trabajo y ya cobra una pensión, no es necesario. *La cuota de socia (6 €) sí los quiere seguir abonando. Dice también que le gustaría hablar con Pedro, que con él se entiende muy bien, pide que le llame cuando él pueda. Por último pide disculpas por si en alguna ocasión ha hablado mal a alguien de la comisión, que ha estado muy malita. De ahora en adelante se tomará la medicación y hará las cosas bien.','2');
