insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-06-02','miguel, me remite la notaria de Juan Manuel Avila (Manuel Duran) email indicando que tienen prisa por firmar. Me confirma que nosotros iríamos como mandatarios verbales. Se firmaría por la tarde, y posteriormente tendríamos que ratificar la herencia.','2');
