insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-02','Ana: Llamo a José Manuel (667 384 817), pregunta sobre el presupuesto de la lavadora y el teléfono, dice que le urge mucho, que el teléfono viejo que está usando no el funciona bien y tiene que sacar la batería para cargarla en un cargador externo pues no tiene el cable cargador del mismo. Por otra parte comunica que tiene cita para la renovación del DNI el día 2/07/20 a las 13:40 h. Las tasas son 12 €. ······················································································· Pido a Coral, Secc. Ecca. que cuando acuda al banco lleve el alta de terceros de Romero Mediavilla. Se lo dejo sobre su mesa con un post-it.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-06-02','(Pedro)Conversación con la Dra. Marco, Cirujana del Hospital Don Benito-Villanueva (86661//86662//86663). +++Dª Josefa se encuentra con unas úlceras, al parecer de larga evolución (15 meses), en los pies que han evolucionado hasta la exposición de los tendones. Plantea la amputación por encima de las rodillas de ambas piernas o no intervenir.En estos moentos no hay infección. Anteriormente se ha estado tratando con antibióticos. +++Sobre la urgencia de la toma de decisión comenta que no hay que tomarla inmediatamente, porque lleva así mucho tiempo. +++SOLICITO nos envié INFORME CLÍNICO lo más explícito posible, con valoración de la alternativa más adecuada en su opìnión, junto con el consentimiento informado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-06-02','Ana: Correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Buenos días, Ana y perdona el retraso en mi respuesta...Le comuniqué a Maripaz tu correo respecto a Josefa y ha decidido que va a convocar una subcomisión de caso. Te sigo informando.. Gracias. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-06-02','miguel, nos citan del jzdo de CORIA Nº2 procedimiento division de herencia 484/2019 para 29-6-20 a 10h','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-04-20','Ana: Se reciben 2 Faxes del CSS; uno del día 18 comunicando que Juan Ángel se ha fugado y otro del 19 comunicando que ya ha regresado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-02','(Pedro) Conversación con Javier (CRR Plasencia). +++Emi está ya en el CRR, EN AISLAMIENTO. La PCR ha sido NEGATIVA. +++Ha dormido esta noche en la calle con su compañero Francisco porque en el Hostal no la han aceptado porque ya habían desinfectado la habitación (tenía reserva de viernes a domingo). +++Ha regresado "muy bajita" de ánimos y cansada. +++Han llamado al ESM: no le han cambiado la pauta de medicación.','1');
