insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2020-06-02','Ana: Recibimos comunicado del INSS, han resulto aprobar el Complemento a Tercera Persona a Eduardo. La PFHC ahora asciende a 593,40 x 12 pagas, con fecha de efecto de 1/04/2020.','2');
