insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-06-02','Ana: Llamada de Damián (622 834 876); hoy se muestra contento de la entrevista que ha mantenido con Paula, "es una persona excelente" manifiesta litaralmente. Han hablado de la posibilidad de que en un futuro Damián vaya a vivir de forma independiente, e incluso de que pueda recuperar su capacidad legal completa y pueda volver a administrar su dinero él mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-06-03','(Pedro) Reviso todo su expediente para ver los informes médicos disponibles y solamente aparecen, en la carpeta "Aspectos Sociales"tres: +++Ingreso en el Hospital de Mérida (Medicina Interna)del 25 de febrero al 15 de marzo de 2005, en el que se habla de edemas leves en miembros inferiores y edema en hemicuerpo derecho, dando el alta por buena evolcuión. +++Ingreso el Hospital de Mérida (Medicina Interna)del 2 al 26 de febrero de 2007, con edemas importantes en kiembros inferiores con lesiones ampollosas. +++Consulta del 23 de septiembre de 2010 en el Servicio de Cardiología del Hospital Don Benito-Villanueva: insuficiencia mitral y tricúspidea ligeras.No parece hacer mención a la patología anterior. +++Tampoco hay registradas incidencias al respecto en la Intranet ni registro de correos-e en ese sentido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-06-02','Ana: Recibo llamada de Maite, cuñada de Desi y hermana de Ángel (943 116 193 / 686 641 770), llama desde Irún, lugar de residencia. Se muestra preocupada por Ángel, pues lleva una temporada notándolo mal. Expresa que Ángel y Desi necesitan unos arreglos básicos en la casa que recientemente han adquirido y a la que ya se han trasladado a vivir. Ángel ya ha comprado el termo de agua caliente y contratado un fontanero que se lo instale, pero ahora tiene un problema mayor, no hay presión de agua por lo que el calentador no funciona. Le han explicado que habría que cambiar las tuberías, pero el presupuesto que le han dado asciende a 1500 € y no puede pagarlo. Además habría que cambiar la bañera por un plato de ducha. A ella le gustaría ayudarles de alguna manera, pero económicamente no puede. **Le parece injusto que siendo él el único que ha aportado económicamente a la relación ahora se haya quedado sin la mitad del dinero que podría utilizar para los arreglos. Ha estado hablando con Ana, Psiquiatra de Ángel, quien le ha manifestado que Ángel está mal, que desde el CSS no pueden proporcionarle el apoyo que venían recibiendo antes debido al estado de alarma y que el principal problema es que ahora no tiene dinero para hacer frente a los arreglos que necesita hacer en la vivienda por haberse gastado su parte de la venta de la vivienda de Valrío en la casa. La psiquiatra no entienden que desde la Comisión no se colabore, pues Desideria tiene su parte de la venta que se podría utilizar para los arreglos que hay que hacer. ··· Entiendo su preocupación, pero le explico el posicionamiento de la CTAEX y las gestiones que se han llevado a cabo hasta ahora; Nuestra tutelada es Desideria, por quién tenemos que velar es por ella. Se le ha solicitado una nueva prestación, que a priori no era necesaria, pues como unidad de convivencia con los ingresos de Ángel hasta ahora habían tenido para vivir bien. Ella aporta una cuantía proporcional todos los meses para los gastos cotidianos. *Le rebato la idea de "injusticia" por la cuestión económica, pues son matrimonio en régimen de bienes gananciales y se le pone varios ejemplos. La vivienda la ha comprado Ángel por decisión propia, sin contar con la opinión de la CTAEX en cuanto a Desi se refiere. Una vivienda que no reúne las condiciones mínimas que requieren. No había ninguna prisa para dicha compra, hasta octubre tenían contrato de alquiler de un piso que estaba muy bien y sí reunía todos los requisitos, podría haber esperado, y en su caso, haber comprado una vivienda con el visto bueno de la CTAEX (siempre y cuando el Jdo. hubiese autorizado). Desideria se ve directamente afectada siempre por las decisiones e impulsos de Ángel. La situación que tienen ahora es consecuencia de las decisiones tomadas y deberían aprender de ello. ·· Maite dice comprender todo lo que le expongo, pero dada la situación en la que ya están pide que por favor les ayudemos para que ambos estén bien, se trata de su bienestar. Ella sólo quiere verles feliz y por 2000 € se podrían solucionar las necesidades básicas, por lo menos que pudieran ducharse con agua caliente. “Bastante tienen con lo que tienen ellos, ya sufren bastante con su enfermedad”. "Si pudiera tener yo la tutela.." añade, le indico que puede solicitarla al Jdo. ··· Acuerdo que lo valoraré en equipo pero que no le garantizo nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-06-03','(Pedro) Conversación con May. +++Por Emergencia Social habría posibilidad de plaza ahora en Arroyo de San Serván, Villafranca de los Barros y, probablemente en Mérida. +++El ingreso se tendría que hacer en 24h, previa prueba de PCR y aislamiento en la Residencia: si el test se le hiciera, por ejemplo, hoy, el resultado estaría por la mañana y ella debería ingresar a mediodía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2020-06-03','(Pedro) Conversación con José (927-004245///649-036297), a raiz de la llamada de Juana dicendo que quiere ir a ver a su hermana, a quien le han detectado un cáncer. +++Su intención es ir a ver a sus otros dos hermanos, con mascarilla -""llevaré cuatro..." y con su hermana hablará por videollamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-06-03','(Pedro) Llamada de la Subdirectora de Tratamiento del C. Psiquiátrico Penitenciario de Sevilla (954-856002). +++Van a enviar los informes en relación a la excarcelación de Juan Carlos a ctutelar. +++Los han enviado también al SES para iniciar el protocolo correspondiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-06-03','miguel, Conforme conversación telefónica con el tutelado Damián Salvador Granado Heredia el lunes 1-6-2020 quiere que haga constar lo siguiente y lo comunique a la parte económica, lo cual hago el día 3-6-20 en email a Alberto. (Cáceres) Dice que el Saldo actual en el Santander es de 5.887€ Quiere que se le DOMICILIEN en la cuenta de liberbank los siguientes pagos: 1.-Comunidad de vecinos del piso de C/ Dan 9, 4ºA,1, Barriada Cortijo de Torres, 29006,Málaga: contacto Administrador García Prieto tlfno 952-336000. 2.-Teléfono, compañía LOWI (tlfno del curatelado 622834876): contacto Lowi Vodafone Enabier Esa, Avda Amérida 115, 28042, Rgtro Mercantil Madrid , tomo 16076, Folio 106,secc 8, hoja M.272208, inscripción 1º cif B82896119. Referencia domiciliación 9902104312 (período de facturación 1 al 30 de Abril, CI 00000020525393), le pregunto que para qué, y me dice que para cambiar la domiciliación, y que no tiene todavía la factura de mayo. Tlfno Lowi clientes 1456(no encuentra otro tlfno ni email), indicándome la página web http://www.lowies/nuestras tarifas 3.-Cofidis: Tlfnos de contacto ( 900-670670; 682-860531;900-848012; 900-844205; 628-226033) 4.- IBI: referencia Rgtro Ayto 2020/48926. Justificante pago de recibo ibi. Subdirección Att al ciudadano y comunicación (Departamento y relaciones con lo sciudadanos) AG/decímetro Asunto: Remisión Justificante pago de ibi fecha 14-2-20 Quiere también se le envíen las claves de Liberbank, únicamente dice para saber y tener controlado el saldo y lo que le van cobrando, comprometiéndose verbalmente que no va a tocar ese dinero) A efectos de IRPF 2019 me indica que desde el Ayuntamiento le ingresaron dos importes: 2160+1890€ También dice que en la casilla 505 de la Renta falta por poner 4,91€. En relación al ALQUILER de la vivienda de Málaga: Nº de contrato de arrendamiento: PAA2388 Datos del Contrato: Ref reg Ayto 2020/48926. Período de Duración 1-8-2018 al 1-8-2021. Email de contacto del Ayto de Málaga: imv.paa@malaga.eu; Ref catastral: 9931101UF6693SO157YI. Me dice que el Ayto de Málaga tiene mal su dirección actual que lo arreglemos, que es Ctra Circunvalación Sur Km2, Grupo 5 CRR, 10600, Plasencia. Inquilino Antonio Pinto Estrada (tlfno 693-376363) Dice que el inquilino le debe muchísimo, no sabe cuánto, pero que ahora tendría que estarle ingresando 135€/mes. Del Ayto dice haber recibido 1890€ del 4º Trimestre, cree que va a recibir en julio o septiembre 1620€ del 5º trimestre del contrato, y espera 1.350€ del 6º semestre. Me indica un teléfono de contacto del Ayto de Málaga 951-926010 y 951-926157, preguntar a Loreto y/o José Luis. Tenía un Juicio el 14-4-2020 que ha sido aplazado dice (no sabemos nada del mismo, no tenemos documentación). Más adelante le pediremos documentación. NOTA: pide por último no mandar DNI suyo al inquilino ya que lo quiere para empadronar a su hija, y como no le paga él quiere echarle. Quiere que amorticemos el Préstamo del Banco Popular para lo cual dice que tiene suficiente dinero en el Banco Santander porque su saldo actual es de 5.887€ y que sólo espera cargos de unos 25€ tlfno, 80 de Cdad, 35 de Cofidis, el ibi que lo paga en plazos (111,79€ +111,78€ ya pagados y que ahora le deberían cargar 55€)+169€ del préstamo del popular que quiere le hagamos cancelación económica anticipada del préstamo. Para la cancelación económica anticipada del préstamo del Banco Popular (actual Santander): Tfno de contacto oficina de Plasencia y que ellos nos den la de su sucursal porque no tiene el tlfno de Málaga…Tlfno sucursal de Plasencia 927-410050 y 927-413700. Pendiente por pagar del popular: 3.784,53€ Identificación del contrato, ES 09 0075 0214 61 0602114154, CONTRATO 214/47 torremolinos, Op Pza de Andalucia. EF Marques de Salana. Anexo de Contrato (identificación Contrato Marco 0075-0214-6650008418) Email: 00750214@bancopopular.es Tlfno: 0034-952-384844. PLAN DE PENSIONES: Dice tenerlo y también quiere que lo cancelemos, cuyos datos son los siguientes: Allianz popular ASSET MANAGEME-NT S.G.I.I.C. SAU, nº se participación 2292444, dice cree hay 95,30€ Dice que unido al plan de pensiones hay un SEGURO: Plan optima pruden ; Apv-vi. Ries.Eu. P.A. 00010001480000023500.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2020-05-05','Ana: Recibimos escrito orinal del CADEX (el que nos adelantó por mail Domingo Salas, "no ha sido valorada")','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-06-03','(Pedro)Correo-e remitido a Alberto y posterior conversación con él: +++Te reenvío el correo de Ana sobre Dª Desideria B.B. (20-T-18) en relación a cambio de tuberías en la vivienda que D. Ángel ha comprado. Pensando en el bienestar de nuestra tutelada, que te parecería que, una vez tengamos los presupuestos correspondientes sobre las actuaciones que realmente haya que hacer y el coste real que supongan (vamos a pensar que son los 1500-2000 euros que se plantean en el correo) se pagase esa cantidad por la parte de nuestra tutelada con las siguientes condiciones que, por supuesto, habría que plantearles previamente a ellos: +++++++++++Retirar de la asignación mensual que le pasa ella a él, por ejemplo, la mitad (100 euros) hasta cubrir esa cantidad o +++++++++++Retirar definitivamente dicha asignación durante el tiempo que se tarde en restituirla. Es cierto que D. Ángel no contó con la Comisión para la compra de la vivienda, dado que no tenía por qué hacerlo puesto que no esta tutelado por ella. Pero sí que sus decisiones afectan a Dª Desideria y en ese sentido debería habernos consultado…En cualquier caso, el único motivo para aceptar esta situación es mejorar las condiciones de habitabilidad de la vivienda en relación con el bienestar de ella. Ya me dices que te parece el tema, ya que la alternativa de ingresar a ambos en el CSS no es viable por dos motivos : porque en estos momentos no existe al parecer criterio clínico para ello; porque él no quiere y ella irá donde él vaya; y porque especialmente para Dª Desideria sería contraproducente su separación, ingresándola solamente a ella. Lo hablamos. +++CONVERSACIÓN: de acuerdro en las alternativas. Que elijan ellos la que quieran, previo conocimiento por nuestra parte de los presupuetsos y su aceptación. Durante el tiempo que tarden en devolver el dinero a Desideria no pueden pedir nada más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-06-03','Ana: llamada de Vanesa: va a solicitar la ayuda para Suministro de Mínimos Vitales. La TS le ha solicitado el Contrato de Alquiler y el justificante de pensiones. Me volverá a llamar para facilitar el email de la TS para enviarselo. Ahora tienen una nueva TS. ·· En cuanto a la situación de violencia de genero vivida, dice que está a la espera de juicio. Le amenazó con una barra de hierro aunque finalmente no llegó a darle con ella. Ya no conviven juntos. Han finalizado la relación. ···················································································· Recibo llamada de Isabel Pino, TS de Miajadas (927 347 000), ahora lleva ella el caso. Como no tenemos Cdo. de Pensiones y en la Declaración Indiv. de Pens. de este año aparece la cuantía, solicitará ella el Cdo. a la Seg. Soc. *Le envío por mail (ipino@miajadas.org) el Contrato de Alquiler. *Le concederán unos 300€ que se abonarán directamente a las empresas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-06-04','Ana: Correo de Miguel Ángel, Dtror. CRR-CC (residenciadir@feafescaceres.com): "Buenos días Ana, te remito el informe de revisión de traumatología de Consuelo Nevado Pacheco. Un cordial saludo." ····················· Guardo Informe en el expte. digital. Según el mismo, Consuelo presenta dolor en el tobillo derecho. Le ponen en Lista de Espera Quirúrgica para extaer tornillo del pie derecho. ···························· Recibo del HUC, por @, C.I. para interveción quirúrgica. *Imprimo y pido a Pedro, jefe de secc., que lo ponga para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-06-03','Icíar. Llama Jonathan desde Badajoz, se encuentra en la oficina de Liberbank para retirar su asignación semanal pero no se la dan porque su oficina está en Mérida. Llama desde el teléfono de un amigo, Víctor (691039664), con el que se encuentra en ese momento. Dice que a partir de ahora va a vivir en Badajoz en casa de ese amigo y que le pide 100 €/mes por la habitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-06-04','(Pedro)Conversación con el Dr. OSAMA, del Servicio de Cirugía del H. Don Benito-Villanueva (86661) +++No es posible salvar ninguna de las dos piernas. +++RIESGO DE MUERTE: existiendo, es mayor durante el postoperatorio que durante la intervención. +++SI SE AMPUTA: tras unos días en el Hospital volvería a la Residencia donde se le practicarían curas periódicas, bien por la Enfermería del propio centro, bien por Enfermería del C. Salud o bajo su supervisión. Cuando se le diera el alta desde el S. de Cuidados Paliativos se informaría/formaría a las Enfermeras de la Residencia en cómo atender esas curas en el caso de que fuera necesario. +++SI NO SE AMPUTA (no intervención): LOS CUIDADOS SERÍAN LOS MISMOS, son cuidados sencillos de limpieza, desinfección y colocación de apósitos limpios. +++NO SE REQUIEREN CUIDADOS ESPECIALES DE ENFERMERÍA que pudieran precisar de plaza sociosanitaria. +++EVOLUCIÓN: incluso con la mejor atención posible de enfermería, no se pueden descartar problemas de infección de la herida. En estas situaciones se volvería a traer a la paciente al Servicio de Urgencias y se le prestarían los cuidados necesarios. +++EL REGRESO A LA RESIDENCIA SUPONE REALIZAR TEST PCR PREVIO. +++SEGÚN EL Dr. OSAMA: "NO SERÍA DESPROPÓSITO NO HACER NADA...". hay pacientes que, sobre todo con amputación bilateral, suelen fallecer a los pocos días de la intervención, si bien no se puede afirmar nada en este sentido. Si no se interviene, la señora puede "aguantar" meses con los cuidados normales de enfermería. +++Si la decisión tomada finalmente fuese intervenir, quedaría todavía PENDIENTE EL Vº BUENO del SERVICIO DE ANESTESIOLOGÍA, que podría no considerar indicada la misma según sus criterios. +++Informo al Dr. Osama de que debemos comunicar nuestra decisión al Juzgado para su ratificación y le pregunto por el plazo que disponemos para tomarla: "No se preocupe, la paciente se encuntra bien, tranquila y no tiene ningún dolor..."Le comento que trataremos de agilizar todo lo posible el proceso. +++LESIONES DE 15 MESES DE EVOLUCIÓN (según Informe). El Dr. Osama refiere que el problema de estas lesiones ES QUE NO LLEGA RIEGO A LA ZONA, con lo cual no llega ni el suficiente oxígeno, ni sufiecientes nutrientes ni anticuerpos...Hay familiares que nos dicen que, a pesar de estar muy pendientes del paciente, las lesiones no mejoran. Les explicamos que es debido a esto, que lo único que se puede hacer es mantener la zona limpia para tratar de evitar infecciones y tapar con apósitos estériles para evitar dicha infección, ya que estos son la "nueva piel" de la zona, porque ésta no se puede regenerar. +++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Conversación con Mª Carmen,Directora de la Residencia "San Miguel" de Santa Amalia (658-878074 y 652833835). No está disponible en este momento. La Enfermera, Cefi, está también en comedor. Volveré a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-06-04','-Amalia : me reúno con Alejandra Contreras , técnico PIA , me va a reenviar por email la aceptación Pia para que no la firme el Gerente. Le explico que no voy a hacer solicitud de centros pq el ingreso se va a realizar por Emergencia Social . ( se tuvo que solicitar durante el Estado de alarma por imposibilidad de cuidados en el domicilio) . Por dependencia no ingresaría, está en G.II y tiene una capacidad económica de unos 9000€ .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-06-04','-Amalia : LLamo a May , me dice que cuando queramos hacer el ingreso ( julio / agosto / septiembre ) la llame , ella va a quedar el expediente abierto. Se tiene que solicitar al Centro de Salud de la localidad que le hagan el PCR e ingresaría al dia siguiente si da negativo. Aún así, estaría aislada en resi durante 7 días. En esa fecha nos diría qué vacantes hay cerca y elegiríamos una , a día de hoy están las mencionadas por Pedro en su anotación , no se sabe cuál quedaría en un mes.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-06-04','-Amalia : LLamo a May , me dice que cuando queramos hacer el ingreso ( julio / agosto / septiembre ) la llame , ella va a quedar el expediente abierto. Se tiene que solicitar al Centro de Salud de la localidad que le hagan el PCR e ingresaría al dia siguiente si da negativo. Aún así, estaría aislada en resi durante 7 días. En esa fecha nos diría qué vacantes hay cerca y elegiríamos una , a día de hoy están las mencionadas por Pedro en su anotación , no se sabe cuál quedaría en un mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA INES'and edp.apellido1='MORENO'and apellido2='POLO'),'2020-06-04','(Pedro)Llamada de D. Miguel Macías Moreno (608-442558), hijo de Dª Inés que reside en Canarias. +++Dice haber promovido él el procedimiento de incapacitación, cuando en la Sentencia consta que tanto él, como su hermano Juan apenas tienen contacto con la madre y que el ingreso en la residencia fue promovido por el marido de una prima, acreditando además desde el centro que sus hijos apenas se interesan por ella. +++Dice querer empadronarla en la residencia pero que no le dan los datos para ello porque ya está tutelada; quiere hacer la declaración de la renta porque le corresponde a él, ya que según "su abogado", aunque esté tutelada eso le corresponde a él. +++Le explico que cualquier decisión de tipo legal que haya que tomar sobre su madre le corresponde a esta Comisión, pero no parce quedarse conforme con ello. Quedo en que cuando tenga más información nos pondremos en contacto con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CORBACHO'and apellido2='GALINDO'),'2020-04-13','-Amalia : llama la excuñada con el tema de las hipotecas y embargos que tiene junto a sus suegros. Se lo derivo a la sección jurídica ( Miguel )','2');
