insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2020-06-04','-Amalia : en los ultimos meses he hablado telefónicamente con la auxiliar SAD y con el Dtor . de la AOEX por la deuda pendiente. Ya ha llegado al domicilio de Julio la resolución suya y de Isabel, con los atrasos de P. Vinculada a SAD del SEPAD . Pedí a Juani ( auxiliar ) que enviase por wasap a la sección eco las cantidades a percibir. Están gestionando con la empresa qué deuda queda pendiente y hacer el pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-06-04','(Pedro)Conversación con la POlicía Local de zalamea de la Serena (664-490060) y correo-e a Ctaex. +++Buenos días. Me acaban de llamar de la Policía Local de Zalamea de la Serena. Por partes: CUESTIÓN SOCIAL. • D. Guillermo: consideran que él si necesita estar ingresado en un Centro, y nosotros vamos a seguir con el plan previsto de Unidad de deshabituación alcohólica de Plasencia y, según evolución, ingreso en Centro de Mayores. • D. Pablo. Al parecer su situación ha mejorado tanto, tanto a nivel doméstico como personal y sin consumo de alcohol que desde la Policía Local consideran que se podría quedar en la localidad, ingresar en los pisos tutelados y seguir cuidando de sus animales, ir a casa, etc. He pedido que noes envíen Informes al respecto , de acuerdo también con el SSB, y que por nuestra parte se puede intentar. Al parecer, D. Pablo estaría dispuesto a aceptar el ingreso en estas condiciones una vez que “nos hubiéramos llevado” a su hermano de allí. • Teresa, habla con Futuex para que inicien las visitas a estos hermanos en coordinación con el SSB y la Policía Local y nos den su visión de la situación. CUESTIÓN ECONÓMICA. • Hasta ahora, desde la Policía Local se ha estado sacando dinero de sus cuentas para alimentación tabaco, etc. (sus gastos básicos) y el banco se lo ha facilitado, pero temen estar incurriendo en alguna ilegalidad. Con ambos estamos en fase de inventario, por lo que entiendo que todavía no figuramos en sus cuentas ¿es así? Y si figuramos, debemos valorar limitar y autorizar a alguien a que saque el dinero que se necesite (ya sea la Policía Local si lo quiere hacer una vez autorizada o bien Futuex. Ya me decís cómo lo veis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-06-04','(Pedro)Conversación con la POlicía Local de zalamea de la Serena (664-490060) y correo-e a Ctaex. +++Buenos días. Me acaban de llamar de la Policía Local de Zalamea de la Serena. Por partes: CUESTIÓN SOCIAL. • D. Guillermo: consideran que él si necesita estar ingresado en un Centro, y nosotros vamos a seguir con el plan previsto de Unidad de deshabituación alcohólica de Plasencia y, según evolución, ingreso en Centro de Mayores. • D. Pablo. Al parecer su situación ha mejorado tanto, tanto a nivel doméstico como personal y sin consumo de alcohol que desde la Policía Local consideran que se podría quedar en la localidad, ingresar en los pisos tutelados y seguir cuidando de sus animales, ir a casa, etc. He pedido que noes envíen Informes al respecto , de acuerdo también con el SSB, y que por nuestra parte se puede intentar. Al parecer, D. Pablo estaría dispuesto a aceptar el ingreso en estas condiciones una vez que “nos hubiéramos llevado” a su hermano de allí. • Teresa, habla con Futuex para que inicien las visitas a estos hermanos en coordinación con el SSB y la Policía Local y nos den su visión de la situación. CUESTIÓN ECONÓMICA. • Hasta ahora, desde la Policía Local se ha estado sacando dinero de sus cuentas para alimentación tabaco, etc. (sus gastos básicos) y el banco se lo ha facilitado, pero temen estar incurriendo en alguna ilegalidad. Con ambos estamos en fase de inventario, por lo que entiendo que todavía no figuramos en sus cuentas ¿es así? Y si figuramos, debemos valorar limitar y autorizar a alguien a que saque el dinero que se necesite (ya sea la Policía Local si lo quiere hacer una vez autorizada o bien Futuex. Ya me decís cómo lo veis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-06-04','-Amalia : durante el E. de alarma han sido numerosas las llamadas de Maribel ( pareja ) , ella pasó el covid 19 . El viernes pasado llamó para decir que habían atracado a Pedro cuando salía del cajero con 270 €. El casero les ha dicho que tienen que irse del piso. Solitan que se le autorice para sacar un préstamo y arregalr su casa del pueblo para irse allí. Llamo al CSS de Mérida , desde donde se le hace un seguimiento para contrastar la información. Juan Pedro y Mariel no ven mal la idea de irse al pueblo. LLamaré al TS del SSASB para ver en qué condiciones está la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-06-04','-Amalia : hablo con Eva , ts de P.I. , Joaquin ( Cristina) tiene citas con endocrino , teniamos pte. quedar con el ESM para explicarnos ésto. Tendremos que firmar unos consentimientos. Quiere ver a su madre , no sabemos porqué su cambio de opinión después de tantos años sin verla . Aceptamos la visita , P.I. la va a gestionar y estará algún profesional presente.','2');
