insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-06-04','Ana: Correo de Miguel, Asesor Jurídico CTAEX: "Buenos días, te adjunto la situación para el 9/7/2020 a 10:40h para reconocimiento forense de Jesús Romero Perez, para que vayas hablando con quién pueda acompañarle a dicha citación en el Juzgado de 1º instancia e instrucción nº1 de Cáceres. Nosotros no es necesario que vayamos." ················································· Llamo a Teo del Arce, TS del CRPS de CC.(927 23 21 06 - Hermanas Hospitalarias), se lo comunicará a Jesús y le dirá que elija quién quiere que le acompañe. *Le envío por mail (tdearce.sanmiguel@hospitalarias.es) ambos documentos: Citación del Jdo. y Señalamiento del Reconocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-06-04','Confirmado con el CADEX , no tiene cdo. de discapacidad. Amalia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-06-04','TERESA: HABLO CON EL MEDICO DE FAMLIA LE PIDO INFOREM MEDICO QUE VALORE LA AMPUTACION DE JOSEFA ASI COMO LAS INTERVENCIONES QUE SE HAN LLAVADO A CABO Y LAS PATALOGIAS QUE PADECE. LE DOY FAX Y CORREO ELECTRONICO PARA QUE ME LO ENVIE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-06-04','(Pedro) Correo del CRR de Mérida (04-06-2020). +++Ángel Pinilla: Sigue saliendo una vez al día, los cambios en el estado de ánimo siguen presentes, reconducible. Muy contento por poder retomar las sesiones de fisioterapia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-04','Ana: Recibo llamada de José Luis, hermano de José Manuel (687 581 061), pide que llame a su hermano. ················ Llamo a José Manuel (667 384 817), vuelve a preguntar por los presupuestos de lavadora, móvil y ropa. Le informo de que hoy mismo he hecho una nueva consulta por @ a la secc. ecca. pero sigo sin respuesta. ·· A parte de esto dice que ayer le llamaron de Jazztel y aceptó una portabilidad, en el contrto incluye fibra óptica... Pero hoy se arrepiente, me pide que busque el nº gratuito de Jazztel porque va a llamar para anularlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-06-04','(Pedro) Correo del CRR de Mérida (04-06-2020). +++Antonio Merchán: Tenemos una charla diaria con él, percibimos con actitud más a la defensiva de lo normal. Coincide con que el año pasado en estas mismas fechas también pasó unos días complicados, sospechamos que se puede tratar de algo cíclico. Sus salidas son con apoyo de profesional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-04','(Pedro) Correo del CRR de Mérida (04-06-2020). +++Mª Dolores Fernández: Ha pasado unos días que refería sentirse mal (físicamente) pero no sabía identificar qué le pasaba. Finalmente conseguimos que entendiera que lo que le pasaba es que había días que estaba más baja de ánimo. Estuvimos hablando, le propusimos ponerse manos a la obra con su portada del recetario y que pensase cómo le gustaría celebrar su cumpleaños con sus compañeros del CRR. Pasó esa tarde y estos días posteriores mejor. Ha planificado con su tutora salidas para peluquería y demás.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-06-04','(Pedro) Correo del CRR de Mérida (04-06-2020). +++José María Guillén: MUY contento tras la aprobación económica. Se ha emocionado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-06-04','(Pedro) Correo del CRR de Mérida (04-06-2020). +++Luisa Rodríguez: Mucha menos dificultad para levantarse y de buen humor. Sus salidas son de manera autónoma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-04','Ana: Llamada de Emi (633 501 059), dice que lleva estos dos días encerrada en su habitación, sólo sale unos ratitos. Le recuerdo que ya le hemos explicado tanto desde el CRR y como yo y que es unas de las consecuncias de sus actos. Añade que no tienen dinero para tabaco, que no es capaz de dejar de fumar. Le digo que si no se hubiera gastado tanto dinero en los últimos 10 días ahora no estaría así. *Me pregunta de nuevo por la factura de la Clínica Dental Monreal y Román (Tlf. 927 42 74 10 / 671 674 834). Como aún no tengo respuesta de la parte eco. *Envío otro correo al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='TAPIERO'and apellido2='JIMENEZ'),'2020-06-04','miguel, me comentó ayer Coral que había una serie de domiciliaciones que no les cuadraban de este tutelado pues en catastro no aparecía como titular. Para descartar si es o no titular de una vivienda, ayer solicité nota simple a nivel nacional al registro de la propiedad, siendo negativa la respuesta. Tras conversación de Coral con el Oar este le dice que desde el 2012 tiene domiciliado los pagos y por la ley de protección de datos no le puede dar más datos acerca de la finca sobre la que recae. Es por eso, que por email le indico a Coral que hable con el banco donde se encuentran las domiciliaciones para intentar obtener información de otros titulares, y autorizados en esa cuenta y para intentar obtener más datos sobre la finca sobre la que recaen los recibos de ibi, basura, etc. De pendiendo del resultado podremos o no eliminar esas domiciliaciones de pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-06-04','miguel, me confirma vía email Amalia, quién ha hablado con el CADEX que no tiene reconocido grado de discapacidad, por lo que no podré aplicarselo al impuesto de sucesiones de la herencia de su madre cuya ratificación firmaré el lunes en Notaria de Badajoz de Juan Manuel Angel Avila','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2020-06-04','miguel, a petición del Centro a Amalia sobre si puede testar él y Maria Antonia Casquero Jaén le contesto lo siguiente: Aunque se ha pedido aclaración de sentencia de la segunda, y habiendo leído los fallos de ambas, desde mi punto de vista ninguno puede testar. Caso de que quieran hacerlo que lo soliciten judicialmente y si el juzgado se lo estima entonces si podrían. Ten en cuenta que en una tutela ejercemos el total de la capacidad de una persona, mientras que en la curatela completamos esa capacidad y precisamente solemos estar designado como es el caso para el cuidado del patrimonio ordinario del curatelado. Por tanto la respuesta es que no pueden testar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2020-06-04','miguel, miguel, a petición del Centro a Amalia sobre si puede testar él y Maria Antonia Casquero Jaén le contesto lo siguiente: Aunque se ha pedido aclaración de sentencia de la segunda, y habiendo leído los fallos de ambas, desde mi punto de vista ninguno puede testar. Caso de que quieran hacerlo que lo soliciten judicialmente y si el juzgado se lo estima entonces si podrían. Ten en cuenta que en una tutela ejercemos el total de la capacidad de una persona, mientras que en la curatela completamos esa capacidad y precisamente solemos estar designado como es el caso para el cuidado del patrimonio ordinario del curatelado. Por tanto la respuesta es que no pueden testar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-06-05','TERESA: EMAIL El miércoles pasado llamó la Subdirectora de Tratamiento del C. Psiquiátrico Penitenciario de Sevilla (954-856002): nos van a enviar por ctutelar los informes en relación a la excarcelación de D. Juan Carlos R.G. (a ctutelar). Los han enviado también al SES para iniciar el protocolo correspondiente. Estemos atentos a ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2020-06-03','(Pedro)Correo de Amalia: +++Hola de nuevo a todos , os comento , he recibido la llamada de la Directora de la Residencia de Caser donde se encuentra ingresado Pedro Sudón . Es una curatela económica , lo recalco , porque su ingreso en esta residencia no lo hemos promovido desde CTAEX . Fue su sobrina Cristina, al claudicar de su cuidado quien lo ingresa allí . El confinamiento que les está dando es de órdago , ha robado al Trabajador Social la cartera , a las auxiliares , a los residentes ... Ninguno ha interpuesto denuncia por diversos motivos. Han tenido que instalar cámaras de vigilancia por la residencia. Esta semana ha robado a otro usuario 500€ . 300€ los ha escondido en un calcetín, que ha acabado en la lavadora .. los billetes han salido descoloridos y algunos rotos. La Directora ha ido al banco y les han dicho que no se los recogen ( mañana va a volver para hablar directamente con el Director) El otro residente es agresivo y exigía su dinero , la Dtra. para evitar mayor conflicto se los ha dado de su dinero personal . Qué solución podríamos darle ? quiere recuperar su dinero y sería lo justo que Pedro , que tiene dinero ahorrado, se lo devolviese. Problema que veo , no han puesto denuncia , cómo vamos a justificar ese dinero en la rendición anual ?? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2020-06-05','Ana: Correo-e de Maribel, TS - R.M. Ciudad Jardín Parque del Príncipe (trabajosocial@grupociudadjardin.com): "Buenas tardes, Ana: Como hemos quedado por teléfono te adjunto el informe del médico donde nos informa de la biopsia que se le debe hacer a Rafael, no entregó a la auxiliar consentimiento informado, solo el informe. Buen finde" ·········· Guardo informe de urología en el expte. digital. *Seguimos pendiente del C.I. ······································ En el informe: "...pendiente de TC (= Tomografía Computarizada: mediante rayos X tomana imágenes trasversales del tórax y la porción superior del abdomen) para el día 15/06, dado resultado de ecografía: masa sospechosa renal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-06-05','Ana: Envío correo-e a Toni-Futuex, con el contenido del correo que envió Pedro, Jefe Secc, a Alberto, Jefe Eco, y el acuerdo de propuesta para Desi y su marido. ···················· Correo respuesta de Toni-Futuex: "HOla! si te parece el lunes lo hablamos mas tranquilamente lo he estado hablando ahora con la compis y bueno creen que pueden acceder a coger solo 100 euros hasta que se termine de pagar con los otros 100 el importe o pueden incluso no coger los 200 durante algunos meses porque Angel dice que ya no tiene dienero y la obra la tienen que acometer. No conocemos a la hermana ni sabemos pq se ha puesto en contacto con vosotros, ni la autoridad que tiene para hacerle caso, pero es cierto que agua caliente no tienen y como siempre pues las deciones las toma angel y la perjudicada en Desi. Te pongo por aqui, nota del siguimiento del pasado miercoles donde estuvieron las dos para retirar el dinero Nota sobre el seguimiento realizado a Desideria Barbero Bueno el día 3 de junio de 2020 para la retirada del dinero pautado mensualmente; Concretamos cita con Desideria y Ángel en la entidad de Liberbank de Plasencia para realizar la retirada de 200 euros, tal y como está estipulado cada principio de mes desde Comisión tutelar de adultos. Al llegar nos vuelven a insistir en los gastos que les está generando el adaptar la nueva vivienda y que ya se han quedado sin dinero para los cambios que tienen que realizar. Tienen que cambiar la instalación del gas, ya que no tienen aún agua caliente y por ello, la hermana de Ángel ha hablado sobre la situación con Ana de la Comisión tutelar de adultos. Se vuelve a tratar con ello dicha situación, reforzando la idea que la comisión no puede cubrir los gastos de las decisiones precipitadas que ellos toman, tal como se había consensuado en meses anteriores desde el equipo de apoyo social comunitario, la comisión tutelar y los profesionales del Sociosanitario. Se decidió así, porque ellos decidieron comprar la vivienda sin asesoramiento ni consentimiento de la comisión tutelar ni desde el programa de apoyo social comunitario. Dentro de la visita también se va a la entidad de Unicaja para saca los dos recibos últimos que han pagado de luz en el piso de alquiler, ya que el casero les solicita nuevamente el pago. Se comprueba que los mismos están pagados y se soluciona dicha cuestión. Por último, nos dirigimos con ellos al coviran donde se realiza una compra de alimentación con los gastos de bolsillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2020-06-08','TERESA: SE ENVIA SOLICITUD PARA PERFIL CADEX','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2020-06-08','TERESA: SE ENVIA SOLICITUD DE DEPENDENCIA PARA REACTIVAR EXPEDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA INES'and edp.apellido1='MORENO'and apellido2='POLO'),'2020-06-08','miguel, me llama el hijo de la tutelada para informarse en qué consiste nuestra función de tutela y qué actos puede hacer él. Me indica que ha vuelto de canarias, que él se encarga de cuestiones habituales como es renta, empadronamiento, le digo que eso lo hacemos nosotros. También dice que viene pagando el IBI y hasta arreglos de la casa que no nos va a pedir pues es conscientes del poco dinero que gana la madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2020-06-08','TERESA: ARCHIVO RESOLUCION INCREMENTO PENSION DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRIGIDA'and edp.apellido1='MURILLO'and apellido2='ALVAREZ'),'2020-06-08','TERESA: ARCHIVO RESOLUCION EN LA QUE DENIEGAN PRESTACION DE ORFANDAD POR NO TENEER PERIODO MINIMO DE COTIZACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-03','Ana: Llamada de Clara, TS CS (927 360 769 = C.S. Logrosán): Comunica que Juan tiene la cita en Salud Mental el día 15. Le llamarán sobre las 12:00 h. *Para ponerse el inyectable deberá acudir al CS a las 13:10 h. ································································· Correo de Toni-Futuex sobre seguimiento de Juan: "Adjuntamos informe sobre la visita realziada ayer a Juan Chamorro Holguín, para llevarle su nuevo teléfono móvil y explicarle su funcionamiento básico. No acudió a la cita planificada, aunque ya lo habían visto caminando a primera hora por el pueblo. Tuvimos que acercarnos a su domicilio donde, despues de un rato salió algo alterado, gritando que él se levanta tarde y que no necesitaba nda y menos un móvil, que no queire nada de la Comisión. Estuvimos esperando, hasta que se le entrega el móvil y le explicamos que , se tomara el tiempo que hiciera falta y que le esperábamos en la cafetería donde habíamos quedado , parfa invitarle a desayunar. A la hora más o menos, apareció ya más calmado y pudimos proceder a explicarle el funcionamiento del teléfono y probar con las llamadas. nos costó también convencerle de subir al centro de salud, pues era necesrio para el cambio de datos en el sistema, alli nos indicaron que al cambiarlo en Jara desde Salud Mental ya contaran con el nuevo número. También se le confirmó, que el lunes 15 de Junio a las 13:00 horas tiene cita para administración de inyectable, desde aquí se pondrá en contacto con él desde salud mental Cáceres, pues le han avisado que mientras haya estado de alarma, no tendrá que desplazarse. Nosotros posiblemente intentemos ese dia ir para ayudar a que se pueda realizar ese tramite del inyectable, pero sin decirle nada todavia, diciendole que tenemos que viajar por la zona o algo parecido, para que el no sienta ese control del que se queja constantemente y hace que se ponga a la defensiva." ················································ Guardo informe en el expte. En el mismo especifican además: "...En este mismo día, teníamos cita previa con la trabajadora social de lo SSB del Ayuntamiento, que nos recibe en su despacho y nos comunica y confirma que con fecha 11 de mayo 2020, Juan chamorro está incluido nuevamente en listado para reparto de alimentos de Cruz Roja en Guadalupe (un total de 5 familias) siendo Juan, el primero en lista, pero todavía no hay día de reparto fijado. Así mismo, nos dice que el Alcalde lo ha incluido también en listado de personas vulnerables para ayuda a mínimos vitales, incluso en un listado de posible contrato de trabajo temporal de tres meses para el Ayuntamiento...", ".... Desde Cáritas parroquial se ha reactivado la entrega de un bono por valor de 10 euros para entregar y canjear en un supermercado concreto del pueblo por productos perecederos. Juan nos dice que ya ha recibido uno...", "...Persiste su discurso de delirio recurrente en el tema de “robo de su dinero de lotería”, sobre todo al cruzarnos en la calle con su hermano y hermana, produciendo en él un fuerte rechazo. Repite que su hermana es la “causante del manual nazi que utilizan aquí en centro de salud”..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2020-06-08','Ana: Llamo a Marisol, TS del HUC (927 256 823): ella no sabe que pasó finalmente con el CI, el Dr. Joao Bernardo le dijo que se lo daría a la administrativo para que nos lo hiciera llegar. *Pero aún no nos lo han enviado. ····················· Llamada de Marisol, TS, ha hablado con Bernardo, Urólogo, éste dice que le pidió a Laura, Admvo., que nos lo enviara. Se lo volverá a decir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-06-08','Ana: Correo en el ctutelar@ de Piedad Cabezas, TS de SSAB: "Buenos días, dña Nemesia Garcia Paniagua con dni 07331247C, domiciliada en Guijo de Granadilla (Cáceres), tiene una tutela parcial con la Junta Extremadura ( tutela económica). Esta mujer está actualmente ingresada en los pisos tutelados del municipio de Guijo de Grandilla. Tiene un terreno dentro del casco urbano que está lleno de maleza y zarzas siendo un peligro potencial de incendio para las viviendas colindantes. Se va a proceder a limpiarlo por parte de empresa privada, la cual nos va a pasar la factura al ayuntamiento y quiriamos saber como hacemos llegar esa factura a la comisión tutelar para que se proceda al pago de la misma . Muchas gracias Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-06-08','Ana: Llamada de Teo del Arce, TS del CRPS de CC.(927 23 21 06): comunica que a Jesús, hace apróximadamente 15 días, le han bloqueado la tarjeta y no entiende por qué. Al parecer en las últimas semanas, puesto que se ha visto con más dinero por haber cobrado la ayuda al alquiler, ha hecho más gasto de lo habitual (ropa y tto. dental). Teo imagina que ha sido por eso, para su mayor protección, pero a todos les extrañó, puesto que desde que está tutelado nunca se le ha controlado el dinero (ni bloqueos de cuenta, ni asignaciones para gasto de bolsillo), ha estado autogestionándose. *Le facilito los nº de las compañeras de la secc. ecca., pues imagino que tendrán que establecer presupuesto para gasto y autorizar asignaciones mensuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2020-06-08','miguel, recibo de la parte económica, Juana y Alberto, documentación para reclamar a la CAIXA que cumplan la resolución del Juzgado de informar e ingresar en la cuenta actual del tutelado cualquier cantidad que pertenezca al tutelado desde que se produjo la remoción en novimbre de 2019 hasta abril 2020, fecha en la que ya se han venido ingresando correctamente el dinero de la pensión en la cuenta de Liberbank','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-05','Ana: Recibo llamada de José Luis, hermano de José Manuel (687 581 061), le indico que si quiere hablar sobre los presupuestos, tal y como me han indicaco los jefes hoy mismo, debe llamar a la secc. ecca. Le facilito los números de las compañeras. Pido que se lo explique a su hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-03','Ana: Varias llamada de José Manuel preguntando por los presupuestos. Aún no me han dado respuesta desde la secc. ecca. Debe tener paciencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-06-05','Ana: Llamada de Damián. Dice haber hablado con Victor, su expareja y éste le ha dicho que no se vaya del CRR, pues no puede vivir solo. Le indico que los profesionales del CRR trabajan con él para su recuperación y para la adquisición de mayor autonomía, entre otras cosas. Sólo le recomendarán dejar el centro en caso de valorar que está preparado. Dice estar muy contento ahora en el recurso y apreciar mucho a Javier, Paula y Blanca. Que le atienden cuando pueden y le ayudan mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-06-08','miguel, llama Sindy 625-712629 y me comunica que quieren alquilar únicamente y en un futuro ya pensarían lo de comprar. Dice que con la trabajadora social de Guadiana acordaron no pagar primer mes ni fianza porque hay que limpiarla a fondo y arreglar unas humedades. La indico que no se preocupe que en cuanto tengamos los Certificados de VPO de la Consejería de Vivienda, la llamaremos para indicarle las limitaciones que tenga la vivienda. ********************* Me pide también que miremos si la vivienda tiene Luz y Agua','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-06-08','(Pedro) Intento varias veces hablar con la Dra. Marco o con el Dr. Osama sin conseguirlo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++LLamada de Inma, T. Soc. Hospital D.BVva.(86647).Han dado el alta a Josefa y llamaban para preguntar por la dedcisión que ha tomadao la Comisión. +++Pido que nos envíen el Informe de Alta para incluirlko enel Informe al Juzgado. +++Le pido que intente conseguir inofrme de Anestesista para fundamentar más si cabe la decisión.','2');
