insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GRANADA'and edp.apellido1='CANO'and apellido2='MARQUEZ'),'2020-06-08','miguel, a petición de Amalia y Pedro envío email con los últimos informes de la policía local y de la trabajadora social de Llerena. Le solicito que si no es firme la resolución que por favor la recurra solicitando ampliación a tutela e internamiento involuntario. ******************************************************** Escalona nos remite la documentación de firmeza y testimonio de aceptación del cargo de la Ctaex, por lo que no hay que hacer nada más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-06-08','TERESA LLAMO A LA RESIDENCIA SAN MIGUEL PARA PREGUNTR POR EL ESTADO DE SALUD DE JOSEFA AL ALTA Y ME DICEN QUE SE ENCUENTRA MAL, LA ULCERAS ESTAN IGUAL QUE ANTES DE IRSE AL HOSPITAL Y AHORA SE NIEGA A COMER, NO TOLERA LA ALIMENTACION POR LA VIDA Y SE LA INTENTA ARRANCAR. ME ENVIARAN INFORME DE ALTA DEL HOSPITAL POR EMAIL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-06-08','miguel, envío fax al jzdo nº4 plasencia indicando que ha sido denegado abogado y procurador para que nombren o soliciten otros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-08','Ana: Al final de la mañana recibo llamada de Emi (633 501 059), dice que está en la calle, que se ha enfrentado a Javier y le han echado. ···················· Antes de llamar al CRR, llamo a Pedro, Jefe Secc. CTAEX. Pedro no sabe nada. ········································ Llamo a Javier, Director del CRR-Plas. (677 40 76 40): Emi ha llevado muy bien el aislamiento. Pero esta mañana de repente se ha arreglado y decía que se iba del recurso. Javier ha llamado al SEPAD, le han dicho que estando en Eº de Alarma, no pueden expulsarla, pero que debe hacerse un test rápido de nuevo y no tendría que volver a hacer el aislamiento. Javier ha llamado al C.S. San Miguel, para que pueda acudir Emi, y aunque han puesto pegas han accedido y acordado que llamarían al CRR con los resultados. Ha llamado a Emi y se lo ha explicado. ···························································· Llamo a Emi, ésta dice que ha acudido al C.S., pero que le han dicho que allí no ha llamado nadie y no le van a hacer la prueba (pongo en duda lo que dice). ·································· Llamo a Javier de nuevo, asegura que han hecho la gestión. Dado que van a ser las 15:00 h, en el CS ya no le atenderán. Acordamos que llamaré a Emi y le diré que acuda al hptal. por Urgencias y explique necesita hacer el test rápido para volver al CRR, sino se quedará en la calle. Que llamen a dicho centro para comunicar el resultado o si tuvieran alguna duda. ························· Llamo a Emi, dice que así lo hará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-06-08','miguel, el gerente me firma modelo 705 para la representación por la abogada Inmaculada para presentación del impuesto de sucesiones en la oficina liquidadora. Me firma también el modelo 650. Ambos modelos los dejaré mañana en la notaria cuando firme la ratificación de la herencia que fue firmada el jueves 4-6-2020 por la tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-06-09','(Pedro)Como el Informe de Alta llegó ayer a última hora pongo hoy a la firma el Informe de la Comisión Tutelar para el Juzgado. +++SE envía por fax la documentación al Juzgado de 1ª Instancia e Instrucción nº 1 de Villafranca de los Barros.Reporte OK.(ERROR: este Juzgado se inhibió en favor del nº 2 de Don Benito). +++SE envía de nuevo por Fax al Juzgado de 1ª instancia nº 2 de Don Benito.Reporte OK del envío. +++Escaneado en su expediente en la carpeta "Juzgados" y en papel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-09','Ana: Llamo a Javier, Director del CRR (677 40 76 40), no obtengo respuesta. ······· Me devuelve la llamada más tarde. Ayer, después de que llamara yo por última vez a Emi, la encontraron escondida en el recinto del CRR. Javier le dijo lo mismo que le dije yo, que fuera al hptal. Ella misma pidió ambulancia para que la llevaran... en el hptal. no quisieron hacerle el test, puesto que se lo habían hecho hacía sólo una semana y tras explorarla y tomarle la temperatura, vieron que estaba asintomática. Sólo había pasado unas horas fuera del centro. Le dieron un informe médico. Ante esta situación, para no dejarla en la calle, Javier le dejó volver al CRR. Se enfadó porque no querían ponerle ambulancia de regreso... Ha vuelto a su aislamiento, hasta esta mañana que lo completaba, pero ya hoy la dejado salir. Ya ha llamado y lo hablado con el SEPAD. *Ayer por la mañana acudió a la clínica dental y se ha puesto y diente, de nuevo sin autorización ni previo comunicado ni al CRR ni a la CTAEX. No saben de cuánto será la factura ni si se la harán llegar desde la clínica. **Van a convocar la Subcomisión Sociosanitaria, pero no saben cuándo podrá ser. También ha llamado ya a Salud Mental para hablar con la Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-06-09','Ana: Llamada de Damián (622 834 876); está contento porque ayer pudo ir a comprarse ropa con el extra. Quiere que le diga a Paula que está muy contento con ella y es una buena profesional. En cuanto a sus dudas con respecto a la Declaración de la Renta le digo que debe preguntar a Juana y en cuanto a los movimientos bancarios a Icíar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2020-06-09','(Pedro)Llamada de Ventura. +++Pide un extra para gafas, que dice haber pedido a Virginia (Futuex). Iciar confirmará que nos haya enviadoi presupuesto. +++Pide extra de 100 euros para su cumpleaños. SE le recuerda el acuerdo al que se llegó ante el juez y el fiscal acerca de ampliar sus reintefgros mensules a 600 euros con la conidición de no volver a pedir extras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-06-09','En el certificado de empadronamineto de Daimiel, del 20 de mayo de 2020, figura empadronado en Villanueva de la Serena (Badajoz). +++Teresa pedirá informe en el que se haga constar que desde S.S.B.de Daimiel no se ha intervenido con José Antonio nunca y la fecha desde la que reside allí. +++Pedirá también certificado de convoivencia para que conste la fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-06-09','Ana: Llamo a Mariví, TS de Torrejoncillo (927 30 33 66). No obtengo respuesta. Le envío un mail (marivirf043@hotmail.com // ssb043@hotmail.com) para pedir el presupuesto de gastos de cara a la limitación/autorización bancaria (indico que lo envíe a la secc. ecca. al ctutelar@) y añado entre otras cosas: "...de acuerdo al fallo de la Sentencia de Incapacitación, en el ámbito personal sólo debemos intervenir cuando José Manuel se encuentre en fase aguda de la enfermedad, no obstante, haremos seguimiento igualmente desde el programa comunitario (convenio firmado desde la Junta con Futuex), pero, puesto que a diario no es viable visitarle, te agradeceríamos que ante cualquier cambio/descompensación, que la Auxiliar o tú pudieseis conocer a través de él mismo o de terceros, nos lo hicieseis saber. Y por supuesto, como siempre, si fuera necesario activaseis el 112 para su ingreso y valoración en UHB, o lo pusieseis en conocimiento del/de la médico de referencia de Atención Primaria para que lo activase. En cuanto al CRR, a ver si pasa pronto esta situación y tuviera opción de ingreso en el mismo..." ··························································································· Envío correo a Toni-Futuex (areasocial3@futuex.es) para la derivación del José Manuel al Programa Comunitario para seguimiento. ······························ Toni indica mediante email que irán a visitarle la semana que viene.','2');
