insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2020-06-09','TERESA: HABLO CON DIEGO Y ME COMENTA QUE YA ESTA BIEN QUE HA HABLADO CON PILAR Y QEU A PARTIR DE AHORA EL SERVICIO LO VA A PRESTAR SU HIJA, EL ESTA CONFORME. SE HA APROBADO PRESUPUESTO PARA LA PINTURA 800 EUROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2020-06-09','(Pedro)Correo-e enviado al ESM en contestación a su correo del día 5 de junio. +++Buenos días, Mar. He estado hablando con Amalia sobre Dª Mercedes y me ha reenviado tu correo del pasado día 5. Desde la Comisión compartimos la complejidad que este caso presenta, al igual que compartimos la idea de que Dª Mercedes se encontraría mucho mejor atendida en un centro residencial que le proporcionase un contexto, como dices, más estructurado y, quizá también, más contenido. Pero si le planteamos a ella esta alternativa, que tanto vosotros desde el ESM, como nosotros desde la Comisión Tutelar, le hemos propuesto repetidas veces, su respuesta va a ser siempre la misma: negarse. Como dices en tu correo, Dª Mercedes está diagnosticada de Esquizofrenia paranoide crónica, con sintomatología productiva, en la que presenta delirios con referencia a los vecinos del bloque y sospecha que alguien entra en casa, le roba, se orina, que le roban su dinero, que no tiene nada en el banco, etc. , que persisten incluso con un ajuste de tratamiento farmacológico. La Comisión Tutelar no tiene competencias, ni por ahora capacidad y conocimientos, para determinar si con este diagnóstico Dª Mercedes tiene las capacidades necesarias, desde un punto de vista clínico, para vivir sola como lo está haciendo, juicio clínico que únicamente se puede valorar desde el ESM y que, entiendo por tu correo, ya se ha hecho cuando dices que “…al no tener capacidad para autogobernarse, al carecer de apoyo social y familiar que le ayude en su tratamiento ambulatorio, lo cual es difícil de seguir teniendo en cuenta su sintomatología productiva activa.” De la misma forma que entiendo que, si se le ha propuesto desde el ESM su ingreso en la UHB, es porque lo consideráis clínicamente necesario, independientemente de su aceptación o no del mismo. Si mi forma de entender no está equivocada, en estos momentos solo se puede ingresar a Dª Mercedes mediante un ingreso involuntario solicitado desde el ESM con derivación a UHB y por los motivos clínicos que comentas en el correo. El acceso a cualquier otro recurso de la red de Salud Mental está sujeto a la voluntariedad de la persona para ingresar. Tramitar ese ingreso desde la Comisión Tutelar en estos momentos no es viable, ya que ahora lo que tenemos es una curatela que obliga a la Comisión no solamente desde el punto de vista económico, sino también en cuanto al seguimiento de su tratamiento médico y pautas terapéuticas a las que ha de continuar sometida (seguimiento que solamente desde el ingreso en centro, como dices, se puede garantizar). Para solicitar por nuestra parte un ingreso involuntario habría que iniciar primero un procedimiento de ampliación de la incapacidad, sin garantía alguna de que finalmente se consiguiese la misma, y justificando su necesidad, sobre todo y especialmente, desde el punto de vista clínico, lo que de nuevo nos lleva a la necesidad de aportar informes desde el ESM. Todo este proceso llevaría un tiempo del que ni Dª Mercedes, ni la Comisión Tutelar como su curador, disponemos si se quieren garantizar los cuidados referidos. Es por eso que, si desde el punto de vista clínico está justificada la decisión de ingresarla en la UHB, es desde el ESM desde donde se debe hacer dicha derivación como ingreso involuntario que luego el Juzgado deberá valorar. La Comisión Tutelar de Adultos entiende que si se promueve desde el ESM dicho ingreso es porque existen criterios clínicos para ello y, por lo tanto, el ESM contará con todo el apoyo de dicha Comisión. Tanto el ESM como esta Comisión tenemos el mismo objetivo: procurar el mayor bienestar posible de Dª Mercedes en el ejercicio de nuestras competencias respectivas, por lo que la colaboración entre ambos servicios es una garantía más para su consecución. Espero que todos os encontréis bien. Un cordial saludo. Cuidaos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2020-06-05','(Pedro)Correo-e remitido por el ESM de Ciudad Jardín, hoy 5 de junio en respuesta al correo del día 2 de Amalia. +++Hola Amalia! Cómo váis? Respecto a la situación que me comentas de Mercedes P.P., durante el estado de alarma y confinamiento por Covid 19, hemos mantenido contacto telefónico casi diario con Mercedes y Presencial, el último día que estuvo en consulta con nosotros ha sido el 8 de Mayo y le insistimos en que viniera de forma presencial a los 15 días siguiente, pero nos llamo y dijo que no podía venir por no disponer de dinero para coger un taxi. Durante el confinamiento y por su situación de vulnerabilidad, tanto por su enfermedad, como ausencia de familiares y otros apoyos sociales, le propusimos un acompañamiento telefónica con una organización de SM, en principio lo acepto, pero a la semana rechazo las llamadas de acompamiento psicosocial. Mercedes, como sabes, tiene como diagnóstico Esquizofrenia paranoide crónica, con sintomatología productiva, en la que presenta delirios con referencia a los vecinos del bloque y sospecha que alguien entra en casa, le roba, se orina, que le roban su dinero, que no tiene nada en el banco, etc. , que persisten incluso con un ajuste de tratamiento farmacológico. Se valoro y se le propuso ingreso en la UHB, también por tenerla más controlada y por la situación actual de pandemia, no lo aceptaba, decía que donde quedaba a su perrita. Contacte con el primo, Jesus, para ver si nos podía ayudar para promover el ingreso. Desde el ESM seguimos con el planteamiento y casi convicción que para Mercedes lo mejor sería un recurso residencial en un contexto más estructurado y contenido al no tener capacidad para autogobernarse, al carecer de apoyo social y familiar que le ayude en su tratamiento ambulatorio, lo cual es difícil de conseguir teniendo en cuenta su sintomatología productiva crónica. Veo conveniente el poder reunirnos y hablar junto con su Especialista de la situación de Mercedes y como actuar de cara a un futuro. Espero vuestra contestación. Saludos. Mar Sánchez TS SM Ciudad Jardín','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2020-06-02','(Pedro) Correo-e de Amalia a ESM de ciudad Jardín. +++Buenos días Mar , qué tal va todo ? te escribo en relación a Mercedes P. P. , ha llamado su casera , os trasladamos lo que nos comenta para información y conocimiento del ESM . Se pone en contacto con nosotros la CASERA (Leonor) de la curatelada. Nos informa de que Mercedes no está bien. Ejemplos que verbaliza: • que tiene alucinaciones constantes. • que la llama constantemente para que le cambie la cerradura ya que le entra gente continuamente y le roba incluso la ropa interior (por no entrar en detalles). Nadie entra en su piso. • que se está duchando con orines que caen de la ducha de arriba. • la casera ha tenido que intervenir mandando una empresa de desatascos que se ha encontrado comida, bolsas de plástico y similares. La casera manifiesta su hartazgo y su preocupación por Mercedes. No ha verbalizado que quiera que deje la vivienda pero que esta situación debe ser solucionada porque le está suponiendo mucho tiempo y dinero: desatascos, mandar gente a ver las situaciones que la tutelada verbaliza (y que no son reales), etc. Hoy mismo Mercedes a estropeado una persiana (durante todos los meses de confinamiento las ha mantenido bajadas). La casera manifiesta que NO ABONARÁ UNA SOLA FACTURA MÁS. Muestra su disposición a hacer de intermediaria con las empresas pero que no pagará más. Está acudiendo a las citas de psiquiatría ? cuándo tiene la próxima cita ? sabes si se ha puesto el inyectable ? Puede ser que estuviera descompensada ? Seguimos en contacto . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-06-09','miguel, tras varios intentos de presentar en registro de la consejería la documentación de solicitud de certificado de Vpo, sigue cerrada con carácter indefinico por lo que el lunes día 15-6-2020 lo remitiré desde el registro de salida del SEPAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-06-09','miguel, firmo la escritura de Ratificación de la herencia de su madre en la notaria de Juan Manuel Angel Avila. Envío email a Inmaculada comentandole también que he dejado en notaria para incorporar en la escritura de herencia el modelo 650 de liquidación de impuesto de sucesiones relleno y firmado por el Gerente. Y el modelo de representación 705. "Buenos días, le confirmo que esta mañana he dejado firmado en la notaria de Don Juan Manuel Angel Avila, la ratificación de la herencia de la madre de nuestra tutelada Doña Iluminada Doncel Lucas. Comentarle que he dado a Manolo Duran para incorporar a la escritura de herencia el Modelo 650 de Autoliquidación negativa del impuesto de sucesiones de nuestra tutelada, junto con el Modelo 705 de representación para que pueda presentarlo a autoliquidación junto con el de sus representados. Asimismo le recuerdo que en cuanto la tenga liquidado el impuesto de sucesiones tendrá que remitirme las escrituras escaneadas (ya le avisaré si necesito originales) a efectos de poder pedir la correspondiente aprobación de la herencia al juzgado, sin la cual no podrá inscribir registralmente".','2');
