insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-06-09','Ana: Recibimos informe del Serv. de Pisquiatría de Plasencia (ESM): "...informamos que dicho paciente no realiza seguimiento con nosotros desde 2012. Fue derivado por su MAP en diciembre de 2019 y se le programa cita para el 21 de enero de 2020 a la que no acude. No disponemos de más información. Adjuntamos informe de su último ingreso en Unidad de psiquiatría en agosto de 2019." ··········· Escaneo y guardo ambos en su expte. digital, tb se archivará en su expte. papel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2020-06-10','(Pedro)No ha llegado todavía la Sentencia solicitada. +++Llamo al CAIS de Cabeza del Buey (contestador): no hay atención al público durante el Estado de alarma. Facilitan un número de información sobre gestiones) +++Llamo a Casimiro. No contesta. +++Llamo a D. Francisco para hacerle saber el estado de las gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-06-08','Ana: Correo de Toni-Futuex(areasocial3@futuex.es); envía nota de incidencia del sábado día 6. Esteve ha sido ingresado en UHB del Hptal. San Pedro de Alcántara. Chus, Directora de los PP.TT., pretendía que Gloria-Futuex, firmara el ingreso y/o alta de Esteve... El Psiquiatra asignado en el HSPA es el Dr. Enrique Daniel (927 25 69 65). Hoy Gloria ha intentado pornerse en contacto con él sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-06-10','Ana: Pregunto a Toni-Futuex (areasocial3@futuex.es) si tienen alguna noticia sobre la evolución de Esteve, si han logrado hablar con el Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-06-08','Ana: Correo de Toni-Futuex: "Hablamos con Ángel (marido de Desideria), sobre el cambio de tuberías, que es necesario en su nuevo hogar, para instalar el agua caliente. Tal y con las codiciones que habiais acordado- Pero justo hoy nos comunica que ha pedido presupuesto en una empresa de la localidad de Plasencia y es menor de lo que esperaba en principio. El precio sería de unos 780 euros más IVA. En total el gasto sería menor de 1000 euros y nos dice que esta cuantía si la pueden asumir con el dinero que tiene Ángel, por ello han aceptado el presupuesto. No saben cuándo lo realizarán ya que están esperando la comunicación de la empresa, esta reaccion es la habitual en ellos...plantean o piden algo del dinero de Desideria, en cuanto se les explica el modo de proceder, su falta de capacidad de espera hace que se produzca siempre una anticipación y se aventuren a hacerlo asumiendo Angel el gasto... No obstante como seguiran contando con la asigancion y son gastos que no justifican si consideran apoyar este gasto, sera cuestión suya..." ································· Se lo comunicaré a Pedro y Alberto, Jefes de Secc.','2');
