insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-06-10','En relación con el procedimiento de reintegro de su capacidad, enviamos a Abogacía General (Curro), Informe con las alegaciones a presentar en el Recurso contra la Resolución por la que se autoriza a María Antonia, para comparecer en el Juzgado en este procedimiento. -------------------------------------------------------------- Por otro lado, en relación con la solicitud de revocación del Apud Acta, que enviamos al Juzgado, éste emite DO en el que deja sin efecto ese poder, pero comunicando a la Procuradora de María Antonia y a la Abogacía General, la opción de que otorgue otro poder, este sólo para el procedimiento de reintegro de su capacidad. De esta comunicación, no hemos recibido nada de Curro. Tenemos conocimiento de ella, tras hablar con el Juzgado (Juan Carlos) y enviarnos, vía email la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2020-06-10','-Amalia : hablo con su madre , Antonia ( 672473570) la Declaración de la Renta ya la ha hecho a través del habilitado. Quiere que su hijo salga del centro , ya no consume , lleva allí 6 años y lo están explotando laboralmente . Estudio la sentencia y le explico que desde la CTAEX no intervenimos en eso , sólo es curatela económica . Que él puede salir cuando lo decidan . Volvería a la casa con los padres en Badajoz. Quiere que se le quite la curatela para que pueda disponer libremente de su dinero , la oriento en proceso judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2020-06-10','-Amalia : hablo con la madre , tf 672473570 quiere que su hijo deje el centro . Se le explica que somos curatela económica , no intervenimos en esa decisión . Volvería a Badajoz con los padres. La declaración de la renta la ha hecho a traves del habilitado. Quiere solicitar que se le quite la incapacitación , le doy información del proceso.','1');
