insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-06-10','Ana: Tras hablarlo con Pedro, Jefe de Secc, envío correo a Toni-Futuex y Teo, TS del CRP, para solicitar que elaboren un presupuesto de gastos de manera conjunta entre Gloria-Futuex y Teo y lo envíen al ctutelar@ a la A/A de la Secc. Ecca. ····················· Ambos me dan el ok.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-10','Ana: Envío correo al ctutelar@ A/A Secc. Ecca: "Buenos días compañeras/o, He recibido llamada de Juan diciendo que necesita dinero, pide 80 € para tabaco y pagar “unas deudas” dice, y que si puede ser el lunes mejor. No sé cómo anda de dinero en la cuenta con los últimos gastos de cáterin y el móvil, ni qué valoraréis en la secc. He tratado de que os llamara directamente, pero llamaba desde la calle y no podía apuntar los números. Así que llamarle vosotras para aclarar y confirmarle si se le aprueba o no. Dice que cuando le llaméis ya guardará el contacto. *Su nuevo número es el 633 391 891" ·························································································· Llamada de Clara, TS CS Guadalupe (Despacho de Logrosán 927 360 769): Ha llamado al ESM-CC, le han confirmado que la cita del día 15 sera consulta telefónica. Le llamarán sobre las 12:30 h. A ponerse el inyectable tiene que acudir sobre las 13:10 h. ········································· Pido a Toni-Futuex, que Teresa se lo recuerde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-06-08','(Pedro) Nueva llamada de D. Pedro, abuelo de Alejandro. +++REclamando el dinero de su nieto para "comprarle" un piso. +++SE le dice que cualquier cosa que quieran solcitar a esta comisión lo hagan por escrito y se le indica la dirección.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-06-10','Ana: Envío correo a Chelo, coordinadora de los SSB-Zafra (ssb@zafra.es): "Buenos días Chelo, ¿qué tal estás? Me pondo en contacto contigo de nuevo en relación a Pilar Sáez Bermejo, Tutelada por la Comisión Tutelar de Adultos, dado que seguimos a la esperar del Informe Social para valoración de Dependencia con priorización. Espero que sea posible remitírnoslo la próxima semana a más tardar, pues lo necesitamos para que le hagan la valoración lo antes posible y pueda mejorar su situación. Gracias de nuevo y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-06-10','(Pedro)Nueva llamada de D. Pedro. +++Mismas peticiones y exigencias. +++Despues de casi media hora tratando de explicarle el contenido de la sentencia y leyéndola con él, se le dirige al Juzgado para que aclare las dudas que tiene, dado que las mias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-10','Ana: Recibo llamada de Emi, hoy se muestra muy contenta y relajada. Quiere realizar consulta económica. Le indico que a partir de ahora debe tratar estas cuestiones directamente con Icíar, compañera de la Secc. Ecca. Le facilito el nº y toma nota.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-06-10','miguel, desde hace días la hermana ha llamado a Amalia y Pedro pidiendoles si ya hemos hecho el trámite de una venta que desconocemos (parece ser que han llegado a un acuerdo para vender no sé qué propiedad de la que también debe ser titular el tutelado) Quedo con Pedro que si tiene cualquier problema o duda me envíe un email y que ya la llamaré. ****************************************************** Hasta la fecha el único trámite que hemos hecho es ratificar la herencia de sus padres cuyo trámite hizo completamente la abogada. Dicha ratificación se la remití por correo certificado a la abogada y no he vuelto a saber nada de ella. Se supone que tenía que haberse puesto de nuevo en contacto con nosotros para poder pedir Aprobación judicial de dicha herencia. ******************************************************* Todavía no he hablado con la hermana, pero hasta que como en cualquier venta, hasta que no tengamos toda la información y documentación de bienes, valores-tasaciones, etc, y hasta que no obtengamos Autorización judicial de venta no podemos autorizar la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-06-11','Ana: Correo de Miguel Ángel, Dir. del CRR-CC (residenciadir@feafescaceres.com): "Buenas tardes Ana, te remito informe del Traumatólogo de Juan Mario, al final y por prescripción médica han decidido no realizar intervención quirúrgica." ·················· Guardo el informe en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-06-11','Ana: Correo de Teo del Arce, TS - CRPS (tdearce.sanmiguel@hospitalarias.es): "Buenos días. Ayer contacté con Gloria y hablé con él y le solicité elaborase un estado de cuentas en cuanto a gastos fijos mensuales e ingresos. Gloria me dijo que antes de la reunión del viernes ella irá con Jesús para solicitar extracto bancario en el Santander. La propuesta de reunión inicialmente la programamos en su casa pero dada la situación y aprovechando que el CRPS reúne mejores condiciones de asepsia y espacio, la celebraremos aquí. Un saludo y buen día!!!!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2020-06-11','(Pedro) Conversación con Mar, T. Soc. del ESM de Ciudad Jardín (924-245541).Estaba reunida con Teresa (Futuex). +++Posibilidad de ingreso involuntario desde el propio ESM: no existe criterio clñinico en estos momentos para ello. Además, en estas circusntancias, consideran que ello supondría una pérdida de confianza de Mercedes hacia ellos y ello respercutiría negativamente en el seguimeinto que, de esas maneras , están consiguiendo hacer.Al menos, tiene los apoyos institucionales de la Comisión, Futuex y el ESM. +++Condsideran que desde el punto de vista social se encuentra bien, porque la patología que tiene es crónica y no se le va a quitar. Pregunta que le formulo: al margen de ello, ¿desde el ESM consideráis que tiene capacidad para vivir sola, con una supervisión tan limitada como la que es posible hacer?. Respuesta: No, consideramos que, para tenerla más contralada y garantizar su bienestar, debería estar ingresada en un centro. Por eso se lo propusimos, de manera voluntaria, pero se negó. Y se negará en todo momento, le digo. +++CONCLUSIÓN: +++++Le pido que nos remitan Informe Social y Psiquiátrico en el que , de manera explícita y nada ambigua, expongan el criterio que me ha comentado a mí para valorar solicitar al Juzgado la ampliación de la incapacidad y/o el ingreso involuntario (como medida cautelar o en un nuevo procedimiento siempre y cuando se ampliase la inacacitación a tutela. Si consideramos que la vía judicial no es oportuna en base a los informes, al menos comunicaremos al Juzgado la situación para su conocimeinto. +++++Envirán los Informes solicitados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-06-11','TERESA INGRESO INVOLUNTARIO PLAZOS Buenos días compi, acabo de hablar con el Juzgado y me dice que el plazo empieza a contar a partir del día 4/6/2020, y que en el momento que sea la firmeza nos lo notificará. Me dice que tiene que computarlo ya que según el caso puede ser hasta de 40 días hábiles… Asi que a esperar…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2020-06-11','Ana: A petición de Ángel, Asesor jurídico CTAEX, solicito por mail a Maite Cañadas, Dir.ª de la Res. Conventual San Fco. - Plas., Certificado de Ingreso en que se especifique la cuantía mensual que abona e Informe Médico actualizado. ································· Tras otra consulta de Ángel, llamao a Maite Cañadas y evío a Ángel un correo con el siguiente contenido: "...Me dice Maite que el Abogado si quiere puede hablar con ella, que a pesar de su deterioro, que no está muy avanzado, puede mantener aún un discurso coherente y de estas cuestiones aún controla bastante. De cantidades no se acuerda. Pero ha ido preguntarle ahora y mantienen el discurso de cuando ingresó, es una herencia de sus abuelos, con los que se fue a vivir cuando era pequeña. Le dejaron la herencia a ella y a su hijo, de ahí el cambio de cuenta del dinero a una a nombre de ellos dos. *Parece coherente, según Maite. En cuanto a las preguntas del Abogado, al ser un “Centro libre de Covid”, se puede organizar la visita sin problemas. Puede llamarla y concertarla." ········································· Recibo por mail (maria.canadasv@salud-juntaex.es) informe médico y Cdo. de ingreso en centro. Se lo reenvío a Ángel, Asesor jurídico CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-06-11','(Pedro) Conversación con Mar, T. Soc. del ESM de Ciudad Jardín (924-245541). +++Como ya se hizo en febrero, se le recuerda que cualquier intervención que se pretenda realizar con Joaquín debe ser puesta en conocimeinto de la Comisión Tutelar con dicha finalidad y para dar su autoirización en caso necesario y plantear la situación al Juzagadpo para su pronunciamiento. +++Le pido los Informes que dispongan acerca de la idoneidad de Joaquín como candidato a la terapia de reasisgnación de sexo: Mar dice que solamente tienen el informe de la Endocrina, de septiembre, pero se muestra reacia a hacérnoslo llegar. Le pido que me diga el nombre de la Dra. Es el siguinete: Dra. María de la O Cabanillas López, S. de Endocrinología del Hospital Universitario de Badajoz, 0924-218100).TIENE CITA CON EL PSIQUIATRA Y LA ENDOCRINÓLOGA EL 3 DE JULIO. +++Pido a Mar que nos envíen INFORME SOCILA Y PSIQUIÁTRICO en el que se refelejen sin posibilidad alguna de segunadas interpretaciones los mismos argumentos que me ha estado refieriendo por teléfono. Así lo harán, ella y el Psiquitra CONJUNTAMENTE. +++Llamo a la Dra. Cabanillas (48081). Está en consulta. Dejo mi teléfono para que me llame cuando termine, indicando el asunto del que quiero tratar.Otros teléfonos. 2970008 (Centralita) y 2970029 (Secretaria S. Endocrinología). +++++++++++++++++++++++++++++++++++++++++(Pedro)Llamada de la Dra.Cabanillas (48707) del H. Universitario de Badajoz, Servicio de Endocrinología. +++Desconocía que Joaquín estuviese tutelado y comprende que en esta situación debe informar y solicitar los permisos correspondientes a la Comisión Tutelar. +++Le explico que dada la situación que se plantea con Joaquín (Cristina), debemos informar al Juzgado de la situación, para lo cual necesitamos todos los informes clínicos y sociales (atención psicosocial que indica el "Protocolo de Atención Integral a Personas Trans en el SES") que se tengan enrelación al caso. +++Enviará los Informes una vez que tenga la próxima consulta con Joaquín el día 3 de julio, junto con los consentimientos que debamos firmar. +++UNA VEZ TENGAMOS LOS INFORMES DEL ESM Y DE ENDOCRINOLOGÍA, PONDREMOS TODO ELLO EN CONOCIMEINTO DEL JUZGADO. En cuanto a la opinión al respcto de la CTAEx, SOLCITAREMOS RECONOCIMIENTO FORENSE para que valore la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-06-11','Ana: Recibo llamada de Ceferino (641 881 543), de nuevo transmite su deseo de cambiar de CRR. Quiere irse a toda costa del de Plasencia, dice que allí no se encuentra bien. Quiere ir en primer lugar al de Ba y si esto no pudiera ser al de CC. Al de Mérida tampoco quiere. Le emplazo, a que una vez levantado el Estado de Alarma (a partir del día 21) pida cita con Ana Benavente, TS del ESM, y se lo plantee a ella para hacer la solicitud de cambio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-11','Ana: envío correo al ctutelar@: "Buenos días compañeras/o, Creo que es Icíar quien lo lleva, pero por si acaso lo pongo aquí. Me ha llamado Salvador, Taxista que llevó a Emi de vuelta a Plasencia. Aún no se le ha abonado la factura de dicho trayecto, dice que la entregó en el CRR, no sé di desde éste os la habrán remitido. Pide que por favor le llaméis aclarándolo y confirmándole cuándo se le hará la transferencia. Su teléfono es: 609 119 506. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-06-11','Ana: Llamo a Mariví, TS de Torrejoncillo (927 30 33 66), pero el número está ocupado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-06-11','Ana: Recibo llamada de Adela, TS del SSAB de Zafra (924 554 601); ya tiene finalizado el informe social del modelo de Dependencia. Lo remitirá por registro y me lo adelantará por mail. ······················ Recibo el informe escaneado (ssb2@zafra.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-06-11','Ana: Correo de Toni-Futuex; "Durante la realización del seguimiento sobre cómo se encuentra Manuela, indica que todo bien. Comunica, José M., que Pilar (TS) ya envió la documentación para vincular a él la Dependencia de Manuela, establece que la necesita firmada antes del 22 de septiembre, que es cuando cumple el plazo para presentarla. Se le dice que eso lo tendrán que valorar la Comisión, comenta que no, pues Pilar le ha dicho que lo único que debe hacer la CTAEX es firmar, si no lo hace es porque no quiere... una vez más, la TS, echa balones fuera, le dice que sí a todo lo que José Manuel solicita, sin explicar, al completo, toda la realidad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-06-11','Ana: Correo de Toni-Futuex: "Como se había acordado, el responsable de limpiezas Refolio envía el presupuesto para la realización del trabajo de limpieza en el domicilio de Ramón, como se preveía, dicho presupuesto es elevado (desproporcioando tal vez), quizá porque ha incluido demasiadas horas de trabajo, aunque es cierto que insistió en que se reajustará el presupuesto si hay que disminuir horas de trabajo. Aún así, quizá es conveniente contrastar con el presupuesto solicitado a la empresa de limpieza José Acedo de Cáceres, con quien se tiene cita concertada para el martes, día 16, para que visiten el domicilio y puedan realizar el presupuesto. El presupuesto emitido por limpiezas Refolio se adjunta a la nota." ························· Mi respuesta: "...En cuanto a los presupuestos de limpieza de Civantos, sí, esperaremos al día 16 y comparamos con el de la otra empresa." ·································· Guardo nota con Presupuesto de Limpieza en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-06-12','(Pedro)Llamada de Teresa (618-819511), hermana de José Mª. +++"Ayer me llamó diciendo que le iban a echar del piso y que a ver qué hacía. Tenía pensado venir a casa de mism padres 8-10 días. Yo le dije que a casa de los papás no podía venir hasta que no enconbtrase un lugar donde quedarse. Me pempezó a insultar a ponerse agresivo conmigo..." +++Alternativas: alquiler muy difícil. CRR en lista de espera pero con probabilidad de que su acceso no sea pronto, sino todo lo contrario. +++Le planteo la possibilidad de que se vaya a vivir con ellos hasta que pueda encontar algo: "De eso nada, porque mis padres son muy dependientes, yo estoy en la campaña de la fruta y de ninguna manera eso puede ser así. Mi hermano es un imbécil que solo quiere vivir a su manera..." +++Le planteo la opción de quie pueda ewstar en un hostal hasta que el dinero se lo permita y cuando ya no pueda ser que la familia lo pueda costear: "No, eso tampoco es posible porque mis padres tienen una pensión más baja que él y yo tampoco puedo...Le pedís al fiscal que lo ingrese. Y si se tiene que quedar en la calle...se quede."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-06-11','(Pedro)Conversación con la Dra.Cabanillas (48707) del H. Universitario de Badajoz, Servicio de Endocrinología. +++Desconocía que Joaquín estuviese tutelado y comprende que en esta situación debe informar y solicitar los permisos correspondientes a la Comisión Tutelar. +++Le explico que dada la situación que se plantea con Joaquín (Cristina), debemos informar al Juzgado de la situación, para lo cual necesitamos todos los informes clínicos y sociales (atención psicosocial que indica el "Protocolo de Atención Integral a Personas Trans en el SES") que se tengan enrelación al caso. +++Enviará los Informes una vez que tenga la próxima consulta con Joaquín el día 3 de julio, junto con los consentimientos que debamos firmar. +++UNA VEZ TENGAMOS LOS INFORMES DEL ESM Y DE ENDOCRINOLOGÍA, PONDREMOS TODO ELLO EN CONOCIMEINTO DEL JUZGADO. En cuanto a la opinión al respcto de la CTAEx, SOLCITAREMOS RECONOCIMIENTO FORENSE para que valore la situación.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='FERNANDEZ'and apellido2='GARCIA'),'2020-06-11','(Pedro)Llamada de la Letrada del Juzgado de 1ª Instancia nº 002 de Don Benito (924-808455//924-808452). +++Nos han vuelto a solicitar el Testimonio de Aceptación del Cargo de Tutor, pero ya contestamos a esa solicitud (3 de octubre de 2019)indicando que "...los presentes autos se perdieron, según diligencia de constancia de fecha 02/03/1998 y fieron reconstruídos con las aportaciones de las partes." +++La contestación está escaneada en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-06-12','Ana: Correo de Miguel Ángel, Dir. CRR-CC (residenciadir@feafescaceres.com): "Buenos días Ana, te remito el informe de consulta de Neumología de Antonia Canelada del Rio." ······························· Guardo el informe en el expte. digital. ·· *En el mismo se indica nueva consulta en 3 meses con pruebas de: espirometría, gasometría arteriral y analítica con inmunidad. Nuevo correo de Miguel Ángel: "Buenos días de nuevo Ana, te remito el certificado de Grado de Discapacidad de Antonia Canelada del Rio que nos fue remitido el día de ayer desde el CADEX de Cáceres." ······· se trata de la RESOLUCIÓN DE LA REVISIÓN DEL GRADO DE DISCAPACIDAD; le reconocen el 69% *Provisional hasta 30/06/2021. ·· DICTAMEN TÉCNICO: "Trastorno mental por trastorno ansiedad en crisis"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELEDONIO'and edp.apellido1='GARCIA'and apellido2='MATEOS'),'2020-06-04','(Pedro)Llamada de D. Celedonio (653-207273). +++Tutelado por su hermana: "Ya no quiere seguir siendo mi tutora y quiere que sea la Junta". +++Ella ha solicitado un centro de "día y de noche", pero si me tutela la Junta ¿podré irme de vacaciones con mi madre?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELEDONIO'and edp.apellido1='GARCIA'and apellido2='MATEOS'),'2020-06-12','(Pedro)Llamada de Celedonio. +++"La semana pasada había un juicio pero no se presentó nadie de la Junta. Lo han puesto la semana que viene, el 23 de junio. ¿No pasará otra vez lo mismo, verdad?. +++++++++++++++++++++++++++++++Llamo a Ana Muñoz, de Abogacía, para confirmar que están al tanto de ello: +++El juicio de la semana pasada se suspendió. Supongo que no se loc omunicarían a él. El procedimeinto de Remoción es el 106/2020 pero se suspendió por que se acumulo al 120/2020. Lo lleva Escalona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-06-12','TERESA Cabezuela está en Cáceres es un pueblo del valle del Jerte, por eso está ella tan convencida de que se puede ir el 15, vamos a tener un problema con ella, porque esta pidiendo que se le den 300 euros correspondientes a los 3 lunes que no estaria en villanueva... evidentemente eso lo consideramos del todo inviable. Hemos intentando con ella, hacerle entender que es mucho tiempo, que tal vez podria ir unos dias y volver para el siguiente lunes y retirar su dinero, pero esta bastante empecinada, aunque le estamos diciendo que nosotros lo trasladamos y será la comision quien decida y tendra que acatar lo que sea. Tambien ha dicho que se le autorice a sacar el dinero en Plasencia, y le hemos explicado que eso no se puedee hacer. Le hemos pedido el telefono de la supuesta amiga, por si consideras hablar con ella.. se llama Sonia, su numero es 641268043 Va a seguir insistiendo de aqui al lunes, todos los dias, a nosotras no para de llamarnos asique habria que decirle lo que sea, nosotros desde luego no tenemos muchos mas datos que lo que ella cuenta... y en fin, desde luego tantos dias tal vez sea arriesgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-06-12','TERESA: EMAIL FUTUEX El pasado 10 de junio se visitó por primera vez a José María Amaya en su domicilio, pero antes de eso se fue al despacho de Olga de los SSB para que comentara sus antecedentes y su historia todos estos años. Olga contó que se había solicitado la incapacidad en el año 2017 cuando José María sufrió una serie de caídas en su casa y se pudo ver en las condiciones en las que vivía. Se pudo arreglar su vivienda, y retirar mucha basura y se consiguió que una empresa de ley de dependencia empezara a trabajar con el tutelado. Llevan trabajando desde entonces con él y no ha habido mayores problemas. Pero José María, sigue acumulando basura en dos habitaciones que tiene cerradas con llave en su casa, su higiene personal es bastante deficiente y no quiere cambiar el colchón de su casa que es muy viejo y huele mal porque se le escapa un poco de pis por las noches. Se camina desde el ayuntamiento a casa de José María en compañía de Olga y se llama a la puerta, el tutelado la abre y Olga hace las presentaciones. El tutelado acepta la visita e incluso permite que se entre un poco en la casa. Olga se despide al poco tiempo y se le pregunta si podemos quedarnos un rato más hablando con él, al tutelado le parece una muy buena idea. Nos enseña su casa, muy por encima y nos sentamos con él en el salón de su casa. Cuenta que va a ser su cumpleaños el mes siguiente y va a cumplir 76 años. Se le pide su número de teléfono para llamarlo de vez en cuando y avisarle de nuestras visitas, accede de buen grado. Se le explica que se le visitará de vez en cuando para hablar un rato con él y conversar sobre su vida y sus rutinas y se le pregunta si le parece bien: él responde que le parece muy buena idea. Nos despedimos del tutelado después de una conversación de unos 20 minutos y nos marchamos con la promesa de llamarle pronto para volver a hacerle una visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRIGIDA'and edp.apellido1='MURILLO'and apellido2='ALVAREZ'),'2020-06-12','TERESA: HABLO CON EL INSS POR LA PENSION DE ORFANDAD DE BRIGIDA,ME EXPLICA QUE NO TIENE DERECHOA ORFADAD ABOLUTA PERO SI AL COMPLENTMENETO DE LA PIENSIONDE VIUDEDAD QUE COBRABA SU MADRE, POR LO TANTO CON CAREACTER RETORACTIVO DE TRES MESES SU NUEVA PENSION ES DE 897,15 Y VA A COBRAR EN ATRASOS LA CANTIDAD DE 2360,79 EUROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-12','Ana: Llamada de Emi (633 501 059), dice haber hablado con Icíar, pero no le ha gustado cómo le ha hablado ésta. Contesto que me extraña que Icíar le haya hablado mal pues es una persona muy educada. ·· Por otra parte cuenta que ayer estuvo llorando por sus hijos. Dice que están muy guerreros. El mayor va a cumplir 18 años. Hace más de 3 años que no los ve. Cada uno de ellos vive con una tía (hermanas del padre). Han hecho alguna videollamda. Espera poder verlos cuando finalice la crisis sanitaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-06-12','(Pedro)Llamada de Bernado, del Juzgado de 1ª Instancia nº 2 de Mérida. +++Tiene cita con el Forense el próximo día 18 de junio a las 12:00h. Enviará la citación. +++Bernardo ha tratado de localizar a Jonathan pero no lo ha coseguido. +++He llamado al teléfono del amigo pero no han cogido el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-06-12','Ana: Correo de Toni-Futuex (areasocial3@futuex.es): "Hoy ha ido la compañera al banco y luego se reunirá con Teo, para elaborar este presupuesto, al pedir el extracto de un año, se nota una diferencia muy acusada desde octubre, donde comienza a hacer mas compras por internet y hacer retiradas de cajero (200 o 300 euros) siendo con anterioridad de 20-50 euros, pero el pico mas acusado es desde Mayo hasta ahora, donde las retiradas son de cerca de 500 euros y donde las compras por internet son casi constantes... Ha coincidido que ha cobrado la ayuda del alquiler toda junta (unos 2000 euros) pero que practicamente se ha gastado ya... A el lo notamos mas a la defensiva y esquivo que habitualmente. Cuando la compañaera elabore el informe y el presupuesto de gasto conjunto os pasaremos tambien el extracto de gastos asi como la información que obtengamos pero obviamente esta teniendo comportamientos desajustados en este ámbito con inicio ya unos meses y con un pico estas ultimas fechas. No correlaciona con nada que nosotras en las visitas o seguimientos que le hayamos realizado durante el estado de alarma hayamso podido detectar..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2020-06-12','Ana: Correo de Amor López, TS - ASPACE (amor.lopez@aspacecaceres.es), a la Secc. Ecca.: "Buenos días. Adjunto envio la factura correspondientes a los gastos extras de Santiago Eduardo Mayoral Suarez dni. 28976640K. Estos gastos se han producido en ropa de verano porque como saben no tenía prácticamente nada utilizable y todo lo que compramos le dura muy poco tiempo porque tiende a romperse la ropa a diario. En este sentido, esto nos supone un problema muy a menudo, le hemos hecho un tapa ropa con distintos materiales (tipo chaleco) pero con el paso de los días lo termina rompiendo todo y aunque nosotros mismos hemos traído ropa de nuestras casas para él se hace indispensable comprarle cada cierto tiempo..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-06-12','josefa ya esta en la residencia municipal de castuera desde hoy porque se le hizo el PCR.y dio negativo y no podian pasar 24 horas entre los resultados y el ingreso ,bueno ya hablamos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-06-10','(Pedro) Correo del CRR de Mérida (10-06-2020). +++Ángel Pinilla: Estuvo en aislamiento por febrícula, le hicieron la prueba y el resultado fue negativo por lo que pudo salir de la habitación y seguir con la cotidianidad. Aunque sigue con cambios de humor notables durante el día, le observamos mejor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-06-10','(Pedro) Correo del CRR de Mérida (10-06-2020). +++Antonio Merchán: A raíz de lo comentado en e-mails anteriores, nos coordinamos con el equipo de salud mental de Mérida Norte y le atendió un Psiquiatra que valoró hacer un ajuste farmacológico. Seguimos muy pendientes de su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-10','(Pedro) Correo del CRR de Mérida (10-06-2020). +++Mª Dolores Fernández: Su principal preocupación vuelve a ser el irse a una residencia y qué pasará con su hermano. Solicita ir a casa unos días pero ya le hemos indicado que actualmente no es posible. Esta mañana está intentando solicitar cita a MAP porque dice que esta noche ha sentido que no respiraba bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-06-10','(Pedro) Correo del CRR de Mérida (10-06-2020). +++','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-06-10','(Pedro) Correo del CRR de Mérida (10-06-2020). +++José María Guillén: Muy contento, ha escrito una reflexión agradeciendo a los distintos profesionales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-06-10','(Pedro) Correo del CRR de Mérida (10-06-2020). +++Luisa Rodríguez: La observamos bien, sin grandes incidencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-06-15','miguel, envío email a Aines Murillo: Buenos días, yo la he llamado durante el mes de mayo un par de veces sin lograr hablar con usted. Por parte de esta Comisión Tutelar lo único que se hizo fue ratificar la escritura de herencia que menciona, y se le envió por carta Certificada a la abogada que tramitó la misma, Doña Ana Mª Laquintana móvil 657-704059 y el fijo 943-565717. Suponemos que la inscripción en registro de la propiedad dicha abogada no lo habrá logrado y el motivo no es otro que necesita “la Aprobación Judicial de la Herencia”: para ello, la abogada tendría que habernos remitido (tras presentar a liquidar el impuesto de sucesiones ) las escrituras de herencia. No obstante si acaso ha logrado inscribir dicha herencia en el registro de la propiedad dígannoslo y entonces podría agilizarse la venta que usted le ha comentado a mis compañeros que quieren hacer. Como digo me informan mis compañeros que quieren hacer alguna venta. Comentarles que para cualquier acuerdo con compradores y trámites antes se tienen que poner en contacto conmigo y remitirme la información siguiente: -Datos de compradores -Precio de venta y forma de pago. -Nota simple actualizada de la finca que se quiera vender. -Gastos que haya que afrontar (deudas pendientes y gastos de administración como por ejemplo comunidad de propietarios, IBI, etc) No pueden ustedes llegar a acuerdo de venta sin previamente hablar con nosotros ya que tenemos que solicitar “Autorización Judicial para vender”, cuyo trámite desde que nos remitan toda esa documentación puede tardar algunos meses. Puede llamarme hoy lunes que estaré en la oficina para aclarar cualquier duda. ****************************************************** Mando email a la abogada Ana Mª Laquintana: Buenos días, nos pregunta una de las herederas de la herencia que tramitó usted que cómo van los trámites? Confírmenos dicha herencia imaginamos que la inscribió usted en el registro de la propiedad, caso contrario indíquenoslo ya que normalmente para inscribir en el registro de la propiedad nos requieren la Aprobación Judicial de la herencia. Al estar con teletrabajo, si tiene cualquier duda, puede contactar conmigo o bien por email o bien los lunes en el teléfono debajo indicado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2020-06-15','Recibimos llamada de su hermana Leonor (617422659), para comunicarnos que ha fallecido su padre hace 3 meses. Va a llevar la documentación de la que dispone a una Gestoría de La Zarza, que se pondrá en contacto con nosotros. Son 4 hermanos, él incluido, vive la madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-06-15','(Pedro)Llamada de Jairo (24101) no programada (Juani me dice que a propuesta de Estrella). +++"He aceptado el traslado a pisos tutelados, pero me dicen que por protocolo debo pasar 15 días primero en el CRR..." +++El resto de la conversación ha seguido con sus argumentos habituales. ········································································································· Llamo a Estrella, TS del CSS, en relación al contenido de la conversación de Jairo y Pedro. Ella no ha halado de nada de eso con Jairo y le extraña, que Fran, el Psiquiatra, le haya dicho eso. Hablará con él y me llamará de nuevo. ················· Llamada de Estrella; Fran dice que hace mucho tiempo que habló con Jairo en relación a la posibilidad de acceder a piso supervisado, pues era muy joven para permanecer allí institucionalizado, pero recientemente no han hablado de nada relacionado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CAMPOS'and apellido2='MARTINEZ'),'2020-06-15','TERESA ENVIO CI ANESTESIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='FERNANDEZ'and apellido2='CALDERON'),'2020-06-15','TERESA ENVIO CONSENTIMIETNO INFORMADO ANESTESIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-06-15','TERESA ENVIO DECLARACION INDIVIDUAL DEL PENSIONISTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-06-15','TERESA ENVIO SOLICITUD INFORME SOCIA PARA TRASLADO DE EXPEDIENTE A DAIMIEL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-15','Ana: Llamada de Juan (633 391 891) muy enfadado dice que le ha llamado el médico nuevo, que "tiene pinta de julandrón" y que quiere aumentarle la medicación, que le parece poco los 300 mg del nuevon inyectable ("Abilify") y "sin haberme visto siquiera", además afirma que el nuevo medicamento ya le está haciendo daño, que tiene movimientos involuntarios en los párpados. El psiquiatra le ha dicho que pida el cambio a Pilar, la TS. Me pide que la llame yo pues casi no le queda saldo y además dice que nosotros tenemos que encargarnos de lo "los médicos y su salud". Añade "...no voy a ir al médico maricón ese que me han mandao, no quiero ningún psiquiatra, están todos en el complot". *Le pido que deje de faltar al respeto y añado que la orientación sexual no tiene nada que ver con la profesionalidad. Expresa "no tengo nada contra los gays, pero cámbiamelo y si tienen algún problema que llamen al CSS del Plas." Al despedirse dice que iba a ponerse el inyectable al C.S. ································································· Llamo a Pilar Martín, no sabe nada al respecto de esta conversación del Psiquiatra con Juan. Si habla con él me llamará. En cuanto al cambio dice que eso no le corresponde a ella, que hable con Jesús, Admvo. ······································· Llamo a ESM (927 21 37 30) Jesús dice que le extaña que Juan Pedro le haya dicho que solicite el cambio de médico pues a él le ha dicho que que le cite nuevamente para cita presencial. No obstante habría que cumplimentar y firmar un impreso, nos lo enviará por fax. De todas formas primero quiero hablarlo con el Psiquiatra. Me pasa con él. ······················································· El Dr. Juan Pedro Jiménez Cano, dice que para empezar no entiende que hayan dadao el "alta voluntaria" a un paciente que está delirando. Ni que le hayabn cambiado de psiquiatra de refencia sin más. Considera que habría que subirle la dosis y quiere atenderle de forma presencial. Pedirá que le citen en 15 días y si no acude él no puede hacer más. También dice que Juan le ha dicho que si tenía algún problema que llamara al Dr. Pizarro al CSS de Plasencia, pero que no se iba a tocar la dosis de la medicación ni nada. Que su Psiquiatra era el dr. Pizarro... Si Juan quiere cambiar de nuevo, que le cambien, al igual que le han cambiado del Dr. Medina. Añade que el sistema no funciona y que entonces él no puede hacer más de lo que hace. Que para eso se ha creado una Sociedad de Psiquiatría, para buscar soluciones y dar respuestas a estas situaciones. ··················································· Llamada de Jesús, Admvo: La nueva cita de Juan está programada para el día 29 de junio a las 12:00 h. Se lo enviarán por escrito por correo. ·············································· Hablo con Pedro, no vamos a pedir cambio de médico a Juan. Él verá si no quiere acudir a la próxima cita. *Si no está conforme con el cambio que se lo diga a quién le tramitó el cambio. ·············································· Envío correo a Toni-Futuex, para comunicar próxima cita en psiquiatría para que, a ser posible, Teresa le acompañe. Le informo, para que estén al corriente, del enfado y petición de Juan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-06-15','miguel, tras conversación con Damian por teléfono me comenta que el inquilino le ha llamado de nuevo dos veces y no se lo ha cogido porque quiere su Dni. Le digo no se lo coja y que nosotros cuando sepamos exactamente cuanto le debe se lo reclamaremos. Me comenta que en Agosto del año que viene le quiere fuera de la vivienda, por lo que le digo que tendremos que hacer el correspondiente aviso de no prórroga del contrato con la antelación legal suficiente. ******************************************************* Le preocupa el supuesto que le echaran del CRR, porque piensa que al tener una buena pensión puede llegar un problema para mantenerse en el Centro, con lo que le paso con Pedro quién le tranquiliza y le dice que su plaza es segura (salvo alteraciones de conducta)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA INES'and edp.apellido1='MORENO'and apellido2='POLO'),'2020-06-15','(Pedro)Llamada de D. Miguel Macías (608-442558), hijo de Dª Inés. +++"Han ingresado este sábado a medio día a mi madre en el Hospital de Mérida (2ª planta). He llamado para ver cómo estaba y no me han quierido dar la información por la Ley de Protección de Datos. Quiero saber cómo está, porque yo trabajo en Canarias y si tengo que ir me tengo que organizar." ++++++++++++++++++++++++++++++++++++++Conversación con Ana Timón, T. Soc. del Servicio de Atención al Usuario (SAU) del Hospital de Mérida (81041). +++Ingresó por Urgencias el pasado 11 de junio. Dada de alta de este servicio e ingresda en el Servicio de Medicina Interna (2ª planta). +++El Internista es el Dr. Agustín Cabanillas. +++Solicito nos envíen todos lo informes al respecto de la situación de Dª Inés.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-06-15','miguel, llamo al Jzdo nº1 de Jerez de los Caballeros tras petición de Teresa de cómo siguen los procedimientos de remoción del cargo de tutor que solicitó el padre de la tutelada y de la solicitud de internamiento involuntario. **************************************************** El Juzgado nº1 de Jerez ha tenido que hacer la consulta al Ministerio Fiscal porque no sabían donde estaban los papeles ni lo último que se había hecho. Me insiste que cuando veamos que tardan en responder que les llamemos como ahora. Quedamos en que en unos días Fiscalía les contestarán (les remiten de nuevo a fiscalía todo)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2020-06-15','Ana: recibo correo de Miguel Ángel, director del CRR-CC (residenciadir@feafescaceres.com): "Buenas tardes Ana te remito el consentimiento informado de Martin Miguel Miranda Hernández para la realización de cirugía oral. Un cordial saludo" *Imprimo documento para ponerlo para la firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-06-15','miguel, dejo la documentación que mandó a Juan Pedro para la ordenen y metan en su expediente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-16','Ana: Juana trae del banco el ALTA DE TERCEROS pendiente. ······················· Pongo para REGISTRO DE ENTRADA, ACEPTACIONES PIA, de Prestacion económica vinculada al SAD y Serv. Residencial (CRR), y, tal y como se había acordado previamente, pido que lo entreguen a Clara I. Gómez Nestares, jefe de secc. de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-06-16','Ana: Recibo llamada de María Barrasa, TS del CSS-Mérida (24005). Me informa de que tuvieron una subcomisión y decidieron que Juan Ángel pasara a **UNIDAD DE LARGA ESTANCIA, dadas las características del paciente y las falta de recurso residencial alternativo adecuado. *A partir de junio debe abonar la estancia (75% de sus ingresos). Se lo comunico a Alberto, Jefe de secc. ecca. y a Icíar, para que esté al corriente. ······················································ Envío correo a María Barrasa (maria.barrasa@salud-juntaex.es): "...Como hemos acordado mediante conversación telefónica te envío adjuntos los siguientes documentos: • Testimonio de la sentencia de incapacitación y nombramiento de tutor • Testimonio de aceptación del cargo de tutor Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JUANA'and edp.apellido1='VECINO'and apellido2='GARCIA'),'2020-06-16','(Pedro)Ana Timón, T. Soc. del SAU del Hospital de Mérida, comunica el FALLECIMIENTO de Dª María el pasado domingo, 14 de junio, en el mismo Hospital. +++Lo ha comunicado a la Residencia de Mayores de La Zarza. +++Nos ponemos en contacto con la Residencia para saber si han dado parte a la compañía Ocaso (Nº póliza: 280700751). +++Me pongo en contacto con Mª Isabel, Directora de la Residencia (924-096331 y fax 924-096324): indico compañía de seguro de deceso y nº de póliza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2020-06-16','Ana: Llamada de Maribel, Res. Parque del Príncipe (927 243 472). Pregunta por el CI pendiente, pero aún no nos lo han enviado de hptal. ··································· Por otra parte, Rafael necesita una silla de ruedas. Enviará a la sección ecca. presupuesto e informe médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2020-06-16','Ana: Correo de Toni-Futuex (areasocial3@futuex.es) a la Secc. Ecca: "Presupuestos para la avería de la bañera, del tutelado Felipe Rodriguez Solís, residente en Miajadas. Se adjunta por peticióndel tutelado dos presupuestos,con el objetivo de poder solucionar la avería de la bañera, la cual tiene bastante intranquilo a Felipe, pues gotea al rellano de la entrada y los vecinos se quejan; durante la desescalada se han ido solicitando presupuestos nuevos para poder comparar con el que ya se tenía para dicha acción y así poder agilizar los trámites, obtenidos los dos presupuestos, se adjuntan para valoración del área ecónomica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2020-06-17','(Pedro)Conversación con Mariví, T. Soc. CSS de Plasencia (URA, 24142). +++Enviará el Informe Médico en modelo anexo II de Dependencia. +++Respecto de los Informes Sociales quedamos en que es desde el CSS desde donde se tienen que elaborar. +++Plantea la duda de quién planteó la idea de solicitar la Dependencia de Francisco: Le digo que fue desde el CSS desde el que nos la plantearon. ··························································································································· Llamada de Mariví: Ya recuerda por qué lo pidió, dice que era pura cuestión administrativa, para no registrar el documento tantas veces. Le digo que no es necesario, que lo que debe registrar para enviarnoslo a nosotros es el oficio y el documento nos lo envía adjunto y ya nosotros o le damos registro desde aquí o se lo devolvemos de nuevo con otro oficio para que lo registre ella allí si lo prefiere. **En cuanto al informe médico en el anexo correspondiente, y lo ha pedido, cuando lo tengan me lo hará llegar escaneado a mi correo. *Y el informe del psiquiatra que envió lo adjuntaremos también, pues hace tiempo que a ella se lo piden también con la solicitud. ············ Por otra parte me comunica que Fco. ha recibido allí una carta del Jdo. de Plasencia que le ha ido a enseñar, no tiene copia pero ha tomado notas: **Se le reconoce ASISTENCIA JURÍDICA GRATUITA para el procedimiento de REMOCIÓN DE LA TUTELA. La Abogada asignada es Mª Rocío Felipe Tomé. La Procuradora: Mª del Carmen Cartagena Delgado. Tlf. de contacto: 927 41 24 97 // 600 221 608. ···················· Se lo comunico a Ángel y Miguel, Asesores Jurídidos CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-16','Ana: Correo de Toni-Futuex "areasocial3@futuex.es" ayer a última hora: "...Pues mira, justo ahora, está hablando con Teresa alteradisimo... pero tela, tela, porque le estaba escuchando yo tras el telefono, pegando gritos. Se ha puesto el inyectable, por lo tanto se ira relajando, ojala... Indicaba que no va ir a ningún sitio (cita de psiquiatra) ni va a salir de su casa si no es con la guardia civil (como dijo la otra vez) Luego al final se ha calmado un poco.. pero en general seguia muy enfadado. Dice que neceista 80 euros.. que no le llega para cortarse el pelo y alguna cosa mas (eso no lo especifica) no se si seria posible subirle un poquito aunque sea esta semana la asignacion o darle un pequeño extra, de 20 euros o lo que sea.. ya que eso le tiene fatal hoy. Tampoco se si ha comentado esto contigo, a nosotros nos ha dicho que si.. y alomejor se lo habeis denegado no se.. Con el, es muy difiicil, pero es cierto que si fuera posible que tuviera un extra eso podria ayudar a seguir trabanjando con el, el tema de la cita presencial del psiquiatra por ej, que Teresa lo acompañaria sin problemas, pero tal y como estaba hace un momento estamos muy lejos de conseguir que acceda." ··························································· Mi respuesta: "...Con respecto al extra que pide, la semana pasada envié un correo a la secc. ecca. comunicando su petición y pidiendo que lo valoraran y les llamaran ellos. No sé si Pedro querrá comentarlo con Alberto. Tampoco sé si con tanto gasto previo (cáterin y teléfono nuevo) lo aceptarían, pero al menos que le llamen y se lo digan o que, como tú dices, le den al menos algo para la peluquería… (cuestión que no me dijo el viernes, sólo me dijo para pagar unas deudillas…)" En relación a la cita presencial con el Dr. Jiménez Cano me temo que se va a negar a acudir, pues además también se niega a que le aumenten la dosis del inyectable, pero como decía Pedro, en mi opinión con buen criterio, no vamos a acceder a todas sus peticiones, y menos a la del cambio de Psiquiatra otra vez… pues ni siquiera le ha visto aún en persona..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JUANA'and edp.apellido1='VECINO'and apellido2='GARCIA'),'2020-06-14','EXITUS El 14/09/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-17','Ana: Llamada de José Manuel (722 493 622); dice que su hermano le quiere echar del piso por haber metido allí a su hijo y a la novia de éste. Los abuelos ya no quieren saber nada de él y la madre también se ha desentendido. *Le digo que su hijo ya es mayorcito para buscarse la vida y que hasta la fecha sólo le ha generado problemas. Dice que lo sabe, pero que le da pena dejarlo en la calle. Añado que de todas formas, nosotros no podemos ayudarle en eso, quién ha permitido que se instalen allí es él, nosotros no podemos impedirlo, tendrá que resolverlo él mismo. ·· Por otra parte pregunta cómo va la reclamación de la pensión de alimentos que pasa a su ex-mujer por sus hijos. *Volveré a recordarlo a los compañeros jurídicos. ···················· Envío un coreo a Ángel, CTAEX, preguntando si saben algo nuevo del colegio de abodados y pidiendo que en cuanto haya novedad me informe. ···································· Respuesta de Ángel: "...Hablé con el Colegio de Abogados y les seguía constando la misma designación a la que nosotros planteamos la queja. Me comentó con quien hablé que iba a revisar el caso con el Secretario y que nos llamarían con lo que resolvieran. Seguimos sin saber nada. Le doy otro toque esta mañana al Colegio..." ································································································································ Correo de Toni-Futuex al final de la mañana: "...El pasado 11 de junio de 2020 recibe mediante correo certificado una notificación de los juzgados de Plasencia, cuyo contenido es la notificación de requerimiento presencial para los próximos días 16 de julio a las 10:00 h. para la celebración de un juicio rápido 21 de julio a las 11:00 h. para la celebración de juicio por delito leve, seguido por amenazas, cuyos hechos ocurrieron en Plasencia el pasado 6 de junio de 2019, en calidad de denunciado. El tutelado muestra su preocupación por este asunto, teme que pueda ir a prisión, según relata este juicio es por un suceso que tuvo lugar en centro sociosanitario de Plasencia, donde provocó la quema de un colchón y realizó amenazas a algunos profesionales y residentes del centro. Se le transmite tranquilidad y se le pide que no se anticipe, se le recomienda que espere a recibir instrucciones de la CTAEx y en el momento del juicio que responda a las cuestiones que se le pregunten tal y como sucedieron, se le trasmite también que no se le puede dar más información puesto que se desconocen los hechos y además no se tiene la capacidad profesional para anticiparse a las posibles consecuencias. Se adjunta dicha notificación a esta nota. Por otro lado, y según relata la situación en el domicilio es insostenible debido a la presencia del hijo y su novia, con los cuales tiene conflictos prácticamente a diario, expresa la exigencia de un cambio de catering, la gestión inmediata de plaza en centro residencial y un aumento de asignación. (en su línea todo)..." *Enviaré la notificación del Jdo. a Ángel, Asesor Jurídico CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2020-06-17','(Pedro) +++Llamo a primera hora (08:00)en dos ocasiones a Aprosuba 3, Caty (628-421501) ante la urgencia que parecía existir dadas las llamadas de ayer por la tarde y el correo electrónico.No me contestan. +++Llamada de Caty:" Durante el fin de semana Diego se sentía bastante incómodo porque no podía defecar y tenía dolor de vientre. Lo vió el médico y lo derivó al Hospital. En un principio se pensó que lo tendrían que operar, porque tenía una torsión intestinal. Finalmente se solucionó mediante una colonoscopia." +++A día de hoy sigue ingresado. Tiene una persona acompañándole . Le indico que tienen que enviarnos una propuesta económica con la previsión de días de acompañamiento. Comenta que se prevé el alta hoy o mañana. +++SE le pide el Informe de Alta cuando se la den.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-16','(Pedro) Conversación con Javier, Director CRR de Plasencia. +++Emilia acudió ayer al ESM acompañada. Montó una buena cuando el Psiquiatra le dijo que le iba a bajar el cipresa. +++No dispone en estos moentos de dinero, pero no deja de comparse ropa: sale con Francis, su pareja, y este le paga todo lo que ella le pide, al parecer porque le quiere hacer regalos y nadie puede impedírselo. Planteo el tema de las relaciones sexuales; Emi estaba acudiendo a Planificación Familiar en Mérida, pero al poarecer no está siendo así en Plasencia: Pido que verifiquen que sigue usando m.a.c. y, en cualquier caso, que retome las consultas en Planificación Familiar. +++Hace unos día volvió de la consulta del ortoprotésico con la prótesis colocada: sin presupuesto previo ni nada. Comento que es imposible controlar este tipo de gasto si en los establecimeinto a los que acuden le permiten la compra sin abono en el momento (dice que pasen la factura a la Comisión y ya está). La única manera que tenemos desde la Comisión es NO pAGAR, lo que llevarúia a que ella se nefrentase a un sin fin de dencuncias. Pido a Javier que le hagan ver este argumento, para ver si facilita que deje ese comportamiento (¿?). +++"Somos solamente el monedero de Emi" -dice Javier. +++Soraya ha enviado una carta a Emi advirtiéndole de que como mantenga los comportamientos que protagoniza, finalemnete será expulsada del CRR y no será admistida en ningún recurso. Están a la espera de recibir la carta y ver la reacción de Emilia. +++Javier considera que Emi debería pasar una temporada efuera del CRR, en la URH, y con resreva de plaza en el CRR. Creo que es acertada esta propuesta, porque en estos moentos su permanencia en el CRR no mejora la situación. +++ESTA PENDIENTE LA CONVOCATORIA DE SUBCOMSIIÓN DE CASOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-06-17','Ana: Correo de José M. Escalona Amor (jose.escalona@juntaex.es): "ASUNTO: MODIFICACION DE CAPACIDAD DE D. JESUS ROMERO PEREZ (TUTELADO) JUZGADO DE PRIMERA INTANCIA NUM. 1 CACERES PROCD. 587/2019 ACOMPAÑO DILIGENCIA DE ORDENACION DE 15 DE JUNIO DE 2020 SUSPENDIENDO EL RECONOCIMIENTO JUDICIAL SEÑALADO PORA EL 9 DE JULIO 2020 Y SE SEÑALA PARA EL 9 DE SEPTIEMBRE DE 2020 A LAS 9:30 HORAS NOTA: ESTA NOTIFICACION MODIFICA LA ANTERIOMENTE ENVIADA DADO EL ERROR EXISTENTE EL REGISTRO DE ESTA ABOGACIA EN LA REFERENCIA (37656) SIENDO EL 44526." ········································································ Envío la comunicación a Teo del Arce, TS - CRPS (tdearce.sanmiguel@hospitalarias.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-17','Ana: Recibo correo de Rosa Marina Fdez - Psiquiatra: "Estimados compañeros/as, Como miembro permanente de la Subcomisión de Gestión de Casos: Se le convoca a la reunión de evaluación del caso EMB que tendrá lugar mediante la aplicación TEAMS el próximo día 25 de Junio a las 13h. Un saludo" ························································································· Devuelvo llamada a Emi (633 501 059): Dice que se ha puesto hoy la Zyprexa y se encontraba mal cuando ha intentado llamarme,quería irse de allí, pero que ha hablado con Alberto, Monitor del CRR-Mérida y ya está más calmada. Dice que quiere ir a ver a su "novio José María de Mérida", pero sabe que ahora no puede.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-17','Ana: Correo de Pedro, Jefe secc., a Alberto, jefe secc. ecca. : "Buenos días, Alberto. En base a los correos que te reenvío, ¿sería posible aumentar algo la mensualidad de D. Juan, o mejor, mantenerla pero dándole una extra para que se tranquilice y Futuex pueda seguir trabajando con él? Es especialmente importante el acompañamiento al ESM para asegurar su asistencia. Si tú no tienes inconveniente en ello, por mi parte tampoco la hay. Y si es así, se lo comunicáis para que sepa cuándo puede disponer de ello. Ya me dices tu parecer." ······················································································· Llamada de Juan (633 391 891) a última hora de la mañana; esta vez más tranquilo, pregunta si e han aprobado el dinero extra que pide, pues debe dinero en el estanco y algún sitio más. NO le han llamado de la secc. ecca. aún. De Cruz Roja tampoco le han llevado alimentos todavía. "Son unos ladrones, se llevan los víveres a su casa". Y tras esto vuelve con su discurso sobre la trama del C. Salud y los psiquiatras, la inyecciones nazis y el complot. "En el psiquiátrico se cargaron a mucha gente cuando lo regentaba la Diputación y por eso me da miedo volver. Conmigo también lo intentaron pero no han podido..." ································································································· Correo de Toni-Futuex a última hora: "Hoy ha llamado a Teresa, él de mutuo propio, y ha estado mucho más tranquilo, incluso reconociendo que se pasó con los gritos ayer… Insiste eso si, en el tema del dinero, que no le llega, que necesita un extra y etc.. le hemos explicado tal y como comentas, que está avisada el área económica y son ellos quienes deben decidirlo. Y respecto a lo de la cita del psiquiatra, dice que si no le llega por carta a su domicilio no va a acudir, que el necesita esa citación, (imagino el ses la enviará no?) ahora lo pone como condición para acudir a Cáceres, Teresa le esperaría allí en salud mental para ir con el, eso no seria ningún problema, pero si seria importante que le llegara la cita porque dice que si no, no acude."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-06-17','Ana: Correo de Toni-Futuex a la Secc. Ecca: "Buenas tardes, a continuación os enviamos el informe solicitado sobre los aspectos ecónomicos del tutelado Jesus Romero, asi como toda la información recabada y el presupuesto de gasto que se ha realizado con el. Nos ha alertado un poco, la falta de control en el gasto desde hace unos meses, incrementandose de forma exponencial en las ultimas retiradas, no sabemos si poroque ha cobrado los atrasos de la ayuda al alquiler, también adjuntamos lo relativo a la contratacion de un producto,un fondo, en renta4 que creemos no puede contratar al estar incapacitado, asi como la información obtenida en este sentido. Quedamos a disposción para cualquier asunto, seguiremos trabajando con el, ahora si cabe poniendole mas atención a el tema del gasto, aunque él, muestra resistencias al control porque se condisdera autonomo, ciertamente tiene un buen nivel compentencial en las areas de desarrollo de su vida, o ha tenido, hasta este momento"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-06-18','(Pedro) Correo del CRR de Mérida (17-06-2020). +++Ángel Pinilla: Mejorando notablemente en la limpieza de habitación. Sigue durmiendo a deshoras y refiriendo dolor de espalda. Importantes cambios de humor a lo largo del día. No obstante, mantiene sus salidas con compañeros a tomar algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-06-18','(Pedro) Correo del CRR de Mérida (17-06-2020). +++Antonio Merchán: Hemos pedido adelantar la cita con su Psiquiatra de referencia (Dra Montero), será el 6 de Julio. Como sabéis el día 5 de Junio solicitamos valoración que fue llevada a cabo "de urgencia" por otro Psiquiatra quien ajustó su medicación. Seguimos observando irascible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-18','(Pedro) Correo del CRR de Mérida (17-06-2020). +++Mª Dolores Fernández: Preocupada por una carta de urbanismo en relación con su casa, comenta que os ha trasladado esta información. Esta mañana ha salido y ha hecho algunas compras, de momento hoy no nos ha vuelto a sacar el tema. Estamos pendientes. ++++++++++++++++++++++++++++++++++(Pedro)Hago varias llamadas al Ayto. de Almendralejo para hablar con Urbanismo pero no me cogen el teléfono. ++++++++++++++++++++++++++++++++++(Pedro)Por fín consigo hablar con Carmen Gordillo, Técnica de Urbanismo del Ayto. de Almendralejo. +++Se trata de las mismas actuaciones, actualizadas, que se inciaron a finales de 2018, Obras por Orden de Ejecución, expedientes 40/2017 y 41/2017, y de las cuales Mauel Porrón ya nos envió la notificación (consta en expediente). En estos momentos se ha inciado de nuevo el procedimiento que va a afectar a la fachada y la cubierta. +++Ya Ángel envío en su día (09-11-2018) la sentencia de incapacitación, nombramiento y aceptación del cargo para que las comunicaciones nos las enviaran a nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-06-18','(Pedro) Correo del CRR de Mérida (17-06-2020). +++José María Guillén: Contento, estamos trabajando las exigencias y su supervisión continua a todo lo que le rodea. Bastante accesible actualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-06-18','(Pedro) Correo del CRR de Mérida (17-06-2020). +++Luisa Rodríguez: Ayer tenía cita para analítica (para comprobar niveles de valproico) pero decidió no ir. Ha gestionado nuevamente la nueva y será el día 26 de Junio. No siempre acepta bien las indicaciones que se le dan, especialmente sobre la duración de las salidas, por lo demás de buen humor y adecuada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-18','Ana: Envío a Ángel, CTAEX (angel.marinm@salud-juntaex.es), las Cédudas de citación del Jdo. de 1A inst. e instrucc. nº1 de Plasencia. ···················································································································· Llamada de José Manuel (722 493 622); "me tenéis que acelerar lo del centro como sea, mi hijo me la lió ayer per bien liá, hasta hizo un agujero en la puerta. Vino mi hija y también se la lió a ella, se fue llorando", una vez más le recuerdo, que está pendiente la subcomisión sosiosanitaria, que el que le den o no plaza ya no depende de nosotros. Asimismo le recuerdo que quién ha consentido que se instale allí su hijo es él, a sabiendas de que no deja de generarle problemas. Le pregunto que por qué no llamó a la policía, su respuesta ha sido "sí, tenía que haber llamado..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-06-17','Ana: Recibimos resolución de SUSPENSIÓN DEL COBRO de la PNC. ········ Se lo envíoa a Juana, secc. ecca, y pregunto si saben algo a respecto. ······················· Correo respuesta de Juana: "...Si estamos al tanto de la suspensión. Estamos solucionando con el Banco Santander una cosa que nos queda pendiente y problamente la semana que viene ya se pueda pedir la reactivación. Te informamos de los acontecimientos..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-06-18','Ana: Recibo llamada de Mariví Clemente, TS CSS, ahora lleva ella larga estancia. Dice que Jairo ahora quiere irse a piso supervisado, considera que tiene habilidades más que suficientes para residir en el mismo. En mi opinión sería, sería más apropiado CRR. Indica que con Grado I, es más complicado que pueda acceder. *Tampoco cree que vaya a funcionar en el piso, pues al igual que pasó en la Ud. de Rehabilitación, que es lo más parecido a CRR, tampoco funcionó porque no quería normas. No obstante, como no hay más alternativas, se encargará de tramitar la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-06-17','Ana: Correo de Toni-Futuex: "Su marido está insistiendo muchísimo sobre la declaración de la renta, que el, tiene cita el 24 de Junio para hacerla por telefóno y pregunta sobre la de Desi, le hemos explicado que eso es algo que le corresponde a la comisión, que posiblemente no este obligada, pero él dice que tienen el tema de la venta de la casa, asique en ese sentido es posible que si, para que lo puedas trasladar a tus compañeros y se ocupen de la gestión en su caso." ······························ Lo comunicaré a la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-06-18','(Pedro)Llamada de Juan José. +++Preocupado porque cuando se traslade a Cáceres no vaya a tener problemas pora sacar su dienro. le tranquilizo al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-18','(Pedro)Hago varias llamadas al Ayto. de Almendralejo para hablar con Urbanismo pero no me cogen el teléfono.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA INES'and edp.apellido1='MORENO'and apellido2='POLO'),'2020-06-18','(Pedro)Llamada de D. Miguel Macías (608-442558), hijo de Dª Inés: +++"Ayer le dieron el alta a mi madre y la llevaron a la residencia. Está con sonda nasogástrica.Solo le llamaba para comunicárselo." +++A la espera de los informes solicitados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2020-06-18','-Email de Cati , Ap3 : Buenos días. Informar que Diego Blanco fue dado de alta anoche a las 21:30 horas. Ha llegado con una sonda urinaria. Estamos intentado contactar con su médico de cabecera para que nos indique las pautas a seguir. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2020-06-18','-Email de Cati , Ap3 : Buenos días. Informar que Diego Blanco fue dado de alta anoche a las 21:30 horas. Ha llegado con una sonda urinaria. Estamos intentado contactar con su médico de cabecera para que nos indique las pautas a seguir. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-18','-Contestación de Pedro al CRR Merida : Dª Mª Dolores lleva llamándome infinidad de veces durante estos últimos días: preocupada por la casa, que dice haber recibido una carta pero que su hermano no quiere ir a por ella. Le he dicho que nos haga llegar esa carta para ver de qué se trata. He llamado varias veces a Urbanismo del Ayuntamiento de Almendralejo sin conseguir contactar con ellos. Ya en otra ocasión, quizá hace más de un año ya me planteó también que si iban a arreglar la fachada. Volveré a llamar a Urbanismo a ver de qué se trata esta vez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2020-06-18','Ana: Recibo llamada de Carolina, hermana de Marisa (696 281 560), está en CC, a las 11 h tienen cita en la residencia para hacer la visita a su hermana. Pregunta si ya se han solucionado los problemas con el banco, le digo que creo que sí, pero igualmente le facilito el nº de Belén, secc. ecca. CTAEX, por si tuviera alguna duda o surgiera alguna otra cuestión económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-06-18','miguel, acaban de llamarme del Juzgado y me confirman que es seguro que le asignarán abogado de oficio. También me ha confirmado que nosotros asistiremos por videoconferencia, como siempre, desde los Juzgados de Mérida. Le he explicado que la solicitud de abogado de oficio es para el curatelado o tutelado no para la Ctaex, y que abogacía general no representa a los tutelados más que en procedimientos judicial de nombramiento de incapacitación y remociones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-18','Ana: Llamada de Pilar, TS ESM-CC: Pregunta si Juan se sigue negando a acudir a la cita. Le comunico que ayer dijo a Teresa, Delegada Futuex, que si sólo acudirá a la consulta si recibe la carta. Y yo ya pedí a Jesús, Admvo., que se la enviaran por correo, así que espero que acuda. *Teresa le acompañará a la consulta, le esperará allí en el C. de Salud. Juan acudirá en ambulancia. ·· Pilar dice que llamará a Clara, TS del C. Salud de Guadalupe. ·················································································································· Llamada de Juan (633 391 891), aún no le han llamado de la secc. ecca. ················································· Correo de Alberto, Jefe Secc. Ecca. CTAEX (alberto.martinr@salud-juntaex.es): "Buenos días. Se remite hoy autorización a banco para reintegro de 80 €. Podrá sacarlos entre mañana día 19/06/2020 y el viernes que viene. Incluyo en copia a Toni para que se lo comunique al tutelado y tenga conocimiento del dinero del que va a disponer. Alberto." ······················ Nuevo correo de Alberto: "Perdonad. Símplemente para que lo tengais en cuenta cuando trateis con el. Aunque tiene autorizados reintegros por 222 €/mes (55 € la primera semana y 50 € el resto), la realidad es que, si incluimos los extras que periódicamente solicita, dicho importe sube hasta los 280 €/mes de media. A parte las trasferencias que hubiera que realizar (catering, móvil, impuestos...). Su situación, conforme a la pensión que tiene y al control que se ejerce, es positiva. Alberto." ··········································································································· Nueva llamada de Juan (633 391 891): como vuelve a preguntar, ya le indico que mañana puede ir a retirar el extra al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2020-06-18','(Pedro)Conversación de Ángel con la Abogada. +++ La Abogada no sabe nada más que la han designado por el Colegio de Abogados para este procedimiento. Tiene toda la pinta que esta solicitud de Abogado de oficio la ha hecho, o bien el propio Francisco, o el Sociosanitario de Plasencia, porque quien consta como interesado en la designación de Abogado, es el propio Francisco. En cualquier caso, no tiene validez, puesto que quien puede solicitar abogado de oficio en su nombre, es la CTAEX. Esta circunstancia ya nos ha ocurrido en otros procedimientos y el Juzgado ha dejado sin efecto la designación. En cualquier caso, la Abogada designada va a ponerlo en conocimiento del Colegio de Abogados. Le he facilitado mi teléfono de la oficina y el correo electrónico de CTAEX, para que nos mantenga informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-06-18','TERESA SE AUTORIZAN 230 EUROS PARA QUE BEATRIZ SE COMPRE ROPA Y VAYA A LA PELU, ME DIJO QUE LE ACOMPAÑABA LA AUXLIAR DEL SAD PERO FINALEMNTE HA IDO CON UNA AMIGA SEGUN ME COMENTA M CIELO TS DEL CRPS, ESEPREMOS QUE HAGA HECHO UNA COMPRA RESPONSABLE EN SEPTIEMBRE QUIERA CONTINUAR CON LA DEPILACION LASER, PEDIRA PRESUPUESTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2020-06-18','TERESA: EMAIL FUTUEX Se recoge a Diego en su domicilio y cuenta que está muy contento porque ayer estuvieron los pintores todo el día en su casa y dejaron el salón y el patio estupendamente. Ahora solo falta que Pilar mande los datos de Diego a los pintores para que éstos hagan una factura y se la pasen a Pilar para que ésta se la mande a Teresa. Se acompaña a Diego al banco y se retiran los 100€ que se han pedido para la compra de ropa y la celebración de su cumpleaños. Se adjuntan las facturas que justifican esa retirada. Seguidamente, se va a una zapatería y se revisan unas sandalias tipo sport que Diego necesita. Se prueba un modelo que le gusta mucho y tiene buen precio y se las compra. Tienen un valor de 20,95€. Al cabo de un rato se pregunta por todas las tiendas de ropa de caballero del pueblo por la talla 52, que es la que tiene el tutelado y solamente la encontramos en dos tiendas, y en una de ellas las bermudas costaban 45€. En la otra tienda nos comentan que solamente les queda una bermuda de esa talla, Diego se la prueba y le queda bien. Se le piden tres camisas de manga corta para y se prueba una. Aunque le quedan un poco grandes, él está contento porque comenta que se siente muy cómodo. Por lo tanto se compra en esa tienda; una bermuda de 10€ y tres camisas de 15,50€ por lo que el total asciende a 56,50€. Se decide entregar el resto del dinero: 22,50€ a Diego. Él manifiesta que quiere irse a comer con su novia Juli el día de su cumpleaños a Zafra, al restaurante Los Cazadores. Se llama al restaurante y se reserva mesa para dos personas para el jueves 25 de Junio y se le pide al dueño del restaurante que cuando Diego y su pareja finalicen la comida, haga una factura a nombre de Diego con sus datos y la mande por email. No ponen impedimentos de ninguna clase pero piden que se les llame el mismo día 25 para dar los datos del tutelado y para pasarles el email al que tienen que mandar la factura. Una vez que se tenga la factura de la comida, la enviaremos para fustificar el gasto, como las dos que se adjuntan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2020-06-18','Ana: Correo de Alberto, Jefe Secc. Ecca. CTAEX, a Icíar: "Hola Iciar. Te llamo pero no soy capaz de hablar contigo. Pongo a Ana en copia. Acabo de hacerle la ficha al tutelado. Todo Ok. 2 cosas: • Presupuestos fontanería: OK...en mi opinión el más barato, pero que decida FUTUEX ya que ellos están más encima del problema. • Con este gasto extraordinario, ya se ha fundido toda posibilidad de ahorro en este año. Tengámoslo presente para posteriores incidencias. • Seguro Deceso: sin prisa. Ya lo ves con Coral...es Mafre?...si ves la ficha, haía anotaciones anteriores de cargos x sesguro de vida que ya no aparecen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-06-19','(Pedro) Llamada de Mª Isabel, pareja de Pedro Tomás. +++. Le han citado en el Juzgado de 1ª Instancia nº 3 de Mérida a las 10:30 del día 2 de julio. He pedido que nos envíen la citación por fax. +++Siguen con la idea de pedir un préstamo a nombre de ella para arreglar la casa del pueblo. Tienen previsto marcharse antes de que finalice el mes. +++Dice que no están teniendo ningún seguimiento del CSS: Juan Pedro ha ido a verlos una vez que ella estaba en la cama y ellos lo llaman de vez en cuando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2020-06-18','TERESA: EMAIL FUTUEX te comento una situación sobre la necesidad de unas gafas para el tutelado David Vita, y lo que ha acontecido con su paddre a continuación: 10 de Junio: Llamada telefónica de Ángel Vita (padre de David, se encuentra residiendo en Fuente de Cantos con su familia por el estado de alarma en lugar de residencia de Plena inclusión Llerena) El pasado día 10 de Junio, se recibe una llamada de Ángel sobre las 14:00h en la que comenta que ha ido esa mañana con su hijo David a la óptica de Fuente de Cantos y le han revisado la vista y le ha mirado la montura que estaba rota (esto es cierto lleva rota todo el tiempo de confinamiento y pegadas con celofan). Le han comentado que le había subido unas diotrías en un ojo y que la montura había que cambiarla por otra y cambiar los cristales también. Por lo que él ha dado el visto bueno y las ha pedido, entregando incluso 50€ de garantía porque el pedido sobrepasaba los 650€. Pero lo ha hecho con la intención de que la Comisión autorizara el pago del resto del dinero sin antes haber recibido un presupuesto ni ningún otro documento por parte de la óptica. Se le comenta a Ángel que así no es cómo se hacen las compras con la comisión. Primero hay que pedir un presupuesto a la óptica con la cuantía de lo que valdrían la montura y los cristales y mandárselo para que le revisen. Y una vez que dan el visto bueno, se ve la mejor manera de hacer el pago, a veces se hace una transferencia a la tienda directamente o se paga en efectivo si la tienda no quiere hacerlo de otro modo. Ángel comenta que llamará a la tienda para cancelar el pedido y se le recuerda que la educadora va el viernes a Fuente de Cantos para visitar a David y de paso se irá a la óptica para hablar con ellos, pedir un presupuesto y ver las opciones posibles que tiene David. 11 de Junio: Llamada telefónica a David y a la óptica Se llama a David y se le pregunta por su estado de salud, él contesta que se encuentra muy bien y que está deseando recibir visitas para poder salir a dar una vuelta o a tomar algo en alguna terraza. Se le pregunta por las recetas de cocina y cuenta que está muy animado y sigue cocinando postres para toda su familia. Se le recuerda que se le visitará al día siguiente sobre las 09:30h, comenta que le parece muy temprano pero después de insistir un par de veces, accede a pasear a esa hora para hacer algo de ejercicio. Se llama a la óptica de Fuente de Cantos para pedir que se envíe por email el presupuesto de la monturas y los cristales nuevos de David para así hacérselos llegar a la comi 12 Junio : Se adjunta la factura proforma de la montura y cristales nuevos para David Vita. Se ha hablado esta mañana con la óptica y se le ha pedido que la mandara por email. En la óptica han trabajado otras veces con la comisión y saben cómo va el proceso. Quedamos a la espera sobre la valoración económica de dicho gasto. Al no existir otra optica donde reisde ahora estamos limitados en el hecho de conseguir otro presupuesto, si es cierto, pq lo hemos constatado que estan rotas. Vamos a interesarnos el lunes, en saber cuando tienen previsto la residencia de plena inclusion llerena o el centro ocuapcional ponerse en funcionamiento por si DAvid regresara al centro pronto o no.+','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-06-18','Ana: Llamada de Ceferino (641 881 543), dice que ayer habló con Javier al respecto. Al parecer su hermano, con el que no mantiene relación alguna, y único heredero junto a él de la vivienda de sus padres, ha alquilado la misma sin decírselo a él ni a la CTAEX y está sacando beneficios sin darle a él la mitad. Pide que los jurídicos intervengan. ············································· Lo comunico a Ángel y Miguel, A.Jurídicos CTAEX por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-19','Ana: Llamada de José Manuel (722 493 622), ya ha hablado esta mañana con Pedro-CTAEX y con Virginia-Futuex. Pregunta por el presupuesto de limpieza y dice que se quiere comprar un televisor nuevo. Le digo que si ya lo ha hablado con ellos no tiene que llamarme a mí para volver a decir lo mismo. Además para cuestiones económicas ya le he explicado en varias ocasiones que no debe seguir llamándome. Pedirá presupuestos para que lo envíen. De todas formas le digo que no sé si se lo aprobarán, pues ya se ha comprado una lavadora, un móvil y ropa, además de seguir pagando cáterin.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2020-06-19','Ana: Llamo a Marisol, TS del HUC (927 256 823) en relación al C.I. del que seguimos pendientes; Lo que le dijo el Dr. Joao Bernardo es que no tienen fecha para la prueba y por eso la no celeridad, o Laura, Admvo. o él mismo lo enviarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2020-06-19','Ana: Envío a Miguel Ángel, director del CRR-CC (residenciadir@feafescaceres.com) C.I. para Cirugía Oral de Martín.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2020-06-19','TERESA SE AUTORIZA EL PAGO DE UNAS GAFAS NUEVAS YA QUE SE LE HAN ROTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='MARTIN'and apellido2='GALLEGO'),'2020-06-19','TERESA HABLO CON EL DIRECTOR DE LA RESIDENCIA LE FACILITO MI CONTACTO PARA CUALQUIES COSA QUE NECESITE EL TUTELADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='GILARTE'and apellido2='FUENTES'),'2020-06-19','DESESTIMACIÓN DEMANDA El Jzdo. nº. de Navalmoral de la Mata desestima la pretensión de incapacitar, a Dña. Concepción, mediante St. 111/19, de 27 de diciembre. Firmeza declarada por DIOR de 17/06/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GRANADA'and edp.apellido1='CANO'and apellido2='MARQUEZ'),'2020-06-18','(Pedro) Conversación con Mª Isabel, T. Soc. del SSB de Llerena. +++Dª Granada se encuentra bien físicamente y su mayor problema en este sentido es su hipoacusia, que le dificulta la comunicación con los demás. +++Si ella aceptase la ayuda de los Servicios Sociales podría permanecer en su domicilio, con el SAD. pero ella no acepta que nadie entre en su casa, salvo las voluntarias de Cáritas. +++Antes de su último ingreso hospitalario ya estaba casi convencida de ingresar temporalmente en el centro de Mayores de la localidad,mientras limpiaban su casa, pero al enterarse de que se tenía que hacer el PCR y estar una semana en aislamiento se negó: "Yo estaré en mi casa mienbtras la limpian y solo me sacarán de allí muerta..." +++La renuncia a la plaza residencial ya adjudicada en Fuente de Cantos estuvo motivada porque los informes del Servicio de Psiquiatría consideraban que no había motivos para un ingreso involuntario en residencia, por lo que el juzgado anuló la resolución de internamiento. +++Comento con Mª Isabel que creo que no procede, en un primer momento, plantear un ingreso involuntario cuando me dice que ella podría permanecer en su casa aceptando la ayuda de los servicios sociales. Le propongo que vuelvan a intentar hablar con ella desde Cáritas para convencerla de ello y así lo harán. +++Ayer estuvo también Susana, de Futuex. Estamos a la espera de su Informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-06-19','miguel, nos comunican Amalia Ts y Pedro Js, que hay citación de este tutelado el Juzgado de 1ª Instancia nº 3 de Mérida a las 10:30 del día 2 de julio. Cuando nos llegue la citación nos informaremos con el Juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-06-19','miguel, nos llega de abogacía citación para el día 17/6/2020. Tras llamar al Juzgado nº2 Castuera me comentan los siguiente: La vista fue el día 17/6/2020, no entiendo que no nos lo hubieran comunicado antes desde abogacía. Me comentan en el Juzgado que todo ha ido bien, que Guillermo acudió y que están a la espera del informe de la fiscalía pues ya lo han explorado el Forense, y para la semana que viene quieren ya enviarnos la resolución de autorización de internamiento. Creo que no habrá problemas por lo que he hablado con ellos en que la concedan','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-19','(Pedro) Correo reenvíado a la Concejalía de urbanismo de Almendralejo en relación a las actuaciones a llevar a cabo en la fachada y cubierta del bloque de Mª Dolores: +++Enviado al correo-e: cga.ofo.almendralejo.es (Carmen Gordillo, Jefa de Sección Admva. de Gestión Urbanística ). +++Buenos días de nuevo, Carmen. Tal como hemos quedado en conversación telefónica, reenvío el correo de fecha 9 de noviembre de 2018 en el que se adjuntan Sentencia de Incapacitación y Aceptación del Cargo de Dª Mª Dolores Fernández Baez, en relación a la actuación a realizar recogida en los expediente Orden de Ejecución 40/2017 y 41/2017. Rogamos que, a los efectos de comunicación, se remita a esta Comisión Tutelar de Adultos cualquier asunto referido a nuestra tutelada a la siguiente dirección: SEPAD. Comisión Tutelar de Adultos de Extremadura. Avda. de Las Américas nº 4 06800. Mérida Correo de contacto: ctutelar@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='PARRA'and apellido2='ALCANTARA'),'2020-06-19','(Pedro)Llamada de Paqui, Residencia Hernando de Soto. +++Enviarán consentimiento informado para TAC. Remitir, una vez firmado, al siguinete correo-e: rm.hernandodesoto@salud-juntaex.es +++Lleva unos días con molestias en el vientre y han decidido hacer esta prueba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CAMPOS'and apellido2='MARTINEZ'),'2020-06-19','TERESA me comenta el servicio sanitario del Centro que a Ana Campos Martínez, a quien ha extraído el día 23 todas las piezas dentales, la posibilidad de ponerla implantes fijos, pues es muy joven para pasar a dieta triturada el resto de su vida. Por lo que solicitamos información economica de su estado de cuentas de si podría hacer frente a un elevado gasto, para pedir presupuesto a una clínica a nivel particular. ANA TIENE 40000 EUROS EN CUENTA CON LO CUAL LE INDICO QUE PIDA PRESUPUESTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELEDONIO'and edp.apellido1='GARCIA'and apellido2='MATEOS'),'2020-06-19','(Pedro)Nueva llamada de Celedonio (628-088420). +++Preocupado porque el próximo marte vaya "el abogado de la Junta", por si podrá ir con su madre al médico y por si podrá ir de vije en agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2020-06-19','Ana: Llamo a la Residencia Balcón de Extremadura - Montánchez (927 380 516 // 603 19 44 81) Hablo con Rosana, Dir.ª, me facilita su teléfono personal por si fuera necesario en alguan ocasión: 699 19 81 86. Me informa de que Isabel continúa bien. Ahora está en un habitación individual, pues con quienes están tienedo mayor precaución es con todas las personas que no se han contagiado por Covid. Isabel continúa diciendo que se quiere ir a su casa (no reúne condiones) y se niega a salir a pasear ni a nada, dice que si no es a su casa no sale de allí, ni siquiera con su prima, que solía acudir a visitarla y con quien mantiene buena relación. Ya ha recibido visita de su hermano Juan, pero éste apenas tuvo conversación con ella. Me informa de que la pareja del hermano es una persona muy conflictiva y manipuladora, el propio Juan en alguna ocasión ha llegado a expresar que ella "es muy mala". Esta Sra. pidió al médico que hiciera un informe para incapacitar a Juan, a lo cual el médico se negó, por no existir motivos para ello. La reacción de ella fue ir a ponerle una denuncia a la Guardia Civil. **En las visitas a Isabel, sólo le permitirán acceder a él, a la pareja no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-06-19','miguel, la abogada me indica que va a remitirme las escrituras para que solicite la aprobación judicial','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-06-22','TERESA HOY TRALADAN A ADNRES A LA UDAC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PAREDES'and apellido2='HERNANDEZ'),'2020-06-22','(Pedro)Merecedes menaya, T. Soc. del Hospital Perpetuo Socorro (46827). +++FALLECIMIENTO de D. Antonio Paredes Hernández el sábado 20 de junio de 2020, a las 14:30, en el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PAREDES'and apellido2='HERNANDEZ'),'2020-06-22','-Amalia : ha fallecido en el H. Perpetuo Socorro. Hablo con Mercedes , TS , y le facilito los datos de OCASO . Los familiares están allí. Lo comunico a Caser Residencial Olivenza y a las secciones eco y auxiliares.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PAREDES'and apellido2='HERNANDEZ'),'2020-06-20','EXITUS. Comunican del Hospital Perpetuo Socorro(Badajoz), su fallecimiento el 20/06/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GRANADA'and edp.apellido1='CANO'and apellido2='MARQUEZ'),'2020-06-22','Hola! pues te cuento de la visita, nos dejó entrar en la casa y mas o menos bien, pero bastante frustante la posiicion de las profesionales, ya que la acompañamos al Cs junto con la gente de Cáritas, porqeu tenia que recoger una analiticas que estaba fatal al parecer, unos valores alteradisimos, suceptibles de ingreso, pero se negó en rotundo Granada a ir al Hospital, mas tarde hablamos con la ts del cs por si podia hacer algo, al ser un tema santiario... y nos dijo que ella pensaba que para eso esta la ctaex y nosotras alli, para "obligarla" asique imaginate.. te detallo un poco mas todo aqui: El pasado 18 de Junio se realizó una reunión con Maribel, SSB y con Loli Mimbrero, voluntaria de Cáritas en el ayuntamiento de Llerena. Entre las dos estuvieron exponiendo el caso de Granada, que prefiere que la llamen Lali, y comentaron que es una mujer con las ideas muy claras, muy independiente y que no se deja aconsejar. Contaron que lleva dos años más deteriorada física y psicológicamente, ha empezado a acumular basura dentro de casa y no quiere que la ayuda a domicilio vaya a su casa para que se le limpie. Se pregunta a Maribel por la gestión del dinero de Granada y ésta cuenta que no es muy buena porque a ella le gusta mucho comprar todo tipo de adornos y cosas para la casa o ropa. Y normalmente si retira toda la pensión un día, al cabo de diez como mucho, ya no le queda nada. Aunque suele organizarse bien para no quedarse sin comida, esa parte la controla algo más. Por lo que se considera que quizá para los próximos meses, sería recomendable que Granada pudiera retirar la cantidad que se considerara necesaria quincenalmente. Así se organizaría mejor y solamente tendría que ir al banco dos veces al mes ya que le duelen mucho las piernas y camina cada día con más dificultad. Después de la reunión, se visitó a Granada acompañados de Loli, su persona de referencia. Granada accedió a conocernos y pudimos entrar en el zagúan de su casa, que ya estaba empezando a llenarse de suciedad por el suelo. Maribel había comentado que hacía poco tiempo había entrado una cuadrilla del ayuntamiento para limpiar la casa entera y retirar toda la basura. Granada comentó que le picaba mucho el cuerpo y se le recomendó la idea de ir al médico para que le echaran un vistazo, no le pareció mal, aunque demandó que antes pasáramos por el banco. Se la acercó al banco, acompañados en todo momento por Loli, para que Granada se sintiera más segura, y se retiraron los 197€ correspondientes al mes de Junio. Se le explicó que en el mes de Julio podría retirar los 396,60€ pero como algo excepcional hasta que se decidiera la cuota que iba a tener y la periodicidad con la que la iba a retirar. El problema era lo dificultoso de la comunicación con Granada ya que sufre una sordera importante y solo escucha algo por un oído. Por lo que se le explica algo y ella se queda con la parte que le interesa, por lo que habrá que seguir incidiendo en el tema económico con ella. Seguidamente se la acompañó al centro de salud donde la visitó su médico de cabecera, la Dra. Gabriela Candilejo. La Dra. comentó que tenía los resultados de una analítica que la tutelada se había hecho la semana anterior y los niveles estaban todos muy alterados. Facilitó los resultados, y fue subrayando los niveles que no estaban bien, se adjunta el documento en el email. Según su criterio, Granada debía ingresar en el hospital para que le hicieran mas pruebas, ya que su estado de salud era alarmante. Pero a la hora de hablar con ella, solamente le comenta que tiene una anemia importante, a lo que la tutelada responde que ella come muy bien y se comprará vitaminas ahora que tiene dinero y se pondrá como una rosa en dos días. La Dra. entrega un informe de derivación a urgencias por si conseguimos convencerla entre Loli y nosotros para llevarla al hospital. Se adjunta dicho informe. Una vez que Granada monta en el coche, se le explica que su estado de salud es muy delicado y que deberíamos ir al hospital para que le hagan más pruebas. Pero ella entra en estado de cólera, diciendo que no se va a ingresar nunca más, que ella no va al hospital y poniéndose muy nerviosa. Se decide cambiar de conversación y dar un paseo para que se calme pero en el momento que se le vuelve a mencionar el tema del hospital, reacciona de la misma manera, y cuenta que ella cuando estuvo ingresada lo pasó muy mal y no quiere volver a estar ahí nunca más. Cuenta que se va a comprar vitaminas y va a cuidarse mucho para ponerse sana enseguida. Se decide volver a intentarlo en la siguiente visita que se le haga. Por lo tanto se deja a Granada en compañía de Loli para tomarse algo en una terraza y se va al centro de salud para reunirse con Fernanda, la trabajadora social. Se le comentan las peripecias de ese día con Granada y ella comenta que pensaba que estando nosotros allí representando a la comisión, podríamos obligar a Granada a que ingresara en el hospital. Ya que ella pensaba que una vez que Granada tuviera la curatela, sus tutores tendrían que obligarla a ir al hospital o a hacer otra serie de cosas beneficiosas para su estado de salud. Se le responde que eso no está en manos de la comisión, no se puede obligar a nadie a ir al hospital, y menos con una curatela, se intenta trabajar con esas personas para que entiendan la importancia de estar sanas, de los buenos hábitos de salud y de higiene....etc. Pero nosotros no estamos allí para llevar a nadie a la fuerza al hospital. Se le comenta que se visitará a Granada con más asiduidad en estas primeras semanas, para conseguir un apego con ella y para intentar que vaya al hospital o por lo menos que cuide algo más su alimentación y su higiene. Fernanda comenta que estaremos en contacto y que si se necesita algo de ella, allí estará. Se le agradece su disposición. -solicito a la parte eco fraccionar quincenal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-06-03','Ana: Correo de Toni-Futuex (areasocial3@futuex.es) a la secc. ecca.: "02/06/2020 Presupuestos de los arquitectos para reforma Vivienda Manuela Morato Picado: Tras contactar con dos arquitectos de Valencia de Alcántara, José Manuel de la Piedad Pirón y Alejandro Fernández Escarmena, se les envía el informe del aparejador del ayuntamiento con el objetivo de que se facilite un presupuesto para la realización de un proyecto de obra y un seguimiento de la misma. Alejandro Fernández es el arquitecto con quien contactó, previamente, José Manuel, nieto de Manuela y con quien se aprecia que tiene cierta afinidad, algún trato… pues Alejandro intenta gestionar la obra acorde a las mismas peticiones que había hecho José Manuel, se le insiste en que la obra debe hacerse acorde al informe emitido por el aparejador, que es la persona que ha detallado las necesidades detectadas y no debe salirse de ahí. Por el contrario, José Manuel de la Piedad solicita el informe del perito y envía el presupuesto ciñéndose a lo que se indica en el mismo, establece que el presupuesto lo envía aproximado, pues conoce la vivienda y hace una aproximación de los metros que puede tener la cubierta de la misma. Se adjuntan ambos presupuestos, siendo: José Manuel de la Piedad Pirón: 600€ + IVA Manuel Alejandro Fernández Escarmena: 780€ + IVA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-06-04','Ana: Envío correo a Toni-Futuex: "Buenos días Toni, Desde la Secc. Ecca. se inclinan hacia el presupuesto “más barato”, y dadas las circunstancias desde el área social estamos de acuerdo. No obstante, no se aprobará aún nada hasta ver el coste total de todo. Por lo que la compañera puede ir pidiendo nuevos presupuesto de obra (al menos 2) de acuerdo al proyecto de José Manuel de la Piedad Pirón: 600€ + IVA ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2020-06-22','Ana: Llamada de Jesús, Dir. de la Resi. de El Torno (927 173 573), le ha llamado una sobrina del marido de María, le ha comunicado que éste, Antonio Paredes, ha fallecido este fin de semana en el hospital. Que el cuerpo está aún en la cámara y no sabe qué hacer... Le indico a Jesús, que no tiene que hacer nada con respecto a la sobrina, que se ponga en contacto con la Res. donde residía Antonio para el sepelio si quiere y si tienen más dudas al Jdo. que incapacitó a su tío. **En la resi de lo comunicarán a María, tiene sus momentos de lucidez. Pero no acudirá al funeral, pues no está en condiciones. ······················································································· Desde el Hptal. Perpetuo Socorro ya habían counicado el fallecimiento de Antonio a la CTAEX y Amalia ya había hablado con Mercedes, TS del mismo y le había facilitado los datos del Seguro de Decesos (Ocaso). ····································································· Nueva conversación con Jesús, la sobrina ha pedido ser ella quién dé la noticia a María. Como por protocolo en estos momentos no están permitiendo la entrada de nadie en la resi, para continuar libre de Covid, la vista será en el exterior del centro estando María acompañada en todo momento por un profesional de la misma. Siempre que no se atisve interés oculto o que actúen de mala fe, no hay inconveniente en que sí se sea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-06-22','(Pedro)Llamada de José manuel, nieto de Dª Manuela.TEMAS: +++Cambio de PIA: se le exponen las dudas y problemas que pueden surgir al tener que atender a su abuela él solo. Comenta que en caso necesario su hermana, la que vive en Toledo, jubilada y con su pensión, acudría para ayudarle en caso necesario. +++Cama articulada: referiere que la médico le ha dicho que la necesita urgentemente. +++La obra. De esto prácticamnete no comenta nada.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-06-22','miguel, vuelve a enviar email Ainés comentando que no logran hablar con su abogada para que les remita la herencia, por lo que han hablado con el Juzgado de Plasencia (tras preguntar en el Decanato..) y les comentan lo mismo que yo, que necesitan aprobación de la herencia para lo cual evidentemente necesitan que nosotros lo solicitemos cuando la abogada que es quién la tiene nos la remita. Así se lo hago saber de nuevo a Ainés, vía email','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2020-06-22','-662231930 EMILIO TANCO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-06-22','Ana: Recibo llamada de José Manuel Correa, nieto de Manuela (927 582 309) pregunta como van las gestiones relacionadas con la obra. Le he dicho que desde la secc. ecca. ya han optado por un presupuesto. Gloria-Futuex, está con el resto de gestiones. ·· Por otra parte dice que Pilar Márquez, TS del SSB de Valencia de Alcántara, ya ha enviado a la CTAEX, la documentación para solicitar el cambio de PIA para que se firme por el Representante Legal. Él quiere cobrar la Prestación para Cuiadados en el Entorno por un familiar. Le comunico que no puedo asegurarle que esa solicitud se vaya a firmar desde la CTAEX. Se valorará en equipo. Pregunta si puede llamar para hablar con Pedro, Jefe Secc. CTAEX., Le indico que no creo que haya ningún inconveniente. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada de José manuel, nieto de Dª Manuela.TEMAS: +++Cambio de PIA: se le exponen las dudas y problemas que pueden surgir al tener que atender a su abuela él solo. Comenta que en caso necesario su hermana, la que vive en Toledo, jubilada y con su pensión, acudría para ayudarle en caso necesario. +++Cama articulada: referiere que la médico le ha dicho que la necesita urgentemente. +++La obra. De esto prácticamnete no comenta nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-06-22','miguel, llamo al Decanato de Zafra para conocer el estado en que se encuentra la Solicitud de Aprobación de la Herencia junto a la Solitud de Autorización de Venta, y me comentan que ya lo asignaron al Jzdo de 1º instancia e instrucción nº2 de Zafra, siendo el procedimiento X15 nº 129/2020, el cual se encuentra pendiente de aprobación por parte de dicho Jzdo. ************************************************************ Llamo a Mely y le comunico que aunque hicimos dicha solicitud a finales de Febrero, estamos en Junio y todavía está en fase inicial de aceptación dicho procedimiento judicial. Me comenta que me llamará para Septiembre para ver si ya está aprobada judicialmente la herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-06-22','Ana: Recibo llamada de Esther Gil, Educadora del CAM-Trujillo (927 027 600), consideran que debemos de mantener un encuentro personal con Aitor y explicarle la nueva situación. Ellas ya se lo han explicado. La situación de Aitor en el centro se está volviendo cada vez más insostenible, él ve que tiene 18 años y ya no debería estar en ese centro y no quiere permanecer más tiempo allí. Durante el confinamiento se ha fugado en varias ocasiones y ha vuelto al consumo. La situación en el centro no es favorable para él, hay otros menores que le influyen negativamente y se aprovechan de él, instándole a cometer delitos, lo cual a ellas les genera bastante miedo por el joven. En cuanto al consumo y alteraciones de conducta, el ***Psiquiatra les ha hecho ya una autorizacion de ingreso involulntario en UHB para que en el momento que vuelva a consumir y tener estaS conductas activen el 112. *Acordamos que así lo harán. ·· *En relación a la plaza en el recurso residencial, les indico que estamos a la espera y que en la CTAEX no tenemos alternativa para él, pues carecemos de recursos propios y las personas adultas tuteladas acceden a recursos por las mismas vías que el resto de los ciudadanos. No obstante lo pondré en conocimiento de Pedro, Jefe de secc. por si estima oportuno hablar con la Jefa de Ud. de RR. Asistenciales. ··*Y en relación a reunirnos con Aitor, hablaré también con Pedro y ya les confirmaremos si podemos acudir (ellas lo prefieren) o si tiene que venir el joven con alguna de ellas a la CTAEX, no obstante, les recuerdo que no vamos a decirle nada nuevo que ellas no le hayan explicado ya.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-06-22','Ana: Llamada de Ceferino (641 881 543), de nuevo diciendo que se quiere marchar del CRR de Plas. pero que le han dicho que si pide el cambio estaría el nº3 en lista de espera. Quiere otra alternativa. Le vuelvo a explicar que no la hay y que para piso tienen que valorar en el CRR que está capacitado para ello y a día de hoy no es así.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-22','Ana: Llamada de Emi (633 501 059), pregunta por su asignación económica. Le recuerdo que para todo lo relacionado con dinero debe dirigirse a la secc. ecca. Ya tiene el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-06-22','Ana: Comunico a María Barrasa, TS CSS-Mér., que a partir de ahora Amalia es quien se encargará del seguimiento de Juan Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-06-22','(Pedro)Envío correo electrónico al Ayto. de Daimiel (educadorac@aytodaimiel.es) solcitando Informe firmado, sellado y en papel oficial. +++Al cabo de un par de horas recibo llamada de Mª Cruz, Educadora social del Ayto. Lo enviará por correo ordinario y electrónico con las indicaciones dadas. +++Una vez recibido, solicitar el cambio de expedeinte de tutela a la C.A. de Castilla-La Mancha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-06-22','Ana: Llamo a Susana Cortés, TS Casa Hptal. Santiago de Zafra (607 33 19 63): han solicitado plaza RAE para Pilar, aunque no tenga el 75% de discapacidad, no es fácil que se lo concedan. ·· Por otra parte le informo de que ya están todas las gestiones pendientes tramitadas, a la espera de las distintas resoluciones. ·· Le comunico que a partir de ahora mi compañera Teresa hará el seguimiento. Como en ese momento no puede anotar le enviré un mail con su teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-22','Ana: Llamada de Jose Luis Romero (687 581 061), pidiendo que llame a su hermano. Así lo hago (722 493 622), pero salta 2 veces el buzón de voz. Dejo un mensaje y le emplazo a hablar mañana pues ya es tarde. ········································································· Correo de Toni-Futuex a última hora: "...22/06/2020: lleva unos días con actitudes muy demandantes y exigentes, sobre todo en lo referente al área económica, durante el fin de semana se reciben 39 llamadas del tutelado para explicar que tiene un grave problema, se le transmite que durante el fin de semana no se le puede proporcionar apoyo puesto que no es horario laboral, pero a él no le importa puesto que llama cualquier día de la semana y a cualquier hora, eso si siempre con exigencias rotundas. El Lunes 22 a primera hora se contacta con el tutelado para averiguar que le ha pasado, explica que ha vendido su teléfono móvil, el que adquirió a principios de mes. Explica también que ha contratado por vía telefónica la instalación de la fibra óptica en casa asociado a la compra de un televisor de 50”. Según relata lo contrato porque desde la compañía lo presionaron e hicieron que lo contratara a nombre de un tal Eulogio, no proporciona más datos, la tv ya la tiene en casa y ahora solicita dinero extra para comprar un tf móvil nuevo, a lo que se le responde que acaba de comprar uno y si lo ha vendido es su responsabilidad, no por eso se le debe autorizar la compra de un terminal nuevo. Por otro lado, expresa de forma exigente también la gestión de plaza en CRR a pesar de que se la transmitido en numerosas ocasiones que eso no depende de la educadora si no de la subcomisión de casos. Con respecto a las relaciones familiares, los conflictos con su hijo siguen siendo un problema para el, tiene fuerte discusiones que les llevan incluso a mostrarse agresivos según cuenta José Manuel, la semana pasado tuvieron una fuerte disputa en la llegaron a romper una puesta de la vivienda. A pesar de limitar los contactos el tutelado cada vez insiste más en sus demandas y cuando no se le responden las llamadas por cualquier motivo se muestra más exigente aún."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-06-22','Ana: Llamo a Mariví, TS de Torrejoncillo (927 30 33 66) dos veces, pero el número comunica.','2');
