insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2020-06-23','Ana: Pongo para REGISTRO DE ENTRADA la SOLICITUD DE DEPENDENCIA junto con el Anexo II (Modelo de Salud), Informe de Psiquiatría y la documentación relativa a la Incapacitación y Tutela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-23','miguel, con fecha de registro de entrada del 16-6-2020 llega la solicitud para ser firmada por el Gerente José Vicente Granados, en relación a las Diligencias previas del procedimiento abreviado 228/2019 del Jzdo de 1º instancia e instrucción nº1 de Mérida por un Delito de Abusos Sexuales, en calidad de perjuidicado. **************************************************** Una vez lo firme José Vicente lo remitiré al Colegio de Abogados de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2020-06-23','Ana: Llamo a la Residencia Balcón de Extremadura - Montánchez (927 380 516 // 603 19 44 81) Hablo con Rosana, Dir.ª, solicito presupuesto de gastos de bolsillo. Rosa dice que no es necesario, Isabel no necesita nada, en el día a día como mucho pide caramelos y cosas así. Cuando su prima le daba 10€ cuando la visitaba lo repartía entre los demás residentes, así que le pidieron que dejara de dárselo. *Lo que sí necesita es ropa. Acordamos que enviarán presupuesto al ctutelar@ y después la factura con el número de cuenta de la tienda y se le hará la transferencia directamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-06-23','Ana: Pongo para la firma del D.Gerente la Autorización para cesión de datos de Andrés desde Plena Inclusión-Cabeza del Buey a la Psicóloga Clínica de la UHDAC, Mª Paz Casado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-06-23','miguel, acudo a la vista prevista hoy en el Jzdo de lo Penal 1 de Mérida, del procedimiento abreviado 194/2019, previsto para que asista a juicio oral. El juicio queda suspendido porque no asiste y se le declarará por Auto en busca y captura, y una vez lo detengan nos avisarán porque le harán ese día el reconocimiento forense. Seguramente le trasladen a prisión, donde posteriormente llegarán a un acuerdo las partes, según me comentan en dicho Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-06-23','miguel, llama Damian para preguntar si hemos recibido un sobre que envió el 18/6/2020 con documentación. Se trata de varios documentos de la parte económica, presupuesto de dentista, etc. Se lo comento a la parte económica y lo dejo en su expte físico','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-06-22','miguel, Juan Pedro solicita de nuevo por fax y envía email para Abogacía general a través de Secretaría General y Mª Guerrero, Solicitando el testimonio de firmeza de aceptación del cargo. ************************************************ Ya ha llegado el informe de FUTUEX que tiene Pedro y me entregará para junto con el Certificado de discapacidad que ha solicitado Teresa lo podamos incorporar cuando esté todo en la Solicitud de Internamiento Involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-06-23','Ana: Llamo a Mariví, TS de Torrejoncillo (927 30 33 66) para solicitar presupuesto de gastos, el viernes ha acordado hacer visita conjunta con Virginia-Futuex y Guadalupe, T.S. del C.Salud. La Aux. de SAD se llama Pilar, cree que lo puso mal en el informe. Me informará a posteriori.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-06-23','Ana: Trato el asunto de la visita a Aitor con Pedro, Jefes de secc. CTAEX. Acordamos hacer la derivación a Futuex, para que le visiten, expliquen la situación y comiencen a hacerle seguimiento. ······························································································ Envío mail a Toni-Futuex con la derivación de Aitor, para primera visita y seguimiento. Le pido también que, a nivel educativo, intenten abordar la cuestión de las influencias negativas de otros menores del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-06-23','Ana: Envío mail a Toni-Futuex con la derivación de Catalina, para el programa de apoyo comunitario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-06-24','TERESA SE ESTABLECE PREUSPUESTO ECONOMICO, FUTUEX SE VA A ENCARGAR DE NEGOCIAR CON LAS TIENDAS PARA LIMITAR LOS GASTOS Y DOMICILIAR LOS GASTOS DEL SERVIO DE COMIDA SE ESTA GESTIONANDO LOS SEGUROS PARA DARLE DE BAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-24','Ana: Correo de Javier, Dir. CRR-Plas (direccion.crrplasencia@grupo5.net), de ayer por la noche a la secc. ecca.: "Buenas tardes en cuanto a gastos pendientes de Emilia Morales, comentaros que por un lado está la factura del taxi de Almendralejo/Plasencia, que la trajo de vuelta al CRR de Plasencia y que os adjunto, que en lo concerniente a las gafas de sol, encargadas por ella sin el consentimiento o información al CRR, además de al Comisión Tutelar, os remití dicha factura, por lo tanto el cuando al pago de dicho gasto en la óptica debeís decidirlo desde la Comisión. Actualmente no está recibiendo ninguan asignación, ya que dicha cantidad mensula fue retirada por ella misma y manejada también por ella. Desde el CRR de Plasencia, como planteamiento ante la subcomisión de casos y como pauta de futuro, entendemos (Dirección y Equipo Técnico) que es conveniente por nuestra parte una desvinculación del manejo, custodia y administración del dinero de Emila Morales, ya que interfiere en la posibilidad del abordaje de otros aspectos vitales relacionado con su proceso de rehabilitación, por lo tanto, no sólo en la cantidad económica asignada para su gasto diario, si no también en las cantidades de gastos extras, debe realizarse sin que medie ningún profesional del CRR . Está pendiente los gastos de la prótesis dental que realizo, en el período de aislamieniento y que también se saltó, no teníamos conocimento del día de la cita y de los gastos que dicha prótesis le han ocasionado. En breve se celebrará la Subcomisión de Caso solicitada por el CRR y será un espació para acordar, decidir el futuro en la intervención con Emilia Morales. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-24','Ana: Llamo a José Manuel (722 493 622), pero salta de nuevo el buzón de voz. Dejo otro mensaje. Pruebo a llamar al nº anteior (667 348 817), está apagado. ······························································· Más tarde recibo llamada de José Manuel desde un fijo (927 764 710), al preguntarle desde dónde llama, dice que desde el fijo que le han puesto en Jazztel al contratar fibra óptica con un contrato a nombre de otra persona. Añade que estás intentando cambiarlo a su nombre. Le digo que desde la CTAEX no se ha autorizado dicho contrato y no se va a abonar. Le recomiendo que intente anularlo. ··· En cuanto al teléfono móvil, dice que volvamos a llamarle al número de antes, pues ha vendido el móvil nuevo y ya no tienen esa tarjeta. Además pide que se le autorice para comprar otro terminal. Respondo que no se va a autorizar la compra de otro, pues sólo hace 2 semanas que lo compró. ··· Por otro lado, insiste en que le busquemos un centro, que no puede seguir conviviendo con su hijo pues le ocasiona muchos problemas y es muy agresivo. Según manifiesta le ha amenazado con matarlo mientras duerme. Le recuerdo que ha sido él quién ha permitido que se instale en su casa, contra la oponión de todos los profesionales que intervenimos con él. En cuanto a las amenazas, agresividad y daño en la vivienda (puerta rota) debería acudir a poner una denuncia a la comisaria. Y llamar a la policía si suceden nuevos altercados. Y por último, en cuanto al centro, le recuerdo, una vez más, que no depende de la CTAEX, seguimos a la espera de la subcomisón de gestión de casos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-24','Ana: Llamada de Clara, TS CS (927 360 769 = C.S. Logrosán): Ha intentado contactar con Juan en distintas ocasiones y en distintos horarios pero no le coge el teléfono. Tienen que pasarse a recoger el papel de la ambulancia para la cita en Salud Mental. ·········································································· Llamo a Juan (633 391 891): Intento contactar varias veces a lo largo de la mañana, pero no lo coge ninguna de la veces, salando siempre al final el buzón de voa. Le dejo dos mensajes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-06-24','Recibimos llamada de su hermano Rafael (620143379), necesita el DNI de Josefa, para presentarlo en la solicitud de la ayuda de la PAC. Esa ayuda de la PAC, es por unas ovejas que le pertenecían a su madre, fallecida a principios de año, de la que no se ha hecho la herencia. Le pedimos el teléfono de la OCA de Montehermoso (927015814)donde se gestionan estas ayudas. Hablamos con el técnico César, que nos indica que los derechos de esas ovejas, una vez fallecido el titular, que en este caso era la madre, pasan a los herederos y que para poder ser beneficiarios de estas ayudas, necesitan el requisito de ostentar la condición de ganadero. En este caso el único ganadero es Rafael, ni Josefa ni el otro hermano, son ganaderos, por lo que deben formalizar un escrito de renuncia a esos derechos por escrito, firmado por los tres. Le pedimos a César que nos remita al correo de CTAEX, la normativa que regula esos requisitos y la cuantía a la que asciende la ayuda, a los efectos de negociar la compensación de Josefa, por esa renuncia, con su hermano Rafael. El plazo para solicitar esta ayuda finaliza el 30/6. No obstante, tramitarán la solicitud con la documentación que dispongan, el resto se aportará una vez seamos requeridos para la subsanación. En cuanto a la herencia, según Rafael, consiste en una casa y estas ovejas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-06-24','Ana: Llamo al CAM Fco. Pizarro -Trujillo (927 027 600), me dicen que Esther Gil no está hoy y su compañera Gema Campañón tampoco. Le dejan nota y mi número de teléfono para que me llame cuando pueda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-06-24','Desde el área jurídica, se pone en conocimiento del área económica, anexo al contrato de arrendamiento de alquiler del piso donde reside Jesús Manuel, a los efectos de actualizar la renta, pasando de 240, a 250 euros mensuales, a partir del 30 de junio de 2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-06-24','Ana: a petición de Juana, secc. ecca., solicito a Toni-Futuex, unos datos de Ángel, marido de Desideria, que necesita el gestor para hacer la declaración de la renta de Desi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE DOLORES'and edp.apellido1='VARGAS'and apellido2='CHAVERO'),'2020-06-25','Hablamos con Antonio Naranjo (620221390), interesado en la compra de la vivienda que a día de hoy aún sigue perteneciendo a la madre de José Dolores, puesto que no se ha hecho la herencia. Nos va a enviar una propuesta con la cantidad que está dispuesto a pagar. La herencia de la madre no está hecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-06-25','Ana: Llamada de Gema, Ed. del CAM Fco. Pizarro de Trujillo (927 027 600). Le explico que para dar continuidad a la visita que se haga desde la CTAEX, para que no se produzcan tanto cambio de personas de referencia, se ha decidido derivar el caso al programa de FUTUEX, en que se le asignará una Delegada-Educadora de Refencia que será quién lo visite de forma regular. Ella le explicará todo lo relativo a la Tutela como Adulto y a la CTAEX. Desde Futuex se pondrán en contacto para acordar fecha y hora de la primera visita. ·· Gema aprovecha para transmitirme su preocupación por Aitor. LLeva trabajando más de 2 años con él e intentando que acceda a distintos recursos, pero en todos ha sido rechazado: Colegios de Educación Especial como el CEE PROA, Enseñanza Ordinaria, Talleres Ocupacionales e incluso un contrato de trabajo (subvenciones para colectivos especiales) para el que llegó incluso a realizar la entrevista. Les han cerrado las puertas en todos los sitios, o cual resulta muy frustrante para él. "Es un hijo del sistema, ha pasado practicamente toda su vida dentro del mismo en distintos programas y/o recursos residenciales y en 2 años que lleva allí, por más que lo hemos intentado aún no le han dado respuesta a sus necesidades, teníamos la esperanza de que al ser tutelado por la CTAEX la cosa cambiara y pudiera acceder pronto a otro centro donde poder cubrir necesidades y sus demandas con Centro Ocupacional o algo que dé sentido a su vida". "En Trujillo se relaciona en un entorno negativo para él, como es normal quiere hacer cosas de su edad, pero se junta con jóvenes, algunos de ellos anteriores menores tutelados, que le dicen que ya es mayor de edad y puede hacer lo que quiera y le inducen a consumir y realizar otras conductas. Con el consumo se muestra agresivo. Es muy influenciable y manipulable y nos preoupa que después de 2 años preparándolo para la salida del centro se pierda". "Sería fundamental encontrar un recurso nuevo en que reconducir el caso". "Es un chico que por sus antecentes (CMMJ Marcelo Nessi) y su aspecto daba miedo a muchos profesionales y en ningún sitio le han aceptado, pero es un buen niño si mantienen relaciones adecuadas." Se aprecia que Gema está muy implicada con el joven y que han trabajado mucho por buscarles recursos adecuados y ya se ve sin respuestas para darle. ····················································································· Volveré a hablar con la secc. correspondiente en relación a los recuros y lista de espera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-25','Ana: Tienen lugar la subcomisión sociosanitaria de Gestión de Casos. Propuesta final: Canalización de Emi a Centro especializado en Trastorno de Personalidad en Málaga. *No hay acuerdo en segundas opciones por si esta solicitud fuera rechazada. También hay que plantearle a Emi este traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-06-24','Ana: Recibo llamada de Mª Isabel, hermana de Pilar (695 967 774). Pregunta por su hermana, quiere saber cómo está y cómo se encuentra. Le informo que está muy bien, en un centro residencial de Zafra totalmente adaptada, bien cuidada, sin alteraciones de conducta y participando en las actividades del centro. ·· Se alegra de saberlo y quiere saber si es posible ir a visitarla. Le indico que, dada las circustancias por la crisis sanitarias, aunque haya finalizado el Estado de Alarma, lo mejor es eperar. Podrá pedir al centro cita para ir a visitarla más adelante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-06-26','Ana: Llamo a Piedad, de la Mancomunidad de Trasirra (670 29 30 45), salta el buzón de voz ("está lleno"). No es el primer día que lo intento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-06-26','TERESA:no va a renunciar a la plaza, va a solicitar ausencia voluntaria de 15 días. Se va a ir en autobús. Con la madre no conseguimos hablar, pero dice José Florenico que no va a tener problemas en ir a su casa, que su madre lo acoge. Se le va a autorizar por el centro las vacaciones y con un compromiso informado según resoluciónde 20 de junio (regreso con pcr negativa que él debe gestionar y evitar contacto 7 días con resto de usuarios a su regreso, etc)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-06-26','TERESA: CONVERSACION TELEFONICA CON ANA EUDUCADORA PI NATALIA DESDE QUE INGRESO NO SABE NADA DE SU ABUELA, LA ABUELA HA CAMBIADO DE TELEFONO, EL DIA DE SU CUMPLEAÑOS LA ABUELA SE LIMITO A MANDAR UN MENSAGE A UN MONITOR PARA QUE SE LO HICIERA LLEGAR A NATALIA NATALIA AHORA COMENTA QUE SU ABUELA LE TRATA MAL NO LE CUIDA BIEN Y LE PIDE DINERO EL ABUELO JOAQUIN AHORA HA EMPEZADO A LLAMAR A NATALIA, ANTES NUNCA LO HABIA HEHCO Y NO SABEN SI A TRAVES DE EL HABLA CON LA MADRE NATALIA AFIRMA QUE SOLO QUIERE A SU MADRE QUE NO QUIERE SABER NADA DE NADIE MAS EN EL CENTRO SIGUE CON LAS AMANEZAS Y ROBANDO LE COMENTO A ANA QUE VALOREN LA POSIBILIDAD DE CAMBIAR DE CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-06-26','TERESA ENVIO CAMBIO DE NUMERO DE CUENTA PARA COBRAR VINCULADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-06-26','Ana: Recibo llamada de Marisol (660 802 605 // 645 217 324), ahijada de Jualiana Paula. Pregunta por las llaves de la casa de Juliana, en la residencia de mayores le han dicho que las llaves las tiene la CTAEX. ··· Cuando lo comprobemos se lo comunicaré. ··························································································· Tras hablarlo con Pedro, envío un correo a los Asesores Jurídicos - CTAEX: "...La ahijada, y según dice, única heredera, de Juliana Paula Centeno Rodríguez, fallecida el pasado mes de abril, pregunta si tenemos en la CTAEX las llaves de la vivienda, pues las necesita. A parte de que lo comprobaremos la semana que viene, queríamos consultaros, si en tal caso, además de que nos envíe documento acreditativo de ser la única heredera, si sería necesario o no esperar a que la Rendición Final de cuentas esté terminada y enviada al Jdo. para entregárselas. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-06-29','TERESA ENVIO EMIAL A JUAN PEDRO APOLO JEFE SECCION DEPENDENCIA (924010131) Te expongo el caso de Paloma Rodriguez Jiménez con DNI 80057354N La última valoración que se le hizo a Paloma, tutelada por esta comisión, fue a raíz de solicitar un cambio de PIA, ya que queríamos ingresarla en el modulo familiar del Campf de Don Benito. El padre no dio perfil ya que es una persona dependiente y por lo tanto no fue aceptado para usuario del módulo familiar, mientras tanto Paloma debería haber ido al CADEX para valorar su perfil, el cual aún no se ha valorado porque no ha asistido cuando la han citado por lo tanto sigue pendiente el cambio de PIA para módulo familiar. Te comento estos antecedentes porque ahora mismo tenemos pedido ingreso involuntario para Paloma y necesitamos centro residencial, está pendiente de cita en CADEX, pero claro este cita la origino el cambio de PIA para módulo familiar, el cual hoy por hoy ya no nos vale. Mi duda es, ¿tengo que volver a pedir un cambio de PIA para solicitar recurso residencial para que valoren el perfil de residencia y así poder acceder al recurso?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-06-29','Ana: Llamo a Piedad, de la Mancomunidad de Trasierra (670 29 30 45), en relación a los correos y escritos recibidos, confirma que son 2 cosas distintas. Por un lado se ha realizado ya la limpieza del solar, por riesgo de incendios. Enviarán la factura y el nº de cuenta al ctutelar@ para que se realice la correspondiente transferencia (no recuerda exactamente la cuantía, en torno a 400 €). Por otra parte, debido al Síndrome de Diógenes que padece Nemesia, y a pesar de residir en los PPTT, la casa está llena de objetos y basura, pues acude con frecuencia a su casa. Numerosos gatos entran por un hueco en una ventana y campan a sus anchas, con las consecuentes quejas de los vecinos por riesgo de infección, etc. Me enviará a mi email un informe y fotos de la situación de la vivienda. Y cuanto le confirme el Alcalde qué empresa realizará la limpieza, nos remitirán presupuesto al ctutelar. *Requerirán que le envíen, al menos mediante email, AUTORIZACIÓN del gasto y de la entrada en el domicilio para realizar la limpieza. ······························································ Al final de la mañana recibo correo con Informe Médico, Informe de la Trabajadora Social, así como fotografías de la vivienda. **Se hace imprescindible realizar limpieza en el domicilio, sin gran demora, debido al riesgo de infecciones así como de incendios. ·························································· Envío correo a la secc. ecca.: "...En relación a Nemesia García Paniagua, una vez leído los informes y visto las fotos que también ha remitido (está guardado todo en su expediente) decir que la limpieza en el solar era necesaria. Del mismo modo, es imprescindible realizar la limpieza en el domicilio, para la que remitirán presupuesto y solicitan autorización. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-06-29','Ana: Llamada de Clara, TS CS (927 360 769 = C.S. Logrosán): Juan acudió a recoger el volante de la ambulancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2020-06-29','Ana: Correo de Maribel, TS de la R.M. Ciudad Jardín Parque del Príncipe (trabajosocial@grupociudadjardin.com) a la Secc. Ecca.: "Buenos días: Hace días hablé con Ana Matamoros para informarle de que Rafael Fernández Bermejo necesitaba una silla de ruedas y me comentó que debía enviaros un correo para que lo valorarais, pues bien, os adjunto prescripción de la silla, el presupuesto y la orden de domiciliación para que me la mandéis firmada junto con la solicitud de material ortoprotésico y pueda enviarlo todo al SES. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-06-29','Ana: Ángel, asesor jurídico CTAEX, me comunica que ha llamado al hermano de Ceferino, éste le ha dicho que no ha alquilado el piso, que quién haya dicho eso miente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-06-29','miguel, asisto a la vista para proceder a la división de herencia 484/2019. No hay acuerdo en la fomación de inventario. Se aplaza la vista y nos citarán de nuevo para juicio verbal para aclarar la formación de inventario del padre y la madre. ****************************************** Nuestra abogada Maria José Martin Moreno (Tlfno 666-753922 e email mmartinmoreno@icac.es me enviará por email toda la documentación de testamento, escrituras, etc. ****************************************************** El inventario esta formado por la vivienda de los padres ganancial según nuestra abogada y que queda justificado por escrituras de compraventa, y nota simple, y donde nuestra abogada para justificarlo pedirá certificado del callejero de Coria(Francisco (el hno demandante) dice que es privativo no ganancial) El derecho de habitación es de nuestro tutelado. Hay en inventario otros dos bienes: 1.-un almacén 2.-una rústica (legada a nuestro tutelado)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2020-06-29','miguel, llega del Jzdo de 1º instancia e instruccción nº2 de Arganda del Rey citación 15-10-2020 a 10:30h. *********************************************** Hablar con el Jzdo para videoconferencia y que nombren abogado de oficio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-29','miguel, firmado la solicitud de abogado de oficio que han remitido desde el Colegio de Abogados de Badajoz, lo remitimos ya firmado a dicho colegio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2020-06-29','TERESA: emiail feafes Información situacional de Fco. Javier Fraile Salamanca: Buenas tardes, el pasado miércoles 24 de Junio hubo que realizar una salida de contención a Fco. Javier Fraile Salamanca, ya que, se encontraba desbordado y amenezante con salir del recurso, pedía salida a visitar a su familia. Se valoró con la familia la posibilidad de salida en vista de la situación de alteración e incontrolabilidad que presentaba y como medida de contención. La familia aseguró y se comprometió a realizar una salida que garantizara su seguridad y medidas de higienes en todo momento. Se acordó una salida a una segunda residencia que disponen a las afueras de la población de Almendralejo, donde se encuentran aislados desde antes de la declaración del estado de alarma . Además, se acordó que a su regreso estaría en aislamiento total durante una semana, tomando todas las precauciones posibles. La salida se realizó de forma correcta durante un periodo de 30 horas. Continúa en aislamiento por prevención. Su situación sintomática referida a su trastorno y a la alteración de conducta es mucho más favorable y se encuentra más estabilizado. Por otra parte, Javier pide la revisión de cuentas para poder comprar un ordenador "bueno", ya que, el que tiene actualmente lo ha llevado a reparar y le han dicho que debido a los años que tiene y problemática que presenta, no podrá funcionar adecuadamente y actualmente va a realizar una formación en idiomas (Inglés) en formato on-line, durante el próximo año, son varios módulos, va a comenzar con el nivel básico y necesitará de un ordenador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-30','Ana: Llamada de José Manuel (722 493 622): El jueves a las 13:40 tiene cita para renovar el DNI. A parte, dice que el día 2 se cancelará el contrato de fibra óptica... ········································ Envío correo a la secc. ecca. pidiendo que le autoricen para ese mismo día un reintegro de 12€ para abonar las tasas y a ser posible 3€ más para el autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-06-26','Ana: Llamada de José Manuel a Pedro, Jefe secc. CTAEX; el contenido de la converesación similar al de otras conversaciones. Además insiste en que se autorice la compra de un móvil nuevo. Pedro le repite varias veces que no, que no hubiera vendido el último que compró hace 2 semanas.','2');
