insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='FERNANDEZ'and apellido2='CALDERON'),'2020-06-30','TERESA ENVIO DOCUMMENTACION PARA SUBVENCION SILLA DE RUEDAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2020-06-30','-Amalia: Información de su casa de Santa Ana facilitada por Ángel: Buenos días, compis, Revisada la documentación de este expediente y solicitada Nota Simple al Registro de la Propiedad, aparece esta finca a nombre de María Josefa Zancada Mena e Indalecio Rivera Ruíz, como usufructuarios al 100%. Estos ya fallecieron y se hizo la aceptación de la herencia en escritura que tenemos en la oficina, pero no se inscribió la herencia en el Registro de la Propiedad, ni en el Catastro, por eso siguen apareciendo como titulares. Rosa aparece en esa Nota Simple con el 100% de la nuda propiedad. A efectos prácticos, Rosa es la dueña de esa casa, con el pleno dominio, puesto que los usufructuarios testaron en su favor. De hecho, ya hemos intervenido en otros arreglos de esa casa. Así que Amalia, como decías, solicita presupuestos para arreglar los desperfectos del tejado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2020-06-16','-Amalia : desde el Ayuntamiento de Santa Ana , nos ha llegado un requerimiento solicitando el arreglo del tejado de su casa. Las llaves las tiene su hija Iris en Madrid, quedo con ella en que vendrá este fin de semana y las traerá . Le pido que las haga llegar al SSASB . Pedirá presupuestos a un albañil sobre el arreglo y me lo enviará . Solicito a la parte jurídica confirmación sobre la propiedad de la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2020-06-29','-Pedro acudió ayer a los Juzgados de Mérida para informarse sobre una comparecencia que tiene pendiente. Rubén se encuentra actualmente en la URH del CSS de Mérida , pasó de UHB a UME y de ahí a la URH desde marzo o abril . NO lo comunicaron desde el centro Del fallo judicial se desprende que cumplirá condena en el centro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-06-26','-Amalia: vuelve a ingresar en centro penitenciario de Badajoz. Solicito cuenta peculio.','2');
