insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2020-06-30','-Amalia : llama Mª José de Caser Olivenza, ha conseguido que el banco le cambie los billetes que habían quedado descoloridos , menos 50€ que estaban rotos . Ha Tomás le robó 70€ y le devolvío 50€ que Tomás entregó a Mª JOsé, le debería 20. Como no han presentado denuncia no se les puede devolver ese dinero.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2020-06-30','-Amalia : llama Mª José de Caser Olivenza, ha conseguido que el banco le cambie los billetes que habían quedado descoloridos , menos 50€ que estaban rotos . Ha Tomás le robó 70€ y le devolvío 50€ que Tomás entregó a Mª JOsé, le debería 20. Como no han presentado denuncia no se les puede devolver ese dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GRANADA'and edp.apellido1='CANO'and apellido2='MARQUEZ'),'2020-06-29','-Amalia : recibo llamada de Maribel del SSASB , el viernes aceptó ir a los Pisos tutelados de LLerena con la colaboración de las Sñas. de Cáritas. Por la tarde se puso enferma , según refiere Maribel creen que puede consumir alcohol y tuvo síndrome de abstinencia y la derivaron al hospital. Quieren que al alta hospitalaria vuelva a los pisos pero si no es voluntariamente no será posible. Vuelvo a explicarle que la CTAEX no tiene capacidad jurídica para hacerlo , es curatela económica. Ya se le ha dicho que la pensión la percibirá en dos veces, quincenalmente , salvo que ingrese en Pisos y se hará nuevo pto. cubriendo el copago de la plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-06-30','Ana: Llamo a Marisol, ahijada de Juliana Paula (660 802 605); le confirmo que las llaves de la vivienda de Juliana están en la CTAEX. Le informo además, que para poder entregárselas tendrá que acreditar documentalmente, que es la única heredera y que ha aceptado la herencia (Escrituras de Notaría que lo acredite). Así mismo, cuando acuda, que nos llamará previamente, se firmará por ambas partes un documento de entrega.','2');
