insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-06-30','TERESA HABLO CON CILA DEL CEDEX DE CASTUERA (924 76 00 00), ME COMENTA QUE ELOS YA HAN MANDADO TODA LA DOCUMENTACION AL SOCIO DE PLANSENCIA HABLO CON MARIVI TS CSS PLASENCIA (927 428 800/ 24142) ME COMENTA QUE GUILLERMO ESTA EL CUARTO EN LA LISTA DE ESPERA QUE PREVEE SU INGRESO PARA FIANLES DE MES AL COMENTARLE QUE ES UN INGRESO INVOLUNTARIO ME DICE QUE ELLOS ALLI NO TIENEN NINGUNA MEDIDA DE CONTENCION Y QUE ES UN CENTRO ABIERTO EN EL CUAL LOS PACIENTES ENTRAN DE FORMA VOLUNTARIA Y SALEN DE FORMAR VOLUNTARI LE INDICO QUE SI SE ESCAPA DEL CENTRO AVISEN A LA GUARDIA CIVIL YA QUE HAY UNA ORDEN JUDICIAL DE INGRESO INVOLUNTARIO CUANDO HAYA PLAZA LO COMUNICARAN AL CEDEX Y EL CEDEX A NOSOTROS PARA QUE AVISEMOS A LA POLICIA LOCAL QUE TIENE SUS PERTENENCIAS Y LA LUSIA LA TS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-06-30','Ana: Llamada de Emi (633 501 059); "...no puedo seguir más tiempo aquí", "me quiero ir a Mérida, pero si alquilo un piso con lo que cobro no me da...", "haz que me cambien al CRR de Mérida", "no me encuentro bien, yo no estoy bien". En cuanto al recursos, le recuerdo que no depende de mí, que debe tener paciencia, que ya le darán una respuesta desde el CRR. Y en cuanto a su malestar, le indico que debe hablarlo con las especialistas, tanto con la psicóloga del CRR como con su Psiquiatra del Equipo de Salud Mental. Afirma que así lo hará. ····· Por otra parte, dice que le jueves tiene cita en la clínica dental, se le ha caído un trozo de esmalte de los dientes nuevos que ya están pagados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='RUBIO'and apellido2='BRAVO'),'2020-06-24','EXITUS El Jzdo. n.º 3 de Plasencia comunica, mediante Providencia de 24/06/2020, el fallecimiento de Dña. Jacinta.****El óbito se produjo, efectivamente, el 20/06/2020.','2');
