insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-07-01','Ana: Llamada de Antonio García, Presidente de la A.J.E.R. (Asociación de Jugadores en Rehabilitación // 618 908 506). Mª Eugenia ya no asiste, pero se le sigue pasando la cuota mensual. ······························· Envío correo a la secc. ecca.: "... En relación a Mª Eugenia Pacheco Vicente, comentaros que me ha llamado Antonio García, Presidente de la Asociación de Jugadores en Rehabilitación “Virgen del Puerto”, comunicando que Mª Eugenia ya hace unos meses que no acude a la Asociación pero se le sigue pasando la cuota (está domiciliada). Tienen por norma no dejar de pasarla hasta que la persona acude a comunicar la baja, pero dado el caso que es, han tenido a bien comunicárnoslo. (Yo desconocía que se pagaba una cuota). Por tanto, cuanto os sea posible, por favor, dar de baja la domiciliación bancaria para que no siga pagando la cuota mensual. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-01','Ana: Llamada de José Manuel (722 493 622): Icíar le dijo ayer que no le van a dar el dinero para las tasas de la renovación del DNI (Decisión del Jefe de la Secc. Ecca.) ·············· Llamo a Icíar que me corrobora esta información. ····························· Llamo a Pedro, Jefe secc. CTAEX, hablará con Alberto. Dentro de 15 días José Manuel tiene un juicio y debe ir provisto de DNI en vigor. ··················································· Recibo otras 2 llamadas de José Manuel; a parte de reiterar lo del dinero, a lo que respondo que cuando tenga respuesta de los jefes le diré algo. ·· Por otra parte, expresa que tienen un problema, ha hablado con Rosa, Admvo. del CSS del CSS-Plas. en relación al los juicios que tiene este mes (16 y 21 de julio). Le ha comentado que es posible que tenga que cumplir medida en el CSS de Mérida o en Prisión y dice que él no quiere ir a ninguno de los dos sitios. Que con su discapacidad él no debería ir a prisión y que a él le corresponde el CSS de Plas. ···················································· Envío correo a Toni-Futuex: "... En relación a José Manuel Romero Mediavilla, ayer le dijeron que no le iban a autorizar más reintegros, ni siquiera para las tasas del DNI. Me ha extrañado, tras llamar a Icíar, he hablado con Pedro y éste después con Alberto. La decisión tomada es que NO se le va a dar más. Su hermano le da todos los meses en torno a 300€ (hoy precisamente se lo ha manifestado éste a Pedro en conversación telefónica). Si se abonan las facturas correspondientes, se le tiene contratado y se abona el cáterin y se le ha autorizado para comprar ropa, teléfono y lavadora, tiene cubierta las necesidades básicas, por tanto con los reintegros semanales debería tener para gastos de bolsillo. Si además el hermano le facilita todo ese dinero, en teoría también tiene para pagar las tasas del DNI mañana. ¿Podría transmitírselo Virginia? ¿Y, en su caso, confirmarme si Virginia le va a acompañar mañana a Comisaría?. Comentarte también que, como he hablado con Pedro, a partir de ahora voy a intentar desvincularme yo un poco (especialmente de las cuestiones económicas), en el sentido de que si llama a Virginia todos los días, me llama a mí también varias veces todos los días, llama también a Icíar y a las 3 nos dice lo mismo… pues las cuestiones económicas a la secc. correspondiente, como además se ha dado la orden hace unas semanas. Y lo que necesite, a Virginia, para que nos hagáis las comunicaciones oportunas como venís haciendo hasta ahora. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-01','(Pedro)Correo-e de SSB de Llerena. +++Os informo que según me traslada la persona de Cáritas de Llerena, CARMEN RUBIANO NAVAS consume en la actualidad vino. El pasado viernes le visitamos en el domicilio, Susana de Futuex, la persona de contacto de Cáritas y yo, y acordamos con ella, que cada vez que encargara vino a las auxiliares, le iban a llevar coca cola, que es su segunda bebida preferida. Quedó conforme. Se le trasladó la información a la tienda donde regularmente compra las cajas de vino y se informó a las auxiliares. Pero a fecha de hoy la información es que sigue consumiendo incluso que ha ido a la tienda por vino y al negarse la tendera, las ha cogido M. Carmen con una actitud agresiva. Las auxiliares de SAD serán avisadas que a la mínima que la encuentren agresiva llamen al 112 o a la PM para que activen el protocolo. También he informado a la trabajadora social del Centro de Salud, con quien me coordino al respecto, a los efectos que de traslado de la información al equipo de salud mental que trata a Carmen. En la última visita se encuentra razonable, y tranquila, dentro de su patología. FDO: María Isabel Macías Calvo,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-07-01','EXITUS Acaecido el 01/07/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-07-01','TERESA ENVIO SOLICITUD DE RESIDDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2020-07-01','miguel, a petición de Alberto y Belén, envío email al administrador del señorio de montanera para que fije fecha de firma y para que emitan a efectos de la declaración del IRPF del año que viene un de certificado con precio de compra y venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-02','Ana: Llamada de José Manuel, dice que ya ha hablado con Pedro, le digo que entonces no hace falta que me llame a mí. Pero añade que se le ha olvidado "decirle lo más importante", que quiere dejar de pasarle la manuntención a sus hijos. *Le recuerdo que los compañeros jurídicos ya están en ello y que ya han hecho las reclamaciones oportunas al Colegio de Abogados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-06-25','(Pedro) Correo del CRR de Mérida (25-06-2020). +++Ángel Pinilla: En la misma línea que días atrás, estamos haciendo todos un esfuerzo importante para evitar que pase gran parte del día en la cama. Sigue saliendo a dar un paseo y relacionándose con sus compañeros. Sus quejas por el dolor de espalda siguen...como sucede habitualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-06-25','(Pedro) Correo del CRR de Mérida (25-06-2020). +++Como os comentamos, a principios de este mes se hizo un cambio de pauta y a la vista de que su situación no mejoraba, intentamos adelantar la cita con Psiquiatra de referencia y aunque fue posible, la fecha que nos dieron fue el 6 de Julio. Fue acompañado por un compañero al centro de salud para realizarse analítica de control y se marchó sin realizarse la analítica, volviendo al centro posteriormente (haciendo caso omiso a las pautas que desde el CRR se dan). Fuimos con él al Hospital y ha habido un cambio de medicación, informándole el Psiquiatra que le atendió que de no mejorar, el lunes se producirá el ingreso. Os vamos informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-06-25','(Pedro) Correo del CRR de Mérida (25-06-2020). +++Menos demandante con el tema de la vivienda que la semana pasada. Una compañera del centro le increpó ayer pero estamos desde entonces tratando el tema, ella muy adecuada en la gestión del conflicto. Esta mañana ha salido a dar un paseo, muy arregladita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-06-25','(Pedro) Correo del CRR de Mérida (25-06-2020). +++José María Guillén: En la misma línea que semanas atrás, quizá un poco más irascible que de costumbre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-06-25','(Pedro) Correo del CRR de Mérida (25-06-2020). +++Luisa Rodríguez: Bien, de buen humor y saliendo con compañeros. Ayer acudió a taller, aunque con reticencias, no costó mucho convencerla como suele pasar habitualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2020-07-02','TERESA MANDO EMAIL AL CENTRO PARA PREGUNTAR POR COMO VA EL TEMA DE TRASLADO DE CENTRO Buenos días Teresa, el tema de M. Dolores lo tengo que tratar con el resto del equipo, sobre todo la psicóloga para hacer una valoración de su estado actual y os informamos, el tema de la cita con salud mental va lento, nos han dicho que nos avisaran pero que si no es urgente tardarán unos meses... En cuanto nos reunamos el equipo para tratar este tema te informo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-02','TERESA: EMAIL FUTUEX Visita realizada desde el Equipo de Apoyo Social Comunitario el pasado 26 de Junio de 2020 en Zalamea de la Serena por las trabajadoras del programa, con el objetivo de dar respuesta a las necesidades de los tutelados Pablo Galán Gilgado y Guillermo Galán Gilgado. Las gestiones se llevan a cabo con el apoyo y la intermediación de la Policía Local (José y Alfonso). Al final todo lo que se propuso se va a poder hacer con la colobaración de los establecimientos por transferencia, salvo el tema de la bombona que por ahora no acceden al pago por transferencia, seguiremos intentandolo y si no como ultima opción, se puede poner una retirada en los primeros 10 dias del mes miniina (20 euros por ejemplo) para las compañeras acudan al banco con ellos se retire esa cantidad y se compre la bombana o cualquier otro pequeño bien, que no se hubiera cubierto con las transferencias, en el caso que lo valoreis seria siempre para retirarlo en compañia de una de las compañeras para asegurarnos que esa cantidad se destine a algo necesario que no hubiera quedado cubierto o alguna eventualidad, y no a alcohol.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-02','TERESA: EMAIL FUTUEX Visita realizada desde el Equipo de Apoyo Social Comunitario el pasado 26 de Junio de 2020 en Zalamea de la Serena por las trabajadoras del programa, con el objetivo de dar respuesta a las necesidades de los tutelados Pablo Galán Gilgado y Guillermo Galán Gilgado. Las gestiones se llevan a cabo con el apoyo y la intermediación de la Policía Local (José y Alfonso). Al final todo lo que se propuso se va a poder hacer con la colobaración de los establecimientos por transferencia, salvo el tema de la bombona que por ahora no acceden al pago por transferencia, seguiremos intentandolo y si no como ultima opción, se puede poner una retirada en los primeros 10 dias del mes miniina (20 euros por ejemplo) para las compañeras acudan al banco con ellos se retire esa cantidad y se compre la bombana o cualquier otro pequeño bien, que no se hubiera cubierto con las transferencias, en el caso que lo valoreis seria siempre para retirarlo en compañia de una de las compañeras para asegurarnos que esa cantidad se destine a algo necesario que no hubiera quedado cubierto o alguna eventualidad, y no a alcohol.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-02','TERESA EVIO SOLICITUD PARA CENTRO DE DISCPACIDAD PARA VALORAR PEFIL CEDEX, ME LLAMA MARIBEL PARA INICARME QUE FALTA DOCUENTACION Y QEU CON LA PATOLOGIA QUE TIENE DE CONUSMO DE ALCOHOL NO VA A DAR PERFIL PARA CENTRO AUN ASILO VA A ENVIAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-07-02','Ana: Llamada de Chus, Dir.ª de los PP.TT. de Miajadas (638 499 546), Esteve sigue ingresado en la UHB del San Pedro de CC. Por tanto no esta acudiendo de momento al C.O. *Quién hace el seguimiento en el hptal. es Gloria-Futuex. **Le han quitado toda la medicación, pues después de tanto tiempo consideran que los últimos delirios se debía a ello. Tendrán que prescribirles otras y regulárselas, pero de momento le van a dejar sin medicación una temporada. **Continúa sin fumar, desde que le ingresaron, esperan que pueda mantenerse sin hacerlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-07-02','Acudimos al Juzgado de Primera Instancia e Instrucción, nº 3, de Mérida, DPA 132/2020, hoy estaba citado Pedro Tomás, junto con su pareja. Hemos entrado en sala, le han tomado declaración a él y a su pareja. A la parte demandada la citarán otro día. Comunicamos a la secretaría del Juzgado que las notificaciones relacionadas con este proceso, nos las notifiquen a la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-01','TERESA Os informo que según me traslada la persona de Cáritas de Llerena, CARMEN RUBIANO NAVAS consume en la actualidad vino. El pasado viernes le visitamos en el domicilio, Susana de Futuex, la persona de contacto de Cáritas y yo, y acordamos con ella, que cada vez que encargara vino a las auxiliares, le iban a llevar coca cola, que es su segunda bebida preferida. Quedó conforme. Se le trasladó la información a la tienda donde regularmente compra las cajas de vino y se informó a las auxiliares. Pero a fecha de hoy la información es que sigue consumiendo incluso que ha ido a la tienda por vino y al negarse la tendera, las ha cogido M. Carmen con una actitud agresiva. Las auxiliares de SAD serán avisadas que a la mínima que la encuentren agresiva llamen al 112 o a la PM para que activen el protocolo. También he informado a la trabajadora social del Centro de Salud, con quien me coordino al respecto, a los efectos que de traslado de la información al equipo de salud mental que trata a Carmen. En la última visita se encuentra razonable, y tranquila, dentro de su patología','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-03','TERESA HABLO CON TONI TS DEL CENTRO DE SALUD PARA QUE SOLICTE INFORME MEDICO PARA ACOMPA A LA SOCILICITUD DE RECURSO DE DISCAPACIDAD, QUEDA PENDIENTE ENVIARMELO POR FAX ME COMENTA QUE HA ESTADO VALORANDO PERDIR DEPENDENCIA PERO QEU EL INDICE DE BURTHEL LE DA MUY BAJA PUENTUACION Y NO VA A DAR GRADO CON LO CUAL NO LA VAMOS A TRAMITAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-03','TERESA HABLO CON TONI TS DEL CENRO DE SALUD Y ME COMENTA QUE NO VA A DAR GRADO YA QUE ES TOTALMENTE INDEPENDIENTE CON LO CUAL NO VAMOS A SOLICITAR DEPENDENCIA, QUEDAMOS A LA ESPERA QUE LE DEN PLAZA EN EL SOCIO DE PLASENCIA EN LA UNIDAD DE ALCOHOLICOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='RODRIGUEZ'and apellido2='MARTIN'),'2020-07-02','Ana: A petición de Juana, secc. ecca., pongo para REGISTRO DE ENTRADA, Comunicación al INSS para cambio de nº de cuenta bancaria, tanto para la PFHC como para la Orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2020-07-03','Ana: Llamada de Longina, TS del SSAB (672 614 686 = nº persona), Ana Priscila ha acudido hoy a la cita fitjada en su despacho, previa llamada para recordárselo y convencerla. Ha acudido acompañada de su pareja, pero éste luego se ha quedado fuera esperándola. *Sigue sin aceptar el hecho de estar tutelada y dice que en ella "no manda nadie". *Su pareja ha preguntado que, si cuando se vayan a vivir juntos, Ana tiene que seguir acudiendo al despacho de la TS... ····················· Longina enviará el Informe Soc. para la Rendición Anual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2020-07-03','miguel, llamo por teléfono a señorío de montanera y dejo el recado de que el administrador me responda al email que le remití hace dos dias para la venta de participaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-03','Ana: Llamada de José Manuel (722 493 622), con el mismo contenido que en otras ocasiones; se quiere ir a un CRR, quiere dejar de pasar la manutención a sus hijos, quién le va a acompañar a los juicios, que son delitos delitos leves, que necesita que se le de dinero para el bonobús porque no puede caminar ya que hace 4 años se rompión el menisco... ············································· Tras hablar con Pedro, Jefe Secc. CTAEX, a él también le ha llamado José Manuel, envío correo a Toni: "... En relación a los juicios pendientes que tiene José Manuel Romero en Plasencia, los días 16 y 21 del presente, acabo de hablar con Pedro, al parecer los compañeros jurídicos van a solicitar asistir por videoconferencia. Si se lo conceden, nos gustaría que le acompañara Virginia u otra compañera al Jdo. (sólo en calidad de acompañante), podrían quedar en el Jdo. o cerca de allí, si os parece bien. En cuanto al dinero para el autobús, según me dice, se le va a autorizar, y nos preguntamos también si sería posible que Virginia el día antes le acompañara a retirarlo del banco y a comprar el Billete de Autobús, para asegurarnos que no se lo gasta en otra cosa… "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-07-03','(Pedro) Correo del CRR de Mérida (03-07-2020). +++Ángel Pinilla: Sin incidencias destacables.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-07-03','(Pedro) Correo del CRR de Mérida (03-07-2020). +++Antonio Merchán: Mejor, más accesible, adecuado y tranquilo que en semanas anteriores por lo que no hemos vuelto al servicio de urgencias con él por el momento. Ya está saliendo de manera autónoma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-07-03','(Pedro) Correo del CRR de Mérida (03-07-2020). +++Mª Dolores Fernández: Bien, muy arregladita y pendiente de su imagen. Ayer salió a comprar zapatos y está contenta. Participó en el taller de cocina ayer y como tuvieron comida especial muy satisfecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-07-03','(Pedro) Correo del CRR de Mérida (03-07-2020). +++José María Guillén: Muy bien, recibiendo visitas familiares. De buen humor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-07-03','(Pedro) Correo del CRR de Mérida (03-07-2020). +++Luisa Rodríguez: Hace días tuvo cita telefónica con su Psiquiatra de referencia, quien tras hablar con ella y ver el resultado de la analítica reciente donde los valores están dentro de lo normal pero algo bajos, le ha subido uno de los fármacos. Ayer tuvo visita familiar y se saltó el intervalo horario acordado. Ha pasado la noche eufórica, gritando, cantando, sin atender a indicaciones de profesionales en la terraza. Hoy he hablado con ella y me ha reconocido que durante la visita bebió 4 cafés y una cerveza con limón (shandy). Aprovechando la llamada de su Psiquiatra de referencia (con otra usuaria) le he comentado lo ocurrido y me indica que ante el cambio tan reciente, esperemos un poco su evolución estos días antes de acudir a urgencias. Esta mañana ha limpiado su habitación, se ha responsabilizado de su cita médica (MAP) por un bultito en un dedo de la mano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2020-07-02','Ana: Nota del Toni-Futuex (areasocial3@futuex.es) a la secc. ecca. adjuna en email: "01/07/2020 Solicitud de extra para viaje: La tutelada consulta si puede retirar parte de su paga extra, como viene haciendo de costumbre cada vez que la cobra, para realizar un viaje. Cuando lo comunicó por primera vez, se le propuso ver el viaje en conjunto, solicitar presupuestos para poder enviar algo creíble y factible, en lugar de pedir por pedir, accede a ello y así se ha hecho. Se ha solicitado presupuesto a la pensión en donde se hospedará en la localidad donde reside su padre, Segura de Toro, así como el desplazamiento hasta allí, lo único que no se ha conseguido es el recibo del taxi para desplazarse desde Aldeanueva del Camino, donde la deja el autobús, hasta la población, deberá entregarlo a la vuelta, en caso de que se le conceda dicho extra, se le indica y acepta. Los gastos son los siguientes (se adjunta documentación con presupuestos): • Alojamiento…………………….27´27€/día………x10 días + IVA……………………………………………299,97€ • Autobús ida y vuelta (Cáceres-Aldeanueva del Camino)…..9€/viaje………………………………18€ • Taxi…………………………………………………………………………10€/viaje………………………………………20€ • Manutención durante la estancia…………………………………………………………………………………100€ TOTAL……………………………………………………………………………………………………………………..437,97€ Se le dice que el presupuesto se enviará a la CTAEX para su valoración, pero lo mejor es que piense que debe pasar menos días, pues el presupuesto es alto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2020-07-03','Ana: Correo-respuesta de Juana, secc. ecca. CTAEX, a Toni-Futuex: "Con respecto al presupuesto de Aida Martín de Piñol, comentar que se le van a autorizar 300 euros, el resto si finalmente quiere permanecer 10 días en Segura de Toro, tendrá que pagarlo de su asignación. Así se lo hemos trasladado a ella. Rogamos por otro lado, podáis concertar una cita con el banco y posteriormente nos comuniquéis fecha y oficina para enviar el escrito de autorización."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-07-06','TERESA: EMAIL TONI GALAN José Florencio, actualmente está disfrutando de 15 días de vacaciones, anuncia que mañan martes irá al servicio RAL Francisco de Asuar a por las cosas que le quedan por recoger y firmará la baja voluntaria. La directora se pone en contacto con la madre para decirle si ella le permite ir a su domicilio y en caso contrario si no tiene donde ir se comunicaría Fiscalía. La madre es contradictoria dice que "cómo no le va a permitir quedarse en su casa", pero que le obliguen a quedarse en residencia. Por otra parte José Florencio me acaba de llamar y me dice que renuncia a la plaza en residencia y ha buscado un piso en Olivenza por 200 y algo de euros y la comisión "se lo va a pagar" y que va a pedir plaza en PI OLivenza Aprosuba14. Quedo en informar a Rosa al final de la mañana si hay novedades y sino mañana que firme José Florencio la baja en el servio. Retenerlo es muy difícil y su comportamiento es cíclico y previsible. EL teléfono de la madre no estaba operativo porque José F. le había dicho que le había dado de baja, pero no era cierto lo tenía él apagado, impidiendo así la comunicación con la madre. Hoy lo tiene disponible la madre por si se necesita hablar con ella. RESPUEESTA PEDRO La Comisión Tutelar es Curadora de D. José Florencio solamente en el ámbito económico. Desde este punto de vista nada podemos hacer si quiere pedir la el alta voluntaria como lo ha hecho en otras ocasiones. Pero también es cierto que su comportamiento en cuanto a la aceptación de un centro residencial es cíclico, por lo es posible que de aquí a un tiempo quiera volver al mismo o a cualquier otro. Una posibilidad es tratar de convencerle de que no pida el alta a cambio de que pueda hacer salidas más frecuentes a su casa, pero programadas con la Dirección del Centro. En caso de que pidiera el alta, mantener la plaza todo el tiempo que sea posible (45 días?) por si cambiase de parecer. Además, ahora mismo se arriesga a no poder volver aunque quiera dada la situación sanitaria en la que nos encontramos. Creo que la opción más adecuada es la primera, combinar casa y Centro…pero requiere de su aceptación. Si no es así, no podemos hacer nada más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-07-06','miguel, acudo a SCACE para videoconferencia de Diligencias previas DPA DIL. PREVIAS PROC ABREVIADO 498/2019, del Jzdo nº4 de Plasencia. Me confirma la juez una vez concluida la vista que han solicitado al CSS concreten los daños materiales ocasionados, una vez lo cual nos citarán para juicio y en la resolución seguramente dicten sentencia para continúe en CSS debido a su enfermedad (aunque el tutelado quiere ir a la carcel)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='GARCIA'and apellido2='PESSINI'),'2020-07-06','Teresa email de Julio, he aceptado el cargo de administrador de bienes de Dña. María Teresa García Pessini. El Auto habla de su internamiento. Reside en el “El Cuartillo” del Casar de Cáceres. En principio, tú ya no necesitas hacer nada más. El resto es para la sección económica. Recuerda que la administración de bienes es una defensa judicial. Por tanto, no debemos hacer nada que el juez no ordene expresamente. Este es el caso, pero ya está cumplida la orden. MANDO EMAIL AL CUARTILLO PARA INFORMARLES SOBRE LA DFESNSA JUDICIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-06','miguel, quedamos a la espera de la firmeza para la autorización para internamiento involutario (que la recibimos aproximadamente el 30-6-2020) con lo cual al caber recurso de apelación no habrá firmeza de la resolución hasta aproximadamente el 28-7-2020','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-06','miguel, llamo al Juzgado nº1 de Plasencia, a quienes comento que no nos han enviado citación de ninguno de los dos juicios. Me informan que el procedimiento del día 16 (DPA 351/2019)es un juicio rápido (porque en su declaración ya aceptó los cargos por quemar el colchon, por lo que ahora únicamente dictarán sentencia) al que tenemos que asistir presencialmente. Pediré coche a Pedro Js. ***************************************************** En cuanto al juicio del día 21 DELITOS LEVES 61/20 pido por fax nuestra asistencia a través de los juzgados de Mérida. Explico al juzgado que no podemos garantizar la asistencia del tutelado, y ante la pregunta de donde vive actualmente les comento que en Cáceres ciudad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2020-07-02','Correo de Toni-Futuex a la secc. ecca.: "01/07/2020 Asunto retirada de asignación: Desde el día 18 de junio se hacen gestiones con Liberbank, averiguando si su sucursal ya está abierta e intentando contactar con la oficina central, C/ San Pedro, donde le corresponde realizar la retirada. Sin éxito un día tras otro y con intentos reiterados…, el 22 de junio,se contacta con otra de las oficinas para consultar algún número de teléfono más a través del cual poder intentar contactar, facilitan dos más, pero tampoco… Finalmente el día 25 responden, indican que no hay cita libre hasta el día 6 de julio, se le explica lo ocurrido, pues se lleva una semana llamando sin conseguir contactar y la problemática existente con las fechas de las autorizaciones para la retirada; comenta que lo sienten, pero tienen mucho volumen de trabajo debido a continuar cerradas varias oficinas, por lo que se han marcado un número de atención al público y no atienden más clientes… se le solicita por favor, haciendo alusión a la necesidad de los tutelados y a los inconvenientes de la documentación, comenta que no habrá problema, pero dar cita antes es imposible. Día tras día se iba comunicando a Jose lo que se iba gestionando, una vez que se tiene la cita se le traslada, se muestra muy molesto y enfadado indicando que va a tener que pedir dinero a los compañeros; se le explica que no se ha podido hacer más, pues en Liberbank no han cedido. Se le explica que no es problema de la CTAEX ni de la educadora, sino de gestión de Liberbank, se le da incluso la opción de protestar, por lo ocurrido, el día que vaya a retirar, pero sigue mostrándose molesto estableciendo que nos pese que va a tener que pedir dinero… se le vuelve a explicar e insistir en el problema con las gestiones de Liberbank, sin tener culpa las personas que le realizan seguimiento y atención, pero parece ser que no cree en lo que se le dice."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-07-06','miguel, recibo sobre del curatelado con la citación del PA PROCEDIMIENTO ABREVIADO 55/2020 DEL JZDO Nº1 PENAL DE CÁCERES. Solicito como pide en carta que se le facilite videoconferencia desde los Jzdos de Plasencia. Asimismo se le asigne representación de procurador y abogado. Y que a la Ctaex se nos permita asistir por videoconferencia desde los Jzdos de Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-07-06','Ana: Correo de Toni-Futuex: con información de la primera visita al domicilio de la Educadora, acompañada de la TS y en presencia de la Aux. de SAD, principal apoyo de José Manuel. Parece aceptar de buen grado a la ed. y el seguimiento. Se corrobora la información facilitada por la TS. La casa está limpia y ordenada. Con 200 €/mes tiene suficiente para gastos de bolsillo (todos los recibos están domiciliados). *Guardo correo en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-07-07','Ana: Correo de Sonia Leo, Dirtora de la Residencia Virgen de la Montaña (virgendelamontana@grupociudadjardin.com): "Buenos días, Soy Sonia Leo, Dirtora de la Residencia Geriátrica Virgen de la Montaña, les comunico que ayer Pedro Román García García fue derivado al hospital y ha quedado ingresado. Reciba un cordial saludo." ························································ Dado que es uno de los centros más afectados por Covid, le respondo: "Buenos días Sonia, Gracias por informarnos. ¿Podríais decirnos el motivo del ingreso? Así mismo, agradeceríamos nos mantuvierais informados de su evolución y nos hagáis llegar escaneados los informes que vayan facilitando en el hospital. Por otra parte, si valoraseis necesarias unas horas diarias de acompañamiento hospitalario, podéis hacer la propuesta a la secc. ecca. en el correo ctutelar@salud-juntaex.es con el pertinente “presupuesto” para que puedan valorar su viabilidad. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-05-21','Ana: Correo de Pilar Cerrillo por la tarde: "Buenas tardes Ana, adjunto te envío certificado de pedro Román García García explicando lo del precio. Ya me dirás si sirve. Un saludo" ···················· *Cdo. guardado en expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-05-22','Ana: Pedro, Jefe Secc.CTAEX, entrega en Dependencia el Certificado de la Residencia, para que vuelvan a calcular la cuantía de la prestación económica vinculada al servicio que le corresponde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GRANADA'and edp.apellido1='CANO'and apellido2='MARQUEZ'),'2020-06-18','el pasado 18 de Junio se realizó una reunión con Maribel, SSB y con Loli Mimbrero, voluntaria de Cáritas en el ayuntamiento de Llerena. Entre las dos estuvieron exponiendo el caso de Granada, que prefiere que la llamen Lali, y comentaron que es una mujer con las ideas muy claras, muy independiente y que no se deja aconsejar. Contaron que lleva dos años más deteriorada física y psicológicamente, ha empezado a acumular basura dentro de casa y no quiere que la ayuda a domicilio vaya a su casa para que se le limpie. Se pregunta a Maribel por la gestión del dinero de Granada y ésta cuenta que no es muy buena porque a ella le gusta mucho comprar todo tipo de adornos y cosas para la casa o ropa. Y normalmente si retira toda la pensión un día, al cabo de diez como mucho, ya no le queda nada. Aunque suele organizarse bien para no quedarse sin comida, esa parte la controla algo más. Por lo que se considera que quizá para los próximos meses, sería recomendable que Granada pudiera retirar la cantidad que se considerara necesaria quincenalmente. Así se organizaría mejor y solamente tendría que ir al banco dos veces al mes ya que le duelen mucho las piernas y camina cada día con más dificultad. Después de la reunión, se visitó a Granada acompañados de Loli, su persona de referencia. Granada accedió a conocernos y pudimos entrar en el zagúan de su casa, que ya estaba empezando a llenarse de suciedad por el suelo. Maribel había comentado que hacía poco tiempo había entrado una cuadrilla del ayuntamiento para limpiar la casa entera y retirar toda la basura. Granada comentó que le picaba mucho el cuerpo y se le recomendó la idea de ir al médico para que le echaran un vistazo, no le pareció mal, aunque demandó que antes pasáramos por el banco. Se la acercó al banco, acompañados en todo momento por Loli, para que Granada se sintiera más segura, y se retiraron los 197€ correspondientes al mes de Junio. Se le explicó que en el mes de Julio podría retirar los 396,60€ pero como algo excepcional hasta que se decidiera la cuota que iba a tener y la periodicidad con la que la iba a retirar. El problema era lo dificultoso de la comunicación con Granada ya que sufre una sordera importante y solo escucha algo por un oído. Por lo que se le explica algo y ella se queda con la parte que le interesa, por lo que habrá que seguir incidiendo en el tema económico con ella. Seguidamente se la acompañó al centro de salud donde la visitó su médico de cabecera, la Dra. Gabriela Candilejo. La Dra. comentó que tenía los resultados de una analítica que la tutelada se había hecho la semana anterior y los niveles estaban todos muy alterados. Facilitó los resultados, y fue subrayando los niveles que no estaban bien, se adjunta el documento en el email. Según su criterio, Granada debía ingresar en el hospital para que le hicieran mas pruebas, ya que su estado de salud era alarmante. Pero a la hora de hablar con ella, solamente le comenta que tiene una anemia importante, a lo que la tutelada responde que ella come muy bien y se comprará vitaminas ahora que tiene dinero y se pondrá como una rosa en dos días. La Dra. entrega un informe de derivación a urgencias por si conseguimos convencerla entre Loli y nosotros para llevarla al hospital. Se adjunta dicho informe. Una vez que Granada monta en el coche, se le explica que su estado de salud es muy delicado y que deberíamos ir al hospital para que le hagan más pruebas. Pero ella entra en estado de cólera, diciendo que no se va a ingresar nunca más, que ella no va al hospital y poniéndose muy nerviosa. Se decide cambiar de conversación y dar un paseo para que se calme pero en el momento que se le vuelve a mencionar el tema del hospital, reacciona de la misma manera, y cuenta que ella cuando estuvo ingresada lo pasó muy mal y no quiere volver a estar ahí nunca más. Cuenta que se va a comprar vitaminas y va a cuidarse mucho para ponerse sana enseguida. Se decide volver a intentarlo en la siguiente visita que se le haga. Por lo tanto se deja a Granada en compañía de Loli para tomarse algo en una terraza y se va al centro de salud para reunirse con Fernanda, la trabajadora social. Se le comentan las peripecias de ese día con Granada y ella comenta que pensaba que estando nosotros allí representando a la comisión, podríamos obligar a Granada a que ingresara en el hospital. Ya que ella pensaba que una vez que Granada tuviera la curatela, sus tutores tendrían que obligarla a ir al hospital o a hacer otra serie de cosas beneficiosas para su estado de salud. Se le responde que eso no está en manos de la comisión, no se puede obligar a nadie a ir al hospital, y menos con una curatela, se intenta trabajar con esas personas para que entiendan la importancia de estar sanas, de los buenos hábitos de salud y de higiene....etc. Pero nosotros no estamos allí para llevar a nadie a la fuerza al hospital. Se le comenta que se visitará a Granada con más asiduidad en estas primeras semanas, para conseguir un apego con ella y para intentar que vaya al hospital o por lo menos que cuide algo más su alimentación y su higiene. Fernanda comenta que estaremos en contacto y que si se necesita algo de ella, allí estará. Se le agradece su disposición. El pasado 26 de Junio, se llama a Loli, la voluntaria de Cáritas, para preguntar por el estado de Granada durante estos últimos días. Comenta que está con ella en esos momentos porque la ha llevado al centro de salud para que le hicieran la PCR. Cuenta que la ha convencido para que se vaya a los pisos tutelados de Llerena unos días mientras fumigan su casa. Así es que si la PCR sale negativa, se ingresaría el sábado 27 de Junio en los pisos tutelados de la localidad. Se va al encuentro de Granada y Loli y se habla durante un rato con ella. Loli comenta que se ha tenido que hacer una compra de productos de aseo personal, algo de ropa, zapatos... desde Cáritas para que Granada pudiera ingresar en los pisos tutelados y que la idea es mandarnos la factura por email para que se le haga el pago cuando sea posible. Se le explica que ese no es el procedimiento habitual con la comisión, que para lo sucesivo consulte con la educadora, ya que hay que pedir presupuesto y que sea esta comisión quien autorice el gasto, dado que ellos son los conocedores de los recursos economicos de la tutelada. Se lleva a Granada a su casa y se habla un rato con ella de las ventajas de irse a pasar unos días a un centro ya que estaría siempre acompañada, estaría en un entorno limpio, tendría más ropa que ponerse...etc. Ella no dice nada al respecto, solamente comenta que tiene una casa nueva por la otra parte de la calle y que no la usa para no ensuciarla. Comenta que tiene los pies y las piernas muy hinchados y se le propone que podría ir al hospital para que le echaran un vistazo, contesta que no tiene nada que hacer allí y que se recuperará muy pronto. El pasado 29 de Junio se llama a los pisos tutelados para preguntar por el estado de Granada y una de las trabajadoras comenta que como el estado de salud de Granada no era bueno, llamaron al médico el domingo por la mañana y éste decidió que había que llevarla al hospital para hacerle una transfusión de sangre entre otras muchas cosas. Ingresó esa misma mañana y seguía allí por lo que comentó la trabajadora. Seguidamente se llama al hospital de Llerena y se pregunta por el estado de Granada, cometan que está en la habitación 149 de la primera planta que corresponde a Cirugía. Se llama a la primera planta y se la habla con el médico que está atendiendo a Granada. Cuenta que la tutelada se encuentra mucho mejor porque se le ha hecho una transfusión de sangre pero que todavía está muy débil y necesita pasar alrededor de una semana en el hospital. Ella no se encuentra mal de ánimos, está contenta porque se siente mejor de salud y algo más fuerte, pero pregunta a cada rato a las enfermeras cuando le van a dar el alta. El pasado 6 de Julio se recibe una llamada de Fernanda comentando que Manuela Moreno, de los SSB y que lleva el tema de los pisos tutelados, necesita el número de cuenta de Granada Cano para pasar la cuota mensual del centro. Se llama a Manuela Moreno y se la saluda, ella cuenta que está con el papeleo del ingreso de Granada en los pisos tutelados y que necesita el número de cuenta de la curatelada para poder pasar la cuota mensual del centro. Se le pide que facilite su correo electrónico para que se le haga llegar a la comisión y desde allí se pongan en contacto entre los dos organismos. Manuela accede de muy buen grado: manuelassb@gmail.com El pasado 7 de Julio se llama la hospital de Llerena y se habla con la planta de cirugía que es en la que se encuentra ingresada Granada. Se pregunta por su estado de salud y una de las enfermeras cuenta que cree que se va de alta ese mismo día. Que no sabe si habrá habido algún cambio durante la noche pero que según la información de la que dispone, ella cree que se va de alta hoy. Se pregunta por el médico que la está llevando pero responde que está haciendo la ronda y que no puede ponerse en ese momento. Se comenta que se volverá a llamar un poco más tarde para hablar con la doctora y para que confirmen 100% que Granada recibe el alta a lo largo del día de hoy. En la historia clinica y habitos de esta mujer, al parecer hay un consumo de alcohol excesivo durante largo tiempo, aspecto que desconociamos. Creo que esto es todo lo mas relevante de los seguimiento de este nuevo caso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2020-07-07','-Amalia : Hablo con la hija y le escribo para solicitarle las llaves de la casa de su madre que se ha vuelto a llevar a Madrid. Solicito a Emilio (649716566 ) pto. reforma del tejado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-07-07','(Pedro) Llamo dos veces a la Dra. Cabanillas una vez que ha atendico a Joaquín en consulta. +++No consigo hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-07-08','(Pedro) Llamo UNA VEZ a la Dra. Cabanillas una vez que ha atendico a Joaquín en consulta. +++No consigo hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-07-07','Ana: Toni-Futuex (areasocial3@futuex.es) nos envía correo con Informe adjunto sobre la primera visita de Gloria, Ed.Futuex, a Catalina. Le Educadora también mantiene reunión con Pilar, TS del SSB. Catalina se encuentra bien, la casa ordenada y limpia (ella es quién se encarga de las tareas y de cocinar), nunca ha querido SAD. Acepta de buen grado el seguimiento y los futuros apoyos y acompañamiento a citas médicas por parte de la Educadora. Por otro lado, acusa un importante aislamiento social y falta de actividad en el día día. Acepta así mismo, con cierto entusiasmo, acudir a incribirse como demandante de empleo, de cara a la realización de algún curso y desempeñar algún puesto de trabajo compatible con su PNC. // *Se propone una retirada de efectivo semanal de 40€ para sus gastos. *Lo comunico a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-07-08','Ana: Tras intercambiar varios correos con Juana, secc. ecca. CTAEX., en las últimas semanas, sobre la suspensión del pago de la PNC de Rosa, vuelvo a escribirle preguntando si hay alguna novedad, pues hasta el momento no había conseguido solventar el problema con el banco. ········· Respuesta de Juana: "...Pues es muy fuerte, la del banco no sabe poner a José Vicente de representante legal, hablo todos los días con ella, si esta semana no lo hemos conseguido, abrimos cuenta en Liberbank y nos traemos el dinero. Ya te voy contando..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-07-08','Ana: Icíar me comunica que le ha informado la dueña del piso de alquiler de Jualiana Pauala, que le han confirmado en al notaría, que Marisol, ahijada, finalmente no es la heredera de Juliana. Al parecer, después de ese testamento de 2014, volvió a testar en 2015 y en esta última ocasión no nombró a la ahijada, se había enfadado con ella. No sabemos quién es la persona/s heredera/s.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-07-08','TERESA: EMAIL ANA PI ZAFRA Te hemos llamado Eduardo y yo para comunicarte un incidente sobre Natalia que ocurrió anoche con una compañera de residencia. Natalia aprovechó el cambio de turno de los monitores ( a las 23:00 h) para ir a buscar a su compañera y agredirla, dando puñetazo en la cara y rompiéndole las gafas, después de eso la agredió dos veces más. Físicamente Lorena está bien, un pequeño golpe en la nariz, pero con miedo a que vuelva a suceder. Evidentemente Natalia, en primer lugar lo negaba, tras saber que lo hemos visto en las cámaras…pues da su versión. La primera medida a tomar es sacarla de la excursión a Chipiona, y justificar que ese dinero y bastante más (de sus caprichos) van a ir a compara unas gafas nuevas. La segunda…pues tras informar a la familia de esta chica, a su tutora legal, puede ser la denuncia aunque estamos valorándolo….si quieres lo hablamos cuando tú puedas por teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-07-01','Ana: Recibimos en al CTAEX, copia del informe semestral que remiten desde la Res. Padcre Damián - Plasenzuela, al Jdo. de Trujillo. Según el informe de enfermería, Rosa "..se encuentra en buen estado general (buena coloración de piel, hidratada, consciente). Responde a estímulos verbales. No edemas...", "...desde mediados de septiembre, la residente se niega a ingerir alimentación por vía oral, se coloca sonda nasogástrica para su realimentación y no poner en riesgo su salud.", "Se le cambia de habitación por las voces de la compañera...", "dependiente para todas las ABVD, ha vuelto a tolerar la ingesta de alimentos por vía oral, principalmente batidos...".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-07-08','TERESA HABLO POR TELEFONO CON EDUARDO PSICOLOGO Y ANA EDUCDORA ME COEMNTAN QUE TIENEN DUDAS CON RESPECTO A LA DENUNCIA POR EL EMPODEAMIENTO QUE ESTO PUEDE SUPONER PARA LAPERSONA AGREDIDA, TRAS DEBATIR EL TEMA LLEGAMOS A LA CONCLUSION QUE ES NECESARIA LA DENUNCIA PARA QUE NATALIA VEA LAS CONSECUENCIAS LEGALES QUE TIENEN LAS AMENAZAS Y LAS AGRESIONES QUE LLEVA DESDE HACE MUCHO TIEMPO HACIENDO. ME COMENTA QUE SIGUEN SIN SABER NADA DE LA ABUELA Y QUE NATALIA INSISTE EN QUE SE PONGAN EN CONTACTO CON ELLA, DESDE EL CENTRO NO SE HAN INTENTADO PONER EN COTACTO CON LA ABUELA PARA RESPETAR LA DECISION DE ELLA EL ABUELO JUAQUIN SIGUE EN ESCENA Y VAN A INTENTAR REGULAR LOS CONTACTOS CON EL ABUELO. QUEDAMOS A AL ESPERA DE SE FORMALICE LA DENUNCIA Y NOS LLEGUE NOTIFICACION DEL JUZGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-08','TERESA:EMAIL TONI FUTUEX Buenos día Teresa, te paso a comentar lo acontecido en cuanto al nuevo seguimiento en LLerena, de Carmen Rubiano El pasado 26 de Junio se realizó una pequeña reunión con Maribel de los SSB de Llerena para comentar el caso de Carmen Rubiano. Maribel contó que era una chica muy joven que siempre había vivido con su madre y que ahora estaba pasándolo mal porque su madre estaba en una residencia de Azuaga. Después de hablar durante un rato sobre su situación actual, que ha empeorado por el estado de alarma y el confinamiento, se decidió ir a su casa acompañados de Maribel para hacerle una visita. Cuando se llega a su casa, se encuentra allí a Loli, la voluntaria de Cáritas, que ha ido a hacerle una visita. Se la saluda y Maribel hace las presentaciones, ella comenta que está muy contenta por tener a gente que la visite a menudo y esté con ella porque se siente muy sola. Maribel comenta que tanto las auxiliares de ayuda a domicilio como los vecinos de su calle la han visto consumiendo mucho vino de caja y están preocupados por ella. Ella admite que ha vuelto a consumir alcohol pero no mucha cantidad, se le confronta esa información porque Loli ha hablado con la dueña de la tiendecita de comida al lado de su casa y le ha dicho que en una sola tarde le ha vendido tres litros y se los ha bebido en muy poco tiempo. Se le recuerda que tiene una medicación muy fuerte por su enfermedad y no puede mezclarse con el alcohol. Por lo que se le hace un llamamiento sobre este tema y se le pide que baje el consumo de alcohol poco a poco hasta que deje de tomarlo, se le propone que lo cambie por la Coca Cola, que es lo que ella suele beber siempre. Carmen se queda muy seria y responde que tenemos razón pero que es muy difícil para ella dejar el alcohol, que lo tendrá que hacer muy poco a poco. Al cabo de un rato llegan las dos auxiliares de ayuda a domicilio y se les comenta que se ha llegado a un acuerdo con Carmen y se le comprará un litro de vino y otro de Coca Cola por las mañanas y otro tanto por las tardes para que lo vaya dejando poco a poco. Ellas están totalmente de acuerdo con el plan y comentan que ayudarán a Carmen en todo lo que puedan. Que sepamos no ha acudido nunca Cedex y debe ser una historia de consumo bastante larga. Se le comenta a Carmen que se la visitará a menudo para saber cómo se encuentra y que se intentará que salga un poco más de casa para dar paseos por su pueblo. Ella contesta que lo intentará aunque le duelen mucho las piernas. 2 de Julio 2020 Se recibe una llamada de Fernanda, la trabajadora social del centro de salud de Llerena, en la que comenta que ha estado visitando esta semana a Carmen Rubiano junto con el enfermero de salud mental porque está consumiendo grandes cantidades de vino sin control. Cuando han ido a verla la han visto hinchada, con los ojos hundidos y casi sin poder articular palabra. Además tenía blísters vacíos encima de la mesa y no han podido comprobar si se toma la medicación correctamente o no, aunque lo dudan. Fernanda comenta que incluso a principios de esta semana, Carmen ha ido al supermercado que tiene cerca de casa a comprar más vino cuando ya se había avisado para que no le vendieran, y como la dependienta le ha dicho que no, ella se ha llevados tres bricks sin pagarlos. Tiene una gran adicción al alcohol que se remonta varios años y no tiene capacidad de controlarse. Cuando Fernanda y Juanma hablaron con ella, acordó que no iba a tomar más vino, sino cerveza sin alcohol. Fernanda comenta que han ido a verla esta mañana y estaba algo más tranquila pero se bebía las latas de cerveza sin alcohol como si fuera agua delante de ellos. En un día se puede beber 15 latas tranquilamente. Fernanda cuenta que ha hablado con el psiquiatra de Carmen, el Dr. Idilio para que estuviera al tanto de la situación de la tutelada en estos momentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-07','TERESA RECIBO LLAMADA DE M FERNANDA TS DEL CENTRO DE SALUD PARA MOSTRAR SU PREOCUPACION POR EL CONSUMO DE ALCOHOL LE INDICO QUE VAMOS A PEDIR INGRESO INVOLUNTARIO Y QUE SI ES NECESARIO AVISEN A 112 A VER SI LA PUEDEN INGRESAR EN UHB YA QUE DESDE LA CTAEX NO PODEMOS HACER NADA MAS QUEDO A LA ESPERA DE LOS INFORMES PSQUITRICOS YLE PIDO A MIGUEL QUE PREPARE LA PETICION DE INGRESO INVOLUNTARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-07-09','TERESA LE PASO A ANGEL INFORM SOCIAL PARA QUE PIDA EL TRASLADO DE EXPEDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2020-07-09','TERESA ENVIO CONSENTIMIENTO INFORMADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2020-07-09','TERESA ARCHIVO RESOLUCION CON DENEGACION PERNSION DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-08','(Pedro)Converasaciones sucesivas con Pilar (ESM de Cáceres), José Manuel Romero Mediavilla, 112. +++SITUACIÓN: José manuel había hablado con Pilar porque se encontraba "muy mal" y amenzaba con tomarse dos cajas de pastillas.Decía haber llamado al C.Salud y no le cogían el teléfono ¿cierto? +++Pilar llama a la Comisión para poenrnos al corriente. +++Probablemente manipulando la situación de nuevo, pero ante la posibilidad de que sea cierto llamo a José Manuel. Se escucha con voz muy baja, apenas se le entiende. dice ques e encuentra mal, que se quiere ir al CSS de Plasencia. Le digo que por qué no llama a su médico y dice que no le cogen el teléfono. +++Llamo al 112: concen de sobra a José manuel porque "está constantemente llamándonos, es un manipulador..." Quedan en que avisarán a su Centro de Salud para que vayan a verlo. +++Llamo a José Manuel y le digo que va a ir el médico a verlo: "Estoy bajando las escalera de casa para irme a Plasencia cuando llege la ambulancia..." Le digo que vuelvba a subir y que espere al médico, que lo verá en su casa, no en el patio. +++Al rato llama José Manuel a Ana: "Ya no hace falta que venga el médico. Ha venido una amiga mía (otra tutelada del CRR) y ya me encuentro mejor. He llamado al 112 para que no vengan ya. +++Llamo al 112 para confirmar la cancelación de la incidencia y, efectivamente, es cierto. +++Llama a la Comisión Tutelar la Dra. Obdulia Moreno (53607). Me habla de José Manuel en los mismos términos insistinedo en que este señor tendría que estar en un Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-09','TERESA ENVIO INFORME SOCIAL E INFORME PSQUIATRICO A MIGUEL PARA QUE SOLICITE INGRESO INVOLUTARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-09','TERESA ENVIO SOLICITUD RECONOCIMIETNO GRADO DE DISCAPACIDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-07-09','Ana: Llamada de Adela, Admvo. CSS Plas. (Rosa está de vacaciones): Han recibido el oficio-solicitud de documentación para la realización del inventario de Julia Morón, pero Julia ya no se encuentra en el CSS. En mayo se fue de alta al domicilio familiar. ···· Se lo comunico a Julio y a Juan Pedro - CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2020-07-09','Ana: Llamada de Amor, TS Aspace (678 975 906), pregunta por la autorización para las activiades de ocio de Santi. Le recuerdo que acordaron enviarnos la misma para que se pudiera poner a la firma del Representante Legal y aún no lo han hecho. El correo que mandaron al respecto, llevaba bastantes documentos adjuntos y ninguno era de Santi, tal y como contesté al mismo correo y le comuniqué a ella mediante conversación telefónica. *Me la enviará hoy mismo a mí correo. ········· Una vez recibida se cumplimento el documento y pido a Tere (está en la ofi hoy) me la lleven a firma. Por otra parte, envío a Miguel, A.Jurídico CTAEX, la autorización de derechos de imagen, para que valoren y en su caso remitan a Fiscalía. ·············· Envío por mail la Solicitud de participación en el progarma de ocio debidamente firmada y sellada. ············· Tras el visto bueno de Miguel, A. Jurídico-CTAEX, se pone para la firma la Autorización de Dchos de Imagen, sólo se firmará en la casilla de "uso interno".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2020-07-09','Ana: Llamada de Aída (671507221): dice que tiene lumbago, y aunque en un inicio no quiere posponer su viaje a Segura de Toro, no sabe realmente si se va a encontrar bien para viajar en autobús y llevar la maleta. Gloria, Ed. Futuex, le ha llamado para acompañarla a comprar los billetes de bús, pero ella no le dice fecha concreta pues no saba cómo va a estar. Según dice, ante esto, "Gloria le "amenaza" con suspenderle la próxima asignacción", le digo que me extraña mucho, Gloria no tiene esta potestad, y que habrá sido algún malentendido. Acudirá al médico hoy. ······ Nueva llamada de Aída, en el C. Salud le han dico que su médico ha tenido que salir a un domicilio por urgencia. Le emplazan a que llame mañana y el médico le atienda telefónicamente. ···· Escribo un mail a Toni-Futuex, para poner en aviso a Gloria, pues no sé muy bien qué pretende Aida. ··········································································· Conversación con Toni-Futuex, me dice que están teniendo sospechas de que Aída quiera hacer como ya hizo una vez, y gastarse el dinero que ha pedido para sus vacaciones en otra cosa, pues ésta no deja de darle largas en relación a la compra de los billetes de autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-07-08','(Pedro) Llamada de D. Pedro, abuelo de Alejandro. +++No le dan cita en Salud Mental al estar curatelado en esta esfera de su vida. +++Pediremos cita desde aquí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-07-09','(Pedro) Solicitud de cita en el ESM por Amalia. +++He contactado con el ESM Valdepasillas que es el que le corresponde. El psiquiatra ( Antonio ) lo vió en Agosto del año pasado y Carmen ( TS ) también. Al hacer un año que no acude , me indican que tiene que ir a su médico de cabecera , Centro de Salud de La Paz , su médico es Sergio Luna , y pedir la cita . Que se encarguen de llamar y pedir la cita , no cogen el tf y tendrán que llamar o acercarse y para pedirla. Otra cosa será que luego él acuda. Debería pedirla él , y se vería si realmente está interesado. +++Tiene cita para mañana, 10 de julio. Le llamarán por teléfono.Pongo al corriente al su abuelo. +++++++++++++++++++++++++++++++++++++++++Teléfono de la madre de Alejandro:671-330861','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-07-09','Ana: Tras conversación con Pilar Cerrillo, TS de la Res., envío un correo al ctutelar (secc. ecca.) y a Miguel, A. Jurídico-CTAEX: "...En relación a Pedro Román García García, me preguntan desde la residencia, si ya se ha podido recupera el dinero del Contrato de Valores que tenía Pedro Román, pues aún tienen deudas que amortizar en el C. Residencial. La última anotación al respecto en la Intranet es de fecha de 19/05/2020: “miguel, llega la firmeza para el desbloqueo de cuentas y le reenvío dicha resolución al Santander por email”, ¿sabemos algo nuevo? Si no es así, ¿podríais alguno poneros en contacto con el banco? Ya me decís. " ·········· Miguel envía correo al B. Santander: "Buenas tardes, urge el desbloqueo de la cuenta de valores cuya resolución firme judicial se les remitió el 19/5/2020, sin que hasta la fecha actual hayan ustedes ni desbloqueado ni se han puesto en contacto con esta Comisión Tutelar de Adultos. Ruego que lo desbloquen con urgencia. Para aclarar cualquier duda pueden ponerse en contacto con esta Comisión Tutelar de Adultos por esta misma vía. Un saludo" adjuntando de nuevo los documentos pertinentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-07-08','(Pedro) A petición de D. José Manuel, nieto de Dª Manuela, se mantendrá reunión con él y su hermana Dª Mª Carmen el próximo martes, 14 de julio de 2020, a las 09:30h en la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2020-07-09','miguel, se pone en contacto via email la abogada de la fallecida hermana por haber un problema en una venta que se hizo en su día y que habría que subsanar: "Estimado compañero: Me dirijo a ti como antigua abogada de Doña Maria Vacquez Corrales, hermana de Juan, ya fallecida. Entiendo que Juan vive y que sigue en la Resdiencia geriátrica de Casar de Palomero, ultimas noticias que yo tengo de él. Tambien, que sigue tutelado por la Comision, como me pusisteis en conocimiento en su momento, dato que aquí se ignoraba (Los Santos de Mna., donde residia la familia de Juan y este antes de su traslado a dicha residencia). Te ruego tengas la amabilidad de confirmarme estos datos y si eres de entre los compñeros que estéis, la persona idónea para contactar representando a Juan, en su caso, como único heredero de su hermana, por un problema legal surgido en una venta que hizo esta en su momento y en la que al parecer hubo un error, a fin de poder subsanarlo, como desean los compradores afectados. Te agradezco la atención prestada y quedo pendiente de tus noticias. Mi teléfono es el 924544555 y mi correo como colegiada 1000@icaba.com Un cordial saludo Ma.Carmen Gómez Abogado)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-07-09','miguel, tras pregunta por el centro y la parte social por el desbloqueo de la cuenta de valores solicitada el 19/5/2020 vía email al Santarder, y tras no recibir respuesta reenvío de nuevo al Santarder la urgencia del desbloqueo de dicha cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-07-10','(Pedro)Conversación con la Dra. Mª José Sánchez Melo (81611) del Hospital de Mérida. +++Ayer operaron a Emilia de un pie y todos los consentimientos los firmó ella. Se dieron cuenta después de que estba tutelada por la Comisión y esto les preocupó. +++Inoformo quie se trata de una curatela en el ámbito patrimonial (para administrar sus bienes). +++DESCONOZCO por qué ha sido intervenida en Mérida si ella se encuentra residiendo en el CRR de Plasencia. +++Es previsible que le den el alta a lo largo del día de hoy. +++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Javier, Director del CRR. +++Sin demandas económicas desde su vuelta y buen compñortamiento. +++SE ha operado en Mérida porque tenía ya la cita prevista desde que estuvo en el CRR de Mérida. Comenta que lo comunicaron por correo electrónico pero están teniendo problemas con su correo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-07-10','(Pedro).Correo-e para Miguel. +++• D. Francisco Javier tiene una curatela patrimonial exclusivamente. Hace cuatro años perdió todos los puntos del carnet de conducir y ahora quiere recuperarlo. Alberto le ha pedido que nos diga por escrito que quiere hacer el curso correspondiente. Al tratarse de una curatela no está dentro de las obligaciones de la Comisión este tema, pero creo que sería conveniente informar al Juzgado de que no solamente se quiere sacar el carnet de conducir sino que también está actualmente conduciendo sin él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-07-10','(Pedro).(Pedro).Correo-e para Miguel. +++• D. Miguel tiene una tutela. Tiene un coche en propiedad al que Alberto quería dar de baja, pero consultándolo con el CSS de Plasencia él quiere mantener su propiedad y que se siga pagando la póliza de su seguro. Desde hace tiempo lo tiene aparcado en Guadalupe, sin moverlo, por lo que no sabemos en qué condiciones puede estar. En este caso sí creo que se debería consultar al Juzgado sobre la pertinencia o no de que D. Miguel pueda conducir, recabando los informes médicos o forenses que fuesen necesarios para valorar su capacidad. ································································································ Ana: Envío email a Mariví Clemente, pidiendo que me confirme la fecha de finalización de la medida de Miguel (nos constaba 25/10/20) y si tiene alguna otra medida pendiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2020-07-10','TERESA VALORO LA POSIBILIDAD DE SOLICITAR ORFANDAD YA QUE SU PADRE ESTA FALLECIDO HABLO CON SU HERMANA M JOSE 625925914 PARA PEDIRLE LIBOR DE FAMILIA Y ME REMITE A SU HERMANO JOSE 65574366, ESTE ME COMENTA QUE NO SABE DONDE ESTA EL LIBRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-10','Ana: tras conversación telefónica con José Manuel, en que me comunica que Icíar, secc. ecca. le ha dicho que no se le va a dar dinero para acudir a los próximos juicios, envío un correo al ctutelar@, Alberto, Jefe secc. ecca., Pedro, Jefe secc. CTAEX y Toni-Futuex: "Buenos días a todas/os, En relación a los próximos juicios a los que tiene que acudir en Plasencia José Manuel Romero Mediavilla, los días 16 y 21 de julio, hablé con Pedro el otro día y me comentó que para comprar los billetes de autobús para acudir a los mismos sí se le iba a dar dinero. Los billetes cuestan apróx. 15 € ida y vuelta, si no me equivoco. La idea es que retirara dicha cantidad los días previos de acudir a los respectivos juicios acompañado Virginia-Futuex, y que ésta le acompañara también a adquirir los billetes, para asegurarnos de que los compra. Miguel, Asesor Jurídico, asistirá al juicio del día 16 al menos (el otro no lo sé), por lo que, como hablé ayer con Toni, no es necesario que la Educadora de Futuex le acompañe al mismo. Necesito que me corroboréis, por las distintas partes, que esto finalmente va a ser así. Gracias y buena mañana de viernes." ··········································· Conversación con Pedro, Jefe CTAEX, ha hablado con Alberto, Jefe Ecca., finalmente se le autorizará para retirar 15€ el día 15 acompañado de Virgina para que acudan a comprar el billete. ································ Envío correo a Toni-Futuex, para comunicárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-07-10','miguel, quedo pendiente para poder hacer el escrito al juzgado que me remitan de la parte económica y/o social los datos identificativos de los vehículos, así como la fuente de la que procede la información (centros, servicios sociales de base...)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-07-10','miguel, quedo pendiente para poder hacer el escrito al juzgado que me remitan de la parte económica y/o social los datos identificativos de los vehículos, así como la fuente de la que procede la información (centros, servicios sociales de base...)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2020-07-10','Ana: Llamada de Aída, ha llamado al C. Salud, y la Dra. que sustituía hoy a su médico le ha dicho que mejor acuda el lunes con su médico de atención primaria, que se incorpora.Pero que lo que debería es hacer reposo y no coger peso. En función de lo que le diga el médico ya tomará una deción con respecto al viaje. ·································································································· Correo de Toni-Futuex, al final de la mañana: "...comentarte tb, que he puesto un email destinado al área ecónomica para que sean conocedores de que por el momento Aida no ha comprado nada relacionado con el viaje, de los 300 retirados el lunes... yo creo que nos va a hacer el lio, otra vez..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-07-10','Ana: Llamada de Damián (622 834 876), el día 14 tienen juicio por el robo de los 5000 €. Ha enviado a Miguel, Asesor Jurídico la carta del Jdo. ······ También ha hablado ya hoy con Icíar sobre distintas cuestiones eccas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-07-10','Ana: Conversación con Cristina, Ed. Soc. Asociación Vera (681 143 911): en relación a las vacaciones, ella en general no es partidaria de que acudan a sus domicilios por el riesgo por el Covid. En el caso de Adrián, dadas las características del domicilio y la falta de higiene que suele haber en el mismo, lo ve menos conveniente. Estoy de acuerdo con ella. No obstante estamos esperando respuesta de la D.Gerencia y de la Ud. de RR. Asistenciales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-07-10','Ana: Llamada a Gema, Ed. CAM Trujillo (927 027 600), pone el manos libre y hablamos a tres con Felipe, Ed. también del grupo de mayores: les comunico que Pedro, Jefe de secc. ya hablado con Soraya Maya. Y que en cuanto a la plaza, aunque en la lista general general está el número 2, está en 1º para plaza de hombres, pues por delante tiene a una mujer. *Me informan de que Virgina-Futuex, ya acudió a visitar a Aitor la semana pasada. Éste se mostró un poco timído y no habló mucho, dicen que suele pasarle. Pero la visita le vino muy bien. ······ En cuanto a la ocupación de Aitor, en caso de que tarden en concederle la plaza, planteamos opciones de Talleres de Empleo/Ocupacionales si hubiera alguna convocatoria nueva del SEXPE, de cara a septiembre. **Está inscrito como demandante de empleo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-07-10','(Pedro) Correo del CRR de Mérida (10-07-2020). +++Ángel Pinilla: Ha habido algunas noches que se ha despertado de madrugada y, ante las indicaciones de los compañeros, se ha puesto a la defensiva. En concreto hoy más accesible para abordar este y otros temas. En general bien, estamos en coordinación con la residencia donde se encuentra su madre para poder realizar una visita próximamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-07-10','(Pedro) Correo del CRR de Mérida (10-07-2020). +++Antonio Merchán: Sigue en la misma línea que la semana pasada, más colaborador y tranquilo. Parece que el efecto del cambio de medicación está funcionando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-07-10','(Pedro) Correo del CRR de Mérida (10-07-2020). +++Mª Dolores Fernández: Ha acudido al Hospital por su cuenta, no se queda conforme cuando nosotros le decimos que lo que le pasa es que se pone nerviosa.... como se lo ha dicho el Médico parece que lo ha interiorizado, no sabemos cuánto le durará. Del tema vivienda a mi no me ha dicho nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-07-10','(Pedro) Correo del CRR de Mérida (10-07-2020). +++José María Guillén: Ha recibido esta semana la visita de su hermano y su cuñada. Ahora su principal demanda es el paso al piso supervisado. Ya le hemos dicho que hay cosas que trabajar antes de dar ese paso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-07-10','(Pedro) Correo del CRR de Mérida (10-07-2020). +++Luisa Rodríguez: Observamos un poco agitada, estamos valorando un cambio de habitación para favorecer el descanso de su compañera de habitación e intentar que la convivencia sea mejor con otra persona. Abordamos continuamente la importancia de evitar bebidas cafeínadas. Os seguimos comentando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-07-13','Ana: Correo de Sonia Leo, Dir.ª Res. Virgen de la Montaña: "Buenos días, informo de que el tutelado, Pedro Román García continua ingresado en el Hospital San Pedro de Alcántara, su mejoría es lenta pero favorable. Presenta una insuficiencia cardiaca y renal. Un saludo, Sonia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-07-10','Ana: Correo de Toni-Futuex: "...Comentarte que aunque lo estamos llamando no conesguimos hablar con Juan Chamorro para explicarle que si quiere que se le suba la asignacion tendra que renunciar a extras, pero no le localizamos, lo seguiremos intentando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-07-13','Ana: De cara a la reunión de mañana en la CTAEX con José Manuel Correa y su hermana, llamo a la Empresa de SAD Serv. del Fresno (924 677 705), y hablo con Manuel Guerrero, Gerente (nº personal: 677 39 36 85), para acordar un acompañamiento puntual para Manuela de 8:00 a 12:30 h. En ppio. no habrá problema, pero me lo confirmará por teléfono o email. *Manu me informa de las exigencias y problemas con José Manuel, a petición del mismo la Aux. en alguna ocasión ya ha tenido que modificar las horas de atención a otras personas usuarias para adaptarse a sus exigencias y hace 2 semanas, que fue la última vez que ocurrió, José Manuel no regresó al domicilio hasta pasadas las 16 h. *Durante el confinamiento dejó varios días a Quini, Aux., encerrada con llaves en el domicilio con Manuela, hasta que la aux. se impuso y le dijo que o le dejaba llaves o dejaba la puerta abierta. Manu dice haberse enterado a posteriori. Ya le ha parado los pies y no le va a consentir más exigencias. ·················· Confirmado el Serv. de Acompañamiento, Pedro, Jefe CTAEX, llama a José Mauel. ···················································································· Correo de Manuel Guerrero por la tarde (mguerrero@serviciosdelfresno.es): "Ana buenos días, La auxiliar que va a realizar el servicio extraordinario es MA DOLORES ROMERO GONZALEZ Esta mediodía no te pude confirmar el nombre porque la compañera no estaba. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-07-13','Ana: Llamada de Clara, TS CS Guadalupe: Juan tiene cita el próximo día 15 a las 12:00 h en enfermería del C.Salud para ponerse el inyectable. *El siguiente será el 14 de agosto, viernes, pues le tocaría el 15 pero es sábado. ·· Y el día 21 en CC en Cirugía (En Jara no se especifica para qué). Debe haber recibido la carta de citación. Si quiere asistir tendrá que acudir al C.S. a recoger el volante para la ambulancia. ························ Lo comunico a Toni-Futuex, por mail para que lo tengan en cuenta y se lo recuerden a Juan. ····················································· Correo de Toni-Futuex, a última hora: "Hola ! sii finalmente ahora hace poquito hemos logrado hablar con el... ha refunfuñado un poco, porque dice que para ropa y otras cosas necesitará dinero a parte, le hemos explicado que no puede ser que solo tiene que hacer cuentas y ver como no hay mas que la pensión no se puede estirar mas, le hemos dicho que elija si prefiere quedarse con la cantidad de ahora y solicitar los extras, pero no, en dice que mejor los 70 eu, esperemos que efectivamente lo haya entendido. Y respecto de las citas, si el esta al tanto de todas, ya ha pasado para recoger el inyectable, y tiene también previsto lo de la cita que es para una colonoscopia de prevención que tiene el ses un pograma en el que él, entraria por edad, hasta el momento esta pendiente de acudir tanto al inyectable como a la otra cita de colonoscopia en Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-13','Ana: Correo de Belén, secc. ecca.: "Buenas Ana, ya he enviado al banco el reintegro de 15€ Jose M Romero Mediavilla, para que lo pueda retirar hasta el próximo viernes 17 julio, por si tienes que avisar a futuex." ················ Se lo comunico a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2020-07-13','Ana: Llamada de Aída, aparentemente muy angustiada porque le ha costado mucho contactar con el C. Salud y no le ha atendido el médico directamente, debe esperar a qué le llame él a lo largo de la mañana. Por otra parte dice que está pendiente de quedar con Gloria para comprar el billete de autobús y retirar el dinero. Le preocupa que no el vayan a autorizar el siguiente reintegro. *Llamará a Juana, secc.ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-07-09','Ana: Correo de Alberto, Jefe Secc. Ecca. CTAEX: "Hola Ana. Tengo un correo nuevo de FUTUEX. para pasar la asignación del tutelado de 50 €/semana a 70 €/semana. En un correo previo que te envie (lo tienes más abajo) se explicaba que, aunque tiene asignados 50 €/semana aprox. (222 €/mes) en realidad, CON LOS EXTRAS CONCEDIDOS, está sacando 65 €/semana aprox (280 €/mes). NO HAY PROBLEMA en subir asignación a 70 €/semana (304 €/mes). PERO ALGUIEN SE TIENE QUE HACER CARGO de que NO HABRÁ EXTRAS (lo digo para que cada semana no estemos con nuevas peticiones. Háblalo si quieres con Toni y si estais de acuerdo me lo decís y cambiamos la asignación inmediatamente. Hablamos Alberto." ······················ Conversación con Toni-Futuex: hablarán con Juan y le harán el planteamiento, para que sea él quién decida qué prefiere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-07-13','Ana: Llamo a Dir.ª Javier, CRR (677 407 640), pues Pedro me informa que el viernes cuando Emi salió del hptal., se presentó en el SEPAD a las 15 h, pidiendo dinero para un taxi porque había perdido el autobús. ···························· Javier me informa, que todo era mentira, sólo quería efectivo para unos zapatos. Tenía el billete cerrado y finalmente volvió a Plasencia en autobús. Llegó a Plasencia a la 1:00 a.m. y al parecer se fuen caminando desde la estación de autobús hasta el CRR, llegó a las 3:30 a.m. *Durante el fin de semana, no saben de dónde ha sacado el dinero, pero e ha comprado unos zapatos como ella quería.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-07-14','miguel, recibimos en email de ayer 13/7/2020 de ctutelar el siguiente email: Buenos días, En el asunto de Herencia de Hermanos Murillo Horrillo, les he enviado, por correo certificado urgente y acuse de recibo, la documentación para que puedan promover el expediente de Aprobación Judicial de Herencia y al mismo tiempo Autorización Judicial de la venta de las siete fincas del haber hereditario. En cuanto reciba el informe de valoración de las fincas sitas en Extremadura, les enviaré también. A continuación les envío escaneada la escritura de propiedad de la vivienda de Azkoitia, cuyo original creo que les remitió la Notaría de Azkoitia. En caso de que no dispongan de esta escritura, me informan para que pueda localizarla y enviarla. Esperando sus noticias, reciban un cordial saludo Ana Mª de Pablo Laquintana. Abogada. Elkano kalea 1, bajo. 20240. Ordizia. Gipuzkoa. 675704059 / 943565717 adepablo8@gmail.com *********************************************************** miguel, le contesto lo siguiente Buenos días, quedo pendiente de recibir dicha documentación. En cuanto me llegue se lo haré saber a efectos de poder iniciar la solicitud de aprobación judicial de esta herencia. Agradecería también para intentar agilizar me indique qué finca es la que se quiere vender, la tasación (remítamela), quiénes son los compradores (si se conocen) y cuál será el precio de escrituración de la compraventa. Reciba un cordial saludo.','2');
