insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-07-14','En relación al PA 194/2019, seguido en el Juzgado de lo Penal 1, de Mérida (juicio por atentado a agentes de policía), asistimos al juicio celebrado el 14/7. Jonathan asiste a través de videconferencia desde el Centro Penitenciario de Badajoz. A la espera de la Sentencia, el Abogado (José María Delgado Temprano 607924597), nos inidica que ha conseguido rebajar la pena que pedía la acusación. De momento, tiene que cumplir 6 meses de prisión. Ahora ya se encuentra en el Centro Penitenciario de Badajoz, donde estaba retenido para que acudiera a este juicio. Va a seguir en el Centro Penitenciario, para cumplir esos 6 meses. Una vez salga la Sentencia, le condenarán al pago de una multa a la que no podrá hacer frente, debido a la PNC que cobra, se le declarará insolvente, con lo que se le sustituirá por trabajos en beneficio de la comunidad. Si la Sentencia sale pronto, esos trabajos podría cumplirlos en el centro Penitenciario.','2');
