insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2020-07-15','(Pedro)Llamada de Yessica, de la Asoc. de Derechos Humanos de Extremadura (927-629370). +++Rafael se ha puesto en contacto con ellos porque dice que con los 75 eiros que se le dan no le llega. +++++Exoplico que esa cantidad está en función de las necesidades que desde el Centro Penitenciario comunican a la Comisión Tutelar y que cualquier necesidad que la perosna tutelada tenga es comunicada desde el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-07-15','Ana: Correo de Juana, secc. ecca.: "...con respecto a Rosa Marín Laureano, no nos dan solución en el Santander, no saben meter al representante legal en la cuenta, muy fuerte... Así que voy a tramitar esta semana para abrirle cuenta en Liberbank. Necesitamos DNI escaneado de Rosa que no tenemos en su expediente, tienes algún contacto del centro?" ············································································ Llamo a la Res. Padre Damián - Plasenzuela (927 31 37 45) numerosas veces a lo largo de la mañana, pero comunica todas ellas. ···················· Envío un correo a la dirección que aparece en el buscador de residencias de la web del SEPAD (secretaria@plasenzuela.es). Y llamo por teléfono al Ayto. (927 31 35 52), Jesús me corrobora que el nº al que he estado llamando es el de la Residencia y me facilita otro de Alfredo: 619 45 92 81. Llamo pero salta el buzón de voz, dejo un mensaje diciendo lo que necesitamos y mi número de tlf.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILIA'and edp.apellido1='SALGADO'and apellido2='DURAN'),'2020-07-15','Ana: Llamada de Estrella Durán, TS CSS-Plas.; enviarán un CI de Basilia por correo postal, para que se lo devolvamos por el mismo medio. No es urgente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-07-15','Este chico estaba tutelado por su padre y solicitó remoción del cargo , aunque en la práctica es quien ejerce toda la supervisión. Manuel vive en Moraleja desde hace más de 5 meses, con el padre y la madre , conflictos familiares por el tema del dinero , les pide continuamente. Tiene asignación semanal , y percibe PNC . De ella 100€ se transfieren a su hija , ya tiene unos 16 años y mantiene buena relación con ella. Estamos pendiente de plaza para piso supervisado de salud mental , está de los primeros en la lista , y esperemos que no tarden mucho en dársela . Tf de Manuel 677716154 tf. del padre 657656184 tf. de la hija 611070785','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2020-07-15','TERESA SOLICITO AL JUZAGADO LIBRO DE FAMILIA PARA PODER PERDIR ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-15','TERESA PIDO POR EMAIL A LA TS DE ZALAMEA COPIA DEL LIBRO DE FAMILIA DE PABLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-07-16','Ana: Correo de Toni-Futuex, ayer tarde: "...Comentarte que respecto a lo Juan Chamorro hemos hablado con él, y está a favor del cambio a 70 euros pero no tener mas extras, estaba incluso risueño y esperando esto." ········································································ Ennvío correo a Alberto, Jefe secc. ecca., con copia al ctutelar: "Buenos días Alberto, Me comunican desde Futuex, que Juan Chamorro está de acuerdo en ampliar su asignación a 70€ semanales a cambio de no recibir extras. Confirma por favor a Futuex, y ponme en copia para que yo lo sepa más que nada, a partir de cuándo es efectivo el cambio. Seguimos. Buena mañana." ······································································ Correo de Alberto a Toni-Futuex: "Buenos días. En relación con el incremento del importe de la asignación del tutelado Juan Chamorro Holguín, se establece importe en 70 €/semanales (304 €/mes). Este incremento será efectivo a partir del próximo 20/07/2020 Tal y como hemos acordado, dicho incremento está condicionado a la no concesión de reintegros extraordinarios. Toni, por favor, avisad a tutelado de lo aquí acordado. Un saludo" ································································································ Llamada de Clara, TS CS Guadalupe (927 154 305): Juan ha acudido al despacho para pedir que envíen a la CTAEX por fax unos recibos del OAR (IBI). Al preguntarle Clara cómo estaba y si quería alguna otra cosa le ha contestado "Lo que tenga que hablar contigo ya lo hablaremos en los Juzgados", Clara cree que les va a denunciar. *En cuanto a la cita para la colonoscopia, le ha dicho la Dra. Consolación que Juan no quiere ir. Como es voluntaria, sólo le han pedido que si se notara cualquier cosa que acudiera a la consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-15','Ana: Correo de Toni-Futuex: "JM Mediavilla, al final comprado por anticipado el billete de tren le ha salido todo por 9 euros sale sobre las 7 de la mañana y regresa a la 1 esta informado y parece que dispuesto, ayer tuvo un momento de no querer ir al juicio... ademas se le ha entregado los 5 euros restantes para desplazarse desde la estacion al juzgado y viceversa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-07-14','Ana: Correo de Paula, TO, CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Respecto a Antonia Bernardo, comentaros que se ha ido de vacaciones al domicilio familiar del 13 al 22 de Julio. Ha recibido toda la información necesaria para su protección y la de las personas con las que va a convivir, así como la necesidad de realizarse la prueba PCR para su regreso al CRR."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELEDONIO'and edp.apellido1='GARCIA'and apellido2='MATEOS'),'2020-07-16','(Pedro)Registro de la llamada realizada por Escalona hace unos días (la fecha no coincide con la indicada), en relación con la remoción planteada por la hermana y tutora actual de D. Celedonio. +++27-28 años en Trujillo con su madre. +++Tenía plaza en centro de Trujillo pero hace 2-3 años que no asiste. Fue EXPULSADO por ALTERACIONES DED CONDUCTA. +++Hay varias dencuncias contra él (pero no interpuestas por la madre) por maltrato hacia su madre (palizas). +++Familia desestructurada (todos los hijos tutelados por la Junta), tiene otros dos hermanos discapacitados. +++Al parecer, la madre lo que pretende es mantener el control de la pensión de su hijo. +++OTRO RIESGO: es MUY ENAMORADIZO. +++HERMANA/TUTORA.Escalona entiende que el cargo está bien ejecutado. Económicamente, cuando masumió el cargo, la cuenta de Celedomnio tenía un saldo de 400 euros y con la tutela ha llegado a los 20.000. +++++RAZONES PARA LA EXCUSA: no haber rendido cuentas y el maltrato a la madre. +++Escalona considera que no hay razones para la remoción y va a RECURRIR EL NOMBRAMIENTO DE LA COMISIÓN TUTELAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2020-07-14','Ana: Correo de Paula, TO, CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "...En cuanto a Mª Ángeles Santos Urbano, está deseando poder visitar a su padre en el pueblo. De momento vamos a esperar a que bajen las temperaturas e incluso motivar a su padre a que pueda venir a visitarla antes de la misma (posiblemente en Septiembre con una duración menor a 48 horas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2020-07-14','Ana: Correo de Paula, TO, CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "...Así mismo desde el SEPAD contactan con nosotros para concretar la zona de Residencia de Mayores que solicitaría Guadalupe Barragán. Tal y como acordamos con vosotros, y respondiendo a sus intereses, se ha concretado la zona norte de Cáceres (Hervás, Malpartida de Plasencia y Plasencia)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-07-16','(Pedro)Llamada de Esperanza, T. Soc. del ESM de Mérida (85832). +++Básicamente "agobiada" por las consatantes llamadas telefónicas de María Dolores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-07-15','TERESA El pasado día 10 de Julio actual, denuncia en esta Unidad Dª. MARIA DEL CARMEN DIAZ GONZALEZ, como Tutora Legal de su sobrina Lorena Sanchez Rodriguez (80102048V), la cual se halla actualmente internada en el Centro de Plena Inclusión de Zafra, sito en Avda. de la Fuente s/n. Se instruyen diligencias nº. 2020-839-933, por un supuesto Delito Leve de Lesiones, ocurrido en el referido Centro el día 06 de Julio actual, tratándose de una denuncia por una agresión física por parte de otra interna llamada Natalia Mejias Millón (DNI 77662143K), consistente en agarrar a la victima por el brazo, propinarle varios puñetazos en cara y cuello con el resultado de rotura de las gafas de Lorena. La tutora presenta Parte de Lesiones y fotografía de las gafas dañadas. Todo lo anterior para conocimiento de esa Comisión Tutelar y a la vez solicitar, si a bien lo tiene, remitir a la contestación de este correo Fotocopia de DNI de Natalia y si lo estiman oporturno, para inclusión en diligencias, de la documentación de Tutela y grado de discapacidad de Natalia. Un cordial saludo. ENVIO DOCUMENTACION SOLICITADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-07-16','- Amalia : Paso a derivar a MANUEL DOMINGUEZ MARTÍN a la zona de Cáceres : Este chico estaba tutelado por su padre y solicitó remoción del cargo , aunque en la práctica es quien ejerce toda la supervisión. Manuel vive en Moraleja desde hace más de 5 meses, con el padre y la madre , conflictos familiares por el tema del dinero , les pide continuamente. Tiene asignación semanal , y percibe PNC . De ella 100€ se transfieren a su hija , ya tiene unos 16 años y mantiene buena relación con ella. Estamos pendiente de plaza para piso supervisado de salud mental , está de los primeros en la lista , y esperemos que no tarden mucho en dársela . Tf de Manuel 677716154 tf. del padre 657656184 tf. de la hija 611070785','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-07-16','- Amalia : Paso a derivar a MANUEL DOMINGUEZ MARTÍN a la zona de Cáceres : Este chico estaba tutelado por su padre y solicitó remoción del cargo , aunque en la práctica es quien ejerce toda la supervisión. Manuel vive en Moraleja desde hace más de 5 meses, con el padre y la madre , conflictos familiares por el tema del dinero , les pide continuamente. Tiene asignación semanal , y percibe PNC . De ella 100€ se transfieren a su hija , ya tiene unos 16 años y mantiene buena relación con ella. Estamos pendiente de plaza para piso supervisado de salud mental , está de los primeros en la lista , y esperemos que no tarden mucho en dársela . Tf de Manuel 677716154 tf. del padre 657656184 tf. de la hija 611070785','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-07-16','-Amalia , derivo el caso a la zona de Teresa : Pedro Tomás Murillo y Maribel , su pareja , ésta no tutelada , se han trasladado desde el 1 de Julio a vivir a Monterrrubio de la Serena . Han alquilado un piso ( 250€ mes + fianza ) mientras arreglan la casa que Pedro tiene allí en propiedad. La nueva dirección es : Avda. Virgen del Carmen , Nº9 , 1ºA . Tere , yo ya he hablado con Futuex , han hecho una primera visita de la vivienda , el estado es de no habitabilidad , y habría que hacer un pto. de arreglo. Por el momento , creo que es mejor , que se queden de alquiler y si vemos que la cosa va bien arreglar la otra. Es conveniente que futuex los visite , los ayudará a hacer las gestiones para el traslado del ESM y del CEDEX , supervisión ... Si estás de acuerdo puedes pasarlo ya a Futuex , no les he querido dar la dirección actual hasta no decírtelo a tí. Por lo demás , están bien , él tiene una P. invalidez ( es revisable ) no recuerdo cuando tienen que volver a pasar por CADEX y ella también tiene otra pensión . Comparten gastos e ingresos pero no saben administrarlo. Se le da la pensión íntegra . El Trabajador Social , ya conoce todo el caso , he hablado con él bastante , y los conoce pq además es del pueblo . Colaborador , acompañó a Futuex a la visita de la casa .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-07-16','-Amalia , derivo el caso a la zona de Teresa : Pedro Tomás Murillo y Maribel , su pareja , ésta no tutelada , se han trasladado desde el 1 de Julio a vivir a Monterrrubio de la Serena . Han alquilado un piso ( 250€ mes + fianza ) mientras arreglan la casa que Pedro tiene allí en propiedad. La nueva dirección es : Avda. Virgen del Carmen , Nº9 , 1ºA . Tere , yo ya he hablado con Futuex , han hecho una primera visita de la vivienda , el estado es de no habitabilidad , y habría que hacer un pto. de arreglo. Por el momento , creo que es mejor , que se queden de alquiler y si vemos que la cosa va bien arreglar la otra. Es conveniente que futuex los visite , los ayudará a hacer las gestiones para el traslado del ESM y del CEDEX , supervisión ... Si estás de acuerdo puedes pasarlo ya a Futuex , no les he querido dar la dirección actual hasta no decírtelo a tí. Por lo demás , están bien , él tiene una P. invalidez ( es revisable ) no recuerdo cuando tienen que volver a pasar por CADEX y ella también tiene otra pensión . Comparten gastos e ingresos pero no saben administrarlo. Se le da la pensión íntegra . El Trabajador Social , ya conoce todo el caso , he hablado con él bastante , y los conoce pq además es del pueblo . Colaborador , acompañó a Futuex a la visita de la casa .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GRANADA'and edp.apellido1='CANO'and apellido2='MARQUEZ'),'2020-07-16','- Amalia : derivo el caso a la zona de Tere. Buenos días , comunicaros que finalmente , Granada Cano ha consentido ingresar en los pisos tutelados de LLerena, tras su alta hospitalaria. Teresa , te derivo el caso , tema económico tb visto. Solicité visitas de Futuex ( puedes leer todo en la intranet ) considero que por el momento es bueno que se mantengan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-07-16','(Pedro) Llamo a la Dra. Cabanillas una vez que ha atendido a Joaquín en consulta. +++No consigo hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-07-16','En relación con el expediente de venta de fincas, llamamos al teléfono del despacho de Abogados Pajuelo Abogados, de Badajoz, 924242814, para intentar hablar con Concha Gómez, la Abogada. No está. Nos atiende Raúl y nos coge los datos. Le pasará el mensaje y nos llama.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-16','En relación con el procedimiento de modifación de medidas, el Colegio de Abogados de Cáceres ha designado al nuevo abogado (Santiago Merino Jerez, 927214748 y 670650164)y procuradora (Mª Magdalena Luengo Simón). Van a adelantarnos la designación por vax, a la espera de recibirla por correo ordinario. +++Documento escaneado en expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-07-16','Ana: Correo de Alfredo Moreno; Residencia Padre Damián - Plasenzuela (resiplase@gmail.com): "Buenos días, Ana. Te mando el DNi de Doña Rosa Marin Laureano, como podrás ver esta caducado desde 1998. No se le ha renovado por lo incomodo y perjudicial que sería para ella y nosotros desplazarla a Cáceres, a parte del coste económico puesto que habría que trasladara en Ambulancia. Todo esto se habló con vosotros cuando ingreso en la Residencia y se tomo la deciión por ambas parte que lo mejor para ella era no desplazarla. De todos modos, me puedes llamar al teléfono: 619 45 92 81, si tienes alguna duda. Un Saludo." ······················································ mi respuesta "Buenos días, Gracias Alfredo. Yo no estaba en aquel entonces, hay algo anotado, pero yo interpreté que se esperaría a que fuera la unidad móvil de la policía nacional, así que pensaba que lo tendría renovado. Se lo he pasado a la compañera de la sección económica que lo necesita y según me diga ya hacemos. Si fuera necesario me pondría en contacto contigo. Gracias y un saludo." ························································· Correo de Juana, secc. ecca.: "...Necesitamos que se haga el DNI nuevo, si no imposible hacer nada...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-07-16','TERESA TRAS HABLAR CON CANDI FINALMENTE ABANDONA LA IDEA DE IR A BARCELONA, SOSPECHAMOS QUE REALMENTE NO SE IBA A IR E IBA A DAR USO AL DINERO PARA SUS COSAS MANDO EMAIL A M JOSE TS DEL SSB PARA COMENTARTLE EL TEMA DEL VIAJE Y PARA QUE VALORE EL TEMA DE SEGIR CON EL PISO PUESTO QUE NO LE ESTA DANDO USO Y ESTMOS MALGASTANDO ESE DINERO DE ALQUILER Y DE LIMPIEZA LE PROPONGO CORTAR SUMINISTROS PARA QUE NO PUEDA SEGUIR ALLI O BIEN HACER UNA REFORMA EN LA VIVIENDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-16','Ana: Correo de Ángel, Asesor Jurídico CTAEX: "...Te comunico que el Colegio de Abogados de Cáceres, después de enviarles aquella queja relacionada con la inacción llevada a cabo por el Abogado designado, en el procedimiento de modificación de medidas, escrito que remitimos el 4/11/2019, ayer designó al nuevo Abogado. Nos van a remitir la designación, primero por fax y luego por correo ordinario. A ver qué tal este…"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-07-16','TERESA HABLAO CON PATRICIA ES LA TS QUE LLEVA SU EXPEDIENTE, SE LE SOCIOLITA INFORME SOCIAL Y CI DE JUAN CARLOS PARA VALORAR RECURSO MAS ADECUADO DE CARA A SU SALIDA DE PRISION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-07-16','Ana: Correo de Sonia Generelo, Directora Res. Virgen de la Montaña, Casar de CC (virgendelamontana@grupociudadjardin.com): "Buenos días, le comunico que Pedro Román García García, tutelado por ustedes fue ayer dado de alta hospitalaria y se encuentra de nuevo con nosotros en el Centro. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-07-16','TERESA ARCHIVO citación que hacen desde el Juzgado a Aurora Parejo para: 1.- 29-7-2020, para la reconozca el forense y examen judicial, y deberá portar la cédula de citación que aquí remiten. 2.-preguntarle tanto a Aurora como a sus hermanos Antonio y Francisco (hermanos de la tutelada) sobre si están o no de acuerdo con la solicitud de internamiento involuntario. Tendrán que acudir el 25-8-2020, a 10:30h en el Juzgado de Villanueva nº1.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-07-16','Ana: Correo de Miguel Ángel, Dir. del CRR-CC (residenciadir@feafescaceres.com): "Buenos días, les remito el informe de revisión del Servicio de Traumatología de Juan Maria San Román Blasco con las recomendaciones del especialista. Le han realizan radiografías, él especialista nos informa que Juan Mario está teniendo una recuperación muy rápida y eficaz con las características que presenta el mismo y aun sabiendo que el reposo que está llevando a cabo no es el que debiese de realizar, que el hueso presenta buen estado y buena movilidad, pero aun así nos comenta que debe evitar cargar el tobillo y hacer deportes en general durante el próximo mes y medio. Nos citará de nuevo para principios de septiembre, llegará la cita por correo. Un cordial saludo." ·················· Guardo el informe en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-07-16','-Amalia : a la consulta sobre si puede contraer matrimonio. En relación a esta cuestión, habría que tener en cuenta dos factores: Si Ildefonso se encuentra estable, desde el punto de vista de su tratamiento médico, para tratar su esquizofrenia, y su consumo compartido de tóxicos y por tanto, su grado de discernimiento es de tal estado que le permita tener conciencia plena de su voluntad para casarse, tendríamos que aplicar lo que dice la Sentencia de incapacitación: “El curador no suple la voluntad del afectado, la refuerza, controla y encauza, complementando su deficiente capacidad, su función es más bien de asistencia y protección, prestando su apoyo e intervención para aquellos actos que haya que realizar el incapaz y que no tienen que ser únicamente de carácter patrimonial”. O bien, si Ildefonso se encuentra durante uno de sus brotes agresivos de su padecimiento, habría que aplicar lo que dice la Sentencia de incapacitación: “…y todo ello sin perjuicio ante la absoluta falta de la capacidad volitiva, y cognoscitiva del demandado, su voluntad en tales supuestos no deba ser complementada, sino suplida y sustituida plenamente por la de su curador, bajo el necesario control judicial respecto a aquellas decisiones que puedan afectar a alguno de los actos enumerados en el artículo 271 del Código Civil” (ente ellos la de celebrar contratos, como pudiera ser el de casarse, al ser susceptible de inscripción). Al margen de lo anterior, tendríamos que dilucidar, en el seno de la CTAEX, con todas las áreas afectadas, económica, social y jurídica, la conveniencia o no para Ildefonso, de llevar a cabo este casamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-07-16','Ana: Correo de Paula, T.O. del CRR-Plas. al ctutelar@ con informe para la rendición anual: "Buenos días, os envío de nuevo el informe de Conchi. Creo que se mandó también en papel, pero os lo remito de nuevo. Si bien ese informe recoge lo que ha sido la evolución hasta el día 2 de Marzo. Desde entonces y hasta ahora ha necesitado mucho apoyo profesional por lo que valoramos la necesidad de pasar de nuevo por CRR durante una época para intentar apoyarla con los medios suficientes. Cuando tengamos la respuesta del SEPAD respecto a esta cuestión os iremos informando. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-07-16','Ana: Según informe social para la rendición anual de 2020: Felisa continúa ingresada en la UHDAC. Está pendiente de valoración del grado de dependencia. No mantiene relaciones familiares de ningún tipo; NO ha recibido visitas ni llamadas desde su ingreso en la UHDAC en noviembre de 2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-07-16','(Pedro)Llamada de Don Pedro Bono, abuelo de Alejandro. +++Le han citado en el ESM el lunes 20 de julio a las 09:10h. +++Sigue insitiendo en la necesidad de "comprarle un piso a su nieto".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2020-07-16','Ana: Según informe de la Aso. Vera para la rendición de 2020, Antonia presenta notables carencias en su cuidado e higiene personal, pero desde hace unos meses permite que el personal del centro le supervise en estas cuestiones. Continúa participando en las actividades de limpieza del centro y su participación en el resto de actividades está comenzando a ser más notoria, aunque necesita que le insten a ello. Asiste al programa PADDI de Salud Bucodental y a Salud Mental. Presenta mayor estabilidad conductual. Ligera mejoría en el trato con sus iguales. Inestabilidad en la aceptación de normas. Requiere supervisión conductual continuada. ·· Escasa relación con su familia, a pesar del interés que muestra Antonia. En navidad acudió a casa de su hermano en Miajadas, pero no recibe visitas. Su madre reside en un geriátrico y ella desea ir a verla. ·· Semanalmente retira su asignación del banco acompañada de la T.O.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-07-16','miguel, llega por carta un escrito de Damian junto con una cédula de citación judicial para el 14-10-20 Y le contesto: Buenas tardes Damian, comentarle que nos ha llegado la cedula de citación judicial en el día de hoy. En cuanto al requerimiento que indica en su escrito indicarle que no haremos tal requerimiento tal como le indiqué anteriormente hasta que podamos recalcular la cantidad exacta que se le debe para lo cual seguimos pendiente de que el Ayuntamiento nos mande la relación de pagos recibidos, con las correspondientes fechas tanto efectuadas por el Ayuntamiento como las efectuadas por el inquilino. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-16','miguel, acudo personalmente al juicio rapido por daños leves 351/19 del tutelado donde quemó un colchón, asumiendo los cargos que se le imputan. La sentencia consiste en una multa de 6€ por día durante 30 días y 108€ de los daños. ************************************************************ se ha suspendido el procedimiento de amenazas de la semana que viene por que la enfermera ha retirado la denuncia. ****************************************************** Me comenta que le vayamos tramitando la modificación de medidas para dejar de pagar a sus hijos la pensión que les abonaba mensualmente y que dice se la queda su mujer de la que está, según comenta, divorciado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2020-07-16','miguel, a petición de la parte económica hablo con su hermano Fernando quién nos reclama unas cantidades que dice corresponden a su hermana fallecida, la cual falleció antes que su madre y portanto ese dinero era de su madre no de los hermanos. Se lo explico, así como también le recomiendo que vaya a un abogado y nos reclame ese dinero ya que sin sentencia judicial no podemos dar ninguna cantidad de la cuenta a que se refiere de Caja Almendralejo donde está ella y su hermano Juan Manuel de titulares y por tanto él no tiene ningún derecho sobre dicha cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2020-07-16','miguel, hablo con la abogada MARIA DEL CARMEN GOMEZ GALAN 924-544555 (email: 1000@icaba.com), quién me comenta que hubo un error en la venta de una finca que vendió la hermana fallecida de Juan (me lo comenta porque Juan es el único heredero, según dice, de su hermana Maria). Le pido documentación y me dice que sólo tiene escrituras antiguas de compraventa, pero nada de testamentaria de Maria (testamento, certificado de defunción, y últimas voluntades), para poder hacer la herencia. En cuanto a la compraventa que menciona parece ser que se vendió una finca y se segregó y a esos compradores que adquirieron parte les pusieron mal el número de referencia catastral, así que la indico que lleve todo a notaria y que allí me indiquen si tenemos o no que ir a firmar alguna subsanación (lógicamente primero tendremos que estar legítimados ya que esa venta la hizo su hermana María hoy fallecida y no tenemos nada hecho de la herencia, porque como digo no tenemos ninguna documentación)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-07-17','(Pedro)Llamada de Joaquina,pareja de Ildefonso (665-940924). La que llama es Joaquina, aunque se siente a alguien (¿Ildefonso?) que le hace algunas indiccaciones por detrás. Él no interviene en ningún momento.(Ver ibncidencias del mes de marzo). +++"Mi madre nos ha hechado de casa y estamos durmiendo en un coche. Acudió la Policía y todo, pero no quise poner dencuncia. Hace una semana que salí del Psiquíatrico. Ingresé porque mi madre me pega constantemente". +++"Por favor, mándanos 2000 euros para alquilar un piso. Nos piden dos meses de fianza (1000 euros) más 500 euros del primer mes -¿y los otros 500?- para pagar cosas que les debemos a mis padres..." +++Les propongo que acudan a un hostal de momento, pero se niegan a ello. +++Hace unos días Ildefonso llamó para pedir dinero para comprar un ordenador, una mesa, etc. para Joaquina, para que pudiera estudiar...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-17','(Pedro)Llamada de José Manuel. +++Acaba de llamar a su Psiquiatra y -dice- que le ha dicho que "...se tiene que cambiar de Psiquiatra porque a él no le hacen caso...Y que no va a tener un centro en el que quedarse." +++Pregunta si se va a reunir la suxbcomisión. +++Termina diciendo: "Yo me voy a un CRR, mis hermanos mque vendan el piso y que ingresen en mi cuenta la parte que me corresponde..." ++++++++++++++++++++++++++++++Hablo con Mª Luz (Secc. SM): no hay prevista de momento ninguna subcomisión. ··········································································· Ana: Recibo llamada de José Manel, el contenido es el mismo que ha mantenido en la conversación con Pedro. Habla también sobre le juicio de ayer, dice que cree que fue bien, sólo le han puesto una multa. Por otra parte dice que ahora quiere comprar unos auriculares, le emplazo a hablar con el area economica, pero de todos modos le digo que no se lo van autorizar, no es algo necesario y además ahora tiene que añadir la multa a sus gastos habituales. *En cuanto a su demanda relativa a la manutención que abona a sus hijos, por la que también pregunta, le informo de que ya le han asignado nuevo abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-07-17','Ana: Recibo llamda de Isabel Pino, TS del SSB de Miajadas (927 347 000), ha tramitado la ayuda para suministros mínimos vitales para Vanesa. Así mismo está elaborando informe por Violencia de Género. *A petición suya, le envío por mail (ipino@miajadas.org) el Certificado de Discapacidad y el Dictamen Técnico del CADEX, pues no lo tienen en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-07-17','(Pedro) Correo del CRR de Mérida (17-07-2020). +++Ángel Pinilla: Esta semana tenía concertada una visita a la residencia de su madre. No ha podido ser porque, como sabéis, están restringiéndolas. Cuando le trasladamos la noticia estuvo un poco afectado pero después lo comprendió y se comunicó telefónicamente con ella, lo cual le tranquilizó bastante. Por lo demás, en la misma línea que semanas atrás.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-07-17','(Pedro) Correo del CRR de Mérida (17-07-2020). +++Luisa Rodríguez: Por dificultades en la convivencia con su compañera de habitación (esto viene siendo muy habitual en ella durante su estancia en el CRR) se ha cambiado con otra persona. Menos agitada que anteriormente aunque seguimos percibiendo "un poquito alta". Hoy he contactado con C.S Mérida Norte y me comentan que su Psiquiatra de referencia está de baja. De momento seguimos pendientes de ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-07-17','(Pedro) Correo del CRR de Mérida (17-07-2020). +++Antonio Merchán: Mucho mejor con el cambio de medicación, más adecuado y "tranquilo".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-07-17','(Pedro) Correo del CRR de Mérida (17-07-2020). +++Mª Dolores Fernández: Refiere que el comportamiento de un compañero en concreto del CRR le afecta. No es que sea un conflicto o dificultad "personal" entre ambos, si no que ver la forma de afrontar las situaciones de su otro compañero le entristece. Por otro lado, comenta escuchar peor que antes se lo traslado a T.O para que apoye en esta cuestión. No me ha vuelto a decir nada del tema casa/residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-07-17','(Pedro) Correo del CRR de Mérida (17-07-2020). +++José María Guillén: Bien, con sus demandas como viene siendo habitual, nada extraordinario. En la misma línea que en comunicaciones anteriores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-07-17','Ana: Llamo varias veces a lo largo de la mañana tanto a la Res. Padre Damián - Plasenzuela (927 31 37 45) como al teléfono de Alfredo (619 45 92 81)sin éxito. Dejo 2 mensajes en el buzón del voz del móvil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2020-07-20','Ana: Rosa Bravo, Admvo. CSS-Plas.: nos remite Cédula de citación judicial para el día 28/10/2020 a las 9:00, para prestar declaración en calidad de investigado, sobre delitos de abusos sexuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-07-20','Ana: Llamo a Alfredo - Res. Padre Damián - Plasenzuela (927 31 37 45 // 619 45 92 81): En relación a la renovación del DNI de Rosa, Acordamos que llamaremos a la Policía Nacional, Equpio de CC, para que envíen una Ud. móvil a la Res. para renovar el DNI. Ellos lo han intentado en otros casos y no se la envían. ········································································ Llamo a la Res. Padre Damián; me dicen que Alfredo está de viaje. *Le envío un correo (resiplase@gmail.com)solicitando fotografía actual de Rosa, Informe médico y Certificado oficial de la farmacia, para aportar con el formulario de solicitud de equipo móvil para la renovación del DNI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-07-20','TERESA Teresa queria comentarte la posibilidad de que Beatriz hicera una visita a su hija en agosto. Ya lo pensais y me decís. Solo por dejarlo planteado de cara a mi vuelta de vacaciones. Iría acompañada de una auxiliar y velaría en todo momento por que se respetaran las medidas de seguridad Ya me dices.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-20','TERESA: NOTA FUTUEX El pasado 13 de Julio se recibe una llamada de Ángela, la dueña de la tienda de alimentación de la calle de Carmen Rubiano, comentando que la tutelada tiene una deuda allí, hoy nos ha mandado una pequeña nota y asciende a 270 eu (le solicitaremos una factura ) Cuenta que es la primera vez que Carmen ha hecho algo así porque siempre que ha dejado algo a deber, lo ha pagado cuando ha cobrado su pensión. Se le pide a Ángela que, en la medida de la posible, no permita que Carmen se siga llevando productos de su tienda cuando no tiene dinero. Ella dice que a veces se siente muy violenta porque cuando le dice a Carmen que no se lleve el vino, ella se pone agresiva y lo coge de las estanterías igualmente. Pero también se lleva carne y otros productos de alimentación que no necesita porque le llevan la comida y la cena. El pasado 14 de Julio se recibe una llamada de Granada, una vecina de Carmen que trabaja en un estanco. Granada comenta que hace un mes que ella le está llevando el tabaco a Carmen a su casa porque ésta se lo pidió y a ella no le cuesta trabajo. Y siempre se lo ha pagado sin problema, pero ahora tiene una deuda de más de 60€ en el estanco y Carmen la llama todos los días para que le lleve la lata que cuesta 3,90€ y cada tres días una caja de cigarrillos vacíos que cuesta otros 3€. Granada comenta la adicción tan grande que tiene la tutelada ya que se fuma la lata de tabaco de liar en un día cuando normalmente dura tres, como mínimo. Y su pregunta era si seguía llevándole tabaco a su casa cuando se sabe que no lo va a poder pagar y la deuda va a seguir subiendo. Además tampoco está del todo segura de que los dueños del estanco quieran seguir vendiéndole si no va a pagar en unas cuantas semanas. Se llama a Carmen y se le pregunta cómo se suele organizar con el dinero, ella cuenta que este mes ya no le queda nada porque se lo ha gastado todo muy rápido pensando que tendría la paga extra como todos los años. Se le recuerda que ahora su situación ha cambiado y solamente cuenta con 250€ al mes, que para su tabaco y para comprar algunas cosas que puedan surgir, es más que suficiente. Se le pregunta si sabe que tiene una deuda en la tienda y otra en el estanco y dice que si, pero que no sabe a cuánto asciende. Se le pide que reflexione un poco y entienda que si ahora mismo no tiene dinero, no debe ir a la tienda a seguir comprando comida o vino. El vino porque es muy perjudicial para su salud y la comida porque no le hace falta ya que le llevan comida y cena a casa todos los días. Ella escucha pero no comenta nada al respecto. Y con relación al tabaco, se le pide que intente fumar menos ya que si sigue al ritmo de siempre, cuando acabe Julio tendrá una deuda muy grande en el estanco. Con respecto al tabaco ella reconoce que fuma mucho pero comenta que es algo que no puede evitar y se sobreentiende que el consumo que tiene no lo va a reducir. Además se sospecha que ha bebido alcohol porque se echa a reír sin motivo en mitad de la conversación y llega a llamarnos peluche o algo parecido mientras se habla con ella. Cuando se le pregunta si sigue bebiendo vino, contesta rápidamente que no, pero en la tienda de su calle confirmaron ayer que sigue comprando unos cuantos cartones al día. Cuando se habla con Carmen del gasto de tabaco, ella cuenta que gasta una lata de 3,90€ al día y cada tres días, una caja de cigarrillos vacíos que cuesta 3€. Por lo que mensualmente, gastaría entre el tabaco de liar y los cigarrillos vacíos unos 215€ aproximadamente, contando que el mes sea de 31 días como Julio, por ejemplo. Por lo que una opción sería hablar con el estanco, explicarle la situación actual de Carmen y preguntar si sería posible que estas dos últimas semanas de Julio, Carmen pudiera seguir llevándose el tabaco sin abonarlo y a finales de mes, pagar la deuda completa por transferencia al estanco. Lo mismo podría hacerse con la tienda de alimentación, se podría hablar con la dueña para que Carmen pudiera ir a por cosas de primera necesidad a la tienda y cuando acabara el mes, se adjuntaría la deuda a la comisión y se abonaría por transferencia. Porque si el pago de las dos deudas pendientes, se abonara ahora, se seguiría acumulando deuda estas dos semanas de Julio y cuando volviera a cobrar y las pagara, se volvería a quedar sin dinero y entraría en un círculo vicioso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-07-20','(Pedro)Varias llamadas de Ildefonso y Joaquina por problemas para sacar el dinero en el banco. Querían sacarlo en la sucursal de Palafoix cuando él pidió que se lo enviáramos a la de Malgrat de Mar. +++LLAMADA DE LA POLICÍA LOCAL de Palafolls, Agente 141 (608-740404). +++++Han tenido que intervenir ya en dos ocasiones por alteración del orden público. Dice que ha ido a sacar 300 euros y que no se le han dado en Palafolls. Se indica que es en Malgrat de Mar donde él dijo que quería sacarlos, pero hoy hay mucha cola y no quiere esperar. +++++La Agente lo dirige a la sucursal de Malgrat de Mar y" si tiene que esperar tendrá que esperar..." +++++Explico los términos de la curatela para que no haya dudas acerca de las competencias de la Comisión Tutelar. ++++++++++++++++++++++++++++++++++++Correo-e de BBVA Zafra. +++Buenos días Juana, agradeceríamos que desde CTAEX realizarais alguna gestión o contacto con el cliente. Como le comentaba a la oficina de Zafra y al compañero Carlos (gracias por las gestiones!), muestra una actitud violenta, gritos, golpes fuertes en persiana y puerta, amenazas con ir a buscar armas o gasolina....Hemos avisado policía y seguridad del banco, pero esta situación es cada semana e incluso más de un día por semana, y varias veces al día. Durante esta media mañana ya ha venido varias veces. Nos acaba de indicar la polícia que si vuelve a venir, les avisemos y le pondran una denúncia por alteración del orden público. Gracias de antemano. Un saludo Anna Missatge de ZAFRA-ALVAREZ CHAMORRO (G010382A) >g010382a@bbva.com> del dia dl., 20 de jul. 2020 a les 11:06: Buenos días, Anna Te reenvío comunicación de tutelados, y nos indican que no se tiene que entregar al tutelado, y en el mismo indican que puede disponer 225 € semanales. Saludos. ---------- Forwarded message --------- De: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Date: lun., 20 jul. 2020 a las 10:52 Subject: RE: 80044285F ILDEFONSO GARCIA RODRIGUEZ To: ZAFRA-ALVAREZ CHAMORRO (G010382A) >g010382a@bbva.com> ++++++++++++++++++++++++++++++++++++++++++++++++++++++Intentamos ponernos en contacto con Ildefonso tanto en el teléfono actual (665-940924) como en el que tenía anteriormente (695893358). En los tres intentos realizados (dos con con cada uno y en dsitintos momentos) ambos estaban "no disponibles en este momento" +++Hablo con Ildefonso finalmente (llama él). "Afortunadamente no ha pasado nada con la Policía Local, pero si tocan a mi chica..." +++++No hay forma de hacerle entender que el dinero se ha enviado a la sucursal que él nos dijo: "no vo y a ir, mejor que se acumule en Margat, así en vez de comparle un anillo de oro a mi chica se lo compro de platino..." Intento que escuche, pero no hay manera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-07-20','Ana: Conversación con Damián (622 834 876), vuelve a hablar sobre la parafilia, de la que me ha informado en otras ocasiones y sobre la que escribe un email que remitió el pasado viernes 17 por la noche. El médico especialista que le atendía en Málaga es Fco. ("Paco") Cabello Santamaría. ································································································································ Llamada a Ana Benavente (620 275 323 = personal // 927 458 036): Damián accedión al CRR por Emergencia Social, la tramitó Pilar Martín, TS del ESM-CC. *En ppio. no creemos que haya problemas con la plaza a pesar de no haber obtenido grado dependencia en la valoración. **Dada la disconformidad de Damián, quién considera que no se le ha valorado ciertos aspectos, como por ejemplo la parafilia que presenta, acordamos que Ana Benavente le citará y le emplazará a solicitar la revisión del grado más adelante. ···················································································································· Comprobado en SIDEX: Resolución de Dependencia de fecha 21/01/2020 = SIN GRADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-07-15','Ana: Llamada de Damián (622 834 876), expresa está muy disgustado pues ha recibido la resolución de valoración de dependencia y el resultado es "SIN GRADO". No está nada conforme pues considera que no se han tenido en cuenta ciertos aspectos y problemas que tiene y le da miedo el hecho de poder perder la plaza. *Le tranquilizo al repecto, él no ha accedido al CRR por dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-07-20','TERESA RECIBO LLAMADA DE LA TRABAJADORA SOCIAL DEL AYUNTAMIENTO DE PALAFOIS. HA PASADO ATI POR SU DESPACHO DEMANDANDO UN NOTARIO PARA QUE PASE SU PENSION A SU PAREJA JOAQUI PUESTO QUE EL VA A ENRAR EN PRISION TAMBIEN DEMANDA UN PISO YA QUE LOS PADRES DE JOAQUI LOS HAN EHCADO POR UNA DISCURSION LA TRABAJADORA SOCIAL LLAMA PARA INFORMARSE DEL CASO, LE EXPLICO UN POCO POR ENCIMA EL CASO DE ILDEFONSO Y LE COMENTO QUE AMALIA ESTA DE VACAIONES QUE LA LLAME LA SEMANA QUE VIENE QUE ELLA LE DARA MAS DETALLES SOBRE EL CASO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-07-20','Ana: Recibo correo Francisco Acedo, Albacea testamentario de Juliana (francisacedo@gmail.com): "Estimada señora, me dirijo a usted como albacea testamentario de Doña Juliana Paula Centeno Rodríguez, fallecida el pasado 24 de abril en Cáceres. Me ha dado su contacto Mariola, la directora de la Residencia San Jorge. Juliana ha dejado instituidas en su testamento como herederas de los bienes que se encuentran en su domicilio a instituciones de caridad. Para poder proceder a ejecutar su voluntad me pongo en contacto con usted para ver cuál es el protocolo que se debe seguir. Le ruego se ponga en contacto conmigo a través de este medio o telefónicamente en el número 651111710. Le agradezco su atención y, a la espera de su respuesta, le envío un cordial saludo, Francisco Acedo" ································· Se lo reenvío a Ángel y Miguel, Asesores Jurídicos CTAEX, para que sean ellos quiene se pongan en contacto y le den respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-20','Ana: Cooreo de Toni-Futuex con las últimas incidencias protagonizadas por José Manuel: "19/07/2020: Se recibe llamada del catering que se ha contratado para que se le reparta la comida de forma diaria, explicando que de forma habitual tienen problemas para dejarle la comida en casa porque no consiguen que abra la puerta, bien porque se queda dormido o porque no está en casa a la hora del reparto, con el consiguiente retraso que genera al repartidor en su ruta diaria. Desde este servicio le han pedido una llave del portal para evitar esos problemas, pero el tutelado no se la ha facilitado. Finalmente, este domingo 17 el tutelado le ha transmitido al repartidor que no le sirvan más menús. 20/07/2020 Se contacta con el tutelado que confirma que ha indicado al catering que no quiere q se le reparta más la comida de los menús, expresa quejas sin fundamento puesto que el servicio no es a la hora que le apetezca cada día como el pretende sino un reparto en ruta que se hace cada día a la misma hora y es su responsabilidad recibirlo. Se contacta con el catering y se confirma que hoy lunes no se haga el reparto tal y como ha pedido el tutelado, pero se mantiene la preocupación para garantizarle una alimentación adecuada al menos al mediodía que es el servicio que se está cubriendo en la actualidad, desde el catering se muestran abiertos q que el tutelado recoja la comida en el local que tienen en C/ Camino llano o bien que el reparto se hacía dos veces a a la semana en lugar de hacerlo a diario. El tutelado se muestra conforme con se reduzcan los días de reparto a dos en lugar de ser diario, por lo que se tomará esa medida para evitar conflictos y malentendidos que pueda provocar. Por otro lado en conversación con José Manuel comunica que a acudido al banco a primera hora de la mañana a retirar la asignación pero que ha pedido que le entreguen 200€ y se los han dado, explica que los ha invertido en comprar una Televisión de segunda mano, no especifica a quien, tan sólo que es un particular, por lo que no se puede contrastar la información, se le transmite que no debía haber sacado más dinero del autorizado y que puede tener consecuencias puesto que no es lo acordado con él, también se le insiste en que la cancelación del catering no implicaría un aumento en su dinero semanal para gastos diarios."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-07-20','Ana: Gema Lorenzo, TS del SSASB, de la Mancomunidad de la Vera (ssb.gema@mancomunidaddelavera.es // 927172208), remite por mail al ctutelar Informe Social para rendición anual: "...Pedro y Eugenia viven juntos desde que salieron del CRR. Viven en una vivienda social propiedad de Pedro. La vivienda consta de dos pisos. Tiene cocina, dos baños, tres habitaciones y salón. Cuenta con equipamiento básico. En la vivienda hay desorden y falta de higiene. Eugenia comenta que es ella la que limpia y” lo va haciendo poco a poco”. Con respecto a lo económico Eugenia comenta que ella le da todo el dinero a Pedro y es él, el que lo administra y le va dando a ella a medida que lo necesita. Pedro actualmente está ingresado en el hospital de Plasencia. Eugenia comenta que ha sido una subida de azúcar y se ha caído por las escaleras. Está valorado por dependencia con Grado I. Se le ha ofrecido Servicio de Ayuda a Domicilio por dependencia, 20 horas al mes, que hasta ahora han rechazado. Necesitan apoyo para las tareas doméstica. Desde estos SSASB y a raíz de la entrevista mantenida con Eugenia y visita domiciliaria, se considera importante y necesario que acepten el PIA de dependencia, Servicio de Ayuda a Domicilio del SEPAD, para atención domestica y supervisión"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-07-21','TERESA LLAMA JOAQUI LA PAREJA DE ILDEFONSO PARA PEDIR UN EXTRA DE 3500 ERUOS PARA ALQUILAR UN PISO. LE COMENTO QUE AMALIA ESTA DE VACACIONES Y QUE ESA CANTIDAD TAN ELEVADA HAY QUE PEDIR AUTORIZACION JUDICIAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-07-21','(Pedro)Conversación con Marili, Directora del C.O. de Miajadas (927029632 y 21959). +++No cree que Steve pueda llegar a ahorra una paga:el 75% se va en la plaza de Pisos Tutelados y le quedan 75 euros. +++Nos enviará PRESUPUESTO de gastos habituales para intentarlo y sus datos personales para autorizarla a sacar dinero de su cuenta. Lo enviará a ctutelar, asunto Secc. Eco. ·································································· **La PFHC son 395,60 €, abonando el 75% a los PP.TT. (= 296,70 €), le quedarían 98,90 € xa otros gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-21','Ana: Correo de Alberto, Jefe Secc. Ecca. a Toni-Futuex: "Buenos días Toni. En relación con el reintegro indebido de ROMERO MEDIAVILLA, a partir de la semana que viene se baja su asignación a 20 €/semana. Esta bajada se aplicará hasta la semana del 05/10/2020, en la cual volverá a cobrar los 40 €/semanales. Por favor comunicádselo al tutelado. Un saludo. Gracias!!!" ························································································································ Recibo llamada de Pilar Martín, TS del ESM-CC (54612): Le ha llamado José Manuel dicíendole que sólo le quedan 20 € y necesita más, le ha dicho que con eso no puede seguir. *Informo a Pilar acerca, tanto del Juicio de la semana pasada y la correspondiente sanción económica y de la retirada, no autorizada, que realizó ayer de 200€. *No se le va a dar más dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-07-21','(Pedro)Llamada de José Manuel (620673371). +++Ya le ha llegado la cama articulada. +++Dice que se le ha estropeado el calentador y no puede bañar a su abuela. Pregunta si puede avisar al técnico. Le digo que sí, pero que antes de repararlo que le haga un presupuesto y lo remita a la Comisión para su aprobación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-07-21','Ana: Llamo a Orfandad (927 62 00 56), Aitor está dado de alta en la Pensión de Orfandad desde el 25 julio de 2005. Su padre, Santiago Moreno Araujo, falleció en accidente laboral. En Control de Pensiones (927 62 00 49), Miguel Cillán, Jefe de Secc, confirma que es la madre de Aitor quien está percibiendo la pensión: 226,24 €/mes x 14. El domicilio que les aparece es C/Ntra. Sra. de la O de Navas del Madroño. ······················································································································· Cumplimento modelo de COMUNICACIÓN CAMBIO DE CUENTA bancaria al INSS, recabo firma del Gerente y lo pongo para REGISTRO DE ENTRADA junto a la documentación pertinente. *Así mismo, redacto oficio para solicitar que añandan, a efecto de comunicaciones, la dirección de la CTAEX. Lo pongo también para registro. ··················································································································· Comunico a Alberto, jefe secc. ecca. el cambio de la pensión para que lo tengan en cuenta, tanto por Aitor como por Felisi, su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-07-21','TERESA RECIBO EMIAL DEL CRPS EN EL QUE ME ADJUNTA UNA CARTA ENLA QUE SE RECLAMAR HONORARIOS POR UNA DENUNCIA DE VILOLENCIA FAMILIAR, SE LO PASO A LOS JURIDICOS Y LA ARCHVIO EN SU EXPDTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2020-07-21','Ana: Correo de Miguel Ángel, director del CRR-CC: "Buenos días, nos han comunicado desde el Hospital San Pedro de Alcántara debido a la operación de cataratas a la cual está a la espera Feliciano Borreguero Cambero. Nos comentan si tenemos más interés en realizar la intervención en el mes de agosto en la clínica Quirón o por el contrario seguir en lista de espera. Les derivamos a que vuelvan a llamar mañana en horario de mañana cuando esté el equipo técnico o devolver nosotros la llamada al número 927 62 13 70. Desde el Recurso creemos que es más conveniente poder agilizar la misma y que se le realice en la clínica Quirón en el mes de agosto pero necesitaríamos la autorización para poder informar al número de teléfono que nos facilitaron ayer e informarles sobre la decisión tomada. Un cordial saludo." ·············· Mi respuesta: "Buenos días Miguel Ángel, Por nosotros no hay inconveniente en que se agilice y se realice la intervención en la Clínica Quirón. En cuanto a la Autorización (Consentimiento Informado entiendo), ¿te refieres a los que ya enviaron en diciembre? ¿o es otro nuevo? En este último caso, cuanto nos lo hagan llegar, ya sea desde el hptal, la clínica o a través de vosotros, se pondrá para la firma del Gerente y se devolverá firmado. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-07-21','TERESA: LLAMADA DE LA TS DE BARCARROTA José Florencio está de nuevo buscando centro, ahora a Jerez de los Caballeros, esta mañana he recibido llamada de Fernanda, TS de SSB de Barcarrota.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-07-21','Llama José Vicente interesándose por la posibilidad que puedan reconocerle algún beneficio penitenciario y poder salir. Le resta por cumplir un año y seis meses de pena. Hablamos con el subdirector de Régimen del Centro Penitenciario de Badajoz (Raúl Gil, 924289105). Va a consultarlo con el Director (José Manuel Guerrero), también va a hablar con José vicente, para ver cómo se encuentra y con lo que decidan nos llaman.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERNANDO'and edp.apellido1='FEBLES'and apellido2='GONZALEZ'),'2020-07-21','Ana: Recibimos de la Dirección General de Serv. Soc., Infancia y Familias, escrito, en relación a su PNC, solicitando que en 10 días presentemos la siguiente de documentación para su expte.: Nº de cuenta bancaria a nombre del del titular y de del representante legal (ambos deben ser titulares) y Alta de terceros. ······························································································· Pido el primero por mail a las compis de la secc. ecca., cumplimento un modelo de alta de terceros que pongo para la firma y les pido que lo lleven al banco una vez firmado. *Solicito a Juan Pedro y Julio que se encarguen de remitirnos a PNC, pues la semana que vienen yo no estaré.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILIA'and edp.apellido1='SALGADO'and apellido2='DURAN'),'2020-07-21','Ana: Pongo para registro de salida oficio para enviar CI. Pido a Julio, que si llega de registro, lo envíe el jueves al CSS-Plas. tal y como nos han solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-07-22','(Pedro)Llamada de José vicente. +++SE le informa de la conversación mantenida con la Dirección del Centro Penitenciario en el día de ayer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-07-22','Ana: Corre de Miguel Ángel, Director del CRR-CC(residenciadir@feafescaceres.com): "Buenos días os informo sobre un accidente que sufrió Félix Valle Simón en su localidad de procedencia cuando estuvo pasando el fin de semana con sus progenitores. El día 14 regresa al Centro y nos entrega el informe de la prueba del COVID-19 dando negativa en la misma y una lista de las personas con las que se ha estado relacionando los últimos días. Nos indica que ayer le dio un golpe un coche, por lo que viene cojeando. Trae una crema antiinflamatoria, que se está aplicando para el dolor de pierna. Se le acompaña el día 17 a su MAP y deciden hacerle una radiografía por urgencias del Hospital ya que le observa su médico de familia que lo tiene bastante inflamado y nos dan la documentación adjunta en mail para que se le rellene desde la Entidad. Os informo que el plazo de presentación de la misma vence el día 27 de julio. Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-07-22','(Pedro)Llamada de Eva, T. Soc. de la Residencia "Virgen de la Soledad de las Hermanitas de los Ancianos Desamparados" en Badajoz (924-255503). +++Llamaba interesándose por el estado de los trámites de la venta del inmueble. +++Se le informa de los últimos trámites realizados. +++Comenta que se le va a pagar el recibo del seguro de deceso y algunas otras cosas: le pido que guarden todas las facturas al respecto y se le abonarán una vez realizda la venta (si es posible).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-07-21','En relación con la asistencia jurídica gratuita para el inicio del procedimiento de autorización judicial de venta de inmuebles, hablamos con la Comisión de Asistencia jurídica gratuita de Badajoz, porque estábamos pendientes que emitieran la resolución definitiva del reconocimiento del derecho. Nos la han enviado por correo electrónico y nosotros a su vez, se la hemos remitido al Abogado designado, para que inicie el procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-07-22','Llama la policía local de Zalamea de la Serena, interesándose por el ingreso involuntario de Guillermo, le comunicamos que el Auto no es firme aún. Nos traslada su preocupación por la situación en la que se encuentran los dos hermanos en el domicilio. Posteriormente, llamamos al Juzgado de Castuera, para preguntar por la firmeza, ésta cumple el 28/7. Les facilitamos nuestro número de fax para que nos la remitan a la mayor brevedad posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-22','(Pedro)Llamada de José Manuel. +++Dice que su hermano le ha puesto un calentador que ha comprado por Walapop: "Y eso me lo ahorro...." +++Pregunta por el cambio de medidas y por el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-07-22','Ana: Pilar Cerrillo, TS Grupo Ciudad Jardín, nos remite, vía mail, para el inventario, copia del DNI, tarjeta de ISFAS e Informe Social. Según este último, Mateo reside en la Residencia Virgen de la Montaña de Casar de Cáceres desde el 10/06/2012. Mateo padece una esquizofrenia paranoide, pero desde que está en el centro no ha manisfestado ningún trastorno de comportamiento. Está valorado de Dependencia con Grado I. A día de hoy sólo necesita supervisión y apoyo para algunas ABVD. *Percibe una pension de jubilación de Clases Pasivas ISFAS de 1418,95 x 14. Abona una plaza privada de 1546,46 €/mes. Y una pensión compensatoria a sus hijos de 800€/mes. (*Uno de sus hijos falleció hace algunos años, por lo que esto habría que revisarlo). **Tienen contraída una deuda con la residencia de unos 25.000€. ·· En cuanto a su otro hijo, no mantiene ningún tipo de relación, a consecuencia de un grave suceso acaecido hace muchos años y por el que cumplió condena de 20 años en prisión. Red de apoyo social en quiebra, su hermano y anterior tutor falleció y su hermana no puede asumir el cargo. ·················································································································································· Pongo en conocimiento de Ángel, Asesor Jurídico, la situación, a través de e-mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-07-22','Ana: Llamada de Damián (622 834 876): Ana Benavente, TS del ESM-Plasencia, le ha llamado y dado cita para el día 6 de agosto a las 10 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-07-23','(Pedro) Llamada del padre de Adrián. +++Enfadado porque le habían dicho en el Centro que "Pedro no autoriza las vacaciones de Adrián...¿por qué?...?Le xplico que no soy yo quien autoriza o no esas vacaciones, sino la Ctaex. Le explico las condiciones que se deben dar si finalmente Adrián va a su casa de vacaciones: "...Sí, ya, a mi otro hijo también le han hecho el test de virus..." +++Quedo en que hablaré con Vera para ver la postura del centro en este tema. ++++++++++++++++++++++++++++++Llamo a Cristina. Me dice que la postura del centro es que nadie salfga de vacaciones este año porque ellos no podrían garantizar el aislamiento en caso de algún positivo y, además, en el caso de Adrián las condicones higiénicas de la vivienda, con varios perros en el mismo, etc. no lo aconsejan. +++Dado que es una decisión del centro, propongo a Cristina que, en respuesta a la carta recibida de Gerencia, se puesiera en conocimeinto de esta la decisión adoptada. Le parece oportuno hacerlo así.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2020-07-19','TRASLADO "Se comunica a esa Comisión Tutelar de Adultos que el interno JUAN..., ingresado en este Centro y tutelado por esa Comisión, será trasladado al Hospital de Mérida, en fecha 19/07/2020". CSS de Mérida, dixit.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2020-07-23','(Pedro)Converscaión con Mª carmen, Directora del la Residencia Jesús Nazareno. +++hablará con el marido de Dª Paula con la finalidad de averiguar si él quiere seguir pagando la totalidad de la plaza desde la cuenta consjunta (en ella se ingresa la Prestación Vinculada al Servicio) o si necesita que desde la cuenta de su mejer se pueda hacer alguna contribucion a la de ambos. +++Mª Carmen comenta que él está tratando tambié de ingresar en la misma residencia, pero que están tratando de retrasarlo (no refiere el motivo). +++Pido a la Directora también que trate de confirmar con el marido la existemncia de alguna póliza de deceso y, en el caso de existir, que nos envíen una copia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-07-23','(Pedro) Llamada de Ildefonso. +++"Nos queremos volver a Extremadura..." +++++Respuesta: pues coges un tren dcomo otras veces y ya está" +++"Es que tenemos un coche de gran cilindrada y lo queremos poner a buen recaudo..." +++++"Pues en eso no te puedo ayudar..." +++"Vale, solamente quería saber eso..." Tras la despedida veo que no cuelga y le pergunto si pasa algo: +++"No, que no sé como colgar con este teléfono..." +++++"Entonces cuelgo yo...". Es posible que estuviera grabando la conversación ¿?.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-07-23','TERESA: NOTA FUTUEX . PROXIMA CITA SALUD MENTAL OCTUBRE. Si se le ve alterado, se puede llamar al centro de salud para que le llamen antes y la Dra. Leticia pueda conversar con él y compruebe si es necesario modificar la medicación, por ejemplo. SE LO COMUNICO A OLGA TS, ME COMENTA QUE EN LA ULTIMA VISITA DE FUTUEX NO LES HA DEJAO ENTRAR PERO QUE HAN PREGUNTADO A LAS VECINAS Y SE ENCUENTRA BIEN','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-07-23','(Pedro) Se envía a Eva, T. Social de la Residecia Virgen de la Soledad la solcitud para cambio de empadronamiento de Dª Andrea, junto con sentencia de incapacitación y aceptación del cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2020-07-23','TERESA RECIBO LLAMDADA DE SU PRIMA CARMEN 657 04 22 24. COMENTA QUE LA SITUACION DE SU PRIMA CON SU MADRES ES INSOSTENIBLE CONTINUAS PELEAS, NO HAY NADA DE HIGIENE Y MAL COMEN. PIDE QUE INTERVENGAMOS PARA SOLUCIONAR ESTO. LOS VECINOS NO DEJAN DE LLAMARLA COMENTANDOLES LAS SITUACION TAMBIEN LLAMAS LA AYUNTAMIENTO PERO NADIE HACE NADA, ESTA SITUCAION ES DE HACE AÑOS Y CADA VEZ ESTA PEOR QUE CON ELLA EN HABLAR CON LA TS Y VALORAR LA AMPLIACION DE LA INCAPACITACION Y PEDIR INGRESO INVOLUNTARIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-07-23','Ana: Llamo a Chus, Responsable de los PPTT de Miajadas - Empresa Serv. Tierra de Barros (638 499 546): A Esteve le dieron el alta en la UHB el días 7/7/2020. Tras este último ingreso no quiere ir al C.O., entre otras cosas porque dice que los profesionales se ríen de él. Esta información se la ha corroborado a Gloria-Futuex otra chica tutelada a la que hace seguimiento y que asiste al mismo C.O. Para que esté ocupado se lo llevan todas las mañanas al Centro de Días de Mayores de Miajadas que también gestiona la empresa Tierra de Barros y allí se siente bien y útil, participa en las actividades de terapia cognitiva y colabora en el centro con las personas mayores. ··· Hoy van a celebrar su cumpleaños, harán una fiesta con los compañeros del piso, iban a hacer una tarta. *Por otra parte, en el piso han puesto una piscina de 2 m para que el verano sea más llevadero, pues dadas las circustancias sanitarias (Covid), para la mayor protección de los residentes, este año no van a llevarlos de vacaciones a ningún sitio. ··· Chus me enviará todos los informes médicos de psiquiatría que tienen de Esteve (desde que cogieron la gestión del piso) Para que podamos solicitar la Revisión del Grado de Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-07-22','Ana: Llamo a Chus, Responsable de los PPTT de Miajadas - Empresa Serv. Tierra de Barros (638 499 546): NO obtengo respuesta. ················································································································································· Descargo del aplicativo de Futuex, el Informe de Alta de la UHB de Esteve, del día 7 de julio. Indica valoración diagnóstica a fecha de 12/06/2020 de: DISCAPACIDAD INTELECTUAL y TRASTORNO PSICÓTICO (Equizofrenia vs Tno. Psicótico reactivo a situaciones de estrés)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-07-23','Ana: Llamada de José Manuel Correa, nieto de Manuela, (927 582 302), al no contactar con Pedro, Jefe de Secc, me ha llamado a mí. Dice que ha ido el fontanero a casa, no ha querido cobrarle nada. Le ha dicho que el calentador es tan antiguo que no hay piezas en estock, por tanto el calentador no tienen arreglo. *Enviará presupustos al ctutelar@ a la atención de la secc. económica. *Le indico que sería conveniente enviar informe del profesional que les ha atendido explicándolo, pero dice que como no le ha cobrado la visita no podrá pedírselo...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2020-07-23','ana: Llamada de Noelia, TS de la Resi. Cervantes-CC (927 005 575): Mª Luisa ha acudido a su despacho diciendo que ya ha hablado con la TS de la CTEX (conmigo no ha hablado...) y que le "han dicho que sí". Se quiere ir de la residencia. Dice haber llamado también a la Resi. Alonos de Mendoza de Don Benito y que "le han dicho que cuesta lo mismo que la residencia en la que está"... Por otra parte pide que se le aumente la asignación semanal, pero Noelia sabe que es para comprar más tabaco. El otro día, desde su ventana, vió como rebuscaba colillas en un cenicero de la puerta de entrada, le llamó la atención y le mandó a lavarse las manos. *Le preguntará si necesita dinero para algo puntual, para en este caso pedir un extra, pero para aumentar la asingación semanal no, pues sería nocivo para ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAGRARIO'and edp.apellido1='CRESPO'and apellido2='PANADERO'),'2020-07-24','Ana: Correso de Rosa Bravo, Admvo. CSS-Plas.: "Buenas tardes: Os adjunto Informe de la incapaz S.C.P. y consentimientos informados para firma. Según La información que facilita su Médico de Familia en este Centro, Dr. Domínguez, es necesario la prueba para poder actuar en consecuencia. ++++++++++++++++++++++++++++++(Pedro) Envío los consentimientos por correo-e a Rosa. Un saludo. Rosa Bravo. CSS. Plasencia"··················· Se trata de una colonoscopia bajo anestesia general. El informe indica anemia grave de probable origen digestivo. ······················ Imprimo C.I. y pido a Pedro que la ponga para la firma del D.Gerente ···················· Guardo Informe en PDF adjunto en el expdiente digital. ················· Redacto oficio y lo imprimo para que Pedro lo firme y lo ponga para registro de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2020-07-24','"Se comunica a esa Comisión Tutelar de Adultos que el interno JUAN..., ha sido dado de alta en el Hospital de Mérida, en fecha 23/07/2020" retornando de nuevo al CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-07-24','Ana: Remito por mail, a la Secc. de Cargos a Terceros - Gerencia del Área de Salud de Cáceres por mail (faccar.hvmt@salud-juntaex.es): el Formulario de Cargos del SES por accidente de tráfico, la Hoja Informativa del Accidente de Tráfico debidamente firmada y sellada por el D.Gerente y la documentación relativa a la Curatela y al Representante Legal. ········································································································· Nos comunican nuevo correo coorportivo de la Secc. de Cargos a terceros: cargos.caceres@salud-juntaex.es - "EL CUAL YA ESTÁ OPERATIVO AL DÍA DE HOY. Saludos, Jesús Martínez." ························· Nuevo correo de Jesús Mnez. que reenvío a Pedro, jefe de secc. y a Miguel Ángel, director del CRR: "Estimados Sres.: Para poder gestionar los gastos sanitarios a nombre de la aseguradora del vehículo que causó el atropello se necesita como mínimo la matrícula del mismo, a ver si no lo pueden facilitar. Gracias. Saludos, Jesús Martínez." ····································· Llamo al consultorio de Jerte (927 470 121), me atiende la Admvo. a priori no les consta nada. Como el día 11 fue domingo, si le atendieron debío de ser desde el Consultorio de Cabezuela por urgencias. No obstante, cuando la Dra. esté disponible le pidirá que lo mire, pues ella si tiene acceso. *Devolverán la llamada a Pedro posiblemente ya el lunes, hoy será complicado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='LIRON'),'2020-07-24','(Pedro) Se recibe escrito de D. Luis Fernando Sánchez Lirón para el pago de la parte proporcional del IBI de su hermano. +++Paso documento a Alberto en el día de la fecha y guardo correo-e en el expediente virtual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-07-24','Ana: Llamada de Jose Manuel (722 493 622): pregunta si se sabe algo del centro. ··· Ha acudido a ponerse el inyectable hoy a Salud Mental. ··· Antonia Canelada del Río se presentó ayer a última hora en su casa y ha pasado la noche allí. Esta mañana temprano le ha dado dinero para que volviera en autobús al centro. ··· Ya puede duchare con agua caliente porque su hermano le ha puesto un calentador que ha comprado por Wallapop. ··· En cuanto al dinero se queja porque hasta octubre sólo va a tener 20€ de asignación semanal. *Le digo que sabe perfectamente el motivo "ya", dice "saqué 200€", como fue sin autorización esa es la consecuencia. Dice que se gastó 70€ en una TV de segunda mano. Le pregunto que ha hecho con los otros 130€, dice que ha comprado comida para las cenas y tabaco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-07-22','TERESA LLAMADE TELEFONICA DE BEARTRIZ, ME COMENTA QUE HA TENIDO UNA DISCURSION CON SU NOVIO QUE HORA YA SON AMIGOS ENE ESA DISCUSION HA TENEIDO UN FORCEJEO Y COMENTA QUE HA CAIDO A UNA SEÑORA POR LA ESCALERA JUNTO CON UN NIÑO QUE LLEVABA EN BRAZOS A RAIZ DE ESTO HA INGRESADO EL FIN DE SEMANA EN LA UHB, LA PELEA FUE EL DIA 17 Y HA ESTADO INGRESADA DESDE EL 19 AL 20 DE JULIO. COMENTA QUE HA ROTO UNA PUERTA Y QUE UN AMIGO DE SU NOVIO LA VA A ARREGLAR, LE DIGO QUE NO QUE VA A IR SUSANA EL VIERNES Y ELLA BUSCA A UN CARPINTERO PARA QUE SE LA ARREGLE Y NOS HAGA FACTURA SIGUE CON SU IDEA DE CONSEGUIR ALGUN DIA LA CAPACIDAD Y CON SUS HISTORIA CON EL TAROT QUE A LA ESPERA DE QUE SUSANA HAGA FOTOS Y NOS MANDE FACTURA PARA HACER EL PAGO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-24','TERESA RECIBO LLAMADA DE M FERNANDA TS DEL CENTRO DE SALUD PARA COMUNICARME QUE CARMEN ESTA MUY HINCHADA Y PRESENTA QUEMADURAS DE CIGARRILLOS EN EL BRAZO HA IDO SU MEDICO A VERLA PERO NO LE HA ABIERTO LA PUERTA NOS VA A MANDAR LA FACTURA DE LAS COMPRAS QUE HACE EN LA TIENDA M FERNANDA INSISTE EN EL PELIGRO QUE CORRE SU SALUD LE COMENTO QUE ESTA PEDIDO EL INGRESO INVOLUNTARIO Y QUE DESDE LA COMISION NO PODEMOS HACER NADA MAS INTENTAREMOS LLAMAR AL JUZAGADO PARA INFORMARNOS SOBRE COMO ESTA LA PETICION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-07-24','Ana: Llamada de Clara, TS CS (927 360 769 = C.S. Logrosán): Recuerda que Juan debe acudir a ponerese el inyectable el día 14 de agosto. Le digo que ya se lo comuniqué a Futuex en su día. Teresa-Futuex estará pendiente. ··· Por otra parte me informa que a partir del lunes que viene estará de vacaciones y no se incorporará hasta el día 24 de agosto, que estará en el C.S. Guadalupe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-07-24','Ana: Según me comunica José Manuel Romero Mediavilla, Antonia se presentó ayer en su casa a última hora y *ha pasado allí la noche. Esta mañana, a las 7:00 h le ha acompañado a coger el autobús para que volviera al CRR. Le ha dado dinero para el billete.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2013-02-18','Se mantiene conversación telefónica de la Trabajadora Social del SSB pidiendo que hagamos visita a nuestro curatelado porque está muy descontrolado y su madre no entiende porqué la Comisión lleva las cuentas de su hijo. Nos ponemos en contacto con médico de cabecera e informa que no se pone inyección para su esquizofrenia y esto provoca esta situación. Posteriomente en conversación con se Sepad ZAFRA le ha concedido una ayuda para la dependencia de 300 € pero quieren sirva para que un Terapéuta Ocuapacional que trabaje con el, necesitan ver como se articula todo esto. Le paso con Marisa para que gestionen el pago. Posteriormente la TS confirma que sí se lo ha puesto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-07-23','TERESA JOSE FLORENCIO LLAMA INSISTENTEMENTE PARA QUE SE LE SUBA SU ASIGANACION, AMANENAZA CON SUICIDARSE ME LLAMA LA MEDICO DE BARCARROTA PORQUE DICE QUE JOSE FLORENCIO LE HA DICHO QUE LA COMISION QUIERE HABLAR CON ELLA. LE COMENTO QUE NOSOTROS NO HEMOS HECHO ESA DEMANDA Y QUE EL TEMA ECONOMICO DE JOSE FLORENCIO ESTA MAS QUE HABLADO CON EL , ELLA INSISTE QUE EL ATENDAMOS QUE TIENE COLPASADO LAS LINEAS DEL CENTRO DE SALUD LE VA A LLAMAR PARA DECIRLE QUE NO PUEDE LLAMAR AL MEDICO PARA UN TEMA ECONOMICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-07-24','TERESA CONTINUAN LAS LLAMADAD CON EL MISMO ARGUMENTO DE QUE SI NO LE SUBEN LA ASIGNACION VA A PASAR ALGO GORDO Y VAMOS A SER NOSOTROS LOS RESPOSABLES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2020-07-24','Ana: Guardo en el expte. el comunicado que envían desde la Asociación Vera de la no conveniencia de que se vaya de vacaciones este verano por no cumplirse las premisas necesarias (1. No contar con posibilidades de aislamiento domiciliario durante el periodo requerido, en caso de contagio de Covid-19. 2. El centro no reúne medios suficientes para proceder al aislamiento, de aquellas personas que habiendo dado resultado positivo en PCR carezcan de apoyo externos para su aislamiento.','2');
