insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-07-24','Ana: Envío correo a Toni-Futuex: "...En cuanto a Eugenia Pacheco Vicente, según informe de la TS del SSB, sería recomendable que la pareja constase con SAD en el domicilio, en principio ella no está dispuesta. Puesto que es Curatela, la decisión es suya, no obstante, ¿sería posible que la compañera, en las próximas visitas, aborde este aspecto y pueda trabajar la conveniencia de recibir el servicio poco a poco?..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-07-27','(Pedro) Correo del CRR de Mérida (24-07-2020). +++Luisa Rodríguez: En la misma línea que en comunicaciones anteriores. Ha mejorado un poco respecto a las horas de sueño por las noches aunque queda trabajo por hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-07-27','(Pedro) Correo del CRR de Mérida (24-07-2020). +++José María Guillén: Estamos pendientes de ver cómo lleva no poder pasar tanto tiempo fuera del CRR a partir de la próxima semana. La experiencia anterior del confinamiento nos dice que, en su caso, los primeros días se muestra más irascible y crítico pero posteriormente bastante adecuado, más incluso que durante la "normalidad" pre-covid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-07-27','(Pedro) Correo del CRR de Mérida (24-07-2020). +++Mª Dolores Fernández: Se ha mostrado receptiva respecto a las nuevas medidas. Durante la semana nos ha preguntado tanto a Director como a mi sobre su salida a casa y vuelta recurrente con el tema de la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-07-27','(Pedro) Correo del CRR de Mérida (24-07-2020). +++Antonio Fernández: En la misma línea que con José María, observando cómo interfiere en su estado la restricción de las salidas. Con él, y algunos compañeros más, nos estamos planteando aumentar el número de salidas del recurso acompañados de profesional. Iremos actuando según su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-07-27','(Pedro) Correo del CRR de Mérida (24-07-2020). +++Ángel Pinilla: En la misma línea que la semana pasada. Ha acudido a revisión de oftalmología y le han dicho que en principio no le operarán de cataratas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-07-27','teresa mando email a futuex Hemos detectado por los movimientos bancarios que Jose Maria esta pagando dos teleasistencias, una con cruz roja y otra con mapre quavitae. En la próxima visita a ver si la delega puede confirmar con que compañía tiene la teleasistencia para dar de baja la compañía que no está usando, gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-07-27','miguel, llega del Jzgo de 1º instancia nº2 de Badajoz comunicación (Decreto 23-1-20) de notificar nuestra oposición al juicio monitorio planteado por la parte demandante Utilies Sl, y donde se dará un plazo a la parte demandandante para que continúe su reclamación monitoria de los 351€ vía juicio verbal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2020-07-27','TERESA HABLO CON ROSA TS SSB LE COMENTO LA SITUACION Y ME DICE QUE HOY HA ESTADO SUSANA Y QUE SE ENCUENTRA MUY NERVIOSO QUE SUSANA VA A IR A HABLAR CON LA ENFERMERA DE SALUD MENTAL ME COMENTA QUE EL TERAPEURA SE NIEGA A IR MAS AL DOMICILIO YA QUE LO RECIBE CON INSULTOS COMENTA QUE EN LA MAÑANA DE HOY HA IDO LA MADRE DOS VECES AL SSB A DECIR QUE SU HIJO ESTA MUY NERVIOSO LE INDICIO QUE ACTIVEN EL 112 ROSA ME COMENTA QUE VA A ESPERAR A VER QUE LE DICE SUSANA Y ME LLAMA QUE LA SITUACION ES CRITICA Y QUE TEME QUE PASE ALGO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-07-27','(Pedro)Fax del 26 de julio de 2020 del CSS de Mérida: se fugó ayer domingo 26 de julio a las 12:40h. +++Retornó al Centro acompañado de la Policía a las 14:10h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2020-07-27','miguel, me llega por sirex del abogado de Badajoz Felipe Muiel Medrano (tlefno 924220447, email fmurielm@yahoo.es) solicitud nos pongamos en contacto con él para la venta de inmueble del que es cotitular el tutelado. Le remito email solicitandole las condiciones de venta+tasación y para me indique persona de contacto y notaria."Buenas tardes, nos ha llegado a esta Comisión Tutelar de Adultos una autorización de venta así como requerimiento de documentación para dicha venta de este tutelado por la Comisión Tutelar de Adultos de la Junta de Extremadura. Comentarle que para poder solicitar dicha autorización judicial necesitamos nos remitan una tasación, precio de venta, cómo quieren acordar los gastos notariales, en definitiva todas las condiciones de la venta. Para el envío de documentación para la firma necesitaré saber en qué notaria se quiere firmar y persona de contacto en la misma para su remisión, ya que por la Ley de Protección de Datos no podremos facilitar documentación a nadie ajeno a la notaria. Reciba un cordial saludo y quedo a su disposición para aclarar cualquier duda". Le remito email','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-07-17','miguel, remito por fax a los efectos oportunos al jzdo nº3 de Plasencia la situación económica de la tutelada a efectos de demostrar su insolvencia para el cumplimiento de la ejecución de la sentencia proced ETJ EJECUCIÓN DE TITULOS JUDICIALES 35/2018','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-07-27','(Pedro)Tras hablar esta mañana a primera hora conmigo, después con Amalia y por último con Juana, siempre para pedir más dinero, se presenta en la CTAEx al parecer, en taxi que le ha costado 40 euros para "pedir más dinero" (ha sacado hoy lunes los 50 euros semanales. +++No atiende a las razones que se le indican. +++Pide el libro de reclamaciones y se le entrega para que ponaga su reclamacuión.','2');
