insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2020-07-28','-Amalia : en su expediente no encuentro documentación de su difunto esposo, no se le puede dar a Emilio para cambio de suministros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-07-27','TERESA RECIBO EMIAL DEL CRPS La madre de la usuaria llama al CRPS para informar que su hija se encuentra inestable,ha vuelto a tener disputas con su pareja, quiere marcharse a Barcelona y creen que está embarazada. Nos ponemos en contacto con Beatriz que confirma la información de su familiar. La noche pasada ha llamado al servicio de urgencias y le han inyectado un tranquilizante. Dice haber intentado contactar con ustedes sin resultado. Insiste en irse a vivir a Barcelona con otros familiares. Comenta que se ha hecho dos pruebas de detección de embarazo con resultado positivo. Se queja de llamadas del circulo personal de su pareja y que la están acosando. Se le recomineda bloquear los teléfonos de esas personas (incluidas su pareja) y si en algún momento se acercan a su domicilio que llame a los servicios de seguridad. Además que se ponga en contacto con su psiquiatra de referencia ante las dificultades de sueño y aumento de ansiedad. Se lleva a cabo coordinación con FUTUEX (Susana). Al final de la mañana se encuentra más tranquila, aunque aún no ha seguido ninguna de las recomendaciones dadas. Si necesitan más datos, no duden en ponerse en contacto con el centro. Un saludo Alicia Naharro Técnica de Integración Laboral. HABLO CON TONI FUTUEX Y COMENTA QUE HA SUSANA NO LE HA DICHO NADA DE LOS TEST Y QUE AYER ESTABA CON SANGRADO, VA A IR LA MADRE AL CENTRO DE SALUD PARA QUE LE HAGAN EL TEST ME INFORMARA TONI DEL RESULTADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-07-28','TERESA CONVERSACION TELEFONICA CON ANA EDUCADORA NATALIA QUIERE HACERSE UN TATUAJE, SE QUIERE PONER EL NOMBRE DE SU MADRE, NOS PIDEN OPINION, LE DIGO QUE SI ESO LA MANTIENE TRANQUILA NO HAY INCONVENIENTE EN QUE SE LO HAGA SIEMPRE Y CUANDO TENGA DINERO PARA HACERLO Y LO HAGA CON TODAS LAS MEDIDAS DE SEGURIDAD DEMANDA IRSE DE VADACIONES CON SU ABUELO PERO EL CENTRO NO LO VE IDONEO Y MAS CON LA SITUACION ACTUAL DEL COVID CON LO CUAL NO SE AUTORIZAN LAS VACACIONES ACORDAMOA REBAJAR SU ASIGNACION DE 120 A 60 YA QUE AHORA NO NECESITA TANTO DINERO PUESTO QUE YA NO VIAJA A BADAJOZ, LA ABUELA SIGUE SIN DAR SEÑALES DE VIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2020-07-28','TERESA CONVERSACION TELEFONICA CON ANA EDUCADORA NOS COMENTA QUE HAN INVITADO A ISABEL A LA COMUNION DE UNA SOBRINA, DESDE EL CENTRO NO LO VEN CLARO POR EL RIESGO QUE SUPONE ADEMAS QUE NO SE FIAN DE LA FAMILIA EN EL SENTIDO DE QUE APENAS TIENEN RELACION CON ISABEL Y VEN MAS QUE ES POR INTERES DEL REGALO QUE LE HACE A LA NIÑA, LE PROPONEN SALIR OTRO FIN DE SEMANA Y QUE PASE EL DIA EN FAMILIA Y ASI EVITAR EL CONTACTO CON TANTA GENTE, LO VEO BIEN Y ASI SE HARA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-07-28','TERESA CONVERSACION TELEFONICA CON ANA EDUCADORA P.I. ZAFRA COMENTA QUE M PAZ LA PSIQUIATRA DE LA UHDAC PLANTEA EL AL PARA AGOSTO, DESDE EL CENTRO PIDEN LA MANTENGAN HASTA SEPTEMBRE YA QUE EN AGOSTO EL CENTRO NO FUNCIONA SE VAN DE VACACIONES Y SOLO QUEDA RESIDENCIA, EL CENTRO VALORA UN CAMBIO DE PERFIL YA QUE LA VEN MAS USUARIA DE SALUD MENTAL QUE DE CENTRO DE DISCAPACIDAD DESDE LA UHDAC COMENTA QUE HA ESTABLACIDO UNA RED DE APOYO MUY BUENA EN PLASENCIA Y QUE SE PODIRA POBRAR EN DOMICILIO CON EL APOYO DE CENTRO DE DIA LE PLANTEO QUE HABLE CON SALUD MENTAL PARA QUE LA DERIVEN A CRPS Y PROBAR EN DOMICILIO DE CARA A SU SALIDA EN SEPTIEMBRE YA QUE CUENTA CON EL APOYO DE SUS DOS HERMANOS Y ELLA SE ENCUENTRA MUY FELIZ EN EL DOMICILIO CUANDO LAS HACE LAS SALIDAS DOMICILIARIAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-07-28','TERESA LE COGE EL TELEFONO AMALIA LLAMA BEATRIZ DICIENDO QUE QUIERE SU DINERO PARA IRSE A BARCELONA Y QUE ACABA DE TENER UN ABORTO QUE SI NO SE LO DAMOS SE VA A SUICIDAR LE INDICO QUE LLAME A SU PSIQUIATRA Y ME DICE QUE SU PSIQUIATRA LE HA DICHO QUE ESTA BIEN','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FULGENCIO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2020-07-28','TERESA RESUMEN RENDICION SE ENCUENTRA BIEN ADAPTADO PARTICIPA EN LO TALLRES Y ESTA ENCARGADO DEL TEMA DE LA JARDINERIA EN EL CENTRO AYUDA MUCHO A SU HERMANO ECONOMICAMENTE TIENE POCOS AHORROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2020-07-28','TERESA RESUMEN RENDICION DESDE SU INGRESO EN EL PISO SUPERVIADO HA MEJORADO MUCHO, ESTA BIEN ADAPTADO Y CUMPLE CON TODAS SUS OBLIGACIONES, LAS REALCIONES FAMILIARES TAMBIEN HAN MEJORADO SIGUE PIDIENDO COMPRAS EXTRAORDINARIAS A CAMBIO DE SU BUEN COMPORTAMIENTO E INSISTE EN SU ALTA TERAPEUTICA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-07-28','TERESA RECIBO EMIAL DE BEATRIZ QUIERE IRES A BARCELONA CON UNOS FAMILIARES QUE TIENE ALLI NO QUIERE SEGIR VIVIENDO EN ZAFRA COMENTA QUE HA TENIDO UN ABORTO LLAMO AL CRPS Y HABLO CON ALICIA, M CIELO ESTA DE VACACIOENS,ME COMENTA QUE MAÑANA VA A IR CON SU HERMANA AL CENTRO DE SALUD DESDE EL CRPS HAN AVISADO A SALUD MENTAL Y A SU MEDICO,QUEDO PENDIENTE DE HABLAR MAÑANA CON ELLA CUANDO LE LLAME BEATRIZ TRAS LA CONSULTA AL MEDICO ALICIA ME COMENTA QUE TIEE ABIERTA OTRA CUENTA EN LA QUE INGRESA EL DINERO QUE GANA CON EL TAROT, VAN A INTENTAR AVERIGUAR LA ENTIDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RODRIGUEZ'and apellido2='PARRILLA'),'2020-07-29','TERESA ENVIO AUTORIZACION MEDICACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2020-07-29','(Pedro)Sec recibe por correo electrónico Informe de Cocemfe para rendición anual de cuentas. +++Hablo con Julián al respecto. +++Tienen pendiente consulta con el Rehabilitador y es posible que requiera una silla más adapatada que la actual para sus necesidades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-07-29','TERESA Susana ha hablado con la hermana de Bea. Dice que cuando fue a su casa ayer por la tarde Bea se puso nerviosa y empezó a decirle que no quería ir con ella al médico. La quería echar de casa, pero poco a poco su hermana la fue tranquilizando y se fueron juntas a urgencias. A Bea le vio el médico y le hicieron la prueba de embarazo que dió negativa. Hablaron en la consulta de métodos anticonceptivos y Bea estaba receptiva a ponerse un DIU o los parches....etc. Por lo que es algo en lo que habria que trabajar con ella. Rosi, la hermana de Bea tb ha contado que ayer por la tarde la llamó la guardia civil para decirle que Toni había denunciado a su hermana por haberle hecho algo en la puerta. No le dieron más explicaciones. Podemos llamar a Toni, y preguntarle por qué motivo la ha denunciado, si la puerta ya está arreglada. A ver si Bea ha ido durante el fin de semana a su piso y ha hecho más cosas en la puerta, no se. Dada la situación general de la tutelada, hemos considerado imprescindible hablar con Salud mental de Zafra, pero sin éxito, asiqeu hemos llamado a Llerena a la uidad de hospitalización y hablando con una de las psiquiatras, porque la Dra. Constanza está de vacaciones hasta finales de Agosto. Nos han facilitado los teléfonos de los despacho de Isabel, la enfermera de salud mental Zafra para que hablar con ella y comentar que le está pasando con Beatriz. Amenza con coger un cuchillo y quitarse de enmedio cuando se frusta... El pasado 28 de Julio se visita a Beatriz Mejías en su domicilio y se la encuentra más tranquila que el día anterior pero con mucha verborrea y comentando todo el rato que se quiere ir a Barcelona. Se la deja hablar un poco porque es imposible meter baza y cuando se va calmando se le pregunta por su supuesto embarazo. Ella comenta que se hizo dos test de embarazo el pasado sábado día 25 y que le dieron positivo pero cuando se le pregunta si tiene algún documento que lo acredite o alguna prueba, responde que no, que no tiene nada. Se le propone la opción de ir con ella a urgencias para que la revise un médico y le haga otra prueba más fiable para estar del todo segura, ella dice que no, que va a esperar a su hermana que viene esta tarde a verla y ella la acompañará al médico. Bea cuenta que ella está segura de que lo ha perdido porque ha estado manchando dos días seguidos después de no haberle venido la regla en dos años y sabe que ella ya no está embarazada. Bea vuelve al tema del viaje a Barcelona y su discurso se basa en irse para allá y quedarse allí a vivir, cuenta que un amigo suyo le está mirando lofts en Santa Coloma de Granollers y que ella tiene muchas ganas de irse a Barcelona porque como se quede más tiempo en Zafra se va a morir de la pena. Cuenta que en Badalona tiene a su prima con la que se lleva muy bien y a la que quiere mucho y necesita verla y pasar un tiempo con ella y su familia. Después de escucharla por más de treinta minutos, se le comenta que un viaje de ese calibre necesita preparación y no puede hacerse a la ligera, y que tiene que planificar muy bien todos los pasos. Se le pregunta en qué medio de transporte se iría y ella contesta que ha pensando en el AVE Sevilla-Barcelona porque se va a llevar a su perrita. Su hermana la podría llevar en coche hasta Sevilla y una vez que llegara allí la podría recoger su amigo Vicent y se podría quedar en su casa hasta que encontrara algo. Se habla un rato más con ella y se le plantea la opción de que se tome esa idea de viaje cuando se pueda y si la comisión lo ve pertinente como unas vacaciones, como un respiro que necesita mucho pero no como un cambio de residencia, ya que eso sería algo mucho más importante y permanente. Y ella en Zafra tiene muchos profesionales con los que cuenta, amigos, su piso de alquiler, el CRPS, el equipo social comunitario,...etc. Bea se queda algo pensativa y cuenta que quizá tengamos razón porque mudarse a otra comunidad es algo muy serio pero no lo dice muy convencida. Se apela a la mala situación de Covid que hay ahora en toda la zona catalana y ella cuenta que no le importa tener que quedarse encerrada en un piso 14 días, pero que lo quiere es salir de Zafra. Los contactos que nos facilita son: -Su amigo Vicent: 680 14 25 15 ( Se habla con él y cuenta que conoce a Bea desde hace más de 12 años cuando ella estuvo allí viviendo. Y comenta que él podría alojarla en su casa el tiempo que ella necesitara, pero que incluso está mirando estudios para alquilar por si ella quisiera quedarse más tiempo en Badalona. - Su prima Raquel: 666 89 26 80, según Bea la apoya en su decisión de irse a Barcelona. Pero Bea no quiere quedarse en su casa porque no quiere provocarle inconveniencias ya que ella está casada y tiene una niña. No se ha podido hablar con su prima aún, se llamará mañana para que cuente cómo ve la situación de su prima y si corrobora la historia de Bea. CONVERSACION TELEFONICA CON BEATRIZ Acabo de hablar con ella y he conseguido que posponga la idea de irse a Barcelona pero no se cuanto le durara porque lo tiene todo pensado dice que la tutele la comisión de allí que ella en Barcelona tiene amigos y familia como bien comentas tu en el correo. Ayer por la tarde fue a urgencias y dice que mañana va a ir a su médico de cabecera…. A ver si su médico la deriva a salud mental Hoy esta bastante cuerda y razoble, al menos conmigo… Quedamos a la espera de la cita del médico de mañana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='GARCIA'and apellido2='FERNANDEZ'),'2020-07-29','EXITUS El centro (Felipe Trigo) informa de su fallecimiento el 16/07/2020. Remitirá Certificado de Defunción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-07-29','(Pedro)Llamada de Dª Salobrar (652-470337). +++Han ingresado grave a su padre en el Hospital y no creen que vuelva a la casa. +++Solcita docuemntación relativa a los ingresos de Eugenia para tramitar una plaza residencial porque no quieren que Eugenia se quede emn la casa una vez que su padre (de Salobrar) ya no va a estar con ella. +++Dice que Gema, la Trabajadora Social del SSB, ha inciado los trámites para buscar una residencia. Le digo que mnos pondremos en contacto con ella, pero me dice que estás de vacaciones hasta el 15 de agosto. +++Me pongo en contacto con Toni, de Futuex: intentarán hablar con la hija sobre la necesidad de que Eugenia se mantenga en la vivienda hasta que tenga un recurso al que acudir. Averiguarán en qué punto están los trámites (si es que se han inciado) para ingreso en centro, contando siempre con la aceptación de Dª Eugenia, dado que se trata de una CURATELA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ORTIZ'and apellido2='MONTAÑO'),'2020-07-30','FIN PROCEDIMIENTO El Jzdo. n.º 4 de Cáceres declara la incapacidad absoluta de Dña. Concepción. Nombra tutor a su sobrino: Rafael Ortiz Merino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-07-30','TERESA ADELANTO POR EMAIL PIA FIRMADO PARA CAMBIO DE CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='CAPILLA'and apellido2='CAPITA'),'2020-07-29','TERESA ENVIO ALTA Y SOLITUD FIRMADA PARA SOLICITA SUBVENCION SILLA DE RUEDAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-29','TERESA SE RECIBE PROVIDENCDIA EN LA QUE EL FORENSE VISITA A CARMEN EN SU DOMICLIO EL PROXIMO DIA 29 A LAS 11 EN RELACION A LA SOLICITUD DE INGRESO INVOLUNTARIO. SE LO COMUNICO A FUTUEX Y A M FERNANDA TS DEL CENTRO DE SALUD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-07-30','TELEFONO JUANMA ENFERMERO SALUD MENTAL 45654','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-07-30','TERESA Como ya preveíamos en tu correo anterior y yo concitaba mis sospechas con tus argumentos, después de tres semanas en el pueblo y según manifestaciones hechas ayer por un conocido, el pasado Sábado tuvo una caída, con participación de la ambulancia incluida y diagnóstico de fisura en la zona del hombro por ingesta de alcohol. En el hospital, siempre según este conocido, dijo que se había caído por las escaleras. Por cierto, por el servicio no ha pasado ni siquiera a saludar. Parece ser que efectivamente están de alquiler en un piso y regularmente está haciendo limpieza en el domicilio familiar. En estos momentos también estaba con ellos la madre de María Ángeles, su compañera. En fin, la situación vuelve por sus derroteros. Un saludo. Antonio López Cortés (TS del SSASB de Monterrubio de la Serena y de apoyo al SSASB de Cabeza del Buey)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-07-31','TERESA Acaba de telefonear Beatriz para comentar que una pareja de la Guardia Civil acaba de estar en su casa para notificarle que su expareja la ha denunciado por haber causado destrozos en la puerta de su vivienda. Le han notificado que se tiene que presentar hoy en el juzgado a declarar. Ella ha comentado que está tutelada y que no va a acudir a ningún sitio sin que le acompañe su tutor legal. Ha facilitado vuestro teléfono a la Guardia Civil, y ella está intentando contactar con vosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-07-31','TERESA Buenos días. Me comunica Rosa Tena, la directora del servicio RAL de Fuente de Cantos ( Francisco de Asuar) que el retorno de José Florencio no puede ser hasta el 26 de agosto, para poder garantizar los 7 días de aislamiento previa pcr negativa, al estar programados otros retornos de usuarios que se han ido de vacaciones. Asimimismo planteamos otras cuestiones a tener en cuenta: • planificar salidas a casa y el retorno cuando se aprecie que puede estar al límite en el servido (ampliable los 45 días naturales Decreto 45/2002). • cumplir las mismas normas que el resto de usuarios tanto en RAL como en CO. • Aumentar su participación ( medias proactivas). • Limitar los enseres que puede llevar a la residencia. Inventariar los mismos. • Solicita cita al ESM, para informar a su psiquiatra de las conductas de José Florenico de cara a comunicar al juez por si procede ampliar la curatela o tutelar. • Documentar la entidad la dificultades de manejo con josé FlorenCIo y sus dificultades para a autogobernarse de cara a comunicar al juez. Si os parece correcto, comunico a José Florencio y Rosa se pondrá en cotacto con él la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-08-03','miguel, pongo a la firma del Gerente la Solicitud de Aprobación Judicial de Herencia. Pongo en registro de Salida el oficio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2020-08-03','miguel, contesto al email a petición de Ana "Buenos días, le hemos llamado de la Comisión Tutelar de Adultos en relación a la solicitud que realizó días anteriores a mi compañera trabajadora social Ana Matamoros. Comentarle que en este momento estamos a la espera que nos remitan la documentación solicitada al Registro Civil correspondiente al certificado de actos de últimas voluntades para poder incorporarlo a la correspondiente rendición de cuenta final, y posteriormente remitirlo al Juzgado de 1º instancia nº3 de Cáceres, conforme establece el artículo 279 del Código Civil. Una vez que remitamos nosotros a dicho juzgado la rendición de cuentas final podrá ponerse usted directamente con el juzgado de 1º instancia nº3 de Cáceres, ya que nuestra labor como tutores se extinguió con el fallecimiento de Doña Juliana Paula Centeno Rodríguez, tal como establece el artículo 276.3 del Código Civil. No podemos facilitar ninguna otra información conforme la Ley de Protección de Datos, salvo que el Juzgado competente así nos lo requiera. Reciba un cordial saludo".','2');
