insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-08-05','TERESA LLAMO AL INSS(924 21 61 60) PARA INFORMARME DE LA PENSION ME DICEN QUE ES UNA PENSION DE INCAPACIDAD PERMANENTE DE INVALIDEZ REVISABLE, ME FACILITAN NUMERO DE TELEFONO INVALIDEZ PARA AVERIGAR FECHA DE REVISION (924 21 61 77/78) ME DICEN QUE LA FECHA DE REVISION ES 29/01/22, SE LE CITARA POR ESCRITO LA DIRECCION QUE TIENE ACTUALMENTE ES LA DEL SOCIOSANITARIO, PIDO POR ESCRITO CAMBIO DE DIRECCION A LA CTAEX PARA RECIBIR NOSOTROS LAS NOTIFICACIONES','2');
