insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-08-06','TERESA María Elena llama todos los días con lo típico hoy si residencia y mañana no.... el otro día se tomó un blíster de pastillas y le tuvieron que hacer un lavado de estómago, todo por la mala relación con su padre. LE PIDO A MIGUEL QUE PRENGUNTE AL JUZGADO YA QUE ESTAMOS PENDIENTES DE QUE LA VEA EL FORENSE Te lo pongo en conocimiento para que consideréis lo oportuno... Seguimos!','2');
