insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2020-08-06','miguel, a petición de Tere, miro en intranet y en el expte virtual si se ha comunicado algo al juzgado. Compruebo que no se ha encargado nada a la parte jurídica de la Ctaex. La comento vía email las distintas posibilidades que hay con este expte y al comentarme ella que al ser agosto un mes complicado para que nos emitan informe psiquiatrico y/o social, le indico que comunique a la trabajadora social con la que mantenga contacto el curatelado que deje constancia de cualquier incidencia sobre la conducta violenta con su madre y/o terceros del curatelado a efectos como mínimo de poder comunicarlo al juzgado a los efectos oportunos. Caso de que tengamos fundamentación necesaria basada en informe social y psiquiatrico, si la parte social lo estima oportuno, podríamos solicitar internamiento involuntario judicial.','2');
