insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-08-10','Ana: Llamada de Juan José (667 958 878), expresa que está muy bien, que ya lo habló con Pedro, Jefe de Secc., en su día, que está más asentado, se administra bien y quiere volver gestionar su dinero de forma autónoma e incluso recuperar su capacidad. *Hablaré con Pedro. En cuanto al procedimiento de Recuperación de la Capacidad, pediré a los compañeros Asesores Jurídicos, que le llamen para explicarle en qué consiste el procedimiento y cómo debería proceder en tal caso. ***************************************************** miguel, tras hablarlo con Pedro y Ana, comprobamos que vive en un piso tutelado y por tanto son sus reponsables quienes nos tendrían que solicitar su recuperación de capacidad. Por ahora Pedro comenta que no hagamos nada, que ya llamará y hablará con él. ··············································································································································· Ana: Correo de Amalia, TS CTAEX, del día 6/08/20 (durante mis vacaciones): "Buenos días Ana , he preguntado a Miguel quién tendría que firmar este documento y me confirma que el Gerente . Es para el empadronamiento de Juan José Bergantiño , el chico que ha pasado del CRR Bjoz a Pisos asociados al CRR de Cáceres . Para que lo pongas a firma. Le respondo yo al centro y te pongo en copia . Ya he pedido que hagan el cambio en la retirada del dinero asignado , 100€ semanales a la entidad en Cáceres. Por lo demás este chico funciona bastante bien , quería regresar a su ciudad y llevaba años esperando el traslado . Su madre y su familia viven allí , y las visita. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILIA'and edp.apellido1='SALGADO'and apellido2='DURAN'),'2020-08-10','Ana: Debido a un error, se envió el CI de Basilia al CAMP Las Cruces de Don Benito, en lugar de al CSS-Plas. *Tras comunicárselo a Rosa Bravo, Admva.CSS (24200), como tengo el CI escaneado, se le envío por email. ···························· Llamo a CAM Las Cruces (924 021 564), hablo con la Directora, pedirá que lo envíen directamente al CSS-Plas. en cuando lo reciban en lugar de devolvérnoslo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-08-10','miguel, al no contestar la abogada Ana Mª de Pablo, remito el siguiente email a Ainés "Buenos días, en relación a la solicitud judicial para la aprobación de herencia y de venta de las fincas (entiendo por la abogada Ana de Pablo de las 7 fincas), necesitamos hablen con la abogada para nos remita (por email) las tasaciones de todas las fincas, indicando quiénes son los compradores y precio de venta (que nos remita los contratos de señal que comenta la abogada que han firmado). Hasta que no me remitan dicha documentación no podremos remitir dicha solicitud de autorización judicial de aprobación de la herencia y de las ventas. Le adjunto la relación de emails intercambiados con la abogada".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAO DANIEL'and edp.apellido1='CARVALHO'and apellido2='VENTURA'),'2020-08-10','TERESA RESUMENE RENDICION A PENSAR DE QUE LLEVA DOS AÑOS EN LA VIVIENDA TUTELADA NO SE TERMINA DE ADPATAR, TIENE BUENA RELACION CON LO COMPAÑEROS PERO CON CONTINUOS PROBLEMAS POR SU ACTITUD DESAFIANTES. QUEBRANTA CONTINUAMENT LAS NORMAS Y NO MUESTRA INTRES POR HACER NINGUNA ACTIVIDAD NI TALLER ACUDE OBLIGADO A CENTRO OCUAPCIONAL Y SIEMPRE HACE CON DESGANO LAS TAREAS ENCOMENDADAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-08-10','TERESA ANICA PRESETA DEPENDENCIA PARA TODAS LAS ABVD, NO TIENE RELACION FAMILIAR DESCONOCE EL IDIOMA CON LO CUAL NO SE RELACIONA CON NADIE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-08-10','miguel, llega citación para el 15-9-20 del Juzdo de lo Penal nº1 de Plasencia por procedimiento abreviado penal 511/2018 (PA 95/20). Solicito vía fax videoconferencia y abogado de oficio (aunque han puesto al letrado de la Comunidad)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-08-10','(Pedro) Correo del CRR de Mérida (06-08-2020). +++El martes un usuario del CRR agredió a Ángel Pinilla. Por lo que me cuentan mis compañeros, fue difícil separarles y actualmente la persona que agredió está ingresada en UHB. Hoy he hablado con Ángel para saber cómo se encuentra y qué le gustaría hacer al respecto. No quiere interponer denuncia ante la Policía por lo ocurrido. ++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo-e (Pedro): Buenos días, Cristina. Hoy me he reincorporado de vacaciones. Respecto de D. Ángel, ¿ha sufrido algún daño por la agresión? ¿Hay algún parte de lesiones en su caso? Espero que esté bien. Y si hubiera parte de lesiones, enviarán del Juzgado al CRR una carta comunicando diligencias previas. Por favor, si se dan estás circunstancias, enviadnos el parte de lesiones y la carta a la Comisión para contestar en nombre del tutelado en el sentido de si se continúa con las actuaciones o no. Espero tu contestación. ++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo-e del CRR:Buenos días Pedro, El día 4 de Agosto cuando sucedió la agresión yo estaba de vacaciones. He estado preguntando a compañeros y leyendo en la base de datos así como en su expediente y lo que veo es que el Médico le valoró, no he encontrado parte de lesiones ni informe médico al respecto. Indicó que no presentaba heridas pero que al haberse golpeado la cabeza si se observaban vómitos, dolor de cabeza o hematoma tendríamos que consultar con el Médico. Nada de eso ha ocurrido hasta día de hoy. Dirección dijo que se le acompañara el jueves a interponer denuncia porque en un principio Ángel quería pero posteriormente se ha negado a acudir a Comisaría para denunciar, no quiere. Hemos abordado el tema diversos profesionales pero su respuesta es siempre la misma. Los primeros días Ángel estaba emocionalmente afectado por lo ocurrido, ahora se encuentra mejor. Refiere dolor en la espalda, como sabes también lo hacía antes, por este motivo sigue acudiendo a sus citas con Fisioterapeuta. En cualquier caso, cualquier documentación que llegara os la remitimos. No obstante, esta tarde preguntaré a las compañeras que estaban trabajando ese día (la agresión se produjo por la tarde) y vuelvo a contactar contigo. Gracias, Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-08-10','(Pedro) Correo del CRR de Mérida (06-08-2020). +++También he hablado con María Dolores Fernández, ella estuvo presente en el momento de la agresión y desde entonces se encuentra un poco nerviosa, aunque verbaliza que cada día un poquito mejor. Por todo lo demás bien, ha vuelto a solicitar irse a casa unos días pero al indicarle que no es posible ha aceptado y no ha vuelto a insistir, de momento, en esta cuestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-08-10','Ana: Victoria, Dependencia, nos sube la Resolución de Beatriz; Resuelven aprobar el PIA consistente en SAD. *Se lo dejo a Teresa sobre su mesa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-08-10','miguel, a petición de Iciar llamo a Rafael, hermano del curatelado (tlfno 654-532604). Me explica que están renunciando los hermanos a la herencia del padre y me llamó para avisar de que debemos renunciar, parece ser que sólo existe una cuenta corriente con 80€ (y que le comentan que desde el Bbva dejó una deuda) y que no hay más bienes inmuebles. Le pido que me envíe vía email la información que pueda junto con el dni del padre para indagar nosotros. Lo comento con Ana para que avise al CRR de Cáceres de que tendrá que ir a firmar a la notaria la renuncia de herencia, la cual será ratificada por nosotros en Mérida ··························································································································· Ana: Llamamos con el manos libre Pedro, Miguel y yo a Miguel Ángel, director CRR-CC. Rafael, hermano de Félix le llamó transmitiendole la misma información que a Miguel, parecía muy sincero y que lo que quiere es ayudar. Suele tener contacto frecuente con Félix y aparentemente se preocupa por él. ························································································································ Correo de Miguel Ángel, Director CRR (residenciadir@feafescaceres.com) : "Buenas tardes de nuevo Ana, el padre de Félix Figueroa falleció el 30 de Octubre de 2019."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-08-10','Ana: Pongo para REGISTRO DE ENTRADA la Solicitud de Desplazamiento del Equipo Móvil para renovar el DNI de Rosa, junto a las copias compulsadas de los documentos pertinentes, para que la remitan al Centro de DNI de la Dirección General de la Policía Nacional de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-08-10','Ana: Llamada de Ana Benavente, TS del ESM-Pla. (74955), han ingresado a Pedro, pareja de Eugenia, en una residencia en Navalmoral de la Mata, con plaza sociosanitaria. La familia de Pedro no quiere que Eugenia siga viviendo en la casa de Tejada de Tiétar. No la van a echar inmediatamente pero pide que le busquemos algún recurso. ··································································································································· Pedro y yo hablamos con Mariluz Madrigal, Jefa de Secc. Salud Mental, dice que al haber cumplido ya los 60 años, Eugenia ya no tiene opción de volver a ingresar en CRR. *La opción que nos queda es la de solicitar plaza en Residencia de Mayores. Como tampoco está valorada por Dependencia, hablo de nuevo con Ana Benabente, acordamos que se solicitará tanto plaza vía Decreto por Emergencia Social como Valoración de Dependencia por emergencia social. *Como Ana en 2 días se va de vacaciones, nos pondremos en contacto con Gema, TS del SSB de Tejada de Tiétar, a partir del día 17, que se incorpora de sus vacaciones. **Envío email a Toni-Futuex al repecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-08-10','miguel,a petición de Amalia llamo a Sindy,y quedo en que me mande el certificado de precio de VPO que tiene de la vivienda que ella va a comprar en la misma calle. También me indica las dos inmobiliarias que están vendiendo viviendas por la zona (Colón y Danan (tlfno 625712629). Me comenta que los precios son máximo de 65.000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-08-10','miguel, llega de nuevo la subsanación de aportación de documentación del colegio de abogados de badajoz para abogado de oficio. Lo subo a firmar por el Gerente pero no está y lo dejo a Felipa. Ya remití dicha documentación al colegio de abogados el 29-6-2020','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-08-10','TERESA LLAMO A SILA DEL CEDEX Y ME COMENTA QUE ENRIQUE EL DOCTOR CONSIDERA QUE NO CUMPLE CRITERIO PARA DERIVACION A LA UNIDAD DE ALCOHOL PUESTO QUE ACTUALMENTE NO CONSUME ALCOHOL COMO NO TIENE DISCAPACIDAD RECONOCIDA (ESTA YA SOLITADA) LA UNICA VIA QUE NOS QUEDA ES LA DE MAYORES SOLICITO PLAZA RESIDENCIAL PARA MAYORES VIA DECRETO POR EMERGENCIA SOCIAL PEDOR SOLICITA NOS CONIEQUEN POR ESCRITO LA DECION DE SACARLO DE LA LISTA DE ESPERA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2020-08-10','TERESA INTNTO HABLAR CON LA TS DEL SSB PARA PEDIR INFORME SOCIAL Y COMUICAR LA SITUAICON AL JUZGADO, ME COMENTA QUE ESTA DE VACACIONES HASTA FINALES DE AGOSTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-08-10','miguel, remito al Jzdo nº4 de Badajoz solicitud de aprobación de Herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2020-08-11','Ana: Icíar, Secc. Ecca, me informa en un email: "...del CRR de Plasencia, nos han pedido autorización para una ayuda a domicilio para el aseo de la señora dos veces por semana con un presupuesto de 130 €/mes, Alberto ha dado el OK..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-08-05','-Amalia : LLama Xesca, TS de Palafolls ( al lado de Blanes en Gerona , último pueblo de Barcelona ) Enfrentamientos de Ati con la policia local por el tema de la retirada del dinero . Estuvieron viviendo en la plana baja de la casa de los padres de Joaquina pero se han marchado de allí , enfrentamientos con la madre que tb padece E. mental .La casa la han dejado muy sucia. No tienen vivienda y allí no hay opciones de alquiler. Se quieren casar , pregunta si pueden hacerlo . Viven en un coche . Va a ir a realizar visita domiciliaria y nos enviará todos los informes , policiales y de salud mental , no está tomando medicación. Le explico su trayectoria socio personal y la extensión de la curatela. Se podría comunicar al juzgado la situación por si pueden solicitar alguna medida cautelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-08-11','(Pedro)Intento nuevamente ponerme en contacto con la Dra. Cabanillas sin conseguirlo. +++Pido en centralita que me pasen con la Trabajadora Social sin que tampoco me cojan el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-08-11','-Amalia : se recibe email de TS de Palafolls. Ha estado esta mañana aquí Ildefonso. Hoy decía que quiere un abogado para poder demandar a todos los que le tienen retenido su dinero. Le hablo de la curatela, el dice que no tiene la sentencia, que mientras el no lo vea no lo cree…. No se que posibilidades hay de que me hagáis llegar la sentencia, y quizás que sirva para ir pudiendo trabajar algun aspecto con él… Joaqui esta ingresada involuntariamente des del viernes. No he podido esclarecer donde estav viviendo el.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-08-11','Enviamos al Abogado designado la Resolución rectificada de la Comisión de Asistencia Jurídica Gratuita de Badajoz, reconociendo el derecho para que se presente el expediente en el Juzgado que corresponda de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-08-11','-Amalia : hablo dos veces con Carmen , la TS del ESM . La familia ha ido dos veces por allí , están desbordados. El casero quiere subirles el precio con la idea de echarlos de la casa , por los disturbios que ocasiona Alejandro. La madre y el abuelo quieren comprar un piso . Se le explica que para ello se necesita autorización judicial y además hasta que no se resuelva la sentencia judicial pendiente ( probable ingreso en Ctro. penitencirio) no se va a decidir nada sobre ese tema . Tampoco sería una solución muy positiva , si quiere podría echar a la madre del piso y siendo ya dueño puede entrar en casa a otras personas. Desde el ESM se intenta valorar alguna alternativa residencial: -por discapacidad , con el consumo de drogas no da perfil. -está acudiendo al CEDEX de Valdepasillas , tiene cita el dia 29/9 , se podría valorar ingreso en C. terapéutica si el quiere voluntariamente. -Por salud mental , se puede valorar ingreso en la UDAC ó UHB . No toma la medicación . Sólo lo ha visto una vez el psiquiatra ( Pablo ) y a la TS no ha asistido a la cita concertada. Carmen le va a decir que adelante la cita que tiene para octubre para valorar estas opciones o solicitar subcomison de S.M. -Pte. de la resolución judicial , puede que ingrese en prisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GOZALO'and apellido2='CALDERON'),'2020-08-11','TERESA INFORME RENDICION SE ENCUENTRA BIEN ADAPTADO AL CENTRO Y PARTICIPA EN LAS ACTIVIDADES Y TALLERES, ESTE AÑO NO PUEDE PASAR LAS VACACIONES EN SU PUEBLO COMO HACE TODOS LOS AÑOS DEBIDO AL COVID. LO HA ACEPTADO BIEN ECONOMICAMENTE VA MUY JUSTO DE DINERO POR ELLO EL CENTRO LE COMPRA A VECES LO QUE VA NECESITANDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-08-07','-Amalia , email de Xesca : Buenos días Amalia, Te escribo para comunicarte que ya he realizado coordinación con Policía Local, ambulatorio en Palafolls, visita a domicilio, entrevista con la hermana de Joaquina. En breve te haré llegar la documentación solicitada. En estos momentos Ildefonso y Joaquina hace 1 semana que viven en el coche, no quieren volver al domicilio de los padres ( aunque tienen las puertas abiertas) i Ildefonso no recibe control psquiatrico. Feliz finde!!! Xesca Torres Alarcón Treballadora Social Ajuntament de Palafolls C/Francesc Macià, no. 1, 2a Planta. 08389 Palafolls Tel. 93 762 00 43 ext. 201','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='FAGUNDEZ'and apellido2='CORTES'),'2020-08-11','TERESA INFORME RENDICION SE ENCUENTRA ENCAMADO DEBIDO A SU GRAN DISCAPACIDAD, RECIBE SESION DE FISIOTERAPIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-08-07','-Amalia , email de Xesca : Buenos días Amalia, Te escribo para comunicarte que ya he realizado coordinación con Policía Local, ambulatorio en Palafolls, visita a domicilio, entrevista con la hermana de Joaquina. En breve te haré llegar la documentación solicitada. En estos momentos Ildefonso y Joaquina hace 1 semana que viven en el coche, no quieren volver al domicilio de los padres ( aunque tienen las puertas abiertas) i Ildefonso no recibe control psquiatrico. Feliz finde!!! Xesca Torres Alarcón Treballadora Social Ajuntament de Palafolls C/Francesc Macià, no. 1, 2a Planta. 08389 Palafolls Tel. 93 762 00 43 ext. 201','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2020-08-11','-Buenos días. El lunes por la mañana se decidió acercar a Diego Blanco Luque a urgencias del Hospital Perpeuto Socorro porque empezó a manifestar dolor abdominal. Desde allí le derivan a Hospital Universitario de Badajoz donde se verifica que presenta de nuevo vólvulo Sigma. Se le práctica colonoscopia y se le pone sonda rectal durante tres días, con la que viene al centro en el día de hoy ,y cuyos cuidados asumirá Atención Continuada durante el fin de semana. Ante la recidiva , se propone pasar a control por cirugía en un mes. Cuando se disponga de más información sobre el proceso se la trasladaremos. Se le ha hecho PCR, mientras nos den resultados se le pone en aislamiento estricto. En cuanto tengamos resultado, si es negativo, se suavizara el aislamiento con distancia social y mascarilla. Se contrataron los servicios de la empresa el Angel. Saludos Susana Torres García-Moreno Dirección Técnica Aprosuba 3','2');
