insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2020-08-11','miguel, conforme me indica Belén y tras el email del 27-7-20 de Pedro (recabando información del piso de alquiler). Compruebo que el contrato de alquiler indicaba una cuenta en que hacer el abono, y que siempre según indica nuestra tutelada y los inquilinos el pago se realiza en efectivo. Prepararé un burofax que justifique los pagos, caso contrario la buscaremos abogado de pago para la reclamación de la cuantía y el consiguiente desahucio. Envío email a Angel para coincidir en los pasos a dar y buscar un modelo y ver la forma de envío del burofax en otra ocasiones anteriores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2020-08-11','Ana: Llamada de Noelia, TS de la Resi. Cervantes-CC (927 005 575): Mª Luisa ha vuelto a su despacho a decir, de nuevo, que quiere pedir el traslado a la Residencia Alonso de Mendoza de Don Benito. Según le ha dicho también su hija le ha estado llamando estos días. *Pregunta también por la pensión de viudedad, quiere pedirla para poder cobrar aún más dinero. (*Mª Luisa percibe PFHC y Orfandad Absoluta). *También le ha dicho que ya ha llamado a la CTAEX (conmigo no ha hablado) ·························································································································· Tras hablar con Noelia, recibo llamada de Mª Luisa (644 547 304), expresa con vehemencia que quiere irse a la residencia de Don Benito, los motivos que aduce son dos: 1- la comida de esta residencia no le gusta y 2- quiere estar más cerca de la familia. *Dadas las circustancias sanitarias actuales, le explico que en estos momentos esa opción ni se puede plantear. Cuando la situación esté más calmada se podrá valorar esta posibilidad en equipo. ··································· La realidad es que estar cerca de su hija es contraproducente para ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-08-11','miguel, me llega la documentación acreditativa a efectos de Renunciar a la Herencia del padre, para lo cual remiten certificados de defunción, últimas voluntades, movimientos de cuentas, escritura notarial de renuncia de herencia (remitida a la junta de Andalucía). Por mi parte pido la nota simple del registro de la propiedad a nivel nacional y me contestan negativamente (no tiene ningún bien a su nombre). Envío email a Ana y Pedro, quién solicita vía email al Centro que pidan cita en una notaría de Cáceres y nos indiquen notaria y trabajador para hacer un seguimiento de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-08-05','-Amalia : llama Sindy , 625712629 , para ver cómo va el tema del alquiler . Primer mes y fianza no se entregaría para cubrir gastos de reparación de la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='TORES'and apellido2='NUÑEZ'),'2020-08-11','miguel, escribe el representante de la familia para pedirnos autorización para adjudicación de herencia: "Estimados señores, A través del Centro Sociosanitario de Plasencia y en su nombre, la trabajadora social, Maria Victoria Clemente, me pongo en contacto con ustedes para que informen del procedimiento a cumplir con el objetivo de tramitar la adjudicación de herencia de Dominica Nuñez Cañadas y Alejandro Torés Moreno (ambos fallecidos) como progenitores de Julián Núñez Cañadas en calidad de protegido de su comisión tutelar de adultos de la Junta de Extremadura. Les escribo este correo, una vez iniciada la recopilación de documentación necesaria tras el 1er. contacto mantenido con la notaría de D. Daniel Alonso ubicada en Jarandilla de la Vera y domicilio de la familia de Julián Torés- Para cualquier duda, o aclaración pueden contactarme en este correo electrónico o en el teléfono 627 531167, como coordinador de la familia, en calidad de primo hermano de Julián y sus 3 hermanos: Magdalena, Alejadro y Dominica. Muchísimas gracias por su atención y quedo a la espera de sus noticias". ******************************************** Y mi contestación: "Buenas tardes, para la tramitación de dicha herencia habrá de indicarnos la persona de notaria que está preparando la escritura de herencia de los padres del tutelado Don Julián Nuñez Torés, ya que necesitaremos nos adjunten testamentaria de sus padres fallecidos, y borrador de escritura de adjudicación de herencia. Al ser una persona tutelada y conforme exige el artículo 271 CC habría que pedir autorización judicial para adjudicación de herencia".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-08-11','Ana: Correo de Pilar Sánchez (direccion.hgsvplasencia@gmail.com), Hogar San vicente de Paúl: "Buenos días, Ana, nos hemos puesto en contacto con la Dra. Lorenzo que es la que lleva el caso de Marga en la Unidad de Psiquiatría y nos ha comunicado que la van a mandar a la UME del Centro Sociosanitario, si puede ser durante esta mañana, porque Marga se niega a volver aquí, ya que se ha obsesionado con la idea de que ella quiere hacer lo que quiera y no quiere estar donde haya normas. En cuanto la envíen nos lo comunicarán. En el caso de que siga con esta situación, hablaremos para ver qué pensáis hacer. En cuanto sepamos algo os iremos informando. Un saludo" ································································· Conversación telefónica con Pilar: A pesar de la buena conducta y actitud de Marga tras el último ingreso, en los últimos días Marga ha comenzado una etapa de rebeldía propia de la adolescencia, en su opinión, todo obedece a la retraso madurativo. No quiere residir en ningún sitio en que haya normas, sólo quiere estar en la calle, fumar y beber. El jueves pasado estuvo tomando vino de un tetrabrik, tras ducharla y darle café para espabilarla, pues estaba afectada, intentó escaparse y cuándo Pilar la alcanzó y paró hizo amago de pegarla pero finalmente se controló y no llegó a darle. De vuelta en el hogar intentaron razonar con ella, pero como no había formad de calmarla llamaron al 112. **Esta misma tarde la trasladarán en ambulancia a la UME del CSS-Plas. No saben si dadas las circustancias allí podrán acudir a visitarla. Nos mantendrán al corriente. Yo me coordinaré con el CSS para estar al tanto de su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-08-07','Ana: Correo de Pilar Sánchez, Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "Buenas tardes, les informamos que llevamos a Margarita al Hospital para ingresar en la Unidad de Psiquiatría. Llevaba tres días bastante inquieta y hoy ha intentado escapar y se ha empeñado en que quiere ingresar. Hemos intentado hacerle cambiar de opinión, pero sólo insiste en que se va a escapar y que ya no puede más Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-08-11','TERESA ARCHIVO RESOLUCION RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-08-11','TERESA EMAIL DEL CRPS Te comento de Beatriz. Me ha llamado para decirme que la empresa con la que colabora como tarotista le ha dicho que ya no puede continuar cobrando en negro y que tiene que darse de alta. ha solicitado cita a la Seguridad social para ver si es compatible con su pensión y está convencida en firmar un contrato con ellos dándose de alta como autónoma. Le he dicho que debe ponerse en contacto con vosotros para comunicároslo y que la asesoréis, pero no quiere porque no quiere que le digáis que no; a pesar de que le he dicho que no tiene validez legal el documento que firme ella sin contar con su tutor legal. Se ha enfadado e incluso se ha puesto bastante impertinente conmigo, así que he terminado por decirle que haga lo que considere oportuno. Lo pongo en vuestro conocimiento por si llamase. BEATRIZ TIENE UNA INCAPACIDAD ABSOLUTA CON LO CUAL NO PUEE TRABAJAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-08-12','TERESA ARCHIVO RESOLUCION PIA SAD Y ENVIO COPIA AL AYTO DE ZAFRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-08-12','TERESA DOY REGISTRO DE SALIDA COMUNICACION CAMBIO DE DIRECCION AL INSS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-08-11','Ana: Conversación telefónica con Pilar - Hogar San Vicente de Paúl (671 016 615). Al preguntarle por la posibilidad de ingreso en su centro de Eugenia, me informa de que el límite de edad son los 60 años. Al igual que en CRR, al tenerlos ya cumplidos no podría ingresas. Por otra parte, dada la crisis sanintaria, no se han vuelto a producir ingresos en su centro desde antes de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2020-08-12','Llamada de Dª Hortensia, reclamando la colocación de una lápida para su primo. +++Dicen que han entrado en casa de su primo "alguien". +++Se le informa de que la Comisión cesó en su cargo de tutela cuando falleció su primo y que si cree que eso está ocurriendo que ponjga la correspondiente denuncia. +++Si quiere alguna información tiene que dirigirse al Juzgado correspondiente. +++Y puede reclamar la herencia de su primo: "Mi marido no quiere que haga nada, me va a costar la separación..." Se oye al marido por detrás diciendo "Mándalo ya a tomar por culo. O cuelgas tú o cvuelgo yo..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-08-12','Ana: Correos, durante mis vacaciones, de Sonia Leo, Directora de la Res. Virgen de la Montaña de Casar de CC (virgendelamontana@grupociudadjardin.com). Fecha: 27/07/2020 "Buenos días, le comunico que Pedro Román García, fue derivado y quedo hospitalizado el 25/07/2020. Un saludo". Fecha: 29/07/2020 "Buenas tardes Ana, me pongo en contacto con vosotros, porque como ya informe, Pedro Román García García esta ingresado desde el 25/07/2020. Hemos llamado varias veces al Hospital San Pedro de Alcántara para interesarnos por su estado, pero no conseguimos que nos la faciliten, suponemos que es por estar tuteado. ¿Os han informado de su evolución?. Un saludo y gracias" ············································································································································· Llamo al HSPA (927 25 62 00), hablo con Juani, TS. Me informa de que está en ingresado en Medicina Interna, en la habitación 220. Y me facilita varios nº para que contacte con los médicos (Despacho Médico: 927 62 15 23 // Sala: 927 62 15 24 / 927 62 15 28) llamo varias veces a todos los números sin respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2020-08-12','Ana: Recibo llamada de Mª Eugenia (633 578 274), le digo que hoy puede llamar a mi compañera Teresa, hoy está en la oficina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-08-12','(Pedro)Conversación con Judith, Admva. del Consultorio de Jerte (927-470121). +++No pudo llamar a la Comisión tras su conversación con Ana. +++La Médico le dijo que ella atendió a Felix el día 17 de julio en urgencias de Cabezuela y que no hay parte de lesiones. +++Pregunto sobre si dió algún dato sobre el accidente: volverá a hablar con la Médico para preguntarle. +++NUEVA LLAMADA DE JUDITH: +++++NO FUE ATENDIDO NI EN CABEZUELA NI EN JERTE, SINO EN EL HOSPITAL UNIVERSITARIO DE CÁCERES EL DÍA 17 DE JULIO (no tienen acceso a esa información). ······················································································································································· Correo de Miguel Ángel, Director del CRR-CC: "Buenas tardes Pedro, te informo después de mantener conversación vía telefónica con la hermana de Félix Valle Simón del accidente sucedido en su localidad de procedencia el día 10 de julio, me comunica que no se le acompaño a los servicios de salud (Centro de Salud de su localidad) cuando sucedió el accidente debido a que fue la tarde anterior al desplazamiento al CRR siendo ella quien le observo el estado del pie y decidió comprarle en la farmacia una crema antiinflamatoria. Ella desconoce como fue el suceso y me comunica que también ella tiene la misma sensación que tenemos en el CRR de que la persona que le dio en el pie no se dio cuenta y es por esto que no paro el automóvil. No te puedo dar más información de la que disponemos. Un cordial saludo." +++++++++++++++++++++++++++++++++++++++++++CORREO de Miguel Ángel, Director del CRR de Cáceres (14:59h). +++De: residenciadir@feafescaceres.com >residenciadir@feafescaceres.com> Enviado el: miércoles, 12 de agosto de 2020 14:33 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: A AT/ PEDRO GRACIA. ACCIDENTE F.V.S Buenas tardes Pedro, te informo después de mantener conversación vía telefónica con la hermana de Félix Valle Simón del accidente sucedido en su localidad de procedencia el día 10 de julio, me comunica que no se le acompaño a los servicios de salud (Centro de Salud de su localidad) cuando sucedió el accidente debido a que fue la tarde anterior al desplazamiento al CRR siendo ella quien le observo el estado del pie y decidió comprarle en la farmacia una crema antiinflamatoria. Ella desconoce como fue el suceso y me comunica que también ella tiene la misma sensación que tenemos en el CRR de que la persona que le dio en el pie no se dio cuenta y es por esto que no paro el automóvil. No te puedo dar más información de la que disponemos. Un cordial saludo. Miguel Ángel Ramírez Félix','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-08-12','Ana: Correo de Futuex (areasocial3@futuex.es): "Jose Manuel Moreno Carlos, nos comunican q le han concedido plaza para CRR y al parecer accede, entendemos te lo han comunicado pero por si acaso, está es la secuencia: 06/08/2020 Se realiza llamada de seguimiento para comprobar su situación actual y fijar fecha para realizar visita de seguimiento, el tutelado expresa que sen encuentra bien y todo continúa dentro de la normalidad, accede a que se realiza visita el en domicilio el próximo Jueves 13 de agosto. Posteriormente se recibe llamada de Marisa Olivera Ts del equipo de salud mental de Coria, para informar que le han concedido plaza en CRR de Plasencia y la semana que viene previsiblemente se realizará la entrevista con el centro para valorar su ingreso, solicita que se trabaje la motivación para que el tutelado ingrese en dicho recurso de forma voluntaria y que consideran desde este equipo que sería benéficos para él aunque fuera temporal, puesto que se podría trabajar aspectos como la toma de conciencia sobre su enfermedad o la adquisición de hábitos de ocio.... 11/08/2020 Se recibe llamada de la trabajadora social del Centro de salud de Torrejoncillo explicando que el Lunes se produce el ingreso del tutelado en CRR, explica que el tutelado le ha comunicado que se le realizaría una visita este jueves por parte del equipo de apoyo de Cáceres y llama para informa que se le ha concedido la plaza y que el ingreso se produce el próximo lunes 17 de agosto." ······································································································································ Conversación con Paula, TO CRR-Plas. (682 704 401)a última hora de la mañana: José Manuel ingresará el lunes 17 en el CRR. Le han hecho una entrevista telefónica, dada la situación sanitaria ahora lo hacen así, espera que a pesar de ello y José Manuel se adapte bien. Me pregunta por los términos de la incapacitación, le explico lo que aparece en la sentencia y, tal y como acordamos, le envío copia a ella (tocupacional.crrplasencia@grupo5.net) y a Blanca (coordinaciontecnica.crrplasencia@grupo5.net). *Por otra parte, Jose Manuel tiene cita con un especialista en Coria el día 27 de agosto, para que no la pierta, solicitarán autorización a la parte eco para que acuda a la misma. Después le cambiarán al área de salud de Plasencia y pedirán los cambios de especialistas correspondientes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-08-12','(Pedro)Conversación con Cristina, del CRR de Mérida, en relación al correo de fechas 5,7 y 12 de agosto en el que José Mª pedía tener una reunión conmigo porque necesita un colchón y alguna cosa más. +++Comento a Cristina que para ello no copnsidero necesario mantener una reunión, y menos en laas circunstancias actuales. Pido que hagan un presupuesto con las necesidades que José Mª manifieste y que consideren oportunas y lo remitan a la Sección Económica. +++En el caso de que , además, quiera hablar de algún otro tema de otra índole, podemos quedar un día para hacer la consulta por teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-08-12','Ana: A petición de Icíar, secc. ecca., cumplimento y pido a Tere, TS CTAEX, que ponga para firma, comunicaciones de cambio de número de cuentas de PFHC y P.Orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-08-12','Ana: Correo de Javier, Director del CRR-Plas., a las 16:01 h.: "Buenas tardes Emilia MB tenía hoy revisión médica de la cirugía del pie en el Hospital de Mérida, ayer sacó de su cuenta 30€ tal y como se autorizó por la sección económica de la C.Tutelar. Esta mañana viajaba a Mérida en autobús con salida de Plasencia a las 8.10 de la mañana, la vuelta a Plasencia era en un tren de a las 15.10 de la tarde llegando a Plasencia sobre las 17.30. Es coste del viaje total es de 27€, aunque hay que añadir el descuento por la tarjeta de persona con dependencia. Sobre las 14.45 recibo llamada desde el CRR de Mérida intenta acceder al recurso y ante la oposición de los profesionales, Emilia les amenaza y grita, al final decide marcharse. Desde el CRR de Plasencia, nos ponemos en contacto con Emilia que nos informa que ha decidido viajar en el autobús que sale de Mérida a las 23.00 hs (llegando a Plasencia a la 1 de la madrugada), porque "le sale más barato que el tren y así se queda con más dinero". Os informo de esta situación por dos motivos, el primero que no tengo la certeza que Emilia pueda subirse al autobús de las 23.00 hs y si vendrá al recurso a su llegada a Plasencia o decidirá dormir en casa de una supuesta pareja que ha tenido en Plasencia; y segundo porque la situación es complicada con ella cada vez que tiene que seguir una pauta, una norma, un acuerdo. Que ya no sólo se limita en sus explosiones de falta de control al CRR de Plasencia, también al de Mérida (o incluso a la propia C.Tutelar, como ocurrió en su viaje anterior). La unidad de Gestión de programas asistenciales del SEPAD, conoce esta situación de Emilia, el CRR de Mérida llamará al 091 si vuelve a personarse en esas condiciones en el recurso y desde luego creo que es necesario una consecuencia con ella. Mañana según sepamos el desenlace de hoy propondré consecuencias a la unidad de programas y os informaré de ellas. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2020-08-12','TRASLADO A HOSPITAL CSS de Mérida: "Se comunica a esa Comisión Tutelar de Adultos que el interno Juan Bautista Ramírez de la Rosa, ingresado en este Centro y tuelado por esa Comisión, será trsasladado al Hospital de Mérida, en fecha 12/08/2020."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-08-12','Ana: Conversación con Paula, T.O. CRR-Plas. (682 704 401): "Conchi continúa en el CRR, no descartan que vuelva a pasar a piso supervisado, pero de momento necesita el apoyo del la residencia. *Este fin de semana, viajará a su pueblo, al domicilio de su hermana a pasar el fin de semana (menos de 48 h.). Se le han recordado todas las recomendaciones de prevención del Covid-19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-08-13','(Pedro)LLamada de Juan José.Tema :Quiere sacar su dinero como todo el mundo "cuando quiera". Porque ya he comprendido que el dinero hay que gastarlo en cosas necesarias y en el CRR me decían vuestros compañeros que lo estaba haciendo bien..." +++Se le pide que siga con esa actitud y que se dé un tiempo para adapatarse a sus nuevas circunstancias. +++Muy educado y comprensivo. ················································································································································ Ana: Conversación con Amalia, TS-CTAEX; Juan José actualmente retira su asignación de forma semanal y él quiere retirarla, si no cuándo quiera, al menos de forma mensual. Amalia plantea hacer prueba quincenal y valorar si funciona. Ahora está mejor, pero anteriormente compraba de forma compulsiva. Por lo demás, suele funcionar bien. Su madre es mayor, pero mantienen contacto y la visita. *Está muy contento con la permuta de Badajoz a Cáceres, pues él es de CC y llevaba mucho tiempo esperándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-08-13','(Pedro) Ayer llamó su hermana Teresa porque no sabían nada de él. +++Llamo hoy a Teresa, su hermana.Le informo de que he hablado con José Mª esta misma mañana y se encuentra bien. +++Ha llamado a su madre en el día de ayer (José Mª). +++Ante la posibilidad de no encontrar alquiler le planteo la alternativa de buscar ella alguno en Jerte: "Eso no es posible porque no quiero que esté cerca de mis padres y menos ahora con el tema del covid. Ya le he dicho que por aquí no venga hasta que tenga un piso nuevo de alquiler y venga aseado y duchado..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-08-13','TERESA SOLICITO A TONIO TS CENTRO SALUD INFORME MEDICO PARA ADJUNTAR A LA SOLICITUD DE INGRESO EN RESIDENCIA SOLICITIO POR EMAIL y POR CARTA INFORME SOCIAL A LUISA PADA ADJUNTAR A LA SOLICITUD DE INGRESO EN RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-08-13','(Pedro)Conversación con Teresa, hermana de Félix. Sobre el "accidente" que dice haber tenido: +++El viernes 10 de julio le hicieron la prueba del covid-19 y el lunes le dieron el resultado. +++"El accidente se produjo el día 13 de julio, la víspera de antes de volver al CRR. Él recorre todo el pueblo, legusta salir a la garganta y no parar. Cuando volvió a casa dijo que le había atropellado un coche...dos veces. Le dijimos que cómo era posible eso y nos dijo que, bueno, que le había atropellado un coche el pie...Siempre que tuiene que volver al CRR empieza a decir que algo le duele (lumbago, etc.) y a decir que no quiere volver con esos H. de ***. Le dijimos que cómo era el coche pero solo decía que era uno garande, como una pick up te teníamos antes y que era de color oscuro (en el CRR dijo que no sabía de qué color). NO LO LLEVAMOS AL MÉDICO en el Jerte porque aunque tenía el pie dolorido le dí con una crema y no lo consideramos necesario. Mi marido dice que no se lo cree,que mi hermano es de esa manera de ser y que no se puede estar nunca seguro de lo que te dice."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-08-13','(Pedro)Correo de Miguel Ángel, del CRR de Cáceres en relación a la RENUNCIA de HERENCIA: +++Buenos días, os informamos que se ha realizado llamada telefónica para concertar cita con la Notaria Virgen de Guadalupe de Cáceres referida al caso de renuncia hereditaria de Félix Figueroa Martín y nos comunican que no es necesaria tener cita previa para gestionar el tramite simplemente se debe acudir a la Notaria para que nos deriven al profesional encargado de herencias y allí nos informan sobre los pasos que hay que seguir. Se le comunica a Notaria que es el caso de una persona curatelada a nivel económica/ administrativa por la CTAEX y que sería conveniente que nos aporten el nombre del profesional que se va a encargar de realizar los trámites y nos siguen comentando que los pasos a seguir con respecto a que le atienda el profesional encargado de herencias es el expuesto anteriormente. Se realizará acompañamiento a la notaria el martes 18 de agosto, una vez nos informen y comuniquen allí sobre el profesional encargado de herencias, si hay que aportar informes o documentación, etc… manteniéndoos informados en todo momento sobre valga la redundancia la información que nos remitan o sobre la documentación que sea necesaria aportar… Un cordial saludo. Miguel Ángel Ramírez Félix Director Técnico CRR- PS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-08-12','TERESA ENVIO SOLICITUD DE PF Y ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-08-13','TERESA ENVIO SOLICITUD MODIFICACION DE DOMICILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2020-08-13','Ana: Correo de Mª José Polo, TS de SSASB Mancomunidad Trasierra de Granadilla (ssbm@trasierratierrasdegranadilla.es): "Buenos días, se le ha estropeado la puerta del dormitorio a Florencia Simon de Zarza de Granadilla, debido a las termitas Te mando dos presupuestos para que nos autoriceis al cambio del marco" ····· Renvío el correo a Alberto y al ctutelar@ a la A/A de la secc. ecca. Y pido a Mª José que a partir de ahora remita a la secc. ecca. a dicha dirección todo lo relativo a cuestiones económicas. ······················································································································································· Icíar me comunica que Florencia continúa sin percibir la PFHC, llamaré mañana al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-08-13','(Pedro)Conversación/llamada de Javier, Director del CRR de Plasencia. +++Emi llegó al CRR a las 02.00h, exigiendo la cena y amenazando con "montarla" si no se le hacía caso. En ese tono no se atendieron sus demandas y se fue a acostar. +++Considera que es imposible trabajar nada con ella con esta actitud. +++Javier estará de VACACIONES desde el 17 de agosto al 07 de septiembre. Se queda en su lugar Blanca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='VAZQUEZ'and apellido2='GILEZ'),'2020-08-13','Entregan de registro docuemntación de la Agencia Tributaria sobre deuda contraida tras finalización del plazo de pago voluntario (08-01-2020). Se trata de una multa de la DG Tráfico por no tener la ITV realizada. +++Lo paso a la Sec. ECo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-08-13','Ana: Llamada de Emi, ayer acudió a la revisión de su operación al hptal de Mérida. Le dijeron que todo va bien. Le quitaron la venda y le pusieron un pequeño apósito. En cuanto a la vuelta al CRR tras la consulta, dice que no cogió el tren porque le salía más caro, por ello regresó en el autobús de las 23 h a Plasencia, y llegó a las 2:00 a.m. al CRR. Está muy enfadada porque dice que no le guardaron cena y que por ello no se quiso tomar las pastillas. Esta mañana tampoco se las ha tomado. Le digo que no puede estar sin tomarlas, sabe que no le viene bien. Dice que entonces en un rato comerá algo para la merienda y se las tomará. *Hablará con Carolina y Javier, CRR, para pedir, que si no pueden trasladarla a Mérida, como ya ha pedido, que la cambien a CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-08-13','Ana: De nuevo hoy llamo a Medicina Interna, del HSPA, (Despacho Médico: 927 62 15 23 // Sala: 927 62 15 24 / 927 62 15 28), a distintas horas a lo largo de la mañana, pero no obtengo respuesta en ninguno de los nºs. / Pdio a Pedro, Jefe de secc., que lo intente él desde el despacho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-08-13','(Pedro)LLamada de José Manuel. +++Anteayer estuvo en el médico porque tenía molestías en el costado. Le hicieron nuevamente la prueva del covi-19 (dice que es la 5ª) y le dió negativo. La Médico le aconsejó que dejara de tomar las bebidas energéticas de las que abusa. Él mismo refiere que se toma 3 o 4 cuando se acuesta "para pasar toda la noche..." y otras tantas por el día. SE le insite en que debe hacer caso a la recomendación de su Médica. +++Al parecer, según comenta, le ha llamado su PSIQUIATRA: "Va a hacer un Informe él y la T. Social para que entrar en un CRR. Per4o me ha dicho que es MI ÚLTIMA OPORTUNIDAD..." +++Dice que va a dejar de tomar esas bebidas porque "me hacen mucho daño...". +++También hace referencia a cómo está el tema de la modificación de medidas, porque al parecer su hijo está trabajando "desde que le eché de casa..."Le informó que el Colegio de Abogados ya designó abogado y procurador, pero "no se han puesto en contacto todavía conmigo...". +++++++++++++++++++++++++++++++++++Conversación con Pilar Martín. +++Van ha hacer propuesta de ingreso en CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2020-08-14','Ana: Llamo a Antonio Ballesteros, Jefe de Secc. de PFHC (927 62 00 23), en relación al impago de la PFHC dice que debe haber algún problema con la transacción, pero no sabe cuál, intentará averiguarlo y me devolverá la llamada. ············································· Antonio me devuelve la llamada: dice que si Florencia no está cobrando la prestación debe haber un error/problema con el banco, pues a ellos les figura que están todas las mensualidades abonadas desde octubre de 2019, incluso la de Agosto qué aún no habrá entrado, en la cuenta de Liberbank, que estaba ella sola: ES12 2048 1007 6634 0000 3701. ················· Se lo comunico a Icíar, secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-08-14','(Pedro)Conversación con el Dr. Antón, de Medicina Interna del Hospital San Pedro de Alcántara. (927-621523). +++Preguntado por el estado actual de D. Pedro el Médico contesta: "...es un superviviente..." +++Está siendo tratado por una bacteriemia (cándida en sangre). Tuvo una hemorragia digestiva con un índice de hmgba de 7, que obligó a realizar una transfusión.También tenía alguna pequeña grieta en los talones y quizá haya sido por ahí por donde se haya podido producir la infección. +++"En estos momentos se encuentra tranquilo, ha comenzado a comer bien, está más lúcido e, incluso,ha pedido que le afeiten para estar más arreglado...Ha habido algún momento de agitación anteriormente pero nada significativo". . PREVISIÓN DE ALTA: dependerá de la evolución de la bacteria presente en sangre. Le ha pedido varios cultivos para valorar dicha evolución y si los resultados son los esperados quizá le den el ALTA el próximo JUEVES o VIERNES. +++Si se confirma el alta, le harán la prueba PCR antes de volver al Centro siguinedo el protocolo. +++Pregunto si necesita algo que desde la Comisión le podamos facilitar, en concreto necesidad de ACOMPAÑAMIENTO: "NO ES NECESARIO, SE ENCUENTRA BIEN Y TRANQUILO...". +++SOLCITO que nos ENVIEN INFORME DE ALTA a la Comisión. Dejo fax y correo-e de ctutelar. ················································································································································· Ana: Llamo a la Res. Virgen de la Montaña (927 290 550), me comentan que Sonia Leo, Directora, está de vacaciones, y me piden que les envíe la información que han facilitado al correo electrónico para que puedan trasladarlo a las enfermeras de la Res. y prepararse para el alta. ······ Lo remito al: virgendelamontana@grupociudadjardin.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELEDONIO'and edp.apellido1='GARCIA'and apellido2='MATEOS'),'2020-08-14','Ana: Aceptado el cargo de Defensa Judicial el 11/06/2020. ······················································································································································· Recibo llamada del C. Salud de Trujillo (927 32 23 63), Cora me pregunta si somos Tutores de Celedonio, le indico que de momento sólo se ha aceptado el cargo de Defensor Judidial por la CTAEX. *Necesita enviar bastante documentación e informes que tiene allí en el C.Salud a la Tutora, pregunta si nos lo puede enviar. **Preguntaré a Pedro, Jefe de Secc. y en su caso a los compañeros jurídicos. ····················································································································································· Correo de Ángel, Asesor Jurídico, "... Acabo de hablar con Escalona y me indica que si ha recurrido la excusa presentada por la hermana en el procedimiento de remoción del cargo, pero no puede facilitarme más información porque está de vacaciones, con el teléfono desviado… Podemos llamar a Secretaría de Abogacía y preguntar por este expediente, por si tuvieran más información, pero no me sé el teléfono. Si me lo facilitáis llamo. En mi agenda negra de la mesa, en la pestana A, de Abogacía, están los teléfonos. Si no en la G, de Gabinete Jurídico. Hasta que tengamos constancia de la resolución del recurso, quien sigue ostentando el cargo de tutor es su hermana, aunque tiene toda la pinta que finalmente seremos nosotros, por lo que hasta entonces no deben enviarnos documentación alguna." ············································· Llamo a Cora, C. Salud de Trujillo (927 32 23 63), pero no obtengo respuesta. +++++++++++++++++++++++++++++++++++++++Nuevo correo de Ángel: Buenas, de nuevo, Acabo de hablar con Ana, de Abogacía. Me indica que efectivamente, Escalona recurrió. Tiene constancia que el 29 de julio le han dado traslado a la parte contraria para que alegue lo que estime conveniente, por 10 días. Posteriormente, resolverán. Con lo que posiblemente, a fecha de hoy, aún no lo hayan hecho. EL HILO DE CORREOS-e ESTÁ EN SU EXPEDIENTE VIRTUAL. ······························································································································································· Ana: A última hora consigo contactar con Cora, C. Salud de Trujillo (927 32 23 63), acordamos que, de momento, guardarán la documentación y cuando haya una resolución firme se lo comunicaré a ella o a Laura, y en caso de ser nombrados Turores, desde la CTAEX nos pondremos de nuevo en contacto con ellos para que nos la remitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-08-12','Ana: Una vez confirmado con los compañeros admvos.-CTAEX, que Eugenia tiene reconocido Grado II de Depedencia, llamo a Ana Benavente, TS del ESM-Pla., para comunicárselo. *Solicitaremos a Gema, TS del SSB, que pida plaza residencial por Dependencia, pero como prioritaria, con informe social por emergencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-08-14','Ana: Solito a Clara I. Gómez Nestares mediante correo-e (clara.gomez@salud-juntaex.es) nos facilite Certificado de Grado de Dependencia de Eugenia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-08-14','Ana: Solicito a Clara I. Gómez Nestares mediante correo-e (clara.gomez@salud-juntaex.es) nos facilite Certificado de Grado de Dependencia. Ya se lo solicité hace meses mediante nota interior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-08-14','Ana: recibido llamada de Jesús Manuel (635 33 65 39), le he dicho que excepcionalmente le atiendo y lo comunico a la secc. ecca. pero que las cuestiones económicas no debe decírmelas a mí para que yo las traslade, sino que las debe comunicar directamente a secc. correspondiente. Como dice que no le cogen el teléfono y, se pone como se pone, le he dicho que sólo por esta vez (y porque entiendo que es algo que deben mirar). El caso es que dice que este mes *se ha pagado dos veces el alquiler. Por otra parte dice que necesita una botella de butano… Comenta también que Virgina (Futuex) es quién le hace el seguimiento y que el lunes ha quedado con ella. ································ Lo comunico a la secc. ecca. al ctutelar@','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-08-14','miguel, llega el día 12-7-2020 diligencia de ordenación del Jzdo nº6 de Cáceres dandonos traslado de contestación de demanda de procedimiento monitorio por deuda con Vodafone. *********************************************************** Preparo contestación a la demanda y oficio y envío email a los compañeros para que lo pongan a la firma, den salida y envíen por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-08-14','Ana: pido a Julio,CTAEX, por email, que me confirme si, como me comentó Amalia, CTAEX, puso él para la firma los documentos para el empadronamiento, y en tal caso, si él o Juan Pedro lo han envido al CRR. ················· Julio me comunica que no sabía nada al respecto. *El lunes me encargaré de los tramites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-08-14','(Pedro) Llamada de la Residencia de Torre de Don Miguel, para recbar datos para formalizar el contrato de residencia. +++Nos lo enviarán a ctutelar para su cumplimentación y firma. +++En el correo incluirán también todos aquellos aspectos que considerne oportunos de cara a la intervención de la Comisión: presupuesto de gastos, certificado de pensión,etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2020-08-14','miguel, el 11-8-20, me llega email de la parte económica, sobre el impago por alquiler que reclama la tutelada. Tras analizarlo con la parte económica (Alberto y Belén)les remito el word con el burofax para que se lo den a la tutelada y vaya a presentarlo a correos. Pasados 30 días desde su notificación, caso de no justificar los pagos lo pondremos en manos de abogado de pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-08-14','(Pedro) Correo de Pilar Martín (ESM Cáceres): +++Hola Pedro, hoy hemos remitido informes clínico y social de José Manuel Romero Mediavilla a la Comisión de Valoración de Acceso a Recursos ResidEnciales Comunitarios de Saud Mental para solicitar que se retome la solicitud previa de CRR dado que se encuentra estabilizado desde el último ingreso en UME. ························································································································································································ Ana: Llamada de José Manuel (722 493 622), me trasnmite lo mismo que a Pedro ayer y añada que se encuentra mal. Sigue pendiente de la colonoscopia que tienen que hacerle, aún no le han dado la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-08-17','Ana: Pongo para la firma del D.Gerente la Autorización Expresa remitida por Rosa, Advo. del CSS-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-08-17','Ana: Pongo para la firma del D.Gerente, el contrato de la Residencia de Torre de Don Miguel, por triplicado, junto con la orden de domiciliación de adeudo de abono de dicha residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-08-17','Ana: Pongo para la firma del D-Gerente la Hoja de Inscripción Padronal de Ayto. de Cáceres. Y para Registro de Salida el oficio para enviarlo adjunto. *El documento de Autorización, corresponde firmarlo a algún representante legal de la Entidad que gestiona los pisos (FEAFES), pues autorizan a que se incriba en dicho domicilio. ·································· Así lo comunico en un correo al CRR-CC. ·········································································· Pido a Juan Pedro, Admvo. CTAEX, que si el miércoles están ya los documentos, los envíe por correo certificado al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='RUBIO'and apellido2='BRAVO'),'2020-08-17','(Pedro)Llamada recibida de D. Marco Rubio (918-082598), sobrino de Dª Jacinta. +++Quiere saber cuáles son los pasos a seguir para reclamar la herencia. +++Le explico el papel de la Ctaex tras el fallecimiento y le informo para que se ponga en conbtacto con el Juzgado Nº 3 de Plasendcia. +++A petición suya, le pongo con Ángel.','1');
