insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-08-17','Ana: Realizo derivación a FUTUEX para seguimiento no exhaustivo de Juanjo ahora que reside en piso supervisado, donde contará con mayor autonomía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-08-17','Ana: llamada de Emi (643 803 243): lo primero que dice es que le ayude que está "en problemas". Según relata, lleva 2 días fuera del CRR, se fue al piso de "un amigo", pero dice que hay tantas cucarachas que prefiere dormir, y así lo ha hecho, en la calle. Dice que se tomó una caja de ibuprofeno en un descampado junto al CRR, al preguntarel con qué intención, responde "para nada, yo sabía que no me iba a pasar nada, ya me las he tomado más veces, pero me dio mucho sueño". Añade que se cayó por un terraplen. *En el CRR le acusaron de haber salido del centro y por eso, dice, se escapó y se encontró a Francis, quién le llevó al piso de su amigo. **Intentó darle un tortazo a Juan Llanos por chivato, dijo a los monitores que estaba pidiendo dinero a otro residente, pero no llegó a darle, sólo le rozó y ahora Victor, un monitor, le acusa de haberle pegado. Por otra parte dice que cuando llegó por primera vez al CRR **Juan Llanos abusó de ella, se aprovechó de que estaba "malita" para que le hiciera una felación, la "engatusó" con invitarla a desayunar churros, la engañó para que entrara en el cuarto de baño, cerró el pestillo y le besó en la boca y ella no quería... No puso denuncia. *Por último dice que va a buscar trabajo como interna en una casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICANOR'and edp.apellido1='IÑAÑEZ'and apellido2='CORTES'),'2020-08-18','Comunican por fax desde elCSS de Mérida el ingreso de D. Nicanor en el Hospital de Mérida ayer, día 17 de agosto de 2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2020-08-17','Ana: Pongon para REGISTRO DE ENTRADA comunicaciones al INSS de cambio de número de cuentas de PFHC y P.Orfandad.','2');
