insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-08-10','Ana: Llamada de Ana Benavente, el día 6, cuando acudió Damián a la cita, presentaron un recurso en relación a la resolución de la valoración de dependencia. ······························································································································· Llamada de Damián: Comunica la misma información facilitada por Ana Benavente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-08-18','TERESA RECIBO EMIAL DE EUGENIA TS SBB 924730101. ME COMENTA QUE LA CASA DE RAMON ESTA EN MALAS CONDICIONES DE HIGIENE, VA A INTENTAR HACER UNA VISITA PARA VERIFICAR EL ESTADO Y SI ES NECESARIO INTERVENIR PARA SU LIMPIEZA. ME PREGUNTA SI SABEMOS ALGO DE LA INCAPACITACION DE SU MADRE PERO A DIA DE HOY NO HEMOS RECIBIODO NADA AL RESPECTO QUEDA EN PONERSE EN CONTACTO NUEVAMENTE CONMIGO UNA VEZ REALIZADO LA VISITA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-08-18','TERESA Te comento que ayer hizo Beatriz la visita a su hija tal y como habíamos acordado. Como la casa de los padres está a 1 km pasaron a saludarlos y la madre le comentó que el dia anterior le habían hecho la PCR. Estuvieron 15 minutos si acaso porque la monitora que acompañaba a Bea no consideró oportuno estar más tiempo puesto que la madre estaba sin mascarilla LA PCR NOS HAN COMFIRMADO QUE DIO NEGATIVA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2020-08-18','El SSB de Monesterio nos envía personas interesadas en la compra del solar de Francisco. (Manolo Fernández, tlf. 627 823 782 y José Carlos tlfo. 637 032 130)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-08-10','Ana: Llamada de José Manuel (722 493 622): Dice que le ha llamado el Psiquiatra, que le ha dicho que van a pedirle plaza en Cróncicos en el CSS, pero que él se ha negado, dice que allí no quiere ir de ninguna de las maneras. ··· Por otra parte, dice que se encuentra mal, tiene pendiente haceres una colonoscopia, aún no le han citado. ··· Va a dejar de consumir bebidas energéticas, pues los médicos le han dicho que le van fatal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-08-18','Ana: Llamada de José Manuel (722 493 622): pregunta si Pilar Martín, TS ESM-CC, nos he enviado el informe para ingresar en CRR. *Le explico que a nosotros no tiene que enviarnos dicho informe ni la solicitud, le recuerdo que nosotros ni lo decidimos ni lo gestionamos, pero que sí nos ha informado de que el viernes lo envió a la Unidad Correspondiente para que lo valoren. ···· Me pregunta también por la pensión compensatoria que pasa a su mujer por sus hijos. Le indico que aún no se ha puesto en contacto el abogado asignado, pero debe tener paciencia, agosto es un mes inhábil en los Jdos. y tampoco sabemos si el abogado está de vaciones, es mala fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2020-08-12','- Amalia : Lali nos informó en diciembre del contrato de Jorge , 1 año , media jornada en el Ayto Merida . Lo envió a ctutelar junto con la renuncia como nadié le contestó no volvió a contactar con nosotros. Pongo a firma del Gerente el contrato y lo reenvio junto con el documento necesario a PNC para comunicar variaciones. Firmo renuncia a C.O. Cuando acabe el contrato si quiere volver hay que volver a solicitarlo. Efectivamente nadie me remitió firmado la baja del servicio, y aprovecho para recordar que si desea volver al centro tras el fin de contrato, debe solicitarlo de nuevo al SEPAD. Saludos Laly C. Efectivamente nadie me remitió firmado la baja del servicio, y aprovecho para recordar que si desea volver al centro tras el fin de contrato, debe solicitarlo de nuevo al SEPAD. Saludos Laly C.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2020-08-18','-Amalia : entrego a Mayte la baja al servicio de C.O. y se lo comunico a Lali . Dejo el contrato y lo de PNC para que lo envien los auxiliares a PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-07-31','Ana: Juana-CTAEX, me comunica mediante mail que ya han procedido a dar de baja la transferencia de la cuota de la Asociación de Jugadores en Rehabilitación “Virgen del Puerto” de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-08-11','Ana: Llamo a Julia Hdez., madre de Julia (644 876 893), y hablo con ambas. Julia está residiendo en Cilleros, en el domicilio familiar desde mayo que le dieron el alta en el CSS-Plas. Desde entonces está muy bien, estable y contenta. Le alegra que la CTAEX ya haya aceptado el cargo. Le gustaría irse a vivir a un centro, pero uno que tenga actividades o talleres ocupacionales. La propia Julia expresa, que *no quiere ir a CRR, ya estuvo y dice que un centro muy abierto y que eso a ella no le viene bien. *Les informo que hay que tener paciencia, que aún estamos en fase de inventario y no contamos aún con documentación alguna, estamos a la espera de que nos la remitan. En cuanto podamos comenzaremos a realizar las solicitudes y gestiones oportunas. Por otra parte, se hará derivación al Progama de apoyo comunitario (FUTUEX) desde el que en unas semanas irán a visitarla y podrán ayudarla en distintas cuestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-08-14','Ana: Recibo llamada de Julia (644 89 73 39), pregunta si puede seguir sacando el dinero en el banco como hasta ahora. Le explico que por el momento sí, pues aún los compañero de la secc. ecc. no tienen información sobre sus cuentas. En cuanto las tengan y hagan los trámites oportunos se le pondrá una asignación para que pueda retirar dinero. La idea es ayudarle a administrarse y ahorrale un dinero para cuando lo pueda necesitar. *Dice que lo entiende y le parece bien. ··· Por otra parte, comunica haber *perdido la tarjeta sanitaria. El centro de Salud que le corresponde es el de Hoyos. *En cuanto pueda intentaré pedirle un duplicado de la tarjeta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-08-18','-EMAIL XESCA , TS PALAFOLLS : Tal y como te comenté Joaquina está ingresada en el Psiquiatrico de Mataró, se está valorando un ingreso a largo plazo. Idelfonso ha venido de manera (espontanea) hoy, he podido mantener una entrevista. Acepta el seguimiento psiquiátrico y me ha pedido que me ocupe de esa gestión. Aunque dijo en un principio que no retiro el dinero del cajero de Malgrat de mar el miércoles lo hizo, esta durmiendo en la calle y también ocupando, pide comida también en la calle…. Hemos acordado que el lunes pasará por aquí. Me dirijo a vosotros para solicitaros si tenéis algun informe psiquiátrico de este año 2020, nos lo solicita el psiquiatra con el que vamos a intentar la vinculación, quiere conocer el diagnostico. (por mi parte le haré llegar el diagnostico que consta en la sentencia)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-08-18','-Amalia: le han comprado el billete de tren y se viene a Mérida .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-08-19','Enviamos a la Abogacía General, solicitud para que inste el traslado del expediente al organismo tutelar de la Comunidad Autónoma de Castilla-La Mancha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2020-08-19','En relación al procedimiento DPA 602/2019, seguido en el Juzgado de Instrucción nº 4, de Plasencia (agresión de Alfonso a un vigilante de seguridad en el Hospital Virgen del Puerto, de Plasencia), el Juzgado está intentando citarle para que le reconozca el médico forense, a efectos de su imputabilidad. No acude a las citaciones, tampoco a las que ha practicado el Juzgado de Instrucción nº 2, de Coria, que recibió auxilio para intervenir por parte de Plasencia, al residir Alfonso en Torrecilla de los Ángeles, y pertenecer este municipio a ese Partido Judicial. Devueltas las actuaciones al Juzgado de Plasencia, comunicarán esta circunstancia a su señoría en septiembre, a los efectos de determinar lo que corresponda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2020-08-19','Llama la madre de Francisco, (661417701), quiere dejarle a su nieta, hija de Francisco, de 11 años, una casa en las minas y un campo. Menciona que compró otra casa, una vez fallecido el marido. La nieta está en acogida con su sobrina, Ana Garrido. Le indico que vaya a Notaría(ella dice conocer y tener confianza con la Notaría Varona, de Cáceres), la cual desconozco y plantee una posible donación en vida, para tenerla en cuenta, una vez fallezca, a los efectos del reparto igualitario de la herencia correspondiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-08-19','TERESA RECIBO EMAIL DEL CRPS Comunicarte que Beatriz se ha ido con su hermana a Calera de León y que nos ha comunicado que su expareja le ha puesto varias denuncias por injurias, amenazas, .... y no sé por cuantas cosas más. Nos acaba de llamar para decirnos que la han citado en el juzgado de Zafra el 21 de agosto a las 11:00 h y tiene que personarse con el tutor legal. PIEDO A TONI FUTUEX QUE LA ACOMPAÑE LA DELEGADA TUTELAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2020-07-06','El Abogado de Joaquina, Jesús Bueno, nos remite Testimonio de la Sentencia y Sentencia, dictada por el Juzgado de Primera Instancia 1 de Plasencia por el cual conforme al acuerdo alcanzado por las partes en el acto de juicio, debidamente ratificado: 1º.- Se acuerda la separación del matrimonio, declarando disuelto el régimen matrimonial. 2º.- Se acuerda la atribución limitada y temporal al esposo de la vivienda hasta lo que se acuerde en el proceso de liquidación de la sociedad de gananciales. 3º.- Se ordena la inscripción de la separación matrimonial en el Registro Civil en la inscripción de matrimonio de dichos cónyuges. Todo ello sin costas. El esposo procederá posteriormente a formular demanda para obtener la liquidación de la sociedad de gananciales con el reparto y adjudicación de los bienes del matrimonio. En dicho caso solicitaremos cuando recibamos la demanda del Juzgado, la suspensión del proceso hasta que le sean designados Letrado y Prrocurador por el Turno de Oficio a Joaquina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-08-19','Ana: Llamada de José Manuel (722 493 622), dice que se encuentra muy mal, solo y angustiado. Ha llamado a Salud Mental, pero le han dicho que su Psiquiatra está de vacaciones y no regresa hasta septiembre. Le planteo que si se encuentra muy mal puede llamar/acudir también a urgencias del hptal. para que le valoren en la Ud. de Psiquiatría. Ante esto, su respuesta es que está esperando que le llame el Psicólogo del Teléfono de la Esperanza, pues ayer cuando llamó a este númeron para hablar porque se sentía sólo, le dijeron que hoy le llamaría, que le vendría bien hablar con él. ···· Por otra parte, pide que le dé su número a los Asesores Jurídicos de la CTAEX, para que le llamen, pues quiere desheredar a sus hijos y dejar en herencia a su hermano José Luis, su parte del piso familiar, pues es el único que le ayuda y se lo merece. ············· Lo comunico por correo-e a los compañeros Ángel y Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-08-19','Ana: Recibido llamada Manuel Domínguez Duque, padre de Manuel, (Telf. 722 570 842), diciendo que su nieta (hija de nuestro tutelado) lleva 4 meses sin cobrar la pensión de manutención que le debe pasar Manuel. Al parecer ya se puso en contacto y envió el número de cuenta de su nieta a la secc. ecca. para que se solucionara el problema, el cuál viene ocurriendo desde que se cambió la cuenta de Manuel. Amalia, TS - CTAEX, le facilitó el número de Icíar, pero debió anotarlo mal, no se correspondía en un número. Ya se lo he dado bien. Le he dicho que en esta ocasión lo trasladaría a la secc. ecca. y que a partir de ahora, para las cuestiones meramente económicas, se ponga en contacto directamente con dicha secc. ············· Remito correo a la secc. ecca., tanto al ctutelar@ como al correo de Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='PARRA'and apellido2='ALCANTARA'),'2020-08-20','TERESA ENVIO NUMERO DE CUENTA BANCARIA PARA SER INCLUIDO EN LA BASE DE DATOS DE PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2020-08-20','TERESA ENVIO DECLARACION DEL PENSIONISTA Y GUARDO COPIA EN LA CARPETA DE PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-08-20','Ana: Correo de Pilar, TS del Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "...Con respecto a Margarita, nos informan desde el Centro Sociosanitario que no tiene una evolución lineal, parece ser que ha tenido algún día "regular". Sigue en sus trece de no querer venir, pero tampoco se quiere quedar allí. Según nos indican, demanda recursos en función de lo que va oyendo a sus compañeros (CRR entre otros) y nos han preguntado que, de darle el alta, donde iría. Me ha indicado la trabajadora social del Centro Sociosanitario que también ha intentado ponerse en contacto con ustedes, vía telefónica, pero tampoco le ha sido posible. Por favor, en cuanto puedan, pónganse en contacto con nosotros para ver qué se va a hacer." ····················································································································································································································································································································································· Tras hablarlo con Pedro, Jefe de secc. CTAEX, llamo a Emilia, TS del CSS; En cuanto a los datos básicos del perfil: 44 años, Grado II de Dependencia y Diagnóstico según Dictamen Técnico del CADEX: Alteración de conducta y Retraso Mental Ligero. **En estos momentos no presenta alteraciones de conducta, por lo que se descarta posibilidad de Derivación a UHDAC. *Se encuentra muy bien y cómoda en UME, debio en opinión de Emilia, a que es un sitio novedoso para ella, con nuevos compañeros/as, y ha pasado de fumar 1 cigarro al día (en el HSVP) a 9 diarios. Se siente más libre, entrando y saliendo del módulo a su antojo y acudiendo con frecuencia a la cafetería. *El Psicólogo le ha pedido a Emilia, que le dé los 30€ que le quedan, pero Emilia le ha pedido que le pongan límite, si le dan todo el dinero para tabaco y café no querrá volver al hogar. *La Psiquiatra aún no sabe cuándo darle el alta. La otra opción que se plantea es pasarla a Larga Estancia, pero no sabemos en este caso si podrían reservarle la plaza en el HSVP, pues la pensión es muy baja y si tiene que pagar el 75% al CSS, no podría asumir el coste de ambos recursos. **Emilia planteará a la Psiquiatra la posibilidad de que permanezca una temporada en UME (donde no tiene que pagar) pero con restricciones y límites, pues puede que así se plantee su retorno al HSVP. En caso de que fuera necesario, Pedro, Jefe Secc. CTAEX, podría llamar a UME para hablar con ella. ··································································································································································································································································································································································· Soraya Masa, Jefa Ud. RR. AA., en conversación con Pedro Gracias, Jefe CTAEX, plantea como alternativa que desde el propio CSS, soliciten revisión de PIA para pasar a CRR. ···································································································································································································································································································································································································· Dado que el Cdo. de Discapacidad que obra en nuestro expte. es antiguo y se hizo una valoración posterior (si hay imagen del Dictamen Técnico), solicito a Domingo, Director del CADEX-CC, por email, Cdo. de Discapacida en vigor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-08-20','TERESA ENVIO COPIA FIRMADA DE CONTRATO DE RESIDENCIA AL AYTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-08-20','Ana: recibido llamada de Jesús Manuel (635 33 65 39), con muy malos modos y dando voces. Le digo, de forma muy calmada, que hasta el momento yo no le he hablado mal ni le he faltado el respeto y por tanto o me habla bien o se termina la conversación. Jesús Manuel baja el volumen y relaja el tono. Pregunta quién ha autorizado el pago del alquiler de este mes sin su consentimiento. Le recuerdo que tienen una curatela por la cuál la CTAEX debe autorizar sus bienes. Y para cuestiones puramenete económicas no debe llamarme a mí, sino a la secc. ecca. Esgrime una serie de acusaciones infundadas sobre la CTEX como: "alguien de ahí se está beneficiando con esto", "se han chuleado mi dinero", "os estási llenando los bolsillos con el dinero que gano sudor de mi frente"... Le pregunto que en dónde está trabajando, responde que en nada, que se refería a su pensión... *Quiere cambiar de alquiler, dice que lleva pidiéndolo mucho tiempo, pero en la CTAEX no le hacemos caso, expresa... le digo que cuando se mantiene ese alquiler será por alguna razón. No obstante, preguntaré al respecto. **Por último, se queja "...mi piso de alquier lo utiliza todo el mundo menos yo", "entran gatos, que se han orinado en su sofá", "...también entran mujeres a ducharse porque he encontrado pelos de mujer en el baño", le digo que en ese caso puede acudir él mismo a interponer una denuncia a comisaría, pues para eso no está incapacitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-08-20','TERESA ENVIO POR CARTA OFICIO SOLICITANDO INFORME SOCIAL ACTUALIZADO PARA SOLICITAR INGRESO INVOLUNTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-08-20','(Pedro) Correo del CRR de Mérida (19-08-2020). +++Luisa Rodríguez: Tras dar un margen de tiempo pertinente tras el cambio de pauta que se produjo entre finales de Mayo y principios de Junio, solicitamos a Psiquiatra de urgencias (ya que su Psiquiatra de referencia de Mérida Norte no está actualmente). Fundamentalmente verbalizaba dificultades por las noches, tanto con el sueño como respecto a sintomatología que no estaba presente anteriormente. No hace mucho que se ha producido dicho cambio, estamos pendientes de la evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2020-08-20','(Pedro) Correo del CRR de Mérida (19-08-2020). +++José María Guillén: Hemos mandado el presupuesto a la sección económica para la compra del colchón. En general bastante crítico con todo, se lo hacemos saber y recapacita pero enseguida se repite el mismo comportamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-08-20','(Pedro) Correo del CRR de Mérida (19-08-2020). +++Mª Dolores Fernández: La semana pasada tuvo algunos días malos, hicimos salidas con ella (acompañada de profesional) porque ella no sabe identificar qué le pasa, refiere no tener "una preocupación en concreto". Pensamos que el haber reducido bastante las salidas del CRR (por el coronavirus) puede estar afectándole ya que como sabéis a ella le gustaba estar de un lado para otro con sus gestiones. Ya se encuentra mucho mejor. El lunes estuvimos preparando la cita con Psiquiatra que tiene esta semana. Esta tarde la acompañaremos a que le hagan un control de su audición y que nos digan si es necesario el uso de audífonos o no. Os informamos con lo que sea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2020-08-20','(Pedro) Correo del CRR de Mérida (19-08-2020). +++Antonio Fernández: Está bien, adecuado, sigue con su rutina habitual. Nada especialmente relevante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-08-20','(Pedro) Correo del CRR de Mérida (19-08-2020). +++Ángel Pinilla: Está bien, sigue acudiendo a sus citas con el Fisioterapeuta por los dolores de espalda. Algunos días percibimos especialmente eufórico pero se reconduce. Está solicitando irse a vivir fuera del CRR con su pareja (también usuaria del recurso). Les cuesta comprender que las medidas que se toman respecto a la pandemia que estamos viviendo son generalizadas y que no variarían mucho, independientemente de donde estuvieran. Cuando se le explican los motivos por los que no es una opción lo comprende y acepta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-08-20','TERESA RECIBO EMAIL M EUGINA TS JEREZ 924 730 101 Servicio Social de Atención Social Básica >ssbjerezcros@jerezcaballeros.es> la vivista a la casa de Ramon, esta otra vez en malas condiciones y con acumulacion de cosas. ENVIO A SUSANA PARA QUE ME INFORME DE LA SITUACION DE LA VIVIENDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-08-20','(Pedro)Llamada del Juzgado de 1ª Instancia nº 1 de Jerez de los Caballeros. Contacto JOAQUINA (924-751960).PROCEDIMIENTO 266/2020. +++Recaban la CONFORMIDAD de la Comisión Tutelar en cuanto a la NO AUTORIZACIÓN del ingreso involuntario solicitado, dado que se considera que NO SE DAN ACTUALMENTE LAS CONDICIONES QUE LO JUSTIFICARÍAN. LO NECESITAN para que su Señoría dicte la Sentencia definitiva. +++LO han enviado a Abogacía el 29 de julio. +++Pendiente de confirmar si se ha remitido a la Comisión o no desde Abogacía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-08-17','(Pedro)Pongo a la firma del Gerente la contestación al Juzgado de 1ª Instancia nº 6 de Cáceres (procedimeitno monitorio) y paso a Registro la firma del Oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-08-19','Llega el Oficio de la contestación al procedeimiento monitorio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-08-20','(Pedro)Se envía al Juzgado de 1ª Instancia nº 6 de Cáceres la contestación al procedimiento monitorio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-08-20','Ana: Correo de Toni-Futuex (areasocial3@futuex.es): "19/08/2020 Situación actualizada: Se acude a visitar a Eugenia a su domicilio actual, se aprecia que ha estado limpiando y desinfectando toda la casa a lo largo de la mañana; la vivienda se encuentra, más o menos, en buen estado, con algunos detalles algo más dejados, pero en general apta para ser habitada, especialmente porque la tutelada la mantiene cuidada. Eugenia se encuentra muy decaída y bastante agotada, según indica no duerme bien y se levanta a las 5 de la mañana, pero también comenta que se acuesta sobre las 10 de la noche, nada más cenar, porque no quiere encender la televisión ni la luz, ya que le han dicho que hace mucho gasto y Pedro está pagando facturas elevadas de luz. Al parecer tiene que pagar atrasos y por eso le vienen cantidades tan altas, pero culpan a Eugenia. Aspecto que se aprovecha para hablar con la tutelada de lo positivo de irse a un centro, pues así se evita ese tipo de problemas, además de estar acompañada, pues está llevando muy mal la soledad, debido a que no tiene relación, ni vínculo con nadie de la localidad. Ante el hecho de irse a un centro, tiene sentimientos contradictorios, por una lado, lo ve bien pues allí no puede estar y tampoco puede estar con Pedro; por otro, siente que se le va a separar de éste para siempre, se le dice que si la situación de Pedro cambia y regresa al domicilio, se valoraría que pudiesen estar juntos, pero eso, si llega a ocurrir, no será en un corto periodo de tiempo. Por otro lado, tiene miedo a contagiarse de la COVID-19, se le dice que en los centros hay medidas de prevención mucho más estrictas que las que puede guardar en el domicilio, lo que le lleva a pensar que esas medidas incluyen el no poder salir y no poder cobrar su asignación… se le dice que no ocurrirá, se le permitirá tener para sus gastos y si hay un periodo en el que no puede salir, recibirá sus visitas, por parte de la educadora y mantendrá el contacto con Pedro. Aunque apagada, se queda más convencida y tranquila. Se contacta con la Trabajadora Social para comentar la situación y consultar si ya está en marcha algún tipo de solicitud, Gema establece que está haciendo el informe y cree que en esta semana lo tendrá. Comenta que en Dependencia, en Plasencia, la responsable, Diana, ha señalado que Eugenia sí tiene reconocida dependencia con un grado II-1, establece que por la graduación debe haberse hecho hace tiempo. Indica que para realizar la solicitud de centro tiene dos vías: -Mediante Dependencia, solicitando revisión del PIA alegando emergencia social -A través de Decreto, pero se precisa informe de su psiquiatra de referencia, en el que alegue que no padece alteración de la conducta actualmente, pues tiene antecedentes; se le dice que en el tiempo que se lleva trabajando con la tutelada no ha presentado alteración alguna, ahora tiene comportamientos más extraños pero se pueden deber a la situación que está viviendo, pues se mantiene en constante incertidumbre Se le dice a Gema que quizá hay que decantarse por la solicitud que vaya a procesarse en la mayor brevedad, pues Eugenia está viviendo un momento muy delicado y complicado que le está haciendo decaer."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-08-21','TERESA EMAIL DE FUTUEX el pasado 13 de Agosto se visita a Ramón en su domicilio y se encuentra a su madre dormida en su habitación, comenta que su hijo estará dormido. Se sube a la primera planta y se encuentra a Ramón acostado en su cama, su habitación llena de trastos y los cachorros de su perra Mori, metidos en una caja de la habitación contigua Una vez que Ramón se levanta, se viste y se asea un poco, se sale de la casa donde se ve una motocicleta en una de las ventanas de su fachada. Se le pregunta si la moto es suya y Ramón responde que si, que la ha comprado en Oliva de la Frontera, fue a por ella el jueves anterior con la ayuda de su hermano Luis. Se adjunta una foto de lamisma. Se le pide que la enseñe y al ver la pegatina de la ITV se descubre que la tiene caducada. Se informa a Ramón de la imposibilidad de que tenga una moto pero a él parece darle exactamente igual. Él comenta que la ha comprado para usarla y para ir al campo y aunque se le dice en varias ocasiones que él no puede manejar vehículos motorizados, sin carnet, y por la medicacion que toma y por que no estan en regla los papeles..no hace ningún caso. Dice que lo va a seguir usando y que nadie le va a decir que no puede. Se le pregunta la cuantía de la moto y cómo ha podido pagarla y solamente responde que la moto la ha comprado él y la ha pagado pero no habla de la cantidad. Se sale a caminar con Ramón y mientras se conversa, comenta que el frigorífico no le funciona bien. Propone acercarse a la tienda de electrodomésticos donde lo compró para ir a hablar con el dueño. Se le propone otro plan, se vuelve con él a su casa para comprobar el estado del frigorífico y se llama al dueño de la tienda para preguntarle qué ha podido pasar. Se llama a Agapito, de la tienda de electrodomésticos y se le comenta el problema del frigorífico. Él cuenta que es una problemática muy común en los frigoríficos No Frost y que la solución es que lo apague durante un día y lo vuelva a encender para que la placa de hielo que se le ha formado en el congelador, se deshaga y vuelva a enfriar con normalidad. Se va a casa de Ramón para informarle de lo que se ha hablado con Agapito pero ha salido a comprar y ha cambiado de número de móvil, por lo que no se dispone de él. Se le comenta a su madre que nos llame cuando llegue para contarle las novedades sobre el frigorífico. No se han recibido noticias suyas. El pasado 17 de Agosto, se recibe una llamada de Eugenia de los SSB de Jerez, para preguntar por el estado de la casa de Ramón. Se le comenta que la casa está en malas condiciones porque en estos últimos meses de confinamiento tanto él como su madre han ido acumulando sofás en el salón y más trastos en el cuarto de María. Además desde Marzo no está acudiendo ninguna auxiliar de ayuda a domicilio a limpiar la casa. Se cortó el servicio y no se ha restablecido. Se llamó a los SSB hace unas semanas para preguntar por ese tema y Mamen, comentó que el servicio del ayuntamiento se había suspendido porque se había aprobado la ley de la dependencia a María y tendría ayuda a domicilio de manos de una empresa privada. Pero eso no está sucediendo, allí no ha ido ninguna auxiliar a limpiar y eso agrava aún más la situación de desorden de la casa. Ramón se encarga de fregar el suelo y de organizar un poco la planta baja pero no es suficiente, además tienen dos perros y un gato. Una de las perras ha tenido cachorros y los tienen en una caja en la primera planta. Ramón cuando se le preguntó sobre el tema, comentó que los estaba regalando porque no se podía ocupar de ellos. Es decir que si, la casa está en malas condiciones, nunca ha estado bien de hecho, pero claro desde que el SSB interrumpio el servicio pues está infinitamente peor.. no entendemos por lo tanto la razon de la llamada de la ts a Susana ni tampoco lo que traslada a ti, que ha comprobado en la visita domiciliaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA INES'and edp.apellido1='MORENO'and apellido2='POLO'),'2020-08-21','(Pedro)Llamada de D. Miguel Macías, hijo de Dª Inés, desde Fuerteventura. +++Nos comunica el fallecimeinto de su madre el pasado sábado 15 de agosto. Fue enterrada en Aljucen el domingo 16 de agosto. +++Comenta que había una cuenta en la que figuraba su madre y un primo como autorizado (¿?).Le explico que en estos momentos a la Comisión solamente le queda presentar la rendición final de cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-08-21','En relación con la adquisición de la moto, hablamos con la Guardia Civil de Jerez de los Caballeros. Van a pasarle esta incidencia al Comandante de Puesto y con la actuación que lleven a cabo nos llaman. Les he dado mi teléfono (Ángel) y el de Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-08-21','Ana: Correo del CADEX-CC (cadex.caceres@salud-juntaex.es) en respuesta a mi solicitud: "Buenos días. Os adelantamos el certificado por esta vía, y remitimos el original por correo ordinario. Saludos" ······························ Lo guardo en el expte. virtual, sustituyendo el antiguo y modifico el dato en al base de datos "CTAEx", pues constaba el grado anterior. ·················································································································································· Llamada de Pilar, HSVP (671 016 615), me ha prenguntado si sabíamos algo nuevo, pues le ha extrañado que no le hayan vuelto a llamar ni desde el CSS ni nosotros, a excepción de para pedirle dinero y tabaco para Marga. Le explico que Pedro aún no le ha llamado porque quería hablar primero con al Psiquiatra. Ella tampoco sabe quién es la Psiquiatra que lleva a Marga. Aprovecho para informarle sobre lo tratado con Emilia, TS CSS, y con Pedro, CTAEX, en el día de ayer. *En cuanto al tabaco y dinero, ya ha entregado en el CSS todo lo que tenía para este mes, acordamos que no se les dará más. ····································································································································· Intento contactar con Emilia, CSS, varias veces, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-08-21','Ana: Llamo al C. Salud de Hoyos (927 51 43 46), proceden al cambio de domicilio de Julia, pues aún les constaba la dirección del CRR-Mérida, le asignan médico de A. Primaria, José Manuel Aguilar, y solicitan nueva tarjeta sanitaria. Me informan que la tarjeta nueva tardará meses en llegar y actualmente no están dando el resguardo en papel ni me lo pueden enviar de ninguna manera, no obstante, expresa que no la necesita para acudir al médico, que con que lleve el DNI es suficiente, pues todas las Aux. Amvos. del SES tienen acceso a los datos de la Seg. Soc. ························· Cominico a Toni-Futuex, que este trámite está hecho, por si Julia vuelve a demandarlo en la visita que le hagan. ···················· Igualmente llamo a Julia y se lo comunico, dice que anteriormente ella estaba con D. Jesús, probarán y si no les convencen, pedirán en el mostrador el cambio. *Me informan también de que *hoy a las 11:00 h, Gloria-Futuex, les hará la primera visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-08-21','(Pedro)Conversación con Ana Muñoz (Abogacía) y posteriormente con Curro. +++Curro está de vacaciones hasta el 1 de septiembre.No obstante me comenta, una vez referida la información que me faclitó Joaquina (Juzgado), que no entiende qué trámite es ese de "requerir la conformidad" si ya la Comisión fue la solicitante de la autorización del internamiento Involuntario: "...que te digan en qué artículo de la ley hacen refencia a ese trámite..." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Joaquina, del Juzgado de 1ª Instancia nº 1 de Jerez de los Caballeros (924-751960), tal como quedamos ayer. +++Llamo varias veecs a lo largo de la mañana pero no consigo contactar con ella.','2');
