insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA INES'and edp.apellido1='MORENO'and apellido2='POLO'),'2020-08-24','(Pedro)Nueva llamada de D. Miguel Macías. +++Comenta que según le han dicho en la residencia allí no tienen ninguna documentación porque todo lo tramitó la familia. +++Queda en enviarnos el certificado de defunción y toda la docuemntación que tiene en sus manos. +++Se le da el correo de ctutelar para su envío. +++A lo largo de la mañana envía contrato de Servisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-08-24','(Pedro)Llamo nuevamente al Juzgado de 1ª Instancia nº 1 de Jerez de los Caballeros, tanto al número que me indicó Joaquina, el 924-751960 (no lo cogen), como al 924-730044 (parece que cortan). No consigo comunicar con el juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-08-24','Ana: Devuelven de firma la autorización expresa remitida por el CSS. *Se la envío escaneada a Rosa Mª Bravo, Admvo. CSS-Plas. por email. ········· Hago oficio para el envío y lo pongo para Registro de Salida. Dejo preparado el sobre y el acuse de recibo (tarjeta rosa) para envío por correo certificado. *Pido a Teresa y Juan Pedro, CTAEX, que si llega esta semana de registro el oficio se encarguen de enviarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-08-19','Ana: Por fin llegan los documentos originales remitidos por la Res. Padre Damián, por correo certificado, para la solicitud de Ud. Móvil de la Policía para renovación del DNI. Ha sido registrado de ENTRADA a fecha de 18/08/2020. *Previamente Alfredo nos los adelantó escaneados a color por email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-08-24','Ana: Recibimos, remitido por Damián, RECURSO DE REPOSICIÓN contra resolución de grado de dependencia con firma a bolígrafo, junto con copias de documentación (informes médicos y Resolución de Incapacitación Absoluta). Entendí a Ana Benavente que ya lo entregaron, pero me queda la duda de sí fue así, o si este documento es el original. *Llamo a Ana Benavente, pero me dicen que está de vacaciones y no regresa hasta el 7 de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-08-21','Ana: recibido llamada de Jesús Manuel (635 33 65 39): "¿Me podéis decir por qué no me dejáis cambiar de piso de alquiler? Le indico que la semana que viene hablaremos de ello, una vez haya podido revisar el expte. y hablado con el equipo de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-08-24','Ana: Conversación con Estrella, TS del CSS-Plas (24146). Ya se ha incorporado y es ella quién lleva el caso. Me informa de que la Psiquiatra de Margarita es la Dra. Ana Pérez Tejada, pero ésta no se incorpora hasta la semana que viene, cree que el lunes 31. *Comentamos lo ya tratado con Emilia y Pedro la semana pasada. Propuesta: Mantener a Marga en UME pero con límites. Lo anotará y comentará en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-08-24','(Pedro)Conversación con Pilar, T. Soc. del Hogar San Vicente de Paul. +++Estamos pendientes de hablar con la Psiquiatra de Margarita, la Dra. Ana Lopez Tejada.Está de vacaiones hasta la semana que viene. +++PROPUESTA de la Comisión: mantener el ingreso en UME todo el tiempo que sea necesario/posible y retorno al Hogar (el paso a otra Unidad Hospitalaria supondrá un doble gasto en relación a la plaza que Matgarita no se puede permitir).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-08-24','Ana: Llamo a Manuel (677 716 154), le comunico que le han concedido plaza en piso supervisado en Don Benito y que uno de los requisitos que debe cumplir es el de aceptar y firmar compromiso de seguimiento en CEDEX. **Le llamaré cuando se pongan en contacton conmigo desde el recurso y le daré más información. De momento no sabemos nada más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='MARTIN'and apellido2='GALLEGO'),'2020-08-24','TERESA INFORME RENDICION MANUEL SE ENCUENTRA BIEN DE SALUD Y BIEN ADAPTADO AL CENTRO NO PRESENTA NINGUNA DIFICULTAS NI PROBLEMATICA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='LOPEZ'and apellido2='CORRALES'),'2020-08-24','TERESA INFORME RENDICION PEDRO SE ENCUENTRA BIEN ADAPTADO AL CENTRO, CON SUS INGRESOS NO LLEGA PARA PAGAR LA PLZA RESIDENCIAL PERO SE HACE CARGO EL CENTRO ASI COMO DE CORRER CON TODOS SUS GASTOS. TIENE UN SALOD DE 30 EUROS EN LA CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='FERNANDEZ'and apellido2='CALDERON'),'2020-08-24','TERESA INFORME RENDICION JUAN SE ENCUENTRA BIEN ADAPTADO AL CENTRO, VIVE CON SU MADRE EN EL MODULO FAMILIAR Y HAY BUENA RELACION PARTICIPA EN VARIAS ACTIVIDADES Y TERAPIAS DEL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-08-24','TERESA INFORME RENDICION M ANTONIA CONTINUA VIVIENDO EN CASA DE SU PRIMA MANUELA Y NO QUIERE IRSE HASTA QUE ELLA FALLEZCA, EN EL PROPIO INFORME SOCIAL EL TS PLASMA LA NECESIDA DE QUE M ANTONIA PASE A UN CENTRO RESIDENCIAL. YO LO TENGO SOLICITDO ESTA PENDIENTE QUE LE ASIGNEN PLAZA LO CUAL ESTA PARALIZADO POR EL COVID','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA INES'and edp.apellido1='MORENO'and apellido2='POLO'),'2020-08-15','EXITUS. Nos comunica su hijo el fallecimiento de Da. Inex Morno Polo, el 15/08/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-08-24','Ana: En relación a la demanda e insistencia de los últimos mese de Saturnino a Virginia, Ed.- FUTUEX, de comprar un coche (ya emitió nota a fecha de 24/06/20 y envío a la secc. ecca. "precontrato de compra-venta"), envío fax al ESM de CC, solicitando a la Psiquiatra de Saturnino, Dra. Guadalupe Espárrago, informe en que haga constar el tto. y *si dichos medicamentos son compatibles con la conducción de vehículos a motor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-08-24','TERESA Realizamos nota informativa para dar a conocer la situación actual de la tutelada, ya que se encuentra en Cabeza del Valle (Cáceres) desde el día 31 de julio. Se fue a dicha localidad a visitar a una amiga por el periodo de una semana, sin embargo, a fecha de 24 de agosto aún no ha regresado a su domicilio. Estas semanas ha estado según interpretamos porque se ha personado en la oficina de Plasencia, pidiendo llamaran a Villanueva, para qeu asi le pudieran dar el dinero.... y los bancos haciendo lo que les da la gana una vez mas, se lo han dado. Nos indica que su regreso será en tren hoy a las 13:00h, pero desde el programa de apoyo social comunitario no tenemos nada que justifique dicha declaración, ya que el billete del tren informa que lo sacará antes de la salida. Suponemos porque acabamos de hablar con ella por whtasapp que va de camino ya a Villanueva.. . La citación judicial para la propuesta de internamiento solicitada por la Comisión tutelar de Adultos es mañana 25 de agosto de 2020. Desde el programa de apoyo social comunitario le acompañará la profesional que de forma habitual realiza su seguimiento, pero según las indicaciones de Aurora no podemos asegurar que regrese a Villanueva de la Serena para poder asistir a dicha comparecencia. En relación a las retiradas de dinero en efectivo (100 euros semanales), los ha estado retirando durante este periodo en una entidad de Plasencia. Manifiesta que no existe autorización expresa de gestión económica para poder realizarlo así, que el permiso lo está mandando la entidad de Villanueva de la Serena por decisión propia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2020-08-25','(Pedro) +++Iciar solicita visita domiciliaria y seguimiento a Futuex. +++Hablo con el Dr. Antonio Arbizu, del C.S. Urbano III de Mérida, Médico de Familia de Dª Rosa. Solicito nos remita Informe sobre el estado de salud de Dª Rosa. Lo enviará a mi correo electrónico (no requiere que se lo pida por escrito). +++++Se reciben Informes de consulta de Reumatología, de Neumología y de Atención Primaria en esta misma mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2020-08-25','Correo remitido por la directora del CSS de Mérida. TEMA: HERENCIA. +++Hola Pedro Os reenvío un correo relacionado con uno de vuestros tutelados. Como está relacionado con un tema de herencia, entiendo que os atañe a vosotros. Por cierto leí el correo sobre la psicóloga, Asun vuelve el lunes. Un abrazo. Espero que estés bien Obtener Outlook para Android ________________________________________ From: JORGE DE LA BARRERA DIAZ >jorgedelabarrera@icaba.com> Sent: Monday, August 24, 2020 1:30:46 PM To: CARMEN FRANCO ALVAREZ >carmen.franco@salud-juntaex.es> Subject: A la Comisión tutelar: D. Agustín Rastrollo Buenos días, Mi nombre es Jorge de la Barrera, soy abogado ejerciente en Llerena (Badajoz), colegiado 4063 ICABA. Según conversación mantenida, me dirijo ante la Comisión tutelar para comentar la siguiente cuestión: • Recientemente he tenido conocimiento por parte de mi mandante: D. Juan Barragán, que uno de sus primos llamado Agustín Rastrollo se encuentra internado en el Centro sociosanitario de Mérida. • Que al objeto de tratar con él una cuestión jurídica, interesa que se le traslade el siguiente mensaje para que, en caso de poder otorgar su consentimiento, lo manifieste, o, en el caso de que no pueda gobernarse por sí mismo lo haga el órgano tutelar correspondiente de conformidad con lo dispuesto en la ley. • La cuestión es la siguiente: Dado que la tía del Sr. Rastrollo, Isabel Barragán, ha fallecido, ésta tenía en su haber patrimonial una finca urbana (casa sita en Llerena) que será próximamente enajenada y sus beneficios repartidos entre los herederos que correspondan (primos). Dado que no todos los herederos de Isabel han decidido aceptar sus derechos sucesorios por el posible gravamen que ello pudiere suponer, es por lo que por medio de este escrito se pone en conocimiento, al objeto de averiguar si el Sr. Rastrollo procederá a la aceptación o renuncia. También es de significar que hasta la fecha, mi mandante: Juan Barragán ha estado costeando los gastos ordinarios de mantenimiento de la vivienda, por lo que en caso de que decidiera su aceptación habría que proceder a la concreta liquidación de estos gastos para su abono, sin perjuicio de los otros gastos que se hayan de abonar por adelantado en concepto de provisión de fondos como notaría, registro de la propiedad, abogado, liquidaciones tributarias, así como cualquier gasto que pudiere ser originado en el transcurso del procedimiento. Así las cosas, se hace saber que en caso de renuncia a su derecho sucesorio, el coste de dicha renuncia sería abonado por mi representado (gastos de notaría). En virtud de todo lo expuesto, les saluda atentamente y quedo a su disposición para cualquier otro dato adicional que precisen sobre el asunto. Jorge de la Barrera Díaz Abogado nº. 4063 ICABA Tlf. 697 633 303/924 870 284 jorgedelabarrera@icaba.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2020-08-24','Ana: Correo del CRR-Plas. (coordinaciontecnica.crrplasencia@grupo5.net): "Buenas, Os informo sobre M. Ángeles Santos Urbano. Se ha puesto en contacto el padre con nosotros para proponer una salida de M. Ángeles al domicilio familiar. Propone las fechas del 11 al 13 de septiembre de 2020, a nosotros nos parece bien, si las restricciones sanitarias lo permiten. A la espera de vuestra respuesta para la gestión del viaje. Saludos." ······································ Mi respuesta: "Buenos días Blanca, Por mi parte, como bien dices, si las restricciones sanitarias lo permiten, y si cumple los requisitos establecidos para estos casos por el SEPAD, me parece bien que realice esta visita a su padre, entiendo que le vendrá bien. Pues, por otra parte, Mª Ángeles no ha vuelto a manifestar la idea de querer retornar de forma permanente al domicilio familiar, ¿verdad? Confírmame por favor que es así, y en este caso yo no veo más inconveniente. Pongo en copia a Pedro, Jefe de sección, para que esté al corriente y por si quisiera decir/añadir otra cosa. Un saludo y buen día." ············································· Respuesta de Blanca: "Genial, le comentamos a M. Ángeles la salida. Por otra parte M. Ángeles, si continúa manifestando la idea de poder volver al domicilio familiar. Consideramos saludable que quiera mantener el contacto con su lugar de origen, ya que éste forma parte de su identidad. Si nos lo preguntas por las salidas, no creemos que corra riesgo de no volver, ella habla de hacer una visita, e incluso hablando con el padre no expresa en ningún momento querer que M. Ángeles vuelva al domicilio. Saludos." ····················································· Respuesta de Pedro: "Buenos días. De acuerdo con lo que dice mi compañera Ana, siempre y cuando se cumplan las condiciones establecidas en la Resolución de 20 de junio (DOE Extraordinario nº 5, del domingo 21 de junio de 2020), la Resolución de 17 de agosto de 2020 (DOE 160, del martes 18 de agosto de 2020) y las indicaciones que se dieron desde la Dirección Gerencia del SEPAD en cuanto a que se pudiera llevar a cabo el asilamiento en caso de PCR positivo antes del retorno al Centro, bien en el propio domicilio, bien en el Centro una vez retornada la persona. Teniendo en cuenta todo lo anterior y si se considera que limitar la salida de Dª Mª Ángeles (Resolución de 17 de agosto de 2020, Punto Primero, apartado C, punto 7) puede ser contraproducente, os ruego que, dada la situación, solicitéis formalmente dicha autorización indicando en ella la disponibilidad de medios para el aislamiento, caso de ser preciso, bien en el propio domicilio, bien en el Centro, para su firma por el Vicepresidente de la Comisión Tutelar. Gracias como siempre por vuestra colaboración. Un saludo." ·············································· Respuesta de Blana: "La salida sería de menos de 48 horas con lo que no sería necesaria la prueba PCR. Estamos viendo la posibilidad de que se fuera el viernes y volviera el domingo contando 48 horas máximo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2020-08-25','En relación con la herencia de una tía de Agustín (Isabel Barragán), enviamos contestación al Abogado del resto de herederos (jorgedelabarrera@icaba.com), al objeto nos envíe más documentación. Asimismo le indicamos los pormenores que necesitamos para poder aceptar o renunciar una herencia, en nombre de una persona tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-08-25','(Pedro) +++Nueva llamada al 924-751960: no lo cogen y +++Pruebo con el 924-730044. Me dicen que ayer fue fiuesta en Jerez y por eso no me lo cogieron. "...Te voy a pasar con Civil, a ver si te lo cogen...". +++Me pasa con Civil, pero después de varios tonos parece que cortan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2020-08-25','Ana: Llamada de Mar, CRR-Ba (924 23 16 51): Han concedido plaza en el CRR a Manuel. El ingreso se efectuará la semana que viene, pero aún no se ha concretado el día. Ya han hablado con el CSS. Se pondrán en contacto de nuevo con nosotros para concretar todo lo necesario. En cuanto a la cuestión económica, como el ingreso será a primeros de mes, preguntarán en el CSS si llevará dinero de bolsillo y a posteriori enviarán a las secc. ecca. presupuesto para la asignación mensual. **Le comunico que el expte. le corresponderá a Amalia y que a partir del día 1 podrán contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2020-08-25','(Pedro)Llamada de D. Antonio Meléndez Margallo (699-239561), primo hermano de Castillo.Dice llamar ´´el en nombre de su prima porque ellla dice que "...se pone muy nerviosa al hablar con la Comisión..." +++En la vivienda de Castillo que tiene en Montánchez hay unas tejas que se están cayendo. Ya han retirado alguna y quiere saber quñé permisos hay que recabar para solucionar el problema. +++Enviará dos presupuestos de lo quye suponga la obra y un informe del Apaarejador municipal en el que se refleje el riesgo para la vía pública. +++Además de mi teléfomno, dejo ta,bién contacto de Sección Económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2020-08-25','TERESA RECIBO LLAMADA DE TELEFONO DE UN PRIMO DE ROSA EL CUAL HA ESTADO PENDIENTE DE ELLA,COMENTA QUE EL VIVE EN JEREZ Y QUE NO PODIA SEGUIR HACIENDOSE CARGO DE SU PRIMA POR LA DISTANCIA Y POR ELLO PIDIO LA INCAPACITACION YA QUE SUFRE ALTHEIMER Y NECESITA AYUDA PARA LAS ABVD. ME COMENTA QUE TIENE UNA CUDIDADORA A TRAVES DE LA EMPRESA SADEX DE MERIDA. ESTA EMPRESA COBRA MEDIANTE TRANSAFERENCIA LA CUAL ORDENABA EL PRIMO PERO YA NO LA PUEDE HACER AL SER YA NOSOTROS TUTORES TAMBIEN COMENTA QUE LE HACIA TRANSFERENCIA DE 200 EUROS MENSUALES A LA CUIDADORA PARA LA GESTION DE LAS COMPRAS YA QUE ELLA YA NO SABE GESTIONAR EL DINERO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-08-25','Ana: Nos remiten por mail desde el Hptal. San Pedro de Alcántara Informe de Alta de Medicina Interna a fecha de hoy. *Guardo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-08-25','Ana: correo de Pilar, TS del Ayto. de Valencia de Alcántara (trabajadorasocial@valenciadealcantara.es): "Buenos días , Pongo en vuestro conocimiento el fallecimiento en el día de ayer del padre de la tutelada Dña. Catalina Silva Bautista de Valencia de Alcántara. Esta información también ha sido transmitida a Gloria, la delegada de Cáceres de futuex. Quedando a vuestra entera disposición para cualquier aclaración. Un saludo , la trabajadora social Pilar Márquez." ······················································································································································· Mi respuesta: "Buenos días Pilar, Gracias por informarnos. Dado el relativo poco tiempo que llevamos interviniendo con esta persona, agradeceríamos así mismo que, según tu criterio profesional, nos informes de la conveniencia de que Catalina continúe viviendo sola en su domicilio o si por el contrario sería más positivo para ella el acceder a un recurso residencial acorde a su perfil. Gloria, Delegada de Futuex, nos comunicó hace algunas semanas, que rechaza el servicio de SAD, además de que “acusa un importante aislamiento social y falta de actividad en el día a día” . Un saludo." ··························································································································· Envío nuevo correo a Pilar Márquez: "Buenas tardes de nuevo Pilar, ¿podrías facilitarnos los datos del padre de Catalina? Tras haber revisado lo que, a fecha de hoy, tenemos en el expte., quiero comprobar si tiene derecho a P. Orfandad (no sé si el padre cotizó lo suficiente) y en este caso solicitársela. Con respecto a la madre, ¿tienes alguna información? No sabemos nada sobre la misma. Gracias de nuevo. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='SANCHEZ'and apellido2='PANIAGUA TRENADO'),'2020-08-26','TERESA ENVIO ALTA A TERECEROS AL SERVICIO DE PRESTACIONES PARA ABONO DEL COMPLEMENTO DE LA PESION, PRESTACION UNICA DE CARACTER EXTRAORDINARIO 204 €','2');
