insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-08-26','Comunicamos al Juzgado de Jerez de los Caballeros, que Ramón ha adquirido una motocicleta, de la que carece de seguro y de itv, a los efectos de poder inmovilizarla. Esta circunstancia ha sido puesta igualmente en conocimiento de la Guardia Civil, que a su vez lo ha trasladado a la policía local.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-08-26','Ana: Correo de Carmen Torres, TS SSASB Ayuntamiento de Cilleros (tsocial@ayuntamientodecilleros.es) a la secc. ecca.: "Buenos días Iciar. Adjunto remito copia del DNI de Julia Morón, y según conversación mantenida con Julia hija y Julia madre han manifestado que su madre le suele dar 30€ (Treinta Euros) mensuales para sus gastos de bolsillo, y para los gastos de manutención, ropa, calzado y demás, nos comenta que 200€ (Doscientos Euros) para tal fin. La madre comenta que si se puede se haga el ingreso en la cuenta de los padres y ella se encarga de entregarle los 30€, como ha venido haciendo hasta ahora. Te enviaré el Informe Social en unos días. Un saludo." ·········································································································································· En relación al presupuesto de gastos, intercambio correos con Alberto, Jefe Secc. Ecca., yo no veo mal los 230€ mensuales que plantean. Si él también está de acuerdo será la asignación mensual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2020-08-26','(Pedro) Llamada de D. Nocolás Ortega, de Liberbank (693-904170). +++Llamaba para hacer una oferta mejorada sobre seguros. +++Le comento que si quiere hacer esa oferta la tiene que remitir a la Comisión Tutelar por escrito. Al recibir esta información desiste de plantear la oferta a pesar de que se le ofrecen los medios para plantearla por escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2020-08-25','Ana: Según Informe Social del CSS-Plas. para la Rendición Anual, Remedios sigue "ingresada en la UHDAC, desde abril del año pasado, debido a sus conductas autolesivas". En cuanto a las relaciones familiares, "se observa un gran cariño tanto por parte de su madre y hermana como por parte de Reme hacia ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-08-25','Ana: Informe social del CRR-CC para la rendición de 2020: "sale regularmente del centro y es capaz de manejarse en el medio próximo. Las dificultades que manifiesta, en este sentido, se relacionan con la adecuación de las salidas en tiempo y hora ya que permanece en reiteradas ocasiones fuera de la residencia sin respetar, en ocasiones, actividades organizadas. Necesita acompañamiento para desplazamientos a lugares de mayor distancia o nuevos. Usa el transporte regularmente de forma independiente en líneas conocidas. A pesar de usar regularmente locales y servicios públicos, en ocasiones sus conductas resultan poco adaptativas en función de su interpretación de la situación, aunque en general su desenvolvimiento podemos valorarlo como óptimo", "...En cuanto al manejo de medicación, ésta es guardada y supervisada por el personal profesional del centro, pero C.N.P tiene la oportunidad de rellenar su pastillero. Dentro de su plan individualizado de rehabilitación acude al programa de manejo, administración y planificación de previsión de la medicación dónde su participación es en el mismo es estable. Necesitando apoyos para realizar la planificación y adquisición de su medicación. En esta área la mayor dificultad que presenta está orientada a la ambivalencia relacionada con la necesidad toma de medicación, necesitando apoyo en numerosas ocasiones para la adecuada ingesta de la misma. Necesita apoyo para el cumplimento de la pauta farmacológica establecida por su psiquiatra de referencia y en ocasiones con algún fármaco en concreto necesita intervención especial para que acceda a su toma o atención puntual por psiquiatra para su retirada ante su negativa al tratamiento. En la actualidad necesita apoyo para acudirá sus citas médicas, recibiendo ayuda para la correcta gestión de los servicios asistenciales...", "Al hablar de su ocupación diaria podemos expresar que C.N.P no realiza actividades estructuradas diarias, no participando en los talleres de rehabilitación si en las tareas comunes de funcionamiento del centro. Pasa la mayor parte de su tiempo fuera del centro deambulando por Cáceres...", "...Estableciendo relaciones de pareja conflictivas. En este momento mantiene una relación sentimental con otra persona usuaria del centro con la cual desarrolla conductas no saludables para ella habiendo comenzado a fumar de manera frecuente y beber alcohol de manera esporádica. En su estancia en el centro se presentan episodios de falta de control de impulso y conductas desadaptativas relacionadas con ideas delirante y obsesivas sobre temas religiosos que generan gran angustia en la paciente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-08-26','Ana: correo de Toni- FUTUEX: "Hola buenos dias, dos cositas, que no se si estás al tanto Respecto a Jose Manuel Romero Mediavillla, está ingresado en el san pedro en la unidad desde el domingo creo,... El ingreso se produjo por una ingesta masiva de medicación según la médico de guardia q el propio Mediavilla lo expresa q son llamadas de atención a nivel médico está estabilizado y explica q su comportamiento depende más de su personalidad q de su trastorno....iban a hablar con su psiquiatra de referencia para derivación a centro porq valoran tb q no está bien en casa.... aunque la compañera les ha dicho que eso ya se hizo, y que si dados los frecuentes intentos autoliticos nos e consideraba la derivacion a otro recurso en centro sociosanitario como la unidad de media estancia, le ha comentado que como se encuentra "estable" eso no se valora.. Mas de lo mismo, si esto es estar estable pues nada, seguiremos con los frecuentes intentos no se cuanto tiempo mas.. Virginia, contacto con el hermano al no saber nada de él desde el lunes, y por el hermano nos enteramos del ingreso, parece ser porque el hijo a vuelto a casa y tuvieron una fuerte discusion (mas de lo mismo también)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-08-26','Ana: Correo de Toni-FUTUEX: "...que falleció su padre, ayer fue el entierro. Pide ayuda para algunas cositas, sobre todo para contratar el catering que le lleve la comida todos los días, el lunes que estos dias está fuera, ira la compañera para allá para ayudarla en lo que se pueda..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-08-26','Hablamos con el Abogado, Luis Cándido Moreno Morgado (927582008), con motivo del fallecimiento del padre de Catalina. Falleció el 24/08/20, en Cácerres y se ha enterrado en Valencia de Alcántara. Nos envía documentación, certificado de defunción, testamento. Parece ser que el caudal hereditario consta de unos 150.000 euros, más la casa del pueblo. Nos envía información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2020-08-26','Llamo al centro en relación a este asunto. Bibi está de vacaciones, mañana vuelve el director. Nos llama (En relación con la autorización judicial para vender las fincas heredadas de su tío, hemos solicitado al centro Aprosuba 7, de Mérida (Bibi, TS, 924312056)certificación de residencia, para aportarlo al Juzgado).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2020-08-26','TERESA HABLO CON ROSA TS SSB 924 72 70 01, ME COMUNICA QUE LE HA LLEGADO COMUNICACION DEL JUZGADO QUE ESTA ABIERTO EL PROCESO DE INCAPACITACIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-08-26','Ana: Recibimos escrito del Serv. de Prestaciones Soc. de la Direcc. Gral. de Serv. Soc., Infancia y familias: comunican error detectado en el procedimiento de gestión. Abonarán en concepto de atrasos 1501,43 € correspondientes a los meses de marzo-julio, junto con la nómina de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2020-08-27','Ana: Llamada de Manuela, TS del CSS-Mérida (924 38 81 80): el ingreso de Manuel en el CRR se llevará a cabo el día 1, el traslado se realizará en un vehículo del CSS, lo tiene ya organizado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-08-27','(Pedro)Llamada de Antonio (649999360), hermano de Aurora. +++Llama preguntando por Juana. Se le indica que se incorporará el próximo lunes.. +++Llama porque su hermana, después del juicio del martes, está muy nerviosa porque teme que la vayamos a ingresar.Le explico el por qué fue citada por el Juzgado ( a petición de la Comisión). +++"En el Juzgadoe expliqué que mi hermana no tenía necesidad de ir a un Centro, que solamente había que limpiar un poco más la casa, que ya lo estamos haciendo mi hermana y yo, y que nosotros nos encargábamos de ella...". +++Le propongo hablar yo con Aurora para tranquilizarla o que hable con Teresa, pero me dice que prefiere que sea Juana la que la llame primero a ella y luego a él. +++Pongo en antecedentes también a Teresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-08-27','(Pedro)Conversación con Soraya. +++Ya ha remitido al CADEX la documentación para valoración de perfil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-08-27','En relación con el traslado del expediente a la JUnta de Castilla-La Mancha, nos facilitan los contactos del organismo que gestiona las mismas, Jefa de Servicio de tutelas de mayores, Ana Rosa 925268999 (armunoz@jccm.es) +++Llamo tres veces al teléfono indicado sin que atiendan la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-08-27','Ana: Llamada de Carmen Ferrer (924 009 263); tiene ya la Resolución de plaza en piso supervisado asociado al CRR-CC de Juan José, me la dejará cuando pueda sobre mi mesa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-08-27','Ana: Llamada de Carmen Ferrer, Secc. Salud Mental - Ud. PP.AA. SEPAD (924 009 263); tiene ya la Resolución de plaza en CRR-Plas. de José Manuel, me la dejará cuando pueda sobre mi mesa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-08-27','Ana: Llamada de Emilia, TS del CSS-Plas., está cumplimentando la solicitud de plaza en pisos supervisados para Jairo, y no sabe si tiene más causas pendientes, debe indicarlo en la solicitud. Le informo de la que ha anotado Miguel, Asesor Jurídico CTAEX: procedimiento abreviado penal 511/2018.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2020-08-27','Ana: Llamada de Noelia, TS de la Resi. Cervantes-CC (927 005 575): Nueva incidencia de Mª Luisa; tiene engatusado a otro residente, éste le ha dejado en teléfono en teoria para alguan llamada breve, pero se va con el teléfono y le ha ocasionado un gasto importante, la factura ha llegado 30 € más cara de lo que suele llegar. La hija del residente, que es quién paga la factura, ha hablado con Noelia y reclana el abono de ese gasto extra. En toería el padre apenas sabe usar el teléfono, sólo tiene en la agenda a su hija que es con la única que habla. *En la relacion de llamadas que aparece en la factura, aparecen entre otras llamadas a la localdiad de Don Benito (a la sucursal del BBVA en que retiraba el dinero antes Mª Luisa, la Residencia Alonso de Mendoza a la que ha manifestado llamar Mª Luisa este verano en varias ocasiones...). Ya le han dicho al usuario que no vuelva a prestar el teléfono ni a Mª Luia ni a nadie. **Propuesta: Qué se devuelva el dinero al residente y que a Mª Luisa se le descuente gradualmente de su asignación. ···················································································································································· Noelia, TS, enviará un correo al ctutelar@ a la att. de la secc. ecca. con la factura y explicación de los hechos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-08-25','Ana: Llamada de Julia, madre, al final de la jornada: Dice que en el banco no le han dejado retirar dinero de Julia (le recuerdo que, como ya le expliqué, una vez que apereciera el Representante Legal en la cuenta, ésta se bloquearía y no podrían retirar nada hasta que se realice la autorización desde la secc. ecca. *El problema, no es sólo ese, sino que en esa misma cuenta, está tambiébn otro hijo, Juan Carlos, tutelado por ellos, y tampoco le dejan sacar dinero de la pensión de él. Les indico que pueden llevar al banco la sentencia de incapacitación y nombramiento de tutor de su hijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-08-27','Ana: Correo de Pilar Marquez, TS del Ayto. de Valencia de Alcántara: "Buenos días Ana, El padre de Catalina se llamaba Juan Silva Márquez con DNI 07046005R, tenía una pensión contributiva de Jubilación. Su madre falleció cuando Catalina era una adolescente , se suicidó, ella fue quien la encontró. Considero que Catalina va a presentar dificultades en la gestión de su vida diaria, en el control del dinero, planificación de compras , comidas, control médico y farmacológico.... necesita una supervisión constante. Un saludo" ································································································································ Mi respuesta: "Buenos días Pilar, Mucha gracias por la información facilitada, en cuanto pueda tramitaré la P. Orfandad y pediré un seguimiento más frecuente por parte de FUTUEX. Tendremos en cuenta lo que nos comentas y valoraremos en equipo, según su evolución, la posibilidad de acceso a algún recurso y en tal caso abordarlo con ella. Te mantendremos informada. Pongo en copia a Pedro, Jefe de secc, para que pueda leer lo que nos trasmites. Un saludo." ············································································································································ Respueta de Pedro, CTAEX, para mí: "Vamos a ver cómo evoluciona la situación y cómo se desenvuelve ella…pero vamos pensando en alguno recurso como alternativa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-08-26','Ana: Icíar, Secc. Ecca, me informa, que en su día costó mucho trabajo encontrar un piso para Jesús Manuel (en el que vive actualmente), incluso estuvo una temporada en la calle. ·························· *En cualquier caso, dado que es una curatela económica y para el control de su medicación, si quisiera cambiar de piso, tendría que buscarlo él mismo y enviar un precontrato a la CTAEX para que, tanto los Asesores Jurídicos como la secc. ecca. pudiera valorarlo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2020-08-28','(Pedro)Llamada de Antonia. hablo con su madre. +++"Le hemos hecho a la niña la prueba del virus y está todo bien..." (NEGATIVA). +++Pide más dinero para el mes que viene (para ropa), pero se conforma con seguir sancando lo mismo que hasta ahora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-08-28','Ana: Llamada de Jose Manuel (722 493 622), ayer le dieron el alta y acudió con Virginia-Futuex a un supermercado a canjear por alimentos un vale de 20€ que le dieron en la parroquia.Ingresó el domingo 23 y le dieron de alta el jueves 27.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2020-08-28','Ana: Llamada de Cristina, Psicóloga del CRR-CC: Martín Miguel lleva mucho tiempo sin ver a la madre (Victoriana Hdez. también tutelada) Desde la Res. Cervantes, en la que reside, les han dicho que no era recomendable que Martín la visite pues en la fase en que e encuentra de Alzheimer se altera mucho. **Desde el CRR comunican que Martín está deprimiéndose y solicitan que desde la Res. les envíen foto reciente para que al menos pueda ver que está bien. **Por parte de la CTAEX se autoriza. *Llamaré a la Res. Cervantes y pediré que la remitan a ser posible mediante email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2020-08-28','Ana: Llamada a Noelia, TS de la Resi. Cervantes-CC (927 005 575): solicito que envíen, cuando les sea posible, al CRR-CC, un par de fotos actuales de Victoriana para que se las puedan enseñar a su hijo Martín y éste vea que su madre está bien. *Ver anotación en la Intrantet, a nobre de Martín Miguel Miranda Hdez. **Facilito a Noelia la dirección de email y teléfonos de contacto del CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-08-27','Ana: llamada de Damián. Ha contratado por su cuenta una abogada para realizar un recurso nuevo contra la resolución de Dependencia. Le indico que ya presentó uno con Ana Benavente y que desde la CTAEX no se le ha autorizado el contratar ninguna abogada. Tendría que haber enviado presupuesto previo. No creo que desde la secc. ecca. se vaya a autorizar el abono de dicha factura. *Tendrá que abonarlo él de su asignación (Lo entiende y acepta). En cuanto al recurso, me lo han remitido a mí a la CTAEX... Hablaré con Ana Benavente cuando se incorpore al repecto, pues ya habían presentado uno. Él dice que no aportó la documentación que me ha enviado adjunta con el nuevo recurso redactado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-08-28','Ana: Llamada de Damián (622 834 876), dice que la abogada que contrató quiere hablar conmigo. Le facilito mi teléfono fijo directo para que me llame a partir del día 9. *Además envía un par de correos, en su línea. Y pide perdón por las muchas veces que volvió a llamar ayer tras haberle atendido ya.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-08-31','miguel, a petición de Pedro llamo al Jzdo nº1 de Jerez para pedirles una diligencia de confirmación del procedimiento de internamiento involuntario que nos pidieron, y como no logramos desde hace días hablar telefónicamente con el Jzdo, remito el siguiente email a María Guerrero :"Buenos días Maria, el 20-8-20 llamaron desde el Juzgado nº1 de Jerez a Pedro Gracia nuestro Jefe de Sección de Ctaex, donde le comentó Joaquina que debíamos contestar a una diligencia donde se nos requería en relación a esta solicitud de ingreso involuntario y cuyo número de procedimiento nos dijero es nº 266/2020, y que creemos que notificaron vía Lexnet a abogacía. Necesitamos que porfavor nos requiráis dicha diligencia a abogacía, ya que nos piden la conformidad, pero desconocemos el contenido de dicha Diligencia. Hemos tratado de ponernos en contacto con el juzgado sin éxito en reiteradas ocasiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-08-31','miguel, me llama para preguntar como hacer para que sus hijos no puedan heredar nada, le explico que para eso hay que hacer testamento (para lo cual habría que solicitar autorización judicial)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-08-31','miguel, aunque se trata de una curatela principalmente de carácter personal y excepcionalmente de carácter patrimonial, procedo a enviar el siguiente email a la empresa que reclama la cantidad de 1.285,94€ a nuestro curatelado: "Buenos días, hemos recibido vía fax por el Ayto de Helechosa de los Montes una comunicación de ustedes de inicio de acciones judiciales contra un curatelado, “José Vicente Vicente”, de esta Comisión tutelar de adultos de la Junta de Extremadura. Les respondemos negativamente a su requerimiento de la cuantía de 1.285,94€, en base a que el curatelado no puede contratar unilateralmente ningún tipo de documento sin el consentimiento de esta Comisión Tutelar de Adultos, y al desconocer desde esta Comisión los términos del acuerdo al que llegaron ustedes. Es por ello, que les requerimos para que nos remitan cualquier documentación, (contratos o cualquier documento firmado y que vincule a nuestro curatelado), objeto de su reclamación".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-08-31','(Pedro)Llamada de los abuelos de Alejandro, Dª Primitiva y D. pedro. Temas: +++Un centro para su nieto y dinero para comprar un piso a su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2020-08-31','miguel, a petición de Ana Ts, llamo al telefono que me indica de esta tutelada pero no corresponde a Maria Jesús Nevado (hermana de la tutelada que quiere consultar con parte jurídica algo sobre una herencia y/o compraventa). Devuelvo el email a Ana para me de el contacto (email y/o tlfno de Mª Jesús Nevado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-08-31','miguel, sigue pendiente de firmarse la renuncia de herencia, con lo que hablo con la notaria y remito el siguiente email: "Buenas tardes Iñigo, conforme hemos hablado por teléfono necesitamos que prepares la Renuncia a la Herencia del padre del curatelado para lo cual te adjunto en relación al finado certificado de últimas voluntades y defunción. En cuanto a nuestra acreditación como curadores te adjunto sentencia de incapacitación y aceptación firme del cargo. Si necesitas algo más dímelo. Necesitamos que se firme lo antes posible. La intención es que la firme el curatelado en vuestra notaria y nosotros ratifiquemos vía telemática desde la notaria de Romero Leal en Mérida, si es posible. Míralo y me dices".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-08-31','miguel, hablo con el Jzdo de lo penal nº1 de Plasencia para la citación del día 15-9-20 (PA 95/20) y me piden que remita de nuevo el fax del día 10/8/20 para me puedan ver si han pedido abogado de ofio y si nos conceden o no la videoconferencia. Me piden persona de contacto para que mañana llame la persona que lleva en el jzdo el procedimiento, se lo doy a Pedro Js.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-08-31','miguel, seguimos pendientes que el centro nos remita la Diligencia de Citación para el 12-11-2020 del jzdo de 1º instancia e instrucción nº2 de Mérida (se lo doy a Pedro para que hable con el Centro) y una vez sepamos de qué es el procedimiento veamos si tiene o no representación procesal','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2020-08-31','miguel, llega resolución del Ayto de Barcarrota haciendo caso omiso al email que le remitimos el año pasado sobre que nuestro tutelado no es propietario de ningún bien inmueble y por tanto no tiene que reparar nada. En dicha resolución se menciona que debido al deterioro de la finca se ha procedido a repararla y que el importe de los arreglos es de 14.750€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2020-08-31','miguel, llega el viernes 28-8-2020 notificación del Ayuntamiento de Barcarrota indicando presupuesto e inicio de reparación de inmueble. Preparo oficio y dejo para su firma y registro de salida a Pedro Js, negando titularidad alguna de inmueble del tutelado.','2');
