insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-09-01','TERESA INFORMA LA TS DEL SSB Informar que Candi no pernocta en el nuevo domicilio, ni tampoco viene a este servicio desde hace tiempo, ni siquiera para acompañarlo a la compra de alimentos en Mercadona desde hace más de tres meses. un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-09-01','(Pedro)Conversación con Blanca, Coordinadora Técnica del CRR de Plasencia (927-423978). +++Emi ha pedido el alta voluntaria del CRR. +++Dado que se trata de una curatela patrimonial se considera que no procede facilitar docvuemntación relativa a las incidencias que provocaron su expusión y solicitud de alta voluntaria la semana pasada. +++Comunicar al Juzgado que ha solicitado el alta voluntaria','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-01','(Pedro)Llamada recibida del Juzgado de lo Penal nº 1 de Plasencia. P.A. 95/20. +++Han remitido exhorto a Mérida para llevar a cabo la videoconferencia. +++Tiene abogado de oficio: D. Mosises palacios Cotano. Teléfono de contacto: 656-533967.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2020-09-01','(Pedro)Llamada de Miguel (642-632131). +++Refiere haber tenido un "encontronazo" con una Cuidadora con la que ahora no se habla. +++También ha puesto una queja en consumo contra un bar al que solía ir. +++Comenta que se van a poner en contacto con nosotros desde el centro para ver si podemos agilizar su traslado a otro centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='LARIOS'and apellido2='CARRASCO'),'2020-09-02','Dª Fermina HA PASADO del CRR de Mérida a LOS PISOS SUPERVISADOS DE SALUD MENTAL de Mérida el 23 de julio (nos lo comunican en el día de ayer, por correo-e). Se adjunta : Direccion CRR Merida >direccion.crrmerida@grupo5.net> Jue 27/08/2020 8:58 Buenos días Amalia, Que tal va todo, espero que bien aunque seguro que como siempre con mucho trabajo jaja. Te escribo con respecto a Fermina Larios Carrasco en relación al dinero mensual del que actualmente dispone. El día 23 de julio de 2020 Fermina cambio de recurso a pisos supervisados dada su progresión y evolución positiva en su proceso de rehabilitación; los gastos mensuales en este recurso son mayores ya que deben ser ellos mismos los que asuman todos los gastos a excepción de lo relacionado con la vivienda (luz, agua, alquiler, comunidad…). El gasto estimado del mes es: Compras de casa: Todos los miembros del piso acuerdan un dinero en común destinado a comida, productos de limpieza o necesidades que compartan entre todos los participantes. Dependiendo del número de personas que convivan en el piso varía la cantidad oscilando entre 40€ o 50€, actualmente están disponiendo de 40€ Higiene personal y medicación: el gasto medio mensual es entre 20€ y 30€ a pesar de que estos meses se está utilizando una cantidad superior por el tema de las mascarillas y gel hidroalcohol. Peluquería, esteticien, podólogo: Cada mes me manera alterna suele acudir a citas relacionadas con su estética y cuidado de mano y pies. Este es un resumen de los gastos medios mensuales; con el dinero del que actualmente dispone Fermina (280€) el presupuesto queda muy ajustado teniendo en cuenta alguna salida de ocio o imprevisto. Por lo que si fuese posible (ella percibe una PNC) autorizar la cantidad de 350€ menstruales. Por último, comentarle que el cambio lo valoramos como muy positivo, fermina se ha adaptado tanto al recurso como a sus compañeros, participando y colaborando en todas las tareas y administrándose de manera autónoma','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2020-09-02','D. Manuel HA PASADO del CSS de Mérida al CRR de BADAJOZ hoy, 02 de septiembre de 2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-09-01','(Pedro)Intento de comunicar con la Dra. Cabanillas sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='FERNANDEZ'and apellido2='CALDERON'),'2020-09-02','En relación al escrito recibido de María Guadalupe, hermana de Juan José, solicitando certificación en el que indiquemos que el mismo se encuentra tutelado por nosotros, hablamos con ella por teléfono (628579921). Está tramitando con una Abogada, las gestiones de la herencia correspondiente a su madre fallecida, el 9/8/20. Era viuda de segundas nupcias y divorciada de primeras nupcias, con el padre de Juan José. Quedamos en que nos llame su Abogada, a los efectos de intercambiar información y documentación. Llama la Abogada (Blanca del Molino 924844852), le facilitamos nuestro correo electrónico y nos da el suyo (3072@icaba.com), a los efectos de estar en contacto. Nos indica que la madre sólo dejó dinero en una cuenta bancaria, no dispone de bienes inmuebles, al residir en el Cam las Cruces. Le indicamos que solicite certificados de estar al corriente con hacienda y seguridad social, a los efectos de aceptar la herencia, al no tener deudas. Van a tramitar la Declaración de Herederos, en una Notaría de Villanueva de la Serena.','2');
