insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2020-08-26','En relación al contrato que firmó Jorge en diciembre de 2019 y en el que nosotros no firmamos, llamamos a la Delegación de Personal del Ayuntamiento de Mérida (924380111), para subsanar este defecto, pero no responde. Hablamos con Lali, del Centro Ocupacional La Encina(924373361). Va a intentarlo ella y les facilita nuestro número para que nos llame.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-09-02','Llama el abuelo Pedro Bueno (650632836), la madre Belén (671330861) y la abuela (Primitiva), muy preocupados por la situación de Alejandro, por su agresividad y porque el piso donde viven de alquiler van a tener que abandonarlo en próximas fechas. Propone la madre que Alejandro compre un piso y se vaya a vivir su madre con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2020-09-02','(Pedro)Llaman de la empresa El Secredit (0932044968). +++Paso la llamada a Juana, al estar Iciar de vacaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-09-02','(Pedro)Se remite vía fax al Juzgado de 1ª Instancia nº 4 de Mérida informando del alta voluntaria de Dª Emilia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-09-02','(Pedro)Conversación con Ana Pérez, Psiquiatra de Margarita. +++Margarita sigue en UME. +++"Margarita NO QUIERE VOLVER AL HOGAR. Reconoce, y así lo manifiesta, que allí la tratan muy bien, pero no quiere volver porque allí no le dejan ser ella misma: no tiene la libertad para relacioonarse con las compañeras comno ella quiere, no le permiten fumar ni salir cuando quiera a tomar algo.No le permiten tener relaciones afectivas con otras chicas. Es decir que "no me dejan ser yo misma"-dice-". +++"Yo creo que, SI SE PUEDE MANTENER LA PLAZA en el HOGAR, DEBERÍAMOS DARLE MÁS TIEMPO para ver cómo evoluciona y si esa idealización de las relaciones personales es algo que se le puede pasar con el tiempo: ella vino al CSS con la esperanza de recuperar la relación que tuvo con otra paciente durante el tiempo que estuvo con nosotros (tras regresar de Ávila y antes de ingresar en el Hogar), pero esa paciente no quiere volver a retomar en estos momentos esa relación, lo que ha llevado a Margarita a comportamientos de agresividad y ameanzas autolíticas. Se lo hemos dicho, que si mantiene esa actitud habráque considerar que no seencuentra en el recurso adecuado. No obstante, HAY QUE RECONOCER que Margarita es UN ENCANTO cunando se encuentra estable, que es la mayor parte del tiempo. Pero lo idealizadas que tiene las relaciones personales (al carecer de padres se vuelca en ellas) le lleva a manifestar la frutración que le producen dfe esta manera:" +++"También creemos que el mejor recursdos para ella es el propio hogar, pero también hay que reconocer que los argumentos de Margarita también son sólidos. Y de ser otro recurso debería ser demntro de la red de Salud Mental, dado que si bien la discapacidad tiene un peso importante en su caso, también es ciertom que los comportamnientos derivados son propios de enefermedad mental y no pueden ser atendidos en centros de discapacidad" +++PROPUESTA:Mantendrán el ingreso en UME unas semanas para ver evolución y según sea se le mantendrá en UME o se valorará laraga estancia. Comento a Ana que lo que no puede hacer Margarita es pagar dos plazas (Hogar y Larga Estancia, pero que sí se puede mantener la plaza del Hogar, si no hay inconveniente por parte del centro ya que se está abonando) y siempre existe la posibilidad de que puediera cambiar de opinión parta volver a ella. +++Pido que nos envíen un Informe con la evolcuión de Margarita y quedo en hablar con ella cuando ellos lo considerenoportuno, probablemente mañana o pasado, estandfo presentes los profesionales para ver el comportamiento de ella durante la misma y poder hablar de ello después con ella. Queda claro que si Margarita quisiera hablar a solas también se lo permitirían.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-09-02','(Pedro)Conversación con Ana Pérez, Psiquiatra de Margarita. +++Margarita sigue en UME. +++"Margarita NO QUIERE VOLVER AL HOGAR. Reconoce, y así lo manifiesta, que allí la tratan muy bien, pero no quiere volver porque allí no le dejan ser ella misma: no tiene la libertad para relacioonarse con las compañeras comno ella quiere, no le permiten fumar ni salir cuando quiera a tomar algo.No le permiten tener relaciones afectivas con otras chicas. Es decir que "no me dejan ser yo misma"-dice-". +++"Yo creo que, SI SE PUEDE MANTENER LA PLAZA en el HOGAR, DEBERÍAMOS DARLE MÁS TIEMPO para ver cómo evoluciona y si esa idealización de las relaciones personales es algo que se le puede pasar con el tiempo: ella vino al CSS con la esperanza de recuperar la relación que tuvo con otra paciente durante el tiempo que estuvo con nosotros (tras regresar de Ávila y antes de ingresar en el Hogar), pero esa paciente no quiere volver a retomar en estos momentos esa relación, lo que ha llevado a Margarita a comportamientos de agresividad y ameanzas autolíticas. Se lo hemos dicho, que si mantiene esa actitud habráque considerar que no seencuentra en el recurso adecuado. No obstante, HAY QUE RECONOCER que Margarita es UN ENCANTO cunando se encuentra estable, que es la mayor parte del tiempo. Pero lo idealizadas que tiene las relaciones personales (al carecer de padres se vuelca en ellas) le lleva a manifestar la frutración que le producen dfe esta manera:" +++"También creemos que el mejor recursdos para ella es el propio hogar, pero también hay que reconocer que los argumentos de Margarita también son sólidos. Y de ser otro recurso debería ser demntro de la red de Salud Mental, dado que si bien la discapacidad tiene un peso importante en su caso, también es ciertom que los comportamnientos derivados son propios de enefermedad mental y no pueden ser atendidos en centros de discapacidad" +++PROPUESTA:Mantendrán el ingreso en UME unas semanas para ver evolución y según sea se le mantendrá en UME o se valorará laraga estancia. Comento a Ana que lo que no puede hacer Margarita es pagar dos plazas (Hogar y Larga Estancia, pero que sí se puede mantener la plaza del Hogar, si no hay inconveniente por parte del centro ya que se está abonando) y siempre existe la posibilidad de que puediera cambiar de opinión parta volver a ella. +++Pido que nos envíen un Informe con la evolcuión de Margarita y quedo en hablar con ella cuando ellos lo considerenoportuno, probablemente mañana o pasado, estandfo presentes los profesionales para ver el comportamiento de ella durante la misma y poder hablar de ello después con ella. Queda claro que si Margarita quisiera hablar a solas también se lo permitirían.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2020-09-03','Escalona confirma que va a tramitar la solicitud del traslado del expediente al organismo tutelar de la Comunidad Autónoma de Castilla-La Mancha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2020-09-03','-Amalia : Cati está bien , se siente un poco sóla , se ha contactado con Asun Cabrera que acuerda con ella llamadas telefónicas semanales. "Sin embargo, Cati es algo ambivalente en sus planteamientos, porque en ocasiones anteriores cuando las citas eran presenciales con frecuencia me decía que se las espaciara en el tiempo "porque estaba bien y hasta cuándo tenía que continuar viniendo" y ahora ha adoptado la posición inversa. En Cati son normales estas posiciones cambiantes. En cualquier caso, como continuamos sin actividad presencial, la llamaré periódicamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-09-03','-Amalia : Se solicita plaza por emeregencia para Rosario , hablamos con May y nos comunica que la misma será en Garrovillas de Alconetar , Avda. de la Soledad tf 92739542 . El dia 9 a las 8.30 le harán el PCR en el Centro de Salud de Pueblonuevo del Guadiana , irá trasladada desde Guadiana en taxi acompañada por Miriam. El día 10 , en cuanto estén los resultados PCR será trasladada en taxi hasta la R. M . Irá acompañada por Miriam y Elo o su sobrina . Al día siguiente , día 11 Miriam , Elo y delegada tutelar harán inventario , cerrarán la vivienda , la llave nos la quedaremos en la CTAEX . Elo y su vecina Carmen tienen copias de las llaves. LLamo al taxista ( Juan 639323237 )para concretar el servicio .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-09-03','-Amalia : Se solicita plaza por emeregencia para Rosario , hablamos con May y nos comunica que la misma será en Garrovillas de Alconetar , Avda. de la Soledad tf 92739542 . El dia 9 a las 8.30 le harán el PCR en el Centro de Salud de Pueblonuevo del Guadiana , irá trasladada desde Guadiana en taxi acompañada por Miriam. El día 10 , en cuanto estén los resultados PCR será trasladada en taxi hasta la R. M . Irá acompañada por Miriam y Elo o su sobrina . Al día siguiente , día 11 Miriam , Elo y delegada tutelar harán inventario , cerrarán la vivienda , la llave nos la quedaremos en la CTAEX . Elo y su vecina Carmen tienen copias de las llaves. LLamo al taxista ( Juan 639323237 )para concretar el servicio .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-09-03','(Pedro)Llamo al C.Salud de Guadiana ( 924-478785)para hablar con el Dr. José Felipe Sánchez, Médico de Familia de Dª Rosario, para tratar de que comuniquen lo antes posible el resultado de la PCR para la que ha sido citada el día 9 de septiembre de 2020 a las 08:30h para llevar a cabo su ingreso en residencia. +++Llamadas efectuadas sin conseguir contactar con el centro de Salud: +++++DIA 02 de septiembre, a las 12:34h. +++++DÍA 03 de septiembre, a las 08:24, 09:02, 09:21, 09.40, 10:27, 11:19h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-09-03','(Pedro)Conversación con Carmen Ferrer y Mª Luz sobre ingreso de manuel en Proines. +++Conclusión: la semana que viene no va a ser el ingreso, por lo que ya esperarán a hablr con Ana una vez vuelva de vacaciones. +++Les comento que la Comisión lo único que tiene que hacer es frimar el contrato de la plaza y, una vez sepamos la fecha del ingreso, solcitar la PCR con la antelación suficente para que el resultado esté en las 24 horas anteriores al ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-09-03','(Pedro) +++Me acaba de llamar Dª Juana Antonia Ruiz Sánchez (689-250954), madre de Dª Beatriz (al menos así se ha identificado). Solicitaba un “certificado” que le había pedido su abogado para (una vez que le he preguntado por el motivo) poder sacar a su hija del centro, porque se quiere hacer cargo de ella. Lleva tres años viviendo en Huerta de Ánimas y quiere volver a tener a su hija con ella. Por favor, llama al centro para ver si se ha puesto en contacto con ellos y les ha comentado algo al respecto. Si no puedes hoy, mañana, antes de que cojas vacaciones. Dejo el teléfono desde el que ha llamado en la intranet. Mientras estaba escribiendo esto me ha llamado D. Pedro Ruiz (686-558488), Abogado de Dª Juana Antonia solicitando un certificado médico para plantear el retorno de Dª Beatriz con su madre. Le he explicado que dada la situación de la hija tendría que dirigirse al Juzgado para solicitar cualquier información que requiriese al respecto. Además del mío, he dado también vuestros teléfonos (Miguel y Ángel) por si se tuviese que poner en contacto con nosotros, además del correo-e de la Comisión. Y he dejado el suyo en la Intranet. Tendremos que estar más atentos, si cabe, ante esta situación en beneficio de Dª Beatriz. ++++++++++++++++++++++++++++++++++++++++++++Correo-e de Teresa: +++Buenas He llamado al centro y la trabajadora social me comenta que la madre llamo ayer por la tarde al centro para lo mismo, hoy ha hablado Mercedes la TS con la madre y le ha remitido a la comisión ya que esta tutelada de ahí que haya llamado. Beatriz se encuentra bien y en ningún momento ha manifestado que quiera irse con su madre. La vivienda de la madre no cuenta con las condiciones de habitabilidad ni si quiera para que puedan vivir los padres ya que Mercedes la pudo ver en una de las visitas cuando acompaño a Bea a ver su hija. En una ocasión me puse en contacto con el ssb de Huerta de Ánima para que me informaran sobre esta familiar y tal y como dice Mercedes la vivienda esta en malas condiciones y la madre es usuaria de SSB. Mercedes le ha extrañado que remueva ahora todo esto, yo le he dicho que quizás sea por interés económico. Le he dicho que no le faciliten ninguna información ni documentación que la remita a nosotros o bien al juzgado que la incapacito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-09-03','(Pedro)Se remite vía fax al Juzgado de 1ª Instancia nº 4 de Mérida informando del alta voluntaria de Dª Emilia. +++Ayer se intentó hasta en 3 ocasiones (reporte "ocupado" en el fax 924-384313). +++Hoy se ha enviado dos veces al 924-304313 (primer reporte "ocupado" y segundo OK). ++++++++++++++++++++++++++++++++++++++++++(Pedro)Ha llamado Emi (643-803243). +++Según dice, está viviendo con un chico al que han acogido en su casa unos ancianos (¿?) +++Dice que ha estado en la Casa de la Mujer porque dice que la maltrata psicológicamente, pero le han dicho que para quedarse allí necesita poner una denuncia.Dice que también maltarta a los ancianos (¿?). +++Al parecer intervino en alguna situación la Policía pero ella les dijo que no la maltrataba, pero dice que sí lo hace psicológicamente. +++Está decidida a poner la denuncia por maltrato psicológico e irse a la Casa de la Mujer, no sé si como recurso habitacional más que como refugio por el maltrato. Ella dice que por esto último. +++Respecto al por qué ha pedido el alta voluntaria del CRR no ha querido hacer comentarios. +++En caso de que la situación que plantea sea cierta y ponga la denuncia, le insiisto en que no le diga nada a él de sus intenciones (ni a nadie) y que si tiene que salir de casa sin nada que coja un taxi, que el taxista pase la factura a la Comisión, y acuda a la Casa de la Mujer. Sus cosas ya las recuperá en otro momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-09-03','TERESA He llamado al centro y la trabajadora social me comenta que la madre llamo ayer por la tarde al centro para lo mismo, hoy ha hablado Mercedes la TS con la madre y le ha remitido a la comisión ya que esta tutelada de ahí que haya llamado. Beatriz se encuentra bien y en ningún momento ha manifestado que quiera irse con su madre. La vivienda de la madre no cuenta con las condiciones de habitabilidad ni si quiera para que puedan vivir los padres ya que Mercedes la pudo ver en una de las visitas cuando acompaño a Bea a ver su hija. En una ocasión me puse en contacto con el ssb de Huerta de Ánima para que me informaran sobre esta familiar y tal y como dice Mercedes la vivienda esta en malas condiciones y la madre es usuaria de SSB. Mercedes le ha extrañado que remueva ahora todo esto, yo le he dicho que quizás sea por interés económico. Le he dicho que no le faciliten ninguna información ni documentación que la remita a nosotros o bien al juzgado que la incapacito.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-09-03','TERESA He llamado al centro y la trabajadora social me comenta que la madre llamo ayer por la tarde al centro para lo mismo, hoy ha hablado Mercedes la TS con la madre y le ha remitido a la comisión ya que esta tutelada de ahí que haya llamado. Beatriz se encuentra bien y en ningún momento ha manifestado que quiera irse con su madre. La vivienda de la madre no cuenta con las condiciones de habitabilidad ni si quiera para que puedan vivir los padres ya que Mercedes la pudo ver en una de las visitas cuando acompaño a Bea a ver su hija. En una ocasión me puse en contacto con el ssb de Huerta de Ánima para que me informaran sobre esta familiar y tal y como dice Mercedes la vivienda esta en malas condiciones y la madre es usuaria de SSB. Mercedes le ha extrañado que remueva ahora todo esto, yo le he dicho que quizás sea por interés económico. Le he dicho que no le faciliten ninguna información ni documentación que la remita a nosotros o bien al juzgado que la incapacito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-09-04','(Pedro)Llamo al C.Salud de Guadiana ( 924-478785)para hablar con el Dr. José Felipe Sánchez, Médico de Familia de Dª Rosario, para tratar de que comuniquen lo antes posible el resultado de la PCR.Llamadas: +++08:30, 09:12, 09:58, 11:22, 11:23, 12:06, 13:30h. No consigo contactar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2020-09-04','TERESA BUENOS DÍAS. OS ENVÍO LOS INFORMES MÉDICOS ÚLTIMOS DE ANASTASIO. ESTE USUARIO SUFRIÓ UNA CAIDA Y SE FRACTURÓ EL HÚMERO. FUÉ AL HOSPITAL PERO NO LE HAN INTERVENIDO, LE DIJERON QUE PERMANECIERA CON EL CABESTRILLO HASTA LA SIGUIENTE REVISIÓN MÉDICA. A ESTA YA HA IDO, Y LE HAN COMENTADO QUE EL CABESTRILLO SE LE RETIRARA Y QUE EMPEZARA A MOVERLO, Y SE LE HICIERA REHABILITACIÓN POR EL FISIO DEL CENTRO. EL FISIO JUNTO CON LA DUE DEL CENTRO HAN HABLADO CON LA MÉDICO DE CABECERA PORQUE ESA FRACTURA NO HA CONSOLIDADO Y NO ES POSIBLE HACERLE LA REHABILITACIÓN. SEGUIREMOS INSISTIENDO CON MAP , DEBIDO A QUE EL USUARIO SE SIGUE QUEJANDO, TODOS LOS DÍAS NOS PIDE CALMANTE, Y CONSIDERAMOS QUE ESE BRAZO SE LE VA A QUEDAR INMOVIL. OS LO TRASLADAMOS POR SI DESDE LA COMISIÓN TUTELAR PODÉIS HACER TAMBIÉN ALGO AL RESPECTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-09-04','TERESA el pasado 2 de Septiembre se visita a Beatriz Mejías y se le pregunta cómo se encuentra, ella responde que está algo mejor y más tranquila que las últimas semanas. Comenta que la semana anterior estuvo en Calera con su familia y su hermana la llevó a Zafra el pasado viernes día 28 de Agosto. Ese mismo día recibió mensajes de Toni pidiéndole hablar con ella para quedar como amigos. Ella accedió a verle durante el fin de semana y estuvieron hablando tranquilamente. Quedaron como amigos y Toni le comentó a Bea que le quitaría la denuncia y ella le dijo que le arreglaría la puerta, porque aunque ella no había sido, no quería que se lo estuviera echando en cara siempre. Y si querían ser buenos vecinos, tenían que empezar con buen pie. Se le pregunta a Bea si ha sido ella la que ha rayado la puerta y ha escrito todos esos insultos, ella contesta que no, pero ha sido un amigo suyo y se siente responsable. Ella cuenta que ha estado hablando con Toni y quieren quedar bien con él para poder convivir como vecinos. Y para ello ella se ha comprometido con él a pagarle el arreglo de la puerta aunque no haya sido ella la que lo haya hecho. Se adjunta una foto tomada el día 2 de Septiembre del estado de la puerta de Toni, para que se puedan ver los desperfectos de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2020-09-04','TERESA INFORME RENDICION ACISCO SE ENCUENTRA BIEN ADAPTADO AL CENTRO, PARTICIPA EN LAS ACTIVIDADES Y TIENE BUENA RELACION CON LOS RESIDENTES Y PROFESIONALES PRESENTA DETERIOR COGNITIVO DEBIDO A SU ALCOHOLISMO NECESITA APOYO PARA ALGUNAS ABVD Y PARA GESTIONAR EL DINERO PUES GASTA POR ENCIMA DE SUS POSIBILIDADES, A PESAR DE ELLO TIENE AHORROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2020-09-04','TERESA INFORME RENDICION ANTONIO SE ENCUENTRA BIEN ADAPTADO AL CENTRO, PARTICIPA DE TODAS LAS ACTIVIDADES QUE SE REALIZAN EN EL CENTRO, TIENE UN GRADO I DE DEPENDNECIA, NO TIENE MUCHOS AHORROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2020-09-04','TERESA JOSE ANTONIO PROVIENE DE UNA FAMILIAR DESECTRUCTURADA. CONVIVE EN EL CENTRO JUNTO CON UNA DE SUS HERMANAS, CORAL, SE ENCUENTRA BIEN ADAPTADO AL CENTRO Y PARTICIPA EN LAS ACTIVIDADES TIENE UN GRADO I DE DEPENDENCIA HACEN SALIDAS PARA REAGRUPACION FAMILIAR POR CORTOS PERIODOS DE TIEMPO, A LA VUELTA DE ESTAS SALIDAS SIEMPRE VIENE EN UNAS CONDICIONES HIGIENICAS LAMENTABLES, A PESAR DE ELLO JOSE ANTONIO INSISITE EN VOLVER A VER A SU FAMILIAR Y DURANTE MAS TIEMPO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-09-04','(Pedro)Llamada de Dª Olivia Novillos (691-236633), abogada contratada por D. José Vicente Vicente. +++Reclama la minuta que le debe. +++Le doy el correo-e de la Comisión para que la envíe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-09-07','(Pedro) +++Llamo al C.Salud de Guadiana ( 924-478785)para hablar con el Dr. José Felipe Sánchez, Médico de Familia de Dª Rosario, para tratar de que comuniquen lo antes posible el resultado de la PCR.Llamadas: +++ 09:14h,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2020-09-07','(Pedro) Llega fax del CSS de Mérida, de hoy, 07 de septiembre de 2020, comunicando el alta facultativa de D. Manuel del pasado 31 de agosto y su derivación al CRR de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-07','miguel, llama preguntando por el procedimiento judicial para dejar de pasar la pensión a sus hijos. Hablo con Angel, y me comenta que el nuevo abogado que lo tramita es Santiago Merino Jerez, a quién remitió la documentación para que iniciara el procedimiento judicial a mediados de Julio. Le remite de nuevo el email','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-09-07','miguel, a petición de Pedro Js envío fax comunicando al Jzdo nº1 de Llerena autorización para poder internar a la tutelada debido a la gravedad indicada en el informe médico remitido desde el Cetro de Salud de Llerena. Nos dicen desde el Jzdo que se lo darán al Ministerio Fiscal para que aclare si va o no a recurrir. En principio nos confirman que la firmeza de la autorización de internamiento el 15-9-20','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2020-09-07','miguel, nos llega la citación para la vista para remoción el 22-9-2020 en Jzdo nº4 de Mérida. Angel remitió a Alonso de Abogacía citación para se personen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2020-09-07','miguel, llega informe técnico del ayto de Montanchez y certificado de catastro, pero no el presupesto. Me dice Pedro Js que hablará con Alberto directamente. Ya le digo que en mi opinión hay que arreglarlo lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-08-10','miguel, me remite Sindy su contrato de alquiler en la misma calle, también con opción de compra, veo que el valor real es 127.000€, bastante superior al que me dice verbalmente de como se venden por la zona (60.000€) Quedo en verlo con Alberto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-09-07','miguel, me pregunta Sindy lo del contrato, la indico que el valor observo que el valor de mercado de esas viviendas es bastante superior al que se ponen en venta. Que lo hablaré con Alberto y haremos el contrato de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2020-09-07','(Pedro) Llamada de Juani. +++"Por favor, Pedro, ayudadme. Yo me quiero ir a vivir para siempre con mi madre, aquí no me encuentro bien. No digo que no me traten bien, pero no quiero seguir aquí, me quiero ir con mi madre..." +++Me da el teléfono y dirección de la madre: 617898217. C/. GRupo Sepe , poratl 2, bajho A (Badajoz)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-09-07','miguel, llega por fax Auto no firme de 4-9-20, denegando la Solicitud de Internamiento Involuntario del Jzdo 1º instancia e Instrucción nº1 de Villanueva de la Serena','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-09-07','miguel, llega citación para el 29-920 a 12h en jzdo nº2 de Plasencia para revisión por forense para posible retirada del carnet de conducir. Pedro Js hablará con centro socio sanitario para le lleven ese día al jzdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-08-25','miguel, llega autorización no firme de internamiento involuntario por el jzdo de Villafranca de los Barros nº1. Tras llamar para preguntar la fecha de firmeza me comentan que depende de cuando llegue el último acuse de recibo que remitieron tanto a nosotros, como a las trabajadoras sociales, como al tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-09-07','miguel, llega del Jzdo nº1 de Jerez de los Caballeros acta de al audiencia realizada a la tutelaa el 21-7-20.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE DOLORES'and edp.apellido1='VARGAS'and apellido2='CHAVERO'),'2020-09-01','miguel, llega del ayto de Monesterio comunicación de que proceden a limpiar el solar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2020-09-07','miguel, compruebo tras pedir nota simple y certificado de catastro que no tiene bienes a su nombre','2');
