insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2020-09-02','miguel, recibimos vía fax aceptación de videoconferencia para el 28-10-20 a 9h','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2020-09-07','-Amalia: me llama la cuñada 924496151 para comunicar que José está ingresado en el H.U.B. Desde el centro no han comunicado nada . Solicitan acompañamiento hospitalario nocturno , la familia acudirá durante el día. LLamo a El Angel y tras comprobar con Juana viabilidad economica procedo a contratar el servicio. T Social >tsocial@servasistelangel.es> Lun 07/09/2020 15:02 Amalia, se empieza esta noche el servicio y lo hace Najat, su número de teléfono es el 643 84 96 62. Cuando puedas me mandas el Dni del usuario. Gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2020-09-09','Ana: Remito a Miguel, Asesor Jurídico CTAEX, el contacto de Mª Jesús Nevado (622658338).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2020-09-09','(Pedro) Llamo al ESM de Mérida. Intento hablar con Esperanza (T. Social) para saber cómo se encuentra Castillo pero no contesta +++Conversación con Castillo. +++Estaba paseando con su marido (él, actualmente de baja). +++Castillo se encuentra bien y ha pedido a su primo que se encargue del arreglo del tejado de la vivienda. +++La últioma consulta que ha tenido con el ESM ha sido este pasado lunes (al parecer tyiene una Psiquatra nueva de la que no me ha sabido decir el nombre, ya que del Dr. Simón dice que se ha jubilado. +++En la converscaión telefónica Castillo dice encontrarse bien, la conversación es cordial y distendida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2020-09-09','(Pedro)Llamada de José Florencio. +++Luciano no lo puede llevar al ESM de Jerez el próximo día 21 de septiembre porque ese día estará en Badajoz haciendo gestiones. +++Me da el teléfono de Dª Cayetana Molina (625-130277) con la que ya ha ido alguna otra vez. +++Llamo a Dª Cayetana : ella tampoco puede llevar a José Florencio a la onsulta del día 21. Le pido el contacto de algún otro taxista y me da el siguiente: D. José Ramírez, con teléfono 608-421500. +++Llamo a D. José y confirma que ese día sí puede llevar a José Florencio. Pero como es también conductor de ambulancia y faltan casi dos semanas para la fecha, no sabe si le podrá surgir algún imprevisto. En previsión de ello, le dejo los teléfonos de Juana y Belén.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-09','(Pedro)Llama José Manuel (667-384817). +++Dice encontrarse en Urgencias, donde ha acudido para ver si lo ingresan y lo llevan a URA (Plasencia). Estáesperando que lo vea el Psiquiatra. +++Le pido que nos llame una vez haya habaldo con él. ············································································································································································································································· Ana: Llamada de José Manuel: el mismo contenido de la conversación con Pedro; lleva en urgencias desde las 8 de la mañana. Dice que *no le quieren ingresar. La médica le ha sugerido ajustarle la medicación y mandarle para casa. Pero tiene que esperar a las 14h, pues él le ha dicho que quiere ingresar y tienen que comprobar si hay camas. Le han dicho que en tal caso estaría allí 2 semanas antes de pasar a UME. En el caso de que le ingresen pedirá que nos lo comuniquen desde el hospital vía teléfono o fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-09','(Pedro)Conversación con Adela (CSS de Plasencia). +++Le recuerdo la citación que tiene pendiente Jairo para el próximo día 15 de septiembre de 2020 a las 12:30 en el Juzgado de lo Penal nº 1 de Plasencia. LO acompañarán desde el CSS y la cComisión asisitirá por videoconferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-09-09','(Pedro)Conversación con Adela (CSS de Plasencia). +++Le remito la citación que tiene pendiente Miguel para el próximo día 29 de septiembre de 2020 a las 12:00 en el Juzgado de 1ª Instancia nº 2 de Plasencia. Intentarán que sea el forense el que acuda al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-09-09','En relación con la casa de Madroñera, sita en c/. Juan de Austria, 4 y de la que Concepción ostenta el 100% de pleno dominio, llamamos al Ayuntamiento para solicitar un Informe Técnico del estado en el que se encuentra la vivienda. La Trabajadora Social y el Técnico están de vacaciones. Nos facilitan un correo electrónico (gsolis@madronera.es). Buscamos en la caja fuerte por si tuviéramos la llave, no está. Enviamos el correo electrónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATILDE'and edp.apellido1='SORIA'and apellido2='ORTIZ'),'2020-09-09','Ana: Llamada de Maite Cañadas, el lunes falleció Matilde Soria, como ayer fue fiesta no nos lo ha podido comunicar hasta hoy. Ya se ha enterrado, como tampoco tenía familiares acudió ella sola al entierro y se encargó de todo, no tenía seguro de decesos. Ya a mediados de agosto sufrió un ictus y quedó bastante mal, por eso hubo que adaptarle la silla de ruedas. *Enviará al ctutelar@ la factura pendiente de la silla de ruedas y el certificado de defunción. *Así mismo, o ella, o desde el propio tanatorio, enviarán la factura. Se encargará también de elegir la lápida. *El nicho será de "segunda mano", pues el cementerio de Plasencia no tiene nichos nuevos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='PARIENTE'and apellido2='LUCAS'),'2020-09-09','Ana: recibo llamada de Mercedario, Ayto. de Villa del Campo (927 448 177), quiere hacer una consulta sobre una autorización para acceder a un solar de Luisa. Le derivo a los Asesores Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-09-09','(Pedro)Llamada de Ana, Psiquiatra del CSS de Plasencia (24172). +++Mantengo conversación con Margarita: "No quiero volver al Centro, estoy cansada de vivir con las monjas. Yo me quiero quedar aquí. +++Relata el problama que tuvo con las monitoras del Hogar a raiz de una relación que mantuvo con una compañera (residente) del centro. +++Su negativa a volver es rotunda. Se le explican las dificultades de cambiar de recurso cuando se ha cansado del que tiene, las ventajas de un centro pequeño y con una atención mas personalizada, etc. +++Tras hablar con Margarita, mantenemos una conversación Ana y yo: Ana cosnidera que, si durante las próximas semanas su comportamiento es bueno, la considera una candidata perfecta para Larga Estancia, porque es un encanto de persona la mayor parte del tiempo. +++A la vuelta de vacaciones planetaremos la decisión, pero Ana opta por mantenerla en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-09-09','Ana: Envío correo a Ángel y Miguel, Asesores Jurídicos CTAEX: "... Acaba de llamarme el director de la residencia de Jaraicejo, os llamará en relación a la asistencia o no a un juicio de Isabel Muñoz Melchor ...el teléfono desde el que me ha llamado es: 608 962 782" ······································································································································································ Respuesta de Ángel: "...Ya he hablado con el Director. Vamos a enviar al Juzgado un fax, comunicando que ella no reside en Trujillo, por lo tanto no tiene obligación de acudir. Además, solicitaremos que se le designe abogado de oficio que la represente en el juicio, debido a que la otra parte cuenta con representación procesal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATILDE'and edp.apellido1='SORIA'and apellido2='ORTIZ'),'2020-09-09','EXITUS El centro comunica que el óbito acaeció el 07/09/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-09-01','Jose Miguel Manzano Morillo Mié 12/08/2020 11:49 Me gusta Buenos días Amalia. Te escribo desde las vacaciones porque no quiero que se retrase el expediente de Nerea. Ta mando la documentación que tengo escaneada. Actualmente se encuentra en el piso: Centro de Acción Educativa especializada para la atención de necesidades educativas derivadas de situación de discapacidad intelectual, C/ Cáceres 22 06008 Badajoz 924 09 73 88 pisomenores@centronuestrasradelaluz.es La coordinadora del piso es Cristina 661117707 En ese piso estará hasta el día 24 de agosto, fecha en la que pasará a un nuevo piso (de otra entidad que ha ganado el concurso) Se trata de CERUJOVI y la dirección será C/ Castillo de Olivenza 12, también en Badajoz. El teléfono de la coordinadora es el 669348464. Se llama Guadalupe. Los que mayor información tienen, lógicamente, son los del piso actual, ya que pertenecen al Instituto Hogar de Nazaret que son los mismos del Centro Ntra. Sra. de La Luz, donde está cursando estudios de Tránsito a la Vida Adulta. Actualmente la madre de Nerea se encuentra, con otro hijo, en la Casa de la Mujer de Badajoz. Si necesitas más documentación y puede mandártela desde las vacaciones no dudes en pedírmela.','2');
