insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-09-09','Ana: Recibo informe del Servicio de Psiquiatría, Dra. Güendolina Andrés Pereira, de fecha de 31/08/20. En el mismo , además de indicar el diagnóstico, Esquizofrenia, y el tto. psicofarmacológico actual, dice textualmente: "Todos los psicofármacos pueden causar sedación y mermar la capacidad para manejar máquinas. Las pruebas pertinentes realizadas en el centro de reconocimiento de conductores determinará si el paciente se encuentra afectado o no por el tratamiento a efectos de conducir vehículos. ·················································································································································································· Pido a Toni, Futuex, mediante mail, que nos confirmen que Saturnino tiene el permiso de conducir en vigor y cuando les sea posible nos envíen copia del mismo. ············································································································································· Toni-Futuex me envía nota de visita (se observa buen estado en general, más estable que en otras ocasiones y aseado) y copia del Permiso de conducir **Valido hasta el 08/08/2028. ···················································································································································································· Envío correo a la secc ecca. para que valoren el presupuesto de reparación del coche y si es viable, se apruebe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-09-10','En relación con la herencia correspondiente a la madre de los hermanos, disponemos de la aprobación judicial firme, se la enviamos a Malen, de Zancas, para que la inscriba en el Registro de la Propiedad. Se lo comunicamos también a Luis Miguel para que esté al tanto. Posteriormente, una vez se haya inscrito, solicitaremos autorización judicial para la venta.','2');
