insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-09-10','En relación con la solicitud de autorización judicial para la venta de los inmuebles pertenecientes a Andrea, volvemos a contactar con el Abogado designado, (pablogperez@icaba.com) (675199400)y (cgomez@pajueloabogados.com), indicándoles que la situación económica de Andrea es muy crítica y la obtención de la autorización judicial, nos permitiría intentar vender todas las propiedades, con el objeto de obtener algo de liquidez. Nos indican que intentarán agilizar la solicitud vía judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-09-10','(Pedro)Llamo a Emilia por teléfono (643-803243), a las 09:47, 09:54, 10:54h. +++Dejo que dé llamada hasta el final. No coge las llamadas. Volveré a intentarlo. ························································································································································· Ana: Llamo más tarde a Emi(643-803243) un par de veces, pero el teléfono está apagado o fuera de cobertura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='PARIENTE'and apellido2='LUCAS'),'2020-09-10','Nos llama un constructor (Víctor 650470944), de Villa del Campo, quiere pedirnos autorización para acceder a una propiedad de Luisa, que es ahora un solar, sito en Calle Pozo Morón, 5 (cree el constructor) lo deribamos en su día, porque el vecino contiguo está haciéndose una casa y necesita entrar por la pared de Luisa. Una vez terminen, dejarían la pared de Luisa en el estado en el que se encuentra ahora. Nos envían al correo de ctaex el escrito solicitando la autorización.','2');
