insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-09-10','miguel, a petición de Teresa Ts, llamo al Jzdo nº1 de Zafra por el procedimiento pendiente que es DPA Dilig Previas Proc. Abreviado 475/2019 y me indican que tomaron declaración al padre vía exhorto y que han remitido las actuaciones al Ministerio Fiscal el 2/9/20 para que este pueda o bien pedir otras diligencias o bien solicitar el archivo de las actuaciones, posteriormente pasaría al juez quién podría archivar o bien realizar otras actuaciones (como por ejemplo remitirla de nuevo al forense, o tomarle nueva declaración.) ******************************************************* Que sepamos no hay más procedimientos abiertos ni en vía civil ni en la penal','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-10','(Pedro)Llamada de José Manuel (667384817). +++"Ayer ingresé en el Hospital -UHB-, pero por la tarde pedí el alta voluntaria..." +++Peticiones: cambiar de catering, alquilarle una habitación en Mérida, que le den una plaza en el CRR. +++Es imposible ayudar a esta persona: lo unico que pretende es que todos estemos pendientes de él y aprovecharse de los recursos existentes en beneficio propio. Como le he dicho, caben muchas posibilidades de que una vez tenga plaza en CRR decida abandonarlo. ······························································································································································································································································ Ana: Llamada de José Manuel, expresa que ya ha hablado tamibén con Pedro, el contenido de la conversación y las demandas son las mismas, insinuando además que nosotros no queremos que ingrese en CRR... vuelvo a explicarle una vez más el procedimiento y por lo demás me mantengo en los mismos términos que Pedro, diciéndole que mis respuestas son las mismas que las suyas y que deje de insistir y que ha vuelto a desaprovechar una oportunidad para acceder a recursos. ··············································································································································································· Ana: nueva llamada de José Manuel (667384817), ha hablado con su psiquiatra, y según dice, éste le ha dicho que no le quieren dar centro y que se cambie de Psiquiatra... En cuanto a nosotros dice "...no sé para qué me tenéis tutelado si no queréis ayudarme..." me pregunta qué Jdo. le incapacitó, afirma que va a ir a pedir que le quiten la tutela... le indico cuál es.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-09-10','(Pedro)Se recibe Informe Médico con resultado de PCR NEGATIVO previo a ingreso en Centro de Mayores de Garrovillas de Alconétar. +++Al no estar May se habla con José Vicente para dar el visto bueno a la Resolución y se procede al traslado de Dª Rosario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2020-01-28','Enviamos correo electrónico a Axactor, que es un despacho de Abogados a los que le han cedido el cobro de una supuesta deuda contraída por Ricardo, requiriéndoles nos envíen documentación para estudiar el caso y, si procede, solicitar autorización judicial de gastos extraordinarios y pagar esa deuda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2020-09-10','Nos llaman por teléfono de Axactor (693364163), que es un despacho de Abogados a los que le han cedido el cobro de una supuesta deuda contraída por Ricardo, de muy malas maneras, queriendo grabar la conversación, que no autorizo (Ángel), cuelgan. Les vuelvo a reenviar el correo requiriéndoles nos envíen documentación para estudiar el caso y, si procede, solicitar autorización judicial de gastos extraordinarios y pagar esa deuda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2020-09-10','Llama Blanca Molina Dorado, de Almendralejo, 636858767, 2241@icaba.com, Abogada de la familia de Manuel Jesús, en relación con la venta de los inmuebles que forman parte de la herencia del tío. Tomamos sus datos para seguir informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2020-09-10','Hemos solicitado al centro Aprosuba 7, de Mérida (Bibi, TS, 924312056)certificación de residencia, para aportarlo al Juzgado). Bibi está de baja y el director está de vacaciones, vuelve a finales de septiembre. Quien nos ha atendido por teléfono, va a intentar hacer el certificado y lo envía al correo de ctaex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2020-09-10','(Pedro)Hablo con Antonio Alonso, quien pide a Curro que me llame.Para resumir: +++Me envía el decreto del juzgado, completo. Dice que siempre nos oponemos a las remociones (¿?). ¿Por qué, si se puede considerar apta a quien la pide, eso no significa que el trabajo de la Comisión esté mal hecho? +++Dice que intentará aplazar la vista prevista para el 22 de septiembre. +++Pido a Amalia que hable con la residencia de "El Prado" para que nos envien informe en el que se haga constar cuál es la relación de la solcitante con nuestra tutelada, así como las relaciones familiares que mantiene con otros miembros de la familia. +++Cuando tengamos ese informe, poenrlo en conociiento de la Abogacía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-09-10','miguel, contestación a la interesada en el alquiler Sindy: Buenas tardes, tras revisar la petición sobre el alquiler de la vivienda que nos solicitó, tenemos que comunicarle la denegación del alquiler, debido que como ya comentamos por ley no se pueden alquilar las Viviendas de Protección Oficial, no obstante intentamos que nos comunicaran desde la Consejería de Vivienda tanto el Precio para venta o alquiler con opción de compra, petición que nos fue denegada al no tener los datos de los interesados. Llegados a este punto, tras la remisión que me hizo de un contrato similar, y habiéndolo estudiado detenidamente vemos que es nulo de pleno derecho al no tenerse en cuenta las condiciones que debería fijar la Junta (no los particulares en cuanto a duración, precio de alquiler y finalmente precio de venta). Así observamos en el documento que usted nos remitió que: 1.- Aunque se pongan 270€ de alquiler, es algo no autorizado por la Junta ya que por Ley las VPO deben destinarse a vivienda o residencia habitual. 2.- La duración del contrato de alquiler con opción a compra tampoco está dictada por resolución de la Junta. 3.-El valor de venta de 60.000€ es ilegal por cuanto ya en la resolución en la que se hace mención en su contrato indica que el valor de esa vivienda es de 127.700€. Por todo ello, le indicamos que la Junta podría ejercer el derecho de tanteo y retracto, y por tanto recuperar esas viviendas, anulando los contratos de compraventa que se están realizando por la inmobiliaria Colón. Centrándonos en el alquiler de la vivienda de nuestro curatelado, sólo cabría la opción de venta salvo que la Junta les autorizase a ustedes como interesados una propuesta de compra o de alquiler con opción de compra(que entiendo no la concederá ya que las únicas viviendas que la Junta alquila son las viviendas sociales (para lo cual hay que cumplir una serie de requisitos). Le adjunto el documento que desde la Consejería de Vivienda nos remitieron a efectos de subsanación, y el cuál no pudo subsanarse por dos razones: 1.-no están ustedes interesados en la compra de la vivienda al precio que con seguridad fijará la Junta de más de 100.000€ 2.-no disponemos de los dni del interesado en el posible alquiler con opción de compra (cuyas condiciones en caso de aceptar serían indicadas por la Consejería de Vivienda). Es por ello que le adjunto el documento de subsanación por si quieren rellenarlo y solicitarlo y en caso de obtener una respuesta positiva a su solicitud hacédnoslo llegar. Pero mientras tanto, y ciñéndonos a la ley no podemos alquilar ni vender la vivienda si no es por autorización expresa de la Consejería de Vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-09-09','miguel, confirmado con Pedro, Amalia y Alberto que no se vende. Pedro así lo dice "Si no es legal el alquiler al tratarse de una VPO entonces no se alquila, ni con opción a compra ni sin ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2020-09-11','(Ángel) Acaba de llamarme el trabajador social de Madroñera (662545510), Eloy, con motivo del ingreso en centro de Rafael y está bastante perdido con lo que debe y puede hacer. En el aspecto relativo a los bienes, está recabando la documentación para remitírnosla. En cuanto a Rafael, sigue sin estar ingresado en centro. Al parecer, ha recibido comunicación del Juzgado para que se encargue el SSB, del ingreso. He llamado al Juzgado, para preguntar si recibieron nuestro correo electrónico en el que les indicábamos que nosotros tan solo somos Administradores de Bienes, por lo que no nos compete el ingreso en centro de Rafael. El Juzgado me dice que ha recibido el correo y que le dieron traslado al Juez, que a su vez lo comunicó al SSB, pero que no saben tampoco cómo va el procedimiento. Les he indicado al Juzgado que lo que deberían hacer es enviar escrito al Sepad (Servicio de gestión de centros), adjuntando toda la documentación de la que dispongan de Rafael, para, en atención a su perfil, el servicio de gestión de centros designen centro adecuado y procedan a su internamiento. Os lo comento para que estemos atentos, porque el Juzgado va a enviar esta petición al Sepad (Servicio de Gestión de Centros) y el Registro en cuanto vean Comisión Tutelar nos lo va a remitir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-09-11','Ana: Recibimos del CADEX citación para revisión de Grado de Felisa. Tiene que acudir a Badajoz el día 25 de septiembre a las 12:30 h. ······················ Envío citación por mail a Estrella, TS del CSS-Plas. y a Rosa, Admvo. ································ Respuesta de Estrella: "Hola Ana, pues estamos fatal con el transporte...no se podría trasladar al Cadex de Cáceres?" ······················ Llamo al CADEX-Ba, pero las TS están ocupadas, le dejan nota para que me devuelvan la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-09-11','Ana: Correo de Miguel, Asesor Jurídico CTAEX: "Buenos días, ya está preparada la escritura de renuncia de herencia en la notaria, necesito que me confirméis día y hora en que irá Félix a firmar para comunicárselo a la notaria. Después ratificaremos nosotros en Mérida." ················ Envío correo a Miguel Ángel, Director del CRR-CC, pidiendo que nos comuniquen fecha y hora. Les indico el correo de Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-09-10','Ana: Correo de Estralla, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Como sabrás tenemos ingresado en UME a José Mª. Ha verbalizado que quiere ir a Piso Tutelado o CRR. Entro en base datos del SEPAD y tiene un grado II, tendría que hacerle una revisión del PIA, así que supongo que tendréis que firmar vosotros la solicitud. Dime que os parece...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-09-11','Ana: Respuesta de Pedro, Jefes Secc. CTAE al correo de Estrella: "...Respecto a la petición de D. José Mª V.A. necesitaríamos un Informe del Equipo Terapéutico en el que se considerase adecuada esa derivación antes de firmar la revisión PIA. Como dice mi compañera Ana, con los antecedentes que tiene D. José Mª no me parece que de el perfil necesario para un CRR y menos para un Piso Tutelado. De hecho, ninguno de los profesionales que han intervenido con él hasta ahora han planteado una alternativa de esa índole. Ahora, si en estos momentos sus circunstancias personales han cambiado tanto como para justificar ese cambio de recurso, por favor, enviadnos el Informe en ese sentido para valorarlo. Es más, D. José Mª siempre ha manifestado que prefería estar antes en el Centro Penitenciario que en el CSS. La petición de D. José Mª es por supuesto respetable, pero tenemos que valorar que sea también adecuada tanto para él, como para el resto de usuarios de los recursos a los que, hipotéticamente, se pueda derivar." ·············································································································································· Respuesta de Estrella, TS CSS-Plas: "Buenos días. Perdonad, no sabía que tenía que ingresar en prisión próximamente, así que cuando salga de prisión lo valoramos. Gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-11','Ana: Llamada de José Manuel (667384817) con las mismas demandas y actitud del día anterior. Con gran insistencia en que le busquemos CRR, argumentando que allí no manejaría tanta medicación y no habría riesgo de que se la tomara... Además dice que le gustaría que su hermano José Luis se hiciera cargo de su tutela, pero éste no quiere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-09-11','Ana: Correo de Miguel Ángel, Director del CRR-CC (residenciadir@feafescaceres.com) en relación al último ingreso en la UHB de Consuelo: "Buenas tardes Ana, Consuelo presento una descomposición a nivel psicopatológico y decido en un primer momento que se le hiciese por parte de la UHB un ingreso voluntario que al final tuvo que se involuntario debido a la sintomatología que comenzó a presentar (conversaciones de contenido religioso “tengo el diablo dentro….” y visionado de videos del mismo carácter con la inclusión de la idea de no querer tomar la medicación debido a que esta le produce que aumente de peso y la consecuente conducta de no querer probar bocado o alimentarse de manera inadecuada). Con respecto a la PCR no se la realizaron porque desde el HOSPITAL nos informaron que ellos tienen la obligación de realizar la prueba cuando un paciente ingresa no cuando le dan de alta, se informo a su MAP y mantuvimos las medidas de prevención durante el día del alta hospitalaria y el día siguiente le realizaron la PCR desde el AUTOCOVID y tuvo que estar esta tarde dentro de su habitación dándonos los resultados el día siguiente y siendo los resultados negativos. Un cordial saludo." *Guardo en el expte. el informe de alta enviado previamente el día 2.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-09-11','Ana: Email de Amalia, TS CTAEX sobre las actuaciones llevadas a cabo con Rosario: "Pasa a la zona de Cáceres , actuaciones finales ya realizadas : -He pasado a la R. M . su Nº cuenta y pensión que percibe, cargarán a la cuenta el copago. -He solicitado a la empresa VITALAIRE , el traslado del equipo de oxigeno que tiene prescrito . El médico de cabecera hace una prescripción que tiene una validez de 3m . Luego hay que volver a pedir otra prescripción de otros 3m . ( doctora del centro de salud Marta ) -He dado de baja el servicio de sustitución de un fin de semana con la empresa ASINDE . El servicio causará baja el día 9 de septiembre. - He realizado inventario de toda la casa , joyas y documentos importantes ( testamento incluido ) . Futuex va a enviarme una copia que guardaré en el expediente . -Se cierra y revisa toda la casa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-09-14','Ana: Esther, Ed. CAM Trujillo (927 027 600), Aitor lleva 14 días en aislamiento por haber dado POSITIVO en COVID. Están a la espera de los resultados de la nueva prueba. Nos informarán al respecto.·················· Por otra parte, solicitan autorización, para cuando sea posible, pueda ir a pasar un fin de semana a casa con la madre. **Este verano ya estuvo un fin de semana, al parecer los educadores que estaban haciendo las sustituciones de vacaciones, enviaron un correo a la CTAEX. La visita fue bien. Estuvieron en La Nava de Santiago. **Nos enviarán una autorización general de salidas para que la firme el D.Gerente. ······················· En cuanto al recurso del que está a la espera, le comunico que la lista no se ha movido, sigue en 1º como varón. Pero van a abrir un centro nuevo en Castuera y aquí puede tener la opción de entrar de los primeros. Les mantendré informados al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-09-14','Ana: Llamo al CADEX-Ba, hablo con Montse Gamir, TS (924 009 530 // 20447). La única opción para que puedan valorar a Felisa en Cáceres es solicitando el traslado de expte. *La han pasado para valoración del EVO, porque lo que se ha pedido es la revisión para poder pasar de plaza de RAL a RAE. ··· La solicitud hay que hacerla a Cácere, y ya desde allí piden que desde Badajoz les remitan su expte. ································ Llamo a Domingo, Direcotor del CADEX-CC (927 00 55 09), no tienen mucha lista de espera para valoraciones de este perfil, podrían valorarla pronto. Me pide, que una vez haya solicitado el traslado de expte., le envíe un correo recordándoselo para que él esté pendiente. ························ Pongo para registro de salida escrito-solicitud de traslado de expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-14','Ana: Llamada de Emilia, TS CSS-Plas. (24142): En la revisión del grado de discapacidad del CADEX a Jairo le han reconocido el 75%. *Van a solicitar el complento a 3ª persona. Espera que le dé tiempo pues termina su contrato mañana. A una malas haré yo la solicitud. *Me enviarán escaneado el nuevo Cdo. de Discapacidad. ·············· Por otra parte, Jairo quería comprarse ropa, desde Dirección le autorizaron y le dieron 150€, pero pide más. *Le digo que desde la secc. ecca. no se va autorizar más dinero para ropa. ···························· *En cuanto a la solicitud de piso supervisado, la ha firmado Jairo pero con otros apellidos... desde aquí no se va a firmar dicha solicitud, pues la CTAEX no tiene tutelada a ninguna persona con esos datos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2020-09-14','Llama la hija de Agustín, 638583263, al parecer su padre es agredido de manera habitual por otro residente del centro. No quiere denunciarlo, por miedo a represalias. Hablaremos con el centro para que nos indique si esto es así, para que adopten las medidas oportunas tendentes a evitar posibles lesiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-09-14','Llama el Técnico municipal del Ayuntamiento de Madroñera (662544575), va a realizar visita a la vivienda de Concepción, desde fuera, porque no disponemos de la llave. Nos informan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-09-14','Ana: Pido por email a Pilar Márquez, TS del SSB de Valencia de Alcántara, que si es posible, solicite en el Registro y me haga llegar Acta de Defunción del padre, así como copia del libro de familia o acta de nacimiento, y nos los haga llegar a la CTAEX, pues nos lo pedirán desde la Seg. Soc. para la solicitud de Orfandad. ······················································································································································ Pongo para REGISTRO DE ENTRADA, las solicitudes, debidamente firmadas y selladas, de las P. Orfandad y PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2020-09-14','miguel, recibo email del abogado de la exnuera Luis A. Carretero: "Te mandé otros correos anteriores pero no se si los habrás visto por como me comentaste que estabais con el teletrabajo. He llamado en varias ocasiones y a pesar de que me dice tu compañera que llamando al fijo lo podrías coger por tele-trabajo sin embargo no consigo hablar contigo. Te remito de nuevo documentos relativos al procedimiento judicial y comentarte que a mi cliente Doña Antonia Silvero le están embargando parte de su nómina como consecuencia de firmar en su día el contrato de préstamo, aunque como te comenté en días pasados el dinero prestado por el banco iba destinado a reformar la vivienda de sus ex suegros (los tutelados). Por otro lado, como el hijo de los tutelados a pesar de los numerosos requerimientos da la callada por respuesta, pues no tiene bienes y le da igual el procedimiento, entendemos que hay que dar una solución amistosa a este asunto a la mayor brevedad posible. Las últimas noticias judiciales que existen es que han trabado un embargo sobre la vivienda de los tutelados y el embargo mensual de la nómina de mi cliente. Por ello, os solicitamos de nuevo una reunión con vosotros o aunar criterios vía telefónica para actuar urgente judicialmente para que el banco se cobre a través de la vivienda de los tutelados que por supuesto daría suficiente para abonar el préstamo. De lo contrario, tendríamos que esperar a la ejecución judicial de la vivienda y posteriormente mi cliente interpondría una demanda contra los tutelados y que entiendo que elevaría los costes judiciales contra los tutelados y sus bienes. Quedo a la espera de respuesta por vuestra parte y un cordial saludo." ************************************************************ Le contesto negativamente a la petición de la exnuera a que asumamos la deuda del préstamo: "Buenos días compañero, siento comunicarte que efectivamente seguimos con parte presencial y parte teletrabajo motivo por el cual es posible que no haya podido recibir por problemas técnicos algunas de las llamadas recibidas. Comentarte que en su día hablé con el Juzgado nº1 de Almendralejo quién ya me indicó que la vivienda está en ejecución hipotecaria, motivo por el cual desde la Comisión Tutelar no podemos hacer nada para el levantamiento de esta deuda (por ejemplo venderla) Además nos informarnos en su día con Caja Rural de Almendralejo, quienes nos confirmaron lo mismo que en el documento que nos remites aparece, y que ya le comentamos a Tony y es que ella aparece de prestataria y por tanto obligada principal de un préstamo junto a su exmarido (los cuales salen fuera de las competencias de esta Comisión Tutelar al no ser tutelados por la Junta) y únicamente son estrictamente los intereses de los tutelados (los padres de su ex) los que desde aquí intentamos cubrir, y que como sabes eran hipotecantes y garantes en esa operación (quienes también perderán su vivienda por el procedimiento de ejecución). Desde esta Comisión no dudamos de la buena fe de las partes, pero tenemos que cumplir conforme se no exige por sentencia, como por Código Civil el cargo de tutor, así como dar cuentas al juzgado correspondiente, sin poder actuar de forma arbitraria. Tony debe entender que la Comisión no puede asumir una deuda adquirida por ella y su exmarido, que a estos efectos son terceros cuyos intereses son ajenos a esta Comisión. Por tanto sus problemas de liquidación de la sociedad de gananciales, y custodia, o pago de manutención tampoco son de la incumbencia de esta Comisión. Es por esto, en consecuencia y teniendo en cuenta las condiciones del préstamo y salvo que un juez indique lo contrario que desde esta Comisión Tutelar no se va a realizar ninguna actuación y por tanto asumir ningún tipo de deudas (que no sean claras y estén perfectamente documentadas), y entre las cuales no se encuentran el pago de un préstamo como es el que es objeto aquí de debate ya que los prestatarios son Tony y su ex. Por tanto solamente quedamos pendientes de quede ejecutada la vivienda por el juzgado".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CORBACHO'and apellido2='GALINDO'),'2020-09-14','miguel, miguel, recibo email del abogado de la exnuera Luis A. Carretero: "Te mandé otros correos anteriores pero no se si los habrás visto por como me comentaste que estabais con el teletrabajo. He llamado en varias ocasiones y a pesar de que me dice tu compañera que llamando al fijo lo podrías coger por tele-trabajo sin embargo no consigo hablar contigo. Te remito de nuevo documentos relativos al procedimiento judicial y comentarte que a mi cliente Doña Antonia Silvero le están embargando parte de su nómina como consecuencia de firmar en su día el contrato de préstamo, aunque como te comenté en días pasados el dinero prestado por el banco iba destinado a reformar la vivienda de sus ex suegros (los tutelados). Por otro lado, como el hijo de los tutelados a pesar de los numerosos requerimientos da la callada por respuesta, pues no tiene bienes y le da igual el procedimiento, entendemos que hay que dar una solución amistosa a este asunto a la mayor brevedad posible. Las últimas noticias judiciales que existen es que han trabado un embargo sobre la vivienda de los tutelados y el embargo mensual de la nómina de mi cliente. Por ello, os solicitamos de nuevo una reunión con vosotros o aunar criterios vía telefónica para actuar urgente judicialmente para que el banco se cobre a través de la vivienda de los tutelados que por supuesto daría suficiente para abonar el préstamo. De lo contrario, tendríamos que esperar a la ejecución judicial de la vivienda y posteriormente mi cliente interpondría una demanda contra los tutelados y que entiendo que elevaría los costes judiciales contra los tutelados y sus bienes. Quedo a la espera de respuesta por vuestra parte y un cordial saludo." ************************************************************ Le contesto negativamente a la petición de la exnuera a que asumamos la deuda del préstamo: "Buenos días compañero, siento comunicarte que efectivamente seguimos con parte presencial y parte teletrabajo motivo por el cual es posible que no haya podido recibir por problemas técnicos algunas de las llamadas recibidas. Comentarte que en su día hablé con el Juzgado nº1 de Almendralejo quién ya me indicó que la vivienda está en ejecución hipotecaria, motivo por el cual desde la Comisión Tutelar no podemos hacer nada para el levantamiento de esta deuda (por ejemplo venderla) Además nos informarnos en su día con Caja Rural de Almendralejo, quienes nos confirmaron lo mismo que en el documento que nos remites aparece, y que ya le comentamos a Tony y es que ella aparece de prestataria y por tanto obligada principal de un préstamo junto a su exmarido (los cuales salen fuera de las competencias de esta Comisión Tutelar al no ser tutelados por la Junta) y únicamente son estrictamente los intereses de los tutelados (los padres de su ex) los que desde aquí intentamos cubrir, y que como sabes eran hipotecantes y garantes en esa operación (quienes también perderán su vivienda por el procedimiento de ejecución). Desde esta Comisión no dudamos de la buena fe de las partes, pero tenemos que cumplir conforme se no exige por sentencia, como por Código Civil el cargo de tutor, así como dar cuentas al juzgado correspondiente, sin poder actuar de forma arbitraria. Tony debe entender que la Comisión no puede asumir una deuda adquirida por ella y su exmarido, que a estos efectos son terceros cuyos intereses son ajenos a esta Comisión. Por tanto sus problemas de liquidación de la sociedad de gananciales, y custodia, o pago de manutención tampoco son de la incumbencia de esta Comisión. Es por esto, en consecuencia y teniendo en cuenta las condiciones del préstamo y salvo que un juez indique lo contrario que desde esta Comisión Tutelar no se va a realizar ninguna actuación y por tanto asumir ningún tipo de deudas (que no sean claras y estén perfectamente documentadas), y entre las cuales no se encuentran el pago de un préstamo como es el que es objeto aquí de debate ya que los prestatarios son Tony y su ex. Por tanto solamente quedamos pendientes de quede ejecutada la vivienda por el juzgado".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-09-14','Ana: Llamo al C. Salud de Moraleja (927 14 73 00 / 71024). Pido cita para PCR para Manuel con motivo de su inminente ingreso en Piso Supervisado de Salud Mental. *Es la enfermera quién debe darle cita. Le llamarán a él directamente (facilité su contacto y el del padre) y me lo comunicarán a mí también. ······················· Escribo a Pilar Lavadiño, Coordinadora de los Pisos para comunicárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-09-14','Ana: Recibo llamada la enfermera del ESM-CC (54611), Saturnino Miguel no acudió el viernes pasado a la cita de enfermería a ponerse el inyectable. Han intentado hablar con Virgina de Futuex, sin éxito. Les indico que Virgina está ausente unos días. Como quieren llamar a alguien más de Futuex, les facilito el teléfono de Toni, pero pido que la llamen mañana pues hoy no está. ··································· Lo comunico por teléfono a Teresa-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-15','Ana: Llamada de José Manuel (667 384 817): dice que Virginia ha remitido dos presupuestos de podólogo, al parecer tiene los pies fatal. Por otra parte ha vuelto a engordar, dice pesar ya 140 kg., pero ante la recomendación de caminar a diario argumenta que lo hace pero poco y despacito porque tiene el menisco roto. En cuanto a la colonoscopia sigue esperando que le den cita. Vuelve a preguntar por la plaza en CRR. Y se queja de que Miguel, Asesor Jurídico no le ha llamado. Se lo volveré a recordar. ········ Envío correo a Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-09-15','-Hablo con MariLuz y Sonia , comunico que se tiene que dar de baja a la P.vinculada , me indican que se hace directametne desde mayores , pero además se lo van a comunicar. -Ya han instalado la maquina de aire a Rosario en la residencia. -Miguel se encarga de comunicar el ingeso en la Resi al juzgado.','2');
