insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2020-09-15','-He pedido ASINDE , contrato con clausula suspensiva para 20h de SAD , para entregarselo a Mariluz . Cuando la Junta abone podemos ponerle este servicio. Se lo tengo que entregar a Mari Luz cuando esté listo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2020-09-15','miguel, a petición de Juana hablo con Inmaculada hija de nuestra tutelada quién me hace consulta de tramitación de la herencia de su abuela: "Buenos días Juana, he hablado con Inmaculada (hija de la tutelada CONCEPCIÓN DELGADO MOTIÑO) Parece ser que Concepción tiene una hermana “Angela” cuyo cargo de tutor tienen ella. Dice que en manos de un abogado de Azuaga lleva años la herencia de su abuela Consuelo Motiño Delgado, y que no sabe lo que lleva hecho de la herencia pero que le parece que no hay nada. Me indica que hay muchos bienes, unos inscritos y otro no (estos últimos son varios de importante valor, aunque no los identifica, rústicos, urbanos, construídos o no…) El problema es que no dispone de líquido y yo la comento que lo suyo es hacer la venta de algún inmueble (previa autorización judicial de las dos tuteladas, la suya y la nuestra, tanto para aceptar la herencia como para poder vender), y una vez tenga ese líquido se vaya a un abogado a que le prepare los expedientes de dominio vía judicial para poder poner a nombre de su abuela esos bienes que no están inscritos, y una vez que tenga esas resoluciones judiciales inscritas en el registro de la propiedad los lleve a una inmobiliaria y previa autorización judicial los vaya vendiendo. Creo que lo que pretendía es que lo tramitáramos nosotros pero nosotros no intervenimos más que cuando es necesario para nuestros tutelados y además no somos abogados que podamos intervenir en exptes de dominio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-09-15','miguel, pido a Ana concrete con el centro dia y hora para renuncia de herencia en notaria. Y la informo que envié ayer email a su hermano Rafael indicando que cuando tengamos firmada la renuncia y ratificada por nosotros se lo remitiré todo para que pueda presentarlo en la Junta de Andalucía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-15','miguel, envío email a Angel y Ana: "Buenos días, he hablado dos veces y las que quedan esta mañana con José Manuel Romero Mediavilla y tengo dudas de dos cuestiones, por si me podéis aportar algo más, es que no veo en la intranet: 1)Dice que si se puede quedar con la tele de Jazztel y que estos no le dan un código para su devolución, dice que dio de baja su hermano los servicios (entiendo por lo que dice de televisión) pero que como no le dan el código que en la tienda no se lo recogen y que aun así el está llamando a Jazztel para que se lo den. Me pregunta si puede desembalarla y verla, y luego me dice que el hno le comenta que Pedro ha dicho que la tiene que devolver y no se la puede quedar, pero se queja y se queja de que Jazztel no le da el código de devolución y po tanto no le cogen en la tienda la tele… 2) Pensión alimenticia: no sé Angel si tienes algún teléfono del abogado o bien sabes algo de cómo va ese procedimiento (sé que le nombraron según hablamos no hace mucho y por tanto imagino que interpondrá la demanda para la modificación de eliminación de esas medidas de pensión pronto) Si puedes dame el nombre y datos de contacto del abogado para preguntarle".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-15','Llamamos, de nuevo, al Abogado, en relación con el procedimiento de modificación de medidas, ya que no sabemos nada de él, ni contesta a nuestros correos. Nos dice que debemos ser nosotros quien llamemos, no él. Sigue sin hacer nada. Precisa que averigüemos información laboral de los hijos, si trabajan o no, donde, sus DNI, para incorporar esta información a la demanda. Traslado esta información a Ana, para que intente hablar con José Manuel y se lo pregunte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2020-09-15','-llama el padre de Almudena , está a la espera de resultado PCR en el CSS Mérida , no nos han comunicado nada , con lo que entendemos que es - . Dice que está sin wifi, tv...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-15','Con motivo del procedimiento de modifación de medidas, comunicamos al Abogado el teléfono de José Manuel, para que pueda llamarle y preguntarle información relacionada con sus hijos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-09-15','Ana: Correo de Toni- Futuex: "Buenos dias Ana, he leido lo que me puso la compañera de tu llama de ayer, respecto a SAturnino Miguel, como sabes la relacion con el es muy ambivalente.. bueno en los ultimos tiempos a permitido el cotacto con la educadora pq estaba el tema de la factura pendiente pero llevaba bastante tiempo que rechaza la visita y el seguimiento, durante el estado de alarma hemos contactado en alguna ocasion con el hermano, para indicarle lo de las retiradas y la cita previa en LIberbank, pero era este quien iba con el. A las consultas de salud mental hace mucho tiempo que no permite que se le acompañe, suele ir, o eso teniamos constancia, en citas anteriores, bien a trves de su psiquiatra o de la ts de salud mental. Te voy a psar por aqui, los telefonos que tenemso de contacto de su heramano y el suyo, por si resultara de utilidad. +34 671 37 45 84 Nino +34 630211717 Paco hermano Nino La proxima semana la educadora procurará ponerse en contacto con el, a ver si hay suerte!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-09-15','Recibimos de Abogacía General, Auto denegando el internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORCILLO'and apellido2='HERRERO'),'2020-09-15','Ana: Llamada de Sandra, TS de la Residencia Patronato de Coria (Despacho Ayto. 927 50 80 00 ext. 283 // Residencia-centralita: 927 50 80 50). Pregunta por este expediente, me dice que le parecía raro que aún no nos hubiésemos puesto en contacto con ellos, pues ya debíamos tener aceptado el cargo. He mirado en la Intranet y aparece el Regimen Actual “sin datos”, pero luego en los exptes. digitales veo que está como Defensa Judicial. Dentro de la Carpeta he visto el Testimonio de la Sentencia en que sí nombran tutora a la CTAEX. *Cuando averigüe algo me pondré en contacto con ella. ······ Envío un correo a Juan Pedro y Julio, CTAEX, preguntando al respecto. ·········································································································································· Julio-CTAEX, me comunica: "Cumple el plazo de recurso (para la CTAEx) mañana día 16 de septiembre. No sabemos el plazo que tendrá José. Hasta entonces no se puede solicitar la firmeza de la sentencia." ······················································································································································· Se lo comunico a Sandra, TS de la Resid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2020-09-15','-Amalia : solicitado contrato SAD a ASINDE . Se lo envio a los auxiliares para que una vez firmado por el gerente me lo vuelvan a enviar para que yo entregue una copia a Rafael y otra a M. Luz ( dependencia Badajoz ) con el resto de la documentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2020-09-15','miguel, llamo al jzdo de 1º instancia e instrucción nº4 para preguntar por el procedimiento X06 REMOCIÓN DE TUTELA 232/20 donde Curro solicitó la suspensión y el traslado de las actuaciones de la parte demandante, y me comentan que llame mañana para confirmar dicha suspensión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-15','miguel, acudo al juicio en Scape del Jzdo de lo Penal nº1 de Plasencia donde la vista es unicamente para conformidad con la pena que se le impone (la mínima por el procedimiento 511/2018) consistente en más de 10.000€ de indemnización a los denunciantes y 1 año y 3 meses de ingreso involuntario en Centro adecuado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-09-15','miguel, me llega providencia de 1/9/20 del jzdo nº1 de Almendralejo en relación al escrito que hicimos de no operar y donde el Ministerio acepta la decisión de la Ctaex, con la obligación de informar sobre cualquier alteración significativa en el estado físco de Anica o de la realización de la pruebacuando se considere procedente desde el punto de vista médico','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-09-15','miguel, finalmente acordamos con el centro y la notaria que el día de la firma de la renuncia de la herencia será el día 23/9/20 a 10h','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2020-09-15','miguel, llama Toñi del Cam de Don Benito pidiendo me informe para la renovación del permiso de xtranjería de la tutelada ya que ha comprobado que el pasaporte lo tiene caducado. Hablo con la Policía Nacional de Don Benito quién me confirma que tiene que se rla propia tutelada quién denunciae el extravío del pasaporte (sólo tienen fotocopias) y al tiempo soliciten renovación del pasaporte a la embadaja o consulado de Argentina en España. Trasmito vía telefónica toda esa información a Toñi, quién me dice que hablará con el Consulado de Argentina a ver de qué manera se puede presentar (si es posible no presencial ya que la tutelada está en silla de ruedas, y sería bastante el coste de traslado a Madrid, unido al gasto de acompañante). Toñi hablará con el Consulado y después con extranjería a ver si presentando la denuncia y la fotocopia del pasaporte extraviado fuera por ahora suficiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-09-15','miguel, Belen y yo hablamos con Tony de Futuex y la pido tal como hablé ayer con Alberto, acudan a c/Sor Valentina Miron 3, 2ªB, Plasencia y hagan fotos y nos den su opinión sobre el estado de la vivienda. Dice que intentará vaya la compañera esta semana. Me pide los datos de contacto de la sobrina para ponerse en contacto con ella para acercarse a verlo. *************************************************** Una vez sepamos la opinión (fotos, informe de Futuex) llamaré a la posible compradora para intentar que mejore la oferta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-09-14','miguel, hablo con Angel y acordamos que lo mejor es no pedir Tasación ya que no se requiere judicialmente y tampoco nos serviría de mucho ante la oferta que hace días ha hecho la sobrina de la compra de la vivienda de c/ Sor Valentina Mirón 3. Hablo con Alberto y acordamos que pese a la urgencia de la venta y la necesidad imperiosa de dinero del tutelado, vaya Futuex haga fotos y nos dé su opinión para ver si podemos pedir más o no a la compradora','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-16','Ana: Dado que Emilia, TS - CSS, ya ha finalizado el contrato, comunico a Estrella y Mariví, TS - CSS, mediante mail, la pena impuesta a Jairo ayer en el juicio por lesiones a compañeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-09-16','Ana: Tras llamar al C.Salud de Moraleja, envío el siguiente correo a Pilar Lavadiño, responsable de lo Piso Supervisado de Salud Mental de Proines: "Buenos días Pilar, Dado que ayer no tuve noticias del C. Salud de Moraleja, acabo de llamar y hablar con el médico. *A Manuel Domínguez Martín Le hicieron ayer la PCR (a pesar de que el lunes me dijeron que el martes era muy precipitado y no podrían hacérsela hasta miércoles o jueves… en fin). El resultado es negativo! Me lo enviarán por fax, a lo largo de la mañana te lo remito a tu correo escaneado. ¿Llamas tú a Manuel para el ingreso o prefieres que le llame yo? Ya me dices." ···················· Pido por mail a Toni-Futuex el compromiso de acceso al Piso Supervisado firmado por Manuel, pues aún no me lo han remitido y lo necesitan en el piso. ·························· Una vez recibido tanto el compromiso como el resultado de la PCR, *envío ambos documentos por mail a Pilar Lavadiño. ································ Correo de Pilar: "...Ya hablé con Manuel, a él aún no le habían llamado de su centro de salud, osea que se ha enterado del resultado negativo por mí. Despues de comer salían para don Benito, hemos quedado a las 17.00 en el centro para que firme toda la documentación y luego yo le acompañaré al recurso. En cuanto sea efectiva su entrada, lo comunico de nuevo. También me llamo Juana de la sección económica para aclarar su aportación a piso, ha quedado en mandarme un correo especificandolo todo para que yo se lo comunique a Manuel cuando llegue..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2020-09-15','Ana: Leo en ctutelar@ un correo de Fernando Pecero, Casa de la Misericordia (aromasdecaridad@hotmail.com) del día 11: "Buenos días Les adjunto el informe del Médico especialista para valoración de la situación de Álvaro y proceder a su tratamiento. En el informe queda explicada la situación actual. Pueden ponerse en contacto directamente con el Médico o con nosotros para tratar el proceder. Muchas gracias y reciban un cordial saludo. Atentamente Fernando Pecero Herrera" ···················· Envío la siguiente respuesta tras leer y guardar en el expte. virtual el informe que nos han remitido: "Buenos días, En primer lugar, comunicarle que tanto Teresa, Trabajadora Social de referencia, como Pedro, Jefe de Secc. CTAEX, estarán ausentes durante estas 2 semanas. Teresa se incorpora el día 24, mientras tanto pueden contactar conmigo. En relación al informe médico que nos han remitido, decirles que falta la página 2, agradecemos que cuando les sea posible nos las hagan llegar. Por lo que he podido leer en el informe, a priori, y a la espera del TAC que se menciona, dada las situación y el deterioro de Álvaro Rafael, estoy de acuerdo en que, como indican en el propio informe, “lo mejor para el paciente sería evitar medidas agresivas e indicar cuidados paliativos cuando lo precise”. No obstante, ¿han consultado esto con algún otro profesional sanitario de referencia de Álvaro Rafael, como enfermeras/médico del centro o médico de atención primaria? Estaría bien contar con su criterio para poder tomar una decisión informada. Ya me van diciendo. Seguimos en contacto. Gracias y un saludo." ·································· Respuesta de Fernándo a últinma hora: "Buenas tardes Le mando el folio 2 No estamos esperando ningún TAC, ya se lo ha hecho y el diagnóstico del especialista se basa en ese TAC. En cuanto a la consulta de su médico de atención primaria estamos a la espera de la incorporación de su médico. Le informaremos de lo que nos digan Muchas gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2020-09-16','Ana: Envío correo-respuesta a Fernando Pecero, Casa de la Misericordia: "Buenos días Fernando, Gracias, no sabía que se había hecho el TAC dado que es justo en esa página que faltaba donde aparece. Ya lo he leído. Quedamos pues a la espera de lo que le diga su médico de Att. Primaria cuando se incorpore. Pongo en copia a Teresa, mi compañera, para que pueda leer el hilo de los correos cuando se incorpore y así estar al corriente. Seguimos en contacto ante cualquier cuestión. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-09-16','miguel, hablo con el Jzgdo de 1º instancia e instrucción nº4 de Badajoz y me indican que no encuentran el fax que les enviamos el 27/7/2020 solicitando la retirada del carnet de conducir de este curatelado. Me indican que tenemos que hacer una solicitud de iniciación de procedimiento voluntario dirigido al Decanato. ************************************************** Envío email a Alberto para su conocimiento','2');
