insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-09-16','Ana: Llamo a Pilar Cerrillo, TS de la Res. (618 90 85 06): le informo que Belén, compañera de la secc. ecc. CTAEX, se pondrá en contacto con el banco de nuevo, pues la resolución del rescate del contrato de valores es firme desde mayo, fecha en que la remitieron al banco y a día de hoy no se lo han devuelto aún. ······················································································································································································ Recibo llamada de Marisol, TS del HUC (56823) en relación a Pedro. La Médica Internista, le ha preguntado si la plaza que ocupa Pedro es de asistidos, pues quiere saber si cuando den el Alta a Pedro, que no será en los próximos días, contará con los apoyos que precisa, le preocupa que esto no sea así. *Al parecer se quita las vías y se niega a comer. Y según les informaron en el último tiempo Pedro realiza vida Cama-Sillón. *Llamaré a Pilar Cerrillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-09-15','Ana: Miguel y Belén, compañeros CTAEX, me comunican que Pilar Cerrillo, TS Res. Casar de Cáceres, ha acudido a la CTAEX y ha preguntado por la deuda de Pedro Román y de otro residente tutelado. Tras valorar, a última hora con ambos compañeros la situación, acordamos que la llamaré mañana para informarle al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-09-15','Ana: Miguel y Belén, compañeros CTAEX, me comunican que Pilar Cerrillo, TS Res. Casar de Cáceres, ha acudido a la CTAEX y ha preguntado por la deuda que tienen con ellos Mateo y de otro residente tutelado. Tras valorar, a última hora con ambos compañeros la situación, acordamos que la llamaré mañana para informarle al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-09-16','Ana: Llamo a Pilar Cerrillo, TS de la Res. (618 90 85 06): le informo que el expte. de Mateo Aún está en fase de inventario, a las compañeras de la secc. ecca. aún no le han dado acceso a las cuentas bancarias para ver la situación y poder operar. El próximo lunes, Juana, secc. ecca, acudirá al banco personalmente para intentar solucionarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2020-09-16','Ana: Acuden a la CTAEX Elisa, madre de Ana María (924 31 85 92) y Fernando, hermano (648 977 307), preguntan "quién se va a hacer cargo de Ana María", le explico que de momento la CTAEX no tiene aceptado el cargo de tutor y por tanto no podemos actuar. Tanto ellos como Ana María residen en Mérida. Ana Mª en Proserpina. Según relatan, Ana Mª tenía su trabajo, debía tener una vida normalizada hasta que enfermó. En una ocasión estuvo hospitalizada en el CSS 10 días y mejoró mucho, pero de eso expresan hace mucho tiempo. Le concedieron una "incapacidad", pero según dicen "ha perdido la paga"... Ahora se dedica a deambular cargada con una maleta acompañada de otra mujer. Caminan a diario de Proserpina al centro de Mérida, independientemente de la temperatura que haga. *Ana Mª no quiere saber nada de ellos, no les coge el teléfono cuando la llaman. **Creen que ha dejado de tomar la medicación y ya no acude a sus citas de Salud Mental. Tampoco saben qué come, aunque alguien les ha dicho que le llevan comida de Cruz Roja de vez en cuando a su puerta, porque no abre cuando le llaman, pero después la recoge. Elisa expresa que ella lo que quiere es "que la lleven a algún centro donde le den su medicación y se ponga de nuevo bien", "...cuando salió la otra vez de Psiquiátrico era un dulce, vamos, como era ella antes de todo esto..." **El teléfono de contacto de Ana Mª es 616 729 463.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-09-16','Ana: En relación a la comunicación recibida de la Ud. de Gestión de Programa Asistenciales, de la apertura en nuevo centro con servicio de RAL, en Castuera, gestionado por ADISER HORIZONTES, a fecha de 1 de noviembre, cumplimento y pongo para la firma del D.Gerente, el Modelo de SOLICITUD DE ELECCIÓN DE CENTROS DE ATT. A P.D., dejando abierta de nuevo la solicitud a toda Extremadura para que lo añadan también en este centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-09-16','Ana: Llamo a Patricia, Enfermera (sustituta) del ESM-CC (54611), consiguió contactar con el hermano de Saturnino, quién le ha informado que Saturnino está bien, debe haber olvidado la cita. Mañana se incorpora la enfermera de referencia, le ha dejado todo anotado. También hablaron con Toni-Futuex, en caso de no conseguir contactar en estos días desde Salud Mental con Saturnino, avisarán para que Virginia-Futuex, la semana que viene, intente contactar con él y recordarle la cita para el inyectable.','2');
