insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2020-09-17','CORREO Se pone al correo Contrato de Prestación de Servicio Social de Ayuda a Domicilio. Empresa: ASINDE; C/ José Espronceda, 17,-C, Badajoz, 06001.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-09-17','Ana: Correo de ayer por la tarde de las educadoras del CAM Fco. Pizarro-Trujillo (educadoraspizarro@gmail.com): "Buenos días Ana, te remito el permiso de salida para que lo firme el Director del Sepad, si consideras que hay que modificar algún aspecto, me lo comentas y se cambia. Decirte que Aitor se encuentra ya bien de salud. Un saludo." ······················································································································································· Mi respuesta: "Buenos días, En relación a la autorización que enviáis, es un modelo que sirve para menores, pero no lo vemos apropiado para Aitor, dada su nueva circunstancia. Los compañeros han hecho un modelo general que ya se ha utilizado en otros centros, así que más fácil aún para vosotros, pues ya os lo hago llegar firmado y sellado por el Director-Gerente del SEPAD (representante legal de Aitor). En cuanto a su estado de salud, me alegro de que ya esté bien y espero que nadie más del centro e haya visto afectado (ni menores ni profesionales). Por otra parte, en relación a las medidas de prevención adoptadas ante el Covid-19, os remito en documento adjunto, una carta del Representante Legal, que se ha enviado a los centros que solicitaban salidas este verano, de modo que es necesario cumplir lo que en la misma se indica. En este caso que planteáis (salidas de fin de semana para visitar a la madre), para no tener que hacer la PCR antes de regresar, lo mejor es que la duración de la estancia sea inferior a las 48 h. Ante cualquier cuestión no dudéis en contactar de nuevo conmigo. Un saludo y buen día." ·················································································································································· Respuesta de las educadoras del CAM: "Buenos días, Ana Nos parece perfecto que nos envíes una autorización más acorde a las circunstancias de Aitor y la Comisión Tutelar. Tendremos en cuenta vuestras indicaciones. Por el momento, tanto los menores como los profesionales estamos bien, gracias. Esperamos que vosotros también. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-09-15','Ana: Envío correo a Paula, T.O. CRR-Plas.: "...os escribo este correo en relación a la posibilidad de venta de la vivienda de Mª Concepción Fernández Muñoz. Deciros que los compañeros ya han comenzado las gestiones oportunas. Pidieron nota simple al Registro de la Propiedad y han solicitado valoración del estado de la misma al técnico municipal del Ayto. de Madroñera. El Técnico ya ha confirmado que va a realizar una visita a la casa, pero dado que no disponemos de la llave (en la CTAEX no la tenemos), a priori no podrá hacer la visita en el interior, por ello, queríamos pediros que le preguntéis a Conchi quién la tiene y veáis cómo se puede facilitar al técnico para que realice visita también en el interior. Espero vuestra respuesta. Gracias de antemano y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-09-17','Ana: Correo de Paula TO CRR (tocupacional.crrplasencia@grupo5.net), en respuesta al mío: "Buenos días Ana, he hablado con Conchi y me va a facilitar el teléfono de un hermano suyo que tiene las llaves. En cuanto lo tenga os lo paso para que podáis contactar con él. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-09-17','Ana: Correo de Paula, CRR-Plas. (tocupacional.crrplasencia@grupo5.net) para secc. ecca. y social: "Buenos días, me pongo en contacto con vosotros en relación a Toñi Bernardo por varias cuestiones: • La primera es que nos comenta que quiere que se le haga una trasferencia de 300 Euros a su hija. La semana que viene es su cumpleaños y dice que lo sigue pasando bastante mal a causa del impacto del coronavirus en su vida laboral, para ella es muy importante. Si no pudiera ser esta cantidad agradecería que pudiera ser alguna (la más aproximada). Los datos serían Alba Vaquero Bernardo ES3702390806773248264727. • Por otro lado queremos empezar a concretar con Toñi la posibilidad de paso a piso supervisado. Ella es ambivalente respecto al tema, puesto que argumenta que le cuesta creer que pueda tener un alta terapeútica y que lo aceptéis desde la comisión. Por este motivo queremos plantearle un plan en el que hay un plazo (unos 6 meses) de estancia en el piso en el que debe cumplir los objetivos propuestos (en relación a medicación, realización de actividades instrumentales y autocuidado, así como de manejo en comunidad, posibilidad de búsqueda de empleo y convivencia). Si va cumpliendo al 4º o 5ºmes se comenzaría a buscar vivienda en su localidad (Valencia de Alcántara) o en otra localidad (acordada) que pudiera cumplir los requisitos para poder vivir con los limitados recursos económicos que dispone o en la que pudiera buscar un empleo. • Así mismo su deseo de ir al domicilio familiar desde el día 23 de septiembre al 6 de Octubre. Conoce y entiende las medidas de seguridad para la prevención del Covid, así como la necesidad de hacerse una prueba PCR y tener un resultado negativo para poder regresar al recurso. Espero vuestra respuesta. Un saludo." ········································································································································· Mi respuesta: "Buenos días Paula, • En relación al dinero que quiere ingresar a su hija, l@s compañeros del área económica mirarán sus posibilidades económicas y la cuantía que se autoriza en caso de ser posible. Entiendo que es una cuestión importante para ella y redunda en su bienestar. • En cuanto al paso al piso supervisado, si en el equipo terapéutico del centro consideráis que está preparada y que es positivo para ella, no pondremos inconveniente, pero sería conveniente que nos remitieseis un informe, no es necesario que sea muy extenso, en que expongáis los motivos y criterios de dicha propuesta. En cuanto al plan de trabajo propuesto, para la consecución de los objetivos que os planteáis con ella, vosotros sois los especialistas competentes, por mi parte, lo único que quiero añadir, es que no sé si 6 meses será tiempo suficiente para abordar todos los aspectos y retome su vida independiente con seguridad y ciertas garantías de éxito. • En cuanto a la visita al domicilio familiar, supongo que la familia también entiende que en el caso de que diera positivo debería poder hacer el aislamiento allí y dispondrá de medios para ello. O, en su defecto, que en el CRR, seguís teniendo la posibilidad de aislarla, tal y como se ha hecho anteriormente en otros casos. Por mi parte, de momento, nada más. Ante cualquier otra cuestión no dudéis en contactar de nuevo. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-09-17','miguel, nuevo email de Pablo (familiar de la tutelada): "Esta mañana les he mandado un correo con el asunto de mi abuela Manuela Morato Picado y no tengo ninguna respuestas de ustedes,lo que quiero que entienda es que estamos preocupados y como aquí hace todo el mundo lo que le da la gana ,espero que ustedes por lo menos tengan cinco minutos en llamarme o mandarme un correo.En contarme donde esta,como se encuentra e.t.c. Espero y deseo que lo tengan en cuenta ,porque tengo los vecinos de la abuela que son los que me informan es más me dijeron que la chica que está con la abuela a cojido vacaciones y resulta que mandan a otra chica para sustituirla llega a casa de la abuela y se encuentra de que la abuela no esta no existe,entonces a mi entender significa una cosa que a cogido Don Jose Manuel Correa Morato a cojido a la abuela y se la a llevado a no se donde,en fin sabéis que es lo que pienso que hay que ser un sirvenguenza para que te hagan caso, os lo pido de rodillas que me digan algo sobre mi abuela, Un saludo Pablo Correa Morato. Mi numero de telefono es 676783101"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-09-18','miguel, comunico vía email a la Policía local de Valencia de Alcantara la desaparición de la tutelada: "“Estimados/as Sres./as.: La Comisión Tutelar de Adultos de Extremadura fue nombrada Tutor de Dña. MANUELA MORATO PICADO, con DNI nº. 07033829-S, mediante Sentencia Judicial nº 11/14, de 26 de marzo de 2014. Cargo que fue aceptado, por ésta, mediante Acuerdo de 15 de abril de 2014. En base al cargo conferido, según lo expuesto en el párrafo anterior, solicitamos acudan al domicilio de nuestra tutelada, sito en la C/ Extremadura, nº 25 de la localidad de Valencia de Alcántara, para corroborar, en informe o documento pertinente, información que se nos ha comunicado por terceros: qué su nieto y principal cuidador D. José Manuel Correa Morato, se ha llevado, de nuevo, a Dña. Manuela Morato Picado, suponemos que a la Provincia de Toledo sin ponerlo en conocimiento previo ni recabar autorización de esta Comisión Tutelar de Adultos, llevando ya varias semanas fuera de la residencia habitual”. *********************************************************** Asimismo respondo vía email a Pablo: "Buenos días, tenemos conocimiento de dicha situación y ya hemos procedido a ponerlo en conocimiento de la Policía Local".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-09-18','Ana: Adelanto escaneado por mail, tanto al CADEX de CC como al de Ba, la solicitud de traslado de expte. de Felisa, que me han devuelto de registro. Registrada de salida a fecha: 16/09/20. ···················· La envío también por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-09-18','Ana: Pongo para REGISTRO DE ENTRADA la SOLICITUD DE ELECCIÓN DE CENTROS DE ATT. A P.D. **De nuevo no indico ningún centro para que siga incluido en la lista general de todos. ··························································································································································· Llamo a Maribel Ramos, TS de Discapacidad (68494), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-09-18','Ana: En respuesta al escrito del INSS solicitando documentación, dado que no recibimos el libro de familia solicitado, una vez dado registro de salida, envío por correo certificado Oficio adjuntando Certificados de Actas de Nacimiento de Pablo y su hermnano Guillermo al CAISS de Don Benito. *Aclaro en el mismo, que no se adjunta NIF/CIF de la entidad por carecer la CTAEX de Personalidad Jurídica Propia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-09-15','miguel, se celebra el juicio y la condenan entre otros a prohibición de residir durante 6 meses en el municipio, con lo que habría que sacarla del Centro de Mayores de Jaraicejo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-09-18','“He llamado al Jzdo nº1 de Trujillo por el procedimiento Lev juicio Delito Leve 4/20 cuya vista fue el día 15/9/20, y donde fue representada por abogado de oficio Antonio Gil Alvarez, tfno 927-237901 y 678636803 y me comentan que han mandado un exhorto a los servicio común procesal de los jzdos de Mérida para que nos notifiquen la sentencia aúno no firme hasta pasados 5 días a partir del martes (según me comenta el jzdo tendrán en cuenta la fecha en que notifican a nuestra procuradora Mª Blanca) Y han mandado un oficio a oficina de la junta de avda Hernan Cortés (me comenta a la Consejería de bienestar social de Cáceres, entiendo se refiere al SEPAD), por el motivo del contenido de la sentencia donde condenan a la tutelada entre otras prohibiciones a no poder residir durante el plazo de 6 meses en la misma localidad. Me comenta que ya lo ha notificado a abogacía vía Lexnet. La pido nos lo envíe esta mañana por fax (me dice que o bien esperemos a que nos requieran para comunicarnos la sentencia desde los servicios de comunicación procesal de los juzgados de Mérida o bien les devolvamos el fax que nos remiten poniendo la fecha y firma de recibí. Por tanto, una vez que nos llegue la sentencia y veamos el contenido hablaré con el Abogado para que la recurra y entre otras cuestiones alegue que no podemos encontrarla otro centro donde residir. Paralelamente he hablado con Angel para tener un criterio común, y comunico vía email a Ana por si se le ocurre alguna solución aparte”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2020-09-18','miguel, llamo al Jzdo de Mérida nº4 por el procedimiento de X06 REmoción de Tutela 232/20 y me confirman que no se ha suspendido el procedimiento previsto para el día 22-9-20 a 12h. Por tanto han denegado la suspensión solicitada por Curro, ya que solicitó que le notificaran la demanda y documentación complementaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-09-18','miguel, contesto a la hna del tutelado adjuntandole el documento que nos envió la abogada donde queda acreditado que falta que nos envíe los contratos de arras y tasaciones así como que necesito que me aclaren cuáles son las fincas que necesitan autorización de venta (aparte de la solicitud de aprobación judicial)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-09-21','Ana: Llamo a Pilar Cerrillo, TS de la Res. (618 90 85 06): confirma que,por supuesto, Pedro al alta tendrá todos los cuidados que precise. ·········································································································································································· Llamo a Marisol, TS del HUC (56823): se lo comunico. Pedro al alta volverá a la misma residencia. *Le indico que otra cuestión sería que diera puntuación para plaza sociosanitaria, pero mientras no sea así vuelve a su plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2020-09-21','Ana: llamada de Mariví Clemente, CSS-Plas., dice que Francisco, a quién han reconocido Grado I de dependencia, está estable y han decidido solicitarle plaza en Piso Supervisado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-21','Ana: Llamada de Mariví Clemente, le digo que aún no he recibido el Cdo. del CADEX. Me lo enviará escaneado mañana sin falta. *En cuanto a la solicitud del complemento a 3º persona de la PNC de Jairo, dice que como no hay modelo oficial de la solicitud va a ser un jaleo enviarme ella el escrito para la firma.... finalmente, le digo que yo lo hago... ···································································································································································· Redacto e imprimo el escrito-solicitud de complemento a 3ª persona y pido a Juan Pedro, Admvo. CTAEX, que lo ponga para la firma del D-Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-09-21','Ana: envío correo al ctutelar@, secc. ecca: "...en relación a Manuel Domínguez Martín, ha vuelto a llamarme el padre (Manuel 722 570 842), diciendo que la hija de Manuel sigue sin percibir la Manutención que tiene que pasarle. He hablado también con la hija, Alicia (611 070 785), al parecer son ya 6 los meses que hace que no la percibe, ¿podríais mirar cuál es el problema e intentar solucionarlo?. Ya me vais diciendo. Gracias!" ····································································································································································································· Envío correo a Pilar Lavadiño, responsable del Piso Supervisado para interesarme por el ingreso y los pirmeros días de Manuel. ········································································································································································································· Respuesta de Pilar: "Buenos días Ana, pues por ahora todo bastante bien. Está en periodo de aislamiento hasta el miércoles y no lo lleva mal. Se adaptó a los dos compañeros bastante bien, y aunque a veces se aburre un poco, por ahora se le ve colaborador y motivado. Por otro lado las cuestiones económicas parece que se arreglaron sin complicaciones, así es que a pesar de los contratiempos parece que todo va bien Ya iremos viendo que tal va."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2020-09-21','Ana: Correo de Carmen, EVD-Plas. (carmen.garciamarti@salud-juntaex.es): "Hola Ana, tengo el caso de Guadalupe Barragan Garcia que tiene Grado II , y esta en el CRR Solicitan residencia, en San Francisco, Hervás y en la de Malpartida pero esta sería una T4 , tendria que pasar una herramienta de enfermeria que avale que no tiene deterioro cognitivo... ya que llevas tu los casos de esta zona, la aceptacion pia donde la mando , ahi ala comision o al CRR ?? a quien se pone como representante legal , a la comisión o a nombre del director ....( perdona es que no he hecho apenas a gente tutelada y ahora mismo lo dudo ) he hablado antes con la terapeuta del centro y me confirma estos centros, pero no se muy bien si tu como comision te parecen bien estos centros ? son todos del area de plasencia..." ··················································································································································· Mi respueta: "... En cuanto a Guadalupe Barragán García, vamos por parte; 1. Los centros son lo que ella quería, sólo en la zona de Plasencia, así que sí, si Paula, TO, te los ha confirmado están bien. 2. La Aceptación PIA nos la tienes que remitir a la CTAEX (SEPAD, COMISIÓN TUTELAR DE ADULTOS, AVDA. DE LAS AMÉRICAS, Nº 4, 06800 MÉRIDA), para que la firme el representante legal: D. José Vicente Granado Granado, Vicepresidente de la Comisión Tutelar de Adultos. (Como sabes es a su vez el Director-Gerente del SEPAD) 3. Y en cuanto a la herramienta para la T4, se la tendrán que pasar desde el C. Salud, no? supongo que en este caso podrás ponerte tú en contacto. Ante cualquier otra cuestión, no dudes en contactar por mail o teléfono..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-09-22','Ana: Me devuelven de registro las solicitudes de PFHC y Orfandad, registradas a 21/09/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-09-22','Ana: Me devuelven de registro la Solicitud de elección de centros, registrada a 21/09/20. ···························································································································································· Llamo a Maribel Ramos, TS de Discapacidad (68494), le informo de que ya está registrada de entrada la solicitud. *Seguirá en la lista general para cualquier centro, incluido el nuevo centro de Castuera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-09-22','miguel, recuerdo a Ana el email que remitií explicando la resolución del jzdo nº1 de Trujillo del procedmiento jucio delito leve 4/20 cuya vista fue el 15/9/2020 y donde una vez sea firme entre otras prohibiciones tendrá que dejar el municipio durante 6 meses. ******************************************************** Paralelamente llamo al abogado defensor de la tutelada Antonio Gil Alvarez (tlfno 927-237901 y 678-636803) no logrando hablar con él, pero le dejo mis datos para se ponga en contacto conmigo y explicación que necesitamos que recurra la resolución judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-09-22','miguel, llega la nueva citación (aplazado dos veces) para vista por proced división herencia 484/2019 del jzdo nº2 Coria','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-09-22','Ana: Tal y como me pidió Pedro, tras haber hablado con Maribel Ramos, TS Secc. Discapacidad, pongo para la firma del D.Gerente la solicitud de elección de centros de At. a P. con Discpacidad, añadiendo el nuevo centro de ASPACE ubicado en Jaraíz de la Vera. ·················································································································································· Entrego con nota interior, la solicitud de elección de centros, debidabmente firmada y sellada, a la Secc. de Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2020-09-22','miguel, hablo con la gestoría quién me indica que necesitan la cuenta para abonar de la herencia del padre (único bien que había y sólo le deja la legítima) 167€. Le harán el abono','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2020-09-22','Iciar- Llama la vecina de la casa de CArmen en Valdecaballeros quiere saber qué se va a hacer con la casa de Carmen pues linda con la suya y la de otro vecino y debido a su estado, sobre todo la parte de atrás,humedades y animales varios, no pueden hacer obras en su terreno. Pide solución - Aurora Schz Shz 924 64 3480','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2020-09-22','Ana: Llamo a Mª FERNANDA 924 870 250 /45637 TS C. Salud de Llerena; Carmen está ingresada en la UHB desde el jueves pasado, fue decisión de su médico. Ella no puson ningún impedimento para el ingreso. Me facilita varios números de Psiquiatría del Hptal de LLerena: 47157 / 47037 / 47171 / 47173. ···································································································································· LLamo al Hptal. de Llerena, hablo con Constanza, Psiquiatra. Acordamos que le enviaré por fax (924 87 70 39) el auto y llamaré también al CSS-Mérida para enviralo. ····· Envío el fax - Reporte Ok. ····································································································································· Tras hablar con Soraya Masa, Ud. RR.AA., Llamo a Carmen Franco - Directora del CSS-Mérida (24003). Le envío por email el Auto de internamiento. Pongo en copia a Soraya Masa. *Carmen se pondrá en contacto con Constanza para organizar el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-09-22','miguel, me escribe el abogado de la familia Miguel Ángel Asensio Muñoz tlfno y fax 924-86-11-23: "Mi nombre es Miguel Ángel Asensio Muñoz, abogado ejerciente con número de colegiado 3243 del ICABA. Siguiendo las indicaciones de Miguel Ángel Figueroa Martín (le reenvío los emails de más abajo para su mejor localización), le dirijo el presente por el siguiente motivo: - Dª ASCENSIÓN MARTIN SAMPER, madre de D. FELIX FIGUEROA MARTIN, a su vez tutora de otra de sus hijas Dª MARIA TERESA FIGUEROA MARTÍN, me ha encargado la gestión de la autorización judicial para renunciar en nombre de Mª TERESA a la herencia de su padre D. RAFAEL FIGUEROA LÓPEZ, delegando en su hijo MIGUEL ÁNGEL para que me facilite la documentación y/o información necesaria. - Miguel Ángel me facilita la renuncia de todos los hermanos menos la de FELIX, me indica que éste se encuentra tutelado por la Junta de Extremadura, quién ya ha iniciado también en su nombre el procedimiento correspondiente para solicitar la autorización judicial para renunciar a la herencia. - De cara al procedimiento de Mª TERESA, nos facilitaría mucho la labor poder acreditar la renuncia del resto de herederos o, como en el caso de Felix, la iniciación del trámite en aras del mismo fin. Es por ello que, si no tiene inconveniente, le rogaría me facilitase una copia de la primera página de la demanda sellada o con el reporte de lexnet para acreditar la renuncia a la herencia de D. RAFAEL FIGUEROA LÓPEZ del total de los herederos restantes o cualquier otro documento que usted pueda considerar oportuno y que acredite este hecho pues, como le he indicado, el único interés que tengo del procedimiento de Félix es poder acreditar en el procedimiento de Mª Teresa que tramito, que el único heredero del que no acompaño renuncia a la herencia, también tiene intención de renunciar a la misma. Agradeciendo de antemano la atención dispensada, quedo a su disposición para cuanto pueda precisar". ********************************************* Le contesto que en cuanto tenga firmada la renuncia y ratificación de la herencia se lo comunicaré','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2020-09-22','Ana: Recibo llamada de Ana Benavente, TS ESM-Plas: en la última cita que tuvo Carmen con ella en su despacho, expresó su preocupación por la precaria situación económica en que se encuentran su madre y su hijo. Le gustaría poder aportar, al igual que año pasado al inicio de curos, dinero para material y ropa. **Pediré a la secc. ecca. que lo valore. ·················· Paso nota a Alberto, Jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-09-22','miguel, me llama Ainés (tlfno 659-251339) y vemos que está todo correcto para pedir aprobación de herencia y autorización de venta de las 7 fincas: Me comenta que cuando hable con el jzdo llame a estos dos tlfnos 927-422110 y 927-405370. ***************************************************** Llama la abogada Ana Mª de Pablo Laquintana. Abogada. Elkano kalea 1, bajo. 20240. Ordizia. Gipuzkoa. 675704059 / 943565717 adepablo8@gmail.com, y al no poder localizarme me remite varios emails con documentación: "Estimados Sres. de la Comisión Tutelar de Adultos de la Junta de Extremadura, estoy llamando al teléfono 924003809 y no consigo hablar. Espero que hayan recibido sin novedad toda la documentación nuevamente enviada por We Transfer. Por si acaso, voy a enviarles en dos correos sucesivos la mitad de la documentación en uno y la otra mitad en otro. Esta parte quiere que ustedes soliciten al Juzgado en un mismo escrito la APROBACIÓN JUDICIAL DE LA PARTICIÓN HEREDITARIA y la AUTORIZACIÓN JUDICIAL DE LA VENTA DE TODAS LAS FINCAS por el precio de las valoraciones realizadas. Les envío a continuación escaneados: .- Testamentos de los padres. .-Certificados de defunción y de actos de últimas voluntades de los padres. -. Escritura de Ratificación de la Herencia por la Comisión Tutelar de Adultos de Junta de Extermadura. .-Último borrador de la Escritura de Partición Hereditaria ***************************************** Y un segundo email: "Estimados Sres. de la Comisión Tutelar de Adultos de la Junta de Extremadura, estoy llamando al teléfono 924003809 y no consigo hablar. Espero que hayan recibido sin novedad toda la documentación nuevamente enviada por We Transfer. Por si acaso, voy a enviarles en dos correos sucesivos la mitad de la documentación en uno y la otra mitad en otro. Esta parte quiere que ustedes soliciten al Juzgado en un mismo escrito la APROBACIÓN JUDICIAL DE LA PARTICIÓN HEREDITARIA y la AUTORIZACIÓN JUDICIAL DE LA VENTA DE TODAS LAS FINCAS por el precio de las valoraciones realizadas. Les envío a continuación escaneados: -Escrituras de Propiedad del Piso de Azkoitia. Finca nº 1. -Contrato de Arras de la vivienda de Azkoitia (Valor 71.600€. Precio de la compraventa: 71.600 €. Abonado a la firma del contrato de Arras: 7.000 €). -Escrituras de la casa de Calle Malavé 47 de Valle de la Serena. - Contrato de Arras de la casa de Calle Malavé. - Informe de Valoración del Piso de Azkoitia -Informe de Valoración de la casa de Calle Malavé y de las demás fincas sitas en Badajoz. Quedo a su entera disposición para cualquier duda o cuestión que quieran plantearme. Un saludo Ana Ana Mª de Pablo Laquintana. Abogada. Elkano kalea 1, bajo. 20240. Ordizia. Gipuzkoa. 675704059 / 943565717 adepablo8@gmail.com " *************************************** Y mi contestación: Buenas tardes, disculpe pero he llegado tarde del juzgado. Ya he hablado con Ainés. Me he comprometido con ella a que en esta semana enviarlo al juzgado donde solicitaré la autorización no sólo de las dos urbanas (que ya tienen el contrato de arras), también de las rústicas, tal como veo en la tasación que me envía por email. La llamaré a las dos tanto para confirmarles la presentación, así mismo haré un seguimiento con el juzgado y se lo comunicaré. Gracias por la documentación.Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2020-09-22','miguel, asisto a la vista y no se suspende el juicio por remoción. Queda aplazado a que nos citen a vista por juicio oral. Le confirmo a Curro que sólo nos enviaron diligencia de ordenación pero no demanda. A él tampoco se la enviaron con lo que no puede oponerse a la demanda. En cuanto la tenga nos pedirá un informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-09-22','Ana: Pongo para la firma del D.Gerente Solicitud de PFHC para personas jurídicas de Julia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2020-09-23','Ana: Correo de Sonia Bernabé - ASindi (trabajosocial@asindi.e.telefonica.net): "Buenos días, os quiero informar que Juan Gabriel regresó anoche al centro. Tras valorar el médico todas las posibilidades creyó inicialmente mejor intentar colocarle la muñeca por los riesgos que podía suponerle la intervención. Le colocaron la muñeca y se la escayolaron. En 15 días tiene consulta para seguimiento y comprobarán si está bien o precisa de intervención. Esta información también se le trasladó a la familia para que su hermana estuviera tranquila. Tardaron tiempo en atenderle porque el traumatólogo estaba operando y organizamos para que una persona sustituyera a la compañera que estaba con él. La persona que estaba con él desde el principio regresó en taxi dado que a esas horas no tenía otra posibilidad y la que fue a sustituirle se fue de Alcántara a Cáceres en ese mismo taxi. Tengo que llamar para el ver el coste precio/hora de la persona que estuvo las últimas horas en el hospital con Juan y me decís si se hace recibí, transferencia ,... No creo que suponga mucho porque fueron pocas horas. Quería aprovechar para preguntaros por los trámites en caso de que hubiera habido intervención o si surge otra urgencia de este tipo a los tutelados. ¿No sé si tenéis un modelo de documento en el que se autorice la intervención siempre que la aconseje el facultativo o algo similar? Porque si ocurre como ayer y no podemos localizaros lo mismo nos solicitan algún documento o poder contactar con el tutor directamente. Ya me decís cómo podemos proceder para organizarlo. Yo sigo con teletrabajo, si precisáis de más información me podéis llamar al 669 60 29 20. En cuanto tenga los datos económicos os los paso. Un saludo," ··············································································································································· Respondo pidiendo que los gastos (factuas/declaraciones juradas las remita a la atención de la secc. ecca. Y explico el funcionamiento en cuanto a los CI médicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2020-09-22','Ana: Correo de Sonia Bernabé, TS y Directora - ASindi (trabajosocial@asindi.e.telefonica.net // 927 39 01 93 / 669 60 29 20): "Hola, quería informaros que Juan Gabriel Sobrino Tardío, se ha caído al chocar , accidentalmente, con otra residente. Hemos llamado al Centro de Salud para que le valorarán la muñeca y nos dicen que creen que es fractura y puede que necesite intervención. Ahora mismo está con una cuidadora de la entidad en el Hospital Universitario de Cáceres. La cuestión que quería plantearos, además de informaros es si llegado el caso tienen que intervenirle, como organizamos. El Centro no puede asumir el tener en el hospital a alguien de apoyo para Juan, entonces en otras ocasiones, lo que hemos hecho es que ayudamos a la familia o tutores a tener a una persona que conoce a Juan, en este caso, (suelen ser cuidadores que han trabajado en el centro para sustituciones) y el coste lo asume la familia. Os mantendré informados pero necesito que me indiquéis cómo proceder si hay ingreso y también en el caso que haya que firmar algún documento previo a la posible intervención. Un saludo" ······················································································································································· Mi respuesta: "Hola Sonia, Perdona, acabo de ver el correo, mantenernos informados de la evolución y si hay que intervenirle. En el caso de ingreso en el hospital, si económicamente puede asumirlo, habría que contratar a alguna persona, si como decís contáis con personas de confianza y que le conozcan mejor, pero pongo en copia a la secc. económica para que valoren las posibilidades, con ellos tendréis que tratar el coste del “servicio” y cuántas horas al día se le podrían contratar." Vamos viendo según evolución. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-23','Ana: Llamada de José Manuel (667 384 817), como en las últimas dos conversaciones no anotadas, realiza sus demandas habituales: qué le suban la asignación (le recuerdo que tiene multas que pagar), que demos de baja el cátering que prefiere ir al comedor social, al mismo que antes se negaba (le digo que en principio no se va a dar de baja, ya se lo dijo Pedro, Jefe de secc. *En todo caso, cuando desde el comedor social nos comuniquen que lleva una semana acudiendo, lo valoraremos), pregunta qué pasa con Jazztel, (le recuerdo que él firmó un contrato cuando no debía, como le dije en su día, que lo soluciones él), que tienen que llevar el ruter a la tienda de orange, pues es lo que le han dicho (le digo que entonces lo lleve), que si se puede quedar la tele (le recuerdo que no, que debe devolverla) y por último **que le autorice a comprar un móvil, que ha hablado con otra compañera de la secc. ecca. que no sabe cómo se llama y ésta le ha dicho que lo decida yo (le digo que me extraña que le hayan dicho eso, pues Alberto, Jefe ecca., es quien toma esas decisiones. *Además le recuerdo que se le autorizó para comprar uno hace unos meses) ················ En cuanto al ABOGADO de oficio, ya le ha facilitado los datos de sus hijos. ···························································································································································· Llamada de Pilar Martín, TS ESM-CC: El abogado de José Manuel, Santiago Merino Jerez (670 650 164), se ha puesto en contacto con ella y dice necesitar documentos justificativos de los gastos habituales que tiene José Manuel al mes. *Me parece raro que no lo haya solicitado directamente a la CTAEX. **Meidante email se lo comunico tanto a los compañeros de la secc. ecca. como a los de la jurídica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-09-23','Ana: Correo de Toni-Futuex de ayer: " Te traslado lo que nos dijo el nieto de Manuela Morato, literal por telefono, la semana anterior: (cualquier cosa es esperable dada su trayectoria) Comunicado viaje: Contacta, el nieto de Manuela, para comunicar que, por motivos personales, se trasladan al domicilio de su hermana a Toledo, adjunta dirección: C/ Gaviota, 5 portal 2 1ºA, El Viso de San Juan, Toledo. También proporciona los teléfonos de contacto: 620 67 33 71 y 671438716, no indica la fecha de retorno, sólo establece que lo comunicará. Se le dice que se comunicará a la CTAEX, aunque según señala, también lo ha hecho por su parte, y se le seguirá llamando para proceder a los seguimientos oportunos como se ha venido haciendo hasta la fecha." ···························································································································································································································································································· Mi respuesta: "Buenos días Toni, Él en su línea… No obstante, hubiera estado bien saberlo cuando os lo dijo, pues nos enteramos por la empresa de SAD, pues fueron a atenderla y no había nadie en casa, así que se comunicó a la policía para que nos vuelvan a remitir informe una vez más… pero vamos, que a la CTAEX no sólo no lo comunicó, sino que no pidió autorización como sabe que debe hacer. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-09-23','miguel, tanto ayer como hoy llamo al abogado Antonio Gil Alvarez, tfno 927-237901 y 678636803, en relación Jzdo nº1 de Trujillo por el procedimiento Lev juicio Delito Leve 4/20. Dejo recado en contestador de móvil tanto de mis datos de contacto como de la necesidad que recurra la resolución en 5 días. ******************************************************* Finalmente hablo con el abogado y me confirma que es inviable el recurrir la sentencia porque es absolutoria y únicamente contiene la prohibición consistente en la expulsión del municipio durante 6 meses. Sólo queda por tanto como vía alternativa una vez que esté en trámites el procedimiento de ejecución comunicar y justificar al juzgado motivo por el que no se puede cumplir dicha sentencia (incluso solicitando un cambio de dichas medidas de prohibición). Pero me asegura que hoy por hoy al ser una sentencia absolutoria (sin multas ni prisión) no se puede hacer más. Por tanto esperaremos a la ejecución de sentencia. Me va a mandar la resolución judicial y envio email a Pedro, Ana explicativo de todo. ******************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-23','miguel, contestación de Rosa del CSS de Plasencia a cómo afrontar la sentencia de Jairo (orden de alejamiento, internamiento de 1 año y 3 meses, y el pago de la multa de unos 10.500€). Dejo aqui los emails intercambiado con Rosa: "Buenos días Miguel: Tras contactar con los profesionales, paso a informarte sobre los temas de Jairo: En cuanto a la medida de seguridad de internamiento, entendemos que la pasará aquí pues el paciente de quien tiene orden de alejamiento no se encuentra ingresado en este Centro, en este momento. Sólo en el caso de que se produjera la circunstancia de ingreso, habría que plantear el tema. La asignación mensual para Gastos de bolsillo asciende a 60 €/mes, para Tabaco 37,20 € mes (redondeando, 100 €). No obstante, en el momento que iniciara el cumplimiento de la medida, el paciente dejaría de abonar cantidades por estancia en el Centro, por lo que mensualmente quedarían libre de su pensión 295,60 €. Si necesitas mayor información y aclaración de cualquier tema, puedes llamarme. Un saludo. Rosa Bravo. CSS. Plasencia. ________________________________________ De: MIGUEL FERNANDEZ DE LLERA >miguel.fernandezd@salud-juntaex.es> Enviado: martes, 22 de septiembre de 2020 11:16 Para: Rosa Maria Bravo Pacheco >rosamaria.bravop@salud-juntaex.es> Asunto: RE: DILIGENCIA NOTIFICACIÓN JAIRO Buenos días, salvo que me indiques lo contrario entiendo que la medida de alejamiento y de internamiento la cumplirá desde este momento en vuestro centro. Caso contrario tendríais que solicitar el traslado a CSS Mérida. Confírmame por favor este extremo. En cuanto el dinero, se ha solicitado el aplazamiento de la cantidad de los 10.570€ nos lo indicará el juzgado en procedimiento de ejecución las cantidades a abonar al mes. Necesitamos por vuestra parte que nos indiques una cantidad de dinero mínima mínima a darle al mes, para poder pagar esta cantidad pasarán años".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-09-23','Ana: Llamada de Juan José (667 958 878), sigue contento en CC, parece que se está adaptando bien. En cuanto a las retiradas de efectivo, acordamos que esperaremos 3-4 semanas más para volorar el cambio. La idea es, que si se adapta bien al nuevo recurso y se sigue administrando bien, probaremos a pasar a retirar la asignación de forma quincenal, retiraría los 220€ cada dos lunes (Actualmete saca 100€ un lunes y 120€ al siguiente). Le gusta la propuesta y la acepta de buen grado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-09-23','miguel, recibo de la policía local por email notificación de donde se encuentra la tutelada y me indican esto: "Habiéndose realizado las gestiones y averiguaciones pertinentes, les informamos que Dª MANUELA MORATO PICADO con DNI nº 07033829S se encuentra junto a su nieto desde hace aproximadamente unos 10 días en la localidad de: Viso De San Juan (C/Gaviota nº5, Portal 2,1ºA) provincia de Toledo. Telf. de contacto 925502182." *********************************************** Envío el email a Pedro, Ana y Angel. Y contesto a Pablo Correa indicandole dónde se encuentra su abuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-09-23','Ana: Correo de Toni-Futuex: "Hola Ana, te comento alrespecto del tutelado de Miajadas, Esteve Pascual: Contacta la directora de los PPTT para consultar si Esteve tiene obligatoriedad de acudir al Centro Ocupacional, dada la situación de rebrotes que estamos viviendo. Se le dice que se comunicará a la CTAEX, pues sus tutores son quienes tienen esta capacidad de decisión; se le explica que, en condiciones normales, tiene dicha obligación, (ya que entendemos que tiene una plaza subvencionada, pero tampoco estamos seguras de ellos) pero dada la situación excepcional que estamos viviendo, se desconoce si se puede hacer alguna excepción. Chus, directora de los pisos, indica que no se niega, sólo quiere saberlo, pues tiene que separar a Esteve de los otros usuarios que no acuden al C.O., como medida de prevención, además de precisar conocer las medidas que se tomarán en el mismo. Por parte de la dirección del C.O., de forma constante, amenazan con quitarle la plaza al tutelado, aspecto que tiene agobiada la directora de los pisos. Por otra parte, consulta que si acude al C.O. hay posibilidad de inscribirlo en la escuela de educación de adultos para que pueda retomar sus estudios, los cuales dejó hace años y tiene el graduado escolar a medias. Se le comenta que desde la CTAEX siempre se apoya que se lleven a cabo este tipo de actividades pues son importantes para los tutelados, pero, al parecer, la directora del C.O. se opone a que falte un par de horas a la semana para practicar dicha formación; se le dice que, igualmente, se comunicará a la CTAEX y se esperará su respuesta. No se que opinas, y como se puede intervenir, o mas bien mediar, entre los dos organismos para el bien del tutelado. Ya me comentaras al respecto!" ·············································································································································· Respondo que el lunes hablé yo con Chus y le informo sobre la conversación que mantuvimos. ···························································································································································· Envío correo a la secc. ecca. (ctutelar@ y a Alberto, Jefe) en relación a los gastos de farmacia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2020-09-23','ICiar. Facilito a Aurora el correo de la Comisión para que lo exponga por escrito','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-09-23','Ana: Llamada de Marisol, TS del HUC (927 25 68 23): la médica internista le ha dicho que Pedro Román tiene una úlcera, que no es reciente, mal curada, la debe tener desde hace algún tiempo y que tanto ella como la enfermera consideran que seguramente es debido a que no se le ha movilizado lo necesario. *Lo reflejarán en el informe médico. *De nuevo me dicen que no me lo envían, que se lo entregarán al paciente al alta. ········································································································································································································································ Llamo a Pilar Cerrillo, TS de la Res. (618 90 85 06) y se lo comunico. Pilar enseguida me indica que eso no es así, que Pedro trajo esa escara tras el anterior ingreso en el hospital, pues cuando él se fue de aquí no tenía ninguna. Hablará con Sonia, Directora de la Res. ·································································································································································································································· Recibo llamada de Sonia, Direcotora de la Res. (927 290 550), me enviará el informe de alta del ingreso anterior (ya se reflejaba en el mismo) y fotos a la llegada al centro. Adjuntarán también informes del personal de enfermería del centro, así como las indicaciones médicas de cuidados. ········································································································································································································································ En relación a la prestación vinculada al serv. residencia de dependencia (reclamación) llamo a Clara, Jefa de secc. (924 00 92 69), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-09-21','Ana: Conversación con Chus, Directora PP.TT. - Miajadas. Acordamos que a partir del miércoles Esteve comenzará a asistir al C.O. Ella enviará un correo al C.O. para comunicarlo y que lo tengan en cuenta también a la hora de hacer la comida. ···· En cuanto a la idea de que Esteve retome los estudios, me parece bien, pero de momento tendrá que ser en turno de tarde, en el CO tienen plaza pública y no puede faltar. Lo inscribirán en algunas asignaturas solamente. Según se vaya viendo su evolución, motivación e implicación se valorarán otras alternativas. ························· En cuanto a los gastos de farmacia, los pagan desde el PPTT, luego tienen que entregar los recibos/facturas al CO para que la directora se lo abone. Actualmente les deben las facturas de varios meses. *Preguntaré a la secc. ecca. si sería posible gestionarlo directamente con la farmacia, como se hace en otros casos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-22','Ana: Pongo para Registro de Salida la solicitud de complemento ATP. ············································································································································································· Rosa. Amvo. CSS- me remite escaneados el Cdo. de Discapacida y el Dictamen Técnico Facultativo del CADEX. *No tienen el Cdo. de Dependencia. ······················································································································································································· Llamo a Clara I. Gómez Nestares, jefa de secc. depend, para pedírselo, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-09-23','Ana: Correo de Estrella, TS CSS-Plas. "Buenas tardes. Después de varias conversaciones telefónicas mantenidas con Cadex Badajoz, Cadex Cáceres y Comisión Tutelar de Adultos, para un posible traslado de expediente de Felisa Bruno Saavedra, se decide QUE PERMANEZCA EN CADEX BADAJOZ, para lo que contacto telefónicamente con este último y me confirman que la cita el día 25 de septiembre a las 12,30 sigue vigente, con lo que se organiza el traslado de la paciente para la valoración pertinente. Gracias. Disculpen las molestias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-09-23','miguel, a petición de Ana, remito al jzdo comunicación de lo sucedido por fax: En relación con nuestra tutelada, Dª MANUELA MORATO PICADO, se comunica a este juzgado lo siguiente: 1.-Que por Sentencia dictada por ese Juzgado en el Procedimiento de Incapacitación nº 205/2013, de fecha 4 de junio de 2014 se declara la Incapacidad Total de Dª. MAUELA MORATO PICADO y se nombra tutor de la misma a la COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA, cargo que fue aceptado con fecha 15 de abril de 2014. 2.- Que como ya se ha comunicado anteriormente a este juzgado, por ejemplo con la remisión de rendiciones de cuenta, su nieto D. José Manuel Correa de forma habitual se lleva a la tutelada sin previa comunicación y autorización por parte de esta Comisión Tutelar. A esto hay que añadir que únicamente se pone en contacto con esta Comisión Tutelar de Adultos para solicitar dinero para arreglos de la vivienda, negando el acceso a las personas autorizadas por esta Comisión para conocer tanto el estado de la tutelada como de la vivienda. Se comunica todo esto a este Juzgado a los efectos oportunos, para se tenga en cuenta a los efectos de la imposibilidad por parte de esta Comisión Tutelar de ejercer correctamente el cargo de tutor en su día concedido por este Juzgado. 3.- Se adjunta comunicación de la policía de Valencia de Alcantara','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-09-23','Ana: Llamada de Juana, secc. ecca. CTAEX, ha hablado con Felisi, no pueden aumentarle la asignación, pues al dejar de percibir la orfandad de su hijo sólo contará con la PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-09-24','miguel, tras conversación telefónica con Tony de Futuex me comentó que me remitía ese mismo día las fotos, las cuales no nos ha enviado, motivo por el cual la llamé sin lograr hablar con ella y hoy la envío email con copia a Alberto para nos remita las fotos e informe de la visita a la vivienda del curatelado en c/ Sor Valentina Mirón 3, 2ºB, Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-09-24','miguel, ante la insistente queja de su nieto Pablo vía email al correo de la Ctaex, le contesto que ya se ha notificado al Juzgado y que para cualquier duda hable con Pedro Js ······················································································ Ana: Guardo en el expte. digital los distintos correos remitidos por Pablo Correa, nieto de Manuela. En todos pide explicaciones a la CTAEX...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-09-21','Ana: Conversación telefónica con Gema, TS de La Vera (927 46 90 02) Eugenia ha acudido esta mañana a su despacho acompañada de Gloria-Futuex. Pregunta si desde la CTAEX no podemos hacer algo para priorizar la valoración de dependencia de Eugenia para el acceso a recurso. Ella ha enviado el informe social de dependencia. *Le explico que para empezar, de Eugenia sólo tenemso la curatela económica, pero que en cualquier caso, las personas adultas a cargo de la admón., ya sean con tutelas o curatelas, acceden a los mismos recursos y por las mismas vías que el resto de ciudadanos. No obstante, acordamos que ella llamará a Dependencia de Plasencia y yo intentaré hablar con Clara, Jefa de Secc. ··· Por otra parte, me informa de que le ha solicitado el PLAN ACTIVA SOCIAL de ALIMENTOS de la Diputación de Cáceres. ········································································································································ Llamo a Clara I. Gómez Nestares, Jefa de Secc. Depedn (924 00 92 69), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-09-23','Ana: Llamo a Clara I. Gómez Nestares, Jefa de Secc. Depedn (924 00 92 69), en relación a la priorización de revisión PIA de Eugenia, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-09-24','Ana: Llamo a Clara I. Gómez Nestares, Jefa de Secc. Depedn (924 00 92 69), en relación a la priorización de revisión PIA de Eugenia, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-09-23','Ana: Llamada de Paula, TO CRR-Plas.: comunica que finalmente Toñi no se irá al domicilio familiar estos días, como estaba previsto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-09-22','Ana: Llamada de Ana Benavente, TS ESM-Plas. (74955 // 927 458 036): pregunta si hay alguna novedad con Eugenia. Le informo de la conversación mantenida ayer con Gema. Estamos la espera de la priorización y revisión PIA para acceso a recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-09-22','Ana: Llamada de Ana Benavente, TS ESM-Plas. (74955 // 927 458 036): en consulta, tanto con ella como con el psiquiatra, ha demandado cambio de recurso a otro CRR, preferiblemente a Badajoz. *Le informo de la conversación mantenida con Paula-CRR la semana pasada. Estamos a la espera de que nos remitan informe. *Igualmente llamará al CRR ella también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2020-09-24','Ana: Envío correo a Amalia, TS CTAEX, en relación a la conversación mantenida el día 22 con Maribel, TS Secc. Discap.: "...En relación a Miguel Ortiz Gordillo, me dice que te comunique que ella, que como sabes conoce bien el caso, no quiere que se traslade, porque está muy bien en el centro. Considera que acercarse a su familia, motivo por el que hace la solicitud, es contraproducente para él. En su opinión deberíamos dejarlo como está. *De momento no he hecho nada con su solicitud. Tú dirás."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-09-24','Ana: En relación al correo con los informes, médio y de enfermería (éste último de la resi.) remitido por Sonia, Directora, llamo de Marisol, TS del HUC (927 25 68 23): le informo acerca de la conversación mantenida con Sonia, Directora, y de los informes recibido. **Hablará con la médica de Medicina Interna.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-09-24','Ana: Llamo a la oficina de la Habilitada Mª Isabel Latorre Revilla (91 547 53 40), me pasan con Miguel. *Se encargará él de hacer la comunicación del cambio de nº de cuenta bancaria de la pensión a la nueva cuenta que le facilito de Liberbank. Ya este mes no podrá ser, pero para octubre será efectivo el cambio. Nos enviarán certificado a la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-09-24','miguel, una vez recibido por email (me lo manda Alberto)las fotos e informe de la vivienda por futuex, llamo a la hermana de la interesada Eva Tejada 657224973 a quién comento los gastos que conlleva la venta y ella me comenta que además de la reforma, han invertido mucho dinero allí. Le explico que estamos muy interesados en llegar a un acuerdo, así que quedamos en que le envíe nuestra propuesta de precio a su email para hablarlo con su hermana que es la interesada en la compra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-24','Ana: Llamada de José Manuel (667 384 817), dice haber hablado con Alberto, Jefe Secc. Ecca., sobre la necesidad que tienen de comprarse un teléfono. Éste le ha dicho que lo hablará conmigo. Le recuerdo, una vez más, que se le autorizó la compra de un móvil hace pocos meses y jura que no va a cometer el mismo error, que esta vez NO LO VA A VENDER...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-09-24','Ana: Llmada de Juan José (667 958 878), dice que se le ha estropeado el móvil y necesita comprarse uno nuevo. Le indico que acuda a alguna tienda y nos envíe presupuestos (o bien desde la propia tienda o bien desde el piso supervisado), para que la secc. ecca. pueda valorarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-09-23','Ana: Correo de Toni- Futuex con notas de los días 21 y 22: "21/09/2020: Se contacta con Rosario enfermera del equipo de salud mental de Cáceres para coordinar la información sobre el tutelado, desde este equipo se transmite que finalmente acudió a la cita que tenía en salud mental el pasado viernes 18 de septiembre. Según cuenta la enfermera el desarrollo de la cita se basó en las quejas que tiene el tutelado sobre el tratamiento actual por vía inyectable, expresa su deseo de dejar esa medicación porque según explica no le sienta bien y se siente aturdido con ella. Ante la negativa de Saturnino, su psiquiatra decide cambiarle la pauta medica por medicación oral en su totalidad, dado que de lo contrario se temen que pueda dejar de acudir a las citas en su consulta. Se le trasmite a Rosario, la enfermera de referencia, la escasa conciencia de enfermedad y la falta de adherencia al tratamiento del tutelado para que se tenido en cuenta, desde este equipo se conoce esta situación por lo que se concia no obstante en su criterio profesional. 22/09/2020: Se intenta contactar con el tutelado sin éxito por lo que se realiza llamada telefónica su hermano, paco cuenta que ha sido informado de toda la situación a través de Rosario la enfermera, el considera que Nino no se tomará el tratamiento por vía oral de forma autónoma porque nunca lo ha hecho dada su escasa conciencia sobre su patología. Propone que intervenga la CTAEX a modo de contingencia económica puesto que considera que no hay otra forma de lograr un cambio de actitud si no es condicionando la cantidad de dinero que se le permite retirar de forma periódica o con cualquier otro refuerzo negativo relacionado con los bienes materiales. Por lo que propone que sea la propia la proa CTAEX quien le de un toque de atención con este condicionante ya que hace caso omiso a las recomendaciones que se dan desde otros ámbitos, Paco consideraría positivo esta contingencia por parte de una figura de autoridad como pueden ser los técnicos de la comisión tutelar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-09-24','Ana: Respuesta al coreo de ayer de Toni-Futuex: "...La verdad es que no entiendo que en el ESM accedan a su petición de cambiar el inyectable por medicación oral, aún conociendo su falta de conciencia de enfermedad y de adherencia al tratamiento. Tampoco entiendo muy bien la propuesta del hermano de que desde la CTAEX intervengamos “a modo de contingencia económica”, no tengo claro como implementar esta propuesta que hace, mientras él resida en su casa, no podemos controlar a diario si toma la mediación o no para ir “negociando” con “gratificación” o “restricciones” de tipo material o económico… La semana que vienen hablaré de ello con Pedro, Jefe de secc., a ver qué opina, o por si quisiera hablar con el ESM, pue entiendo que su llamada puede tener más fuerza que la mía. Pues, en mi opinión, sin ser especialista, claro, deberían de volver a administrársela inyectada. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2020-09-24','Ana: Envío correo a Paula y Blanca, CRR-Plas.: "...Ante la demanda de Carmen de apoyar económicamente a su madre e hijo en estas fechas, que me trasladó Ana Benavente, TS ESM, me confirman mis compañeras, que a día de hoy, al igual que el año pasado al inicio de curso, se ha hecho una transferencia de la misma cuantía (150 €) al mismo número de cuenta bancaria. Agradecería que se lo comunicaseis a Carmen, para su tranquilidad y para que pueda transmitírselo a su vez a su madre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-09-24','miguel, me confirma ayer la notaria de virgen de guadalupe de Cáceres(Iñigo) que la renuncia de herencia del padre del curatelado ya ha sido firmada. Hoy remito email a José Luis de la notaria de Romero Leal de Mérida para que me dé cita la próxima semana para su ratificación por la Ctaex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-09-24','Ana: correo de Chus-Directora PP.TT. Miajadas: (tierradebarrosserv.sociales@gmail.com): "buenos días: esteven se ha matriculado en 1 de la ESO, solo en el ámbito social, de momento. desde el centro de adultos se nos pide la autorización para fotos y publicarlas en la escuela de adultos, por si lo veis conveniente. las clases son tres días a la semana: lunes 3 horas por la tarde. jueves 2 horas por la tarde viernes 1 hora por la mañana. después de la clase del viernes acudirá al Centro Ocupacional. también os informo que Esteven inicio hoy el Centro Ocupacional y que hemos recibido una notificación de dicho recurso comentando que no le han pedido la comida en el día de hoy, por lo tanto Esteven ha venido sin comer a los pisos tutelados. se les informó ayer por la tarde de la incorporación de dicho usuario al centro. sin nada más que añadir. le saluda atentamente María Jesús Población" ···························································································································· Remito las autorizaciones a los compañeros Asesores Jurídicos. ·········································································································································· Respondo a Chus: "Buenas tardes Chus, Tomo nota de lo ocurrido hoy en el C.O. (el no haberle dado la comida…), la semana que viene que está Pedro, Jefe de sección trataré éste y otros asuntos con él. En cuanto a la matriculación en la ESO me parece perfecto, gracias por comunicárnoslo. Pr último, en relación a la autorización de derecho de imagen, se lo remito ahora a los compañeros jurídicos que son quienes tienen que valorarlo y en caso de ser necesario comunicarlo a fiscalía. Seguimos en contacto. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-09-24','miguel, conforme indicaciones, por teléfono del Jzdo nº4 de Badajoz, y al no valerles el fax que remitimos para la retirada del carne de conducir, preparo solicitud de incoación de procedimiento de jurisdicción voluntaria dirigido el Decanato de Badajoz y se lo remito por email a la parte económica para lo revisen y lo pongan a la firma y a dar registro de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='NOGALES'and apellido2='MATADOR'),'2020-09-25','TERESA INFOMRE VISITA FUTUEX Tras evaluar la información recogida y valorar lo observado en el primer seguimiento, se podría concluir que D. Manuel es una persona con buena competencia autónoma para su desenvolvimiento personal, que con supervisión y apoyo se podrían suplir los déficits y mejorar su desarrollo personal. Como se menciona anteriormente, se encarga de la gestión de su dinero sin control, hasta el momento no tiene una asignación acotada de dinero en efectivo para sus gastos, retirando de 300 a 400€ mensuales. Se destaca la buena disposición y colaboración ante el desarrollo del seguimiento, sin mostrar negativa a la hora de facilitarnos información y presentar documentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-09-25','Ana: Envío por CORREO CERTIFICADO la AUTORIZACIÓN general de SALIDAS al CAM Fco. Pizarro -Trujillo. ··············· Se lo adelanto escaneado por mail a las educadoras del CAM.','2');
