insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-09-24','Ana: correo de Damián, le han cambiado de habitación tras problemas con el anterior compañero. Se muestra agradecido por la ayuda que le han dispensado los monitores en la mudanza.','2');
