insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-09-25','Ana: Llamada de José Manuel (667 384 817): le indico que puesto que el teléfono que compró hace tres mese lo vendió, de momento no se le va autorizar para comprar otro. Además, de la retirada indebida de efectivo que hizo en verano, y que se acordó que lo repondría poco a poco en su cuenta, dándosele asignaciones menores, aún no ha devuelto nada, pues el banco no ha tenido en cuenta dicho escrito de la secc. ecca. y han seguido dándole 40€ todas las semanas...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-09-22','Ana: Correo de Toni-Futuex con nota de seguimiento y gestiones realizadas por Gloria tras fallecimiento del Padre de Catalina: "...Se acude al banco a realizar la retirada y ver si tiene algún pago vinculado a su cuenta, se comprueba que no, los gastos de la vivienda corren en la cuenta del padre, por el momento permanecerá así.", Solicita a la TS, Pilar Márquez, servicio de SAD (para apoyo, se pretende mantener y potenciar su autonomía) y ayudas para alimentos de Cruz Roja. *Contacta también con Caritas, le proporcionarán alimentos no perecederos y vales para canjear en tiendas de la localidad por pescado y carne. "...Se le propone, a la tutelada, llevar a cabo la realización de un menú, indicando comida y cena, con comidas de elaboración sencilla, para que pueda ir haciendo y hacer la compra acorde a lo señalado, se le acompañará los días que acuda la educadora; Catalina acepta.", "...Se contacta con el abogado de referencia de la familia, establece que el padre de Catalina cambió el testamento una semana antes de fallecer, de momento la tutelada puede permanecer en el domicilio, cree que así lo habrá dejado también el padre, pero hasta pasados 15 días no se procederá a la lectura del mismo, después ya se puede solicitar también el documento de últimas voluntades."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-09-25','Ana: Cominica que ha dejado la relación con su novia (otra compañera del CRR, con la que ha estado poco tiempo) y que está contento con el cambio de habitación. Pregunta de nuevo por el recurso de la valoración de dependencia. Se le indica que debe ser paciente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-09-25','Ana: Corro de Paula, TO CRR-Plas.(tocupacional.crrplasencia@grupo5.net) al ctutelar@: "Hola Ana, te envío los puntos que consideramos importantes valorar a la hora de decidir solicitar el traslado de Ceferino Mariscal a otro CRR, tal y como comentamos el otro día telefónicamente. De cualquier forma si determináis otra cosa no dudéis en comunicárnoslo." ······················· **No consideran propicio el cambio al CRR de Badajoz por distintos motivos, en todo caso a otro de otra localidad.····················································································································· *Guardo documento en su expte. ····································································································· Mi respuesta: "...Ok, muchas gracias Paula, tendremos en cuenta vuestro criterio, lo trataré con Pedro la semana que viene."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-09-25','Ana: Pongo para registro de salida Oficio adjuntando documentación relativa a la solicitud de Orfandad (Libro de familia)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-09-25','Ana: Con el visto bueno de Miguel, Asesor Jurídico CTAEX, cumplimento autorización de derechos de imagen del C.E.P.A. de Miajadas, recabo firma del D.Gerente y se lo adelanto por mail a Chus, Directora PP.TT. ······························································································································································ Llamo a Clara I. Gómez Nestares, jefa de secc. depend (68513 / 924 00 92 69) para solicitarle el Cdo. Dependencia, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-09-28','Ana: Llamada de Ana Benabente, TS ESM (74955): Hoy tiene cita con Ceferino. En relación a su demanda de cambio de recurso, le remito el informe que me enviaron el viernes desde el CRR y acordamos mantener el discurso en la misma línea: No se valora procedente el cambio a un recurso en el que no estuvo bien, el cambio a Plasencia le vino muy bien. *Si con el tiempo persiste su malestar y su demanda valoraremos el cambio a otro que no sea el de BA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-09-28','Ana: Envío correo a Paula, TO CRR-Plas.: "...En relación al correo que enviaste relativo a Toñi Bernardo Piris, confirmarte que hoy mismo las compañeras harán una transferencia bancaria de 300 € a su hija. En cuanto al cambio de recurso residencial al piso, si llega a implementarse (recuerda eso sí lo del informe), tenéis que comunicarnos también cuándo se hace efectivo el traslado, Alberto, Jefe de Secc. Económica, nos recuerda que debemos tener en cuenta las posibilidades económicas de Toñi: sus ingresos son una PNC de 395,60 x 14 (intentemos ahorrar las 2 pagas extras). Actualmente tiene autorizado un reintegro de 250 €/mes para gastos personales/bolsillo (como sabéis, mientras permanece en el CRR, no abona el recurso residencial) por lo que cuando pase a piso, habría que bajar SUSTANCIOSAMENTE la asignación y habría que replantearse las aportaciones a su hija. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-09-25','miguel, tras conversación telefónica con el juzgado nº2 Coria me confirman que les remita fax solicitud de videoconferencia. ************************************************ Envío fax de solicitud de videoconferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-09-25','miguel, tras comentar con Angel el expte vemos necesario contratar para su tramitación a un abogado. Habría que dirigirlo al Jzdo Decano de Plasencia e intentaré que se tramite en el mismo procedimiento de jurisdicción voluntaria tanto la aprobación de la herencia como la autorización para venta de todos los inmuebles. **********************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-09-28','miguel, contrato los servicios del abogado de Plasencia Jesús Bueno Clemente; tfno 927-422628, email:jesusbueno@buenoabogados.com ******************************************************* Me comenta que aproximadamente y teniendo en cuenta que prácticamente únicamente tendrá que tramitar lo que ya tengo hecho, aproximadamente el presupuesto pueden ser unos 500€+iva. ******************************************************** Dejo a la firma del gerente la Solicitud de aprobación de herencia y autorización de venta, y dejo en su carpeta para dar salida al oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2020-09-28','Ana: Correo de Soni Bernabé, TS y Directora Asindi: "Buenos días, ayer por la tarde Juan Gabriel Sobrino tuvo que ir nuevamente al hospital a Cáceres porque en el brazo cuya muñeca se fracturó, presentaba una herida en la parte superior del antebrazo que no se estaba curando muy al contrario parecía infectada. Cuando le atendieron le quitaron la escayola del brazo y comprobaron que tenía ampollas que le había salido además de la herida, los médicos indicaron al profesional que le acompañó que podía ser del sudor. Revisaron la colocación de la muñeca, le volvieron a escayolar abarcando menos parte del brazo para posibilitar que se curaran las ampollas y le hicieron la cura de la herida. Tiene cita de seguimiento para comprobar cómo ha quedado la fractura en unos 15 días y le curarán la herida y le harán seguimiento en el Centro de Salud del pueblo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2020-09-23','Ana: Correo de Felisa Custodio, TS del CAMF - Alcuescar: "Estimada Ana, adjunto solicitud de subvención por la adquisición de cojín para la silla de ducha que compró el pasado 23 de julio la residente. Faltaría cumplimentar vuestro NIF que no sé cual es. Ruego una vez firmadas las hojas pertinentes me lo devuelvas por correo postal para su tramitación. ..." ·························································································································· Respondo explicando que la CTAEX no tienen entidad jurídica propia y por tanto no tienen CIF. **Modifico los datos añadiendo al Representante Legal - Vicepresidente de la CTAEX. ······················· Se pone a la firma el documento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2020-09-24','Ana: Redacto y pongo para registro de salida, oficio para adjuntar solicitud de subvención del IMSERSO a Felisa Custodio - CAMF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-09-28','Ana: Recibo llamada de Julia (644 897 339), dice que ha engordado y necesita ropa. Pide 100 €. *Le indico que cuando Gloria, Futuex, envío presupuesto de gastos, nos indicó que tanto ella como su madre dijeron que 30€ mensuales eran para gastos de bolsillo y otros 200€ para manuntención, ropa y calzado. Dice que eso no era así, que los 200 € eran sólo para comida y gastos del domicilio. Le indico que en cualquier caso lo pasaré a la secc. ecca. para que lo valoren. ······································································································································· Paso nota a Alberto, Jefe de la secc. ecca. ······························· Finalmente, por esta vez, se le autorizarán 100€ extra para ropa.','2');
