insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-09-28','Ana: Llamada de Esther, Ed. Soc. CAM Trujillo (927 027 600): Se plantean que la salida de Aitor con su madre sea un poco más larga, entre 5-7 días. Consideran que al joven puede venirle muy bien, además si finalmente tuviera opción de ingreso en el centro nuevo de discapacidad de Castuera, una vez ingrese allí, las visitas familiares serán más complicadas dada la distancia. *Han hablado con la madre, Felisi, y ésta pide que lleve algo de dinero para aportar al gasto de comida. *Acordamos que se aprobarían 30€. *Cuando tengan todo organizado y sepan fecha exacta me avisarán. ································································································································································· Tras llamar de nuevo a Felisi y la pareja, éste último, Jesús, se queja del dinero que se ha propuesto, pide más de 100€. Dado el interés económico que manifiestan, han decidido volver a valorar la propuesta, de momento Aitor NO acudirá al domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2020-09-28','Ana: Correo de María, Aspace (maria.gonzalez@aspacecaceres.es): "...Adjunto remito solicitud de autorización para la vacunación de la gripe para Santiago Eduardo. Necesitaríamos que la devolviesen firmada si están de acuerdo. ... ············· Pongo la autorización para la firma del D.Gerente. ························ Envío a María, escaneada por mail, la autorización para la vacuna de la gripe debidamente firmada y sellada. *Dice que no es necesario que le remita el original.','2');
