insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-09-28','TERESA: LLAMO A BEATRIZ 641 28 55 60 SE ENCUENTRA BIEN MUY COHERENTE Y CONTENTA CON NOSOTROS, NOS PIDE SACAR DINERO QUE NO PUEDO SACAR POR ESTAR INGRESADA. ME COMENTA QUE ESTA EN LISTA DE ESPERA PARA UME ESTA CONVENCIDA PARA IR UNOS MESES. TENEMOS PENDIENTE EL ARREGLO DE LA PUERTA, LA DENUNCIA HA SIDO RETIRADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-09-28','Ana: Escribo a Alfredo, Residencia, para preguntar si les han comunicado algo con respecto al desplazamiento del Equipo Móvil de la policía nacional solictado para la renovación del DNI de Rosa. ································································································································· Respuesta de Alfredo (resiplase@gmail.com ): "Buenos días, Ana. Se pusieron en contacto conmigo hace dos semanas, para pedirme una foto y una fotocopia del DNI caducado, se las entregué personalmente al día siguiente y me dijeron que ya se pondrían en contacto conmigo. De momento no me han vuelto a llamar. Un saludo Alfredo Moreno."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2020-09-28','Ana: En relación a los documentos remitidos por la Casa Familiar Virgen de la Montaña de CC (Cruz Blanca), paso a Alberto, Jefe Secc. Ecca, el documento de "Deuda" generada en el centro debido a la subida de las pensiones. ··············· *Pongo para la firma del D.Gerente, el documentode Autorización anual de actividad. ···················· El resto de documentos, los revisaré con calma e iré dando respuesta.','2');
