insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2020-09-28','28/09/2020: MERCEDES QUIERE METER A UNA AUXILIAR DE AYUDA A DOMICILIO EN SU CASA. DESDE LA COMISIÓN TUTELAR SE ACEPTA QUE ELLA SEA LA QUE CONTRATE A UNA PERSONA PERO SE LE DEJA CLARO QUE TIENE QUE SER A TRAVÉS DE EMPRESA O BIEN QUE ESTÉ CONTRATADA DE FORMA LEGAL, SE LE DARÁ DE PRESUPUESTO 350 EUROS A MES VENCIDO. NOS COMUNICA QUE YA TIENE UNA PERSONA PARA ENCARGARSE DE LAS TAREAS DE LIMPEZA, ERIKA (636059075 O 642536017), SE LE LLAMA DESDE LA COMISIÓN Y SE LE DEJA TAMBIÉN CLARA NUESTRA POSTURA, TODOS LOS ACUERDOS A LOS QUE LLEGUE CON MERCEDES, LO TENDRÁ QUE VER CON ELLA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-09-29','TERESA ME COMENTA ANA EUDCADORA P.I. ZAFRA QUE MAÑANA VUELVE JOSEFA DE LA UHDAC. COMENTA QUE NO ESTAN DE ACUERDO CON SU VUELTA ALLI PORQUE VEN QUE ES UN PERFIL MAS DE SALUD MENTAL QUE DE DISCAPACIDAD, SUS ALTERACIONES FUERON MUY GRAVES Y NO CUENTAN CON MEDIOS DE CONTENCION ANTE SUS CRISIS ADEMAS DE QUE EXISTE MUY MALA RELACION CON OTRA RESIDENTE (NATALIA) TAMBIEN CON MUCHA PROBLEMATICA. ADEMAS COMENTA LA LEJANIA CON EL DOMICILIO DE SU HERMANO EL CUAL PASAN FINES DE SEMANAS JUNTOS LO CUAL A ELLA LE AGRADA MUCHO LE SUGIERO QUE PIDAN TRASLADO POR CERCANIA FAMILIAR, COMENTAR LO VAN A SOLICITAR A LA UNIDAD','2');
