insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-09-29','Ana: Llamada de Miguel Ángel, Direrctor del CRR-CC (687 487 908): Juan Marío, y dos residentes más, llevan una temporada saltándose las normas establecidas en el centro para la prevención del COVID-19, que a su vez siguen las recomendaciones de los Decretos. Rompieron una valla trasera del centro y se escapan por el hueco por las noches. Durante estas salidas no autorizadas, acudía a bares y consumían alcohol y otras sustancias estupefacintes, regresando al centro en estados de embriaguez o similar, faltando al respeto a monitores/as y compañeras/os. Arreglaron la valla una primera vez, pero volvieron a hacer un agujero. Como han vuelto a repararla una segunda vez, ahora se saltan por arriba. *El pasado domingo, día 27, al regresar al centro, tal era su estado que tuvieron que llamar al 112, quién le administró medicación, pues además él es diabético y había consumido mucho alcohol. **Carmen Ferrer, Secc. Salud Mental, ya está al tanto de la situación, ya han hablado del asunto en varias ocasiones. **Ayer tuvieron consulta con su Psiquiatra, Dra. Rubio, quién estableción y le dijo con claridad, que como se repitan estas conductas, le derivarán a la UHB y si fuera necesario a UME. Ayer estuvo más tranquilo y cumplió las normas. **Pero hoy han tenido una reunión al respecto en el centro (los otros 2 usuarios volvieron a escaparse) y Juan Mario se ha enfadado mucho pues "dice que quiere ser libre". **La Dra. Rubio les ha pedido que lo observen bien hoy y mañana, y si incumple alguna norma, que le llamen, ella misma activará el 112 para su internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2020-09-29','TERESA SE RECIBE FALLO REMOCION EN EL NOMBRE COMO TUTOR A SU PRIMA A PARTIR EL 24 DE SEPTBRE DISPONGO COMISIÓN TUTELAR DE ADULTOS DE LA JUNTA DE EXTREMADURA como tutor del incapaz SAUL RODRÍGUEZ RAMOS, y nombro como nuevo tutor del incapaz a su prima hermana, JUANA RODRÍGUEZ GARCÍA, previa aceptación por este del cargo que se le asigna.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2020-09-29','TERESA 924 70 32 92 TELEFONO DE LUISA SU MADRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-09-29','Ana: Tal y como acordé con Juana, secc. ecca., llamo a Control de Pensiones del INSS (927 620 065), allí no me lo pueden mirar pues le constan PNC (ellos no tienen acceso) y PFHC (al ser subsidio tampoco pueden verlo). ················································································································ Llamo a Antonio Ballesteros, Jefe Secc. PFHC (927 62 00 23): me informa que desde PF no les consta ningún pago desde finales de 2019. *El expte. de PF (por su hijo Aitor) está de baja desde 28 de febrero de 2020. Habrá que consultar en PNC. ····························································································································· Llamo a Javier Monago - PNC (927 00 43 42), no obtengo respuesta. ····· Llamo a su compañera Marta (927 00 52 27), tampoco obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-29','miguel, me comunica Alberto lo siguiente encuanto a la forma de afrontar la multa de Jairo: "Buenos días. En relación con el pago de los 10.570 € exigidos x el Jdo. de lo Penal nº 1 de Plasencia al tutelado D. JAIRO PUERTAS MARTÍN, se expone lo siguiente: • Saldo bancario a 29/09/2020: 3.047,81 € • Ingresos: PNC 395,60 x 14 = 461,53 €/mes. • Presupuesto gastos emitido x centro el 23/09/2020: 100 €/mes. • Coste Centro: 0 €/mes (se hace cargo Ministerio Interior?) • Seguro Deceso: 47 €/año = 4 €/mes • DIFERENCIA INGRESOS-GASTOS: 461,53-100-4= 357,53 €/mes Dispondríamos por tanto de una máximo de 357,53 €/mes para abonar el pago del dinero exigido por el juzgado. En mi opinión, se podría afrontar esto de la siguiente manera: • Hacer un pago inicial con el saldo del que dispone a día de hoy de un importe que no supere los 3.000 €. Entiendo que 2.700 € sería razonable. • Abonar mensualmente un importe máximo de 300 €/mes. Esto nos permitiría ahorrar unos 57 € aproximadamente al mes para posibles imprevistos. Ficción pago: Deuda inicial: 10.570 € Pago inicial: 2.700 € Resto: 7.870 € Pagos mensuales: 26 pagos mensuales de 300 € y 1 pago final de 70 €. Comienzo pago: 1 noviembre 2020 Fin pago: 1 enero 2023 Observaciones: comunicación a centro de imposibilidad de asumir cualquier tipo de gasto, salvo extrema necesidad y siempre previa autorización CTAEX". ***********************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-09-30','miguel, conforme al email que me envió ayer Alberto, notifico al Jzdo nº1 de Plasencia, vía fax, lo siguiente: " Estimado/a Sr./Sra.: En relación con nuestra tutelado, D. Jairo Puertas Martin, se comunica a este juzgado lo siguiente: 1.-Que por Diligencia de notificación y requerimiento se nos ha comunicado ala condena por delito de lesiones en el procedimiento arriba indicado a los efectos de aplicar la pena condenatoria de las cuales se hace saber a este Juzgado a los efectos oportunos que las dos primeras (medida de internamiento y de alejamiento las cumplirá en el Centro Socio Sanitario donde ya se encuentra). En cuanto a la tercera medida consistente en el pago de los 10.570 € exigidos su Juzgado al tutelado D. JAIRO PUERTAS MARTÍN, se expone lo siguiente: • Saldo bancario a 29/09/2020: 3.047,81 € • Ingresos: PNC 395,60 x 14 = 461,53 €/mes. • Presupuesto gastos emitido x centro el 23/09/2020: 100 €/mes. • Coste Centro: 0 €/mes (se hace cargo Ministerio Interior?) • Seguro Deceso: 47 €/año = 4 €/mes • DIFERENCIA INGRESOS-GASTOS: 461,53-100-4= 357,53 €/mes Dispondríamos por tanto de una máximo de 357,53 €/mes para abonar el pago del dinero exigido por el juzgado. Desde la Comisión Tutelar de Adultos se propone al Juzgado que se podría afrontar esto de la siguiente manera: • Hacer un pago inicial de 2.700 €. • Abonar mensualmente un importe máximo de 300 €/mes, con lo que quedan 57€/mensuales para imprevistos. Por tanto, la fijación del pago es de la siguiente manera: Deuda inicial: 10.570 € Pago inicial: 2.700 € Resto: 7.870 € Pagos mensuales: 26 pagos mensuales de 300 € y 1 pago final de 70 €. Comienzo pago: 1 noviembre 2020 Fin pago: 1 enero 2023 Solicitamos al Juzgado sea aceptado este escrito de propuesta y nos comuniquen su aceptación". ***************************************** Asimismo, conforme a las indicaciones de la parte económica, envío a Rosa del CSS el siguiente email: "Buenos días, tras comprobar con la parte económica de la Comisión Tutelar de Adultos la capacidad económica de Jairo tras afrontar mensualmente el pago de la multa de la resolución judicial del Jzdo de lo Penal nº1 Plasencia, del procedimiento PA Procedimiento Abreviado 95/2020, que la capacidad de mensual de Jairo quedará en unos 57€, y que por tanto en caso de existir cualquier pago no previsto habréis primero de consultar con la parte económica de esta Comisión a los efectos de ver de si es posible dicho pago. Por parte de la Comisión en el día de hoy vía fax vamos a hacer propuesta del pago de dicha multa desde el 1-11-2020 hasta 1-1-2023 en 27 pagos más lo que tiene ahorrado. Para cualquier duda podéis hablar directamente con la parte económica".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-09-28','miguel, tras conversación con la interesada en la compra Beatriz Beatriz Tejeda >beatriz@atica-aparejadores.com>, y aceptación por nosotros de las condiciones por vía telefónica, me remite el siguiente email: "Buenos días Miguel, tal y como hemos comentado estoy dispuesta a subir la oferta hasta 57.000 € que sería según conversación el precio definitivo de la venta. Te paso mis datos para empezar a mover el tema de la notaría: Beatriz Tejeda Ramos DNI: 44407823k Teléfono: 675937218 Correo electrónico:beatriz@atica-aparejadores.com Si que me gustaría tener la nota simple actualizada del piso con antelación. Y que todos los temas que comentabas: -Comunidad de Propietarios: derrama de 900€ -Plusvalía: mínimo serán 2.000€ -Gastos estimados según Ley de notaria: 600€ -Levantamiento de la hipoteca que hay sobre la vivienda; carga económica pendiente de concretar, y la carga registral aproximadamente 600€. Queden resueltos a poder ser antes de la firma para no tener ningún problema a posteriori. Este es mi correo para lo que queráis que comentemos. Organizar la firma a ver si se puede para el 9 o 12 de octubre." ***************************************************** Comunico a Alberto las condiciones que son aceptadas, y éste encarga a Pedro hablar con el curatelado para comunicarle la venta y que intentaremos firmar para el 9 de octubre aproximadamente, en la notaria de plasencia. *********************************************** Alberto remite a Juana para cuando lo tenga me remita con respecto a la venta del inmueble del curatelado el siguiente email:"Se va a proceder a la venta de la vivienda de JOSE PEDRO VILLEGAS SERRANO, en C/ Sor Valentina Mirón, 3, 2ºB - Plasencia x 57.000 €. La vente se establece para el día 09/10/2020. Área social se encarga de preparar al curatelado. Miguel, que lleva la negociación, nos pide la siguiente documentación. Es URGENTE su obtención: • Banco Santander: certificado deuda pendiente del préstamos con denominaciónn "Hip.Adquisicion vivienda s.Vinculacion" con nº de contrato 0049 1594 103 0000087, en el que figuren las fincas gravadas por el mismo. Son: o Vivienda C/ Sor Valentina Mirón, 3 - 2ªA Plasencia (según registro propiedad Plasencia, finca nº 17530, Paraje Berrocal, 2ºB). Ref. Catastro: 8256007QE4385E0017WL o Vivienda C/ Zapatería, 38, 2º A Plasencia (según registro propiedad Plasencia, finca nº 14489, letra "C" según registro). Ref. Catastro: 8253776QE4385C0005QG • Comunidad de Propietarios: certificado de estar al corriente: 927-411330 / 649-145165 Mary: Pagamos x años completos 230 €/año. Último pago 07/05/2020. • IBI: Último recibo de IBI. Ayuntamiento de Plasencia? • Ayuntamiento Plasencia: certificado CALLEJERO del Ayunamiento de Plasencia indicando que la actual C/ Sor Valentina Mirón, 3 antes se denominaba, Paraje Berrocal, nº 10".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-09-30','miguel, remito nota simple a la compradora y los datos de contacto de la notaria para que le envíe sus datos, dni.. Y me pongo en contacto con la notaria de plasencia para ir preparando la venta a la cual la remito a parte de la sentencia de nombramiento y aceptación de cargo, nota simple, certificado de calllejero y certificado de deuda del SCH. ************************************************* Y a la parte económica les envío el siguiente email: Hola, a parte del IBI (no tiene que ser original) necesito originales de: 1.-Certificado energético (entiendo que debería estar porque sin ello no se puede alquilar, y lo ha estado…) 2.-certificado de estar al corriente de la comunidad de vecinos (para incorporarlo a la escritura de compraventa) 3.-Certificado original de deuda pendiente del Santander (para incorporarlo también a la escritura) Ya he remitido esta mañana a la notaria sentencias de nombramiento y aceptación de cargo, junto a nota simple (antigua de 2018), certificado del callejero, y certificado de deuda del SCH. Los datos de la notaria para cualquier duda son: notaria de Plasencia Fco Asis Jimenez Velasco 927-427147, persona de contacto Francisco con email fcanadas@despacho.notariado.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2020-09-30','Ana: Correo de Sonia Bernabé - TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, me dicen las compañeras que Juan Gabriel está mejor, le están curando la herida que tenía y las ampollas que ahora están fuera de la escayola. Se le cura en ASINDI y cada pocos días lo verá en el Centro de Salud para ver cómo evoluciona. Te comento, hablé con la persona que hizo el acompañamiento y son 10 € por hora. Serán 40 €, si hubiera quedado ingresado o hubieran sido muchas horas en urgencias hubiera ajustado el precio. Lo tendremos en cuenta si hay una próxima vez, aunque esperemos que no haga falta. Pero esta vez al responder rápido para ir y cubrir parte de la tarde noche lo hemos dejado así. Les pasaré el documento en cuanto nos haya firmado como que ha cobrado, porque tiene dinero de sobra en su fondo a los que llevan la parte económica. Un saludo"','2');
