insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-09-29','TERESA MANDO CORREO A TONI FUTUEX Y A LUISA SSB PARA PREGUNTAR POR LA PRESTACION DE GUILLERMO YA QUE HAY QUE RENOVARLA ME CONTESTA LUISA Buenos días Teresa, tranquila, al parecer está todo bajo control, la policía municipal, encargada antes del asunto, lo puso en conocimiento de Gloria del equipo psicosocial asignado al caso, y tras recibir tu correo ayer se lo recordé para mayor seguridad. Realizan la gestión telemáticamente. Si, esperemos que no tarde el ingreso, demasiada espera ya.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-09-29','TERESA SE RECIBE LA FIRMEZA DEL AUTO DE INGRESO INVOLUNTARIO HABLO CON MAITE DISCAPACICAD PARA EL TEMA DE LA PLAZA, ME COMENTA QUE EN ZAFRA ESTA LA SEGUNDA QUE LO VA A COMENTAR CON MANUELA Y QUE LE VUELVA A PREGUNTAR LA SEMANA QUE VIENE HABLO CON ANA TS P.I. ZAFRA PARA COMENTARLE LA SITUACION, ELLA COMENTA QUE NO VA A QUERER SEPARARSE DE LA TITA, QUE VA A SER COMPLICADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-09-29','TERESA HABLO CON ANA EDUCADORA DE P.I. ZAFRA Y ME COMENTA QUE NATALIA SIGUE MAS O MENOS IGUAL SIN CONTACTO CON LA ABUELA NO SABEN NADA DE ELLA, HACE ALGUNAS LLAMADAS AL ABUELO JOAQUIN. ESTAN A LA ESPERA DE QUE LE RESPONDAN DEL CAMBIO DE CENTRO QUE SE PIDIO POR PIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-09-30','Ana: Llamo a Javier Monago - PNC (927 00 43 42), no obtengo respuesta. ····· Llamo a su compañera Marta (927 00 52 27), tampoco obtengo respuesta. Llamo a un tercer número: 927 00 43 81, tampoco responden. Llamo a Mérida a Marina Carmen Cintas, Jefa de secc. (924 00 59 22), sin éxito. ················ Finalmente envío un correo electrónico efectuando la consulta a Javier Monago, Jefe de secc. (javier.monago@salud-juntaex.es). ················ Respuesta: "hola, pues creo que no te voy a poder resolver la incógnita. Esta señora está percibiendo una pnc y los abonos que se le hacen son de 395.60€ según consta en el programa. Habal con Adela Molina por si se hubiera hecho algún abona y no esté reflejado en el programa. Telf de Adela es 924005995 y el email adela.molina@salud-juntaex.es Siento no haberte podido ayudar. Saludos Fco. Javier Monago Lozano" ··························· Llamo a Adela, pero no obtengo respuesta. ···· Le escribo un correo-e haciéndole la consulta. ············ Respuesta: "Buenas tardes, Esta señora tiene una pensión no contributiva por importe de 395,60 €, y es lo que consta en la nómina del mes de agosto, así como en el resto de meses. En el caso de que se hubiese realizado un pago de más o se hubiese minorado el importe de la pensión, se hubiese notificado. Con lo cual siento no poder ayudarte, de pensión no contributiva no es. Un saludo" ·························· Comunico a Juana, secc. ecca. CTAEX, las averiguaciones raelizadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-09-30','miguel, a través del CSS Mª Victoria Clemente llega requerimiento del Ayto de Plasencia para se proceda con urgencia a la reparación de los daños que presenta la vivienda de calle General Margallo,para lo cual dan 4 meses, caso contrario embargarán. Se lo paso vía email a Alberto para que la parte económica vea qué tiene hecho al respecto(parece ser que su presidenta Inés Mª Talavera Pacheco lo ha reclamado varias veces anteriormente)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2020-09-16','Ana: Pilar Cerrillo, TS de la Res. Virgen de la Montaña, me comunica mediante conversación telefónica, que yua han remitido, por correo ordinario, el informe que le pidió Pedro, Jefe de secc., en relación a la sobrina de Isidora. Actualmente está acudiendo 2 veces en semana a visitarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-09-15','Ana: Llamada de Clara, TS C.Salud Guadalupe (927 150 253): Juan ha acudido finalmente a la cita de enfermería a ponerse el inyectable, pero en otro horario diferente al indicado y con malas formas. Montse, la Enfermera se queja de esta situación que se repite mes a mes. **Le insisto a Clara que lo refleje en un informe o que anote en Jara las distintas incidencias cada vez que ocurran. Al parecer no está dispuesta a ponerlo por escrito...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-09-14','Ana: Llamada de Clara, TS C.S.: Juan tiene cita mañana a las 9:00 con la enfermera para ponerse el inyectable. ········ *Pido a Futuex que se lo recuerden y estén pendiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-09-16','Ana: Juana, Secc. Ecca. me comunica que ha recibido llamada de la Directora del C.O. de Miajadas (687 820 329), quejándose porque Esteve no está acudiendo al centro a pesar de que ellos están cumpliendo con todas las normas y recomendaciones relativas a la prevención del Covid. ···························· *Llamaré a la responsable de los PP.TT.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-09-14','Ana: Recibo llamada de Ceferino (641 881 543), comunica que ha hablado con Carmen Ferrer, Secc. Salud Mental, y ésta le ha dicho que no hay permutas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-09-30','miguel, tengo de hace unos días (no lo había visto) demanda en papel solicitando modificación de capacidad e internamiento involuntarioa y siendo parte demandada la CTAEX. Los documentos están fechados de 14-9-20. Hablo con Jzdo nº2 Montijo quién no me sabe decir cuándo lo hemos recibido.Se nos da 20 días hábiles para contestar y parece ser no han dado traslado a abogacía general. Lo escaneo y envío por email a secretaría general y Mª Guerrero para su remisión a abogacía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-09-11','Ana: Llamada de Ceferino (641 881 543) da las gracias por el ordenador y todas la cosas que se le han autorizado, pero añade "no me hago a este CRR y no me dejan cambiarme". Cuenta también que ayer ser despertó tarde de la siesta y tiraron la cena delante suya a la basura". Pide que hablemos con Javier, director CRR para que solicitemos una permuta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-09-10','Ana: Llamada de Damián, dice estar muy contento porque se ha "echado novia", una compañera del CRR. Ayer tuvo cita con Ana Benavente. Tiene una Psiquiatra nueva, Mª José. Le va a hacer un informe para dárselo a Ana Benavente, TS. Además le ha ajustado la medicación. Cuenta también que en el centro tiene un compañero nuevo de habitación que lleva poco tiempo allí, así que él le está apoyando mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-09-17','Ana: Conversación con Paula TO CRR-Plas. (682 704 401): En relación a la demanda que hace de nuevo Ceferino de cambio de recurso, Paula expresa que Ceferino cada vez aque comete algún error tiende a pedir irse. Ella no ve positivo para él el cambio que solicita. **Pido que nos remita un breve informe acerca de la conveniencia o no del cambio del CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-09-18','Ana: Convesación con Paula, TO CRR-Plas. (682 704 401): Conchi actualmente se muestra ambivalente con respecto a la venta de la vivienda, pero también es cierto que el mes de septiembre resulta muy duro para ella, es el mes que falleció su hijo. *Si finalmente sale del recurso residencia, necesitará apoyos. *Despues avisa a Conchi para que hable con ella, me facilita el nº de su hermano Anotnio (606 88 34 44) y dice que la casa necesitaría unas mejoras como pintar y poner una barandilla en la terraza. ··························································································································· Envío a Ángel y Miguel, Asesores Jurídicos CTAEX, el contacto del hermano de Conchi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2020-10-01','CORREO Se pone al correo el convenio para realizar prácticas de veterinaria. Se reminte a P. I. Montijo.','2');
