insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-09-30','miguel, remito al Jzdo Decano de Badajoz solicitud de retirada del carne de conducir del curatelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-09-30','miguel, nos notifican via fax del jzdo nº3 de Plasencia juicio por lesiones donde el denunciante es este tutelado y denunciado José Mª Vicho. Remito fax solicitando videoconferencia para el 6-10-20, y pido a Ana que les acompañe alguien por separado el día de la citación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-10-01','Ana: Correo de Miguel Ángel, Director del CRR (residenciadir@feafescaceres.com) de ayer tarde: "Buenas tardes, después de la llamada telefónica por parte de los/as monitores/as rehabilitadores/as que están en turno de tarde y ser informado se especifica y se decide que no se haga nada en dicho turno con respecto a la salida no autorizada de Juan Mario siendo el Director Técnico en calidad de psicólogo de referencia de este quien se pondrá en contacto mañana con la Dr. Rubio para comentarle las ultimas incidencias y que sea esta quien se coordine con sus compañeros de la UHB y plantee el ingreso tal cual nos plantea la Doctora en el día de ayer." ····················· Mi respuesta: "Buenos días Miguel Ángel, Gracias por la información, es una pena que el aviso transmitido en la reunión no haya servido de nada, en cuanto a la actitud y acciones de Juan Mario me refiero. Por favor, informarnos de la decisión de la Psiquiatra y si finalmente procede al ingreso, que tras habérselo dicho a él mismo, espero que así sea. Un saludo. PD: Pongo en copia al Jefe de Secc. para que esté al corriente." ·································································································································· Nuevo correo del Director del CRR: "Buenos días, os informo que se han realizado tres llamadas telefónicas a la Dr. Rubio (psiquiatra de referencia de Juan Mario) para exponerle e informarle sobre la situación vivida durante la tarde de ayer sin obtener respuesta, en cuanto pueda comunicarme con la misma os indicaré cuales son las medidas que hay que adoptar." ·········································································································································· Nuevo correo del Director del CRR-CC: "Buenos días, os informo sobre las últimas incidencias referidas a Juan Mario San Román Blasco, desde que se pusieran en práctica las franjas horarias de 1,5h de salidas terapéuticas Juan Mario no deja de presentar repetidas escapadas del Recurso en horarios no autorizados por la Dirección del Centro con las consecuentes alteraciones conductuales por haber consumido tanto bebidas alcohólicas como sustancias tóxicas que le producen no tener consciencia del problema que realmente existe con respecto a la COVID-19 y mucho menos de la realidad. Cada vez que se ha intentado hacerle ver que el salir sin poner en práctica las medidas preventivas (no podemos asegurar con que personas se relaciona cuando está fuera del recurso en horarios no autorizados) le supone no solamente un riesgo para su salud (presenta problemas de diabetes aguda con grandes descompensaciones en los niveles de glucosa) sino para el resto de personas que están en el recurso con él que presentan patologías de salud hace caso omiso y solamente importándole su libertad encontrándose en el momento actual en una situación de desestabilización a nivel psicopatológica. Estamos en contacto diario con su psiquiatra de referencia para informarle de la situación en la cual se encuentra Juan Mario y nos ha dado una serie de pautas para poder intervenir cuando presente dichas alteraciones conductuales, el principal problema es que no solamente presenta problemas de conducta sino que lo que realmente nos preocupa es que es un peligro de salud pública tanto para el mismo como para los demás usuarios/as que están en el recurso y con las personas con las que mantiene contacto estrecho (profesionales de la Entidad). Hace unos minutos nos informa la Dr. Rubio que hay ponerse en contacto con su médico de cabecera para que le haga una valoración ( ella ya ha informado a la UHB y ha emitido informe para que sea efectivo dicho ingreso) y la consiguiente derivación a la UHB y desde allí se le deriva a UME debido a que es un problema de salud pública, os seguiremos manteniendo informadas. Un cordial saludo." ·················································································································································· Nuevo correo del Director del CRR-CC: "Buenas tardes os informo que se ha procedido a realizar una valoración y revisión de Juan Mario San Román Blasco en la UHB para posible ingreso en la UME por desestabilización psicopatológica, no os puedo dar más información porque desde la Entidad no disponen de más información en cuanto me comuniquen si lo derivan a la UME o lo dejan en la UHB os informaré. Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-09-30','miguel, me llama de notaria de Romero Leal (José Luis) y me comenta que no se puede firmar la ratificación de la herencia porque tenemos que pedir autorización judicial y certificado de nacimiento al registro civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-09-30','Ana: Correo de Miguel, Asesor Jurídico CTAEX: "...nos ha llegado hoy por fax, que han citado a Jose Luis Murillo Horrillo (día 6-10-20 a 12h) como denunciante de posibles lesiones y denunciado a Jose Mª Vicho (día 6-10-20 a 12,30h). Yo he pedido videoconferencia. Tienes que hablar con alguien del centro para que acompañen a cada uno por separado. Buena tarde!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-10-01','miguel, solicito a Rafael, por email, que pida y me envie certificado de nacimiento de su hermano. Envío de nuevo a José Luis que hable con el Notario Don Gonzalo y le diga que es una curatela y que en la sentencia no habla que necesite autorización judicial conforme el artículo 271CC, y que como le remitimos testimonios de sentencia tampoco tendría que pedir certificado de nacimiento(no obstante pido a Rafael, hermano del tutelado que lo pida él para agilizar)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-10-01','Ana: Envío correo a Rosa, CSS-Plas.: "Buenos días Rosa, Me pide mi compañero Miguel, Asesor Jurídico, que os solicite acompañamiento al Juzgado para los siguiente tutelados: Jose Luis murillo Horrillo y Jose María Vicho Alfonso. El primero citado el día 6-10-20 a 12h como denunciante de posibles lesiones y el segundo como denunciado el mismo día 6-10-20 a 12,30h. Pide que acompañen a cada uno por separado. Él ha solicitado asistir al juicio por videoconferencia desde el Jdo. de Mérida. Ya nos confirmáis cuando podáis. Gracias y buen día"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-10-01','Ana: Envío correo a Rosa, CSS-Plas.: "Buenos días Rosa, Me pide mi compañero Miguel, Asesor Jurídico, que os solicite acompañamiento al Juzgado para los siguiente tutelados: Jose Luis murillo Horrillo y Jose María Vicho Alfonso. El primero citado el día 6-10-20 a 12h como denunciante de posibles lesiones y el segundo como denunciado el mismo día 6-10-20 a 12,30h. Pide que acompañen a cada uno por separado. Él ha solicitado asistir al juicio por videoconferencia desde el Jdo. de Mérida. Ya nos confirmáis cuando podáis. Gracias y buen día"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-09-21','miguel, llega demanda del Juzgado donde la familia solicitan ampliación de incapacidad e internamiento involuntario (veo la documentación y confirmo que llegó este día con Juan Pedro el día 1-10-20. Remito a Mª Guerrero para lo remita a abogacía el 1-10-20','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-10-01','miguel, remito email a la parte económica solicitando pidan certificado de nacimiento del registro civil además de lo pendiente en llegar. Así mismo les informo de los posibles problemas para firmar la venta y de mis gestiones hoy mismo con ambas notarias (plasencia, la de la venta y mérida la de la ratificación): "Hola compañeros, no nos vale el recibí Juana, cuando te llegue el certificado envíamelo. Comentaros que tenemos dos problemas (a ver si podemos resolverlos) 1.-Certificado Energético: me confirmó Beatriz, vía email ayer por la tarde que no lo tiene. La he puesto esta mañana un email para que me diga si puede hacerlo ella (la he pedido que me conteste hoy mismo). Si a la 13,30h no recibo ninguna contestación lo solicitaré…aunque no veo ningún tasador salvo tinsa, certicalia, arquart (que me da que son empresas nacionales). Sí hay una inmobiliaria que hace esta gestión: INMOBILIARIA PERIAÑEZ 927412610 662579605 ***Si se os ocurre alguna idea decídmelo**** 2.-OJO!! Muy importante, tengo un problema para la venta…Como sabéis para las curatelas no hace falta autorización para vender (nunca lo hacemos), no obstante veo en su sentencia que hace mención a la sujeción al artículo 271CC, lo cual supone que sí habría que pedirla. Os comento esto porque la notaria de Romero Leal (Mérida) donde normalmente firmamos las ratificaciones (herencias, ventas…), me ha puesto ya problemas para una ratificación de renuncia de herencia para otra curatela ayer (Félix Figueroa) y me han pedido tanto la autorización de venta como el certificado de nacimiento del registro civil (para comprobar si la última inscripción de cargo de curador sigue siendo la nuestra…) Entonces yo previendo que pueda sucedernos lo mismo para esta venta de Villegas, he mandado esta mañana a José Luis (notaria de romero leal de Mérida) las sentencias de incapacitación, nombramiento y aceptación de cargo de la Ctaex, para que la vea con D. Gonzalo Pugnaire (que es el notario que siempre ve lo de la Ctaex), y estoy a la espera de contestación(le he dicho que la idea es firmar el día 9(la compradora insiste ese día que es cuando bajará a Plasencia). Le he indicado que ese día firmará el curatelado en notaria de Plasencia y nosotros ratificaríamos esa misma mañana en notaria de romero leal (el porque, es sencillamente porque en las notarias de fuera de Mérida no reconocen la legitimación de firmas de las autorizaciones que nos hace nuestro Gerente, José Vicente, para firmar en su nombre. No obstante he hecho la doble jugada (por si cuela), he mandado paralelamente también las sentencias del curatelado y los datos que tenéis en vuestra carpeta acreditación bancaria (dni José Vicente, nombramiento, y mantenimiento de competencias) a la notaria donde ser firmará la venta de Plasencia, para que si me autorizan firmaría yo directamente allí con el curatelado ese mismo día… Como veis todo pende de un hilo, por lo que a ver que contesta cada notaria. No obstante para asegurarnos al menos de que nuestra inscripción en registro civil sigue vigente, necesito que pidáis urgentemente al Registro Civil (no sé si el de Plasencia o donde) Certificado de Nacimiento del curatelado, que tendrá que llegar antes del día 9. Cualquier duda decidme. ****Por otra parte, y aunque Alberto y yo hablamos el otro día con Pedro para que explicara al curatelado José Pedro lo de la venta y alguien le acompañara a la firma…Viendo que es posible que se alargue su regreso, he enviado email a Ana para que se encargue de comunicarlo al curatelado y alguien le acompañe a la firma.*****"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2020-10-01','miguel, llega citación para vista procedimiento OTRAS MATERIAS, TUTELA (ant. LJV 15/15)347/2001. Llamo sin éxito al juzgado para informe de este procedimiento','2');
