insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-10-01','Ana: A petición de Miguel, Asesor Jurídico, llamo a Raquel, Hogar de Nazaret (927 416 563) y comunico que el día 9/10/2020 José Pedro tendrá que acudir, a la Notaría a firmar la venta de la vivienda de la C/Sor Valentina Mirón. La hora está pendiente de confirmar. *Lo comunicará a la dirección del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ROMERO'and apellido2='VERA'),'2020-10-01','TERESA ENVIO A PNC CERTIFICADO DE RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-10-01','Ana: Tras recibir llamada de Toñi, envío correo a Miguel, Asesor Jurídico CTAEX: "...He recibido llamada de Mª Antonia Bernardo (615 619 857), dice que llama por la reclamación de responsabilidades patrimoniales y el abogado que le habéis solicitado, pide que le llaméis. Como Ángel no está, por eso te lo envío a ti." ********************************************************** miguel, remito email a Angel que está llevando el asunto para que el martes que vendrá se ponga a ello','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-10-01','Ana: Llamada de Ana Benabente, TS ESM (74955): en relación a la consulta del otro día con Ceferino, explica que éste se quedón conforme con el hecho de que a Badajoz no le conviene ir. *Le dijo que entonces pedirá el cambio a CC, pues además él es de allí. Ana le dijo que ya valorará, que tenga paciencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2020-10-01','Ana: Llamada de Ana Benabente, TS ESM (927 458 036 / 74955): me comunica que ha consultado en SIDEX, a Félix le valoraron en 2007 y en 2010 SIN GRADO. Pero desde Octubre de 2018 está pendiente de nueva valoración, ya son 2 años y está parada. Dado que ya tiene 61 años, quiere que le valoren para poder optar a plaza en PP.TT. de mayores llegado el momento que tenga que salir del CRR. **Ha llamado a Dependencia y le hen dicho que envíe un escrito para re-activar la solicitud. *Así lo hará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-10-01','Ana: Llamada de Ana Benabente, TS ESM (74955): pregunta si hay alguna novedad en relacón a Eugenia, le informo de los intentos de contacto con Clara, Jefa de secc. depend. sin éxito. *Por su parte, me informa de que le llamó la Psiquiatra y le ha ajustado el tratamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2020-10-01','miguel, a petición del curatelado, pido y me enviarán desde la notaria de Valdepasillas copia simple de Rafa Santos Gómez. En cuanto me llegue al email ctutelar, reenviar a su email para su declaración de renta del próximo año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-10-01','miguel, preparo el oficio al registro civil de Jaen, para solicitar el certificado de nacimiento y dejo en registro de salida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2020-09-09','Ana: Recibo llamada de Mª Eugenia (633 578 274), no puede hablar con Teresa. Le informo que ésta no estará en un par de semanas. *Me cuenta que como ha podido ir unos días "de permiso" al pueblo, ha podido estar con su familia y con su compañero, así que se encuentra mejor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-08-24','Ana: Llmada de Jesús Manuel: Pregunta quién ha contratado un seguro de decesos sin su permiso. Le explico que la CTAEX no necesita su permiso puesto que está tutelado por ella. Además se les contrata a todos las personas tuteladas pues llegado el momento es mejor tenerlo. ····· A parte, dice que los Psiquiatras tienen sobornado a su padre... ····· Por último, como es habitual en él, comienza a plantear múltiples demandas; cambio de vivienda, material para la escuela de música, botella de butano, dentista, dinero para asistir al funeral de un primo...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-09-09','Ana: Llamada de Carmen Ferrer; me comunica que aún no se ha procedido al ingreso de Manuel en el piso de Proines. Pilar Lavadiño, responsable del piso le llamó el día 4, pero el teléfono estaba apagado. Volverán a llamar mañana o el viernes. *Me informa de que, debido a la situación de crisis sanitaria, en el CEDEX no están haciendo los controles a menos que haya una resolución judicial para ello. Por tanto desde el piso plantean hacerle el control en la propia asociación comprando las tiras reactivas en la farmacia. *Ni a Carmen ni a mí nos parece mal esta alternativa siempre y cuando se preserve su derecho a la intimidad y confidencialidad. *Acordamos que hablaré con Pilar para organizarlo todo. ····································································································································· Conversación con Pilar Lavadiño, responsable Piso supervisado PROINES (924 80 50 77): Conoce a Manuel, de cuando trabajó en los pisos de Zafra, en que él también estuvo una temporada. Como necesitan hacer una entrevista previa al ingreso, acordamos que se realizará de forma telefónica y para que haya alguién presente, que además puedan ayudar a aclarar dudas a Manuel, acudirá una delegada de Futuex, el viernes a las 10:30 h. Ésta llamará a Pilar 5-10 min. antes de entrar en el domicilio de Manuel. *Yo llamaré al C.Salud para que hagan la PCR a Manuel a ser posible martes o jueves siguiente y así pueda ingresar en el piso el miércoles o vienes de la próxima semana, que es cuando está allí Pilar. ································································································································· Coordino con Toni-Futuex este acompañamiento puntual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-09-14','Ana: Recibo llamada a última hora de Amelia, Empresa Serv. del Fresno. La auxiliar habitual, Quini, ha cogido vacaciones, la sustituta (Mª del Carmen Álvarez Rguez) ha acudido al domicilio de Manuela, como no había nadie, has esperado más de 15 minutos en la puerta. *Cuando han llamado a José Manuel, nieto y cuidador habitual de Manuela, éste le ha dicho que están fuera por asuntos personales, que ya le avisará cuando regrese... Amelia me pide discreción a la hora de decirle algo a él, pues no quiere tener problemas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-10-02','TERSA EMAIL DE ANA EDUCADORA DE PLENA INCLUSION ZAFRA El problema de Juana siempre han sido sus adiciones a las compras y “el enganche” y uso y manejo del móvil. Estuvo un periodo muy largo sin móvil y hace como un año finalmente se le compró uno de tarjeta prepago y con cierta supervisión parece que el tema iba bien. Pues bien, hemos descubierto en primer lugar que tenía un teléfono móvil de gama media alta nuevo (porque quería fundas nuevas para ese móvil ) y al preguntarle decía que se lo ha regalado un primo suyo. Varios días después pide otra funda para colgárselo, a lo que le decimos que espere un poco porque acaba de comprarse un pack de varias fundas (no se lo toma muy mal). Pide un pijama y zapatillas de andar por casa y evidentemente se le compran porque era muy necesario. No se muestra satisfecha y empieza a decir que necesita más ropa, a lo que le decimos que vaya revisando armario con la ropa de temporada y haga lista de lo necesario (según se viene haciendo con todos los residentes) y antes de hacer esa lista, y tras ver como sus compañeras tenían ya algunas prendas nuevas, monta una gran “pataleta” y amenaza con irse a su casa porque no quiere estar aquí y reclama todo su dinero porque, confiesa durante la gran bronca, que ella tiene un contrato de teléfono que pagar. Tiene una gran alteración de conducta y cuesta calmarla, como esto ocurre sobre las dos media de la tarde, después de comer, hasta el día siguiente no consigo hablar con ella. Durante esa tarde habla con sus hermanas y primas. Las dos hermanas llaman al día siguiente al centro (una de ellas habla conmigo-Gema) para decir que ellas conocían la existencia del teléfono pero no se explican cómo lo ha hecho, y que desde luego sus primas no la han ayudado (nadie había hablado de sus primas). Por su parte Juana dice que ella estaba tan nerviosa porque sus hermanas y primas les estaban reclamando los 35€ de las facturas y no los tenía. Su prima iba a venir a verla y por la ventana de su habitación le daba el dinero y confiesa que es su prima María José quien la ayuda a hacer contrato por teléfono durante el confinamiento y que es de dos años por lo menos. La hermana ha quedado en mandarme las cartas que le han ido llegando y yo les he aclarado que todas estas cuestiones son a través vuestra y por tanto estaba en la obligación de informaros para decidir qué hacer con ese contrato y esas facturas, al mismo tiempo que les he sugerido que por el bien de Juana, si sus primas están siendo un referente para ella en estos momentos y ellas quieren “ayudarla” toda intervención tendría que ser en equipo. ( ayer mismo por la tarde vino de nuevo su prima María José a verla, pero nunca entra en la entidad, no solicitan la visita, desde la calle le piden por teléfono a Juana que se asome y por ahí se intercambian cosas, ayer sin ir más lejos, la funda para colgarse el móvil que teníamos pendiente aquí comprarle-también se les dijo que en tiempos de COVID y según nuestros protocolos estaba prohibido darles objetos directamente, sin pasar por los monitores y desinfección correspondiente). En fin….espero haber sido clara ;P …cuando tengas facturas te las mando y vemos siguiente paso pero creo que la prima, al menos, una llamada de atención debería tener','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-10-02','TERESA EMAIL ANAN ADUCACORA PLENA INCLUSION ZAFRA Recuerdas que ayer te decía que Natalia estaba haciendo cosas con los compañeros pero que aún no había podido ponerme al corriente…pues bien acabamos de tener reunión tras detectar y comprobar dos nuevos problemas con ella como protagonista principal. El primero es del que te hablé con Francisco Toro, al que tiene nerviosito perdido, y es que no deja de meterse con él y ya ha llegado a confesar (Natalia) que” ha sentido las ganas de coger una buena piedra de la huerta y dejarlo en el sitio”. El segundo conflicto, que es el que nos ha llevado más tiempo, principalmente por la parte familiar de la usuaria. Luisa, compañera de RAL, se viene quejando de agresiones por parte de Natalia desde hace tiempo pero no hemos podido comprobarlo hasta hoy. Tras varios testimonios (de la propia Luisa, de su hermana que escuchaba algo mientras hablaban por telefono cuando ocurrían los hechos, de una compañera, y de una monitora), de ver las imágenes de la cámara de residencia y tras la propia confesión de la propia Natalia, sabemos que la agradió dandos patadas en una pierna (que tiene toda llena de moratones) y puños en la cabeza. Hemos informado a la familia y quedaría pendiente “tratar” con ellos el derecho, la posibilidad…de denunciar lo ocurrido. Hablamos si quieres en otro momento, mañana….y valoramos todo LE INDICO QUE DENUNCIEN','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-10-02','Ana: Correo de Estrella, CSS-Plas.: "Buenos días. Os comunico que el día 30 de septiembre se ha procedido a dar el alta a Josefa Domínguez Blanco, con lo que ha vuelto a ingresar en su Centro de Plena Inclusión de Zafra. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-10-02','Ana: Correo de Miguel Ángel, Director del CRR-CC: "Buenas tardes, se pone en contacto con monitores/as el Dr. Jerez de la UHB para poder comunicarse con Dirección Técnica no estando disponible en ese momento. Se realiza llamada por parte de Dirección Técnica al DR. Jerez para informarle sobre las incidencias y alteraciones presentadas por dicho usuario durante las últimas semanas y sobre todo por la peligrosidad de su conducta a nivel de salud pública, entiende perfectamente que se haya optado por la medida tomada tanto por la psiquiatra de referencia de Juan Mario como por parte de la Entidad, nos comenta que nos mantendrá informados sobre la evolución del mismo, incidiendo que en el momento actual se encuentra bastante estable y tranquilo. Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-10-02','TERESA Teresa este informe fue enviado con fecha de 22 de Julio de 2020 y yo pensaba que ya os había llegado. No obstante lo he registrado y se ha mandado con oficio pero te adelanto el informe para que lo vayáis viendo. Informar que Candi no pernocta en el nuevo domicilio, ni tampoco viene a este servicio desde hace tiempo, ni siquiera para acompañarlo a la compra de alimentos en Mercadona desde hace más de tres meses HEMOS SOLICITADO NO REVOAR EL CONTRATO QUE CUMPLE EN NOVIEBRE VAMOS A INTENTAR MEJORAR LA VIVIENDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-10-05','En relación con la solicitud de autorización judicial para la venta de los inmuebles pertenecientes a Andrea, volvemos a contactar con el Abogado designado, (pablogperez@icaba.com) (675199400). Nos indica que CREE, porque según él, este tema lo lleva su compañera (cgomez@pajueloabogados.com), que está terminándolo de redactar para presentarlo al Juzgado. Les rogamos que nos mantentan informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2020-10-05','CORREO. Se remite a APNABA Autorización de vacunación contra la gripe.','2');
