insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-10-05','Ana: Llamada de Juanjo (667 958 878), pregunta que para cuándo podrá sacar la asingación de forma quincenal. Como lo hablamos el día 23, le digo que la semana que viene o la próxima, si todo sigue bien, lo hablaré con el jefe de la secc.ecca. para probar a partir de noviembre. *Le parece muy bien y se muestra agradecido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-10-05','Ana: Correo de Sonia Leo, Directora Resid. Virgen de la Montaña, Casar de CC (virgendelamontana@grupociudadjardin.com): "Buenos días Ana, te comunico que Pedro Román García fue dado de alta el Viernes día 2, no nos facilitarón informe de alta, si os lo mandaron a vosotros os agradeceríamos nos lo hicierais llegar. Un saludo, Sonia" ······················································· Mi respuesta: "Buenos días Sonia, Gracias por informarnos. A nosotros no nos han comunicado nada, ni el alta… Si no nos remiten hoy el informe lo pediré al hospital. ¿Qué tal habéis encontrado a Pedro Román en esta ocasión? Un saludo y buen día." ···························· Nuevo correo-e de Sonia: "Buenos días de nuevo, el paciente viene con Actilobacter perineal y nasofaringeo por lo tanto se están tomando medidas de aislamiento de contacto además del preventivo. Presenta UPP grado II en sacro y grado III en gluteo derecho. Ayer se tuvo que llamar al Pac por fuerte dolor abdominal y su juicio clínico es de posible hernia. Continuamos viendo su evolución" ········································································································································································································································································· Ana: Llamo a Clara I. Gómez Nestares, jefa de secc. depend (68513 / 924 00 92 69), en relación a la reclamación de la cuantía de la prestación vinculada al serv. residencial concedida a Pedro Román. Pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-10-02','Correo de José Manuel, nieto de Manuela: "Muy buenas... les comunico como a la vez lo a hecho Gloria (delegada de apoyo ) que ya estamos en el domicilio habitual..." pide también en el mismo que se agilicen los trámites para las obras del tejado de la vivienda. *Guardo correo en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-10-04','Ana: coreo de Pablo, nieto de Manuela Morato: "Buenas Tardes,me podrian mandar a mi correo un numero de telefono,para ponerme yo en contacto con Pedro,jefe de sección,porque he intentado con este numero 924006030 y no lo cogen ,gracias. Un saludo." ·················· Respuesta, lunes 5/10/20: "Buenos días Pablo, Pedro de nuevo no está disponible, tampoco lo estuvo finalmente la semana pasada. Si a lo largo de la semana no se incorpora intentaremos ponernos, alguna otra persona del equipo, en contacto contigo o te diremos con quién puedes hablar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-10-05','Ana: Envío escaneados al Abogado de Oficio (santiagomerinoyjerez@hotmail.com) mediante correo-e, copia del contrato de SAD con cláusula suspensiva y Aceptación del PIA de prestación vinculada al servicio, recordándole que aún no se ha dado de alta el servicio pues no hay resolución del SEPAD.','2');
