insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-10-05','miguel, me contesta el abogado que hemos contratado (Jesús Bueno Clemente de Plasencia tlfno 927-422628 email: jesusbueno@buenoabogados.com) para que solicite la Aprobación de la Herencia y autorización de venta de los inmuebles que no da lugar porque tendría que haberse tramitado sin beneficio de inventario. Tras hablarlo con Angel me comenta que ha de aplicar el 272 CC por el cual no se requiere la autorización pero sí la aprobación judicial. Y al tiempo aplicar el artículo 62 LJV por el cual el competente es el juzgado del domicilio del tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2020-10-05','Ana: Llamada de Rosa, Admvo. CSS-Plas. (24145): pregunta si desde la CTAEX se ha aceptado el cargo de tutor de Isabel Mª, pues en el Jdo. le han dicho que hace más de un mes que nos lo environ. *Tras consultar con Juan Pedro, Admvo. CTAEX, le confirmo a Rosa que efectivamente, nombran tutor a la CTAEX y ya es firme, pero aún no está aceptado. *Le indico que está en trámites, cuando esté aceptado el cargo se lo comunicaremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-10-05','Ana: Se envía por correo certificado a la Dirección Provincial de la Seg. Soc., Oficio adjuntando documentación relativa a la solicitud de Orfandad (Libro de familia + Certificado Médico de Defunción)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2020-10-05','Ana: Llamo a Paz Boticario- TS de la Cruz Blanca (927 24 68 52), una vez resuelta algunas dudas con respecto a los documentos que nos han enviado, pongo para la firma del D.Gerente los distintos modelos: Autoización Anual de Actividad, Informe de la reunión interdisciplinar u Autorización de Información a Familiares. *En cuanto al "Consentimiento Expreso Residente" acerca de varias cuestiones como Dcho. de Imagen, se lo paso a Miguel, Asesor Jurídico CTAEX. *Éste dice que se ponga para la firma y se lo devolvamos para que lo remita a Fiscalía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-06','TERESA ENVIO SOLICITUD DE COMPENSACION DE GASTOS DEL TAXI 150 EUROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-10-05','Ana: Llamada de Julia (927 14 50 83), no puede retirar el dinero de las autorizaciones. Le indico que el extra sí podrá retirarlo directamente, pero la asignación mensual se le hará transferencia a la cuenta de la madre. No obstante le recuerdo que para cuestiones económicas tiene que llamar a Icíar, no sé si habrá habido algun problema con los bancos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-06','Ana: Llamada de Emi (le han prestado un tlf. 643 40 17 82): Está viviendo en Plasencia con un amigo. Pero se tienen que cambiar a otro piso de alquier, se quieren mudar al barrio de San Miguel, pero tiene que pagar la mitad del alquiler. *Se le han partido las gafas por la mitad, ayer se mareó en el portal y se le cayeron. *No está comiendo apenas porque no tienen dinero. *Le han robado el teléfono. *El mes pasado estuvo en la consulta con la Dra. Parrado (psiquiatra), ésta le ha dicho que necesita ayuda psicológica y psiquiátrica. *Pide que se le autorice dinero para las gafas (enviará presupuesto), para unas botas, un móvil y la tarjeta de recarga. **Hablaré con la secc. ecca. ······································································································································································· Pregunto a Icíar, secc. ecca. CTAEX, por la situación económica de Emi a día de hoy. ········································································································································································ Llamo a Ana Benavente, TS ESM-Plas., varias veces. Cuando consigo hablar con ella, Emi ya ha estado allí. Le ha dado cita para el jueves. Iba acelerada con las gafas rotas y las mismas demandas que me ha hech a mí. Hasta el jueves no le atenderá. **Cuando tuvo la cita con la Dra. Parrado, le propusieron el ir al centro de Málaga, pero dijo que se lo iba a pensar y aún no ha dado respuesta. El jueves se lo planteará de nuevo. En función de esto solicitarán la canalización o no, pues aún no está pedida. Me llamará el jueves tras la cita con Emi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-06','Ana: Recibo correo de Mariví Clemente, TS CSS-Plas. (victoria.clemente@salud-juntaex.es): "El presupuesto aproximado que el Paciente MIGUEL SANTOS CORDERO estima como gastos para mantenerse en domicilio sería de 600 €, cantidad que desglosa de la siguiente manera :200€ para alimentación y aseo, 100€ para ayuda a sus hijos, 100€ para tabaco y gastos de bolsillo, 100€ para ropa, calzado y telefono movil, 100€ para aportación , mantenimiento y gastos de casa. Despues de hablar con el Padre y el hijo del Paciente, nos aclaran que el tema de la vivienda y convivencia, estaría cubierto por alguno de ellos de forma temporal, hasta que la casa en la que Miguel quiere vivir se arregla , limpia y acondiciona. Un saludo" ··························· *Se lo remito a Alberto, Jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='NOGALES'and apellido2='MATADOR'),'2020-10-06','TERESA ME LLAMA AMALIA COMPAÑERA PARA COMENTARME QUE SE HA DESCOMPENSADO Y HA SACADO TODOS LOS MUEBLES FUERA DE LA CASA Y SE LOS HAN ROBADO HABLO CON PIEDAD LA TS 924340001 PARA INFORMARME QUEDA EN VER EL DINERO QUE TIENE PARA QUE LE ACOMPAÑE SONIA Y COMPRAR LO QUE NECESITE COMENTA QUE MANUEL AUN ESTA NERVIOSO Y QUE AHORA NO HAY POLICIA LOCAL EN LA LOCALIDAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-10-06','Ana: A petición de Miguel, Asesor Jurídico, y Alberto, Jefe de la secc. ecca., llamo a Raquel, Hogar de Nazaret (927 416 563). Hablará con José Pedro en relación a la venta, cree que lo entenderá y no habrá problemas. En cuanto a la asistenia a notaría, les digo que si no hay cambio será a las 10:30 h. *El acompañamiento no podrá realizarse con personal del centro. *El taxi adaptado intentarán solicitarlo ellos. *Lo coordinaré con Futuex. ··········································································································································· LLamo a Toni-Futuex, como salta el buzón de voz, envío correo-e: "...En relación a José Pedro Villegas Serrano, el próximo viernes días 9 a las 10:30 h, debe acudir a la notaría de Manuel Gomez Moro (Dirección C/ Alfonso VIII, 29 de Plasencia. / Tlfno 927-427147) para la firma de la venta de la vivienda, en el centro residencial le van a explicar que existe tal necesidad y no hay más opción. Miguel, Asesor Jurídico, acudirá a la ratificación telemática desde una notaría de Mérida. Desde la Residencia nos dicen que no es viable el acompañamiento con personal del centro, así pues ¿sería posible que la compañera que suele visitarlo le acompañase a dicha gestión? El taxi adaptado en principio lo pedirán desde la residencia, me lo confirmarán en lo que queda de mañana. Confírmame cuando puedas por favor si es posible este acompañamiento. ..." ····················································································································································· Respuesta de Toni: "...ningun problema para que Gloria que es la persona que lo ha visitado y ha realizado gestiones con él, le acompañe en el taxi adaptado para dicha gestión, contad con ello!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-10-06','Ana: Solicito a Marisol, TS del HUC (927 256 823) mediante llamada telefónica, informe de alta de Pedro Román. Me lo remitirá por correo-e. ··········································································· Una vez recibido el informe, lo guardo en su expte. y se lo remito a Sonia Leo, direcotra Resid. Virgen de la Montaña. ······························································ Llamo a Clara I. Gómez, Jefa Secc. Depend. (924 00 92 69), le pregunto por la reclamación de la prestación vinculada al servicio. *Lo mirará y me dará respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-10-06','Ana: Solicito a Clara, Jefa Secc. Depend (924 00 92 69) Certificado de Grado de Dependencia de Margarita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-10-02','Ana: Llamada de Rosa Fdez, Psiquiatra CSS Plas. y Borja, Psicólogo. *Han trabajado con Margarita la idea de retorno al Centro suyo de referencia y lo acepta, aunque con muchas reticencias. *Borja apunta que, no obstante, es una persona que "cambia continuamente de idea." *Continúa con malestar por tener que volver con la monjas. *Consideran que podría venirle bien el cambio de recurso. *Lo reflejarán en el informe, así como la ausencia de Alteraciones de conducta en estos momentos. *El alta está prevista para la próxima semana. Hablarán con Pilar, Directora del Hogar, para organizar el regreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-10-06','TERESA LE PASO RECIBO A ALBERTO DEL PAGO DEL TELEFONO, VA HA PROCEDER A DEVOLVERLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-10-06','Ana: Tal y como me solicita Ana Benavente, TS ESM-Plas. Le remito por mail la sentencia de incapacitación inicial, el auto de remoción y nombramiento de la CTAEX como curador, así como la firmeza de este último.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-06','TERESA Remitimos por correo postal está mañana a Comisión tutelar de adultos, a tu atención, toda la documentación original. El reconocimiento médico fue bien, la médico que lo valaró indicó que no se le habia concedido la incapacidad laboral en un par de ocasiones anteriores en 2008 creo la ultima vez, en virtud a los informes médicos existentes,..pero que lo mandaria a tribunal medico para valorar (le insistimos que el retraso mental, mas que objetivable, en la entrevista personal, no es sobrevenido sino desde nacimiento.. segun consta en cadex) pero a ver que le dicen. ENVIO SOLICITUD DE GASTOS DE COMPENSACION Y PASO LA FACTURA A LA PARTE ECO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-10-02','miguel, a petición de Amalia activo con la policía la busqueda del tutelado que ha desaparecido desde el martes por la tarde (su hermana fue la última que habló con él). Futuex quedó el miercóles en ir a verle conforme visita rutinaria habitual sin éxito, no está en su casa, lo cual es confirmado por los compañeros Ana y Alberto que acuden al domicilio y nadie les abre. Me confirma Amalia que el teléfono da señal al llamar pero nadie lo coge. La policía va al domicilio y comprueba que no hay nadie. Me llaman de nuevo para preguntar si tenemos o no una copia de las llaves. El dueño parece ser que finalmente si tiene copia pero está en Badajoz. A las 17h me confirma Amalia que ha aparecido, que se encontraba mal y fue a la UHB de Mérida donde quedó ingresado hasta la tarde del viernes. Llamo a la Policía para desactivar la busqueda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-10-07','Ana:en relación a la necesidad de ropa de Paula (Andrés), llamo a Estrella, TS CSS-Plas (24146): se había producido un malentendido. Enviarán presupuseto a la secc. ecca. por emial para que les autoricen la compra de la ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-07','miguel, pongo a la firma del Gerente la solicitud de incoacion de procedimiento judicial voluntario de gastos extraordinario al jzdo Decano de Plasencia, tras lo cual se lo remitiré el abogado para que lo tramite ((Jesús Bueno Clemente de Plasencia tlfno 927-422628 email: jesusbueno@buenoabogados.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-05','miguel, confirmo con la parte económica que procedemos a buscar abogado y solicitar autorización de gastos extraordinarios al juzgado de plasencia para los arreglos de la vivienda de Cáceres, donde el ayto nos ha dado 4 meses para el arreglo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-06','miguel,remito borrador del escrito de solicitud de autorización judicial de gastos extraordinario al abogado Jesús Bueno de Plasencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-10-06','Ana: recibimos mediante nota interior Resolución de Aprobación de PIA Y adjudicación de plaza en el piso supervisado de Salud Mental (Don Benito).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-07','Ana: Llamada de Emi (hoy desde otro nº: 643 943 315), hoy se encuentra mejor y habla más calmada. Mañana tiene cita con Ana Benavente. Juan, el chico con el que se está quedando tiene solictada plaza en CRR. Dice haber encargado las gafas, le explico, como en ocasiones anteriores, que no debería haberlo hecho sin haber envido previamente el presupuesto, este gasto no está aprobado. *Le indico que vaya a la óptica y diga que nos la hagan aún hasta que den el visto bueno desde la CTAEX, que les pida que envíen el presupuesto por corro-e, le facilito la dirección. Dice que acudirá en cuanto abran a las 10:00h. *Por lo demás mantiene la demanda de comprar botas, teléfono y comida. Pide que se le autoricen 200€ en total. ·················· Paso nota a Alberto, Jefe secc. ecca. ····· Conversación y acuerdos con Alberto: de momento la asignación se le queda tal cual hasta el 9 de noviembre,después se reajustará. Aparte se valorará presupuesto que nos han remitido de Opticalia, en cuanto al móvil que pide se valorará el mes que viene, de momento no se le va a comprar. Voy a enviar a Futuex para que comience a visitarle y hacerle seguimiento, planteamos la posibilidad de hacer transferencia a su amigo para colaborar con los gastos de la vivienda/manutención. ············································································ Informo a Emi sobre todo lo acordado. Me facilita el nombre de su amigo, Juan Corrales, y la dirección en que están viviendo: C/ Rincón de la Magdalena, nº 12, 2º. *De alquile, según manifiesta Juan, paga 300 €, pero están incluidos la luz y el agua. ···· Por otra parte, Emi manifiesta que en el Comedor Social no le quieren dar comida, pues comenzaron a darle y como su asistencia era irregular le han dicho que no le dan más. A Juan sí se lo dan y lo comparten. ······················································································································· Envío correo con derivación a Toni-Futuex, solicitando que acudan a visitarla en cuanto puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-06','TERESA El tema de la institucionalización estamos en ello… para Guillermo necesito que lo vea el CADEX para que le den discapacidad y poder pedir residencia ya que por la edad que tiene el requisito para mayores es tener discapacidad y el tema del CADEX va para largo…. Con respecto a Pablo nos piden haber iniciado el proceso de incapacitación para continuar con la solicitud así es que esta mi compañero en ello. Mas no podemos hacer','2');
