insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-10-07','TERESA EMAIL DEL CRPS Ayer me pidió cita para hablar conmigo y hoy ha venido con la solicitud de justicia gratuita; le he ayudado a rellenarla, y le dicho la documentación que necesita, pero le he dicho que no tiene validez legal esta solicitud porque ella esta incapacitada y no puede firmarla, aun así ha insistido en hacerla, aunque le he comunicado que te mandaría este email, para informarte y ver qué hacemos con la solicitud; te la mando a ti o la tramito en el juzgado o le digo que no se puede hacer nada y que vosotros lo haréis cuando consideréis oportuno????? Aún no tiene la documentación preparada LE INDICO A MIGUEL QUE ME MIRE SI TIENE ALGUN JUICIO PENDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-10-07','Ana: llamo a Raquel, Hogar de Nazaret (927 416 563), a José Pedro no le han querido decir nada todavía, en equipo han decidido decírselo mañana para que no tenga mucho margen para darle vueltas, no obstante no cree que ponga ningún problema. *En cuanto al taxi, dicen que sólo hay uno adaptado en Plasencia y que, según les ha explicado el taxista, mañana debe pasar la ITV, han acordado que en cuanto la pase, confirmarán el traslado del viernes. *Le explico que deben enviar (ellos o el taxista) la factura a nombre de José Pedro y el nº de cuenta al ctutelar@ para que procedan a realizar la transferncia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-10-07','miguel, llama Mely para preguntar por el estado del procedimiento de aprobación de herencia y autorización de venta.Llamo al Jzdo nº2 de Zafra procedimiento X15 nº129/2020 y me indican que desde Agosto solicitaron abogado de oficio y por ahora no les han contestado. Que llamemos más adelante a ver si ya designan abogado y procurador de oficio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2020-10-07','Ana: Correo de Sonia, ASINDI: "Hola, únicamente informaros que ayer Juan Gabriel fue a revisión a Cáceres, le han dicho que, según se ve en la radiografía, los huesos van soldando bien, y las heridas que tenía también van cicatrizando. Tiene que volver en 3 semanas y seguramente le retirarán la escayola. Un saludo"','2');
