insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-08','TERESA LLAMO A LA OFICINA DE CASTUERA (SEPE) 924773855, ME ENVIARAN LA DOCUMENTACION POR EMAIL PARA QUE LA FIRME EL TUTOR LEGAL Y ASI RENOVAR EL SUBSIDIO QUE ESTA COBRANDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-10-07','Ana: Conversación telefónica con Alberto Arias Bueso, T.O. - Valorador, EVD Brozas: Ya han acudido a valorar a J. Ramón, ha dado GRADO II, las alternativas son SAD (45 h/mes = 2 h y algo/día) o Plaza residencial (para este última iría a la lista de espera y tardaría en acceder dado su grado. No obstante como en estos momentos él no quiere ir a residencia, acordamos solicitarlo, para, llegado el momento, que tenga la opción). En cuanto al SAD, podría solicitarse a través del servicio municipal conveniado (no tendría que pagarlo) o serv. privado, en cuyo caso la prestación económica vinculada sería sólo de 100 €. *Puesto que en lista de espera sólo hay 3 personas delante y presenta otras ventajas por ser público, optamos por este último. *Intentará avisarme cuando sólo quede una persona delante de cara a la limpieza previa de la vivienda. *Con respecto a ésto, Alberto manifiesta que la casa está muy mal, acumulación de objetos/residuos, mucha suciedad en cocina, paredes, bañera... falta absoluta de higiene ······· *Cuando recibamos el PIA, se lo adelantaré por mail y le remitiré los originales por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-10-08','Ana: Alberto Bueso, TO EVD-Brozas (alberto.arias@salud-juntaex.es): me remite por correo-e las Aceptaciones PIA para solicitar plaza residencial y SAD. *Se ponen para la firma del D.Gerente. ··············· *Acuerdo con Alberto solicitar también la prestación vinculada al SAD por si el servicio público se demorara mucho. ································································································································ Pido a Toni-Futuex, mediante email, presupuesto de limpieza de la empresa de CC. (no está en su aplicativo)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-10-07','Ana: Correo de Toni-Futuex: "...Adjunto se envía información, en relación a la ayuda solicitada para Juan Chamorro Holguín por parte del SSB del Ayuntamiento de Guadalupe (Raquel Moreno) de 100 euros al mes durante un periodo de seis meses (es un progrma de diputación que concede a los ayuntamientos que lo soliciten). De ser aprobado, debe justificar gasto de esta ayuda con tickets de compra, por lo que Juan demanda que se le debería aumentar la asignación semanal durante el tiempo de la ayuda, para poder realizar dicha justificación y tener más disposición de compra. Juan por supuesto, decía que si se lo conceden el tendria que tener mayor asignación, dado que tendria mas ingresos. Se administró su inyectable en fecha, en centro de salud de Guadalupe como estaba planificado y está a la espera de recibir cita en domicilio, para revisión presencial en salud mental durante el mes de octubre en Cáceres. Tenemos previsto acompañarlo a la cita cuando se produzca y hacerle un seguimiento para ver que tal continúa para la semana siguiente o la proxima. ..." *Guardo la Nota en el expte. En ésta también comunican: "...recibe ya la ayuda a necesidades básicas desde el Ayuntamiento (bombona de gas butano) que es entregada en domicilio y alimentos desde el programa de Cruz Roja, que se inicia en esta semana en curso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-08','TERESA ENVIO POR EMAIL DECLARACION DE RENTAS PARA RENOVACION DEL SUBSIDIO POR UN AÑO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-10-08','Ana: Llamada de Clara, TS C.Salud Guadalupe (927 154 305): Juan tiene cita en enfermería para el inyectable el miércoles 14 a las 9:30 h. La enfermera solicita enérgicamente que acuda a la hora y con buenos modales o se va a negar a atenderles, pedirá que se lo administren en Salud Mental en CC. Está muy enfadada pues dice que acude cuando le da la gana y con malas formas. *No quiere poner nada por escrito. ··················· Por otra parte, Clara se muestra molesta, pues dice que es ella quien tienen que llamar todos los meses para recordar la cita. *Le indico que la de Salud mental la comuncan por escrito a Juan y Teresa está pendiente. Y la del inyectable se la dicen a Juan cada vez que acude a ponérsela. ····································· No obstante lo comunico a Futuex mediante email y solicito que trabajan la puntualidad y los modales con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-08','TERESA ENVIO OPCION DE PF AL INSS PARA COMPLEMENTAR CON ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='FERNANDEZ'and apellido2='CALDERON'),'2020-10-08','TERESA RECIBO RESOLUCION DE MODIFICACION DE LA CUANTIA DE LA PNC AHORA ES DE 395.60','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-08','Ana: Tras hablar con Ana Benavente, TS de Salud Mental, y con Emi, envío correo a Alberto al respecto: "Hola Alberto, He recibido llamada de Ana Benavente, TS de Salud Mental de Plasencia También he hablado con Emi. Te comento varias cosas, para que las tengamos en cuenta y/o actuemos en consecuencia: - Emi ha aceptado ir al centro de Málaga que comentamos ayer. Ahora toca espera que acepten la canalización en la Subdirección de Salud Mental. - El miércoles 14, la semana que viene, Emi tienen de nuevo cita en Traumatología en Mérida. Habría que autorizarle dinero para acudir a la misma. Para confirmarle qué día puede retirar el dinero, habría que llamarle al número de su amigo Juan Corrales: 643 943 315 - Ya está derivada a Futuex, pero no sé qué día acudirán a visitarla, para que nos confirmen el dinero que paga Juan de alquiler (según verbaliza éste son 300€ luz y agua incluidos) y que faciliten el CCC para hacerle la transferencia. - Le he dicho que de momento de móviles, nada, se valorará al mes que viene. - El presupuesto de opticalia no sé si lo habéis mirado para comprarse las gafas, lo enviaron ayer al ctutelar@ - ¿Y con las botas qué hacemos? Sigue con sandalias, dice que ha visto unas a 40€, la verdad es que ya está haciendo más fresco y en Plasencia siempre son unos grados menos. - Le van a comenzar a dar comida en el comedor social, por tanto para comida ya no me preocupa tanto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2020-10-08','Ana: Correo de Carmen, EVD Plas.(carmen.garciamarti@salud-juntaex.es): "Hola Ana, buenos dias, que tal la mañana ?? Queria decirte que acabe el expdeinte de Guadalupe y ya tengo la documentacion de la herramienta T4 que me ha traido la psicóloga. La adjuntno a su expediente y lo pongo al correo que saldrá ya mñana, , para que lo sepas !! saludos cualquier cosa , me dices" ·············· Contesto al mail. En cuanto recibamos la Aceptación el PIA la pondré para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-09','miguel, remito al abogado Jesús Bueno toda la documentación preparada para su presentación en el jzdo decano de Plasencia para autorización de gastos extraordinarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-10-09','Ana: Llamada de Juanjo (667 958 878): hoy tienen cita con la TS de Salud Mental. Quiere solicitar participar en algún tipo de actividad/taller ocupacional para tener mente ocupada. *Plantea la posibilidad de en 2-3 años irse a vivir de forma independiente a 1 vivienda social o de alquiler si no hubiera opción en las primeras. Espera seguir evolucionando bien, expresa que se está esforzando. ····························································································································· Llamada de Pilar Martín: Va a solicitar CRPS para Juan José. Me pide algunos datos y documentos. Le remito por mail la sentencia y la aceptación del cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-09','Ana: Recibimos informe médico de alta del Hptal. Virgen del Puerto de Plasencia, lo remitió la propia Emi por correo ordinario. Acudió cuando se cayó al suelo al marearse, según expresa, la tuvieron en observación hasta que ella misma prefirión continuar en "observación domiciliaria".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2020-10-07','miguel, remito conforme petición al escrito que nos envía el 1-10-20 la abogacía general (Curro) del Jzdo de Montijo nº2, para informe de la situación del tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2020-10-09','miguel, remito a abogacía general (Curro) informe de contestación de la demanda de remoción X06 REMOCIÓN DE TUTOR 232/2020 del jzdo nº4 Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-10-09','miguel, el abogado Jesús Bueno me indica que puede interponerse, aunque puede ser que el registro de la propiedad a posteriori pueda poner algún problema, no obstante le pido solicite lo antes posible la Aprobación judicial de herencia junto con la Autorización de venta de los inmuebles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-10-08','Ana: Pilar Martín, TS del ESM-CC: nos remite por fax los informes que enviaron a Dependencia para la priorización del expte. de Clementa. ······· En conversación telefónica Pilar me comunica que le han aprobado plaza residencial. Ahora tiene que elegir entre Plaza en centro público por emergencia social (no puede elegir centro) o puede escoger la prestación vinculada al servicio, ingresando en residencia privada. En opinión, tanto de Pilar como mía, esta última opción no es viable. Por lo que me informa y hacen constar en los informes sociales, Clementa está atravesando dificultades económicas. (ver anotación día anterior). Dado que el cargo está recién aceptado, no tenemos todavía información de su cuenta ni de sus propiedades. ························ Realizo mediante email, *derivación a Futuex (Programa de Apoyo Comunitario)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-10-07','Ana: Conversación telefónica con Pilar Martín, TS ESM-CC: hoy mismo se ha aceptado el cargo por la CTAEX: con carácter cautelar ADMINSITRADOR PROVISIONAL DE LOS BIENES y textualmente: “…así mismo dispongo que han de prestarle el apoyo necesario para el control médico y terapéutico de su enfermedad y toma de medicación prescrita…”. Pilar me facilira la siguiente información: Domicilio: C/ García Plata de Osma, nº 21. 4ºD - Cáceres. Tlf. 693 803 767. Contacto de un voluntario de Cáritas Parroquial: Agustín (666 00 91 19). Clementa percibe una Pensión de Viudedad de 966€/mes. Su vivienda cuenta con una carga hipotecaria por la que abona 180€/mes. Tiene contraída una deuda con Cáritas de unos 1800-2000 €, por haberle ayudado a costear los servicios de varias personas internas que ha tenido. Hoy le han informado que tiene un garaje en propiedad, pero no tiene constancia al respecto. *Nos remitirá informe social emitido para la priorización de la valoración de dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-10-08','Ana: Llamada de Damián, expresa estar mejor. Con lo que se encuentra mal es con los problemas dentales. Acudió ayer a la clínica dental pero no pudieron atenderle porque desde la CTAEX no se ha aprobado aún el presupuesto. *Paula ya lo ha puesto en conocimiento de la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2020-10-09','-Me comenta Crístofer que le gustaría hablar contigo porque tiene la cosa ahora de querer recuperar la capacidad de obrar. Yo le he dicho que si le quitaran la tutela él no tendría dinero para poder subsistir. Dice que le da igual, pero que quiere hablar contigo para que le digas. Si no te importa te paso su número y hablas cuando puedas. Sí te agradecería que me avises antes de llamarlo para que estemos en sobreaviso para ello. Su número de teléfono es 605.163003','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2020-10-09','TERESA El pasado 7 de Octubre se visita a Rosario en su domicilio para comentar con ella el tema del gasto del teléfono. Se empieza a preguntar por el paquete de Imagenio y canales de televisión de Movistar que tienen en casa desde hace unos años, Rosario cuenta que disfruta de muchos canales en la tele, además tiene internet en casa, sumando el fijo y su móvil, todo en la misma factura. Se le comenta que el precio se eleva a 200€ por lo que habría que hacer algo para reducir gastos, en ese momento interviene Luisa, la madre de Rosario y explica que la factura ahora es algo más elevada porque están pagando el terminal de Rosario, que serían unos 25€ al mes. Pero solamente le quedarían 2 coutas para terminar de pagarlo, por lo que la factura debería reducirse considerablemente. Se les pregunta la tarifa que tiene Rosario en su móvil, porque a lo mejor está pagando por las llamadas y eso es algo que está incrementando el precio de la factura. Tanto Rosario como su madre comentan que la tarifa del móvil tiene llamadas ilimitadas y desde el fijo solo llaman a otros fijos por lo que no hacen nada fuera de lo normal. Se les propone llamar a Movistar para preguntar, simplemente, qué tipo de tarifa tienen por si se pudiera modificar de alguna manera y así pagar algo menos de dinero. Rosario se niega a que se llame a la compañía y lo único que repite todo el tiempo es que no quiere que le quiten sus canales de la tele. Es bastante complicado cualquier tipo de intervención con Rosario porque se encierra en sí misma y no permite que se trabaje en ninguna dirección, ya que desconfía de cada decisión que se pueda tomar. LE INDICO QUE LE PID COPIA DE LA FACTURA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-10-09','TERESA TRAS NO HABERNOS CONCEDIDO EL INGRESO INVOLUNTARIO NOS PLANTEAMOS UNA INTERVECION PARA MEJORAR LA VIVIENDA CON GRATIFICACIONES ECONOMICAS EL DIA 14 SE REUNE LA DELEAGA CON AURORA PARA ESTABLECER OBJETIVO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-10-09','TERESA VAMOS A BLOQUEAR LOS RECIBOS Y MASDAR ESCRITO A VODAFONE PARA ANULAR EL CONTRATO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-10-09','Ana: Llamada de Estrella, TS CSS-Plas.: A Felisa finalmente se le hará la revisión en el CADEX de CC. *Desde Aprosuba-Ba, le han dicho a Estrella que quieren acompañarle pesonal de dicho recurso. Y que ya lo han hablado con la CTAEX. Conmigo no han hablado, preguntaré a Amalia, por si han hablado con ella. En mi opinión, lo más adecuado es que le acompañe personal del CSS, pues ya lleva bastante tiempo en la UHDAC. ·················· Llamo a Amalia - Comunica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-10-02','-Amalia : Tras confirmar que ayer dia 1 no fue al banco a retirar el dinero y no personarse el dia anterior a la cita que tenia con la delelgada tutelar , activamos protocolo y avisamos a la policía . Previamente , solicito a Alberto y Ana , que se acerquen en el domicilio para confirmar que no se encuentra . Estamos toda la mañana en coordinación con Futuex y policía a la espera de alguna noticia. Sobre las seis de la tarde me llama Toni Futuex , Jose Mª ha estado ingresado en la UHB , no notificaron ingreso ni a nosotros ni a la familia . Al devolverle el tf ha visto las múltiples llamadas que le hemos hecho y ha llamado para informarnos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-10-06','-Nueva visita a J. M desde Futuex : Valle Simón que fuimos a verlo el martes.. despues de la que "lió" la pasada semana. Adjunto envío nota del seguimiento presencial a José Mª Valle Simón con fecha 06/10/2020. Además adjunto informe del alta del ingreso en psiquiatría en el hospital de Mérida (parece que los síntomas para el ingreso fueron un poco ficcionados, por lo menos en la unidad no consideraron tal descompensación y le dieron el alta sin tocarle medicación ni nada)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2020-09-09','-Amalia : derivo el caso a Futuex para incluir en las visitas . Buenas Amalia! que tal?? te adjunto el informe con la información recogida en la primera visita de seguimiento desarrollada en el domicilio de Rosa Gomez, en Merida. La visita se desarrolló en la vivienda de Rosa junto a su primo Alfonso e Isabel la auxiliar de ayuda a domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2020-09-09','-Amalia : derivo el caso a Futuex para incluir en las visitas . Buenas Amalia! que tal?? te adjunto el informe con la información recogida en la primera visita de seguimiento desarrollada en el domicilio de Rosa Gomez, en Merida. La visita se desarrolló en la vivienda de Rosa junto a su primo Alfonso e Isabel la auxiliar de ayuda a domicilio.','2');
