insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-10-09','miguel, una vez ratificada la escritura de compraventa firmada hoy en Plasencia le envío el siguiente email a la compradora(a petición de ella tras conversación telefónica): Buenas tardes, confirmarte como hemos hablado por teléfono que ya he firmado la ratificación de la compraventa de la finca de c/Sor Valentina Mirón 3, 2ºB, Plasencia (Finca 17530 del registro de la propiedad de Plasencia). El protocolo de la ratificación de la compraventa firmada hoy 9-10-20 ante el notario de Plasencia D. pablo Antonio Mateos Lara con nºde protocolo 880, siendo el protocolo de la ratificación el 596 del notario de Mérida D. Fco de Borja Igartua Fesser. Asímismo, ante la imposibilidad de que me contesten telefónicamente en el Banco Santander, he enviado un email a Santiago Borreguero santiagoborreguero@gruposantander.es para que procedan inmediatamente a la cancelación económica de la hipoteca. Una vez pasen unos días, tendrán que emitir un certificado de cancelación total de la hipoteca y apartir de ahí hablaremos con la gestoría para que procedan al levantamiento registral de la hipoteca. ******************************************************* Asimismo al ser imposible hablar con Santiago del Santander por teléfono le envío el siguiente email: Buenos días Santiago, una vez firmada y realizada la transferencia a la cuenta que nos indicaron desde el Santander ustedes por el importe que aparecía en el certificado emitido sumando como nos dijeron intereses, es decir poniendo algo de más 9.044€. Dicho ingreso se ha realizado conforme a sus instrucciones, es decir donde recibe los cargos de hipoteca, ES 82-0075-0212-76-0700370981 cuya titularidad es de José Pedro Villegas Serrano, habiéndose realizado la transferencia a dicha cuenta ruego hagan la Cancelación Económica Total inmediatamente. Y pasados unos días, cuando quede totalmente cancelada económicamente, ruego que nos emitan el Certificado de Cancelación Económica Total para ponernos en contacto con la Gestoría Menaya para poder tramitar el levantamiento registral de la hipoteca. Le he llamado pero no logro hablar con usted.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-10-09','Comunico a Ana por correo electrónico lo siguiente: "En relación con este asunto, te comento: - No tiene propiedades inscritas a su nombre en el Registro de la Propiedad, ni en el catastro. - Para solicitar modificación de medidas relacionadas con la pensión que abona a sus hijos, uno de ellos fallecido, el otro no sabemos si trabaja o no, tendríamos que disponer de la sentencia de divorcio, donde se fijó la pensión, DNI de los hijos, certificado de defunción del que falleció y toda la documentación que puedan darnos. No sé si puede facilitárnosla Pilar Cerrillo, o bien su sobrino, o hermana. Si te parece, facilítame los contactos de los que dispongamos, para dirigirme a ellos y pedirles toda esta documentación. Saludos!"','2');
