insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-13','Ana: Llamada de Emi (643 943 315), dice que los caseros de Juan se han enterado que está viviendo allí y le han echado, le han dicho que tiene que irse como mucho en 2 días. En el Albergue no hay plazas libres. Dado que quiere venirse a Mérida y que mañana tiene aquí la cita en Traumatología del hospital, se alojará en el Hostal Senero (C/ Holguín, 12. Teléfono: 924 31 72 07). Le cobran 28 €, reservará, de momento, desde mañana hasta el martes por la mañana (6 noches). En esta semana buscará otras opciones y acudirá a Salud Mental de Mérida. *Pasará al hostal la dirección del e-mail de la CTAEX para confirmar el precio, nº de noches y acordar la forma de pago (transferencia bancaria). ························· En cuanto a la gafas, tras hablarlo con Alberto, jefe secc. ecca., le comunico que de momento nos e va a autorizar el pago, se valorará ya en noviembre. *Lo del Hostal también está hablado con Alberto.','2');
