insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-10-13','Ana: solicito a Pilar Cerrillo, mediante correo-e, nº de cotacto del sobrino de Mateo, Ángel, Asesor Jurídico, necesita ponerne en contacto con él para solicitarle información y documentación, de cara a solicitar la modificación de medidas relativas a las pensiones que pasa a sus hijos. ·············· Paso a Ángel el contacto: NACHO RUANO: 686 122 016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-10-13','Ana: Correo del viernes del CRR-Plas: (coordinaciontecnica.crrplasencia@grupo5.net): "Buenos Ana, Os mandamos informe de incidencias de Ceferino Mariscal Crespo. Tiene que hacerse cargo de la reparación de una puerta que ha roto de manera agresiva, cuando tengamos el presupuesto os lo mandaremos a la sección económica puesto que tiene que abonarlo él. Cualquier cosa nos decís, Saludos.". *Guardo informe en el expte. digital. **Ha sustraído dinero de la cuenta bancaria de Ramoni, su pareja y se lo ha gastado en una mesa de mezcla entre otras cosas. Cuando ha reconocido todo y le han dicho que debe devolver la mesa de mezcla y el dinero a Ramoni ha montado en cólera, además de romper la puerta ha lanzado piedras y dado en la cabeza a una usuaria... El 112 acudión 1 hora después de ser llamado, para entonces él estaba calmado y valoraron que no había motivo para trasladarlo y que fuera valorado por Psiquiatría. **Enviarán presupuesto del arreglo de la puerta. ···················· Respondo al correo preguntando por la medidas que han adoptado o tienen pensado adoptar, además de que revuelva la mesa de mezclas y el dinero a Ramoni.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-10-13','TERESA CORREO GUARDIA CIVIL ZAFRA El día 11 de octubre del 2020, se instruyen diligencias 2020-839-1413, por un supuesto delito de lesiones y daños en las cosas, que la autora de los mismos ha sido Beatriz Mejias de la Morera, cuya tutela la tiene la Comisión Tutelar de la Junsta de Extremadura. Breve reseña de los hechos: Sobre las 01:00 horas del dia arriba reseñado Beatriz, muy alterada golpeo la puerta de un vecino del edificio donde vive, por que este se negaba a abrirle por miedo, que continuo golpeando la puerta hasta que rompio la parte inferior de la puerta. Que el vecino al ver que le habia roto la puerta, abrió la misma, momento en que Beatriz aprovecho avalanzandose sobre produciendole arañazos en el pecho, ombro izquierdo y frente. Que no para hasta que Rosa, hermana de Beatriz, la separó. Que trás llamar a los servicios de Urgencia, se decidió por parte del Facultativo Medico, su ingreso en el Ala de psiquiatria del hospital de Llerena. SE NECESITA POR PARTE DE ESA INSTITUCIÓN VERIFICAR SI LA DOCUMENTACIÓN REMITIDA A ESTA UNIDAD EN EL MES DE JULIO DEL PRESENTE AÑO POR OTRO INCIDENTE DE BEATRIZ, SIGUE EN VIGOR O HA HABIDO CAMBIOS. PARA REMITAR LA COPIA AL JUZGADO. REMITA CORREO ELECTRONICO CON OK. UN SALUDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-10-13','miguel, llamo y acuerdo con la abogada que tramite el expte de aprobación de herencia vía judicia. Abogada Inmaculada Nuñez Amigo teléfono 636-752-687 y así podemos hablar del tema y concretar. El nombre de la procuradora ANA ESTHER PALACIOS RODRIGUEZ, DNI 8822335-H Nombre letrada INMACULADA NÚÑEZ AMIGO, DNI 80068003-N','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-09','miguel, el abogado nos remite sus datos y honorarios que supondrá el procedimiento de murillo horrillo y santos cordero. Estimados Miguel y Angel, por la presente una vez he hablado con la procuradora Marivi. Los asuntos para hacer el apoderamiento apud acta por tanto serían 1.- Expediente de Jurisdicción voluntaria de aprobación judicial de partición de herencia practicada y autorización de venta directa de todos sus bienes respecto al tutelado Dº. JOSÉ LUIS MURILLO HORRILLO . Procurador DOÑA MARIA VICTORIA HORNERO RODRIGUEZ (NIF 11.770.892-K) . Letrado Dº. JESUS BUENO CLEMENTE (colegiado ICAC 427)* Órgano Judicial: Juzgados de Primera Instancia de Plasencia 2.- Expediente de Jurisdicción voluntaria de autorización judicial para realizar gastos extraordinarios respecto al tutelado Dº. MIGUEL SANTOS CORDERO . Procurador DOÑA MARIA VICTORIA HORNERO RODRIGUEZ (NIF 11.770.892-K) . Letrado Dº. JESUS BUENO CLEMENTE (colegiado ICAC 427)* Órgano Judicial: Juzgados de Primera Instancia de Plasencia _____________________________________________________________________________________________________________________________________________________________________________________ Respecto los honorarios una vez hablado con ella los hemos reducido y casi establecido de forma simbólica (no por cuantía) atendidas las circunstancias de si necesitáis en un futuro cualquier otra colaboración y serían Asunto 1: Letrado (400 + IVA), Procurador (150 + IVA) Asunto 2: Letrado (300 * IVA), Procurador (90 + IVA) Recibe un cordial saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-10-09','miguel, el abogado nos remite el importe que supondrán los honorarios para los exptes de santos cordero y murillo horrillo Estimados Miguel y Angel, por la presente una vez he hablado con la procuradora Marivi. Los asuntos para hacer el apoderamiento apud acta por tanto serían 1.- Expediente de Jurisdicción voluntaria de aprobación judicial de partición de herencia practicada y autorización de venta directa de todos sus bienes respecto al tutelado Dº. JOSÉ LUIS MURILLO HORRILLO . Procurador DOÑA MARIA VICTORIA HORNERO RODRIGUEZ (NIF 11.770.892-K) . Letrado Dº. JESUS BUENO CLEMENTE (colegiado ICAC 427)* Órgano Judicial: Juzgados de Primera Instancia de Plasencia 2.- Expediente de Jurisdicción voluntaria de autorización judicial para realizar gastos extraordinarios respecto al tutelado Dº. MIGUEL SANTOS CORDERO . Procurador DOÑA MARIA VICTORIA HORNERO RODRIGUEZ (NIF 11.770.892-K) . Letrado Dº. JESUS BUENO CLEMENTE (colegiado ICAC 427)* Órgano Judicial: Juzgados de Primera Instancia de Plasencia _____________________________________________________________________________________________________________________________________________________________________________________ Respecto los honorarios una vez hablado con ella los hemos reducido y casi establecido de forma simbólica (no por cuantía) atendidas las circunstancias de si necesitáis en un futuro cualquier otra colaboración y serían Asunto 1: Letrado (400 + IVA), Procurador (150 + IVA) Asunto 2: Letrado (300 * IVA), Procurador (90 + IVA) Recibe un cordial saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-10-13','Ana: Recibo llamada de Mª Isabel, hermana de Pilar (695 967 774). Pregunta por su hermana, quiere saber cómo está y cómo se encuentra. Le gustaría llamar al centro en el que está para interesarse por ella y cuando lo vena oportuno hablar con ella también. Quisiera ir restableciendo poco a poco el vínculo con ella. *Le facilito el nº del centro y comunico a Susana Cortés, TS Casa Hptal. Santiago, por email, que llamará (hospisantiago.ts@esclavasvirgendolorosa.es). Que valoren en el equipo del centro la pertinencia de que hable directamente con su hermana o no. *Pongo en copia a Teresa, TS CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-10-08','Ana: Correo de Toni-Futuex: "...En relacion a Eugenia Pacheco te ccuento la situacion actualizada, en la nota adjunta, notamos conductas extrañas por su parte..." *Guardo la nota en su expte. virtual. *Eugenia ha solicitado la documentación para hacerse pareja de hecho con Pedro. **Está haciendo salidas a Plasencia sin motivo necesario aparente. En una de las ocasiones ha pedido dinero en un bar para el autobús. *De la ayuda de alimentos no ha gastado lo que puede gastar en la tiendas, aún le queda mucho saldo.','2');
