insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-10-13','Ana: Correo de Teresa, TS CTAEX: "...La madre de Paula llama mucho al centro PI Llerena preguntando por su hijo. Ella no sabe que está en la udhac la última información que tiene es que se fue a Mérida. La llamadas con su madre no eran muy terapéuticas sino todo lo contrario, acababan en fuertes discusiones insultándose mutuamente. No sé hasta qué punto es bueno que Paula hable con su madre, coméntaselo al Equipo de la udhac y que lo valoren siempre y cuando Paula tenga interés por hablar con la madre… al menos así lo veo yo. ..." ················ Llamaré a Estrella, TS CSS-Plas, mañana, pues hoy es fiesta en Plasencia.','2');
